def _ensure_gunicorn_upgrade(console_dir=None):
    """Ensure the venv has gunicorn + PyYAML + any other deps required by the
    post-update boot, and upgrade systemd service if still using Flask dev server.

    Called automatically by the in-app Update Now flow (`/api/update/apply`)
    BEFORE the systemctl restart fires, so the venv is in the right shape by
    the time the new code's `_startup_migrations` runs.

    Deps managed here:
      - `gunicorn` — added in v0.4.x; some legacy installs still use Flask dev server.
      - `pyyaml`  — added in v0.9.23 Phase 6. The PgBouncer migration parses
        and mutates ~/authentik/docker-compose.yml via PyYAML; on field
        installs whose venv was built before PyYAML was needed
        (tak-10, May 2026), the migration would skip with
        "PyYAML not available". Installing it here as part of Update Now
        means Phase 6 fires cleanly on the very first click.

    Idempotent: `pip install --quiet` is a fast no-op when the package is
    already satisfied (~1s on a hot pip cache).
    """
    console_dir = console_dir or BASE_DIR
    venv_pip = os.path.join(console_dir, '.venv', 'bin', 'pip')
    venv_gunicorn = os.path.join(console_dir, '.venv', 'bin', 'gunicorn')
    if not os.path.exists(venv_pip):
        return
    if not os.path.exists(venv_gunicorn):
        subprocess.run([venv_pip, 'install', '--quiet', 'gunicorn'],
                       capture_output=True, timeout=60)

    # v0.9.23 Phase 6: ensure PyYAML is in the venv before the PgBouncer
    # migration runs in the post-restart startup chain. `pip show` first
    # to keep the common-path (already-installed) cost near zero.
    try:
        _show = subprocess.run([venv_pip, 'show', 'pyyaml'],
                               capture_output=True, text=True, timeout=10)
        if _show.returncode != 0:
            subprocess.run([venv_pip, 'install', '--quiet',
                            '--disable-pip-version-check', 'pyyaml'],
                           capture_output=True, timeout=120)
    except Exception:
        pass

    svc = '/etc/systemd/system/takwerx-console.service'
    if not os.path.exists(svc) or not os.path.exists(venv_gunicorn):
        return
    with open(svc) as f:
        content = f.read()
    if 'gunicorn' in content:
        return
    settings = load_settings()
    port = settings.get('console_port', 5001)
    cert_dir = os.path.join(console_dir, '.config', 'ssl')
    ssl_args = ''
    if os.path.exists(os.path.join(cert_dir, 'console.crt')):
        ssl_args = f' --certfile={cert_dir}/console.crt --keyfile={cert_dir}/console.key'
    exec_line = (f'{venv_gunicorn} --bind 0.0.0.0:{port} --workers 1 --threads 8 '
                 f'--timeout 300 --graceful-timeout 30{ssl_args} app:app')
    content = re.sub(r'^ExecStart=.*$', f'ExecStart={exec_line}', content, flags=re.MULTILINE)
    with open(svc, 'w') as f:
        f.write(content)
    subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=10)


def _request_host_is_ip():
    """True if the request is to an IP address (backdoor), so we must not set cookie domain."""
    try:
        host = (request.host or '').split(':')[0]
        if not host:
            return True
        parts = host.split('.')
        if len(parts) != 4:
            return False
        return all(p.isdigit() and 0 <= int(p) <= 255 for p in parts)
    except Exception:
        return True

@app.before_request
def ensure_session_cookie_domain():
    """Pin the session cookie to the FQDN ONLY when the request actually arrives on the FQDN
    (SSO at infratak.<fqdn>, which needs the cross-subdomain cookie). For ANY other host — a bare
    IP, `localhost`, or the SSH-tunnel break-glass path — use a host-only cookie. Otherwise the
    browser silently drops a `.<fqdn>`-scoped cookie that was set over localhost/IP, the session
    never persists, and the break-glass login bounces back to /login ('flash'). The earlier code
    only special-cased a literal IP, so `https://localhost:5001` break-glass was broken on every
    box that has an FQDN configured. (Found 2026-06-13 validating W-IDLE break-glass on test6.)"""
    host = (request.host or '').split(':')[0].lower()
    fqdn = ''
    try:
        fqdn = (load_settings().get('fqdn') or '').split(':')[0].lower()
    except Exception:
        fqdn = ''
    if fqdn and (host == fqdn or host.endswith('.' + fqdn)):
        app.config['SESSION_COOKIE_DOMAIN'] = '.' + fqdn
    else:
        app.config['SESSION_COOKIE_DOMAIN'] = False

    # Baseline rate limiting
    ip = _client_ip()
    if request.method == 'POST' and request.path in ('/login', '/'):
        if _is_rate_limited(f'login:{ip}', limit=12, window_seconds=300):
            return jsonify({'error': 'Too many login attempts. Please wait a few minutes.'}), 429
    if request.method in ('POST', 'PUT', 'PATCH', 'DELETE') and request.path.startswith('/api/'):
        if _is_rate_limited(f'apiw:{ip}', limit=240, window_seconds=60):
            return jsonify({'error': 'Too many requests. Please slow down.'}), 429

    # CSRF baseline for state-changing API calls (same-origin only).
    # Exempt localhost-only Guard Dog script endpoint (not browser/session driven).
    if request.method in ('POST', 'PUT', 'PATCH', 'DELETE') and request.path.startswith('/api/'):
        if request.path not in ('/api/guarddog/send-sms', '/api/guarddog/send-alert-email'):
            if not _same_origin_ok():
                return jsonify({'error': 'CSRF validation failed (same-origin required).'}), 403


@app.after_request
def apply_security_headers(response):
    """Baseline browser hardening headers with compatibility for current inline-heavy UI."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['Referrer-Policy'] = 'strict-origin-when-cross-origin'
    response.headers['Permissions-Policy'] = 'geolocation=(), microphone=(), camera=()'
    # Keep CSP compatible with existing templates (inline script/style, CDN assets, data URLs).
    # v0.9.29 (security audit LOW): dropped 'unsafe-eval' — codebase has no
    # eval()/new Function()/string-form setTimeout. Inline scripts still
    # require 'unsafe-inline' (template surgery deferred to nonces).
    csp = (
        "default-src 'self' https: data: blob:; "
        "script-src 'self' 'unsafe-inline' https:; "
        "style-src 'self' 'unsafe-inline' https:; "
        "img-src 'self' data: https:; "
        "font-src 'self' data: https:; "
        "connect-src 'self' https: wss:; "
        "frame-ancestors 'none'; "
        "base-uri 'self'; "
        "form-action 'self'"
    )
    response.headers['Content-Security-Policy'] = csp
    # HSTS only when request itself is HTTPS (direct or via trusted proxy header).
    xf_proto = (request.headers.get('X-Forwarded-Proto') or '').lower()
    if request.is_secure or xf_proto == 'https':
        response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    return response
