def get_system_metrics():
    cpu = psutil.cpu_percent(interval=0.5)
    ram = psutil.virtual_memory()
    disk = psutil.disk_usage('/')
    boot = datetime.fromtimestamp(psutil.boot_time())
    uptime = datetime.now() - boot
    d, h, m = uptime.days, uptime.seconds // 3600, (uptime.seconds % 3600) // 60
    uu = _get_unattended_upgrades_status()
    return {'cpu_percent': cpu, 'ram_percent': round(ram.percent, 1),
        'ram_used_gb': round(ram.used / (1024**3), 1), 'ram_total_gb': round(ram.total / (1024**3), 1),
        'disk_percent': round(disk.percent, 1), 'disk_used_gb': round(disk.used / (1024**3), 1),
        'disk_total_gb': round(disk.total / (1024**3), 1), 'uptime': f"{d}d {h}h {m}m",
        'unattended_upgrades': uu}


def _get_remote_host_metrics(remote_cfg):
    """Return get_system_metrics()-style dict for a remote host via SSH, or None on failure."""
    if not remote_cfg or not (remote_cfg.get('host') or '').strip():
        return None
    # Run a script on remote (avoids SSH quoting issues with inline Python)
    script_content = '''import json, os, time
try:
    with open("/proc/meminfo") as f:
        d = dict(l.split(None, 1) for l in f if ":" in l)
    t = int(d.get("MemTotal:", "0").split()[0]) * 1024
    a = int((d.get("MemAvailable:") or d.get("MemFree:", "0")).split()[0]) * 1024
    u = t - a
    mem_pct = round(100 * u / t, 1) if t else 0
except Exception:
    mem_pct, u, t = 0, 0, 0
try:
    secs = float(open("/proc/uptime").read().split()[0])
    dd, hh, mm = int(secs // 86400), int((secs % 86400) // 3600), int((secs % 3600) // 60)
    uptime = f"{dd}d {hh}h {mm}m"
except Exception:
    uptime = "-"
try:
    s = os.statvfs("/")
    dt = s.f_blocks * s.f_frsize
    du = dt - s.f_bavail * s.f_frsize
    disk_pct = round(100 * du / dt, 1) if dt else 0
except Exception:
    disk_pct, du, dt = 0, 0, 0
try:
    def r1():
        with open("/proc/stat") as f:
            l = f.readline().split()
        total = sum(int(x) for x in l[1:5])
        idle = int(l[4])
        return total, idle
    t1, i1 = r1()
    time.sleep(1)
    t2, i2 = r1()
    cpu_pct = round((1 - (i2 - i1) / (t2 - t1)) * 100, 1) if (t2 - t1) else 0
except Exception:
    cpu_pct = 0
out = {
    "cpu_percent": cpu_pct,
    "ram_percent": mem_pct,
    "ram_used_gb": round(u / 1e9, 1),
    "ram_total_gb": round(t / 1e9, 1),
    "disk_percent": disk_pct,
    "disk_used_gb": round(du / 1e9, 1),
    "disk_total_gb": round(dt / 1e9, 1),
    "uptime": uptime,
}
print(json.dumps(out))
'''
    fd_m, tmp_path = tempfile.mkstemp(suffix='.py', prefix='infra_tak_metrics_')
    os.close(fd_m)
    try:
        with open(tmp_path, 'w') as f:
            f.write(script_content)
        deploy_cfg = {'target_mode': 'remote', 'remote': remote_cfg}
        copy_ok, _copy_msg = _module_copy(deploy_cfg, tmp_path, tmp_path, timeout=15)
        if not copy_ok:
            return None
        rp = shlex.quote(tmp_path)
        ok, out = _ssh_probe(
            remote_cfg,
            f'command -v python3 >/dev/null 2>&1 && python3 {rp} 2>/dev/null || python {rp} 2>/dev/null; rm -f {rp}',
            timeout=25,
        )
    except Exception:
        return None
    finally:
        try:
            os.remove(tmp_path)
        except Exception:
            pass
    if not ok or not out:
        return None
    raw = (out or '').strip()
    try:
        return json.loads(raw)
    except Exception:
        pass
    try:
        i, j = raw.find('{'), raw.rfind('}')
        if i >= 0 and j > i:
            return json.loads(raw[i : j + 1])
    except Exception:
        pass
    return None

def _get_unattended_upgrades_status():
    """Return dict with 'enabled' (bool) and 'running' (bool). 'running' = upgrade job active (not shutdown-waiter)."""
    enabled = False
    try:
        r = subprocess.run(_sudo_wrap(['systemctl', 'is-enabled', 'unattended-upgrades']), capture_output=True, text=True, timeout=5)
        enabled = (r.stdout or '').strip() == 'enabled'
    except Exception:
        pass
    running = False
    try:
        # Only "Running" when the timer-started upgrade job is active (apt-daily-upgrade.service)
        r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'apt-daily-upgrade.service']), capture_output=True, text=True, timeout=5)
        running = (r.stdout or '').strip() == 'active'
    except Exception:
        pass
    if not enabled:
        running = False
    return {'enabled': enabled, 'running': running}


def _get_unattended_upgrades_status_remote(remote_cfg):
    """Return {enabled, running} for unattended-upgrades on a remote host via SSH, or {error: str}."""
    if not remote_cfg or not (remote_cfg.get('host') or '').strip():
        return {'error': 'no host'}
    cmd = (
        'e=$(systemctl is-enabled unattended-upgrades 2>/dev/null); '
        'r=1; systemctl is-active apt-daily-upgrade.service 2>/dev/null | grep -qx active && r=0; '
        'echo "ENABLED=$e"; echo "RUNNING=$r"'
    )
    try:
        ok, out = _ssh_probe(remote_cfg, cmd, timeout=10)
        if not ok:
            return {'error': (out or 'ssh failed')[:80]}
        enabled = 'enabled' in (out or '')
        running = 'RUNNING=0' in (out or '')  # remote script: RUNNING=0 when process is running
        return {'enabled': enabled, 'running': running}
    except Exception as e:
        return {'error': str(e)[:80]}


def _build_uu_hosts(metrics, settings):
    """Build list of {id, label, enabled, running} for main console UU per-host cards."""
    hosts = [{
        'id': 'this_host',
        'label': 'This host',
        'enabled': metrics.get('unattended_upgrades', {}).get('enabled', False),
        'running': metrics.get('unattended_upgrades', {}).get('running', False),
    }]
    cfg = _get_tak_deployment_config(settings)
    if cfg.get('mode') == 'two_server':
        s1 = cfg.get('server_one', {})
        h = (s1.get('host') or '').strip()
        if h:
            remote = _get_unattended_upgrades_status_remote(s1)
            hosts.append({
                'id': 'tak_db',
                'label': 'TAK DB (' + h + ')',
                'enabled': remote.get('enabled', False) if 'error' not in remote else False,
                'running': remote.get('running', False) if 'error' not in remote else False,
                'error': remote.get('error'),
            })
    # Federation Hub remote host
    fh_cfg = _get_fedhub_deployment_config(settings)
    if fh_cfg.get('target_mode') == 'remote' and fh_cfg.get('deployed'):
        fh_host = (fh_cfg.get('remote', {}).get('host') or '').strip()
        if fh_host:
            fh_remote = _get_unattended_upgrades_status_remote(fh_cfg.get('remote', {}))
            hosts.append({
                'id': 'fedhub',
                'label': 'Fed Hub (' + fh_host + ')',
                'enabled': fh_remote.get('enabled', False) if 'error' not in fh_remote else False,
                'running': fh_remote.get('running', False) if 'error' not in fh_remote else False,
                'error': fh_remote.get('error'),
            })
    return hosts


def _get_total_ram_gb_local():
    """Return total RAM in GB from /proc/meminfo MemTotal (kB), or None."""
    try:
        with open('/proc/meminfo', 'r') as f:
            for line in f:
                if line.startswith('MemTotal:'):
                    parts = line.split()
                    if len(parts) >= 2:
                        return round(int(parts[1]) / (1024 * 1024), 2)  # kB -> GB
    except Exception:
        pass
    return None


def _get_total_ram_gb_remote(remote_cfg):
    """Return total RAM in GB on remote host via SSH, or None."""
    try:
        ok, out = _ssh_probe(remote_cfg, "awk '/MemTotal/{print $2/1024/1024}' /proc/meminfo 2>/dev/null", timeout=5)
        if ok and out:
            return round(float(out.strip()), 2)
    except Exception:
        pass
    return None


def _get_cpu_model_local():
    """Return CPU model name from /proc/cpuinfo (e.g. 'Intel Xeon ...'), or None."""
    try:
        with open('/proc/cpuinfo', 'r') as f:
            for line in f:
                if line.startswith('model name') or line.startswith('Processor'):
                    # "model name\t: Intel(R) Xeon(R) ..." or "Processor\t: ARMv7 ..."
                    idx = line.find(':')
                    if idx >= 0:
                        return line[idx + 1:].strip()
                    break
    except Exception:
        pass
    return None


def _get_vcpu_count_local():
    """Return number of vCPUs visible to the OS (nproc), or None."""
    try:
        import os as _os
        n = _os.cpu_count()
        if n:
            return n
    except Exception:
        pass
    try:
        r = subprocess.run(['nproc'], capture_output=True, text=True, timeout=5)
        v = r.stdout.strip()
        if v.isdigit():
            return int(v)
    except Exception:
        pass
    return None


def _get_cpu_model_remote(remote_cfg):
    """Return CPU model name on remote host via SSH, or None."""
    try:
        ok, out = _ssh_probe(remote_cfg, "grep -m1 -E 'model name|Processor' /proc/cpuinfo 2>/dev/null | sed 's/^[^:]*:[[:space:]]*//'", timeout=5)
        if ok and out:
            return out.strip() or None
    except Exception:
        pass
    return None


def _get_vcpu_count_remote(remote_cfg):
    """Return vCPU count on remote host via SSH, or None."""
    try:
        ok, out = _ssh_probe(remote_cfg, 'nproc 2>/dev/null', timeout=5)
        if ok and out and out.strip().isdigit():
            return int(out.strip())
    except Exception:
        pass
    return None


_GUARDDOG_DISKIO_CSV = '/var/lib/takguard/diskio_history.csv'


def _read_guarddog_csv_text(path):
    """Return the text of a root-owned Guard Dog state file (CSV) under
    /var/lib/takguard/, or None if absent/unreadable.

    v10.0.5 non-root: the disk-I/O CSVs are 0600 root:root (the probe runs as root
    under a systemd timer), so the non-root (takwerx) console must read them through
    the broker — the dir is broker allow-listed. A plain open() EPERMs, which is what
    made the Disk-I/O panel return "API error (500)" with all tiles blank while the
    rest of Guard Dog (0644 state) worked. As root, _read_priv falls back to a direct
    read, so behaviour is unchanged there."""
    try:
        if not os.path.exists(path):
            return None
        return _read_priv(path)
    except Exception:
        return None


def _read_guarddog_latest_write_mbs():
    """Return the most recent sync write speed (MB/s) from Guard Dog's diskio_history.csv, or None."""
    try:
        text = _read_guarddog_csv_text(_GUARDDOG_DISKIO_CSV)
        if text is None:
            return None
        last_val = None
        for line in text.splitlines():
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            parts = line.split(',')
            if len(parts) >= 2:
                try:
                    last_val = float(parts[1])
                except ValueError:
                    pass
        return last_val
    except Exception:
        return None


# v0.9.54: fleet-constant 4 KB commit-latency ceiling — mirrors WARN_MS_PER_COMMIT
# in scripts/guarddog/tak-diskio-watch.sh. Kept in sync by hand (two languages).
_GUARDDOG_DISKIO_LATENCY_CSV = '/var/lib/takguard/diskio_latency.csv'
_GUARDDOG_LAT_CEILING_MS = 10


def _guarddog_diskio_latency_1h_avg():
    """Return the 1h-average 4 KB commit latency (ms/commit) from Guard Dog's
    diskio_latency.csv, or None if the series is absent/empty. Mirrors the 1h
    window the bash latency gate uses (v0.9.54 §4c)."""
    try:
        text = _read_guarddog_csv_text(_GUARDDOG_DISKIO_LATENCY_CSV)
        if text is None:
            return None
        cutoff = datetime.utcnow() - timedelta(hours=1)
        vals = []
        for line in text.splitlines():
            line = line.strip()
            if not line or line.startswith('timestamp') or line.startswith('#'):
                continue
            parts = line.split(',')
            if len(parts) >= 3:
                try:
                    ts = datetime.strptime(parts[0], '%Y-%m-%dT%H:%M:%SZ')
                    if ts >= cutoff:
                        vals.append(float(parts[2]))
                except ValueError:
                    pass
        return (sum(vals) / len(vals)) if vals else None
    except Exception:
        return None


def _get_disk_io_local():
    """Return (read_mbs, write_mbs, source) from Guard Dog CSV (sync) or vmstat (cached). source is 'sync' or 'cached'."""
    # Prefer Guard Dog CSV — already uses dd oflag=dsync, trustworthy
    gd_write = _read_guarddog_latest_write_mbs()
    if gd_write is not None:
        return (None, gd_write, 'sync')
    try:
        r = subprocess.run(
            'vmstat 1 2 2>/dev/null | tail -1 | awk \'{print $9,$10}\'',
            shell=True, capture_output=True, text=True, timeout=5
        )
        if r.returncode != 0 or not (r.stdout or '').strip():
            return None
        parts = (r.stdout or '').strip().split()
        if len(parts) < 2:
            return None
        bi, bo = int(parts[0]), int(parts[1])
        # blocks/s, 512 bytes per block -> MB/s (buffer cache speed, not real disk throughput)
        read_mbs = round((bi * 512) / (1024 * 1024), 2)
        write_mbs = round((bo * 512) / (1024 * 1024), 2)
        return (read_mbs, write_mbs, 'cached')
    except Exception:
        return None


def _get_disk_io_remote(remote_cfg):
    """Return (read_mbs, write_mbs, source) on remote host. Prefers Guard Dog CSV (sync), falls back to vmstat (cached)."""
    if not remote_cfg or not (remote_cfg.get('host') or '').strip():
        return None
    try:
        # Try Guard Dog CSV first (sync, trustworthy)
        ok_gd, out_gd = _ssh_probe(
            remote_cfg,
            f"tail -20 {_GUARDDOG_DISKIO_CSV} 2>/dev/null | grep -v '^#' | grep ',' | tail -1",
            timeout=5
        )
        if ok_gd and out_gd and ',' in out_gd:
            parts = out_gd.strip().split(',')
            if len(parts) >= 2:
                try:
                    return (None, float(parts[1]), 'sync')
                except ValueError:
                    pass
        # Fall back to vmstat (cached)
        ok, out = _ssh_probe(
            remote_cfg,
            "vmstat 1 2 2>/dev/null | tail -1 | awk '{print $9,$10}'",
            timeout=8
        )
        if not ok or not out:
            return None
        parts = out.strip().split()
        if len(parts) < 2:
            return None
        bi, bo = int(parts[0]), int(parts[1])
        read_mbs = round((bi * 512) / (1024 * 1024), 2)
        write_mbs = round((bo * 512) / (1024 * 1024), 2)
        return (read_mbs, write_mbs, 'cached')
    except Exception:
        return None


# Disk speed test: 256 MiB. Prefer /var/tmp (on-disk); fallback to gettempdir() (may be tmpfs).
_DISK_SPEED_TEST_SIZE_MB = 256


def _disk_speed_test_path():
    """Return a writable path for the disk test file (local only). Prefer /var/tmp."""
    for d in ('/var/tmp', tempfile.gettempdir()):
        if d and os.path.isdir(d) and os.access(d, os.W_OK):
            return os.path.join(d, 'infra_tak_disk_speed_test')
    return None


def _parse_dd_speed_mbs(stderr_or_stdout):
    """Parse dd output for speed in MB/s, MiB/s, or GB/s. Returns MB/s."""
    if not stderr_or_stdout:
        return None
    text = (stderr_or_stdout or '').replace(',', '.')

    def to_mbs(num_str, unit_str):
        n = float(num_str)
        if unit_str and 'GB' in unit_str:
            return round(n * 1024, 1)
        return round(n, 1)

    m = re.search(r'copied,\s*[\d.]+\s*s,\s*([\d.]+)\s*(MiB|MB|GB)/s', text)
    if m:
        return to_mbs(m.group(1), m.group(2))
    for m in re.finditer(r'([\d.]+)\s*(MiB|MB|GB)/s', text):
        pass
    if m:
        return to_mbs(m.group(1), m.group(2))
    return None


import threading as _threading
_disk_speed_cache = {'result': None, 'ts': 0.0, 'running': False}
_disk_speed_lock = _threading.Lock()

def _run_disk_speed_test_local(use_cache=True):
    """NON-BLOCKING cached disk benchmark. The raw 256 MiB oflag=dsync write is slow
    on throttled/loaded disks (the SSD-Nodes boxes throttle intermittently), and
    running it synchronously on every /api/host-resource-usage click hogged a thread
    on the 1-worker console — which starved that endpoint AND "check for new release"
    (both 'Request failed'). This wrapper NEVER blocks the request: it returns the
    cached value immediately and, when the cache is cold/stale (>10 min), kicks the
    benchmark off in a background thread so the number appears on a later poll.
    First-ever call returns {} (no disk number yet) rather than waiting."""
    import time as _t
    now = _t.time()
    have = _disk_speed_cache['result'] is not None
    if use_cache and have and (now - _disk_speed_cache['ts'] < 600):
        return _disk_speed_cache['result']
    def _refresh():
        try:
            r = _run_disk_speed_test_local_impl()
        except Exception:
            r = {}
        _disk_speed_cache['result'] = r
        _disk_speed_cache['ts'] = _t.time()
        _disk_speed_cache['running'] = False
    with _disk_speed_lock:
        if not _disk_speed_cache['running']:
            _disk_speed_cache['running'] = True
            try:
                _threading.Thread(target=_refresh, daemon=True).start()
            except Exception:
                _disk_speed_cache['running'] = False
    return _disk_speed_cache['result'] if have else {}

def _run_disk_speed_test_local_impl():
    """Run 256 MiB sync write (oflag=dsync). Returns dict with disk_speed_test_write_mbs or disk_speed_test_error.
    Uses oflag=dsync to match start.sh and Guard Dog — measures real hardware throughput, not buffer cache."""
    path = _disk_speed_test_path()
    if not path:
        return {'disk_speed_test_error': 'no writable temp dir'}
    dd = '/usr/bin/dd' if os.path.isfile('/usr/bin/dd') else 'dd'
    try:
        rw = subprocess.run(
            [dd, 'if=/dev/zero', 'of=' + path,
             'bs=1M', 'count=' + str(_DISK_SPEED_TEST_SIZE_MB), 'oflag=dsync'],
            capture_output=True, text=True, timeout=120
        )
        out_w = (rw.stdout or '') + (rw.stderr or '')
        write_mbs = _parse_dd_speed_mbs(out_w)
        if write_mbs is None and rw.returncode != 0:
            rw2 = subprocess.run(
                [dd, 'if=/dev/zero', 'of=' + path, 'bs=1M', 'count=' + str(_DISK_SPEED_TEST_SIZE_MB)],
                capture_output=True, text=True, timeout=120
            )
            write_mbs = _parse_dd_speed_mbs((rw2.stdout or '') + (rw2.stderr or ''))
        if write_mbs is None:
            try:
                os.unlink(path)
            except Exception:
                pass
            err = (out_w.strip() or 'write failed')[:120]
            return {'disk_speed_test_error': err}
        rr = subprocess.run(
            [dd, 'if=' + path, 'of=/dev/null', 'bs=1M', 'iflag=direct'],
            capture_output=True, text=True, timeout=60
        )
        out_r = (rr.stdout or '') + (rr.stderr or '')
        read_mbs = _parse_dd_speed_mbs(out_r)
        if read_mbs is None and rr.returncode != 0:
            rr2 = subprocess.run(
                [dd, 'if=' + path, 'of=/dev/null', 'bs=1M'],
                capture_output=True, text=True, timeout=60
            )
            read_mbs = _parse_dd_speed_mbs((rr2.stdout or '') + (rr2.stderr or ''))
        try:
            os.unlink(path)
        except Exception:
            pass
        if read_mbs is None:
            return {'disk_speed_test_error': (out_r.strip() or 'read failed')[:120]}
        return {'disk_speed_test_read_mbs': read_mbs, 'disk_speed_test_write_mbs': write_mbs}
    except subprocess.TimeoutExpired:
        try:
            os.unlink(path)
        except Exception:
            pass
        return {'disk_speed_test_error': 'timeout'}
    except FileNotFoundError:
        return {'disk_speed_test_error': 'dd not found'}
    except OSError as e:
        return {'disk_speed_test_error': str(e)[:80]}


def _run_disk_speed_test_remote(remote_cfg):
    """Run same 256 MiB disk speed test on remote host via SSH. Returns dict with speeds or disk_speed_test_error."""
    if not remote_cfg or not (remote_cfg.get('host') or '').strip():
        return {'disk_speed_test_error': 'no host'}
    script = (
        'f=/var/tmp/infra_tak_disk_speed_test; '
        'touch "$f" 2>/dev/null || f=/tmp/infra_tak_disk_speed_test; '
        'dd if=/dev/zero of="$f" bs=1M count=' + str(_DISK_SPEED_TEST_SIZE_MB) + ' oflag=direct 2>&1; '
        'dd if="$f" of=/dev/null bs=1M iflag=direct 2>&1; '
        'rm -f /var/tmp/infra_tak_disk_speed_test /tmp/infra_tak_disk_speed_test 2>/dev/null'
    )
    try:
        ok, out = _ssh_probe(remote_cfg, script, timeout=90)
        if not ok:
            return {'disk_speed_test_error': (out or 'ssh failed')[:120]}
        if not out:
            return {'disk_speed_test_error': 'no output'}
        text = out.replace(',', '.')
        # Parse MB/s, MiB/s, or GB/s (convert GB to MB)
        all_speeds = []
        for match in re.finditer(r'([\d.]+)\s*(?:MiB|MB|GB)/s', text):
            num, suffix = float(match.group(1)), match.group(0)
            all_speeds.append(round(num * 1024, 1) if 'GB/s' in suffix else round(num, 1))
        if len(all_speeds) >= 2:
            return {'disk_speed_test_read_mbs': all_speeds[1], 'disk_speed_test_write_mbs': all_speeds[0]}
        # Fallback: "copied, X.XXX s" or truncated "copied, 0.3" (no " s"). Speed = 256/time.
        times = re.findall(r'copied,\s*([\d.]+)(?:\s*s)?', text)
        if len(times) >= 2:
            write_mbs = round(_DISK_SPEED_TEST_SIZE_MB / float(times[0]), 1)
            read_mbs = round(_DISK_SPEED_TEST_SIZE_MB / float(times[1]), 1)
            return {'disk_speed_test_read_mbs': read_mbs, 'disk_speed_test_write_mbs': write_mbs}
        return {'disk_speed_test_error': ('parse failed: ' + out.strip()[:80])}
    except Exception as e:
        return {'disk_speed_test_error': str(e)[:80]}


def _friendly_process_name(args):
    """Derive a recognizable name from process args (e.g. takserver, authentik, cloudtak, caddy, containers)."""
    a = (args or '').lower()
    if 'takserver' in a or 'tak-server' in a or 'core-api' in a or 'messaging' in a:
        return 'takserver'
    if 'authentik' in a:
        return 'authentik'
    if 'cloudtak' in a:
        return 'cloudtak'
    if 'caddy' in a:
        return 'caddy'
    if 'postgres' in a:
        return 'postgres'
    if 'redis' in a:
        return 'redis'
    if 'containerd' in a or 'runc' in a:
        return 'containerd/docker'
    if 'dockerd' in a or 'docker' in a:
        return 'docker'
    if 'guarddog' in a or 'guard_dog' in a:
        return 'guarddog'
    first = (args or '').strip().split(None, 1)[0] if (args or '').strip() else '?'
    return first.split('/')[-1] if first else '?'


def _top_processes_local():
    """Return { cpu_top, mem_top, total_ram_gb } with friendly names (takserver, authentik, etc.) and percentages."""
    try:
        total_ram_gb = _get_total_ram_gb_local()
        r = subprocess.run(
            'ps -eo pcpu,pmem,args --no-headers 2>/dev/null',
            shell=True, capture_output=True, text=True, timeout=5
        )
        out = (r.stdout or '').strip()
        by_name = {}
        for line in out.split('\n'):
            parts = line.split(None, 2)
            if len(parts) < 3:
                continue
            try:
                cpu = float(parts[0])
                mem = float(parts[1])
                name = _friendly_process_name((parts[2] or '').strip())
                if name and name != '?':
                    by_name[name] = by_name.get(name, {'cpu': 0, 'mem': 0})
                    by_name[name]['cpu'] += cpu
                    by_name[name]['mem'] += mem
            except (ValueError, IndexError):
                continue
        items = [{'name': n, 'cpu_pct': round(v['cpu'], 1), 'mem_pct': round(v['mem'], 1)} for n, v in by_name.items()]
        cpu_top = sorted(items, key=lambda x: -x['cpu_pct'])[:12]
        mem_top = sorted(items, key=lambda x: -x['mem_pct'])[:12]
        result = {'cpu_top': cpu_top, 'mem_top': mem_top}
        if total_ram_gb is not None:
            result['total_ram_gb'] = total_ram_gb
        cpu_model = _get_cpu_model_local()
        if cpu_model:
            result['processor'] = cpu_model
        vcpu = _get_vcpu_count_local()
        if vcpu:
            result['vcpu_count'] = vcpu
        disk_io = _get_disk_io_local()
        if disk_io is not None:
            result['disk_io_read_mbs'], result['disk_io_write_mbs'], result['disk_io_source'] = disk_io
        result.update(_run_disk_speed_test_local())
        return result
    except Exception:
        return {'cpu_top': [], 'mem_top': []}


def _top_processes_remote(remote_cfg):
    """Return { cpu_top, mem_top, total_ram_gb?, error? } with friendly names for remote host via SSH."""
    if not remote_cfg or not (remote_cfg.get('host') or '').strip():
        return {'cpu_top': [], 'mem_top': [], 'error': 'no host'}
    try:
        total_ram_gb = _get_total_ram_gb_remote(remote_cfg)
        ok, out = _ssh_probe(remote_cfg, 'ps -eo pcpu,pmem,args --no-headers 2>/dev/null', timeout=10)
        if not ok or not out:
            return {'cpu_top': [], 'mem_top': [], 'error': (out or 'ssh failed')[:80]}
        by_name = {}
        for line in (out or '').strip().split('\n'):
            parts = line.split(None, 2)
            if len(parts) < 3:
                continue
            try:
                cpu = float(parts[0])
                mem = float(parts[1])
                name = _friendly_process_name((parts[2] or '').strip())
                if name and name != '?':
                    by_name[name] = by_name.get(name, {'cpu': 0, 'mem': 0})
                    by_name[name]['cpu'] += cpu
                    by_name[name]['mem'] += mem
            except (ValueError, IndexError):
                continue
        items = [{'name': n, 'cpu_pct': round(v['cpu'], 1), 'mem_pct': round(v['mem'], 1)} for n, v in by_name.items()]
        cpu_top = sorted(items, key=lambda x: -x['cpu_pct'])[:12]
        mem_top = sorted(items, key=lambda x: -x['mem_pct'])[:12]
        result = {'cpu_top': cpu_top, 'mem_top': mem_top}
        if total_ram_gb is not None:
            result['total_ram_gb'] = total_ram_gb
        cpu_model = _get_cpu_model_remote(remote_cfg)
        if cpu_model:
            result['processor'] = cpu_model
        vcpu = _get_vcpu_count_remote(remote_cfg)
        if vcpu:
            result['vcpu_count'] = vcpu
        disk_io = _get_disk_io_remote(remote_cfg)
        if disk_io is not None:
            result['disk_io_read_mbs'], result['disk_io_write_mbs'], result['disk_io_source'] = disk_io
        result.update(_run_disk_speed_test_remote(remote_cfg))
        return result
    except Exception as e:
        return {'cpu_top': [], 'mem_top': [], 'error': str(e)[:80]}


# === Routes ===

def _login_logo_url():
    """URL for login page logo if static/takwerx-logo.png exists; else None (show ⚡)."""
    if os.path.exists(os.path.join(BASE_DIR, 'static', LOGIN_LOGO_FILENAME)):
        return url_for('static', filename=LOGIN_LOGO_FILENAME)
    return None

def _safe_next_path():
    """A validated SAME-SITE path from ?next= (or the posted form) for the post-login
    redirect. Used by the setup-AP captive to deep-link straight to the light
    /connectivity page on the offline AP (the heavy dashboard crawls with no internet).
    Local absolute paths only — never an off-site URL (open-redirect guard). Empty if
    absent/unsafe → caller falls back to the normal console page. The login form has no
    action= so it POSTs to the current URL, preserving ?next through the round-trip."""
    nxt = (request.args.get('next') or request.form.get('next') or '').strip()
    if nxt.startswith('/') and not nxt.startswith('//') and '://' not in nxt and '\\' not in nxt:
        return nxt
    return ''

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET' and _apply_authentik_session():
        return redirect(url_for('console_page'))
    logo_url = _login_logo_url()
    if request.method == 'POST':
        auth = load_auth()
        if not auth.get('password_hash'):
            return render_template_string(
                LOGIN_TEMPLATE,
                error='Password not set or wrong install path. Use backdoor: https://YOUR_SERVER_IP:5001 and run ./reset-console-password.sh from the install directory.',
                version=VERSION, login_logo_url=logo_url)
        if check_password_hash(auth['password_hash'], request.form.get('password', '')):
            session.clear()
            session['authenticated'] = True
            # W3: in Hardened posture, password login is the on-box break-glass path — audit it.
            audit('auth:login-password', 'console password / break-glass')
            return redirect(_safe_next_path() or url_for('console_page'))
        return render_template_string(LOGIN_TEMPLATE, error='Invalid password', version=VERSION, login_logo_url=logo_url)
    return render_template_string(LOGIN_TEMPLATE, error=None, version=VERSION, login_logo_url=logo_url)

@app.route('/logout', methods=['POST'])
def logout():
    audit('auth:logout', '')
    session.clear()
    return redirect(url_for('index'))

@app.route('/', methods=['GET', 'POST'])
def index():
    """Landing: login at / (infratak.fqdn); when logged in redirect to console. Authentik headers = auto-login."""
    logo_url = _login_logo_url()
    if request.method == 'GET' and _apply_authentik_session():
        return redirect(url_for('console_page'))
    if request.method == 'POST':
        auth = load_auth()
        if not auth.get('password_hash'):
            return render_template_string(
                LOGIN_TEMPLATE,
                error='Password not set or wrong install path. Use backdoor: https://YOUR_SERVER_IP:5001 and run ./reset-console-password.sh from the install directory.',
                version=VERSION, login_logo_url=logo_url)
        if check_password_hash(auth['password_hash'], request.form.get('password', '')):
            session['authenticated'] = True
            audit('auth:login-password', 'console password / break-glass')
            return redirect(_safe_next_path() or url_for('console_page'))
        return render_template_string(LOGIN_TEMPLATE, error='Invalid password', version=VERSION, login_logo_url=logo_url)
    if not session.get('authenticated'):
        return render_template_string(LOGIN_TEMPLATE, error=None, version=VERSION, login_logo_url=logo_url)
    return redirect(url_for('console_page'))

@app.route('/api/forward-auth')
def forward_auth():
    """Caddy forward_auth: return 200 if session is authenticated; else redirect to console login."""
    if session.get('authenticated'):
        return '', 200
    # Redirect to console login so user can log in and retry (Caddy passes this response to the client)
    settings = load_settings()
    fqdn = (settings.get('fqdn') or '').split(':')[0]
    if fqdn:
        login_url = f"https://infratak.{fqdn}/login"
        return redirect(login_url, code=302)
    return '', 401

@app.route('/console')
@login_required
def console_page():
    """Console: only installed/deployed services."""
    settings = load_settings()
    all_modules = detect_modules()
    modules = {k: m for k, m in all_modules.items() if m.get('installed')}
    try:
        module_versions = get_all_module_versions()
    except Exception:
        module_versions = {}
    metrics = get_system_metrics()
    uu_hosts = _build_uu_hosts(metrics, settings)
    # Server-side update state — used to render a no-JS-required banner so broken
    # JS (e.g. the v0.9.31 SyntaxError) can't strand users who can't see the banner.
    _srv_update = False
    _srv_latest = ''
    try:
        _cached = update_cache.get('latest')
        if _cached and (time.time() - update_cache.get('checked', 0)) < 7200:
            _cv = tuple(int(p) for p in VERSION.replace('-alpha','').replace('-beta','').split('.'))
            _lv = tuple(int(p) for p in _cached.replace('-alpha','').replace('-beta','').split('.'))
            _srv_update = _lv > _cv
            if _srv_update:
                _srv_latest = _cached
    except Exception:
        pass
    resp = render_template_string(CONSOLE_TEMPLATE,
        settings=settings, modules=modules, metrics=metrics, version=VERSION,
        module_versions=module_versions, authentik_base_url=_get_authentik_base_url(settings),
        takserver_base_url=_get_takserver_base_url(settings), uu_hosts=uu_hosts,
        srv_update_available=_srv_update, srv_latest=_srv_latest)
    from flask import make_response
    r = make_response(resp)
    r.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    return r

# ============================================================================
# "Harden This Box" — Compliance Hardening Module  (v0.9.55, smell-test core)
# ----------------------------------------------------------------------------
# A post-assembly security-posture toggle. The DEFAULT is "standard" — a box
# that never presses the button (cloud OR edge) behaves exactly as today; the
# absence of hardening.json == standard posture, and every runtime hook below
# no-ops unless posture == 'hardened'. Hardening is explicit, reversible, and
# transactional (W6): apply runs controls in order and rolls back every applied
# control if any one fails, so the flip can never half-land. Recovery is always
# the on-box break-glass path (reset-console-password.sh) — never a network
# backdoor. Controls land per W-item: W2 (session lock) here; W3/W4/W1 follow.
# Parent plan: infra-TAK-notes/docs/PLAN-v0.9.55-harden-this-box.md
# ============================================================================

HARDENING_CONFIG = 'hardening.json'
SESSION_IDLE_MAX_DEFAULT = 1800  # 30 min — CJIS idle-lock ceiling (W2), fleet-uniform constant

def load_hardening():
    """Load hardening.json from CONFIG_DIR (mtime-cached via _load_json_cached — see there
    for the per-request thread-starvation regression this fixes). Never raises — {} on
    missing/error. Missing file == Standard posture (both cloud and edge)."""
    return _load_json_cached(os.path.join(CONFIG_DIR, HARDENING_CONFIG))

def save_hardening(h):
    os.makedirs(CONFIG_DIR, exist_ok=True)
    p = os.path.join(CONFIG_DIR, HARDENING_CONFIG)
    with open(p, 'w') as f:
        json.dump(h, f, indent=2)
    try:
        os.chmod(p, 0o600)
    except Exception:
        pass

def _hardening_posture():
    return (load_hardening().get('posture') or 'standard')

def is_hardened():
    return _hardening_posture() == 'hardened'

# --- W2: 30-minute server-side session idle lock ---------------------------
# --- W-IDLE (v0.9.56): make that lock truly re-prompt under SSO ------------
WIDLE_STATE_KEY = 'WIDLE_sso'
# The forward_auth embedded outpost's sign-out path. Lives on the protected host
# (infratak.<fqdn>); Caddy routes /outpost.goauthentik.io/* to the Authentik outpost.
# Hitting it clears the outpost session so the next request forces a full re-prompt.
# (Confirm the exact path on a live forward_auth box before declaring the gap closed.)
AK_FORWARD_AUTH_SIGNOUT = '/outpost.goauthentik.io/sign_out'

def _widle_sso_logout_active(h):
    """v0.9.56 W-IDLE — True when an idle lock must force a TRUE SSO re-prompt by signing the
    browser out of the forward_auth outpost (not merely clearing the Flask session). Requires:
    the W-IDLE control applied, W1 has SSO-locked the console, AND this very request arrived
    through forward_auth — it carries the X-Authentik-Username header the local Caddy proxy
    injects. That last check is essential: the console is ALSO reachable on the loopback
    break-glass path (127.0.0.1:5001 direct / SSH tunnel) where there is no outpost to sign out
    of and /outpost.goauthentik.io/* is not served by gunicorn (a sign-out redirect there just
    times out). On that path this returns False and W2 falls back to the plain console /login."""
    try:
        if not ((h.get('applied') or {}).get(WIDLE_STATE_KEY) and _w1_console_locked()):
            return False
        return bool(request.headers.get('X-Authentik-Username'))
    except Exception:
        return False

# The W2 control's apply/verify/revert only record intent in hardening.json; the
# authoritative enforcement is this before_request hook, always present but only
# biting when posture == 'hardened'. On the password-auth path, clearing the Flask
# session IS the full lock. Under SSO (W1) that alone is silently re-authed by
# forward_auth against a still-live Authentik session — so when W-IDLE is armed we
# additionally sign the browser out of the outpost, forcing a fresh login + MFA.
# Fail-safe: the Flask session is cleared first, so even if sign-out is unreachable
# the local lock still holds (it just may silently re-auth on that box — which is
# why the SSO re-prompt is not claimed working until validated on a real box).
@app.before_request
def _enforce_session_idle_lock():
    try:
        if not session.get('authenticated'):
            return  # not logged in — nothing to lock
        h = load_hardening()
        if (h.get('posture') or 'standard') != 'hardened':
            return
        a = (h.get('applied') or {}).get('W2_session') or {}
        idle_max = int(a.get('idle_max_seconds', SESSION_IDLE_MAX_DEFAULT))
        now = int(time.time())
        last = session.get('last_activity')
        # "Activity" must mean a real USER action, not the page's own background polling.
        # The console dashboard auto-refreshes /api/metrics every 5s, module cards every 8s,
        # etc. — if every request reset the clock, last_activity would never age past a few
        # seconds and the idle lock could NEVER fire while a tab is open (it silently didn't —
        # caught in v0.9.56 W-IDLE validation; the shipped W2 lock had the same hole). So a
        # read-only GET to /api/* (a poll/data-fetch) does NOT count as activity; only a page
        # navigation (non-/api GET) or a state-changing call (POST/PUT/PATCH/DELETE) does.
        is_poll = request.path.startswith('/api/') and request.method == 'GET'
        if last is not None and (now - int(last)) > idle_max:
            if request.path.startswith('/api/'):
                # Don't reset the clock or kill the SSO session on a background poll — just
                # signal expiry. The true re-prompt fires on the next full-page navigation.
                return jsonify({'error': 'Session expired (idle lock).', 'login_required': True}), 401
            session.clear()  # local lock always holds, regardless of what follows
            if _widle_sso_logout_active(h):
                # Sign out of the forward_auth outpost so the next request re-prompts. Use the
                # ABSOLUTE SSO URL captured at apply time — request.host/host_url are the loopback
                # upstream Caddy proxies to (127.0.0.1:5001), not the SSO vhost. Lazily fall back to
                # https://infratak.<fqdn> for sessions armed before this URL was stored.
                surl = ((h.get('applied') or {}).get(WIDLE_STATE_KEY) or {}).get('signout_url')
                if not surl:
                    fqdn = (load_settings() or {}).get('fqdn')
                    if fqdn:
                        surl = 'https://infratak.%s%s' % (fqdn, AK_FORWARD_AUTH_SIGNOUT)
                if surl:
                    return redirect(surl)
            return redirect(url_for('login'))
        if not is_poll:
            session['last_activity'] = now
    except Exception:
        # A lock failure must never brick a request — fail open to the normal flow.
        return

# v0.9.58: the auto-reload "Session expired — signing you back in…" band-aid was REMOVED.
# It masked the real problem (and reload-looped when the Authentik proxy session lapsed
# fast). The real fix is in generate_caddyfile(): /api/* now BYPASSES the Authentik
# forward_auth, so background XHR hit the console directly and get a clean same-origin 401
# (or just succeed via the console session) instead of a cross-origin OAuth redirect that
# the browser CORS-blocks. No client-side reload hack needed.

def _hardening_control_w2():
    """W2 — 30-minute server-side session lock."""
    def apply_(h, log):
        h.setdefault('applied', {})['W2_session'] = {'idle_max_seconds': SESSION_IDLE_MAX_DEFAULT}
        log('W2: session idle lock armed (%d min)' % (SESSION_IDLE_MAX_DEFAULT // 60))
        return True
    def verify(h):
        a = (h.get('applied') or {}).get('W2_session')
        if not a:
            return (False, 'session idle lock not applied')
        return (True, 'idle lock = %d min' % (int(a.get('idle_max_seconds', SESSION_IDLE_MAX_DEFAULT)) // 60))
    def revert(h, log):
        (h.get('applied') or {}).pop('W2_session', None)
        log('W2: session idle lock disarmed')
        return True
    return {'key': 'W2_session', 'title': '30-minute session lock',
            'desc': 'Server-side idle timeout forces re-authentication after 30 minutes (CJIS 5.5.5).',
            'apply': apply_, 'verify': verify, 'revert': revert}

def _hardening_control_widle():
    """W-IDLE (v0.9.56) — make the W2 idle lock truly re-prompt under SSO. With W1's forward_auth
    ingress, a plain session.clear() is silently re-authed by Authentik; this arms the W2 hook
    (_enforce_session_idle_lock) to instead sign the browser out of the forward_auth outpost on
    idle. State-only control — the enforcement is the always-present hook, gated on this applied
    flag AND W1 having SSO-locked the console (so it is inert on a password-only box)."""
    def apply_(h, log):
        # Capture the console's ABSOLUTE SSO sign-out URL now. It can't be built per-request:
        # Caddy proxies to gunicorn with the upstream Host (127.0.0.1:5001), so request.host /
        # request.host_url are the loopback origin, not the SSO vhost. Derive it from the
        # infra-TAK proxy provider's external_host (fallback: https://infratak.<fqdn>).
        ak_url, ak_headers, settings = _w1_ak_ctx()
        signout_url = None
        try:
            if ak_url:
                for p in _w1_ak_get(ak_url, 'providers/proxy/?page_size=100', ak_headers).get('results', []):
                    eh = (p.get('external_host') or '').rstrip('/')
                    if eh and 'infratak' in eh:
                        signout_url = eh + AK_FORWARD_AUTH_SIGNOUT
                        break
        except Exception as e:
            log('W-IDLE: proxy lookup failed (%s)' % str(e)[:80])
        if not signout_url:
            fqdn = (settings or {}).get('fqdn')
            if fqdn:
                signout_url = 'https://infratak.%s%s' % (fqdn, AK_FORWARD_AUTH_SIGNOUT)
        h.setdefault('applied', {})[WIDLE_STATE_KEY] = {
            'mode': 'sso_signout', 'signout_path': AK_FORWARD_AUTH_SIGNOUT, 'signout_url': signout_url}
        log('W-IDLE: SSO idle-lock re-prompt armed (sign-out → %s)'
            % (signout_url or '(unresolved → /login fallback)'))
        return True
    def verify(h):
        a = (h.get('applied') or {}).get(WIDLE_STATE_KEY)
        if not a:
            return (False, 'SSO idle-lock re-prompt not armed')
        if not _w1_console_locked():
            return (True, 'armed; inert until W1 SSO-locks the console')
        return (True, 'idle lock forces SSO re-auth via %s' % (a.get('signout_url') or AK_FORWARD_AUTH_SIGNOUT))
    def revert(h, log):
        (h.get('applied') or {}).pop(WIDLE_STATE_KEY, None)
        log('W-IDLE: SSO idle-lock re-prompt disarmed (W2 falls back to local session clear)')
        return True
    return {'key': WIDLE_STATE_KEY, 'title': 'SSO idle-lock re-prompt',
            'desc': 'Under SSO the 30-minute idle lock signs you out of Authentik, so re-access needs '
                    'a fresh login + MFA instead of a silent re-auth. Because an SSO session is shared, '
                    'this logs you out of all Authentik-fronted apps at once.',
            'apply': apply_, 'verify': verify, 'revert': revert}

# --- W3: local per-user audit log (JSONL) ----------------------------------
# Records who/what/when for admin actions. Hardened-posture only, so a Standard
# box writes nothing (today's behavior preserved). JSONL now → clean CEF/syslog
# export when off-box shipping lands in .56. Off-box shipping + 365-day retention
# are NOT in .55 — this is local-only.
AUDIT_DIR_NAME = 'audit'
AUDIT_LOG_NAME = 'console-audit.log'
_AUDIT_MAX_BYTES = 5 * 1024 * 1024  # rotate to .1 past 5 MB; kept local

def _audit_path():
    return os.path.join(CONFIG_DIR, AUDIT_DIR_NAME, AUDIT_LOG_NAME)

def audit(event, detail='', force=False):
    """Append a structured JSONL audit line. Hardened-posture only unless force=True
    (used for posture-flip events that may transition out of hardened). Never raises."""
    try:
        if not force and not is_hardened():
            return
        d = os.path.join(CONFIG_DIR, AUDIT_DIR_NAME)
        os.makedirs(d, exist_ok=True)
        p = os.path.join(d, AUDIT_LOG_NAME)
        try:
            if os.path.exists(p) and os.path.getsize(p) > _AUDIT_MAX_BYTES:
                os.replace(p, p + '.1')
        except Exception:
            pass
        try:
            user = session.get('authentik_username') or ('console-admin' if session.get('authenticated') else 'anonymous')
        except Exception:
            user = 'system'
        try:
            ip = _client_ip()
        except Exception:
            ip = 'unknown'
        line = json.dumps({
            'ts': datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
            'user': user, 'ip': ip, 'event': event, 'detail': str(detail)[:500],
        }, separators=(',', ':'))
        with open(p, 'a') as f:
            f.write(line + '\n')
        try:
            os.chmod(p, 0o600)
        except Exception:
            pass
        # W7: also queue the line for off-box shipping (fail-open; never blocks here).
        try:
            if _offbox_enabled():
                _offbox_spool(line)
        except Exception:
            pass
    except Exception:
        pass

def _audit_tail(n=50):
    out = []
    try:
        p = _audit_path()
        if os.path.exists(p):
            with open(p) as f:
                for ln in f.readlines()[-n:]:
                    try:
                        out.append(json.loads(ln))
                    except Exception:
                        pass
    except Exception:
        pass
    return out

# Generic admin-action audit: one after_request hook attributes every state-changing
# /api/* call instead of hand-instrumenting 300+ routes. Hardened-gated, with a
# small denylist for poll/health noise.
_AUDIT_SKIP_PATHS = ('/api/hardening/status', '/api/hardening/audit',
                     '/api/guarddog/send-sms', '/api/guarddog/send-alert-email')

@app.after_request
def _audit_state_changes(response):
    try:
        if (request.method in ('POST', 'PUT', 'PATCH', 'DELETE')
                and request.path.startswith('/api/')
                and request.path not in _AUDIT_SKIP_PATHS
                and is_hardened()):
            audit('api:' + request.method + ' ' + request.path, 'status=%s' % response.status_code)
    except Exception:
        pass
    return response

# ---- W7: off-box immutable audit shipping (v0.9.56) -----------------------
# Local JSONL (W3) stays the source of truth; W7 mirrors each audit line to an
# off-box sink so the >=365-day copy lives where the box admin cannot rewrite it.
# Pluggable: syslog/CEF -> SIEM, or S3-compatible Object-Lock (WORM) bucket.
# Fail-open + buffered: audit() spools locally; a background thread flushes with
# retry. A sink failure never blocks a request or the posture flip, and the
# backlog is surfaced (never silently dropped). Resolves the retention-vs-load
# tension with W8: short LOCAL Authentik/console retention, the compliance copy off-box.
OFFBOX_SPOOL_NAME = 'offbox-spool.jsonl'
OFFBOX_RETENTION_FLOOR = 365            # fleet floor (days); an agency may set higher, never lower
_offbox_status = {'last_ship_ts': None, 'last_error': None, 'shipped_total': 0}
_OFFBOX_LOCK = threading.Lock()

def _offbox_spool_path():
    return os.path.join(CONFIG_DIR, AUDIT_DIR_NAME, OFFBOX_SPOOL_NAME)

def _offbox_config():
    return (load_hardening().get('offbox_config') or {})

def _offbox_enabled():
    h = load_hardening()
    if (h.get('posture') or 'standard') != 'hardened':
        return False
    if not (h.get('applied') or {}).get('W7_offbox', {}).get('active'):
        return False
    return (h.get('offbox_config') or {}).get('mode', 'off') in ('syslog', 's3objlock')

def _offbox_spool(line_str):
    try:
        os.makedirs(os.path.join(CONFIG_DIR, AUDIT_DIR_NAME), exist_ok=True)
        p = _offbox_spool_path()
        with open(p, 'a') as f:
            f.write(line_str + '\n')
        os.chmod(p, 0o600)
    except Exception:
        pass

def _offbox_backlog():
    try:
        p = _offbox_spool_path()
        if not os.path.exists(p):
            return 0
        with open(p) as f:
            return sum(1 for ln in f if ln.strip())
    except Exception:
        return 0

def _offbox_to_cef(rec):
    """Map one audit record to a CEF line (ArcSight-style) for SIEM ingestion."""
    hdr = 'CEF:0|infra-TAK|console|%s|audit|%s|3|' % (VERSION, rec.get('event', 'event'))
    ext = 'rt=%s suser=%s src=%s msg=%s' % (
        rec.get('ts', ''), rec.get('user', ''), rec.get('ip', ''),
        str(rec.get('detail', '')).replace('\n', ' ').replace('=', '\\='))
    return hdr + ext

def _offbox_ship_syslog(lines, cfg):
    """Ship spooled audit lines as RFC5424/CEF over TCP (optionally TLS). Returns
    (n_shipped, error_or_None); never raises — the error is surfaced via status."""
    import socket as _socket, ssl as _ssl
    sink = cfg.get('syslog') or {}
    host = sink.get('host'); port = int(sink.get('port') or 6514)
    if not host:
        return (0, 'no syslog host configured')
    use_tls = sink.get('tls', True)
    fqdn = (load_settings().get('fqdn') or 'console')
    try:
        raw = _socket.create_connection((host, port), timeout=10)
        sock = _ssl.create_default_context().wrap_socket(raw, server_hostname=host) if use_tls else raw
    except Exception as e:
        return (0, 'connect %s:%s failed: %s' % (host, port, str(e)[:120]))
    n = 0
    try:
        for ln in lines:
            try:
                rec = json.loads(ln)
            except Exception:
                continue
            # RFC5424 framing with octet-counting (TCP), local0.info; payload is CEF.
            frame = '<134>1 %s %s infra-TAK - - - %s' % (rec.get('ts', '-'), fqdn, _offbox_to_cef(rec))
            b = frame.encode()
            sock.sendall(('%d ' % len(b)).encode() + b)
            n += 1
    except Exception as e:
        return (n, 'send failed after %d: %s' % (n, str(e)[:120]))
    finally:
        try:
            sock.close()
        except Exception:
            pass
    return (n, None)

def _offbox_ship_s3(lines, cfg):
    """Ship the spooled audit lines as ONE immutable S3 Object-Lock (WORM) segment via a
    SigV4-signed PUT — no boto3 dependency. Object-Lock mode=COMPLIANCE with
    retain-until = now + retention_days makes the object un-deletable / un-overwritable
    (even by the account root) until that date — the WORM guarantee for ≥365d audit.
    Path-style when an `endpoint` is configured (MinIO — the validation target — and any
    S3-compatible store); AWS virtual-host style otherwise. Fail-CLOSED: returns
    (0, reason) on ANY error so the spool is RETAINED and surfaced, never dropped.
    Returns (n_shipped, error_or_None); never raises.
    Validate (v0.9.58 #3) against a local MinIO Object-Lock bucket: write probe →
    confirm immutable read-back → attempt delete/overwrite → confirm REFUSED."""
    import hashlib as _hl, hmac as _hmac, urllib.request as _ur, urllib.error as _ue
    s3 = cfg.get('s3') or {}
    bucket = (s3.get('bucket') or '').strip().strip('/')
    region = (s3.get('region') or 'us-east-1').strip()
    access_key = (s3.get('access_key') or '').strip()
    secret_key = (s3.get('secret_key') or '').strip()
    if not (bucket and access_key and secret_key):
        return (0, 's3 sink incomplete (need bucket + access_key + secret_key)')
    endpoint = (s3.get('endpoint') or '').strip().rstrip('/')
    prefix = (s3.get('prefix') or 'infratak-audit').strip().strip('/')
    retention_days = max(OFFBOX_RETENTION_FLOOR, int(cfg.get('retention_days') or OFFBOX_RETENTION_FLOOR))

    body = ('\n'.join(lines) + '\n').encode('utf-8')
    payload_hash = _hl.sha256(body).hexdigest()
    now = datetime.utcnow()
    amzdate = now.strftime('%Y%m%dT%H%M%SZ')
    datestamp = now.strftime('%Y%m%d')
    retain_until = (now + timedelta(days=retention_days)).strftime('%Y-%m-%dT%H:%M:%SZ')

    fqdn = (load_settings().get('fqdn') or 'console').split(':')[0]
    key = '%s/%s/%s/audit-%s-%s.jsonl' % (prefix, fqdn, now.strftime('%Y/%m/%d'),
                                          amzdate, payload_hash[:12])

    if endpoint:  # path-style: <endpoint>/<bucket>/<key>  (MinIO / S3-compatible)
        host = endpoint.split('://', 1)[-1].split('/', 1)[0]
        raw_uri = '/%s/%s' % (bucket, key)
        url = '%s/%s/%s' % (endpoint, bucket, key)
    else:         # AWS virtual-host: <bucket>.s3.<region>.amazonaws.com/<key>
        host = '%s.s3.%s.amazonaws.com' % (bucket, region)
        raw_uri = '/' + key
        url = 'https://%s/%s' % (host, key)
    # canonical URI: encode each path segment, preserve the slashes
    canonical_uri = '/'.join(_ur.quote(seg, safe='') for seg in raw_uri.split('/'))

    headers = {
        'host': host,
        'content-type': 'application/x-ndjson',
        'x-amz-content-sha256': payload_hash,
        'x-amz-date': amzdate,
        'x-amz-object-lock-mode': 'COMPLIANCE',
        'x-amz-object-lock-retain-until-date': retain_until,
    }
    signed_headers = ';'.join(sorted(headers))
    canonical_headers = ''.join('%s:%s\n' % (k, headers[k]) for k in sorted(headers))
    canonical_request = '\n'.join(['PUT', canonical_uri, '', canonical_headers,
                                   signed_headers, payload_hash])

    algorithm = 'AWS4-HMAC-SHA256'
    scope = '%s/%s/s3/aws4_request' % (datestamp, region)
    string_to_sign = '\n'.join([algorithm, amzdate, scope,
                                _hl.sha256(canonical_request.encode()).hexdigest()])

    def _sign(k, msg):
        return _hmac.new(k, msg.encode(), _hl.sha256).digest()
    k_signing = _sign(_sign(_sign(_sign(('AWS4' + secret_key).encode(), datestamp),
                                  region), 's3'), 'aws4_request')
    signature = _hmac.new(k_signing, string_to_sign.encode(), _hl.sha256).hexdigest()
    authz = '%s Credential=%s/%s, SignedHeaders=%s, Signature=%s' % (
        algorithm, access_key, scope, signed_headers, signature)

    req = _ur.Request(url, data=body, method='PUT')
    for k in headers:
        req.add_header(k, headers[k])
    req.add_header('Authorization', authz)
    try:
        resp = _ur.urlopen(req, timeout=20)
        code = resp.getcode()
        resp.read()
        if 200 <= code < 300:
            return (len(lines), None)
        return (0, 's3 PUT returned HTTP %s' % code)
    except _ue.HTTPError as e:
        detail = ''
        try:
            detail = e.read().decode('utf-8', 'replace')[:200]
        except Exception:
            pass
        return (0, 's3 PUT HTTP %s: %s' % (e.code, detail))
    except Exception as e:
        return (0, 's3 PUT failed: %s' % str(e)[:160])

def _offbox_flush_once():
    """Flush the spool to the configured sink; drop only the confirmed-shipped prefix
    (partial-success safe). Never raises."""
    if not _offbox_enabled():
        return
    with _OFFBOX_LOCK:
        p = _offbox_spool_path()
        try:
            if not os.path.exists(p):
                return
            with open(p) as f:
                lines = [ln.rstrip('\n') for ln in f if ln.strip()]
        except Exception:
            return
        if not lines:
            return
        cfg = _offbox_config()
        mode = cfg.get('mode')
        if mode == 'syslog':
            n, err = _offbox_ship_syslog(lines, cfg)
        elif mode == 's3objlock':
            n, err = _offbox_ship_s3(lines, cfg)
        else:
            return
        if n > 0:  # rewrite the spool with the un-shipped remainder
            try:
                rest = lines[n:]
                with open(p, 'w') as f:
                    f.write(('\n'.join(rest) + '\n') if rest else '')
                os.chmod(p, 0o600)
            except Exception:
                pass
        _offbox_status['shipped_total'] += n
        _offbox_status['last_error'] = err
        if not err:
            _offbox_status['last_ship_ts'] = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

def _offbox_shipper_loop():
    while True:
        try:
            _offbox_flush_once()
        except Exception:
            pass
        time.sleep(15)

def _offbox_status_snapshot():
    cfg = _offbox_config()
    return {
        'mode': cfg.get('mode', 'off'),
        'enabled': _offbox_enabled(),
        'retention_days': int(cfg.get('retention_days') or OFFBOX_RETENTION_FLOOR),
        'backlog': _offbox_backlog(),
        'last_ship_ts': _offbox_status['last_ship_ts'],
        'last_error': _offbox_status['last_error'],
        'shipped_total': _offbox_status['shipped_total'],
        'syslog_host': (cfg.get('syslog') or {}).get('host'),
        's3_bucket': (cfg.get('s3') or {}).get('bucket'),
    }

# Start the background shipper once (daemon; idle-cheap when W7 is off).
try:
    threading.Thread(target=_offbox_shipper_loop, daemon=True, name='offbox-shipper').start()
except Exception:
    pass

def _hardening_control_w7():
    """W7 — off-box immutable audit shipping. Activates the shipper when a sink is
    configured; otherwise applies in an honest 'armed but no sink' state the report flags
    (hardening can still complete, but the report tells the truth — no false green)."""
    def apply_(h, log):
        mode = (h.get('offbox_config') or {}).get('mode', 'off')
        h.setdefault('applied', {})['W7_offbox'] = {'active': True, 'mode': mode}
        if mode in ('syslog', 's3objlock'):
            log('W7: off-box audit shipping active (mode=%s)' % mode)
        else:
            log('W7: off-box audit armed but NO sink configured — set one in Cyber Controls; '
                'audit ships nowhere until then (local W3 audit still retained).')
        return True
    def verify(h):
        a = (h.get('applied') or {}).get('W7_offbox')
        if not a:
            return (False, 'off-box audit not applied')
        cfg = h.get('offbox_config') or {}
        mode = cfg.get('mode', 'off')
        if mode not in ('syslog', 's3objlock'):
            return (True, 'armed; no off-box sink configured (local audit only)')
        err = _offbox_status.get('last_error')
        bl = _offbox_backlog()
        if err and bl:
            return (False, 'sink error (%s); %d lines backlogged' % (str(err)[:60], bl))
        return (True, 'shipping via %s; backlog=%d, retention>=%dd'
                % (mode, bl, int(cfg.get('retention_days') or OFFBOX_RETENTION_FLOOR)))
    def revert(h, log):
        (h.get('applied') or {}).pop('W7_offbox', None)
        log('W7: off-box shipping stopped; local audit + already-shipped immutable records retained')
        return True
    return {'key': 'W7_offbox', 'title': 'Off-box immutable audit',
            'desc': 'Mirrors the audit trail off-box (syslog/CEF to a SIEM, or an S3 Object-Lock '
                    'WORM bucket) so the >=365-day record lives where the box admin cannot rewrite '
                    'it. Local audit (W3) stays the source of truth.',
            'apply': apply_, 'verify': verify, 'revert': revert}

def _hardening_control_w3():
    """W3 — local per-user audit log. One-way (you don't un-audit), so revert keeps it."""
    def apply_(h, log):
        os.makedirs(os.path.join(CONFIG_DIR, AUDIT_DIR_NAME), exist_ok=True)
        h.setdefault('applied', {})['W3_audit'] = {'path': _audit_path(), 'enabled': True}
        log('W3: per-user audit log enabled at ' + _audit_path())
        return True
    def verify(h):
        a = (h.get('applied') or {}).get('W3_audit')
        if not a:
            return (False, 'audit not enabled')
        d = os.path.join(CONFIG_DIR, AUDIT_DIR_NAME)
        ok = os.path.isdir(d) and os.access(d, os.W_OK)
        return (ok, ('writable: ' + _audit_path()) if ok else 'audit dir present but not writable')
    def revert(h, log):
        log('W3: audit log retained (one-way control)')
        return True
    return {'key': 'W3_audit', 'title': 'Per-user audit log',
            'desc': 'Records who/what/when for admin actions locally; W7 ships these off-box immutably.',
            'apply': apply_, 'verify': verify, 'revert': revert}

# --- W4: port / boundary assertions (read-only; verify, don't rebuild) ------
# Reuses the existing UFW + fail2ban machinery and reports pass/fail for the W5
# report. Mutates nothing. Where a TAK/Tomcat surface cannot be reliably evaluated
# from here, the assertion is 'na' with an honest note — never a false green
# (CLAUDE.md "no silent caps"). Deep Tomcat STIG remediation is .57.

def _ufw_default_incoming_deny():
    """True if the host firewall denies incoming by default. firewalld: the default
    zone is default-drop unless its target is ACCEPT (so an active firewalld with the
    public zone IS deny-by-default). UFW: parse `ufw status verbose`. None = can't read.
    Name kept for back-compat; covers both backends."""
    if _fw_backend() == 'firewalld':
        try:
            rs = subprocess.run(_sudo_wrap(['firewall-cmd', '--state']),
                                capture_output=True, text=True, timeout=8)
            if (rs.stdout or '').strip() != 'running':
                return False
            dz = subprocess.run(_sudo_wrap(['firewall-cmd', '--get-default-zone']),
                                capture_output=True, text=True, timeout=8)
            zone = (dz.stdout or '').strip() or 'public'
            # --get-target requires --permanent; without it firewall-cmd errors out.
            tg = subprocess.run(_sudo_wrap(['firewall-cmd', '--permanent', f'--zone={zone}', '--get-target']),
                                capture_output=True, text=True, timeout=8)
            # target 'default'/'%%REJECT%%'/'DROP'/'REJECT' all drop unsolicited incoming;
            # only an explicit ACCEPT target opens the zone. (Empty/err → treat as deny,
            # since an active firewalld public zone drops unsolicited traffic by design.)
            return (tg.stdout or '').strip().upper() != 'ACCEPT'
        except Exception:
            return None
    try:
        r = subprocess.run(_sudo_wrap(['ufw', 'status', 'verbose']), capture_output=True, text=True, timeout=12)
        for ln in (r.stdout or '').splitlines():
            l = ln.lower().strip()
            if l.startswith('default:'):
                # e.g. "Default: deny (incoming), allow (outgoing), disabled (routed)"
                inc = l.split('(incoming)')[0]
                return ('deny' in inc or 'reject' in inc)
    except Exception:
        pass
    return None

def _service_is_active(name):
    try:
        r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', name]),
                           capture_output=True, text=True, timeout=8)
        return (r.stdout or '').strip() == 'active'
    except Exception:
        return None

def _hardening_assertions():
    """Read-only boundary assertions → list of {key,label,status,detail}.
    status ∈ pass|fail|warn|na. Consumed by W4 verify, the page, and the W5 report."""
    res = []
    def add(key, label, status, detail):
        res.append({'key': key, 'label': label, 'status': status, 'detail': detail})

    fw = _firewall_status_local()
    fw_name = 'firewalld' if fw.get('backend') == 'firewalld' else 'UFW'
    if not fw.get('supported'):
        add('ufw_enabled', 'Host firewall present', 'fail', fw.get('error') or 'no UFW/firewalld installed')
    else:
        add('ufw_enabled', f'{fw_name} firewall active', 'pass' if fw.get('enabled') else 'fail',
            'active' if fw.get('enabled') else f'{fw_name} installed but not enabled')
        dd = _ufw_default_incoming_deny()
        add('ufw_default_deny', f'{fw_name} default-deny incoming',
            'pass' if dd else ('na' if dd is None else 'fail'),
            'deny by default' if dd else ('could not read default policy' if dd is None else 'default policy is not deny'))

    if os.path.exists('/etc/fail2ban'):
        active = _service_is_active('fail2ban')
        add('fail2ban_active', 'fail2ban intrusion prevention',
            'pass' if active else ('na' if active is None else 'fail'),
            'active' if active else ('status unknown' if active is None else 'installed but not active'))
    else:
        add('fail2ban_active', 'fail2ban intrusion prevention', 'warn', 'not installed')

    # Console :5001 reachability. In Hardened posture (W1) this should be localhost-only.
    # Probe UFW directly (don't just trust the applied flag) so config drift surfaces.
    h = load_hardening()
    w1 = (h.get('applied') or {}).get('W1_sso')
    port = str((load_settings().get('console_port') or 5001))
    pub = _w1_console_port_public(port)
    label = 'Admin console (:%s) not internet-exposed' % port
    if pub:
        add('console_localhost', label,
            'fail' if (w1 and w1.get('console_localhost_only')) else 'warn',
            'public firewall allow present on :%s' % port)
    elif w1 and w1.get('console_localhost_only'):
        add('console_localhost', label, 'pass',
            'no public firewall allow; reached via SSO reverse proxy (W1)')
    else:
        add('console_localhost', label, 'warn',
            'open to network (Standard posture / W1 not applied)')

    # TAK Tomcat surface — best-effort, honest 'na' where not evaluable here.
    if os.path.exists('/opt/tak'):
        webapps = '/opt/tak/webapps'
        mgr = (os.path.isdir(os.path.join(webapps, 'manager'))
               or os.path.isdir(os.path.join(webapps, 'host-manager'))) if os.path.isdir(webapps) else False
        add('tak_tomcat_manager', 'Tomcat manager/host-manager app not deployed',
            'fail' if mgr else 'pass',
            'manager webapp present' if mgr else 'no manager/host-manager webapp')
        add('tak_tomcat_mtls', 'TAK connectors mTLS client-cert (8443/8446)', 'na',
            'shielded by mTLS+firewall+Caddy; full connector/AJP STIG audit is .57')
    else:
        add('tak_tomcat_manager', 'TAK Tomcat surface', 'na', 'TAK Server not installed on this host')

    return res

def _hardening_control_w4():
    """W4 — port/boundary assertions. Read-only: apply/revert are no-ops; verify
    fails only if a CRITICAL assertion (UFW/fail2ban) fails."""
    def apply_(h, log):
        h.setdefault('applied', {})['W4_assert'] = {'enabled': True}
        log('W4: boundary assertions enabled (read-only)')
        return True
    def verify(h):
        a = (h.get('applied') or {}).get('W4_assert')
        if not a:
            return (False, 'assertions not enabled')
        crit = {'ufw_enabled', 'fail2ban_active'}
        fails = [x['key'] for x in _hardening_assertions() if x['status'] == 'fail' and x['key'] in crit]
        if fails:
            return (False, 'critical assertion failed: ' + ', '.join(fails))
        return (True, 'boundary assertions pass (see report for full surface)')
    def revert(h, log):
        (h.get('applied') or {}).pop('W4_assert', None)
        log('W4: boundary assertions disabled')
        return True
    return {'key': 'W4_assert', 'title': 'Port & Tomcat boundary assertions',
            'desc': 'Verifies host-firewall deny-by-default, fail2ban, and TAK Tomcat shielding (read-only).',
            'apply': apply_, 'verify': verify, 'revert': revert}

# --- W1: console SSO + per-user MFA + :5001 lockdown (the auth flip; last) -----
# Built LAST, behind W6's working revert. In Hardened posture the console is
# reachable ONLY through the existing Caddy `infratak.<fqdn>` vhost (Authentik
# forward_auth) — per-user SSO with enforced MFA. The shared-password login becomes
# on-box break-glass (reset-console-password.sh + an SSH tunnel to 127.0.0.1:5001).
# Three reversible moves, ordered so a fallback exists until the very last step:
#   1. Authentik: require a configured MFA device on the console application
#      (expression policy + binding + policy_engine_mode=all). REFUSES if no admin
#      has MFA enrolled yet — that would lock every SSO user out of the console.
#   2. Caddy: drop the unauthenticated `/login*` bypass so the password page is no
#      longer a network ingress (generate_caddyfile keys off _w1_console_locked()).
#   3. UFW: remove the public :5001 allow so direct-to-port access is dropped by
#      default-deny; loopback (Caddy proxy + SSH tunnel) is UFW-exempt and still works.
# Verifying the binding really lands is mandatory (the netbird PR#42 #4 trap:
# "app has no policy binding"); `ak dump_config` is the release-time env audit.
W1_MFA_POLICY_NAME = 'infratak-require-mfa'
W1_MFA_POLICY_EXPR = 'return ak_user_has_authenticator(request.user)'

def _w1_console_locked():
    """True when W1 has locked the console (Caddy /login bypass dropped). Read by
    generate_caddyfile so every Caddy regen — from anywhere — honors the posture."""
    try:
        return bool((load_hardening().get('applied') or {}).get('W1_sso', {}).get('caddy_login_locked'))
    except Exception:
        return False

def _w1_console_port_public(port):
    """True if the host firewall exposes the console port to the public (not loopback).
    None if the firewall is unsupported/disabled (can't assert lockdown). Backend-aware:
    UFW shows 'ALLOW ... Anywhere'; firewalld shows a bare '<port>/tcp (public)' entry
    (a loopback/source restriction would instead be a [source-rule], not a bare port)."""
    fw = _firewall_status_local()
    if not fw.get('supported') or not fw.get('enabled'):
        return None
    # Both backends now render rows as '<port>  ALLOW IN  <Anywhere|source>', so one
    # check works universally: a public allow = the port ALLOWed from Anywhere.
    for ln in fw.get('rules', []):
        l = ln.lower()
        if port in l and 'allow' in l and 'anywhere' in l:
            # a source-scoped rule (e.g. "from 127.0.0.1") is not a public allow
            if 'from' not in l or '127.0.0.1' not in l:
                return True
    return False

def _w1_ak_ctx():
    """(ak_url, ak_headers, settings) for Authentik API; ak_url None if no token."""
    settings = load_settings()
    tok = (_get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN')
           or _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN'))
    if not tok:
        return (None, None, settings)
    return (_get_authentik_api_url(settings),
            {'Authorization': f'Bearer {tok}', 'Content-Type': 'application/json'}, settings)

def _w1_ak_get(ak_url, path, ak_headers):
    return json.loads(_ak_api_call(f'{ak_url}/api/v3/{path}', headers=ak_headers).read().decode())

def _w1_login_apps(ak_url, ak_headers):
    """All Authentik LOGIN applications behind Authentik = every app whose provider is NOT
    an LDAP provider (the LDAP app is the TAK EUD bind path and MUST stay MFA-free, else
    ATAK/iTAK auth breaks). Returns [(slug, app_pk)]. No hard-coded slugs (fleet-robust)."""
    ldap_pks = set()
    try:
        for p in _w1_ak_get(ak_url, 'providers/ldap/?page_size=100', ak_headers).get('results', []):
            ldap_pks.add(p.get('pk'))
    except Exception:
        pass
    out = []
    for a in _w1_ak_get(ak_url, 'core/applications/?superuser_full_list=true&page_size=100',
                        ak_headers).get('results', []):
        prov = a.get('provider')
        if prov and prov not in ldap_pks:
            out.append((a.get('slug'), a.get('pk')))
    return out

def _w1_mfa_validate_stage(ak_url, ak_headers):
    """The authenticator-validate stage bound to default-authentication-flow (the WEB login
    flow — NOT the LDAP flow). Force-enroll is configured here. (stage_pk, detail) or (None,None)."""
    flows = _w1_ak_get(ak_url, 'flows/instances/?slug=default-authentication-flow', ak_headers).get('results', [])
    if not flows:
        return (None, None)
    flow_pk = flows[0].get('pk')
    for b in _w1_ak_get(ak_url, f'flows/bindings/?target={flow_pk}&page_size=100', ak_headers).get('results', []):
        st = b.get('stage_obj') or {}
        name = (st.get('name') or '') + ' ' + (st.get('verbose_name') or '')
        if 'validat' in name.lower():
            try:
                d = _w1_ak_get(ak_url, f'stages/authenticator/validate/{st.get("pk")}/', ak_headers)
                if 'not_configured_action' in d:
                    return (st.get('pk'), d)
            except Exception:
                continue
    return (None, None)

def _w1_setup_stage_pks(ak_url, ak_headers):
    """TOTP + WebAuthn authenticator SETUP stage pks (configuration_stages for force-enroll)."""
    pks = []
    for kind in ('totp', 'webauthn'):
        try:
            for s in _w1_ak_get(ak_url, f'stages/authenticator/{kind}/?page_size=20', ak_headers).get('results', []):
                pks.append(s.get('pk'))
        except Exception:
            pass
    return pks

# --- Fleet-uniform Authentik login/MFA copy (clearer than the stock "authentik" text) -
# Replaces "Welcome to authentik!" / "TOTP Device" / "WebAuthn device" with plain-English
# wording on every box. Independent of hardening posture — login screens should always read
# clearly. Idempotent; applied by a startup migration when Authentik is present.
AK_BRAND_TITLE = 'infra-TAK'
AK_AUTH_FLOW_TITLE = 'Sign in'
AK_TOTP_FRIENDLY = 'Authenticator App - Scan a QR code'
AK_WEBAUTHN_FRIENDLY = 'Use a Passkey'

# v0.9.56 W8 — Authentik event retention is a fleet-uniform constant, NOT the 365-day stock
# default. The stock default grows authentik_events_event unbounded (200k+ rows / 200MB+ on
# aged boxes); Authentik's periodic retention sweep over that table spikes authentik-postgresql
# CPU (field report: 327% bursts on a 32GB box). Authentik's own docs recommend a SHORT local
# retention when events are forwarded off-box — which the W7 off-box audit sink provides, so the
# >=365-day compliance copy lives off-box while local Postgres stays light. Fleet constant (no
# per-operator value, no max(cur,target)); applied as an idempotent startup migration on EVERY
# box (pure load/hygiene fix, posture-independent). See memory authentik-event-retention-pg-cpu.
AK_EVENT_RETENTION = 'days=30'

def _ensure_authentik_login_copy(log=None):
    """Codify clear, fleet-uniform login/MFA wording: brand title, the authentication-flow
    header, and the TOTP/WebAuthn enrollment button labels. Only PATCHes a field that differs
    (so it's a no-op on subsequent boots). Never raises. Returns True if anything changed."""
    def _l(m):
        if log:
            log(m)
    ak_url, ak_headers, _ = _w1_ak_ctx()
    if not ak_url:
        return False
    changed = False
    try:
        brands = _w1_ak_get(ak_url, 'core/brands/', ak_headers).get('results', [])
        if brands and brands[0].get('branding_title') != AK_BRAND_TITLE:
            bid = brands[0].get('brand_uuid') or brands[0].get('pk')
            _ak_api_call(f'{ak_url}/api/v3/core/brands/{bid}/',
                         data=json.dumps({'branding_title': AK_BRAND_TITLE}).encode(),
                         method='PATCH', headers=ak_headers)
            changed = True; _l('Authentik brand title → %s' % AK_BRAND_TITLE)
    except Exception as e:
        _l('Authentik brand title copy: %s' % str(e)[:100])
    try:
        flows = _w1_ak_get(ak_url, 'flows/instances/?slug=default-authentication-flow', ak_headers).get('results', [])
        if flows and flows[0].get('title') != AK_AUTH_FLOW_TITLE:
            _ak_api_call(f'{ak_url}/api/v3/flows/instances/default-authentication-flow/',
                         data=json.dumps({'title': AK_AUTH_FLOW_TITLE}).encode(),
                         method='PATCH', headers=ak_headers)
            changed = True; _l('Authentik login header → %s' % AK_AUTH_FLOW_TITLE)
    except Exception as e:
        _l('Authentik flow title copy: %s' % str(e)[:100])
    for kind, friendly in (('totp', AK_TOTP_FRIENDLY), ('webauthn', AK_WEBAUTHN_FRIENDLY)):
        try:
            for s in _w1_ak_get(ak_url, f'stages/authenticator/{kind}/?page_size=20', ak_headers).get('results', []):
                if s.get('friendly_name') != friendly:
                    _ak_api_call(f'{ak_url}/api/v3/stages/authenticator/{kind}/{s["pk"]}/',
                                 data=json.dumps({'friendly_name': friendly}).encode(),
                                 method='PATCH', headers=ak_headers)
                    changed = True; _l('Authentik %s setup label → %s' % (kind, friendly))
        except Exception as e:
            _l('Authentik %s label copy: %s' % (kind, str(e)[:100]))
    return changed

def _ensure_authentik_event_retention(log=None):
    """v0.9.56 W8 — codify Authentik's event retention to the fleet constant AK_EVENT_RETENTION.
    The stock 365-day default lets authentik_events_event grow to 200k+ rows; the periodic
    retention sweep over that table spikes authentik-postgresql CPU on modest hardware. We pin a
    short LOCAL retention (the >=365d compliance copy lives off-box via W7). Idempotent: only
    PATCHes when the live value differs, so it's a no-op on subsequent boots. Posture-independent
    (every box). Never raises; never restarts Postgres (a PG restart under load triggers the
    dramatiq-worker spiral — the retention sweep needs no restart). Returns True if it changed.

    Event retention is a System Settings singleton: GET/PATCH /api/v3/admin/settings/, field
    `event_retention` (authentik timedelta string, e.g. 'days=30'). One-time backlog reclaim
    (VACUUM of authentik_events_event) is an operator step, not done here."""
    def _l(m):
        if log:
            log(m)
    ak_url, ak_headers, _ = _w1_ak_ctx()
    if not ak_url:
        return False
    try:
        cur = (_w1_ak_get(ak_url, 'admin/settings/', ak_headers) or {}).get('event_retention')
        if cur == AK_EVENT_RETENTION:
            return False
        _ak_api_call(f'{ak_url}/api/v3/admin/settings/',
                     data=json.dumps({'event_retention': AK_EVENT_RETENTION}).encode(),
                     method='PATCH', headers=ak_headers)
        _l('Authentik event retention %s → %s (off-box holds the compliance copy)'
           % (cur or 'default', AK_EVENT_RETENTION))
        return True
    except Exception as e:
        _l('Authentik event retention: %s' % str(e)[:100])
        return False

def _w1_ensure_mfa_policy(ak_url, ak_headers, log):
    """Ensure the shared require-MFA expression policy exists; return its pk."""
    pols = _w1_ak_get(ak_url, f'policies/expression/?search={W1_MFA_POLICY_NAME}&page_size=100',
                      ak_headers).get('results', [])
    pol_pk = next((p.get('pk') for p in pols if p.get('name') == W1_MFA_POLICY_NAME), None)
    if pol_pk:
        return pol_pk
    body = json.dumps({'name': W1_MFA_POLICY_NAME, 'execution_logging': False,
                       'expression': W1_MFA_POLICY_EXPR}).encode()
    pol_pk = json.loads(_ak_api_call(f'{ak_url}/api/v3/policies/expression/', data=body,
                        method='POST', headers=ak_headers).read().decode()).get('pk')
    log('W1: created MFA-required policy (%s)' % W1_MFA_POLICY_NAME)
    return pol_pk

def _w1_apply_mfa(h, log):
    """All-or-none: enforce per-user MFA on EVERY Authentik login app + force MFA enrollment
    globally on the WEB auth flow. Lockout-safe order — force-enroll FIRST (a device-less user
    is walked through enrollment at login instead of being denied), THEN bind the deny-policy
    to each app. Idempotent; verifies each binding lands (per-app netbird #4 trap); records
    everything for clean revert. The LDAP flow is never touched (TAK client auth unaffected)."""
    ak_url, ak_headers, settings = _w1_ak_ctx()
    if not ak_url:
        log('W1: no Authentik token — cannot enforce SSO MFA'); return False
    w1 = h.setdefault('applied', {}).setdefault('W1_sso', {})

    # 0) shared require-MFA policy
    pol_pk = _w1_ensure_mfa_policy(ak_url, ak_headers, log)
    w1['ak_mfa_policy_pk'] = pol_pk

    # 1) FORCE-ENROLL FIRST on the web auth flow — after this, nobody can be locked out
    stage_pk, stage = _w1_mfa_validate_stage(ak_url, ak_headers)
    if not stage_pk:
        log("W1: could not locate the web MFA validate stage — aborting (won't bind deny-policies "
            'without the force-enroll safety net)'); return False
    setup_pks = _w1_setup_stage_pks(ak_url, ak_headers)
    if not setup_pks:
        log('W1: no TOTP/WebAuthn setup stages found — aborting (force-enroll needs a setup stage)')
        return False
    if 'ak_force_enroll' not in w1:  # record the TRUE prior only once
        w1['ak_force_enroll'] = {'stage_pk': stage_pk,
                                 'prior_not_configured_action': stage.get('not_configured_action'),
                                 'prior_configuration_stages': stage.get('configuration_stages') or []}
        save_hardening(h)
    if stage.get('not_configured_action') != 'configure' or not stage.get('configuration_stages'):
        _ak_api_call(f'{ak_url}/api/v3/stages/authenticator/validate/{stage_pk}/',
                     data=json.dumps({'not_configured_action': 'configure',
                                      'configuration_stages': setup_pks}).encode(),
                     method='PATCH', headers=ak_headers)
        log('W1: force-enroll ON (web login walks device-less users through TOTP/WebAuthn setup)')
    chk = _w1_ak_get(ak_url, f'stages/authenticator/validate/{stage_pk}/', ak_headers)
    if chk.get('not_configured_action') != 'configure' or not chk.get('configuration_stages'):
        log('W1: VERIFY FAILED — force-enroll did not stick; aborting before binding deny-policies')
        return False

    # 2) bind require-MFA to EVERY login app + policy_engine_mode=all
    apps = _w1_login_apps(ak_url, ak_headers)
    if not apps:
        log('W1: no Authentik login apps found — aborting'); return False
    rec = w1.setdefault('ak_apps', {})
    for slug, app_pk in apps:
        prior_mode = _w1_ak_get(ak_url, f'core/applications/{slug}/', ak_headers).get('policy_engine_mode', 'any')
        binds = _w1_ak_get(ak_url, f'policies/bindings/?target={app_pk}&page_size=100', ak_headers).get('results', [])
        bind_pk = next((b.get('pk') for b in binds if b.get('policy') == pol_pk), None)
        if not bind_pk:
            body = json.dumps({'policy': pol_pk, 'target': app_pk, 'enabled': True,
                               'order': 10, 'timeout': 30, 'failure_result': False}).encode()
            bind_pk = json.loads(_ak_api_call(f'{ak_url}/api/v3/policies/bindings/', data=body,
                                 method='POST', headers=ak_headers).read().decode()).get('pk')
        rec[slug] = {'app_pk': app_pk, 'binding_pk': bind_pk,
                     'prior_engine_mode': (rec.get(slug, {}).get('prior_engine_mode') or prior_mode)}
        # Set engine_mode=all (group AND MFA both required). Re-read and retry once: an app
        # with another binding (e.g. the Admins-group binding) MUST be 'all' or that binding
        # alone would satisfy 'any' and bypass the MFA requirement.
        for _try in (1, 2):
            cur = _w1_ak_get(ak_url, f'core/applications/{slug}/', ak_headers).get('policy_engine_mode')
            if cur == 'all':
                break
            _ak_api_call(f'{ak_url}/api/v3/core/applications/{slug}/',
                         data=json.dumps({'policy_engine_mode': 'all'}).encode(),
                         method='PATCH', headers=ak_headers)
        save_hardening(h)
        binds2 = _w1_ak_get(ak_url, f'policies/bindings/?target={app_pk}&page_size=100', ak_headers).get('results', [])
        if not any(b.get('policy') == pol_pk and b.get('enabled') for b in binds2):
            log('W1: VERIFY FAILED — MFA binding missing on app %s' % slug); return False
        if _w1_ak_get(ak_url, f'core/applications/{slug}/', ak_headers).get('policy_engine_mode') != 'all':
            log('W1: VERIFY FAILED — %s policy_engine_mode is not "all"' % slug); return False
    w1['ak_app_slug'] = 'infratak'  # console marker for W4 assertion compatibility
    log('W1: MFA enforced on %d Authentik apps + force-enroll ON (%s)'
        % (len(apps), ', '.join(s for s, _ in apps)))
    return True

def _w1_revert_mfa(h, log):
    """Undo MFA-everywhere: restore the force-enroll stage, delete each app binding + restore
    its engine_mode, delete the shared policy. Idempotent; never raises."""
    ak_url, ak_headers, _ = _w1_ak_ctx()
    if not ak_url:
        log('W1: no Authentik token — skipping MFA unbind'); return
    w1 = (h.get('applied') or {}).get('W1_sso') or {}
    fe = w1.get('ak_force_enroll') or {}
    if fe.get('stage_pk'):
        try:
            _ak_api_call(f'{ak_url}/api/v3/stages/authenticator/validate/{fe["stage_pk"]}/',
                         data=json.dumps({'not_configured_action': fe.get('prior_not_configured_action') or 'skip',
                                          'configuration_stages': fe.get('prior_configuration_stages') or []}).encode(),
                         method='PATCH', headers=ak_headers)
            log('W1: force-enroll restored to prior (%s)' % (fe.get('prior_not_configured_action') or 'skip'))
        except Exception as e:
            log('W1: force-enroll restore error: %s' % str(e)[:120])
    for slug, info in (w1.get('ak_apps') or {}).items():
        try:
            if info.get('binding_pk'):
                _ak_api_call(f'{ak_url}/api/v3/policies/bindings/{info["binding_pk"]}/',
                             method='DELETE', headers=ak_headers)
        except Exception as e:
            log('W1: binding delete error (%s): %s' % (slug, str(e)[:100]))
        try:
            _ak_api_call(f'{ak_url}/api/v3/core/applications/{slug}/',
                         data=json.dumps({'policy_engine_mode': info.get('prior_engine_mode', 'any')}).encode(),
                         method='PATCH', headers=ak_headers)
        except Exception as e:
            log('W1: engine_mode restore error (%s): %s' % (slug, str(e)[:100]))
    if w1.get('ak_apps'):
        log('W1: MFA bindings removed from %d apps; engine_mode restored' % len(w1['ak_apps']))
    # Backward-compat: pre-MFA-everywhere single-app state (ak_app_slug/ak_mfa_binding_pk).
    if w1.get('ak_app_slug') and not w1.get('ak_apps'):
        try:
            if w1.get('ak_mfa_binding_pk'):
                _ak_api_call(f'{ak_url}/api/v3/policies/bindings/{w1["ak_mfa_binding_pk"]}/',
                             method='DELETE', headers=ak_headers)
            _ak_api_call(f'{ak_url}/api/v3/core/applications/{w1["ak_app_slug"]}/',
                         data=json.dumps({'policy_engine_mode': w1.get('ak_prior_engine_mode', 'any')}).encode(),
                         method='PATCH', headers=ak_headers)
            log('W1: legacy single-app MFA binding reverted (%s)' % w1['ak_app_slug'])
        except Exception as e:
            log('W1: legacy revert error: %s' % str(e)[:100])
    try:
        if w1.get('ak_mfa_policy_pk'):
            _ak_api_call(f'{ak_url}/api/v3/policies/expression/{w1["ak_mfa_policy_pk"]}/',
                         method='DELETE', headers=ak_headers)
            log('W1: MFA-required policy deleted')
    except Exception as e:
        log('W1: policy delete error: %s' % str(e)[:120])

def _w1_caddy_regen(log):
    """Regenerate + validate + reload Caddy so the /login bypass state matches posture."""
    try:
        generate_caddyfile()  # writes CADDYFILE_PATH (honors _w1_console_locked())
    except Exception as e:
        log('W1: Caddyfile generation error: %s' % str(e)[:160]); return False
    # Pre-validate if the caddy binary is reachable; otherwise rely on `systemctl
    # reload caddy`, which validates internally and refuses a bad config.
    if subprocess.run('command -v caddy >/dev/null 2>&1', shell=True).returncode == 0:
        val = subprocess.run('caddy validate --config %s --adapter caddyfile 2>&1' % CADDYFILE_PATH,
                             shell=True, capture_output=True, text=True, timeout=30)
        if val.returncode != 0:
            out = (val.stdout or val.stderr or '')
            # On custom-cert (ssl_mode='custom') + non-root boxes this validate runs as
            # takwerx, which can't traverse /var/lib/caddy (0750 caddy:caddy) to open the
            # deployed cert copy — a FALSE fail (the caddy service reads it fine).
            # Permission-denied is inconclusive, not a bad config: defer to the reload
            # below, which validates as the caddy user and refuses a bad config anyway.
            if 'permission denied' in out.lower():
                log("W1: caddy pre-validate inconclusive (cert unreadable by console user); "
                    "deferring to caddy's own reload validation")
            else:
                log('W1: caddy validate FAILED: %s' % out[-200:]); return False
    rl = subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=60)
    if rl.returncode != 0:
        log('W1: caddy reload error: %s' % (rl.stdout or rl.stderr or '')[-160:]); return False
    log('W1: Caddy reloaded'); return True

def _w1_ufw_lock_console(log):
    """Remove the public :5001 allow. Loopback stays exempt (UFW loopback rule / firewalld
    trusted `lo`), so SSO reverse-proxy + SSH-tunnel break-glass keep working. Backend-aware
    (UFW delete allow ↔ firewalld remove-port). Returns False if a public allow survives."""
    port = int(load_settings().get('console_port') or 5001)
    be = _fw_backend()
    # v10.0.5: both backends go through _fw_remove (→ _sudo_wrap → broker). The old UFW branch
    # hand-rolled a literal `sudo ufw delete` shell string, which SILENTLY NO-OPS under the
    # non-root console (takwerx has no sudo and can't run ufw directly), so W1 left :5001
    # world-open while recording console_localhost_only=true. _fw_remove is broker-routed and
    # backend-aware, so this closes on UFW and firewalld alike, root or non-root.
    _fw_remove(port, 'tcp')
    fw_name = 'firewalld' if be == 'firewalld' else 'UFW'
    if _w1_console_port_public(str(port)):
        log('W1: WARNING — :%s still shows a public allow after removal' % port); return False
    log('W1: %s public allow for :%s removed (console now localhost-only)' % (fw_name, port)); return True

def _w1_ufw_unlock_console(log):
    port = int(load_settings().get('console_port') or 5001)
    be = _fw_backend()
    # v10.0.5: broker-routed _fw_allow on both backends (the old literal `sudo ufw allow`
    # no-op'd under the non-root console — same class of bug as the lock above).
    _fw_allow(port, 'tcp')
    log('W1: %s public allow for :%s restored (Standard)' % ('firewalld' if be == 'firewalld' else 'UFW', port))

def _hardening_control_w1():
    """W1 — console SSO + per-user MFA + :5001 lockdown. Highest risk, so it runs LAST
    behind W6's working revert. apply is self-cleaning: any sub-step failure rolls back
    every change W1 already made (the outer transaction does not revert a control that
    returned False)."""
    def apply_(h, log):
        if not _ufw_default_incoming_deny():
            log('W1: REFUSING — host firewall default-incoming is not deny; locking :5001 would '
                'not actually block external access. Enable the firewall (deny-by-default) first.')
            return False
        # 1) Authentik MFA (refuses if it would lock everyone out). On failure, clean up
        # any Authentik objects it recorded before dropping the state.
        if not _w1_apply_mfa(h, log):
            _w1_revert_mfa(h, log)
            (h.get('applied') or {}).pop('W1_sso', None)
            save_hardening(h)
            return False
        w1 = h['applied']['W1_sso']
        # 2) Caddy: drop the /login bypass (persist flag FIRST so generate_caddyfile sees it)
        w1['caddy_login_locked'] = True
        save_hardening(h)
        if not _w1_caddy_regen(log):
            w1['caddy_login_locked'] = False; save_hardening(h)
            _w1_caddy_regen(log)            # restore Standard Caddy
            _w1_revert_mfa(h, log)          # undo MFA — never leave it half-applied
            (h.get('applied') or {}).pop('W1_sso', None)
            return False
        # 3) UFW: close the public :5001 allow
        if not _w1_ufw_lock_console(log):
            w1['caddy_login_locked'] = False; save_hardening(h)
            _w1_caddy_regen(log)
            _w1_revert_mfa(h, log)
            (h.get('applied') or {}).pop('W1_sso', None)
            return False
        w1['console_localhost_only'] = True
        log('W1: console is SSO+MFA only; :5001 localhost-only; password = on-box break-glass')
        return True
    def verify(h):
        w1 = (h.get('applied') or {}).get('W1_sso')
        if not w1:
            return (False, 'SSO+MFA flip not applied')
        port = str((load_settings().get('console_port') or 5001))
        if _w1_console_port_public(port):
            return (False, ':%s still has a public firewall allow' % port)
        napps = len(w1.get('ak_apps') or {})
        if not napps:
            return (False, 'MFA policy not bound to any Authentik app')
        if not (w1.get('ak_force_enroll') or {}).get('stage_pk'):
            return (False, 'MFA force-enroll not configured')
        return (True, 'SSO+MFA on %d Authentik apps + force-enroll; :%s localhost-only; break-glass on-box'
                % (napps, port))
    def revert(h, log):
        # reverse order: UFW unlock → Caddy restore → Authentik unbind
        _w1_ufw_unlock_console(log)
        w1 = h.setdefault('applied', {}).setdefault('W1_sso', {})
        w1['caddy_login_locked'] = False
        save_hardening(h)
        _w1_caddy_regen(log)
        _w1_revert_mfa(h, log)
        (h.get('applied') or {}).pop('W1_sso', None)
        log('W1: reverted — password login reachable, :5001 reopened, MFA unbound')
        return True
    return {'key': 'W1_sso', 'title': 'SSO + per-user MFA (all Authentik apps)',
            'desc': 'Per-user MFA is enforced on every app behind Authentik (console, Node-RED, TAK '
                    'Portal, WebODM, MediaMTX, NetBird) with force-enrollment at first login; the '
                    'console :5001 is localhost-only and its shared password is on-box break-glass. '
                    'TAK Server, CloudTAK and TAK clients use their own native auth (not behind Authentik).',
            'apply': apply_, 'verify': verify, 'revert': revert}

def _hardening_registry():
    """Ordered control list. Apply runs in order; revert runs in reverse.
    W1 (the risky auth flip) is always LAST so a working revert exists before it."""
    return [
        _hardening_control_w2(),
        _hardening_control_widle(),
        _hardening_control_w3(),
        _hardening_control_w7(),
        _hardening_control_w4(),
        _hardening_control_w1(),
    ]

def _breakglass_status():
    """W6 — confirm the on-box break-glass recovery path exists. The posture flip
    must never permanently lock an operator out: recovery is reset-console-password.sh
    run from an on-box shell (network-isolated, auditable), NOT a network ingress."""
    script = os.path.join(BASE_DIR, 'reset-console-password.sh')
    return {'present': os.path.exists(script), 'path': script,
            'note': 'On-box shell only. Restores console password login if SSO/Authentik is down.'}

def _hardening_history(h, action, result):
    h.setdefault('history', []).append({
        'ts': datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
        'actor': session.get('authentik_username') or 'console-admin',
        'action': action, 'result': result})
    # keep the tail bounded
    h['history'] = h['history'][-200:]

@app.route('/api/hardening/status')
@login_required
def hardening_status():
    h = load_hardening()
    controls = []
    for c in _hardening_registry():
        ok, detail = c['verify'](h)
        controls.append({'key': c['key'], 'title': c['title'],
                         'desc': c.get('desc', ''), 'pass': bool(ok), 'detail': detail})
    return jsonify({
        'posture': h.get('posture') or 'standard',
        'controls': controls,
        'breakglass': _breakglass_status(),
        'idle_max_seconds': SESSION_IDLE_MAX_DEFAULT,
        'history': (h.get('history') or [])[-10:],
    })

@app.route('/api/hardening/apply', methods=['POST'])
@login_required
def hardening_apply():
    """W6-transactional flip to Hardened. Applies controls in order; on ANY failure
    rolls back the controls already applied (reverse order) and stays Standard."""
    h = load_hardening()
    log_lines = []
    log = log_lines.append
    applied_ok = []
    try:
        for c in _hardening_registry():
            if not c['apply'](h, log):
                raise RuntimeError('apply failed: %s' % c['key'])
            applied_ok.append(c)
        h['posture'] = 'hardened'
        _hardening_history(h, 'apply', 'hardened')
        save_hardening(h)
        audit('hardening:apply', 'posture=hardened')
        return jsonify({'success': True, 'posture': 'hardened', 'log': log_lines})
    except Exception as e:
        for c in reversed(applied_ok):
            try:
                c['revert'](h, log)
            except Exception:
                log('rollback error on %s' % c.get('key'))
        h['posture'] = 'standard'
        _hardening_history(h, 'apply-rollback', str(e))
        save_hardening(h)
        return jsonify({'success': False, 'error': str(e), 'log': log_lines}), 500

@app.route('/api/hardening/revert', methods=['POST'])
@login_required
def hardening_revert():
    """Un-harden back to Standard. Reverts controls in reverse order. Audit (W3) is
    one-way and intentionally not reverted (you don't un-audit)."""
    h = load_hardening()
    log_lines = []
    log = log_lines.append
    for c in reversed(_hardening_registry()):
        try:
            c['revert'](h, log)
        except Exception:
            log('revert error on %s' % c.get('key'))
    h['posture'] = 'standard'
    _hardening_history(h, 'revert', 'standard')
    save_hardening(h)
    audit('hardening:revert', 'posture=standard', force=True)
    return jsonify({'success': True, 'posture': 'standard', 'log': log_lines})

def _hardening_tls_posture(settings):
    """Honest TLS line for the report. self-deploy boxes vary; never claim FIPS."""
    mode = (settings.get('ssl_mode') or '').strip().lower()
    if mode == 'custom':
        return ('Operator-supplied certificate (BYO TLS, v0.9.51 custom-cert module).',
                'pass')
    if mode in ('fqdn', 'letsencrypt'):
        return ("Let's Encrypt CA-issued certificate.", 'pass')
    return ('Self-signed certificate — browsers will warn. Remediate with a CA-issued '
            'or DNS-validated cert (Caddy/custom-cert module) before review.', 'warn')

def _hardening_report_html(h, settings):
    posture = h.get('posture') or 'standard'
    host = html.escape(settings.get('fqdn') or settings.get('server_ip') or 'unknown')
    generated = datetime.utcnow().strftime('%Y-%m-%d %H:%M UTC')
    bg = _breakglass_status()
    tls_text, tls_status = _hardening_tls_posture(settings)

    def badge(status):
        c = {'pass': '#047857', 'fail': '#b91c1c', 'warn': '#a16207', 'na': '#475569'}.get(status, '#475569')
        return '<span style="color:%s;font-weight:700">%s</span>' % (c, status.upper())

    # Controls (W2/W3/W4 verify)
    ctl_rows = []
    for c in _hardening_registry():
        ok, detail = c['verify'](h)
        st = 'pass' if ok else ('na' if posture != 'hardened' else 'fail')
        ctl_rows.append('<tr><td>%s</td><td>%s</td><td>%s</td></tr>'
                        % (html.escape(c['title']), badge(st), html.escape(detail)))

    # Boundary assertions (W4)
    asrt_rows = []
    for a in _hardening_assertions():
        asrt_rows.append('<tr><td>%s</td><td>%s</td><td>%s</td></tr>'
                         % (html.escape(a['label']), badge(a['status']), html.escape(a['detail'])))

    # Control-mapping (provides / agency owns / hosting owns)
    mapping = [
        ('Unique-user ID + MFA for admin access', 'infra-TAK (W1 SSO+MFA via Authentik)',
         'Provision per-user accounts; enroll MFA tokens'),
        ('30-minute idle session lock', 'infra-TAK (W2)', '—'),
        ('Audit trail: who/what/when', 'infra-TAK (W3 local)',
         'Off-box retention &ge;365d to your SIEM/WORM (.56)'),
        ('Network boundary / least-exposure', 'infra-TAK (W4 UFW+fail2ban, TAK mTLS)',
         'Cloud security groups / NLB if used'),
        ('TLS in transit', 'infra-TAK (Caddy/custom-cert)',
         'FIPS-validated termination = cloud LB or on-prem terminator (.58)'),
        ('Encryption at rest (CJI stores)', 'Deferred (.58 LUKS/Ubuntu Pro FIPS)',
         'Provider disk encryption / agency policy'),
        ('Physical security, US-soil, screened personnel', '—',
         'Cloud provider (CJIS Security Addendum) + agency'),
        ('Personnel screening, training, IR plan, agreements', '—', 'Agency (attestation)'),
    ]
    map_rows = ''.join('<tr><td>%s</td><td>%s</td><td>%s</td></tr>'
                       % (m[0], m[1], m[2]) for m in mapping)

    cjso = (
        "This system (infra-TAK TAK stack) carries position and command-and-control data only. "
        "Per agency policy, criminal history (CHRI) and NCIC query results are NOT entered into TAK "
        "markers, chat, or data feeds. Administrative access to the console is per-user via SSO with "
        "enforced MFA (TOTP or WebAuthn/FIDO2; use WebAuthn for phishing-resistant AAL2); all "
        "administrative actions are logged with the acting user's "
        "identity and timestamp. The admin console is not exposed to the internet (reachable only "
        "through the authenticated reverse proxy). TLS is served with an agency- or CA-issued "
        "certificate. Break-glass recovery requires on-box shell access and is auditable — it is not a "
        "network backdoor. Hosting is on a US-sovereign cloud region (or agency on-prem); the cloud "
        "provider owns the physical, personnel, and data-center CJIS controls under its Security Addendum.")

    parts = []
    parts.append('''<!DOCTYPE html><html><head><meta charset="UTF-8">
<title>Security Posture Readiness Report — infra-TAK</title>
<style>
body{font-family:Arial,Helvetica,sans-serif;margin:40px;color:#0f172a;line-height:1.5;max-width:960px}
h1{font-size:21px;margin-bottom:4px}h2{font-size:15px;margin:26px 0 8px;border-bottom:2px solid #e2e8f0;padding-bottom:4px}
table{border-collapse:collapse;width:100%;margin:10px 0}td,th{border:1px solid #cbd5e1;padding:7px 11px;font-size:12.5px;text-align:left;vertical-align:top}
th{background:#f1f5f9}.meta{color:#475569;font-size:12px}code{background:#f1f5f9;padding:1px 5px;border-radius:3px;font-size:11.5px}
.box{background:#f8fafc;border:1px solid #cbd5e1;border-radius:6px;padding:14px 16px;font-size:12.5px;white-space:pre-wrap}
.note{font-size:11.5px;color:#64748b;margin-top:4px}
@media print{body{margin:0}}
</style></head><body>''')
    parts.append('<h1>infra-TAK — Security Posture Readiness Report</h1>')
    parts.append('<p class="meta">Posture: <strong>%s</strong> &middot; Host: %s &middot; Console v%s &middot; Generated %s</p>'
                 % (html.escape(posture.upper()), host, html.escape(VERSION), html.escape(generated)))
    parts.append('<p class="note">Self-deploy evidence document. infra-TAK is not "CJIS certified" — no software is. '
                 'This maps the technical controls this box provides versus those the agency and cloud provider own.</p>')

    parts.append('<h2>1. Posture controls</h2><table><tr><th>Control</th><th>Status</th><th>Detail</th></tr>'
                 + ''.join(ctl_rows) + '</table>')

    parts.append('<h2>2. Boundary assertions (read-only)</h2><table><tr><th>Check</th><th>Status</th><th>Detail</th></tr>'
                 + ''.join(asrt_rows) + '</table>')

    parts.append('<h2>3. TLS / cryptography</h2>')
    parts.append('<p style="font-size:12.5px">In transit: %s %s</p>' % (badge(tls_status), html.escape(tls_text)))
    parts.append('<p class="note"><strong>FIPS (honest):</strong> in-transit uses TLS 1.2+ but Caddy/Go is '
                 '<strong>not</strong> a FIPS-validated cryptographic module — remediate per policy with a FIPS-validated '
                 'cloud LB or on-prem terminator (.58). At-rest CJI encryption is deferred to .58 (LUKS / Ubuntu Pro FIPS). '
                 'FIPS 140-2 validations move to NIST&rsquo;s historical list 2026-09-21; target FIPS 140-3 for new procurement.</p>')

    parts.append('<h2>4. Control mapping — who owns what</h2>'
                 '<table><tr><th>Control area</th><th>infra-TAK provides</th><th>Agency / hosting owns</th></tr>'
                 + map_rows + '</table>')

    parts.append('<h2>5. Break-glass recovery</h2>')
    parts.append('<p style="font-size:12.5px">Recovery path: <code>%s</code> &mdash; %s Status: %s.</p>'
                 % (html.escape(bg['path']), html.escape(bg['note']),
                    badge('pass' if bg['present'] else 'fail')))

    parts.append('<h2>6. What to tell your security office</h2>')
    parts.append('<p class="note">Editable starting statement for your CJSO/ISSO — adjust to your environment:</p>')
    parts.append('<div class="box">%s</div>' % html.escape(cjso))

    parts.append('<h2>7. Deployment guidance — reverse proxy / load balancer</h2>')
    parts.append('<p style="font-size:12.5px"><strong>No load balancer &ne; non-compliant.</strong> The actual auth '
                 'boundary is host-firewall deny-by-default + mTLS client-cert on the TAK Tomcat connectors — a box with no LB is '
                 'fully defensible on that alone. On real clouds a Network Load Balancer in <strong>TCP passthrough</strong> '
                 'in front of :8089/:8443 is optional (IP-hiding, flood absorption, HA). An on-box reverse proxy is a '
                 '<em>want</em>, not a need; any proxy in front of TAK must be TCP passthrough (terminating TLS breaks '
                 'TAK&rsquo;s client-cert auth). On-box HAProxy is not needed; multi-node HA is out of scope (single-box by design).</p>')

    parts.append('</body></html>')
    return ''.join(parts)

