def _update_check_response(data):
    """Return JSON response with no-cache headers so FQDN/proxy path never serves stale update badge."""
    from flask import make_response
    r = make_response(jsonify(data))
    r.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    r.headers['Pragma'] = 'no-cache'
    return r


def _github_release_notes_for_tag(tag_name: str) -> str:
    """Return human-readable update details for the dashboard Details panel.

    Prefer GitHub **Release** body (same tag). Tags-only releases return 404 — then link to
    docs/RELEASE-*.md and the tag URL on GitHub so operators always see something useful.
    """
    import urllib.request
    import urllib.error
    import urllib.parse
    if not tag_name or not tag_name.strip():
        return ''
    tag_name = tag_name.strip()
    base = f'https://github.com/{GITHUB_REPO}'
    doc_slug = tag_name if tag_name.startswith('v') else f'v{tag_name}'
    fallback = (
        f'Release notes (markdown in repo): {base}/blob/main/docs/RELEASE-{doc_slug}.md\n'
        f'Tag on GitHub: {base}/releases/tag/{urllib.parse.quote(tag_name)}'
    )
    try:
        url = f'https://api.github.com/repos/{GITHUB_REPO}/releases/tags/{urllib.parse.quote(tag_name)}'
        req = urllib.request.Request(
            url,
            headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'}
        )
        with urllib.request.urlopen(req, timeout=6) as resp:
            data = json.loads(resp.read().decode())
        body = (data.get('body') or '').strip()
        if body:
            # Cap size for JSON/UI; panel scrolls but avoid huge payloads
            if len(body) > 12000:
                body = body[:12000].rstrip() + '\n\n… (truncated)'
            html_url = (data.get('html_url') or '').strip()
            extra = f'\n\n---\nOn GitHub: {html_url}' if html_url else ''
            return body + extra
    except urllib.error.HTTPError as e:
        if e.code != 404:
            return fallback + f'\n\n(Release API: HTTP {e.code})'
    except Exception:
        pass
    return fallback


@app.route('/api/update/channel', methods=['POST'])
@login_required
def set_update_channel():
    """Toggle the update channel between 'main' (stable releases) and 'dev' (dev branch head).

    Persisted in settings.json as update_channel. The update check and apply routes
    both respect this setting so the operator never has to SSH to switch tracks.

    Switching TO 'dev' requires the console password to be supplied in the request
    body as 'password' — prevents accidental channel changes by an operator who
    clicked the wrong button. Switching back to 'main' requires no password.
    """
    data = request.get_json(force=True) or {}
    channel = (data.get('channel') or 'main').strip().lower()
    if channel not in ('main', 'dev'):
        return jsonify({'ok': False, 'error': 'channel must be "main" or "dev"'}), 400
    if channel == 'dev':
        pw = (data.get('password') or '').strip()
        if not pw:
            return jsonify({'ok': False, 'error': 'password required to switch to dev channel', 'need_password': True}), 403
        auth = load_auth()
        if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], pw):
            return jsonify({'ok': False, 'error': 'incorrect password', 'need_password': True}), 403
    s = load_settings()
    s['update_channel'] = channel
    save_settings(s)
    update_cache.update({'latest': None, 'checked': 0, 'notes': '', 'body': ''})
    return jsonify({'ok': True, 'channel': channel})


@app.route('/api/update/check')
@login_required
def update_check():
    import urllib.request
    now = time.time()
    def _parse_version_tuple(v):
        return tuple(int(p) for p in v.replace('-alpha','').replace('-beta','').split('.'))

    _settings = load_settings()
    _channel = (_settings.get('update_channel') or 'main').strip().lower()
    _on_dev = (_channel == 'dev')

    # Dev channel: compare current VERSION against the HEAD commit message on dev.
    # We report update_available when the dev branch HEAD SHA differs from the
    # currently running commit (i.e. there are new commits on dev we haven't pulled).
    if _on_dev:
        try:
            gh_headers = {'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'}
            dev_req = urllib.request.Request(
                f'https://api.github.com/repos/{GITHUB_REPO}/commits?sha=dev&per_page=1',
                headers=gh_headers
            )
            dev_resp = urllib.request.urlopen(dev_req, timeout=5)
            dev_data = json.loads(dev_resp.read().decode())
            if not dev_data:
                return _update_check_response({'current': VERSION, 'latest': None, 'channel': 'dev',
                    'error': 'No commits on dev', 'body': '', 'update_available': False})
            head = dev_data[0]
            head_sha = head.get('sha', '')[:7]
            head_msg = (head.get('commit', {}).get('message', '') or '').splitlines()[0][:80]
            # Check local git HEAD to see if we're already at this commit
            try:
                _local_sha = subprocess.run(
                    ['git', f'--git-dir={os.path.join(os.path.dirname(os.path.abspath(__file__)), ".git")}',
                     'rev-parse', '--short', 'HEAD'],
                    capture_output=True, text=True, timeout=5
                ).stdout.strip()
            except Exception:
                _local_sha = ''
            _remote_full_sha = head.get('sha', '')
            _is_ahead = bool(_remote_full_sha) and not _remote_full_sha.startswith(_local_sha or 'XXXXXXXX')
            latest_label = f'dev@{head_sha}'
            notes = f'dev branch — {head_msg}'
            body = f'Latest commit on dev:\n{head_sha} — {head_msg}\n\nClick "Pull dev" to update to this commit.'
            update_cache.update({'latest': latest_label, 'checked': now, 'notes': notes, 'body': body})
            return _update_check_response({'current': VERSION, 'latest': latest_label, 'notes': notes,
                'body': body, 'channel': 'dev', 'update_available': _is_ahead})
        except Exception as e:
            return _update_check_response({'current': VERSION, 'latest': None, 'channel': 'dev',
                'error': str(e)[:200], 'body': '', 'update_available': False})

    # Main channel: existing tag-based check.
    force = request.args.get('refresh') == '1'
    if not force and update_cache['latest'] and (now - update_cache['checked']) < 600:
        try:
            cached_newer = _parse_version_tuple(update_cache['latest']) > _parse_version_tuple(VERSION)
            if update_cache['latest'].strip() == VERSION.strip():
                cached_newer = False
        except (ValueError, IndexError):
            cached_newer = False
        return _update_check_response({'current': VERSION, 'latest': update_cache['latest'], 'notes': update_cache['notes'],
            'body': update_cache.get('body') or '', 'channel': 'main',
            'update_available': cached_newer})
    try:
        gh_headers = {'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'}
        req = urllib.request.Request(
            f'https://api.github.com/repos/{GITHUB_REPO}/tags',
            headers=gh_headers
        )
        resp = urllib.request.urlopen(req, timeout=5)
        data = json.loads(resp.read().decode())
        if not data:
            return _update_check_response({'current': VERSION, 'latest': None, 'channel': 'main', 'error': 'No tags found', 'body': '', 'update_available': False})
        # Only surface tags that are actually on the main branch so that tags
        # pushed on dev before a merge-to-main don't show as "update available".
        try:
            main_req = urllib.request.Request(
                f'https://api.github.com/repos/{GITHUB_REPO}/commits?sha=main&per_page=100',
                headers=gh_headers
            )
            main_resp = urllib.request.urlopen(main_req, timeout=5)
            main_commits = {c['sha'] for c in json.loads(main_resp.read().decode())}
        except Exception:
            main_commits = None  # fall back: don't filter if we can't reach main
        versions = []
        for tag in data:
            if main_commits is not None and tag.get('commit', {}).get('sha') not in main_commits:
                continue
            name = tag.get('name', '').lstrip('v').replace('-alpha','').replace('-beta','')
            parts = name.split('.')
            try:
                versions.append((tuple(int(p) for p in parts), tag))
            except (ValueError, IndexError):
                continue
        if not versions:
            return _update_check_response({'current': VERSION, 'latest': None, 'channel': 'main', 'error': 'No version tags', 'body': '', 'update_available': False})
        versions.sort(key=lambda x: x[0], reverse=True)
        latest_tag = versions[0][1]
        latest = latest_tag.get('name', '').lstrip('v')
        try:
            latest_tuple = _parse_version_tuple(latest)
            current_tuple = _parse_version_tuple(VERSION)
            is_newer = latest_tuple > current_tuple
        except (ValueError, IndexError):
            is_newer = False
        # Never show "update available" when current and latest are the same (avoid stale badge after update)
        if latest.strip() == VERSION.strip():
            is_newer = False
        notes = f"Version {latest_tag.get('name', '')}"
        tag_full = (latest_tag.get('name') or '').strip()
        body = _github_release_notes_for_tag(tag_full) if is_newer else ''
        update_cache.update({'latest': latest, 'checked': now, 'notes': notes, 'body': body})
        return _update_check_response({'current': VERSION, 'latest': latest, 'notes': notes, 'body': body,
            'channel': 'main', 'update_available': is_newer})
    except Exception as e:
        return _update_check_response({'current': VERSION, 'latest': None, 'channel': 'main', 'error': str(e)[:200], 'body': '', 'update_available': False})

def _fetch_latest_tag_name():
    """Return the latest release tag name (e.g. 'v0.2.3-alpha') from GitHub, or None on error."""
    import urllib.request
    try:
        req = urllib.request.Request(
            f'https://api.github.com/repos/{GITHUB_REPO}/tags',
            headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'}
        )
        resp = urllib.request.urlopen(req, timeout=5)
        data = json.loads(resp.read().decode())
        if not data:
            return None
        versions = []
        for tag in data:
            name = tag.get('name', '').lstrip('v').replace('-alpha', '').replace('-beta', '')
            parts = name.split('.')
            try:
                versions.append((tuple(int(p) for p in parts), tag.get('name', '')))
            except (ValueError, IndexError):
                continue
        if not versions:
            return None
        versions.sort(key=lambda x: x[0], reverse=True)
        return versions[0][1]  # full tag name e.g. v0.2.3-alpha
    except Exception:
        return None


@app.route('/api/update/apply', methods=['POST'])
@login_required
def update_apply():
    # v0.9.24 Item 1: Update Now single-flight lock.
    # Field incident on test8 (2026-05-16): operator double-clicked "Update Now"
    # from two browser tabs. Both POSTs to /api/update/apply ran concurrently
    # in the same console process, both did git fetch+checkout, both scheduled
    # `systemctl restart takwerx-console`. The second restart fired ~2s after
    # the first and killed the first deploy mid-bootstrap. Docker `restart:
    # unless-stopped` does NOT restart explicitly stopped containers, so
    # tak-portal and mediamtx ended up in `Exited` state for 12+ minutes until
    # operator manual recovery.
    #
    # The lock is a timestamped file at /var/lib/takwerx-console/update-now.lock.
    # Lifecycle:
    #   - written at the top of this endpoint
    #   - cleared at the end of _post_update_auto_deploy (in _run_post_update_guarded
    #     finally block, AND in the no-op early-return path)
    #   - 20-min TTL covers the rare case where a deploy crashes without clearing it
    #
    # Item 2 below (post-update service recovery sweep) is the belt to this fix's
    # suspenders — if anything still gets stopped mid-deploy, the sweep brings it back.
    _update_lock = '/var/lib/takwerx-console/update-now.lock'
    _update_lock_ttl_s = 1200
    try:
        os.makedirs(os.path.dirname(_update_lock), exist_ok=True)
        if os.path.exists(_update_lock):
            _age = int(time.time() - os.path.getmtime(_update_lock))
            if _age < _update_lock_ttl_s:
                _lock_info = ''
                try:
                    with open(_update_lock) as _lf:
                        _lock_info = _lf.read().strip()
                except Exception:
                    pass
                return jsonify({
                    'success': False,
                    'in_progress': True,
                    'started_seconds_ago': _age,
                    'error': (
                        f'Update Now is already in progress (started ~{_age}s ago). '
                        f'The console will restart automatically when complete — '
                        f'wait 1–3 minutes then refresh this page. Avoid clicking '
                        f'Update Now in multiple browser tabs.'
                    ),
                    'lock_info': _lock_info or None,
                }), 409
            print(f"Update Now: clearing stale lock (age={_age}s ≥ TTL={_update_lock_ttl_s}s)", flush=True)
        with open(_update_lock, 'w') as _lf:
            _lf.write(
                f"version={VERSION}\n"
                f"started_utc={datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')}\n"
                f"pid={os.getpid()}\n"
            )
    except Exception as _le:
        # Lock-file IO failure is non-blocking. Single-flight is an availability
        # optimization, not a correctness guarantee; we'd rather a degraded
        # double-deploy than a wedged Update Now button on a misconfigured box.
        print(f"Update Now: lock-file IO error (non-blocking, continuing): {_le}", flush=True)

    console_dir = os.path.dirname(os.path.abspath(__file__))
    git_env = {'GIT_TERMINAL_PROMPT': '0'}
    git_cfg = ['git', '-c', f'safe.directory={console_dir}']
    # Ensure git works on repos owned by other users (e.g. takwerx-owned
    # ~/TAK-Portal and ~/CloudTAK when the console process HOME differs from
    # the repo owner). --system writes to /etc/gitconfig — applies to every
    # user on the machine, which is correct for a single-tenant server.
    subprocess.run(
        ['git', 'config', '--system', '--replace-all', 'safe.directory', '*'],
        capture_output=True, timeout=5
    )
    # Empty remote.origin.fetch: explicit refspecs are *additive* with defaults; without this,
    # `git fetch origin +refs/tags/foo:refs/tags/foo` still updates heads/tags per origin.fetch
    # and can hit "would clobber existing tag" on field installs.
    git_cfg_fetch_isolated = git_cfg + ['-c', 'remote.origin.fetch=']

    def _git(args, timeout=60, isolated_fetch=False):
        prefix = git_cfg_fetch_isolated if isolated_fetch else git_cfg
        return subprocess.run(
            prefix + args,
            cwd=console_dir,
            capture_output=True,
            text=True,
            timeout=timeout,
            env={**os.environ, **git_env}
        )

    def _git_err(r):
        return (r.stderr or '').strip() or (r.stdout or '').strip() or 'git command failed'

    def _error_payload(err):
        out = {'success': False, 'error': err}
        if 'dubious ownership' in err.lower() or 'safe.directory' in err.lower():
            out['workaround'] = f'On the server run: sudo git config --global --add safe.directory {console_dir}'
        return out

    # v0.9.3: Record current version for one-step rollback before updating
    try:
        _pre_update_version = VERSION
        _s = load_settings()
        # Determine the current git tag so rollback can fetch it
        _cur_tag_r = subprocess.run(
            ['git', f'--git-dir={os.path.join(console_dir, ".git")}',
             f'--work-tree={console_dir}', 'describe', '--tags', '--exact-match'],
            capture_output=True, text=True, timeout=10
        )
        _cur_tag = (_cur_tag_r.stdout or '').strip() if _cur_tag_r.returncode == 0 else f'v{VERSION}'
        _s['console_rollback'] = {
            'available':   True,
            'version':     VERSION,
            'tag':         _cur_tag,
            'snapshot_at': datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
        }
        save_settings(_s)
    except Exception:
        pass

    _apply_settings = load_settings()
    _apply_channel = (_apply_settings.get('update_channel') or 'main').strip().lower()
    _apply_dev = (_apply_channel == 'dev')

    try:
        # Never use pull --rebase in Update Now.
        # Field installs can be detached/tagged or have stale rebase metadata; rebase causes customer-facing conflicts.
        for abort_args in (['rebase', '--abort'], ['merge', '--abort'], ['cherry-pick', '--abort']):
            try:
                _git(abort_args, timeout=15)
            except Exception:
                pass

        if _apply_dev:
            # Dev channel: fetch origin/dev HEAD and check it out directly.
            fetch_dev = _git(
                ['fetch', 'origin', 'dev:refs/remotes/origin/dev'], timeout=60, isolated_fetch=True
            )
            if fetch_dev.returncode != 0:
                return jsonify(_error_payload(_git_err(fetch_dev)))
            target_ref = 'refs/remotes/origin/dev'
            target_label = 'origin/dev'
        else:
            # Main channel: resolve latest tag from GitHub API, then fetch ONLY that tag (+ = update
            # local tag if it moved). Bulk `git fetch --tags` fails on many field installs: local
            # v0.3.8-alpha etc. can differ from origin ("would clobber existing tag") even when the
            # operator only wants the newest release.
            tag_name = _fetch_latest_tag_name()
            target_ref = None
            if tag_name:
                refspec = f'+refs/tags/{tag_name}:refs/tags/{tag_name}'
                fetch_tag = _git(['fetch', 'origin', refspec], timeout=120, isolated_fetch=True)
                if fetch_tag.returncode != 0:
                    return jsonify(_error_payload(_git_err(fetch_tag)))
                verify_tag = _git(['rev-parse', '-q', '--verify', f'refs/tags/{tag_name}'], timeout=15)
                if verify_tag.returncode == 0:
                    target_ref = f'refs/tags/{tag_name}'

            # Fallback: track origin/main if tag lookup fails.
            if not target_ref:
                fetch_main = _git(
                    ['fetch', 'origin', 'main:refs/remotes/origin/main'], timeout=30, isolated_fetch=True
                )
                if fetch_main.returncode != 0:
                    return jsonify(_error_payload(_git_err(fetch_main)))
                target_ref = 'refs/remotes/origin/main'
            target_label = tag_name or 'origin/main'

        checkout = _git(['checkout', '--force', target_ref], timeout=30)
        if checkout.returncode != 0:
            return jsonify(_error_payload(_git_err(checkout)))

        update_cache.update({'latest': None, 'checked': 0, 'notes': '', 'body': ''})
        _ensure_gunicorn_upgrade(console_dir)
        _detached_console_restart()
        return jsonify({
            'success': True,
            'output': f'Updated to {target_label}',
            'restart_required': True,
            'restart_message': 'Console is restarting. You may see 502 briefly — wait 10–15 seconds then refresh the page.'
        })
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:200]})

@app.route('/api/console/restart-safe')
def console_restart_safe():
    """v0.9.44: localhost-only readiness probe for the daily console-restart
    timer (tak-console-restart.sh). Returns {"safe": bool, "reason": str|null}.

    safe=False when any deploy/update operation is in flight, so the timer
    defers the restart instead of killing a mid-flight deploy. Not session/
    browser driven (mirrors the localhost-only Guard Dog script endpoints), so
    it carries no @login_required — but it is restricted to loopback callers.
    """
    if (request.remote_addr or '') not in ('127.0.0.1', '::1', 'localhost'):
        return jsonify({'error': 'forbidden'}), 403

    busy = None
    # 1) Update Now lock — file-based, set at the top of the Update Now endpoint
    #    (20-min TTL), so it survives even if the worker handling it is wedged.
    try:
        _lock = '/var/lib/takwerx-console/update-now.lock'
        if os.path.exists(_lock):
            _age = int(time.time() - os.path.getmtime(_lock))
            if _age < 1200:
                busy = f'Update Now in progress (~{_age}s ago)'
    except Exception:
        pass
    # 2) Any in-memory *_status dict reporting a running operation. Scanned
    #    dynamically so new deploy-status globals are covered automatically.
    if busy is None:
        try:
            for _name, _val in list(globals().items()):
                if _name.endswith('_status') and isinstance(_val, dict) and _val.get('running'):
                    busy = f'{_name} running'
                    break
        except Exception:
            pass

    return jsonify({'safe': busy is None, 'reason': busy})


@app.route('/api/console/power', methods=['POST'])
@login_required
def console_power_api():
    """Power off / reboot the box from the console (no SSH). Destructive and
    outward-facing — poweroff needs a physical power-on to return — so it
    re-confirms the console password (mirrors the dev-channel-switch gate) ON TOP
    of @login_required, so it can't be an accidental click. Runs the systemctl
    verb through the broker (verb-gated: poweroff + reboot are allowlisted),
    detached so the HTTP response returns before the box goes down."""
    data = request.get_json(silent=True) or {}
    action = (data.get('action') or '').strip()
    password = data.get('password') or ''
    if action not in ('poweroff', 'reboot'):
        return jsonify({'success': False, 'error': 'action must be "poweroff" or "reboot".'}), 400
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'success': False, 'error': 'Incorrect console password.', 'need_password': True}), 403
    _detached_power_action(action, delay=2)
    return jsonify({'success': True, 'action': action})


_CONSOLE_UNIT = '/etc/systemd/system/takwerx-console.service'


def _broker_force_enabled_in_unit():
    """True if TAKWERX_FORCE_BROKER=1 is set in the console's systemd unit."""
    try:
        with open(_CONSOLE_UNIT) as f:
            return 'TAKWERX_FORCE_BROKER=1' in f.read()
    except OSError:
        return False


def _broker_service_active():
    try:
        r = subprocess.run(['systemctl', 'is-active', 'takwerx-broker'],
                           capture_output=True, text=True, timeout=8)
        return r.stdout.strip() == 'active'
    except Exception:
        return False


def _broker_status_dict():
    enforce = None
    enforce_info = {}
    deny_count = None
    readiness = {}
    try:
        if _broker_available():
            pong = _broker_request({'op': 'ping'}, timeout=5)
            enforce = bool(pong.get('enforce'))
            enforce_info = pong.get('enforce_info') or {}
            deny_count = pong.get('deny_count')
            readiness = pong.get('readiness') or {}
    except Exception:
        pass
    return {
        'installed': os.path.exists(_BROKER_SCRIPT) and os.path.exists('/etc/systemd/system/takwerx-broker.service'),
        'service_active': _broker_service_active(),
        'socket_present': _broker_available(),
        'routing_active': _broker_should_route(),
        'force_enabled': _broker_force_enabled_in_unit(),
        'enforce': enforce,   # None=unknown, False=permissive (watch), True=enforcing
        # v10.0.8: how the mode was decided, the stay-permissive reason, denials
        # since start, and opt-in readiness (opted_in / ready / clean_since /
        # reason) so the card can render the "Turn on enforcing" flow.
        'enforce_info': enforce_info,
        'deny_count': deny_count,
        'readiness': readiness,
        'console_uid': os.getuid(),
        'audit_log': '/var/log/takwerx-broker/audit.log',
        'socket': BROKER_SOCKET,
    }


@app.route('/api/console/broker/status')
@login_required
def console_broker_status():
    """v10.0.5: status for the 'Least-Privilege Console' Cyber Control card."""
    return jsonify(_broker_status_dict())


@app.route('/api/console/broker/selftest')
@login_required
def console_broker_selftest():
    """v10.0.5: prove the privileged broker works end-to-end. Talks to the broker
    DIRECTLY (via _broker_request), so it is valid whether or not the console is
    currently routing through it — clicking "Run self-test" needs no restart.
    When routing IS active, an extra check exercises the console's own helpers."""
    checks = []

    def add(name, ok, detail='', level=None):
        checks.append({'name': name, 'ok': bool(ok),
                       'level': level or ('pass' if ok else 'fail'),
                       'detail': str(detail)[:300]})

    info = _broker_status_dict()
    if not _broker_available():
        return jsonify({'ok': False, 'info': info,
                        'error': 'broker socket not present — is takwerx-broker.service running?'}), 503

    # 1. ping — the guard answers
    try:
        r = _broker_request({'op': 'ping'})
        add('Guard responds (ping)', r.get('ok') and r.get('pong'), r)
    except Exception as e:
        add('Guard responds (ping)', False, e)

    # 2. allowed write+read round-trip (broker's own log dir always exists)
    probe = '/var/log/takwerx-broker/.selftest'
    try:
        import base64 as _bb
        w = _broker_request({'op': 'write', 'path': probe,
                             'content_b64': _bb.b64encode(b'broker-ok').decode()})
        rd = _broker_request({'op': 'read', 'path': probe})
        got = _bb.b64decode(rd.get('content_b64') or '') if rd.get('ok') else b''
        add('Allowed write + read', w.get('ok') and got == b'broker-ok')
        _broker_request({'op': 'exec', 'argv': ['rm', '-f', probe]})
    except Exception as e:
        add('Allowed write + read', False, e)

    # 3. allowed exec returns output
    try:
        r = _broker_request({'op': 'exec', 'argv': ['systemctl', '--version']})
        out = ''
        if r.get('ok'):
            import base64 as _bb
            out = _bb.b64decode(r.get('stdout_b64') or '').decode(errors='replace')
        add('Allowed command runs', r.get('ok') and r.get('returncode') == 0 and 'systemd' in out)
    except Exception as e:
        add('Allowed command runs', False, e)

    # 4. rulebook would DENY a sudoers write (dry-run verdict — NB this proves the
    #    rulebook's answer, NOT that the console is confined to it; see capstone).
    try:
        r = _broker_request({'op': 'check', 'req': {'op': 'write', 'path': '/etc/sudoers.d/takwerx-evil'}})
        add('Rulebook denies sudoers write (dry-run)', r.get('ok') and r.get('verdict') == 'DENY', r.get('reason'))
    except Exception as e:
        add('Rulebook denies sudoers write (dry-run)', False, e)

    # 5. rulebook would DENY arbitrary shell (dry-run verdict)
    try:
        r = _broker_request({'op': 'check', 'req': {'op': 'exec', 'argv': ['bash', '-c', 'id']}})
        add('Rulebook denies arbitrary shell (dry-run)', r.get('ok') and r.get('verdict') == 'DENY', r.get('reason'))
    except Exception as e:
        add('Rulebook denies arbitrary shell (dry-run)', False, e)

    # 6. when routing is on, prove the console's OWN helpers go through the broker
    if _broker_should_route():
        try:
            _write_priv(probe, 'via-helpers\n')
            back = _read_priv(probe)
            add('Console routes through guard', back.strip() == 'via-helpers')
            _broker_request({'op': 'exec', 'argv': ['rm', '-f', probe]})
        except Exception as e:
            add('Console routes through guard', False, e)

    # Up to here the checks prove the guard MECHANICALLY works. Whether it is an
    # actual ENFORCED privilege boundary depends on two more things the panel must
    # not hide: the console must run NON-ROOT (else it bypasses the guard directly)
    # AND the broker must be ENFORCING (permissive only logs would-deny). State that
    # honestly — a security reviewer reads this panel.
    functional_ok = all(c['ok'] for c in checks)
    console_root = (info.get('console_uid') == 0)
    enforce = info.get('enforce')  # True=enforcing, False=permissive, None=unknown
    # The boundary EXISTS iff the console is NON-ROOT: it then physically cannot make
    # privileged changes except through the guard. Enforce mode is a STRICTNESS level
    # (active deny vs learning-mode logging), not whether a boundary exists — fresh
    # installs ship non-root + permissive, which is the intended locked-down state. So
    # non-root passes; only a still-root console is flagged.
    boundary = not console_root
    if console_root:
        add('Console is confined to the guard', False, level='warn',
            detail='NO — the console runs as ROOT (uid 0): it can make privileged '
                   'changes directly, bypassing the guard, which only records them. '
                   'Switch the console to non-root (automatic on fresh installs; the '
                   'on-box migration for an existing root box) to make it a boundary.')
    else:
        note = ('YES — the console runs unprivileged; it cannot make privileged '
                'changes except through the guard.')
        if enforce is False:
            note += ' Rulebook is in learning mode (permissive) — enforce mode adds active blocking.'
        elif enforce is True:
            note += ' Rulebook is enforcing.'
        add('Console is confined to the guard', True, detail=note)
    overall = 'pass' if (functional_ok and boundary) else ('warn' if functional_ok else 'fail')
    return jsonify({'ok': functional_ok and boundary, 'overall': overall,
                    'functional_ok': functional_ok, 'boundary': boundary,
                    'console_root': console_root, 'enforce': enforce,
                    'info': info, 'checks': checks})


@app.route('/api/console/broker/routing', methods=['POST'])
@login_required
def console_broker_routing():
    """v10.0.5: enable/disable least-privilege routing by toggling
    TAKWERX_FORCE_BROKER=1 in the console's systemd unit, then restarting the
    console. SAFE: the console keeps running as root either way — this only
    decides whether its privileged calls go THROUGH the guard. It does NOT flip
    the console to a non-root user (that stays gated on the rulebook hardening)."""
    data = request.get_json(silent=True) or {}
    enable = bool(data.get('enable'))

    if enable and not _broker_available():
        return jsonify({'success': False,
                        'error': 'Broker is not running — cannot enable routing. Check: systemctl status takwerx-broker'}), 400

    try:
        unit = ''
        if os.path.exists(_CONSOLE_UNIT):
            try:
                unit = _read_priv(_CONSOLE_UNIT)   # v10.0.5 non-root: read via broker
            except Exception:
                unit = ''
        lines = [ln for ln in unit.splitlines()
                 if 'TAKWERX_FORCE_BROKER' not in ln]
        if enable:
            # insert under [Service] (after the line that opens it)
            out = []
            inserted = False
            for ln in lines:
                out.append(ln)
                if ln.strip() == '[Service]' and not inserted:
                    out.append('Environment=TAKWERX_FORCE_BROKER=1')
                    inserted = True
            if not inserted:   # no [Service] header found — append safely
                out.append('Environment=TAKWERX_FORCE_BROKER=1')
            unit = '\n'.join(out) + '\n'
        else:
            unit = '\n'.join(lines) + '\n'
        _write_priv(_CONSOLE_UNIT, unit)   # v10.0.5 non-root: /etc/systemd/system root-owned
        subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=15)
        # persist intent so a future start.sh re-run can honor it (P1 wiring)
        try:
            _s = load_settings()
            _s['broker_force_routing'] = enable
            save_settings(_s)
        except Exception:
            pass
        # detached delayed restart (same pattern as Update Now) so this response returns first
        _detached_console_restart()
        return jsonify({
            'success': True,
            'enabled': enable,
            'restart_required': True,
            'restart_message': 'Console is restarting to apply the change. You may see a brief 502 — wait ~15 seconds, then refresh.'
        })
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/console/broker/enforce', methods=['POST'])
@login_required
def console_broker_enforce():
    """v10.0.8: OPT IN to enforcement (deliberate — the box never flips on its own).
    Calls the broker `enforce_enable` op (a ratchet: it only ever CREATES the
    root-owned opt-in marker, never removes it), then restarts the broker so it
    re-evaluates. The broker enforces ONLY once its 72h audit window is clean;
    until then it reports 'enabled — waiting for clean window'. Turning enforcement
    back OFF is intentionally NOT exposed here — that is the SSH-only break-glass
    kill switch (Environment=TAKWERX_BROKER_ENFORCE=0), so a compromised console can
    only ever make the box MORE locked down."""
    if not _broker_available():
        return jsonify({'success': False,
                        'error': 'Guard is not running — cannot enable enforcement. Check: systemctl status takwerx-broker'}), 400
    try:
        resp = _broker_request({'op': 'enforce_enable'}, timeout=15)
    except Exception as e:
        return jsonify({'success': False, 'error': f'could not reach the guard: {e}'}), 500
    if not resp.get('ok'):
        return jsonify({'success': False, 'error': resp.get('error') or 'guard refused the request'}), 500
    # Restart the broker so _resolve_enforce re-runs with the marker present.
    try:
        subprocess.run(_sudo_wrap(['systemctl', 'restart', 'takwerx-broker']), capture_output=True, timeout=20)
    except Exception:
        pass
    return jsonify({
        'success': True,
        'opted_in': True,
        'ready': bool(resp.get('ready')),
        'message': resp.get('note') or 'Enforcement enabled.',
    })


_NONROOT_MIGRATE_UNIT = 'infratak-nonroot-migrate'
_NONROOT_MIGRATE_STATUS = '/var/lib/infratak-nonroot-migrate.status'
_NONROOT_MIGRATE_LOG = '/var/log/takwerx-console-nonroot-migrate.log'


@app.route('/api/console/migrate-nonroot', methods=['POST'])
@login_required
def console_migrate_nonroot_api():
    """v10.0.5: flip a legacy ROOT console to the unprivileged takwerx user FROM THE
    BROWSER (no CLI — the whole infra-TAK premise), wrapping
    scripts/migrate-console-nonroot.sh --apply --auto-rollback. The migration
    restarts/replaces the console process, so it MUST run DETACHED in its own cgroup
    (systemd-run) to survive — same pattern as the kernel-patch job. The console is
    ALREADY root here (the button only shows on a root console), so this is a
    root->non-root provisioning step, NOT a privilege escalation; the script path is
    fixed (no request input reaches the command). --auto-rollback restores the root
    unit if the flip fails, so a botched migration cannot lock the operator out."""
    if os.getuid() != 0:
        return jsonify({'success': False, 'error': 'Console already runs non-root — nothing to migrate.'}), 400
    if not (os.path.exists('/usr/bin/systemd-run') or os.path.exists('/bin/systemd-run')):
        return jsonify({'success': False, 'error': 'systemd-run not found — cannot run the migration safely.'}), 500
    install_dir = os.path.dirname(os.path.abspath(__file__))
    script = os.path.join(install_dir, 'scripts', 'migrate-console-nonroot.sh')
    if not os.path.exists(script):
        return jsonify({'success': False, 'error': f'migration script not found at {script}'}), 500
    # Refuse if a migration is already in flight (fixed unit name → one at a time);
    # avoids a confusing "unit already exists" 500 on a double-click/retry.
    try:
        st = subprocess.run(_sudo_wrap(['systemctl', 'is-active', _NONROOT_MIGRATE_UNIT + '.service']),
                            capture_output=True, text=True, timeout=5)
        if (st.stdout or '').strip() in ('active', 'activating'):
            return jsonify({'success': False, 'error': 'A non-root migration is already running.'}), 409
    except Exception:
        pass
    # Reset any prior FAILED transient unit so systemd accepts a fresh start of the same name.
    try:
        subprocess.run(_sudo_wrap(['systemctl', 'reset-failed', _NONROOT_MIGRATE_UNIT + '.service']),
                       capture_output=True, timeout=5)
    except Exception:
        pass
    try:  # seed status (0600) so the poller has something the instant this returns (console is root here)
        with open(_NONROOT_MIGRATE_STATUS, 'w') as f:
            f.write('running')
        os.chmod(_NONROOT_MIGRATE_STATUS, 0o600)
    except Exception:
        pass
    cmd = [
        'systemd-run',
        '--unit=' + _NONROOT_MIGRATE_UNIT,
        '--description=infra-TAK console non-root migration (detached)',
        '--property=StandardOutput=append:' + _NONROOT_MIGRATE_LOG,
        '--property=StandardError=append:' + _NONROOT_MIGRATE_LOG,
        '--setenv=PATH=/usr/sbin:/usr/bin:/sbin:/bin',
    ]
    # RHEL/SELinux: the transient migrate unit must run UNCONFINED. Otherwise, under
    # enforcing SELinux it runs in a confined domain and the flip's provision rsync
    # (start.sh: rsync of the current install → /opt/infratak) is denied search
    # access to the current install's home dir (/home/<user>) even as root, so
    # start.sh exits non-zero and the migration auto-rolls-back. Root-caused live on
    # Rocky 9.8: `SELinux is preventing /usr/bin/rsync from search access on the
    # directory rocky`. Same unconfined_service_t treatment the console + broker
    # units already carry (see _startup_ensure_broker). No-op where SELinux is
    # Disabled or absent (Ubuntu/Debian), so the happy path is unchanged.
    try:
        _ge = subprocess.run(['getenforce'], capture_output=True, text=True, timeout=5)
        if _ge.returncode == 0 and _ge.stdout.strip() != 'Disabled':
            cmd.append('--property=SELinuxContext=system_u:system_r:unconfined_service_t:s0')
    except Exception:
        pass
    cmd += [
        '--no-block',
        '/bin/bash', script, '--apply', '--auto-rollback',
    ]
    try:
        r = subprocess.run(_sudo_wrap(cmd), capture_output=True, text=True, timeout=15)
    except Exception as e:
        return jsonify({'success': False, 'error': f'could not launch migration: {e}'}), 500
    if r.returncode != 0:
        err = (r.stderr or r.stdout or '').strip()[:300]
        return jsonify({'success': False, 'error': f'systemd-run failed: {err}'}), 500
    return jsonify({'success': True,
                    'message': 'Migration started. The console will restart as the takwerx user (~30–60s). This page reconnects automatically.'})


@app.route('/api/console/migrate-nonroot/status')
@login_required
def console_migrate_nonroot_status_api():
    """Poll the non-root migration. The page calls this after it reconnects: the
    authoritative success signal is the console actually running non-root now;
    otherwise read the breadcrumb the script writes (running / done / failed:<reason>)."""
    nonroot = (os.getuid() != 0)
    state, detail = 'unknown', ''
    try:
        with open(_NONROOT_MIGRATE_STATUS) as f:
            raw = f.read().strip()
        if raw.startswith('failed-rollback:'):   # flip failed AND rollback unverified — SSH recovery
            state, detail = 'failed', raw[len('failed-rollback:'):]
        elif raw.startswith('failed:'):
            state, detail = 'failed', raw[len('failed:'):]
        elif raw in ('running', 'done'):
            state = raw
    except Exception:
        pass
    if nonroot:           # console answering as non-root == migration succeeded
        state = 'done'
    return jsonify({'state': state, 'nonroot': nonroot, 'detail': detail})


@app.route('/api/console/rollback', methods=['POST'])
@login_required
def console_rollback_api():
    """Roll back the console to the version saved before the last Update Now."""
    data = request.get_json(silent=True) or {}
    password = data.get('password', '')
    auth = load_settings().get('auth', {})
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'ok': False, 'error': 'Incorrect password'}), 403
    console_dir = os.path.dirname(os.path.abspath(__file__))
    s = load_settings()
    rb = s.get('console_rollback') or {}
    if not rb.get('available'):
        return jsonify({'ok': False, 'error': 'No rollback available (no snapshot recorded before last update)'}), 400
    prev_tag = rb.get('tag', '').strip()
    if not prev_tag:
        return jsonify({'ok': False, 'error': 'Rollback tag not recorded'}), 400
    try:
        git_cfg = ['git', '-c', f'safe.directory={console_dir}']
        # Fetch the tag from origin
        fetch_r = subprocess.run(
            git_cfg + ['fetch', 'https://github.com/takwerx/infra-TAK.git',
                       f'refs/tags/{prev_tag}:refs/tags/{prev_tag}'],
            cwd=console_dir, capture_output=True, text=True, timeout=60,
            env={**os.environ, 'GIT_TERMINAL_PROMPT': '0'}
        )
        checkout_r = subprocess.run(
            git_cfg + ['checkout', '--force', prev_tag],
            cwd=console_dir, capture_output=True, text=True, timeout=30,
            env={**os.environ, 'GIT_TERMINAL_PROMPT': '0'}
        )
        if checkout_r.returncode != 0:
            err = (checkout_r.stderr or '').strip() or 'git checkout failed'
            return jsonify({'ok': False, 'error': err}), 500
        # Clear rollback availability (one rollback per update)
        s['console_rollback'] = {'available': False}
        save_settings(s)
        _detached_console_restart()
        return jsonify({
            'ok': True, 'tag': prev_tag,
            'message': f'Rolled back to {prev_tag}. Console is restarting.'
        })
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)[:200]}), 500


@app.route('/takserver')
@login_required
def takserver_page():
    modules = detect_modules()
    tak = modules.get('takserver', {})
    ak = modules.get('authentik', {})
    # Show "Connect TAK Server to LDAP" when: TAK Server + Authentik installed, CoreConfig exists, LDAP not yet applied
    has_ldap = _coreconfig_has_ldap()
    show_connect_ldap = (
        tak.get('installed') and ak.get('installed') and
        os.path.exists('/opt/tak/CoreConfig.xml') and not has_ldap
    )
    ldap_connected = tak.get('installed') and ak.get('installed') and has_ldap
    # Reset deploy_done once TAK Server is running so the running view shows
    if tak.get('installed') and tak.get('running') and not deploy_status.get('running', False):
        deploy_status.update({'complete': False, 'error': False})
    tak_version = _get_takserver_version_info().get('version', '') if tak.get('installed') else ''
    _settings = load_settings()
    _tak_cfg = _get_tak_deployment_config(_settings)
    _is_two_server = _tak_cfg.get('mode') == 'two_server'
    _s1_host = (_tak_cfg.get('server_one', {}).get('host') or '').strip() if _is_two_server else ''
    _total_ram = _get_total_ram_gb_local() if tak.get('installed') else None
    _recommended_heap = _recommended_takserver_heap_gb(_total_ram) if _total_ram is not None else 4
    _current_heap = _get_current_takserver_heap_gb() if tak.get('installed') else None
    _upgrade_done = upgrade_status.get('complete', False)
    if _upgrade_done and not upgrade_status.get('running'):
        upgrade_status.update({'complete': False})
    _migrate_done = tak_migrate_status.get('complete', False)
    if _migrate_done and not tak_migrate_status.get('running'):
        tak_migrate_status.update({'complete': False})
    return render_template_string(TAKSERVER_TEMPLATE,
        settings=_settings, modules=modules, tak=tak, tak_version=tak_version,
        tak_installed=tak.get('installed', False),
        show_connect_ldap=show_connect_ldap, ldap_connected=ldap_connected,
        authentik_base_url=_get_authentik_base_url(_settings),
        takserver_base_url=_get_takserver_base_url(_settings),
        metrics=get_system_metrics(), version=VERSION, deploying=deploy_status.get('running', False),
        deploy_done=deploy_status.get('complete', False), deploy_error=deploy_status.get('error', False),
        upgrading=upgrade_status.get('running', False), upgrade_done=_upgrade_done,
        upgrade_error=upgrade_status.get('error', False),
        migrating=tak_migrate_status.get('running', False), migrate_done=_migrate_done,
        migrate_error=tak_migrate_status.get('error', False),
        two_server_mode=_is_two_server, s1_host=_s1_host, tak_is_container=_tak_is_container(),
        total_ram_gb=_total_ram, recommended_heap_gb=_recommended_heap, current_heap_gb=_current_heap)

