@app.route('/api/takserver/two-server/preflight', methods=['POST'])
@login_required
def takserver_two_server_preflight():
    data = request.get_json() or {}
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    if cfg.get('mode') != 'two_server':
        return jsonify({'success': False, 'error': 'Deployment mode is not set to two_server', 'config': cfg}), 400

    checks = []
    server_one = cfg.get('server_one', {})
    server_two = cfg.get('server_two', {})
    db_port = int(cfg.get('database', {}).get('port') or 5432)

    def add_check(name, ok, details=''):
        checks.append({'name': name, 'ok': bool(ok), 'details': (details or '')[:600]})

    add_check('Server One host configured', bool(server_one.get('host')), server_one.get('host', ''))
    if server_two.get('use_localhost'):
        add_check('Server Two host configured', True, 'Using infra-TAK host (local)')
    else:
        add_check('Server Two host configured', bool(server_two.get('host')), server_two.get('host', ''))

    one_ok = two_ok = False
    one_out = two_out = ''
    if server_one.get('host'):
        one_ok, one_out = _ssh_probe(server_one, 'echo "server_one_ok" && uname -a', timeout=18)
    add_check('SSH to Server One (Database Server)', one_ok, one_out)
    if server_two.get('host') or server_two.get('use_localhost'):
        two_ok, two_out = _ssh_probe(server_two, 'echo "server_two_ok" && uname -a', timeout=18)
    add_check('SSH to Server Two (Core Server)', two_ok, two_out)

    # From Server Two, verify DB TCP path to Server One:5432 (or configured DB port).
    db_reach_ok = False
    if two_ok and server_one.get('host'):
        probe_cmd = f'timeout 6 bash -lc "</dev/tcp/{server_one.get("host")}/{db_port}" >/dev/null 2>&1 && echo OPEN || echo CLOSED'
        ok, out = _ssh_probe(server_two, probe_cmd, timeout=20)
        db_reach_ok = ok and 'OPEN' in (out or '')
        if not db_reach_ok and one_ok:
            # Diagnose: SSH to Server One and check PG status for actionable detail.
            diag_cmd = (
                f'pg_installed=$(dpkg -l 2>/dev/null | grep -ci postgres); '
                f'pg_listen=$(ss -tlnp 2>/dev/null | grep :{db_port} || true); '
                f'ufw_line=$(sudo ufw status 2>/dev/null | grep {db_port} | head -3 || true); '
                f'if [ "$pg_installed" = "0" ]; then echo "DIAG: PostgreSQL not installed on Server One. Run Deploy to Server One first."; '
                f'elif [ -z "$pg_listen" ]; then echo "DIAG: PostgreSQL installed but not listening on port {db_port}. Service may be stopped."; '
                f'else echo "DIAG: PostgreSQL listening: $pg_listen | UFW: $ufw_line"; fi'
            )
            _, diag_out = _ssh_probe(server_one, diag_cmd, timeout=15)
            detail = f'CLOSED — {(diag_out or "").strip()}'
            add_check(f'Server Two can reach Server One DB port {db_port}', False, detail)
        else:
            add_check(f'Server Two can reach Server One DB port {db_port}', db_reach_ok, out)
    else:
        add_check(f'Server Two can reach Server One DB port {db_port}', False, 'Skipped (SSH/host check failed)')

    all_ok = all(c['ok'] for c in checks)
    return jsonify({
        'success': all_ok,
        'config': cfg,
        'checks': checks,
        'summary': {
            'ready': all_ok,
            'server_one_ssh': one_ok,
            'server_two_ssh': two_ok,
            'db_reachable_from_server_two': db_reach_ok,
        }
    })

_PG_IDENT_RE = re.compile(r'^[A-Za-z_][A-Za-z0-9_]{0,62}$')


@app.route('/api/takserver/external-db/provision', methods=['POST'])
@login_required
def takserver_external_db_provision():
    """Provision the TAK Server database user on an external/managed PostgreSQL instance.
    Installs postgresql-client if needed, connects as the admin user, creates the app user
    (martiuser by default), grants required privileges, and returns a log of what was done.

    v0.9.12 hardening — defence against SQL injection:
      * All identifiers (db_user, db_name, admin_user, app_user) are
        regex-validated against the Postgres identifier grammar
        (^[A-Za-z_][A-Za-z0-9_]{0,62}$) before any psql call. Postgres
        does NOT support parameter substitution for identifiers, so this
        is the only safe path.
      * Passwords (app_pass) go through `psql -v` substitution and
        :'name' quoting, NEVER f-strings.
      * db_host is validated via _safe_migration_db_host (IP or simple
        DNS name only).
    """
    import secrets, string
    data = request.get_json() or {}
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    edb = cfg.get('external_db', {})

    db_host    = (data.get('db_host')    or edb.get('host')     or '').strip()
    db_port    = int(data.get('db_port') or edb.get('port')     or 5432)
    db_name    = (data.get('db_name')    or edb.get('name')     or 'cot').strip()
    app_user   = (data.get('app_user')   or edb.get('user')     or 'martiuser').strip()
    app_pass   = (data.get('app_pass')   or '').strip()
    admin_user = (data.get('admin_user') or 'postgres').strip()
    admin_pass = (data.get('admin_pass') or '').strip()

    if not db_host:
        return jsonify({'success': False, 'error': 'No database host provided', 'log': []}), 400
    if not admin_pass:
        return jsonify({'success': False, 'error': 'Admin password is required to provision the database', 'log': []}), 400

    # v0.9.12 — input validation BEFORE any psql call.
    if not _safe_migration_db_host(db_host):
        return jsonify({'success': False, 'error': 'Invalid db_host (must be IP or simple DNS name)', 'log': []}), 400
    if not (1 <= db_port <= 65535):
        return jsonify({'success': False, 'error': 'Invalid db_port', 'log': []}), 400
    for _ident_name, _ident_val in (('app_user', app_user), ('db_name', db_name), ('admin_user', admin_user)):
        if not _PG_IDENT_RE.fullmatch(_ident_val):
            return jsonify({
                'success': False,
                'error': f'Invalid {_ident_name}: must match Postgres identifier grammar ^[A-Za-z_][A-Za-z0-9_]{{0,62}}$',
                'log': []
            }), 400

    log = []

    def plog(msg):
        log.append(msg)

    # Auto-generate app password if not provided
    generated_pass = False
    if not app_pass:
        alphabet = string.ascii_letters + string.digits + '!@#%^*'
        app_pass = ''.join(secrets.choice(alphabet) for _ in range(24))
        generated_pass = True
        plog(f'  Generated strong password for {app_user}')

    # Install postgresql-client if psql not available
    try:
        r = subprocess.run(['which', 'psql'], capture_output=True, text=True, timeout=5)
        if r.returncode != 0:
            # Multiplatform (CLAUDE.md): the psql client package name differs by family —
            # Debian/Ubuntu = postgresql-client, RHEL/Rocky = postgresql (provides /usr/bin/psql).
            # Go through the apt<->dnf shim (_pkg_install), never a bare apt-get (which doesn't
            # exist on RHEL — that was the FileNotFoundError on the external-DB Rocky path).
            client_pkg = 'postgresql' if _distro_family() == 'rhel' else 'postgresql-client'
            plog(f'  psql not found — installing {client_pkg}...')
            ok_inst, inst_out = _pkg_install(client_pkg, timeout=300)
            if not ok_inst:
                plog(f'  ✗ Failed to install {client_pkg}: {(inst_out or "")[:300]}')
                return jsonify({'success': False, 'log': log, 'error': f'Could not install {client_pkg}'}), 500
            plog(f'  ✓ {client_pkg} installed')
        else:
            plog('  ✓ psql available')
    except Exception as e:
        plog(f'  ✗ Error checking psql: {e}')
        return jsonify({'success': False, 'log': log, 'error': str(e)}), 500

    def run_sql(sql, label, use_db=None, pw_var=None):
        """Run a SQL statement as the admin user. Returns (ok, output).

        pw_var={'name': value}: when provided the SQL is piped to psql via
        stdin with a leading \\set directive so psql resolves :'name' before
        sending to the server. Piping via stdin avoids shell-level and psql
        -v parser issues with special characters (e.g. # in passwords).
        """
        try:
            target_db = use_db or db_name
            env = dict(os.environ, PGPASSWORD=admin_pass)
            argv = ['psql', '-h', db_host, '-p', str(db_port), '-U', admin_user,
                    '-d', target_db, '--no-password', '-t', '-A']
            if pw_var:
                # Build \set directives piped via stdin — avoids -v parsing issues
                # with special chars (# treated as comment by psql's -v parser).
                set_lines = ''
                for _k, _v in pw_var.items():
                    escaped = _v.replace('\\', '\\\\').replace("'", "\\'")
                    set_lines += f"\\set {_k} '{escaped}'\n"
                stdin_sql = set_lines + sql
                r = subprocess.run(argv, input=stdin_sql, capture_output=True,
                                   text=True, timeout=20, env=env)
            else:
                argv.extend(['-c', sql])
                r = subprocess.run(argv, capture_output=True, text=True, timeout=20, env=env)
            ok = r.returncode == 0
            out = (r.stdout or r.stderr or '').strip()[:300]
            return ok, out
        except Exception as e:
            return False, str(e)[:300]

    # Step 1: Verify admin connection — always use the 'postgres' system database first
    # since the target database (e.g. 'cot') may not exist yet on fresh managed instances.
    plog(f'  Connecting as {admin_user} to {db_host}:{db_port}/postgres...')
    ok, out = run_sql('SELECT 1;', 'admin connect', use_db='postgres')
    if not ok:
        plog(f'  ✗ Admin connection failed: {out}')
        return jsonify({'success': False, 'log': log, 'error': f'Cannot connect as {admin_user}: {out}'}), 400
    plog(f'  ✓ Connected as {admin_user}')

    # Step 1b: Create the target database if it doesn't exist
    plog(f'  Checking if database {db_name} exists...')
    ok, out = run_sql(f"SELECT 1 FROM pg_database WHERE datname='{db_name}';", 'check db', use_db='postgres')
    db_exists = ok and '1' in out
    if db_exists:
        plog(f'  Database {db_name} already exists')
    else:
        plog(f'  Creating database {db_name}...')
        ok, out = run_sql(
            f"CREATE DATABASE {db_name} ENCODING 'UTF8' LC_COLLATE 'en_US.UTF-8' LC_CTYPE 'en_US.UTF-8' TEMPLATE template0;",
            'create db', use_db='postgres'
        )
        if not ok:
            plog(f'  ✗ Failed to create database: {out}')
            return jsonify({'success': False, 'log': log, 'error': f'Could not create database {db_name}: {out}'}), 500
        plog(f'  ✓ Created database {db_name}')

    # Step 2: Create app user if it doesn't exist.
    # Identifier (app_user) was regex-validated upfront — safe to inline.
    # Password goes through psql -v substitution and :'pw' quoting.
    plog(f'  Checking if user {app_user} exists...')
    ok, out = run_sql(f"SELECT 1 FROM pg_roles WHERE rolname='{app_user}';", 'check user', use_db='postgres')
    user_exists = ok and '1' in out
    if user_exists:
        plog(f'  User {app_user} already exists — updating password...')
        ok, out = run_sql(f"ALTER USER {app_user} WITH PASSWORD :'pw';", 'alter user', use_db='postgres', pw_var={'pw': app_pass})
        if not ok:
            plog(f'  ✗ Failed to update password: {out}')
        else:
            plog(f'  ✓ Password updated for {app_user}')
    else:
        plog(f'  Creating user {app_user}...')
        ok, out = run_sql(f"CREATE USER {app_user} WITH PASSWORD :'pw';", 'create user', use_db='postgres', pw_var={'pw': app_pass})
        if not ok:
            plog(f'  ✗ Failed to create user: {out}')
            return jsonify({'success': False, 'log': log, 'error': f'Could not create user {app_user}: {out}'}), 500
        plog(f'  ✓ Created user {app_user}')

    # Step 3: Grant database privileges (connect to postgres to issue GRANT ON DATABASE)
    plog(f'  Granting privileges on database {db_name} to {app_user}...')
    ok, out = run_sql(f'GRANT ALL PRIVILEGES ON DATABASE {db_name} TO {app_user};', 'grant db', use_db='postgres')
    plog(f'  {"✓" if ok else "✗"} GRANT ALL ON DATABASE: {out if not ok else "OK"}')

    # Step 3b: Cloud-provider-specific role grants
    is_rds = '.rds.amazonaws.com' in db_host
    is_azure = '.postgres.database.azure.com' in db_host
    if is_rds:
        plog(f'  AWS RDS detected — granting rds_superuser to {app_user} (required for PostGIS)...')
        ok, out = run_sql(f'GRANT rds_superuser TO {app_user};', 'grant rds_superuser', use_db='postgres')
        plog(f'  {"✓" if ok else "✗"} rds_superuser grant: {out if not ok else "OK"}')
    if is_azure:
        plog(f'  Azure PostgreSQL detected — granting azure_pg_admin to {app_user}...')
        ok, out = run_sql(f'GRANT azure_pg_admin TO {app_user};', 'grant azure_pg_admin', use_db='postgres')
        plog(f'  {"✓" if ok else "✗"} azure_pg_admin grant: {out if not ok else "OK"}')
        # Pre-create required extensions as admin — Azure blocks CREATE EXTENSION for non-superusers
        # even with IF NOT EXISTS, so SchemaManager (running as app_user) would fail without this.
        azure_exts = ['fuzzystrmatch', 'postgis', 'postgis_topology', 'address_standardizer', 'pgcrypto']
        plog(f'  Azure: pre-creating required extensions as {admin_user}...')
        ext_failures = []
        for ext in azure_exts:
            ok, out = run_sql(f'CREATE EXTENSION IF NOT EXISTS {ext};', f'create ext {ext}', use_db=db_name)
            plog(f'  {"✓" if ok else "△"} {ext}: {out if not ok else "OK"}')
            if not ok:
                ext_failures.append(ext)
        if ext_failures:
            missing = ', '.join(e.upper() for e in ext_failures)
            msg = (
                f'Azure extensions not whitelisted: {missing}. '
                f'Go to Azure Portal → your PostgreSQL Flexible Server → Server parameters → '
                f'search "azure.extensions" → add: FUZZYSTRMATCH, POSTGIS, POSTGIS_TOPOLOGY, '
                f'ADDRESS_STANDARDIZER, PGCRYPTO → Save. Then re-run Provision Database.'
            )
            plog(f'  ✗ Extension pre-creation failed — {msg}')
            return jsonify({'success': False, 'error': msg, 'log': log, 'extensions_not_whitelisted': True}), 400

    # Step 4: Grant schema privileges (must connect to the target database)
    plog(f'  Granting schema privileges...')
    schema_sql = (
        f'GRANT ALL ON SCHEMA public TO {app_user}; '
        f'ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON TABLES TO {app_user}; '
        f'ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON SEQUENCES TO {app_user};'
    )
    ok, out = run_sql(schema_sql, 'grant schema', use_db=db_name)
    plog(f'  {"✓" if ok else "✗"} Schema grants: {out if not ok else "OK"}')

    # Step 5: Verify app user can connect
    plog(f'  Verifying {app_user} can authenticate...')
    try:
        env = dict(os.environ, PGPASSWORD=app_pass)
        r = subprocess.run(
            ['psql', '-h', db_host, '-p', str(db_port), '-U', app_user, '-d', db_name,
             '-c', 'SELECT version();', '--no-password', '-t', '-A'],
            capture_output=True, text=True, timeout=15, env=env
        )
        if r.returncode == 0:
            plog(f'  ✓ {app_user} authenticated successfully')
        else:
            plog(f'  ⚠ {app_user} auth check: {(r.stderr or r.stdout or "").strip()[:200]}')
    except Exception as e:
        plog(f'  ⚠ Auth verify error: {e}')

    plog(f'  ✓ Database provisioned — {app_user}@{db_host}:{db_port}/{db_name}')

    return jsonify({
        'success': True,
        'log': log,
        'app_user': app_user,
        'app_pass': app_pass if generated_pass else None,
        'generated_pass': generated_pass,
    })


@app.route('/api/takserver/external-db/test-connection', methods=['POST'])
@login_required
def takserver_external_db_test_connection():
    """Test TCP + pg_isready connectivity to an external/managed PostgreSQL endpoint.
    Does not require SSH — runs checks from the local host (Server Two / TAK Server VM).
    """
    data = request.get_json() or {}
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    edb = cfg.get('external_db', {})
    db_host = (edb.get('host') or '').strip()
    db_port = int(edb.get('port') or 5432)
    db_name = (edb.get('name') or 'cot').strip()
    db_user = (edb.get('user') or 'martiuser').strip()
    db_pass = (edb.get('password') or '').strip()
    if not db_host:
        return jsonify({'success': False, 'error': 'No database host configured', 'checks': []}), 400

    # v0.9.12 — input validation. Catches command-injection vectors before
    # any shell-out below. Previous code piped `db_host` through `bash -c`.
    if not _safe_migration_db_host(db_host):
        return jsonify({'success': False, 'error': 'Invalid db_host (must be IP or simple DNS name)', 'checks': []}), 400
    if not (1 <= db_port <= 65535):
        return jsonify({'success': False, 'error': 'Invalid db_port', 'checks': []}), 400

    checks = []

    def add_check(name, ok, detail=''):
        # ok=None means "skipped/informational" — preserve as null in JSON, not bool
        checks.append({'name': name, 'ok': (None if ok is None else bool(ok)), 'detail': (detail or '')[:400]})

    # Check 1: TCP reachability — v0.9.12: socket.create_connection instead of
    # `bash -c "</dev/tcp/HOST/PORT"`. No shell, no injection vector.
    tcp_ok = False
    try:
        import socket as _sock_tc
        with _sock_tc.create_connection((db_host, db_port), timeout=8):
            tcp_ok = True
            add_check(f'TCP {db_host}:{db_port}', True, f'Connected to {db_host}:{db_port}')
    except (_sock_tc.timeout, OSError) as _tc_err:
        add_check(f'TCP {db_host}:{db_port}', False, str(_tc_err)[:200])
    except Exception as e:
        add_check(f'TCP {db_host}:{db_port}', False, str(e)[:200])

    # Check 2: pg_isready (if pg_isready available locally)
    pg_ready_ok = False
    try:
        r = subprocess.run(
            ['pg_isready', '-h', db_host, '-p', str(db_port), '-d', db_name, '-U', db_user, '-t', '8'],
            capture_output=True, text=True, timeout=12
        )
        pg_ready_ok = r.returncode == 0
        add_check(f'pg_isready ({db_name}@{db_host})', pg_ready_ok, (r.stdout or r.stderr or '').strip()[:200])
    except FileNotFoundError:
        add_check('pg_isready', None, 'pg_isready not installed locally — TCP check only')
    except Exception as e:
        add_check('pg_isready', False, str(e)[:200])

    # Check 3: psql auth (if password provided and psql available)
    if db_pass and tcp_ok:
        try:
            env = dict(os.environ, PGPASSWORD=db_pass)
            r = subprocess.run(
                ['psql', '-h', db_host, '-p', str(db_port), '-U', db_user, '-d', db_name,
                 '-c', 'SELECT version();', '--no-password', '-t', '-A'],
                capture_output=True, text=True, timeout=15, env=env
            )
            auth_ok = r.returncode == 0
            add_check(f'psql auth ({db_user}@{db_name})', auth_ok,
                      (r.stdout or r.stderr or '').strip()[:200] if not auth_ok else 'Authenticated successfully')
        except FileNotFoundError:
            add_check('psql auth', None, 'psql client not installed locally — skipped')
        except Exception as e:
            add_check('psql auth', False, str(e)[:200])

    # Check 4: Azure extension whitelist probe
    # Only runs when the endpoint is an Azure Flexible Server FQDN AND an app
    # user password is stored (i.e. Provision Database has been run at least once).
    # Skipped gracefully before provisioning — no FAIL so Test Connection passes
    # at the pre-provision stage and the operator can proceed to step 3.
    if '.postgres.database.azure.com' in db_host and tcp_ok:
        if not db_pass:
            add_check('Azure extensions whitelisted', None, 'Skipped — run Provision Database first, then re-test')
        else:
            azure_required = ['fuzzystrmatch', 'postgis', 'postgis_topology', 'address_standardizer', 'pgcrypto']
            try:
                names_sql = "SELECT name FROM pg_available_extensions WHERE name IN ({});".format(
                    ','.join(f"'{e}'" for e in azure_required)
                )
                env = dict(os.environ, PGPASSWORD=db_pass)
                # Use postgres system db — cot may not exist yet before first deploy
                r = subprocess.run(
                    ['psql', '-h', db_host, '-p', str(db_port), '-U', db_user, '-d', 'postgres',
                     '-c', names_sql, '--no-password', '-t', '-A'],
                    capture_output=True, text=True, timeout=15, env=env
                )
                if r.returncode == 0:
                    available = set(line.strip() for line in r.stdout.splitlines() if line.strip())
                    missing = [e for e in azure_required if e not in available]
                    if missing:
                        missing_upper = ','.join(e.upper() for e in missing)
                        all_upper = 'FUZZYSTRMATCH,POSTGIS,POSTGIS_TOPOLOGY,ADDRESS_STANDARDIZER,PGCRYPTO'
                        detail = (
                            f'Missing: {missing_upper}. '
                            f'In Azure Portal → {db_host.split(".")[0]} → Settings → Server parameters → '
                            f'azure.extensions → set value to: {all_upper} → Save.'
                        )
                        add_check('Azure extensions whitelisted', False, detail)
                    else:
                        add_check('Azure extensions whitelisted', True, 'All 5 required extensions available')
                else:
                    add_check('Azure extensions whitelisted', None, f'Could not query extensions — verify manually in Azure Portal')
            except Exception as e:
                add_check('Azure extensions whitelisted', None, f'Extension check skipped: {str(e)[:150]}')

    all_ok = all(c['ok'] for c in checks if c.get('ok') is not None)
    return jsonify({'success': all_ok, 'checks': checks, 'host': db_host, 'port': db_port})


@app.route('/api/takserver/two-server/ensure-ssh-key', methods=['POST'])
@login_required
def takserver_two_server_ensure_ssh_key():
    """Ensure an SSH key exists on this host for Server One. Generate if missing. Returns pub path and fingerprint."""
    data = request.get_json() or {}
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    s1 = cfg.get('server_one', {})
    key_path = (s1.get('ssh_key_path') or '').strip() or os.path.expanduser('~/.ssh/id_rsa')
    key_path = os.path.expanduser(key_path)
    pub_path = key_path + '.pub'
    if os.path.exists(key_path) and os.path.exists(pub_path):
        try:
            r = subprocess.run(
                ['ssh-keygen', '-l', '-f', pub_path],
                capture_output=True, text=True, timeout=5
            )
            fingerprint = (r.stdout or '').strip() if r.returncode == 0 else ''
        except Exception:
            fingerprint = ''
        # Persist key path so Guard Dog and TAK Server UI have it without user typing it
        if cfg.get('server_one', {}).get('ssh_key_path') != key_path:
            cfg['server_one'] = cfg.get('server_one') or {}
            cfg['server_one']['ssh_key_path'] = key_path
            settings['tak_deployment'] = cfg
            save_settings(settings)
        return jsonify({
            'success': True,
            'key_path': key_path,
            'public_key_path': pub_path,
            'fingerprint': fingerprint,
            'message': 'Key already exists',
        })
    key_dir = os.path.dirname(key_path)
    if key_dir and not os.path.isdir(key_dir):
        try:
            os.makedirs(key_dir, mode=0o700)
        except Exception as e:
            return jsonify({'success': False, 'error': f'Could not create {key_dir}: {e}'}), 400
    try:
        subprocess.run(
            ['ssh-keygen', '-t', 'ed25519', '-N', '', '-f', key_path, '-C', 'infra-tak-server-one'],
            capture_output=True, text=True, timeout=30,
            check=True,
        )
    except subprocess.CalledProcessError as e:
        return jsonify({'success': False, 'error': (e.stderr or e.stdout or str(e))[:400]}), 400
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:400]}), 400
    try:
        r = subprocess.run(['ssh-keygen', '-l', '-f', pub_path], capture_output=True, text=True, timeout=5)
        fingerprint = (r.stdout or '').strip() if r.returncode == 0 else ''
    except Exception:
        fingerprint = ''
    # Persist key path so Guard Dog and TAK Server UI have it without user typing it
    cfg['server_one'] = cfg.get('server_one') or {}
    cfg['server_one']['ssh_key_path'] = key_path
    settings['tak_deployment'] = cfg
    save_settings(settings)
    return jsonify({
        'success': True,
        'key_path': key_path,
        'public_key_path': pub_path,
        'fingerprint': fingerprint,
        'message': 'New key generated',
    })


@app.route('/api/takserver/two-server/upload-ssh-key', methods=['POST'])
@login_required
def takserver_two_server_upload_ssh_key():
    """v10.0.5: accept the operator's EXISTING SSH PRIVATE key (the AWS `.pem` / Azure key
    the cloud DB box was launched with) so the console can reach Server One with NO password
    and NO CLI — the universal path for cloud key-only boxes (EC2/Azure don't have SSH
    passwords). Security: the key is written 0600 to a FIXED console-owned path (never a
    request-controlled path → no traversal), validated as a real usable private key via
    `ssh-keygen -y`, and NEVER logged or echoed back. Passphrase-protected keys are rejected
    (can't be used non-interactively). Sets server_one.ssh_key_path + auth_method=ssh_key so
    the deploy skips steps 2-3 entirely."""
    data = request.get_json() or {}
    key_text = (data.get('private_key') or '')
    if not key_text.strip():
        return jsonify({'success': False, 'error': 'No key provided.'}), 400
    key_text = key_text.replace('\r\n', '\n').replace('\r', '\n')
    if not key_text.endswith('\n'):
        key_text += '\n'
    if '-----BEGIN' not in key_text or 'PRIVATE KEY' not in key_text:
        return jsonify({'success': False, 'error': 'That does not look like an SSH private key — expected a "-----BEGIN … PRIVATE KEY-----" block (e.g. your AWS .pem file).'}), 400
    # FIXED destination — never request-controlled (no traversal). Console-owned ~/.ssh.
    key_path = os.path.expanduser('~/.ssh/infratak_serverone')
    try:
        os.makedirs(os.path.dirname(key_path), mode=0o700, exist_ok=True)
    except Exception as e:
        return jsonify({'success': False, 'error': f'Could not prepare key dir: {str(e)[:160]}'}), 400
    try:
        fd = os.open(key_path, os.O_WRONLY | os.O_CREAT | os.O_TRUNC, 0o600)
        with os.fdopen(fd, 'w') as f:
            f.write(key_text)
        os.chmod(key_path, 0o600)
    except Exception as e:
        return jsonify({'success': False, 'error': f'Could not write key: {str(e)[:160]}'}), 500
    # Validate it's a usable, passphrase-free private key by deriving its public half.
    try:
        r = subprocess.run(['ssh-keygen', '-y', '-f', key_path], capture_output=True, text=True, timeout=10)
    except Exception as e:
        try: os.remove(key_path)
        except Exception: pass
        return jsonify({'success': False, 'error': f'Key validation failed: {str(e)[:160]}'}), 500
    if r.returncode != 0:
        try: os.remove(key_path)   # don't leave a bad/sensitive file around
        except Exception: pass
        _err = (r.stderr or r.stdout or '').lower()
        hint = ('the key is passphrase-protected — re-export it without a passphrase and upload that'
                if 'passphrase' in _err or 'incorrect passphrase' in _err
                else 'invalid or unsupported private key format')
        return jsonify({'success': False, 'error': f'Key rejected: {hint}.'}), 400
    fingerprint = ''
    try:
        fr = subprocess.run(['ssh-keygen', '-l', '-f', key_path], capture_output=True, text=True, timeout=5)
        if fr.returncode == 0:
            fingerprint = (fr.stdout or '').strip()
    except Exception:
        pass
    # Point Server One at this key + ssh_key auth (skips generate/copy).
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    cfg['server_one'] = cfg.get('server_one') or {}
    cfg['server_one']['ssh_key_path'] = key_path
    cfg['server_one']['auth_method'] = 'ssh_key'
    settings['tak_deployment'] = cfg
    save_settings(settings)
    return jsonify({
        'success': True,
        'key_path': key_path,
        'fingerprint': fingerprint,
        'message': 'SSH key uploaded — Server One will connect with it. Skip steps 2 & 3; go straight to 4. Deploy Server One.',
    })


@app.route('/api/takserver/two-server/install-ssh-key', methods=['POST'])
@login_required
def takserver_two_server_install_ssh_key():
    """Copy this host's SSH public key to Server One using ssh-copy-id (one-time password). Password not stored.
    Optional body keys install_host, install_user, install_port — copy to that host instead (e.g. new Server One before DB migration)."""
    data = request.get_json() or {}
    password = (data.get('password') or '').strip()
    if not password:
        return jsonify({'success': False, 'error': 'Password required for one-time copy'}), 400
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    s1 = cfg.get('server_one', {})
    install_host = (data.get('install_host') or '').strip()
    if install_host:
        if not _safe_migration_db_host(install_host):
            return jsonify({'success': False, 'error': 'Invalid install_host (use IPv4 or hostname)'}), 400
        host = install_host
        user = (data.get('install_user') or s1.get('ssh_user') or 'root').strip() or 'root'
        raw_port = data.get('install_port')
        if raw_port is not None and str(raw_port).strip():
            try:
                port = int(raw_port)
            except (TypeError, ValueError):
                return jsonify({'success': False, 'error': 'install_port must be a number'}), 400
        else:
            port = int(s1.get('ssh_port') or 22)
    else:
        host = (s1.get('host') or '').strip()
        if not host:
            return jsonify({'success': False, 'error': 'Server One host not set'}), 400
        user = (s1.get('ssh_user') or 'root').strip() or 'root'
        port = int(s1.get('ssh_port') or 22)
    key_path = (s1.get('ssh_key_path') or '').strip() or os.path.expanduser('~/.ssh/id_rsa')
    key_path = os.path.expanduser(key_path)
    pub_path = key_path + '.pub'
    if not os.path.exists(pub_path):
        return jsonify({'success': False, 'error': f'Public key not found at {pub_path}. Run "Setup SSH key" first.'}), 400
    if shutil.which('sshpass') is None:
        return jsonify({'success': False, 'error': 'sshpass not installed. Run: apt install sshpass (or use manual ssh-copy-id)'}), 400
    try:
        r = subprocess.run(
            ['sshpass', '-e', 'ssh-copy-id', '-i', pub_path,
             '-o', 'StrictHostKeyChecking=accept-new', '-p', str(port), f'{user}@{host}'],
            capture_output=True, text=True, timeout=30,
            env={**os.environ, 'SSHPASS': password},
        )
        if r.returncode != 0:
            err = (r.stderr or r.stdout or 'Unknown error').strip()[:500]
            return jsonify({'success': False, 'error': err}), 400
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:400]}), 400
    if install_host:
        return jsonify({'success': True, 'message': f'Key installed on {user}@{host}:{port}. Next: 4. Deploy Server One (DB) on new host (this page), then Start migration.'})
    return jsonify({'success': True, 'message': 'Key installed on Server One. Next: 4. Deploy Server One (DB).'})


def _valid_core_ip(value):
    """core_ip is interpolated into root pg_hba / firewall commands on Server One and
    MUST be a literal IPv4 (used as `<ip>/32` and a firewalld `family='ipv4'` source).
    Strict IPv4 validation keeps the value correct AND makes the shell interpolation
    injection-proof — a valid IPv4 contains no shell-significant characters."""
    v = (value or '').strip()
    if not v:
        return False
    try:
        ipaddress.IPv4Address(v)
        return True
    except (ipaddress.AddressValueError, ValueError):
        return False


def _resolve_core_ip(settings, cfg):
    """Resolve Server Two (Core) public IP for firewall and pg_hba rules.
    Returns a VALIDATED IPv4 string, or None — callers must treat None as 'not set'.
    server_two.host is operator-supplied via the request config blob, so it is
    validated here (the single chokepoint feeding _setup_server_one[_rhel], which
    interpolate core_ip into root shell commands on Server One)."""
    s2 = cfg.get('server_two', {})
    if s2.get('use_localhost'):
        core_ip = (settings.get('server_ip') or '').strip()
        if not core_ip:
            try:
                r = subprocess.run(
                    ['curl', '-s', '--connect-timeout', '5', 'https://ifconfig.me'],
                    capture_output=True, text=True, timeout=8
                )
                core_ip = (r.stdout or '').strip() if r.returncode == 0 else ''
            except Exception:
                pass
    else:
        core_ip = (s2.get('host') or '').strip()
    return core_ip if _valid_core_ip(core_ip) else None


def _setup_server_one_rhel(s1, core_ip, db_port, db_pkg_path=None, db_pkg_name=None):
    """RHEL/Rocky Server One (DB box) setup — the dnf/PGDG/.noarch.rpm/systemctl/firewalld/
    /var/lib/pgsql mirror of the Debian _setup_server_one, per TAK Server Config Guide 5.7
    (pp.14-16) and the proven single-server RHEL install. The takserver-database .noarch.rpm
    is the DB installer (sets up the cot DB + martiuser, same role as the .deb); we install it,
    then verify + SELF-HEAL (postgresql-15-setup initdb + start if the rpm didn't) and configure
    remote access at the RHEL data dir. Heavily instrumented so the first live run shows exactly
    what the rpm did. All ops run over SSH on Server One (sudo there). Returns (ok, log, db_password)."""
    log = ['Server One detected as RHEL/Rocky family — using dnf / firewalld / systemctl / /var/lib/pgsql path.']
    # Defense-in-depth: core_ip is interpolated into root pg_hba/firewalld commands below.
    # _resolve_core_ip already validates it, but re-check at the sink so no future caller
    # can reach the shell interpolation with a non-IPv4 (injection-proofing).
    if not _valid_core_ip(core_ip):
        return False, log + ['Refusing to configure Server One: core IP is not a valid IPv4 address.'], ''
    # EL version + arch for the EPEL/PGDG repo URLs.
    _, _elv = _ssh_probe(s1, '. /etc/os-release 2>/dev/null; echo "${VERSION_ID%%.*}"', timeout=10)
    el_ver = (_elv or '').strip()
    el_ver = el_ver if el_ver in ('8', '9') else '9'
    _, _ar = _ssh_probe(s1, 'uname -m', timeout=10)
    el_arch = 'aarch64' if ('aarch64' in (_ar or '') or 'arm64' in (_ar or '')) else 'x86_64'
    # Reusable SSH snippets: discover the PG data dir + service name (PGDG postgresql-15 vs base).
    # NB: /var/lib/pgsql is 0700 postgres-owned — the glob MUST run under sudo or it expands
    # to nothing as the SSH login user (the bug that bit the first run: empty PGDATA).
    PGDATA = ("PGDATA=$(sudo sh -c 'ls -d /var/lib/pgsql/*/data 2>/dev/null' | sort -V | tail -1); "
              "[ -z \"$PGDATA\" ] && sudo test -d /var/lib/pgsql/data && PGDATA=/var/lib/pgsql/data; true")
    PGSVC = ('PGSVC=postgresql-15; systemctl list-unit-files 2>/dev/null | grep -q "^postgresql-15" || PGSVC=postgresql; true')

    # Step 1: repos — EPEL + PGDG (arch/EL-aware) + disable the system postgresql module + CRB.
    repo_cmd = (
        'sudo dnf -y install epel-release 2>&1 || '
        f'sudo dnf -y install https://dl.fedoraproject.org/pub/epel/epel-release-latest-{el_ver}.noarch.rpm 2>&1 || true; '
        f'sudo dnf -y install https://download.postgresql.org/pub/repos/yum/reporpms/EL-{el_ver}-{el_arch}/pgdg-redhat-repo-latest.noarch.rpm 2>&1 || true; '
        'sudo dnf -qy module disable postgresql 2>&1 || true; '
        'sudo dnf -y install dnf-plugins-core 2>&1 || true; '
        '(sudo dnf config-manager --set-enabled crb 2>/dev/null || sudo dnf config-manager --set-enabled powertools 2>/dev/null || true); '
        'echo REPO_DONE'
    )
    _, rout = _ssh_probe(s1, repo_cmd, timeout=240)
    log.append('Repos (EPEL/PGDG/CRB): ' + ('configured.' if 'REPO_DONE' in (rout or '') else ('warnings — ' + (rout or '')[:300])))

    # Step 2: install the takserver-database .noarch.rpm (the DB installer), unless already set up.
    if db_pkg_path and db_pkg_name:
        verify_cmd = (PGDATA + '; ' + PGSVC + '; '
                      'sudo -u postgres psql -lqt 2>/dev/null | grep -qw cot && '
                      'systemctl is-active "$PGSVC" >/dev/null 2>&1 && echo PG_OK')
        vok, vout = _ssh_probe(s1, verify_cmd, timeout=15)
        if vok and 'PG_OK' in (vout or ''):
            log.append('PostgreSQL already running and cot exists — skipping rpm install.')
        else:
            sok, sout = _scp_to_host(s1, db_pkg_path, '/tmp/', timeout=300)
            if not sok:
                log.append('SCP of database rpm failed: ' + (sout or ''))
                return False, log, ''
            log.append('Copied database rpm to /tmp/ on Server One.')
            install_cmd = f'cd /tmp && sudo dnf -y install ./{db_pkg_name} --setopt=clean_requirements_on_remove=false 2>&1; echo RC=$?'
            _, iout = _ssh_probe(s1, install_cmd, timeout=600)
            log.append('takserver-database rpm install output:')
            log.append((iout or '')[:1000])
    else:
        _, iout = _ssh_probe(s1, (
            'sudo dnf -y install postgresql15-server postgresql15-contrib postgis34_15 2>&1 || '
            'sudo dnf -y install postgresql15-server postgresql15-contrib 2>&1; echo RC=$?'), timeout=600)
        log.append('vanilla PG15 install: ' + (iout or '')[:300])

    # Step 3: ensure the cluster is INITIALIZED + STARTED (self-heal — the rpm may or may not have).
    init_cmd = (
        PGDATA + '; ' + PGSVC + '; '
        'if [ -z "$PGDATA" ] || [ ! -f "$PGDATA/PG_VERSION" ]; then '
        '  SETUP=$(ls /usr/pgsql-*/bin/postgresql-*-setup 2>/dev/null | sort -V | tail -1); '
        '  if [ -n "$SETUP" ]; then sudo "$SETUP" initdb 2>&1; else sudo postgresql-setup --initdb 2>&1; fi; '
        "  PGDATA=$(sudo sh -c 'ls -d /var/lib/pgsql/*/data 2>/dev/null' | sort -V | tail -1); [ -z \"$PGDATA\" ] && PGDATA=/var/lib/pgsql/data; "
        'fi; '
        'sudo systemctl enable "$PGSVC" 2>/dev/null; sudo systemctl start "$PGSVC" 2>&1; '
        'echo "PGDATA=$PGDATA PGSVC=$PGSVC ACTIVE=$(systemctl is-active "$PGSVC" 2>/dev/null)"'
    )
    _, nout = _ssh_probe(s1, init_cmd, timeout=120)
    log.append('PG init/start: ' + (nout or '')[:300])

    # Step 4: remote-access config (listen_addresses + pg_hba) at the RHEL data dir, then restart.
    cfg_cmd = (
        PGDATA + '; ' + PGSVC + '; '
        '[ -z "$PGDATA" ] && { echo NO_PGDATA; exit 0; }; '
        'sudo sed -i "/^[[:space:]]*#*[[:space:]]*listen_addresses[[:space:]]*=/d" "$PGDATA/postgresql.conf"; '
        "printf \"\\nlisten_addresses = '*'\\n\" | sudo tee -a \"$PGDATA/postgresql.conf\" >/dev/null; "
        'sudo sed -i "s/md5host/md5\\nhost/g" "$PGDATA/pg_hba.conf"; '
        f'grep -q "^host.*{core_ip}/32" "$PGDATA/pg_hba.conf" 2>/dev/null || '
        f'printf "\\nhost    all    all    {core_ip}/32    md5\\n" | sudo tee -a "$PGDATA/pg_hba.conf" >/dev/null; '
        'sudo systemctl restart "$PGSVC" 2>&1; echo "ACTIVE=$(systemctl is-active "$PGSVC" 2>/dev/null)"'
    )
    _, cout = _ssh_probe(s1, cfg_cmd, timeout=40)
    if 'NO_PGDATA' in (cout or '') or 'ACTIVE=active' not in (cout or ''):
        log.append('PostgreSQL remote-access config FAILED: ' + (cout or '')[:300])
        _, diag = _ssh_probe(s1, (
            PGDATA + '; ' + PGSVC + '; echo "--- pgdata=$PGDATA svc=$PGSVC ---"; '
            'sudo ls -la "$PGDATA" 2>&1 | head -6; echo "--- journal ---"; '
            'sudo journalctl -u "$PGSVC" -n 25 --no-pager 2>&1 | tail -25; echo "--- rpm -qa postgres/takserver ---"; '
            'rpm -qa 2>/dev/null | grep -iE "postgres|postgis|takserver" | head'), timeout=25)
        log.append('Diagnostics from Server One:')
        log.append((diag or '')[:1400])
        return False, log, ''
    log.append(f'PostgreSQL configured: listen_addresses=*, pg_hba host {core_ip}, service active.')

    # Step 5: firewalld — open db_port FROM the core IP only (+ ssh); drop any broad port-open.
    fw_cmd = (
        'sudo systemctl enable --now firewalld 2>/dev/null || true; '
        'sudo firewall-cmd --permanent --add-service=ssh 2>/dev/null || true; '
        f'sudo firewall-cmd --permanent --add-rich-rule="rule family=\'ipv4\' source address=\'{core_ip}\' port protocol=\'tcp\' port=\'{db_port}\' accept" 2>&1 || true; '
        f'sudo firewall-cmd --permanent --remove-port={db_port}/tcp 2>/dev/null || true; '
        'sudo firewall-cmd --reload 2>&1; echo FW_DONE'
    )
    _, fout = _ssh_probe(s1, fw_cmd, timeout=40)
    log.append('firewalld: ' + ('db port scoped to core, ssh allowed.' if 'FW_DONE' in (fout or '') else (fout or '')[:200]))

    # Step 6: capture + verify the DB password (platform-neutral helpers — already work on RHEL).
    db_password, _ = _fetch_db_password_from_server_one(s1)
    if db_password:
        log.append('Captured DB password from Server One.')
        pw_ok, pw_msg = _verify_server_one_db_password(s1, db_password, db_port=db_port)
        log.append('DB credential verified on Server One.' if pw_ok else f'Warning: captured password failed validation ({pw_msg}).')
    else:
        log.append('Warning: could not read DB password from Server One CoreConfig.')

    # Step 7: build the TAK schema (RHEL-only). The .noarch.rpm deliberately does NOT run
    # SchemaManager — its own takserver-setup-db.sh says it "cannot be run by the RPM installer
    # and must be a manual post-install step." (The Debian .deb's postinst DOES build the schema,
    # which is why the .deb split never needed this.) Without it the cot DB comes up with the
    # martiuser role + database but ZERO tables, so the core 500s on /oauth/token ("relation
    # group_bitpos_sequence does not exist") and 8446 login fails. Run SchemaManager explicitly
    # (idempotent 'upgrade' — reports "up to date" on re-runs; java + SchemaManager.jar both ship
    # with takserver-database). Field-validated on aws-rocky1: 93 updates, cot 0→60 tables.
    if db_pkg_path and db_password:
        schema_cmd = (
            'if [ -f /opt/tak/db-utils/SchemaManager.jar ]; then '
            'cd /opt/tak/db-utils && sudo java -jar SchemaManager.jar '
            f'-url jdbc:postgresql://127.0.0.1:{db_port}/cot -user martiuser '
            f'-password {shlex.quote(db_password)} upgrade 2>&1 | tail -8; '
            'else echo NO_SCHEMA_MANAGER; fi'
        )
        _, scout = _ssh_probe(s1, schema_cmd, timeout=240)
        if 'up to date' in (scout or '') or 'Successfully applied' in (scout or ''):
            log.append('TAK schema built on Server One (SchemaManager upgrade).')
        else:
            log.append('WARNING: TAK schema build did not confirm — the cot DB may have no tables '
                       '(8446 login will 500). Output: ' + (scout or '')[:400])
    return True, log, db_password


def _setup_server_one(s1, core_ip, db_port, db_pkg_path=None, db_pkg_name=None):
    """Full Server One setup: optionally install DB .deb, configure PG for remote access, open UFW.
    Returns (ok, log_lines, db_password).
    """
    log = []
    # Defense-in-depth: core_ip is interpolated into root pg_hba/UFW commands on Server One
    # (and the RHEL branch below). _resolve_core_ip validates it; re-check at the sink so no
    # caller can reach the shell interpolation with a non-IPv4 value (injection-proofing).
    if not _valid_core_ip(core_ip):
        return False, ['Refusing to configure Server One: core IP is not a valid IPv4 address.'], ''
    # v10.0.5: the DB box (Server One) can be a DIFFERENT OS family than the console. Detect its
    # OS over SSH and dispatch to the RHEL/Rocky path (dnf/PGDG/.noarch.rpm/systemctl/firewalld/
    # /var/lib/pgsql) — mirrors the Debian steps below per TAK Config Guide 5.7 + the proven
    # single-server RHEL install. Default stays Debian (byte-identical to the original path).
    _fam_ok, _fam = _ssh_probe(s1, '. /etc/os-release 2>/dev/null; echo "${ID} ${ID_LIKE}"', timeout=12)
    if _fam_ok and any(t in (_fam or '').lower() for t in ('rhel', 'rocky', 'almalinux', 'centos', 'fedora')):
        return _setup_server_one_rhel(s1, core_ip, db_port, db_pkg_path, db_pkg_name)
    # Kill stale apt/dpkg locks and fix broken packages from interrupted installs.
    apt_unlock = (
        'sudo killall -q apt-get dpkg unattended-upgr 2>/dev/null; '
        'for i in 1 2 3 4 5 6; do '
        'fuser /var/lib/dpkg/lock /var/lib/apt/lists/lock /var/cache/apt/archives/lock >/dev/null 2>&1 || break; '
        'echo "Waiting for apt lock ($i)…"; sleep 5; done; '
        'sudo rm -f /var/lib/dpkg/lock /var/lib/dpkg/lock-frontend /var/lib/apt/lists/lock /var/cache/apt/archives/lock 2>/dev/null; '
        'dpkg -l takserver-database 2>/dev/null | grep -q "^..[rR]" && '
        'sudo dpkg --force-remove-reinstreq --remove takserver-database 2>/dev/null; '
        'sudo dpkg --configure -a 2>/dev/null; '
        'sudo apt-get -f install -y 2>/dev/null; true'
    )
    _ssh_probe(s1, apt_unlock, timeout=60)

    # Step 1: SCP and install the database .deb if provided
    if db_pkg_path and db_pkg_name:
        # Fix any corrupted pg_hba.conf before trying to start PG
        _ssh_probe(s1, (
            'PG_MAIN=$(find /etc/postgresql -type d -name main 2>/dev/null | head -1); '
            '[ -n "$PG_MAIN" ] && [ -f "$PG_MAIN/pg_hba.conf" ] && '
            'sudo sed -i "s/md5host/md5\\nhost/g" "$PG_MAIN/pg_hba.conf" 2>/dev/null; true'
        ), timeout=10)
        _ssh_probe(s1, 'sudo pg_ctlcluster 15 main start 2>/dev/null; true', timeout=20)
        already_ok = False
        verify_cmd = 'sudo -u postgres psql -lqt 2>/dev/null | grep -q cot && systemctl is-active postgresql >/dev/null 2>&1 && echo PG_OK'
        vok, vout = _ssh_probe(s1, verify_cmd, timeout=10)
        if vok and 'PG_OK' in (vout or ''):
            already_ok = True
            log.append('PostgreSQL already running and cot database exists — skipping install.')

        if not already_ok:
            ok, out = _scp_to_host(s1, db_pkg_path, '/tmp/', timeout=300)
            if not ok:
                return False, ['SCP failed: ' + (out or '')], ''
            log.append('Copied database package to Server One /tmp/')

            install_cmd = (
                'cd /tmp && sudo apt-get update -qq && '
                'sudo apt-get install -y lsb-release && '
                'sudo mkdir -p /etc/apt/keyrings && '
                'sudo curl -sL https://www.postgresql.org/media/keys/ACCC4CF8.asc --output /etc/apt/keyrings/postgresql.asc && '
                'echo "deb [signed-by=/etc/apt/keyrings/postgresql.asc] https://apt.postgresql.org/pub/repos/apt $(lsb_release -cs)-pgdg main" '
                '| sudo tee /etc/apt/sources.list.d/postgresql.list >/dev/null && '
                'sudo apt-get update -qq && '
                f'sudo DEBIAN_FRONTEND=noninteractive apt-get install -y ./{db_pkg_name}'
            )
            ok, out = _ssh_probe(s1, install_cmd, timeout=600)
            log.append(out or '')
            if not ok:
                _ssh_probe(s1, 'sudo pg_ctlcluster 15 main start 2>/dev/null; true', timeout=20)
                vok, vout = _ssh_probe(s1, verify_cmd, timeout=10)
                if not (vok and 'PG_OK' in (vout or '')):
                    diag_cmd = (
                        'echo "--- cluster start attempt ---"; '
                        'sudo pg_ctlcluster 15 main start 2>&1; '
                        'echo "--- cluster logs ---"; '
                        'sudo cat /var/lib/postgresql/15/main/log/$(ls -t /var/lib/postgresql/15/main/log/ 2>/dev/null | head -1) 2>/dev/null | tail -30 || echo "no cluster logs"; '
                        'echo "--- postgresql.conf listen ---"; '
                        'grep -n listen_addresses /etc/postgresql/15/main/postgresql.conf 2>/dev/null; '
                        'echo "--- pg_hba.conf ---"; '
                        'cat /etc/postgresql/15/main/pg_hba.conf 2>/dev/null | grep -v "^#" | grep -v "^$"'
                    )
                    _, diag = _ssh_probe(s1, diag_cmd, timeout=20)
                    log.append('Install failed. Diagnostics from Server One:')
                    log.append(diag or 'no diagnostic output')
                    return False, log, ''
                log.append('Install had warnings but PostgreSQL is running and cot database exists.')
            log.append('TAK database package installed.')
    else:
        # No .deb provided — check if PG is already installed, if not install vanilla PG
        check_cmd = 'dpkg -l 2>/dev/null | grep -ci postgres'
        ok, out = _ssh_probe(s1, check_cmd, timeout=10)
        pg_count = int((out or '0').strip()) if ok else 0
        if pg_count == 0:
            pg_install = (
                'sudo apt-get update -qq && '
                'sudo apt-get install -y lsb-release && '
                'sudo mkdir -p /etc/apt/keyrings && '
                'sudo curl -sL https://www.postgresql.org/media/keys/ACCC4CF8.asc --output /etc/apt/keyrings/postgresql.asc && '
                'echo "deb [signed-by=/etc/apt/keyrings/postgresql.asc] https://apt.postgresql.org/pub/repos/apt $(lsb_release -cs)-pgdg main" '
                '| sudo tee /etc/apt/sources.list.d/postgresql.list >/dev/null && '
                'sudo apt-get update -qq && '
                'sudo DEBIAN_FRONTEND=noninteractive apt-get install -y postgresql-15 postgresql-15-postgis-3'
            )
            ok, out = _ssh_probe(s1, pg_install, timeout=300)
            log.append(out or '')
            if not ok:
                log.append('PostgreSQL install failed on Server One.')
                return False, log, ''
            log.append('PostgreSQL installed on Server One.')

    # Step 2: Configure PostgreSQL for remote access
    # Fix any previously corrupted pg_hba.conf lines (e.g. "md5host" from missing newline)
    pg_config_cmd = (
        'PG_MAIN=$(find /etc/postgresql -type d -name main 2>/dev/null | head -1) && '
        '[ -n "$PG_MAIN" ] && [ -f "$PG_MAIN/postgresql.conf" ] && '
        "sudo sed -i '/^\\s*#*\\s*listen_addresses\\s*=/d' \"$PG_MAIN/postgresql.conf\" && "
        "printf \"\\nlisten_addresses = '*'\\n\" | sudo tee -a \"$PG_MAIN/postgresql.conf\" > /dev/null && "
        'sudo sed -i "s/md5host/md5\\nhost/g" "$PG_MAIN/pg_hba.conf" && '
        f'(grep -q "^host.*{core_ip}/32" "$PG_MAIN/pg_hba.conf" 2>/dev/null || '
        f'printf "\\nhost    all    all    {core_ip}/32    md5\\n" | sudo tee -a "$PG_MAIN/pg_hba.conf" > /dev/null) && '
        '(sudo pg_ctlcluster 15 main restart 2>/dev/null || sudo systemctl restart postgresql 2>/dev/null || true)'
    )
    ok, out = _ssh_probe(s1, pg_config_cmd, timeout=30)
    if not ok:
        log.append('PostgreSQL remote-access config failed: ' + (out or ''))
        return False, log, ''
    log.append('PostgreSQL configured: listen_addresses=* and pg_hba entry for ' + core_ip)

    # Step 3: UFW — v0.9.12 hardening: drop unconditional `allow {db_port}/tcp`
    # (defeated the source-scoped allow above and exposed Postgres to the public
    # internet). Postgres only needs to be reachable from Server Two's IP. Same
    # class of bug as the v0.9.11 CloudTAK 5433 incident — except UFW is
    # actually effective here (native Postgres, not Docker-published).
    # Also add an explicit `deny {db_port}/tcp` belt-and-braces so a future
    # `ufw allow` of that port (e.g. by an operator script) doesn't reopen the
    # surface unless the source-scope rule is matched first.
    # v0.9.46: delete any legacy broad `allow {db_port}/tcp` (pre-v0.9.12 boxes still
    # carry one; UFW is first-match-wins so it shadows the deny below, leaving Postgres
    # open to the internet). Delete runs AFTER the scoped allow so the core never loses
    # its DB; `delete allow` only removes the Anywhere rule, scoped allows survive.
    # ORDER: delete any pre-existing deny FIRST (UFW appends + first-match-wins, so a
    # stale deny would shadow the scoped allow), add the scoped allow, drop the broad
    # allow, then re-add the deny LAST so it sits below the allow.
    ufw_cmd = (
        f'sudo ufw allow 22/tcp && '
        f'sudo ufw allow from {core_ip} to any port 22 proto tcp && '
        f'(sudo ufw delete deny {db_port}/tcp || true) && '
        f'sudo ufw allow from {core_ip} to any port {db_port} proto tcp && '
        f'(sudo ufw delete allow {db_port}/tcp || true) && '
        f'sudo ufw deny {db_port}/tcp && '
        'sudo ufw --force enable && sudo ufw reload'
    )
    ok, out = _ssh_probe(s1, ufw_cmd, timeout=25)
    if not ok:
        log.append('UFW config failed: ' + (out or ''))
        return False, log, ''
    log.append(f'UFW: allowed {core_ip} → port {db_port}, denied all other sources (v0.9.12 hardening)')

    # Step 4: Read auto-generated DB password from Server One (try multiple sources)
    db_password, _ = _fetch_db_password_from_server_one(s1)
    if db_password:
        log.append('Captured DB password from Server One.')
        pw_ok, pw_msg = _verify_server_one_db_password(s1, db_password, db_port=db_port)
        if pw_ok:
            log.append('DB credential verified on Server One.')
        else:
            log.append(f'Warning: captured password failed validation ({pw_msg}). '
                       'Use Sync DB Password after deploy if TAK Server cannot connect.')
    else:
        log.append('Warning: could not read DB password from Server One — CoreConfig may need manual password fix.')

    return True, log, db_password


def _fetch_db_password_from_server_one(s1_cfg):
    """Fetch martiuser DB password from Server One. Tries CoreConfig.example.xml and CoreConfig.xml.
    Fetches file via sudo cat and parses in Python so we don't depend on remote grep/sed.
    Returns (password, failure_reason). On success: (str, None). On failure: ('', str)."""
    first_ssh_error = None
    for pw_file in ('/opt/tak/CoreConfig.example.xml', '/opt/tak/CoreConfig.xml'):
        ok, out = _ssh_probe(s1_cfg, f"sudo cat {pw_file} 2>/dev/null", timeout=10)
        if not ok:
            if first_ssh_error is None:
                raw = (out or '').strip()[:200]
                first_ssh_error = raw if raw else 'connection failed or no response (check key, host, and that Server One allows SSH from this host)'
            continue
        if not (out or '').strip():
            continue
        # Prefer JDBC <connection ...> password first (avoid matching unrelated
        # password fields like LDAP/service-account credentials in CoreConfig).
        for pattern in (
            r'<connection[^>]*url\s*=\s*["\']jdbc:postgresql://[^"\']+/cot["\'][^>]*password\s*=\s*["\']([^"\']*)["\']',
            r'<connection[^>]*username\s*=\s*["\']martiuser["\'][^>]*password\s*=\s*["\']([^"\']*)["\']',
            r'password\s*=\s*["\']([^"\']*)["\']',
            r'password=["\']([^"\']*)["\']',
        ):
            match = re.search(pattern, out)
            if match:
                candidate = (match.group(1) or '').strip()
                if candidate:
                    return candidate, None
        for pwd_cmd in (
            f"sudo grep -o 'password=\"[^\"]*\"' {pw_file} 2>/dev/null | head -1 | sed 's/.*password=\"//;s/\"$//'",
            f"sudo sed -n 's/.*password=\"\\([^\"]*\\)\".*/\\1/p' {pw_file} 2>/dev/null | head -1",
        ):
            ok2, pwd_out = _ssh_probe(s1_cfg, pwd_cmd, timeout=10)
            candidate = (pwd_out or '').strip() if ok2 else ''
            if candidate:
                return candidate, None
    if first_ssh_error:
        return '', f'SSH to Server One failed: {first_ssh_error}'
    return '', 'No password= found in CoreConfig.example.xml or CoreConfig.xml on Server One (or password was empty).'


def _verify_server_one_db_password(s1_cfg, db_password, db_port=5432, db_user='martiuser', db_name='cot'):
    """Validate DB credentials directly on Server One via psql.
    Returns (True, msg) when auth works, else (False, reason)."""
    if not (db_password or '').strip():
        return False, 'empty DB password'
    try:
        port = int(db_port or 5432)
    except Exception:
        port = 5432
    pw_q = shlex.quote((db_password or '').strip())
    user_q = shlex.quote((db_user or 'martiuser').strip() or 'martiuser')
    db_q = shlex.quote((db_name or 'cot').strip() or 'cot')
    # v0.9.46: capture psql's real error (was 2>/dev/null) so a failure reports WHY —
    # password-auth-failed vs no-pg_hba-entry vs missing-db — instead of a blanket "rejected".
    cmd = (
        "if ! command -v psql >/dev/null 2>&1; then echo NO_PSQL; exit 0; fi; "
        f"ERR=$(PGPASSWORD={pw_q} psql -h 127.0.0.1 -p {port} -U {user_q} -d {db_q} -tAc \"select 1\" 2>&1); "
        "if echo \"$ERR\" | tr -d '[:space:]' | grep -qx 1; then echo AUTH_OK; "
        "else echo \"AUTH_FAIL: $(echo \"$ERR\" | head -1)\"; fi"
    )
    ok, out = _ssh_probe(s1_cfg, cmd, timeout=15)
    out_s = (out or '').strip()
    if not ok:
        return False, (out_s[:200] or 'SSH validation failed')
    if 'AUTH_OK' in out_s:
        return True, 'DB auth verified on Server One'
    if 'NO_PSQL' in out_s:
        return False, 'psql not available on Server One for credential validation'
    low = out_s.lower()
    if 'password authentication failed' in low:
        return False, 'DB password rejected by PostgreSQL on Server One (password authentication failed)'
    if 'pg_hba' in low:
        return False, 'pg_hba.conf on Server One has no entry for the 127.0.0.1/martiuser loopback path — ' + out_s[:160]
    if 'does not exist' in low:
        return False, 'DB or role missing on Server One — ' + out_s[:160]
    return False, ('DB auth failed on Server One — ' + out_s[:180]) if out_s else 'DB password rejected by PostgreSQL on Server One'


@app.route('/api/takserver/two-server/open-db-firewall', methods=['POST'])
@login_required
def takserver_two_server_open_db_firewall():
    """Prepare Server One: install PostgreSQL + TAK database .deb if needed, configure PG for remote access, open UFW."""
    data = request.get_json() or {}
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    if cfg.get('mode') != 'two_server':
        return jsonify({'success': False, 'error': 'Deployment mode is not two_server'}), 400
    s1 = cfg.get('server_one', {})
    if not (s1.get('host') or '').strip():
        return jsonify({'success': False, 'error': 'Server One host not set'}), 400
    db_port = int(cfg.get('database', {}).get('port') or 5432)
    core_ip = _resolve_core_ip(settings, cfg)
    if not core_ip:
        return jsonify({'success': False, 'error': 'Server Two (Core) IP unknown. Set Server IP in Settings.'}), 400

    # Check for uploaded database .deb to SCP + install if PG is missing
    uploaded = [f for f in os.listdir(UPLOAD_DIR) if f.endswith('.deb') or f.endswith('.rpm')]
    db_pkg = next((f for f in uploaded if 'database' in f.lower()), '')
    db_pkg_path = os.path.join(UPLOAD_DIR, db_pkg) if db_pkg else None
    if db_pkg_path and not os.path.isfile(db_pkg_path):
        db_pkg_path = None

    ok, log, db_password = _setup_server_one(s1, core_ip, db_port,
                                              db_pkg_path=db_pkg_path, db_pkg_name=db_pkg if db_pkg_path else None)
    if db_password:
        cfg['database']['password'] = db_password
        settings['tak_deployment'] = cfg
        save_settings(settings)

    if not ok:
        return jsonify({'success': False, 'error': log[-1] if log else 'Setup failed on Server One', 'log': log}), 400
    return jsonify({'success': True, 'message': f'Server One ready: PostgreSQL listening, UFW open for {core_ip} → port {db_port}. Next: 5. Deploy Server Two (Core), then fill out certs and hit Deploy TAK Server.', 'log': log})


@app.route('/api/takserver/two-server/runbook', methods=['GET'])
@login_required
def takserver_two_server_runbook():
    """Generate a practical two-server command runbook using manual naming/order."""
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if cfg.get('mode') != 'two_server':
        return jsonify({'success': False, 'error': 'Deployment mode is not set to two_server', 'config': cfg}), 400

    uploaded = [f for f in os.listdir(UPLOAD_DIR) if f.endswith('.deb') or f.endswith('.rpm')]
    db_pkg = next((f for f in uploaded if 'database' in f.lower()), '')
    core_pkg = next((f for f in uploaded if 'core' in f.lower()), '')

    s1 = cfg.get('server_one', {})
    s2 = cfg.get('server_two', {})
    db_host = (s1.get('host') or '<SERVER_ONE_DB_HOST>').strip() or '<SERVER_ONE_DB_HOST>'
    db_port = int(cfg.get('database', {}).get('port') or 5432)
    core_host_for_db_acl = (s2.get('host') or '').strip()
    if s2.get('use_localhost'):
        core_host_for_db_acl = (settings.get('server_ip') or '').strip() or '<INFRA_SERVER_IP>'
    if not core_host_for_db_acl:
        core_host_for_db_acl = '<SERVER_TWO_CORE_HOST>'

    server_one_steps = [
        '# Server One: Database Server',
        'sudo apt-get update && sudo apt-get install -y lsb-release',
        'sudo mkdir -p /etc/apt/keyrings',
        'sudo curl https://www.postgresql.org/media/keys/ACCC4CF8.asc --output /etc/apt/keyrings/postgresql.asc',
        'echo "deb [signed-by=/etc/apt/keyrings/postgresql.asc] https://apt.postgresql.org/pub/repos/apt $(lsb_release -cs)-pgdg main" | sudo tee /etc/apt/sources.list.d/postgresql.list >/dev/null',
        'sudo apt update',
        f'sudo apt install -y ./{db_pkg}' if db_pkg else 'sudo apt install -y ./takserver-database_x.x-RELEASExx_all.deb',
        # v0.9.12 hardening: source-scope only, deny everything else on db_port.
        # The pre-v0.9.12 unconditional `ufw allow {db_port}/tcp` defeated the
        # source-scope rule above and left Postgres reachable from the internet.
        # v0.9.46: delete any stale deny first (UFW first-match-wins; appended allow would
        # otherwise sit below it), add scoped allow, drop broad allow, re-add deny last.
        f'sudo ufw delete deny {db_port}/tcp || true',
        f'sudo ufw allow from {core_host_for_db_acl} to any port {db_port} proto tcp',
        f'sudo ufw delete allow {db_port}/tcp || true',
        f'sudo ufw deny {db_port}/tcp',
        'sudo ufw --force enable',
    ]
    server_two_steps = [
        '# Server Two: Core Server',
        'sudo apt-get update && sudo apt-get install -y lsb-release',
        f'sudo apt install -y ./{core_pkg}' if core_pkg else 'sudo apt install -y ./takserver-core_x.x-RELEASExx_all.deb',
        f'sudo sed -i \'s|jdbc:postgresql://127.0.0.1:5432/cot|jdbc:postgresql://{db_host}:{db_port}/cot|g\' /opt/tak/CoreConfig.xml',
        'sudo systemctl daemon-reload',
        'sudo systemctl enable takserver',
        'sudo systemctl restart takserver',
        'sudo ufw allow 8089/tcp && sudo ufw allow 8443/tcp && sudo ufw allow 8446/tcp && sudo ufw --force enable',
    ]
    notes = [
        'Manual naming/order preserved: Server One (Database Server) first, then Server Two (Core Server).',
        'Database password is generated by the TAK installer; confirm the value in /opt/tak/CoreConfig.example.xml on Server One and ensure Server Two CoreConfig.xml matches it.',
        'For production, enable PostgreSQL TLS per Appendix D and use sslEnabled/sslMode fields in CoreConfig.xml.',
    ]
    return jsonify({
        'success': True,
        'config': cfg,
        'detected_packages': {'database': db_pkg, 'core': core_pkg},
        'server_one_steps': server_one_steps,
        'server_two_steps': server_two_steps,
        'notes': notes,
    })


@app.route('/api/takserver/two-server/deploy-server-one', methods=['POST'])
@login_required
def takserver_two_server_deploy_server_one():
    """Full Server One deploy: SCP database .deb, install, configure PG for remote, open UFW, capture DB password.
    Optional body: deploy_target_host (+ deploy_target_user, deploy_target_port) — deploy to that host only while
    keeping saved server_one.host unchanged (for DB migration: prepare new VM before Start migration)."""
    data = request.get_json() or {}
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    if cfg.get('mode') != 'two_server':
        return jsonify({'success': False, 'error': 'Deployment mode is not two_server'}), 400
    s1_saved = dict(cfg.get('server_one', {}))
    s1 = dict(cfg.get('server_one', {}))
    deploy_alt = (data.get('deploy_target_host') or '').strip()
    preserve_saved_host = False
    if deploy_alt:
        if not _safe_migration_db_host(deploy_alt):
            return jsonify({'success': False, 'error': 'Invalid deploy_target_host'}), 400
        saved_host = (s1.get('host') or '').strip()
        if saved_host and deploy_alt.lower() == saved_host.lower():
            return jsonify({'success': False, 'error': 'deploy_target_host is the same as saved Server One — use normal step 4 without deploy_target_host.'}), 400
        s1['host'] = deploy_alt
        du = (data.get('deploy_target_user') or '').strip()
        if du:
            s1['ssh_user'] = du
        dp = data.get('deploy_target_port')
        if dp is not None and str(dp).strip():
            try:
                s1['ssh_port'] = int(dp)
            except (TypeError, ValueError):
                return jsonify({'success': False, 'error': 'deploy_target_port must be a number'}), 400
        preserve_saved_host = True
    if not (s1.get('host') or '').strip():
        return jsonify({'success': False, 'error': 'Server One host not set'}), 400
    db_port = int(cfg.get('database', {}).get('port') or 5432)
    core_ip = _resolve_core_ip(settings, cfg)
    if not core_ip:
        return jsonify({'success': False, 'error': 'Server Two (Core) IP unknown. Set Server IP in Settings or ensure this host can reach ifconfig.me.'}), 400

    # Require SSH to Server One first — otherwise deploy and password capture will both fail
    ssh_ok, ssh_out = _ssh_probe(s1, 'echo ok', timeout=10)
    if not ssh_ok:
        err = (ssh_out or 'Connection failed').strip()[:300]
        return jsonify({
            'success': False,
            'error': f'Cannot SSH to Server One ({s1.get("host")}). Run step 2 (Setup SSH key) and step 3 (Copy key to Server One) first. Without SSH, deployment cannot proceed.',
            'detail': err,
        }), 400

    uploaded = [f for f in os.listdir(UPLOAD_DIR) if f.endswith('.deb') or f.endswith('.rpm')]
    db_pkg = next((f for f in uploaded if 'database' in f.lower()), '')
    if not db_pkg:
        return jsonify({
            'success': False,
            'error': 'No takserver-database .deb in uploads — add the file on this TAK Server page (drag/drop or browse) so we can deploy it. If it was deleted, upload it again from tak.gov.',
        }), 400
    local_deb = os.path.join(UPLOAD_DIR, db_pkg)
    if not os.path.isfile(local_deb):
        return jsonify({
            'success': False,
            'error': f'Uploads list "{db_pkg}" but the file is gone from disk — upload the takserver-database .deb again.',
        }), 400

    if preserve_saved_host:
        ok_ver, ver_err = _assert_uploaded_db_deb_matches_server_one(s1_saved, local_deb, db_pkg)
        if not ok_ver:
            return jsonify({'success': False, 'error': ver_err}), 400

    ok, log, db_password = _setup_server_one(s1, core_ip, db_port,
                                              db_pkg_path=local_deb, db_pkg_name=db_pkg)
    if db_password:
        if preserve_saved_host:
            # Do not persist alternate host — migration still needs saved Server One = current DB source.
            settings = load_settings()
            cfg_save = _get_tak_deployment_config(settings)
            cfg_save.setdefault('database', {})['password'] = db_password
            settings['tak_deployment'] = cfg_save
            save_settings(settings)
            log.append('Note: Saved Server One host unchanged (alternate deploy). Use Start migration when ready.')
        else:
            cfg['database']['password'] = db_password
            settings['tak_deployment'] = cfg
            save_settings(settings)

    if not ok:
        return jsonify({'success': False, 'error': log[-1] if log else 'Deploy failed on Server One', 'log': log}), 400

    # Deploy Guard Dog health agent to Server One so Remote DB monitor can go green without a separate deploy
    ssh_key_path = (s1.get('ssh_key_path') or '').strip()
    if ssh_key_path and os.path.exists(os.path.expanduser(ssh_key_path)):
        ha_ok, ha_msg = _deploy_health_agent_to_server_one(s1)
        log.append('Health agent: ' + (ha_msg if ha_ok else f'Skip/fail: {ha_msg}'))
    else:
        log.append('Health agent: skipped (no SSH key to Server One)')

    return jsonify({
        'success': True,
        'message': 'Server One (Database) deploy complete. Next: 5. Deploy Server Two (Core), then fill out certs and hit Deploy TAK Server.',
        'log': log,
        'db_password_captured': bool(db_password),
    })


@app.route('/api/takserver/two-server/deploy-server-two', methods=['POST'])
@login_required
def takserver_two_server_deploy_server_two():
    """Automate Server Two (this host): install core .deb, point CoreConfig at Server One DB with correct password, restart."""
    data = request.get_json() or {}
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if isinstance(data.get('config'), dict):
        cfg = _normalize_tak_deployment_config(_deep_merge_dict(cfg, data.get('config')))
    if cfg.get('mode') != 'two_server':
        return jsonify({'success': False, 'error': 'Deployment mode is not two_server'}), 400
    s1 = cfg.get('server_one', {})
    db_host = (s1.get('host') or '').strip()
    if not db_host:
        return jsonify({'success': False, 'error': 'Server One host not set'}), 400
    db_port = int(cfg.get('database', {}).get('port') or 5432)
    db_password = (cfg.get('database', {}).get('password') or '').strip()
    uploaded = [f for f in os.listdir(UPLOAD_DIR) if f.endswith('.deb') or f.endswith('.rpm')]
    core_pkg = next((f for f in uploaded if 'core' in f.lower()), '')
    if not core_pkg:
        return jsonify({'success': False, 'error': 'No core package uploaded. Upload takserver-core .deb first.'}), 400
    local_deb = os.path.join(UPLOAD_DIR, core_pkg)
    if not os.path.isfile(local_deb):
        return jsonify({'success': False, 'error': f'Package not found: {core_pkg}'}), 400
    log = []

    # If no DB password stored, try to fetch it from Server One now (same SSH as step 4)
    if not db_password:
        db_password, fetch_err = _fetch_db_password_from_server_one(s1)
        if db_password:
            cfg['database']['password'] = db_password
            settings['tak_deployment'] = cfg
            save_settings(settings)
            log.append('Fetched DB password from Server One.')
        else:
            return jsonify({
                'success': False,
                'error': 'DB password not set. Run steps 2–3 (Setup SSH key, Copy key to Server One), then step 4 (Deploy Server One) so we can capture it automatically. Or paste the password from Server One in the "DB password (from Server One)" field above and click Save Config.',
                'detail': (fetch_err or '')[:200],
            }), 400

    # Validate DB password against Server One before patching CoreConfig.
    db_user = (cfg.get('database', {}).get('user') or 'martiuser').strip() or 'martiuser'
    db_name = (cfg.get('database', {}).get('name') or 'cot').strip() or 'cot'
    ok_pw, msg_pw = _verify_server_one_db_password(s1, db_password, db_port=db_port, db_user=db_user, db_name=db_name)
    if not ok_pw:
        return jsonify({
            'success': False,
            'error': (
                'DB credential validation failed on Server One. '
                'Use Sync DB Password with the current martiuser password from Server One, then retry.'
            ),
            'detail': msg_pw,
        }), 400

    # Increase concurrent TCP connections per TAK guide.
    # v10.0.5 non-root: `| sudo tee -a` is dead for takwerx — append via the broker.
    try:
        try:
            _lc = _read_priv('/etc/security/limits.conf')
        except Exception:
            _lc = ''
        if 'soft nofile 32768' not in _lc:
            _write_priv('/etc/security/limits.conf', '* soft nofile 32768\n* hard nofile 32768\n', mode='a')
    except Exception:
        pass

    # Install the core package — Debian: apt; RHEL/Rocky: dnf (+ the repo prereqs the
    # takserver-core rpm needs), mirroring the proven single-server RHEL deploy (Step 2/4).
    if _distro_family() == 'rhel':
        _pg_arch = 'aarch64' if _host_arch() == 'arm64' else 'x86_64'
        run_cmd('dnf install -y epel-release 2>&1', check=False, quiet=True)
        run_cmd(f'dnf install -y https://download.postgresql.org/pub/repos/yum/reporpms/EL-9-{_pg_arch}/pgdg-redhat-repo-latest.noarch.rpm 2>&1', check=False, quiet=True)
        run_cmd('dnf -qy module disable postgresql 2>&1', check=False, quiet=True)
        run_cmd('dnf install -y java-17-openjdk-devel 2>&1', check=False, quiet=True)
        run_cmd('dnf config-manager --set-enabled crb 2>&1', check=False, quiet=True)
        _core_ok = run_cmd(f'cd {UPLOAD_DIR} && dnf install -y ./{core_pkg} --setopt=clean_requirements_on_remove=false 2>&1', "Installing takserver-core (dnf)...")
        run_cmd(f'alternatives --set java java-17-openjdk.{_pg_arch} 2>/dev/null; true', check=False, quiet=True)
        # Idempotency: dnf exits non-zero on a re-install ("Transaction test error" when the
        # package is already present) or on a postinstall-scriptlet hiccup, even though the
        # package files installed fine. Don't hard-fail (which also SKIPS the JDBC patch below)
        # if takserver-core is actually installed — verify with `rpm -q` and treat present as
        # success. (Field-seen on a re-run split pre-stage: install succeeded, second attempt
        # tripped a transaction-test error, whole pre-stage falsely reported failure.)
        if not _core_ok:
            _chk = subprocess.run('rpm -q takserver-core', shell=True, capture_output=True,
                                  text=True, timeout=30, env=_broker_shim_env())
            if _chk.returncode == 0:
                _core_ok = True
                log.append('takserver-core dnf exit non-zero but rpm -q confirms it is installed — continuing (idempotent).')
        log.append('takserver-core installed via dnf (RHEL).' if _core_ok else 'takserver-core dnf install FAILED — see deploy log.')
        if not _core_ok:
            return jsonify({'success': False, 'error': 'Core package install (dnf) failed on Server Two — check the deploy log for the dnf error.', 'log': log}), 400
    else:
        try:
            r = _run_priv_chain([['apt-get', 'update', '-qq'], ['apt-get', 'install', '-y', f'./{core_pkg}']], 'and', timeout=600, cwd=UPLOAD_DIR)
            log.append(r.stdout or '')
            log.append(r.stderr or '')
            if r.returncode != 0:
                return jsonify({'success': False, 'error': (r.stderr or r.stdout or 'apt install failed')[:500], 'log': log}), 400
        except Exception as e:
            return jsonify({'success': False, 'error': str(e)[:400], 'log': log}), 400

    # Patch CoreConfig.xml: JDBC URL and DB password
    core_config = '/opt/tak/CoreConfig.xml'
    # RHEL: the takserver-core rpm ships CoreConfig.example.xml (not CoreConfig.xml). Seed it
    # so the JDBC patch below runs (mirrors the single-server RHEL deploy); else TAK keeps the
    # default localhost JDBC and never connects to Server One.
    if _distro_family() == 'rhel' and not os.path.exists(core_config) and os.path.exists('/opt/tak/CoreConfig.example.xml'):
        run_cmd('cp /opt/tak/CoreConfig.example.xml /opt/tak/CoreConfig.xml 2>&1; chown tak:tak /opt/tak/CoreConfig.xml 2>/dev/null; true', check=False, quiet=True)
    if os.path.exists(core_config):
        try:
            # v10.0.5 non-root: read/write CoreConfig via the broker (literal `sudo
            # cat`/`sudo tee` fail — takwerx isn't in sudoers — and /opt/tak is tak:tak).
            content = _read_priv(core_config)
            if not content:
                return jsonify({'success': False, 'error': 'Could not read CoreConfig.xml', 'log': log}), 400

            jdbc_new = f'jdbc:postgresql://{db_host}:{db_port}/cot'
            content = content.replace('jdbc:postgresql://127.0.0.1:5432/cot', jdbc_new)

            if db_password:
                content = re.sub(
                    r'(<connection[^>]*password=")[^"]*(")',
                    lambda m: m.group(1) + db_password + m.group(2),
                    content
                )

            _write_priv(core_config, content)

            subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=90)
            subprocess.run(_sudo_wrap(['systemctl', 'enable', 'takserver']), capture_output=True, timeout=90)
            subprocess.run(_sudo_wrap(['systemctl', 'restart', 'takserver']), capture_output=True, timeout=90)
            log.append(f'CoreConfig updated: DB→{db_host}:{db_port}, takserver restarted.')
        except Exception as e:
            return jsonify({'success': False, 'error': f'CoreConfig update failed: {e}', 'log': log}), 400
    return jsonify({'success': True, 'message': 'Server Two (Core) pre-staged. Next: fill out Certificate Information and hit Deploy TAK Server to generate certs, configure auth, and finish setup.', 'log': log})


@app.route('/api/takserver/two-server/sync-db-password', methods=['POST'])
@login_required
def takserver_two_server_sync_db_password():
    """Patch CoreConfig.xml on this host with DB password and restart TAK Server. No SSH to Server One.
    Password from: request body (paste in UI), else settings (saved from deploy). Fixes empty password / 8443 auth failure."""
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if cfg.get('mode') != 'two_server':
        return jsonify({'success': False, 'error': 'Not in two-server mode'}), 400
    if not os.path.exists('/opt/tak/CoreConfig.xml'):
        return jsonify({'success': False, 'error': 'TAK Server not installed (no CoreConfig.xml)'}), 400

    data = request.get_json() or {}
    db_pass = (data.get('password') or '').strip()
    if not db_pass:
        db_pass = (cfg.get('database', {}).get('password') or '').strip()
    if not db_pass:
        return jsonify({
            'success': False,
            'error': 'No DB password provided. Paste the martiuser password from Server One in the "DB password" field (from /opt/tak/CoreConfig.example.xml on Server One), or add it in Settings → TAK deployment → Server One / Database.'
        }), 400

    # Validate the provided password against Server One before writing CoreConfig.
    s1 = cfg.get('server_one', {})
    db_port = int(cfg.get('database', {}).get('port') or 5432)
    db_user = (cfg.get('database', {}).get('user') or 'martiuser').strip() or 'martiuser'
    db_name = (cfg.get('database', {}).get('name') or 'cot').strip() or 'cot'
    if (s1.get('host') or '').strip():
        ok_pw, msg_pw = _verify_server_one_db_password(s1, db_pass, db_port=db_port, db_user=db_user, db_name=db_name)
        if not ok_pw:
            return jsonify({
                'success': False,
                'error': (
                    'Password was not accepted by PostgreSQL on Server One. '
                    'Paste the current martiuser password and try again.'
                ),
                'detail': msg_pw,
            }), 400

    try:
        # v10.0.5 non-root: read/write CoreConfig via the broker (literal `sudo cat`/
        # `sudo tee` fail as takwerx; /opt/tak is tak:tak).
        content = _read_priv('/opt/tak/CoreConfig.xml')
        if not content:
            return jsonify({'success': False, 'error': 'Could not read CoreConfig.xml'}), 400
        content = re.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + db_pass + m.group(2), content)
        _write_priv('/opt/tak/CoreConfig.xml', content)
        cfg.setdefault('database', {})['password'] = db_pass
        settings['tak_deployment'] = cfg
        save_settings(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'restart', 'takserver']), capture_output=True, text=True, timeout=60)
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:300]}), 500

    return jsonify({'success': True, 'message': 'DB password updated and TAK Server restarted. Try 8443/8446 again in a minute.'})


@app.route('/api/takserver/two-server/migrate-database/start', methods=['POST'])
@login_required
def takserver_two_server_migrate_database_start():
    """Start background migration: dump cot on current Server One, restore on new host, point Core + settings."""
    if tak_migrate_status.get('running'):
        return jsonify({'error': 'Database migration already in progress'}), 409
    if not os.path.exists('/opt/tak/CoreConfig.xml'):
        return jsonify({'error': 'TAK Server not installed'}), 400
    data = request.get_json() or {}
    new_host = (data.get('new_host') or '').strip()
    if not new_host:
        return jsonify({'error': 'new_host is required (IP or hostname of the new Server One)'}), 400
    if not _safe_migration_db_host(new_host):
        return jsonify({'error': 'Invalid new_host (use IPv4 or hostname, letters/digits/dots/hyphens only)'}), 400
    settings = load_settings()
    cfg = _get_tak_deployment_config(settings)
    if cfg.get('mode') != 'two_server':
        return jsonify({'error': 'Not in two-server mode'}), 400
    old_s1 = dict(cfg.get('server_one', {}))
    old_host = (old_s1.get('host') or '').strip()
    if not old_host:
        return jsonify({'error': 'Current Server One host not configured'}), 400
    if new_host.lower() == old_host.lower():
        return jsonify({'error': 'new_host must differ from current Server One host'}), 400
    core_ip = _resolve_core_ip(settings, cfg)
    if not core_ip:
        return jsonify({'error': 'Server Two (Core) IP unknown — set Server IP in Settings'}), 400
    new_ssh_user = (data.get('new_ssh_user') or '').strip()
    new_ssh_port = data.get('new_ssh_port')
    new_s1 = dict(old_s1)
    new_s1['host'] = new_host
    if new_ssh_user:
        new_s1['ssh_user'] = new_ssh_user
    if new_ssh_port is not None and str(new_ssh_port).strip():
        try:
            new_s1['ssh_port'] = int(new_ssh_port)
        except (TypeError, ValueError):
            return jsonify({'error': 'new_ssh_port must be a number'}), 400
    key_path = _find_ssh_key_for_server_one(old_s1)
    if key_path:
        new_s1['ssh_key_path'] = key_path
    db_port = int(cfg.get('database', {}).get('port') or 5432)
    db_user = (cfg.get('database', {}).get('user') or 'martiuser').strip() or 'martiuser'
    db_name = (cfg.get('database', {}).get('name') or 'cot').strip() or 'cot'
    uploaded_m = [f for f in os.listdir(UPLOAD_DIR) if f.endswith('.deb') or f.endswith('.rpm')]
    db_pkg_m = next((f for f in uploaded_m if 'database' in f.lower()), '')
    if not db_pkg_m:
        return jsonify({
            'error': 'No takserver-database .deb in uploads — upload it again on this page (it may have been removed). It must match the version on your current Server One.',
        }), 400
    local_deb_m = os.path.join(UPLOAD_DIR, db_pkg_m)
    if not os.path.isfile(local_deb_m):
        return jsonify({
            'error': f'Uploads reference "{db_pkg_m}" but the file is missing — upload the takserver-database .deb again before starting migration.',
        }), 400
    # Version match uses SSH to current Server One — run in worker so this POST returns fast
    # (reverse proxies often timeout slow requests → browser "Failed to fetch").
    tak_snap = copy.deepcopy(cfg)
    tak_migrate_log.clear()
    tak_migrate_status.update({'running': True, 'complete': False, 'error': False})
    threading.Thread(
        target=run_takserver_two_server_db_migrate,
        args=(dict(old_s1), dict(new_s1), tak_snap, core_ip, db_port, db_user, db_name, local_deb_m, db_pkg_m),
        daemon=True,
    ).start()
    return jsonify({'success': True})


