# ── Leg 4 — CONNECT ANCHOR (box-side automation) ──────────────────────────────
# Turns the manual wg0.conf hand-assembly into a form: the console generates the
# box WireGuard keypair, writes the tunnel config, and dials the anchor. The
# anchor VPS itself is still stood up manually (RUNBOOK-oracle-anchor-provisioning,
# private notes) — this automates only the box half. Field-validated field defaults
# from the 2026-07-07 Starlink build: overlay 172.31.99.0/24, box .2, anchor .1,
# udp/443 (guest nets filter high UDP ports; 443 looks like HTTPS/QUIC).
_CONN_WG_IF = 'wg0'
_CONN_BOX_WG_IP = '172.31.99.2'
_CONN_ANCHOR_WG_IP = '172.31.99.1'
_CONN_WG_KEY_RE = re.compile(r'^[A-Za-z0-9+/]{43}=$')  # 32-byte base64 WireGuard key


def _conn_wg_conf_path():
    return '/etc/wireguard/%s.conf' % _CONN_WG_IF


def _conn_anchor_status():
    """Parse `wg show wg0` into a status dict. Never raises."""
    out = {'configured': False, 'up': False, 'handshake_secs': None,
           'endpoint': '', 'rx_bytes': None, 'tx_bytes': None}
    settings = load_settings()
    anchor = settings.get('connectivity_anchor') or {}
    if anchor.get('anchor_ip'):
        out['configured'] = True
        out['anchor_ip'] = anchor.get('anchor_ip')
        out['wg_port'] = anchor.get('wg_port')
        out['box_pubkey'] = anchor.get('box_pubkey', '')
    try:
        r = subprocess.run(_sudo_wrap(['wg', 'show', _CONN_WG_IF, 'dump']),
                           capture_output=True, text=True, timeout=8)
        if r.returncode != 0 or not r.stdout.strip():
            return out
        lines = r.stdout.strip().splitlines()
        # dump format: first line = interface; peer lines follow (tab-separated).
        # peer: pubkey preshared endpoint allowed-ips latest-handshake rx tx keepalive
        for ln in lines[1:]:
            f = ln.split('\t')
            if len(f) >= 8:
                out['up'] = True
                out['endpoint'] = f[2] if f[2] != '(none)' else ''
                hs = int(f[4]) if f[4].isdigit() else 0
                out['rx_bytes'] = int(f[5]) if f[5].isdigit() else 0
                out['tx_bytes'] = int(f[6]) if f[6].isdigit() else 0
                if hs > 0:
                    import time as _t
                    # dump gives an absolute epoch for latest handshake; convert to age.
                    out['handshake_secs'] = max(0, int(_t.time()) - hs)
    except Exception:
        pass
    return out


@app.route('/api/connectivity/anchor/status')
@login_required
def connectivity_anchor_status_api():
    return jsonify(_conn_anchor_status())


def _conn_validate_anchor_inputs(anchor_ip, anchor_pubkey, wg_port):
    """Shared strict validation. Returns (ok, wg_port_int_or_error_string)."""
    try:
        ipaddress.ip_address(anchor_ip)
    except (ValueError, TypeError):
        return False, 'Anchor IP is not a valid IP address.'
    if anchor_pubkey is not None and not _CONN_WG_KEY_RE.fullmatch(anchor_pubkey or ''):
        return False, 'Anchor WireGuard public key is malformed (expected a 44-char base64 key ending in "=").'
    try:
        wg_port = int(wg_port)
    except (ValueError, TypeError):
        return False, 'WireGuard port must be a number.'
    if not (1 <= wg_port <= 65535):
        return False, 'WireGuard port out of range.'
    return True, wg_port


def _conn_configure_box_tunnel(anchor_ip, anchor_pubkey, wg_port):
    """Generate the box keypair, write /etc/wireguard/wg0.conf, bring up the tunnel.
    Callers must have validated inputs already. Returns (ok, box_pubkey, error)."""
    if not shutil.which('wg'):
        try:
            _pkg_install(['wireguard-tools'])
        except Exception as ex:
            return False, '', 'Could not install wireguard-tools: %s' % str(ex)[:160]
        if not shutil.which('wg'):
            return False, '', 'wireguard-tools unavailable after install.'
    try:
        priv = subprocess.run(['wg', 'genkey'], capture_output=True, text=True, timeout=10).stdout.strip()
        pub = subprocess.run(['wg', 'pubkey'], input=priv + '\n', capture_output=True, text=True, timeout=10).stdout.strip()
    except Exception as ex:
        return False, '', 'Key generation failed: %s' % str(ex)[:160]
    if not (_CONN_WG_KEY_RE.fullmatch(priv) and _CONN_WG_KEY_RE.fullmatch(pub)):
        return False, '', 'Generated key looked malformed — aborting.'
    conf = (
        '[Interface]\n'
        'Address = %s/24\n'
        # MTU 1280 (IPv6 floor): wg-quick's auto MTU assumes a 1500 path; cellular
        # carriers translate IPv4 into IPv6 (464XLAT, +20B) and the encapsulated
        # packet silently exceeds the path — small packets (handshakes, pings,
        # 302s) pass, the first full-size TCP segment dies forever (field-hit
        # 2026-07-11 night: console 000 through the tunnel over AT&T while ping
        # worked; relay SACKed every byte EXCEPT the first 1368-byte segment).
        'MTU = 1280\n'
        'PrivateKey = %s\n\n'
        '[Peer]\n'
        'PublicKey = %s\n'
        'Endpoint = %s:%d\n'
        'AllowedIPs = %s/32\n'
        'PersistentKeepalive = 25\n'
    ) % (_CONN_BOX_WG_IP, priv, anchor_pubkey, anchor_ip, wg_port, _CONN_ANCHOR_WG_IP)
    tmp_path = None
    try:
        fd, tmp_path = tempfile.mkstemp(prefix='wg-', suffix='.conf')
        os.write(fd, conf.encode())
        os.close(fd)
        os.chmod(tmp_path, 0o600)
        inst = _run_priv_chain([
            ['install', '-D', '-m', '600', '-o', 'root', '-g', 'root', tmp_path, _conn_wg_conf_path()],
        ], mode='and')
        if not inst or inst.returncode != 0:
            return False, '', 'Could not write tunnel config: %s' % ((inst.stderr if inst else '') or 'install failed')[:160]
    finally:
        if tmp_path and os.path.exists(tmp_path):
            try:
                os.remove(tmp_path)
            except Exception:
                pass
    up = _run_priv_chain([
        ['systemctl', 'enable', 'wg-quick@%s' % _CONN_WG_IF],
        ['systemctl', 'restart', 'wg-quick@%s' % _CONN_WG_IF],
    ], mode='seq')
    if not up or up.returncode != 0:
        return False, '', 'Tunnel config written but bring-up failed: %s' % ((up.stderr if up else '') or 'systemctl failed')[:160]
    return True, pub, ''


@app.route('/api/connectivity/anchor/configure', methods=['POST'])
@login_required
def connectivity_anchor_configure_api():
    data = request.get_json(silent=True) or {}
    anchor_ip = (data.get('anchor_ip') or '').strip()
    anchor_pubkey = (data.get('anchor_pubkey') or '').strip()
    ok, wg_port = _conn_validate_anchor_inputs(anchor_ip, anchor_pubkey, data.get('wg_port', 51820))
    if not ok:
        return jsonify({'success': False, 'error': wg_port}), 400
    cfg_ok, pub, err = _conn_configure_box_tunnel(anchor_ip, anchor_pubkey, wg_port)
    if not cfg_ok:
        return jsonify({'success': False, 'error': err}), 500

    settings = load_settings()
    settings['connectivity_anchor'] = {
        'anchor_ip': anchor_ip, 'anchor_pubkey': anchor_pubkey,
        'wg_port': wg_port, 'box_pubkey': pub,
    }
    save_settings(settings)
    return jsonify({
        'success': True,
        'box_pubkey': pub,
        'add_box_cmd': 'sudo ./connectivity-anchor-bootstrap.sh add-box %s' % pub,
    })


@app.route('/api/connectivity/anchor/disconnect', methods=['POST'])
@login_required
def connectivity_anchor_disconnect_api():
    _run_priv_chain([
        ['systemctl', 'disable', 'wg-quick@%s' % _CONN_WG_IF],
        ['systemctl', 'stop', 'wg-quick@%s' % _CONN_WG_IF],
        ['rm', '-f', _conn_wg_conf_path()],
    ], mode='seq')
    settings = load_settings()
    settings.pop('connectivity_anchor', None)
    save_settings(settings)
    return jsonify({'success': True})


# ── Leg 4 (full) — PROVISION ANCHOR OVER SSH (upload the .key, console does it all) ──
# Mirrors the TAK split-deploy pattern (takserver_two_server_upload_ssh_key): the
# operator makes the Oracle VM + downloads its SSH key, then just enters the anchor
# IP and uploads that key. The console SSHes in, runs the bootstrap, reads the WG
# public key out of the output, configures the box tunnel, and authorizes the box on
# the anchor with add-box — no terminal, no hand-copied keys.
_CONN_ANCHOR_BOOTSTRAP_RAW = ('https://raw.githubusercontent.com/takwerx/infra-TAK/'
                              'dev/scripts/connectivity-anchor-bootstrap.sh')
_CONN_ANCHOR_KEY_PATH = os.path.expanduser('~/.ssh/infratak_anchor')
_CONN_SSH_USER_RE = re.compile(r'^[a-z_][a-z0-9_-]{0,31}$')
_connectivity_provision_status = {'running': False, 'complete': False, 'error': '', 'log': []}


def _conn_prov_log(msg):
    _connectivity_provision_status['log'].append(msg)


def _conn_write_anchor_key(key_text):
    """Write + validate the uploaded anchor SSH private key to a FIXED 0600 path
    (never request-controlled → no traversal). Rejects passphrase-protected keys
    (can't be used non-interactively). Returns (ok, error). Mirrors split-deploy."""
    key_text = (key_text or '').replace('\r\n', '\n').replace('\r', '\n')
    if not key_text.strip():
        return False, 'No SSH key provided.'
    if not key_text.endswith('\n'):
        key_text += '\n'
    if '-----BEGIN' not in key_text or 'PRIVATE KEY' not in key_text:
        return False, 'That does not look like an SSH private key (expected a "-----BEGIN … PRIVATE KEY-----" block, e.g. the Oracle .key file).'
    try:
        os.makedirs(os.path.dirname(_CONN_ANCHOR_KEY_PATH), mode=0o700, exist_ok=True)
        fd = os.open(_CONN_ANCHOR_KEY_PATH, os.O_WRONLY | os.O_CREAT | os.O_TRUNC, 0o600)
        with os.fdopen(fd, 'w') as f:
            f.write(key_text)
        os.chmod(_CONN_ANCHOR_KEY_PATH, 0o600)
    except Exception as e:
        return False, 'Could not store key: %s' % str(e)[:160]
    try:
        r = subprocess.run(['ssh-keygen', '-y', '-f', _CONN_ANCHOR_KEY_PATH],
                           capture_output=True, text=True, timeout=10)
    except Exception as e:
        try:
            os.remove(_CONN_ANCHOR_KEY_PATH)
        except Exception:
            pass
        return False, 'Key validation failed: %s' % str(e)[:160]
    if r.returncode != 0:
        try:
            os.remove(_CONN_ANCHOR_KEY_PATH)
        except Exception:
            pass
        _e = (r.stderr or r.stdout or '').lower()
        if 'passphrase' in _e:
            return False, 'The key is passphrase-protected — re-export it without a passphrase and upload that.'
        return False, 'Invalid or unsupported private key format.'
    return True, ''


def _conn_anchor_ssh(anchor_ip, ssh_user, remote_cmd, timeout=180):
    """Run one command on the anchor over SSH with the uploaded key. Returns (ok, output)."""
    host_cfg = {'host': anchor_ip, 'ssh_user': ssh_user, 'ssh_port': 22,
                'auth_method': 'ssh_key', 'ssh_key_path': _CONN_ANCHOR_KEY_PATH}
    return _ssh_probe(host_cfg, remote_cmd, timeout=timeout)


def _run_connectivity_provision(anchor_ip, ssh_user, wg_port):
    st = _connectivity_provision_status
    try:
        _conn_prov_log('Connecting to relay %s as %s…' % (anchor_ip, ssh_user))
        ok, out = _conn_anchor_ssh(anchor_ip, ssh_user, 'echo relay-reachable', timeout=25)
        if not ok:
            st.update({'running': False, 'complete': True, 'error': 'Cannot SSH to the relay: %s' % out[:200]})
            return
        # Fetch + run the bootstrap on the anchor. WG_PORT is an int (validated); the
        # URL is a fixed constant. Nothing operator-typed lands in this remote shell string.
        _conn_prov_log('Running the relay setup (this installs WireGuard + forwards)…')
        setup_cmd = ("curl -fsSL '%s' -o ~/connectivity-anchor-bootstrap.sh && "
                     "chmod +x ~/connectivity-anchor-bootstrap.sh && "
                     "sudo WG_PORT=%d bash ~/connectivity-anchor-bootstrap.sh setup"
                     ) % (_CONN_ANCHOR_BOOTSTRAP_RAW, wg_port)
        ok, out = _conn_anchor_ssh(anchor_ip, ssh_user, setup_cmd, timeout=240)
        if not ok:
            st.update({'running': False, 'complete': True, 'error': 'Anchor bootstrap failed: %s' % out[:300]})
            return
        m = re.search(r'WireGuard public key\s*:\s*([A-Za-z0-9+/]{43}=)', out)
        if not m:
            st.update({'running': False, 'complete': True, 'error': 'Could not read the relay WireGuard key from the setup output.'})
            return
        anchor_pubkey = m.group(1)
        _conn_prov_log('Relay is up. Configuring this box\'s tunnel…')
        cfg_ok, box_pub, err = _conn_configure_box_tunnel(anchor_ip, anchor_pubkey, wg_port)
        if not cfg_ok:
            st.update({'running': False, 'complete': True, 'error': err})
            return
        _conn_prov_log('Authorizing this box on the relay…')
        # box_pub is a validated base64 WG key (fullmatch in _conn_configure_box_tunnel).
        addbox_cmd = 'sudo bash ~/connectivity-anchor-bootstrap.sh add-box %s' % box_pub
        ok, out = _conn_anchor_ssh(anchor_ip, ssh_user, addbox_cmd, timeout=60)
        if not ok:
            st.update({'running': False, 'complete': True, 'error': 'Box configured but authorizing it on the relay failed: %s' % out[:200]})
            return
        settings = load_settings()
        settings['connectivity_anchor'] = {
            'anchor_ip': anchor_ip, 'anchor_pubkey': anchor_pubkey,
            'wg_port': wg_port, 'box_pubkey': box_pub, 'provisioned': True,
        }
        save_settings(settings)
        _conn_prov_log('Done. The tunnel is dialing — status will show connected shortly.')
        st.update({'running': False, 'complete': True, 'error': ''})
    except Exception as ex:
        st.update({'running': False, 'complete': True, 'error': str(ex)[:300]})


@app.route('/api/connectivity/anchor/provision', methods=['POST'])
@login_required
def connectivity_anchor_provision_api():
    if _connectivity_provision_status.get('running'):
        return jsonify({'success': False, 'error': 'A provisioning run is already in progress.'}), 409
    data = request.get_json(silent=True) or {}
    anchor_ip = (data.get('anchor_ip') or '').strip()
    ssh_user = (data.get('ssh_user') or 'ubuntu').strip()
    ssh_key = data.get('ssh_private_key') or ''
    ok, wg_port = _conn_validate_anchor_inputs(anchor_ip, None, data.get('wg_port', 51820))
    if not ok:
        return jsonify({'success': False, 'error': wg_port}), 400
    if not _CONN_SSH_USER_RE.fullmatch(ssh_user):
        return jsonify({'success': False, 'error': 'SSH username has invalid characters.'}), 400
    key_ok, key_err = _conn_write_anchor_key(ssh_key)
    if not key_ok:
        return jsonify({'success': False, 'error': key_err}), 400
    _connectivity_provision_status.update({'running': True, 'complete': False, 'error': '', 'log': []})
    threading.Thread(target=_run_connectivity_provision, args=(anchor_ip, ssh_user, wg_port), daemon=True).start()
    return jsonify({'success': True})


@app.route('/api/connectivity/anchor/provision-status')
@login_required
def connectivity_anchor_provision_status_api():
    st = _connectivity_provision_status
    return jsonify({'running': st.get('running', False), 'complete': st.get('complete', False),
                    'error': st.get('error', ''), 'log': st.get('log', [])})


# ── Leg 5 — VERIFY (green/red reachability matrix) ─────────────────────────────
# Proves clients can actually reach the stack from the public internet — the loop
# that kills router/NSG trial-and-error. v1 vantage decision (deliberate deviation
# from the PLAN's relay-side :5099 prober): the relay CANNOT probe its own public
# IP — locally-originated packets skip the PREROUTING DNAT and never traverse the
# cloud NSG, so a relay-side self-probe false-REDs a perfectly working setup. A
# direct outbound TCP connect from THIS BOX to the relay's public endpoint walks
# the true client path end-to-end (internet → cloud NSG → relay DNAT → WireGuard →
# box service) — the same round trip the LDAP-outpost FQDN probe validated in the
# field 2026-07-08. The :5099 seed prober stays on the relay for a future
# third-vantage / Class-A probe-back build.
_CONN_VERIFY_PORTS = [
    (443,  'Web UIs (Portal / CloudTAK / Authentik via Caddy)', True),
    (8089, 'TAK streaming (CoT / ATAK-iTAK connections)',        True),
    (8443, 'Marti API / WebTAK',                                  True),
    (8446, 'Certificate + QR enrollment',                         True),
    (80,   "Let's Encrypt renewal (HTTP-01)",                     False),
]

_connectivity_verify_status = {'running': False, 'complete': False, 'error': '', 'result': None}


def _conn_verify_tcp(host, port, timeout=5):
    """One TCP connect probe. Returns {'state','ms','detail'} and never raises."""
    import socket as _s
    t0 = time.time()
    try:
        with _s.create_connection((host, port), timeout=timeout):
            return {'state': 'green', 'ms': int((time.time() - t0) * 1000), 'detail': ''}
    except OSError as ex:
        return {'state': 'red', 'ms': int((time.time() - t0) * 1000),
                'detail': (getattr(ex, 'strerror', '') or str(ex))[:80]}


def _run_connectivity_verify(settings):
    st = _connectivity_verify_status
    try:
        anchor = settings.get('connectivity_anchor') or {}
        result = {'ports': {}, 'target': '', 'mode': '', 'vantage': '', 'ts': int(time.time())}
        if anchor.get('anchor_ip'):
            result['target'] = anchor['anchor_ip']
            result['mode'] = 'relay'
            result['vantage'] = ("this box → the relay's public address — the exact path clients take "
                                 "(internet → cloud firewall/NSG → relay forward → tunnel → this box)")
        else:
            fqdn = (settings.get('fqdn') or '').split(':')[0].strip()
            result['target'] = fqdn or (settings.get('server_ip') or '').strip()
            result['mode'] = 'direct'
            result['vantage'] = ("this box → its own public address. On a home network without NAT "
                                 "hairpin this can show red even when outside clients connect fine — "
                                 "confirm with a phone on cellular if reds look wrong.")
        if not result['target']:
            st.update({'running': False, 'complete': True, 'result': None,
                       'error': 'Nothing to verify yet — connect a relay (or set an FQDN / public IP) first.'})
            return
        required_green = 0
        for port, label, required in _CONN_VERIFY_PORTS:
            probe = _conn_verify_tcp(result['target'], port)
            probe['label'] = label
            probe['required'] = required
            if probe['state'] == 'red':
                # The killer diagnostic: is the service even listening locally? Separates
                # "deploy the module first" from "the path (router/NSG/forward) is blocked".
                local = _conn_verify_tcp('127.0.0.1', port, timeout=2)
                probe['local_listener'] = (local['state'] == 'green')
                if not probe['local_listener']:
                    probe['hint'] = 'nothing listening on this box yet — deploy the module that owns this port'
                elif result['mode'] == 'relay':
                    # Relay vantage is a REAL outside path (box -> relay public -> tunnel
                    # -> back); a red here is trustworthy.
                    probe['hint'] = ('service reachable locally but NOT from outside — check the path: '
                                     'relay cloud firewall/NSG ingress + forwarded ports')
                else:
                    # Direct mode probes the box's OWN public address — a self-probe that
                    # fails on any network without NAT hairpin (home routers, 1:1-NAT
                    # VPSes; field-hit 2026-07-12: test12 all-red while the operator was
                    # browsing the console THROUGH port 443). A failed self-probe proves
                    # nothing about outside reachability — never present it as red.
                    probe['state'] = 'unverified'
                    probe['hint'] = ('listening on this box, but the box cannot reach its own public '
                                     'address on this network (no NAT hairpin) — outside clients may '
                                     'connect fine; confirm from a phone on cellular')
            if probe['state'] == 'green' and required:
                required_green += 1
            result['ports'][str(port)] = probe
        result['all_green'] = required_green == sum(1 for _, _, req in _CONN_VERIFY_PORTS if req)
        result['required_red'] = sum(1 for p in result['ports'].values() if p.get('required') and p.get('state') == 'red')
        result['unverified'] = sum(1 for p in result['ports'].values() if p.get('state') == 'unverified')
        st.update({'running': False, 'complete': True, 'error': '', 'result': result})
    except Exception as ex:
        st.update({'running': False, 'complete': True, 'error': str(ex)[:300]})


@app.route('/api/connectivity/verify', methods=['POST'])
@login_required
def connectivity_verify_api():
    if _connectivity_verify_status.get('running'):
        return jsonify({'error': 'A verify run is already in progress'}), 409
    _connectivity_verify_status.update(
        {'running': True, 'complete': False, 'error': '', 'result': None})
    settings = load_settings()
    threading.Thread(target=_run_connectivity_verify, args=(settings,), daemon=True).start()
    return jsonify({'success': True})


@app.route('/api/connectivity/verify-status')
@login_required
def connectivity_verify_status_api():
    st = _connectivity_verify_status
    return jsonify({'running': st.get('running', False), 'complete': st.get('complete', False),
                    'error': st.get('error', ''), 'result': st.get('result')})


# ── Leg 6 — WIFI JOIN (tell the box its next network, from the browser) ────────
# Kills the netplan hand-edit for a portable box: scan/list networks + add one from
# the UI. SAFETY MODEL (headless box reached remotely — a bad apply strands it):
#  - ADDITIVE ONLY: never removes an existing access-point, so the current
#    connection can't be dropped by adding a new one.
#  - VALIDATE BEFORE APPLY: back up the netplan file, write the new one, run
#    `netplan generate`; if it fails, RESTORE the backup and abort — never apply
#    an unvalidated config.
#  - Multiplatform: nmcli (NetworkManager / RHEL) when present, else netplan
#    (Ubuntu). Both via the privileged broker (_sudo_wrap / _run_priv_chain).


def _ensure_iw():
    """Ensure the `iw` CLI exists (wireless scan/detect on netplan boxes without
    NetworkManager). Field gap 2026-07-08: stock Ubuntu 22.04 SERVER does not ship
    `iw` (desktop does) — so on exactly the boxes that need the netplan path, the
    WiFi card's scan silently returned nothing. Mirrors _ensure_ldapsearch: tiny
    package, installed on demand through the apt↔dnf shim (package is named `iw`
    on both families). Checks sbin paths explicitly — the console user's PATH may
    exclude /usr/sbin even when the binary is installed."""
    for p in ('/usr/sbin/iw', '/sbin/iw', '/usr/bin/iw'):
        if os.path.exists(p):
            return True
    if shutil.which('iw'):
        return True
    try:
        _pkg_install('iw', timeout=120)
    except Exception:
        pass
    return any(os.path.exists(p) for p in ('/usr/sbin/iw', '/sbin/iw', '/usr/bin/iw')) or bool(shutil.which('iw'))


def _ensure_nm_wifi():
    """Ensure NetworkManager's WiFi plugin is present on RHEL-family boxes.

    RHEL/Rocky/Alma — minimal AND server installs — DO NOT ship
    `NetworkManager-wifi` (it is a separate package), so a fresh box shows the
    WiFi device as 'unmanaged' and every nmcli WiFi op (scan/add/connect) fails
    silently. Field-hit 2026-07-09 (Rocky NUC, first RHEL Leg-6 test); confirmed
    documented Rocky behaviour. Ubuntu ships WiFi support by default, so this is
    a RHEL-only gap — no-op on debian. Mirrors _ensure_iw: tiny package,
    installed on demand through the apt↔dnf shim (the existing nmcli code path
    then handles scan/add/persist). Restarts NetworkManager once after install
    so the radio flips 'managed'. Cheap once installed (glob short-circuits).
    Returns True when the plugin is present."""
    if _distro_family() != 'rhel':
        return True  # Ubuntu/debian ship WiFi support with NetworkManager.
    if not shutil.which('nmcli'):
        return False  # no NetworkManager — WiFi is not driven via nmcli here.
    import glob as _glob

    def _have_plugin():
        for pat in ('/usr/lib64/NetworkManager/*/libnm-device-plugin-wifi.so',
                    '/usr/lib64/NetworkManager/libnm-device-plugin-wifi.so',
                    '/usr/lib/NetworkManager/*/libnm-device-plugin-wifi.so',
                    '/usr/lib/NetworkManager/libnm-device-plugin-wifi.so'):
            if _glob.glob(pat):
                return True
        return False
    if _have_plugin():
        return True
    try:
        _pkg_install('NetworkManager-wifi', timeout=300)
        # Reload NM so it loads the new plugin and flips the WiFi device managed.
        _run_priv_chain([['systemctl', 'restart', 'NetworkManager']], mode='and', timeout=60)
    except Exception:
        pass
    return _have_plugin()


def _conn_wifi_iface():
    """Detect the wireless interface name (e.g. wlp1s0). Empty if none."""
    try:
        _ensure_iw()
        r = subprocess.run(_sudo_wrap(['iw', 'dev']), capture_output=True, text=True, timeout=8)
        m = re.search(r'Interface\s+(\S+)', r.stdout or '')
        if m:
            return m.group(1)
    except Exception:
        pass
    try:
        for n in sorted(os.listdir('/sys/class/net')):
            if os.path.exists('/sys/class/net/%s/wireless' % n):
                return n
    except Exception:
        pass
    return ''


def _conn_wifi_netplan_file():
    """The netplan file that defines the wifis: block (where APs live).

    Reads via the BROKER — netplan yamls are root-600 by design (they hold WiFi
    PSKs; cloud-init tightened this after CVE-2022-… era), so a direct open() as
    the non-root console EPERMs on every file and this reported 'No netplan wifi
    config found' on a box that was ON WiFi at that very moment (field-hit
    2026-07-08, NUC — first live Leg 6 test). Returns '' if no file has a
    wifis: block (caller creates our own layered file)."""
    try:
        import glob as _glob
        for f in sorted(_glob.glob('/etc/netplan/*.yaml')):
            try:
                r = subprocess.run(_sudo_wrap(['cat', f]), capture_output=True, text=True, timeout=8)
                if r.returncode == 0 and 'wifis' in (r.stdout or ''):
                    return f
            except Exception:
                continue
    except Exception:
        pass
    return ''


def _conn_wifi_saved():
    """SSIDs the box already knows (from nmcli or the netplan file)."""
    out = []
    if shutil.which('nmcli'):
        try:
            r = subprocess.run(_sudo_wrap(['nmcli', '-t', '-f', 'NAME,TYPE', 'connection', 'show']),
                               capture_output=True, text=True, timeout=10)
            for line in (r.stdout or '').splitlines():
                p = line.split(':')
                if len(p) >= 2 and 'wireless' in p[1]:
                    out.append(p[0])
        except Exception:
            pass
        return out
    # netplan branch: read every yaml via the broker (root-600 files — a direct
    # open() EPERMs as the non-root console and the saved list showed empty even
    # while the box was connected; same field bug as _conn_wifi_netplan_file).
    try:
        import glob as _glob
        import yaml as _yaml
        for f in sorted(_glob.glob('/etc/netplan/*.yaml')):
            try:
                r = subprocess.run(_sudo_wrap(['cat', f]), capture_output=True, text=True, timeout=8)
                doc = _yaml.safe_load(r.stdout or '') or {}
                for _iface, cfg in ((doc.get('network') or {}).get('wifis') or {}).items():
                    for _ssid in (cfg.get('access-points') or {}).keys():
                        if _ssid not in out:
                            out.append(_ssid)
            except Exception:
                continue
    except Exception:
        pass
    return out


def _conn_wifi_scan():
    """Best-effort list of visible SSIDs (+ signal where available)."""
    _ensure_nm_wifi()  # RHEL: pull NetworkManager-wifi so the radio is manageable
    nets, seen = [], set()

    def _add(ssid, signal=''):
        ssid = (ssid or '').strip()
        if ssid and ssid not in seen:
            seen.add(ssid)
            nets.append({'ssid': ssid, 'signal': signal})
    if shutil.which('nmcli'):
        try:
            subprocess.run(_sudo_wrap(['nmcli', 'dev', 'wifi', 'rescan']), capture_output=True, timeout=15)
            r = subprocess.run(_sudo_wrap(['nmcli', '-t', '-f', 'SSID,SIGNAL', 'dev', 'wifi', 'list']),
                               capture_output=True, text=True, timeout=20)
            for line in (r.stdout or '').splitlines():
                p = line.rsplit(':', 1)
                _add(p[0], p[1] if len(p) > 1 else '')
        except Exception:
            pass
        return nets
    iface = _conn_wifi_iface()
    if iface:
        try:
            _ensure_iw()
            r = subprocess.run(_sudo_wrap(['iw', 'dev', iface, 'scan']),
                               capture_output=True, text=True, timeout=25)
            for line in (r.stdout or '').splitlines():
                s = line.strip()
                if s.startswith('SSID:'):
                    _add(s[5:])
        except Exception:
            pass
    return nets


def _conn_wifi_visible():
    """SSIDs currently in range, from the radio's CACHED scan results — cheap and
    instant (no active scan), so it's safe to include on the list poll. nmcli uses
    its cached `dev wifi list`; netplan uses `iw dev <iface> scan dump` (kernel
    cache from the client's periodic background scans). The active 'Scan for
    networks' button refreshes the cache. Best-effort; empty if unavailable."""
    seen = set()
    if shutil.which('nmcli'):
        try:
            r = subprocess.run(_sudo_wrap(['nmcli', '-t', '-f', 'SSID', 'dev', 'wifi', 'list']),
                               capture_output=True, text=True, timeout=8)
            for ln in (r.stdout or '').splitlines():
                s = ln.strip()
                if s:
                    seen.add(s)
        except Exception:
            pass
        return list(seen)
    iface = _conn_wifi_iface()
    if iface:
        try:
            _ensure_iw()
            r = subprocess.run(_sudo_wrap(['iw', 'dev', iface, 'scan', 'dump']),
                               capture_output=True, text=True, timeout=8)
            for ln in (r.stdout or '').splitlines():
                s = ln.strip()
                if s.startswith('SSID:'):
                    v = s[5:].strip()
                    if v:
                        seen.add(v)
        except Exception:
            pass
    return list(seen)


def _conn_setup_ap_active():
    """True if the Setup AP is currently broadcasting (flag written by the engine)."""
    return os.path.exists('/var/lib/takguard/setup-ap.active')


def _conn_wifi_add(ssid, psk):
    """Add a wifi network ADDITIVELY and bring config up. Returns (ok, error).
    netplan path validates-before-apply with backup/restore; never strands."""
    if not (1 <= len(ssid.encode('utf-8')) <= 32):
        return False, 'Network name must be 1–32 characters.'
    if psk and not (8 <= len(psk) <= 63):
        return False, 'WiFi password must be 8–63 characters (WPA requirement).'
    _ensure_nm_wifi()  # RHEL: pull NetworkManager-wifi so nmcli can manage the radio
    # NetworkManager path (RHEL / any box with nmcli).
    # v10.1.0 parity fix: use `connection add` (create the PROFILE, activate
    # nothing), NOT `dev wifi connect` — connect ACTIVATES, i.e. it switches
    # the box onto the new network immediately (breaking the "adding never
    # disconnects the one you're on" promise) and it FAILS outright for an SSID
    # that isn't in range (breaking pre-provision, the flagship Leg 6 feature).
    # `connection add` + autoconnect matches netplan's additive semantics:
    # NM joins the network when it sees it, current connection untouched.
    if shutil.which('nmcli'):
        iface = _conn_wifi_iface() or '*'
        if ssid in _conn_wifi_saved():
            if not psk:
                return True, ''
            # Same SSID re-added with a (possibly new) password → update in place.
            cmd = ['nmcli', 'connection', 'modify', ssid, 'wifi-sec.psk', psk]
        else:
            # ipv4.may-fail no: without it NM declares the connection 'activated'
            # on IPv6 alone when DHCPv4 gets no answer (field-hit 2026-07-11,
            # iPhone hotspot: 'dhcp4: no lease' but nmcli up rc=0) — a state with
            # no usable IPv4, no tunnel, and a join loop that thinks it won.
            cmd = ['nmcli', 'connection', 'add', 'type', 'wifi',
                   'con-name', ssid, 'ifname', iface, 'ssid', ssid,
                   'connection.autoconnect', 'yes', 'ipv4.may-fail', 'no']
            if psk:
                cmd += ['wifi-sec.key-mgmt', 'wpa-psk', 'wifi-sec.psk', psk]
        r = subprocess.run(_sudo_wrap(cmd), capture_output=True, text=True, timeout=45)
        if r.returncode != 0:
            return False, (r.stderr or r.stdout or 'nmcli profile add failed').strip()[:200]
        # ADDITIVE-ONLY, even from the Setup AP (2026-07-11 redesign). Honor the card's
        # promise "Adding a network never disconnects the one you're on": just save the
        # profile (autoconnect=yes) and leave the AP broadcasting, so the operator can
        # pre-provision several networks before committing. The SWITCH to a saved network
        # happens ONLY when they explicitly hit "Stop Setup WiFi" (setup-ap/stop ->
        # _conn_join_best_saved), which is where the deterministic join-out-of-AP-mode
        # now lives (NM autoconnect coming out of AP mode is unreliable on RHEL).
        return True, ''
    # netplan path (Ubuntu).
    f = _conn_wifi_netplan_file()
    created_new = False
    if not f:
        # No wifis: block anywhere (ethernet-only cloud-init, or WiFi configured
        # outside netplan). Create our OWN lexically-layered file instead of
        # failing — netplan merges mappings across files, and never touching
        # cloud-init's file means cloud-init can't clobber our APs later.
        f = '/etc/netplan/90-infratak-wifi.yaml'
        created_new = True
    iface = _conn_wifi_iface()
    if not iface:
        return False, 'No wireless interface detected.'
    try:
        import yaml as _yaml
        # Read current config via privileged cat (file may be root-only).
        cur = subprocess.run(_sudo_wrap(['cat', f]), capture_output=True, text=True, timeout=10)
        doc = _yaml.safe_load(cur.stdout or '') or {}
        net = doc.setdefault('network', {})
        net.setdefault('version', 2)
        wifis = net.setdefault('wifis', {})
        ap = wifis.setdefault(iface, {})
        ap.setdefault('dhcp4', True)
        points = ap.setdefault('access-points', {})
        # ADDITIVE: add/replace only THIS ssid, keep every other AP untouched.
        if psk:
            points[ssid] = {'auth': {'key-management': 'psk', 'password': psk}}
        else:
            points[ssid] = {}
        new_yaml = _yaml.safe_dump(doc, default_flow_style=False, sort_keys=False)
    except Exception as ex:
        return False, 'Could not read/parse netplan config: %s' % str(ex)[:160]
    # Write via temp → privileged install, keeping a backup for restore-on-failure.
    tmp_path = bak = None
    try:
        fd, tmp_path = tempfile.mkstemp(prefix='netplan-', suffix='.yaml')
        os.write(fd, new_yaml.encode())
        os.close(fd)
        os.chmod(tmp_path, 0o600)
        bak = f + '.infratak-wifi.bak'
        if not created_new:
            _run_priv_chain([['cp', '-a', f, bak]], mode='and')
        inst = _run_priv_chain([['install', '-m', '600', '-o', 'root', '-g', 'root', tmp_path, f]], mode='and')
        if not inst or inst.returncode != 0:
            return False, 'Could not write netplan config.'
        # VALIDATE — if generate fails, roll back and abort (never apply). For a
        # freshly created file there is no backup to restore — remove it instead
        # (leaves the box exactly as it was).
        gen = _run_priv_chain([['netplan', 'generate']], mode='and')
        if not gen or gen.returncode != 0:
            if created_new:
                _run_priv_chain([['rm', '-f', f], ['netplan', 'generate']], mode='seq')
            else:
                _run_priv_chain([['cp', '-a', bak, f], ['netplan', 'generate']], mode='seq')
            return False, 'New network config failed validation — reverted, nothing changed. (%s)' \
                % ((gen.stderr if gen else '') or '')[:140]
        # If the Setup AP is broadcasting (the operator is provisioning FROM it),
        # the radio is busy being the AP — a raw `netplan apply` would fight
        # hostapd. Instead stop the AP: its teardown restores the client and runs
        # netplan apply, so the box joins the just-added network (in range at the
        # new location) and drops the AP in one step. Otherwise apply directly
        # (additive — doesn't drop the current connection).
        # ADDITIVE-ONLY on the Setup AP (2026-07-11 redesign): the netplan config is
        # written + validated above but deliberately NOT applied here — leave the AP
        # broadcasting and the radio untouched so the operator can pre-provision more
        # networks. The switch happens only on the explicit "Stop Setup WiFi", whose
        # teardown (restore_client) runs `netplan apply` and joins the saved network.
        # Off the AP, apply now (additive — doesn't drop the current connection).
        if _conn_setup_ap_active():
            return True, ''
        appl = _run_priv_chain([['netplan', 'apply']], mode='and')
        if not appl or appl.returncode != 0:
            return False, 'Config validated but apply failed: %s' % ((appl.stderr if appl else '') or '')[:140]
        return True, ''
    finally:
        if tmp_path and os.path.exists(tmp_path):
            try:
                os.remove(tmp_path)
            except Exception:
                pass


@app.route('/api/connectivity/wifi/list')
@login_required
def connectivity_wifi_list_api():
    ap_active = _conn_setup_ap_active()
    # In AP mode the radio can't scan, so skip the (stale/empty) visible probe.
    return jsonify({'iface': _conn_wifi_iface(), 'saved': _conn_wifi_saved(),
                    'current': _conn_wifi_current(),
                    'visible': [] if ap_active else _conn_wifi_visible(),
                    'ap_active': ap_active})


@app.route('/api/connectivity/wifi/scan')
@login_required
def connectivity_wifi_scan_api():
    return jsonify({'networks': _conn_wifi_scan()})


@app.route('/api/connectivity/wifi/add', methods=['POST'])
@login_required
def connectivity_wifi_add_api():
    data = request.get_json(silent=True) or {}
    ssid = (data.get('ssid') or '').strip()
    psk = data.get('password') or ''
    if not ssid:
        return jsonify({'success': False, 'error': 'Enter a network name (SSID).'}), 400
    ok, err = _conn_wifi_add(ssid, psk)
    if not ok:
        return jsonify({'success': False, 'error': err}), 400
    return jsonify({'success': True})


# ── Reaching This Box — every LAN address the console (:port) answers on now ──
def _conn_reach_addresses():
    """Every LAN address this box's console (:port) is reachable at right now —
    the data behind the 'Reaching This Box' card (v10.1.2). Lists each real
    Ethernet/WiFi interface with its IP + a ready console URL, flags the one the
    current request arrived on ('you're here now'), and marks the WiFi ones so
    the UI can say 'use this after you unplug Ethernet' (the exact friction of a
    portable box hopping Ethernet→WiFi). Internal bridges (docker/veth/virbr/
    br-/cni/flannel) are excluded — they are not a reach path. No mDNS: this
    reads the box's OWN addresses inside the authenticated console, adds no
    listener and broadcasts nothing (deliberate — mDNS/Avahi was rejected on
    STIG/attack-surface grounds)."""
    try:
        port = str(load_settings().get('console_port') or 5001)
    except Exception:
        port = '5001'
    wifi_if = _conn_wifi_iface()
    here = ''
    try:
        here = (request.host or '').rsplit(':', 1)[0].strip('[]')
    except Exception:
        here = ''
    addrs = []
    info = _conn_local_network(lambda *_a, **_k: None)
    for i in info.get('interfaces', []):
        name = (i.get('iface') or '').strip()
        ip = (i.get('ip') or '').strip()
        if not name or not ip or name == 'lo':
            continue
        if name.startswith(('docker', 'veth', 'virbr', 'br-', 'cni', 'flannel', 'tailscale', 'wg')):
            continue  # internal / overlay bridges — not a LAN reach path
        addrs.append({
            'iface': name,
            'kind': 'wifi' if name == wifi_if else 'ethernet',
            'ip': ip,
            'url': 'https://%s:%s' % (ip, port),
            'current': bool(here) and ip == here,
        })
    # Ethernet first, then WiFi (mirrors the "unplug Ethernet → fall to WiFi" story).
    addrs.sort(key=lambda a: (a['kind'] != 'ethernet', a['iface']))
    return {'port': port, 'addresses': addrs,
            'has_wifi': any(a['kind'] == 'wifi' for a in addrs),
            'has_ethernet': any(a['kind'] == 'ethernet' for a in addrs)}


@app.route('/api/connectivity/addresses')
@login_required
def connectivity_addresses_api():
    return jsonify(_conn_reach_addresses())


# ── Leg 6c — CURRENT + FORGET (which network the box is on; drop a saved one) ──
def _conn_wifi_current():
    """SSID the box is CURRENTLY associated to (''=not connected). Prefers nmcli's
    active-connection view — reliable on RHEL and works even when the radio can't
    scan (associated + on Ethernet). Falls back to `iw dev`. Field-hit 2026-07-11:
    on a box connected to OXFORD, `iw dev` printed NO `ssid` line (driver quirk), so
    the console wrongly showed the live network as 'not in range' instead of
    'connected now'. Our added profiles use con-name==SSID, so the active connection
    name IS the SSID."""
    iface = _conn_wifi_iface()
    if not iface:
        return ''
    if shutil.which('nmcli'):
        try:
            r = subprocess.run(_sudo_wrap(['nmcli', '-t', '-f', 'DEVICE,TYPE,STATE,CONNECTION', 'device', 'status']),
                               capture_output=True, text=True, timeout=8)
            for ln in (r.stdout or '').splitlines():
                p = ln.split(':')
                if len(p) >= 4 and p[0] == iface and p[1] == 'wifi' and p[2] == 'connected':
                    name = ':'.join(p[3:]).strip()
                    if name and name != '--':
                        return name
        except Exception:
            pass
    try:
        _ensure_iw()
        r = subprocess.run(_sudo_wrap(['iw', 'dev']), capture_output=True, text=True, timeout=8)
        cur_if = None
        for ln in (r.stdout or '').splitlines():
            s = ln.strip()
            if s.startswith('Interface '):
                cur_if = s.split(None, 1)[1].strip()
            elif s.startswith('ssid ') and cur_if == iface:
                return s[5:].strip()
    except Exception:
        pass
    return ''


def _conn_wifi_forget(ssid):
    """Remove a saved network. Returns (ok, error). nmcli: delete the profile.
    netplan: strip the SSID from every netplan file that has it, then
    validate-before-apply (revert on failure). Never touches other APs."""
    ssid = (ssid or '').strip()
    if not ssid:
        return False, 'No network specified.'
    if shutil.which('nmcli'):
        r = subprocess.run(_sudo_wrap(['nmcli', 'connection', 'delete', ssid]),
                           capture_output=True, text=True, timeout=30)
        if r.returncode != 0:
            return False, (r.stderr or r.stdout or 'delete failed').strip()[:200]
        return True, ''
    # netplan: read-modify-write each file that contains the AP (via broker).
    import glob as _glob
    import yaml as _yaml
    touched = False
    for f in sorted(_glob.glob('/etc/netplan/*.yaml')):
        try:
            r = subprocess.run(_sudo_wrap(['cat', f]), capture_output=True, text=True, timeout=8)
            if r.returncode != 0 or 'access-points' not in (r.stdout or ''):
                continue
            doc = _yaml.safe_load(r.stdout or '') or {}
            wifis = ((doc.get('network') or {}).get('wifis') or {})
            removed_here = False
            for _iface, cfg in wifis.items():
                aps = cfg.get('access-points') or {}
                if ssid in aps:
                    del aps[ssid]
                    removed_here = True
            if not removed_here:
                continue
            new_yaml = _yaml.safe_dump(doc, default_flow_style=False, sort_keys=False)
            tmp = None
            try:
                fd, tmp = tempfile.mkstemp(prefix='netplan-', suffix='.yaml')
                os.write(fd, new_yaml.encode())
                os.close(fd)
                os.chmod(tmp, 0o600)
                bak = f + '.infratak-forget.bak'
                _run_priv_chain([['cp', '-a', f, bak]], mode='and')
                _run_priv_chain([['install', '-m', '600', '-o', 'root', '-g', 'root', tmp, f]], mode='and')
                gen = _run_priv_chain([['netplan', 'generate']], mode='and')
                if not gen or gen.returncode != 0:
                    _run_priv_chain([['cp', '-a', bak, f], ['netplan', 'generate']], mode='seq')
                    return False, 'Config failed validation — reverted, nothing changed.'
                touched = True
            finally:
                if tmp and os.path.exists(tmp):
                    try:
                        os.remove(tmp)
                    except Exception:
                        pass
        except Exception:
            continue
    if not touched:
        return False, 'That network is not saved on this box.'
    _run_priv_chain([['netplan', 'apply']], mode='and')
    return True, ''


def _conn_wifi_use(ssid):
    """Switch the box onto an already-SAVED network now, using the stored
    credentials (no re-typing the password). Returns (ok, error).
      nmcli   — `nmcli connection up <ssid>` (activates the saved profile).
      netplan — wpa_cli: find the saved network id, select it (associates now),
                then re-enable all others so roaming/fallback still works after.
    The switch is runtime; netplan config (all networks enabled) is authoritative
    again on the next apply/reboot."""
    ssid = (ssid or '').strip()
    if not ssid:
        return False, 'No network specified.'
    if ssid not in _conn_wifi_saved():
        return False, 'That network is not saved yet — add it first (with its password).'
    # If provisioning FROM the Setup AP, the radio is the AP — wpa_cli/nmcli-up
    # can't take effect. Stop the AP so the box reconnects to its known networks
    # (the target, being saved + in range, is what it lands on).
    if _conn_setup_ap_active():
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'takwerx-setup-ap.service']),
                       capture_output=True, text=True, timeout=60)
        return True, ''
    if shutil.which('nmcli'):
        r = subprocess.run(_sudo_wrap(['nmcli', 'connection', 'up', ssid]),
                           capture_output=True, text=True, timeout=45)
        if r.returncode != 0:
            return False, (r.stderr or r.stdout or 'switch failed').strip()[:200]
        return True, ''
    iface = _conn_wifi_iface()
    if not iface:
        return False, 'No wireless interface detected.'
    try:
        lst = subprocess.run(_sudo_wrap(['wpa_cli', '-i', iface, 'list_networks']),
                             capture_output=True, text=True, timeout=10)
        net_id = None
        for ln in (lst.stdout or '').splitlines():
            parts = ln.split('\t')
            if len(parts) >= 2 and parts[1] == ssid:
                net_id = parts[0].strip()
                break
        if net_id is None or not net_id.isdigit():
            return False, 'Saved network not found in the WiFi supplicant — try re-adding it.'
        sel = subprocess.run(_sudo_wrap(['wpa_cli', '-i', iface, 'select_network', net_id]),
                             capture_output=True, text=True, timeout=15)
        if 'OK' not in (sel.stdout or ''):
            return False, 'Switch command was not accepted: %s' % (sel.stdout or sel.stderr or '')[:120]
        # Re-enable the others so the box can still roam/fall back later.
        subprocess.run(_sudo_wrap(['wpa_cli', '-i', iface, 'enable_network', 'all']),
                       capture_output=True, text=True, timeout=10)
        return True, ''
    except Exception as ex:
        return False, 'Could not switch network: %s' % str(ex)[:160]


@app.route('/api/connectivity/wifi/use', methods=['POST'])
@login_required
def connectivity_wifi_use_api():
    data = request.get_json(silent=True) or {}
    ssid = (data.get('ssid') or '').strip()
    ok, err = _conn_wifi_use(ssid)
    if not ok:
        return jsonify({'success': False, 'error': err}), 400
    return jsonify({'success': True})


@app.route('/api/connectivity/wifi/forget', methods=['POST'])
@login_required
def connectivity_wifi_forget_api():
    data = request.get_json(silent=True) or {}
    ssid = (data.get('ssid') or '').strip()
    if not ssid:
        return jsonify({'success': False, 'error': 'No network specified.'}), 400
    # Forgetting the network the box is CURRENTLY using disconnects it. Allow it,
    # but require the operator to acknowledge (client sends confirm=true) AND warn
    # if the Setup AP isn't armed to catch the box.
    current = _conn_wifi_current()
    if ssid == current and not data.get('confirm'):
        ap = _conn_setup_ap_read_conf()
        return jsonify({'success': False, 'needs_confirm': True, 'is_current': True,
                        'setup_ap_ready': bool(ap.get('has_password')),
                        'error': 'This is the network the box is using right now — forgetting it disconnects the box.'}), 409
    ok, err = _conn_wifi_forget(ssid)
    if not ok:
        return jsonify({'success': False, 'error': err}), 400
    return jsonify({'success': True})


# ── Leg 6b — SETUP AP (broadcast own wifi for local provisioning) ─────────────
# When the box has no uplink, it broadcasts `infraTAK-setup-<host>` (WPA2) so an
# operator joins from a laptop, lands on the console login (captive redirect), and
# uses the WiFi card to pick a real network. ONE radio: broadcasting = not a wifi
# client, so this only runs with no uplink to lose. The powerful bits live in the
# root systemd unit takwerx-setup-ap.service (engine tak-setup-ap.sh); the console
# only start/stops that unit through the broker — no new broker privilege.
_SETUP_AP_CONF = '/var/lib/takguard/setup-ap.conf'
_SETUP_AP_ACTIVE_FLAG = '/var/lib/takguard/setup-ap.active'


def _conn_setup_ap_default_ssid():
    try:
        h = socket.gethostname().split('.')[0]
    except Exception:
        h = 'box'
    return 'infraTAK-setup-%s' % h


def _conn_setup_ap_read_conf():
    """Read the engine conf via the broker (root-600). Returns a dict of the
    SETUP_AP_* keys (ssid/auto only — never returns the password)."""
    out = {'ssid': _conn_setup_ap_default_ssid(), 'auto': True, 'has_password': False}
    try:
        r = subprocess.run(_sudo_wrap(['cat', _SETUP_AP_CONF]), capture_output=True, text=True, timeout=8)
        for ln in (r.stdout or '').splitlines():
            ln = ln.strip()
            if ln.startswith('SETUP_AP_SSID='):
                v = ln.split('=', 1)[1].strip().strip('"').strip("'")
                if v:
                    out['ssid'] = v
            elif ln.startswith('SETUP_AP_AUTO='):
                out['auto'] = ln.split('=', 1)[1].strip() != '0'
            elif ln.startswith('SETUP_AP_PASS=') and len(ln.split('=', 1)[1].strip()) >= 8:
                out['has_password'] = True
    except Exception:
        pass
    return out


def _conn_setup_ap_write_conf(ssid, password, auto):
    """Write the root-600 engine conf via a temp file + privileged install."""
    ssid = (ssid or '').strip() or _conn_setup_ap_default_ssid()
    _console_url = ''
    try:
        _st = load_settings()
        _console_port = int(_st.get('console_port') or 5001)
        # If the box has a real cert (LE via Caddy, or a custom cert), the setup AP
        # can send the laptop to the console's Caddy vhost by NAME — the AP's wildcard
        # DNS resolves it to the box, Caddy presents the TRUSTED cert (no warning), and
        # Caddy is the sanctioned auth proxy (it strips client X-Authentik-* — no
        # bypass). Fresh/self-signed boxes have no trusted cert, so the engine falls
        # back to the box's own self-signed https (accept-the-warning floor).
        _ssl_mode = (_st.get('ssl_mode') or '').strip().lower()
        _fqdn = (_st.get('fqdn') or '').split(':')[0].strip()
        if _fqdn and _ssl_mode in ('fqdn', 'custom'):
            _ihost = _get_all_service_domains(_st).get('infratak')
            if _ihost:
                _console_url = 'https://%s/' % _ihost
    except Exception:
        _console_port = 5001
    lines = ['# infra-TAK Setup AP config (managed by the console)\n',
             'SETUP_AP_SSID=%s\n' % ssid,
             'SETUP_AP_CONSOLE_PORT=%d\n' % _console_port,
             'SETUP_AP_CONSOLE_URL=%s\n' % _console_url,
             'SETUP_AP_AUTO=%s\n' % ('1' if auto else '0')]
    if password:
        lines.append('SETUP_AP_PASS=%s\n' % password)
    tmp = None
    try:
        _makedirs_priv('/var/lib/takguard')
        fd, tmp = tempfile.mkstemp(prefix='setup-ap-', suffix='.conf')
        # If no new password given, preserve the existing one (read via broker).
        if not password:
            try:
                r = subprocess.run(_sudo_wrap(['cat', _SETUP_AP_CONF]), capture_output=True, text=True, timeout=8)
                for ln in (r.stdout or '').splitlines():
                    if ln.strip().startswith('SETUP_AP_PASS='):
                        lines.append(ln if ln.endswith('\n') else ln + '\n')
                        break
            except Exception:
                pass
        os.write(fd, ''.join(lines).encode())
        os.close(fd)
        os.chmod(tmp, 0o600)
        inst = _run_priv_chain([['install', '-m', '600', '-o', 'root', '-g', 'root', tmp, _SETUP_AP_CONF]], mode='and')
        return bool(inst and inst.returncode == 0)
    except Exception:
        return False
    finally:
        if tmp and os.path.exists(tmp):
            try:
                os.remove(tmp)
            except Exception:
                pass


def _conn_setup_ap_status():
    st = {'active': os.path.exists(_SETUP_AP_ACTIVE_FLAG), 'ap_capable': None, 'has_wifi': bool(_conn_wifi_iface())}
    st.update(_conn_setup_ap_read_conf())
    return st


@app.route('/api/connectivity/setup-ap/status')
@login_required
def connectivity_setup_ap_status_api():
    return jsonify(_conn_setup_ap_status())


@app.route('/api/connectivity/setup-ap/reveal')
@login_required
def connectivity_setup_ap_reveal_api():
    """Return the current setup-AP password (the operator must be able to read it
    to type it on a laptop — the engine may have auto-generated a random one).
    On-demand only (not in the status poll), authenticated. Read via the broker."""
    pw = ''
    try:
        r = subprocess.run(_sudo_wrap(['cat', _SETUP_AP_CONF]), capture_output=True, text=True, timeout=8)
        for ln in (r.stdout or '').splitlines():
            if ln.strip().startswith('SETUP_AP_PASS='):
                pw = ln.split('=', 1)[1].strip()
                break
    except Exception:
        pass
    return jsonify({'password': pw})


@app.route('/api/connectivity/setup-ap/config', methods=['POST'])
@login_required
def connectivity_setup_ap_config_api():
    data = request.get_json(silent=True) or {}
    ssid = (data.get('ssid') or '').strip()
    password = data.get('password') or ''
    auto = bool(data.get('auto', True))
    if password and not (8 <= len(password) <= 63):
        return jsonify({'success': False, 'error': 'Setup-WiFi password must be 8–63 characters (WPA2).'}), 400
    if ssid and not (1 <= len(ssid.encode('utf-8')) <= 32):
        return jsonify({'success': False, 'error': 'Setup-WiFi name must be 1–32 characters.'}), 400
    # Strict charset (defense-in-depth: the root engine parses the conf by
    # assignment, not `source`, but never let shell-active bytes into a
    # root-read config file). Reject shell metacharacters, quotes, newlines.
    _bad = set('`$();&|<>\\\'"\n\r\t')
    if any(c in _bad for c in ssid) or any(c in _bad for c in password):
        return jsonify({'success': False, 'error': 'Name/password may not contain quotes, newlines, or any of ` $ ( ) ; & | < > \\'}), 400
    if not _conn_setup_ap_write_conf(ssid, password, auto):
        return jsonify({'success': False, 'error': 'Could not save Setup AP config.'}), 500
    return jsonify({'success': True, 'status': _conn_setup_ap_status()})


@app.route('/api/connectivity/setup-ap/start', methods=['POST'])
@login_required
def connectivity_setup_ap_start_api():
    if not _conn_wifi_iface():
        return jsonify({'success': False, 'error': 'No wireless interface on this box — cannot broadcast a setup network.'}), 400
    _ensure_nm_wifi()  # RHEL: the NM hotspot (mode=ap) path needs NetworkManager-wifi installed
    # RHEL: the NM hotspot uses method=shared, whose DHCP + captive DNS is served by
    # dnsmasq — a fresh Rocky box lacks it, so a joined client gets NO IP (browser:
    # ERR_INTERNET_DISCONNECTED) and the FQDN can't resolve on the isolated AP net.
    # Pull it NOW while the box is still online (this endpoint is reached over the very
    # uplink the AP is about to replace). The captive DNS wildcard that makes the FQDN
    # resolve to the box is written root-side by the engine (tak-setup-ap.sh) — the
    # console broker deliberately can't write /etc/NetworkManager (not in PATH_ALLOW).
    if _distro_family() == 'rhel':
        try:
            _pkg_install('dnsmasq', timeout=300)
        except Exception:
            pass
    # Start the root service through the broker. This SEVERS any wifi uplink (the
    # radio becomes the AP), so the HTTP response is sent before the switch lands;
    # the operator reconnects locally to the setup wifi.
    r = subprocess.run(_sudo_wrap(['systemctl', 'start', 'takwerx-setup-ap.service']),
                       capture_output=True, text=True, timeout=60)
    if r.returncode != 0:
        return jsonify({'success': False, 'error': (r.stderr or r.stdout or 'start failed').strip()[:200]}), 500
    return jsonify({'success': True})


def _conn_clear_dead_ethernet():
    """Tear down ethernet connections whose cable is physically gone. Rocky/RHEL
    images ship NetworkManager with ignore-carrier=* — an unplugged NIC KEEPS its
    activation and its metric-100 default route, which blackholes all egress even
    after a wifi join succeeds (field-hit 2026-07-11: OXFORD associated + leased in
    2s after Stop, but the relay tunnel stayed dead until the cable came back —
    every packet was routed into the dead wire). Only touches devices with
    carrier=0; a NIC with a live cable is never disconnected. NM re-arms
    autoconnect on the next carrier-up, so replugging the cable restores wired."""
    try:
        r = subprocess.run(_sudo_wrap(['nmcli', '-t', '-f', 'DEVICE,TYPE,STATE', 'device', 'status']),
                           capture_output=True, text=True, timeout=10)
        for ln in (r.stdout or '').splitlines():
            parts = ln.split(':')
            if len(parts) < 3 or parts[1] != 'ethernet' or not parts[2].startswith('connected'):
                continue
            dev = parts[0]
            try:
                with open('/sys/class/net/%s/carrier' % dev) as f:
                    if f.read().strip() == '1':
                        continue
            except Exception:
                continue  # cannot prove the cable is gone -> leave the device alone
            subprocess.run(_sudo_wrap(['nmcli', 'device', 'disconnect', dev]),
                           capture_output=True, text=True, timeout=15)
    except Exception:
        pass


def _conn_join_best_saved():
    """After the Setup AP stops (the explicit 'done — switch now' action; add is
    additive), join the best saved CLIENT wifi. NM's autoconnect coming out of AP mode
    is unreliable on RHEL (radio comes up idle -> box offline -> watcher re-broadcasts
    the AP), so do it explicitly. Prefers in-range saved SSIDs (skips a slow 'up'
    timeout on out-of-range profiles), never touches the takwerx-hotspot AP profile.
    Best-effort; runs detached from the stop API."""
    if not shutil.which('nmcli'):
        return
    time.sleep(2)  # let the AP teardown (restore_client) free + re-enable the radio
    # Kill any cable-less ethernet FIRST — its stale default route (RHEL
    # ignore-carrier=*) outranks the wifi route and blackholes the box even after
    # a perfect join.
    _conn_clear_dead_ethernet()
    try:
        r = subprocess.run(_sudo_wrap(['nmcli', '-t', '-f', 'NAME,TYPE', 'connection', 'show']),
                           capture_output=True, text=True, timeout=10)
        saved = []
        for ln in (r.stdout or '').splitlines():
            parts = ln.rsplit(':', 1)
            if len(parts) == 2 and 'wireless' in parts[1] and parts[0] != 'takwerx-hotspot':
                saved.append(parts[0])
    except Exception:
        saved = []
    if not saved:
        return
    try:
        visible = set(_conn_wifi_visible())
    except Exception:
        visible = set()
    ordered = [n for n in saved if n in visible] + [n for n in saved if n not in visible]

    def _wifi_has_ipv4():
        # nmcli up returns 0 even for an IPv6-only 'activated' state (older
        # profiles without ipv4.may-fail=no; field-hit 2026-07-11) — a join with
        # no usable IPv4 is a FAILURE here, not a success.
        try:
            iface = _conn_wifi_iface()
            if not iface:
                return True  # can't verify -> don't block the join on it
            rc = subprocess.run(_sudo_wrap(['nmcli', '-t', '-f', 'IP4.ADDRESS', 'device', 'show', iface]),
                                capture_output=True, text=True, timeout=10)
            return 'IP4.ADDRESS' in (rc.stdout or '')
        except Exception:
            return True

    for name in ordered:
        try:
            rr = subprocess.run(_sudo_wrap(['nmcli', 'connection', 'up', name]),
                                capture_output=True, text=True, timeout=40)
            if rr.returncode == 0 and not _wifi_has_ipv4():
                # IPv6-only limbo: tear it down and let the next candidate try.
                subprocess.run(_sudo_wrap(['nmcli', 'connection', 'down', name]),
                               capture_output=True, text=True, timeout=15)
                continue
            if rr.returncode == 0:
                # Uplink changed interface/address — bounce the relay tunnel.
                # Kernel WireGuard caches the peer's source address; after moving
                # from ethernet to wifi it can keep stamping the OLD source and
                # never complete a handshake (field 2026-07-11: OXFORD joined,
                # default route correct via wlp1s0, tunnel stayed dead until the
                # cable returned). A wg-quick restart resets the socket; the
                # relay reconnects in ~2s. No-op when no relay is provisioned.
                if os.path.exists('/etc/wireguard/%s.conf' % _CONN_WG_IF):
                    try:
                        subprocess.run(_sudo_wrap(['systemctl', 'restart', 'wg-quick@%s' % _CONN_WG_IF]),
                                       capture_output=True, text=True, timeout=30)
                    except Exception:
                        pass
                return
        except Exception:
            continue


@app.route('/api/connectivity/setup-ap/stop', methods=['POST'])
@login_required
def connectivity_setup_ap_stop_api():
    r = subprocess.run(_sudo_wrap(['systemctl', 'stop', 'takwerx-setup-ap.service']),
                       capture_output=True, text=True, timeout=60)
    if r.returncode != 0:
        return jsonify({'success': False, 'error': (r.stderr or r.stdout or 'stop failed').strip()[:200]}), 500
    # Stopping the AP is now the explicit "done provisioning — switch to a saved
    # network" step (add is additive). Deterministically join the best saved client
    # wifi in a detached thread (NM autoconnect out of AP mode is unreliable on RHEL).
    threading.Thread(target=_conn_join_best_saved, daemon=True).start()
    return jsonify({'success': True})


# ── EUD Remote Assist Portal ──────────────────────────────────────────────────

_remote_assist_deploy_status = {'running': False, 'complete': False, 'error': False, 'log': []}
_remote_assist_uninstall_status = {'running': False, 'complete': False, 'error': False}


def _remote_assist_restore_tracked_files(ra_dir):
    """Discard legacy infra-TAK patches to tracked files so git pull succeeds (v2.1.0+ uses .env only)."""
    import subprocess as _sp
    if not os.path.isdir(os.path.join(ra_dir, '.git')):
        return
    _sp.run(['git', '-C', ra_dir, 'checkout', '--', 'docker-compose.yml'],
            capture_output=True, text=True, timeout=30)


def _remote_assist_read_version_file(ra_dir):
    """Semver from upstream VERSION file (source of truth since v2.0.0)."""
    try:
        with open(os.path.join(ra_dir, 'VERSION')) as f:
            return f.read().strip().lstrip('vV')
    except Exception:
        return ''


def _remote_assist_deploy_log(msg):
    _remote_assist_deploy_status['log'].append(msg)


def _remote_assist_compose_files(ra_dir):
    return os.path.join(ra_dir, 'docker-compose.yml')


def _remote_assist_compose_cmd(ra_dir, *args):
    return ['docker', 'compose', '-f', _remote_assist_compose_files(ra_dir), *args]


def _ensure_authentik_remote_assist_app(settings, plog=None):
    """Create Authentik OAuth2/OIDC provider + application for Remote Assist admin portal."""
    import urllib.request as _urlreq
    import urllib.error

    def log(msg):
        if plog:
            plog(msg)

    ak_url = _get_authentik_api_url(settings)
    token = (_get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN')
             or _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN'))
    if not token:
        log('  ✗ No Authentik API token found in .env')
        return None, None
    _ak_headers = {'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'}

    slug = REMOTE_ASSIST_OIDC_SLUG
    provider_name = 'EUD Remote Assist'
    portal_domain = _get_service_domain(settings, 'remote_assist')
    portal_base = f'https://{portal_domain}'
    device_base = f'https://{portal_domain}:{REMOTE_ASSIST_DEVICE_PORT}'
    redirect_uris_obj = [
        {'matching_mode': 'strict', 'url': portal_base},
        {'matching_mode': 'strict', 'url': f'{portal_base}/'},
        {'matching_mode': 'strict', 'url': f'{portal_base}/callback'},
        {'matching_mode': 'strict', 'url': f'{portal_base}/silent-callback'},
    ]

    try:
        flow_pk, inv_flow_pk = None, None
        for attempt in range(6):
            try:
                req = _urlreq.Request(f'{ak_url}/api/v3/flows/instances/?designation=authorization&ordering=slug', headers=_ak_headers)
                auth_flows = json.loads(_urlreq.urlopen(req, timeout=15).read().decode())['results']
                flow_pk = next((f['pk'] for f in auth_flows if 'implicit' in f.get('slug', '')), auth_flows[0]['pk'] if auth_flows else None)
                req = _urlreq.Request(f'{ak_url}/api/v3/flows/instances/?designation=invalidation&ordering=slug', headers=_ak_headers)
                inv_flows = json.loads(_urlreq.urlopen(req, timeout=15).read().decode())['results']
                inv_flow_pk = inv_flows[0]['pk'] if inv_flows else None
            except Exception:
                pass
            if flow_pk and inv_flow_pk:
                break
            time.sleep(5)
        if not flow_pk or not inv_flow_pk:
            log(f'  ✗ Missing Authentik flows: auth={flow_pk}, invalidation={inv_flow_pk}')
            return None, None
        log('  ✓ Got authorization and invalidation flows')

        signing_key_pk = None
        scope_mapping_pks = []
        try:
            req = _urlreq.Request(f'{ak_url}/api/v3/crypto/certificatekeypairs/?has_key=true&ordering=name&page_size=50', headers=_ak_headers)
            certs = json.loads(_urlreq.urlopen(req, timeout=15).read().decode()).get('results', [])
            signing_key_pk = next((c['pk'] for c in certs if 'authentik' in (c.get('name') or '').lower()), None)
            if not signing_key_pk and certs:
                signing_key_pk = certs[0]['pk']
        except Exception:
            pass
        try:
            req = _urlreq.Request(f'{ak_url}/api/v3/propertymappings/provider/scope/?ordering=scope_name&page_size=50', headers=_ak_headers)
            mappings = json.loads(_urlreq.urlopen(req, timeout=15).read().decode()).get('results', [])
            scope_mapping_pks = [m['pk'] for m in mappings if m.get('scope_name') in {'openid', 'email', 'profile', 'groups'}]
        except Exception:
            pass

        _provider_extras = {}
        if signing_key_pk:
            _provider_extras['signing_key'] = signing_key_pk
        if scope_mapping_pks:
            _provider_extras['property_mappings'] = scope_mapping_pks

        provider_pk = None
        client_id = ''
        try:
            req = _urlreq.Request(f'{ak_url}/api/v3/providers/oauth2/?search={urllib.parse.quote(provider_name)}', headers=_ak_headers)
            existing = json.loads(_urlreq.urlopen(req, timeout=15).read().decode()).get('results', [])
            for ex in existing:
                if ex.get('name') == provider_name:
                    ex_pk = ex.get('pk')
                    req = _urlreq.Request(f'{ak_url}/api/v3/providers/oauth2/{ex_pk}/', headers=_ak_headers)
                    detail = json.loads(_urlreq.urlopen(req, timeout=15).read().decode())
                    if detail.get('client_id'):
                        provider_pk = ex_pk
                        client_id = detail['client_id']
                        # Browser portal is a public SPA (oidc-client-ts + PKCE). Confidential
                        # clients require client_secret at /token/ — causes HTTP 400 on sign-in.
                        patch_data = {
                            'redirect_uris': redirect_uris_obj,
                            'client_type': 'public',
                            'grant_types': ['authorization_code', 'refresh_token'],
                        }
                        patch_data.update(_provider_extras)
                        try:
                            req = _urlreq.Request(f'{ak_url}/api/v3/providers/oauth2/{ex_pk}/',
                                data=json.dumps(patch_data).encode(), headers=_ak_headers, method='PATCH')
                            _urlreq.urlopen(req, timeout=10)
                        except Exception:
                            pass
                        log(f'  ✓ Existing OAuth2 provider updated (public SPA), client_id={client_id[:8]}...')
                    break
        except Exception:
            pass

        if not provider_pk:
            payload = {
                'name': provider_name,
                'authorization_flow': flow_pk,
                'invalidation_flow': inv_flow_pk,
                'client_type': 'public',
                'client_id': slug,
                'redirect_uris': redirect_uris_obj,
                'grant_types': ['authorization_code', 'refresh_token'],
            }
            payload.update(_provider_extras)
            try:
                req = _urlreq.Request(f'{ak_url}/api/v3/providers/oauth2/',
                    data=json.dumps(payload).encode(), headers=_ak_headers, method='POST')
                p = json.loads(_urlreq.urlopen(req, timeout=15).read().decode())
                provider_pk = p.get('pk')
                client_id = p.get('client_id', '')
                log(f'  ✓ OAuth2 provider created (public SPA), client_id={client_id[:8]}...')
            except Exception as e:
                body = ''
                try:
                    body = e.read().decode()[:500]
                except Exception:
                    pass
                log(f'  ✗ OAuth2 provider create failed: {body or str(e)[:200]}')

        if not provider_pk or not client_id:
            log('  ✗ No OAuth2 provider — cannot continue')
            return None, None

        _app_body = {
            'name': provider_name,
            'slug': slug,
            'provider': provider_pk,
            'meta_launch_url': portal_base,
        }
        try:
            req = _urlreq.Request(f'{ak_url}/api/v3/core/applications/',
                data=json.dumps(_app_body).encode(), headers=_ak_headers, method='POST')
            _urlreq.urlopen(req, timeout=10)
            log('  ✓ Application created')
        except Exception as e:
            if hasattr(e, 'code') and e.code == 400:
                try:
                    req = _urlreq.Request(f'{ak_url}/api/v3/core/applications/{slug}/',
                        data=json.dumps({'provider': provider_pk, 'meta_launch_url': portal_base}).encode(),
                        headers=_ak_headers, method='PATCH')
                    _urlreq.urlopen(req, timeout=10)
                except Exception:
                    pass
                log('  ✓ Application already exists (updated)')
            else:
                log(f'  ⚠ Application error: {str(e)[:80]}')

        try:
            _ak_url = _get_authentik_api_url(settings)
            _ak_token = token
            if _ak_token:
                _ensure_app_access_policies(_ak_url, {'Authorization': f'Bearer {_ak_token}',
                                                      'Content-Type': 'application/json'}, plog)
                log('  ✓ Portal access restricted to infra-TAK administrators (authentik Admins)')
        except Exception as _e:
            log(f'  ⚠ Access policy binding skipped: {str(_e)[:120]}')

        return client_id, ''
    except Exception as e:
        log(f'  ✗ Authentik OAuth setup failed: {str(e)[:200]}')
        return None, None


def _deregister_authentik_oauth2_app(settings, app_slug, prov_name, plog=None):
    """Remove OAuth2 application + provider from Authentik. Idempotent, non-fatal."""
    _log = plog or (lambda m: None)
    import urllib.request as _req
    ak_token = (
        _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN') or
        _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN')
    )
    if not ak_token:
        return False
    ak_url = _get_authentik_api_url(settings)
    ak_headers = {'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'}

    def _del(url):
        try:
            _req.urlopen(_req.Request(url, headers=ak_headers, method='DELETE'), timeout=10)
            return True
        except Exception as e:
            if getattr(e, 'code', None) == 404:
                return True
            return False

    provider_pk = None
    try:
        r = _req.Request(f'{ak_url}/api/v3/core/applications/{app_slug}/', headers=ak_headers)
        app = json.loads(_req.urlopen(r, timeout=10).read().decode())
        provider_pk = app.get('provider')
    except Exception:
        pass
    if not provider_pk and prov_name:
        try:
            r = _req.Request(f'{ak_url}/api/v3/providers/oauth2/?search={urllib.parse.quote(prov_name)}', headers=ak_headers)
            results = json.loads(_req.urlopen(r, timeout=10).read().decode()).get('results', [])
            match = next((p for p in results if (p.get('name') or '').strip() == prov_name), None)
            if match:
                provider_pk = match.get('pk')
        except Exception:
            pass
    if _del(f'{ak_url}/api/v3/core/applications/{app_slug}/'):
        _log(f"  ✓ Authentik application '{app_slug}' removed")
    if provider_pk and _del(f'{ak_url}/api/v3/providers/oauth2/{provider_pk}/'):
        _log(f"  ✓ Authentik OAuth2 provider '{prov_name}' removed")
    return True


def _remote_assist_write_env(ra_dir, settings, client_id, pg_password):
    ak_domain = _get_service_domain(settings, 'authentik')
    portal_domain = _get_service_domain(settings, 'remote_assist')
    portal_base = f'https://{portal_domain}'
    device_base = f'https://{portal_domain}:{REMOTE_ASSIST_DEVICE_PORT}'
    oidc_issuer = f'https://{ak_domain}/application/o/{REMOTE_ASSIST_OIDC_SLUG}/'
    oidc_jwks = f'{oidc_issuer.rstrip("/")}/jwks/'
    env_lines = [
        f'POSTGRES_USER=cfd',
        f'POSTGRES_PASSWORD={pg_password}',
        f'POSTGRES_DB=eud_remote_assist',
        f'PUBLIC_BASE_URL={device_base}',
        f'OIDC_ISSUER={oidc_issuer}',
        f'OIDC_AUDIENCE={client_id}',
        f'OIDC_CLIENT_ID={client_id}',
        f'OIDC_JWKS_URI={oidc_jwks}',
        f'OIDC_ADMIN_GROUP=authentik Admins',
        f'CORS_ORIGIN={portal_base}',
        f'NGINX_BIND_ADDR=127.0.0.1',
        f'HTTP_PORT={REMOTE_ASSIST_PORT}',
        f'NGINX_ENABLE_TLS=false',
        # v10.0.9 security scan: keep upstream TLS verification ON for the phonedb.net
        # lookup (upstream .env.example ships it disabled-by-default — a MITM could inject
        # crafted HTML into device model metadata rendered in the admin console). CJIS bar
        # forbids disabled cert verification; the lookup is non-critical, so fail-closed.
        f'PHONEDB_TLS_INSECURE=false',
    ]
    env_path = os.path.join(ra_dir, '.env')
    with open(env_path, 'w') as f:
        f.write('\n'.join(env_lines) + '\n')
    os.chmod(env_path, 0o600)


def _run_remote_assist_deploy(settings):
    import subprocess as _sp
    import secrets as _sec
    plog = _remote_assist_deploy_log
    ra_dir = REMOTE_ASSIST_INSTALL_DIR
    try:
        fqdn = (settings.get('fqdn') or '').strip()
        if not fqdn:
            raise RuntimeError('FQDN required — configure Caddy SSL first (Marketplace needs a domain for OIDC).')

        plog('━━━ Step 1/6: Checking Docker ━━━')
        r = _sp.run(_sudo_wrap(['docker', '--version']), capture_output=True, text=True)
        if r.returncode != 0:
            plog('  Docker not found — installing...')
            r2 = _sp.run(_docker_install_cmd() + ' 2>&1',
                         shell=True, capture_output=True, text=True, timeout=300)
            if r2.returncode != 0:
                raise RuntimeError(f'Docker install failed: {r2.stdout[-300:]}')
            plog('✓ Docker installed')
        else:
            plog(f'✓ Docker present: {r.stdout.strip()}')

        plog('')
        plog('━━━ Step 2/6: Provisioning Authentik OIDC Application ━━━')
        client_id, client_secret = _ensure_authentik_remote_assist_app(settings, plog=plog)
        if not client_id:
            raise RuntimeError('Authentik OIDC provisioning failed — ensure Authentik is running.')

        plog('')
        plog('━━━ Step 3/6: Cloning Repository ━━━')
        if os.path.isdir(os.path.join(ra_dir, '.git')):
            plog(f'  Repo already at {ra_dir} — pulling latest...')
            _remote_assist_restore_tracked_files(ra_dir)
            r = _sp.run(['git', '-C', ra_dir, 'pull', '--ff-only'], capture_output=True, text=True, timeout=120)
            plog((r.stdout + r.stderr).strip() or '(no output)')
        else:
            os.makedirs(ra_dir, exist_ok=True)
            plog(f'  Cloning {REMOTE_ASSIST_REPO} → {ra_dir}')
            r = _sp.run(['git', 'clone', '--depth=1', REMOTE_ASSIST_REPO, ra_dir],
                        capture_output=True, text=True, timeout=180)
            if r.returncode != 0:
                raise RuntimeError(f'git clone failed: {r.stderr[:300]}')
            plog('✓ Repository cloned')

        sha_r = _sp.run(['git', '-C', ra_dir, 'rev-parse', '--short', 'HEAD'], capture_output=True, text=True)
        commit_sha = sha_r.stdout.strip() or 'unknown'
        plog(f'  Commit SHA: {commit_sha}')
        _sp.run(['git', '-C', ra_dir, 'fetch', '--tags', '--depth', '1'],
                capture_output=True, text=True, timeout=60)

        plog('')
        plog('━━━ Step 4/6: Writing Configuration ━━━')
        pg_password = settings.get('remote_assist_pg_password') or _sec.token_hex(24)
        _remote_assist_write_env(ra_dir, settings, client_id, pg_password)
        ra_version = _remote_assist_read_version_file(ra_dir)
        plog(f'✓ .env written (NGINX_BIND_ADDR=127.0.0.1 HTTP_PORT={REMOTE_ASSIST_PORT})')
        if ra_version:
            plog(f'  Portal release: v{ra_version}')

        plog('')
        plog('━━━ Step 5/6: Building & Starting Containers ━━━')
        plog('  ⏳ First build compiles server + web — allow 5–10 min...')
        r = _sp.run(_remote_assist_compose_cmd(ra_dir, 'up', '-d', '--build'),
                    capture_output=True, text=True, timeout=900, cwd=ra_dir)
        if r.returncode != 0:
            raise RuntimeError(f'docker compose up --build failed:\n{(r.stderr or r.stdout)[-600:]}')
        plog('✓ Containers built and started')
        _sp.run(_remote_assist_compose_cmd(ra_dir, 'up', '-d', '--force-recreate', 'nginx'),
                capture_output=True, text=True, timeout=120, cwd=ra_dir)
        plog('✓ nginx recreated (picks up host nginx.conf + loopback bind)')

        plog('')
        plog('━━━ Step 6/6: Firewall & Reverse Proxy ━━━')
        if _distro_family() == 'rhel':
            # No ufw on RHEL (bare argv ufw aborts the deploy). The admin/proxy port stays
            # closed — it's loopback/Caddy-only and firewalld default-deny covers it. But the
            # Android device API port is a real inbound listener (host Caddy), so it must be
            # opened in firewalld explicitly: the cloud SG sits IN FRONT of the host firewall,
            # so 'SG handles it' is not enough — firewalld still drops 8448 at the host.
            _run_priv_chain([['firewall-cmd', '--permanent', f'--add-port={REMOTE_ASSIST_DEVICE_PORT}/tcp'], ['firewall-cmd', '--reload']], 'seq', timeout=30)
            plog(f'  ✓ firewalld allow {REMOTE_ASSIST_DEVICE_PORT}/tcp (Android device API); {REMOTE_ASSIST_PORT} Caddy-only (loopback)')
        else:
            _sp.run(_sudo_wrap(['ufw', 'deny', f'{REMOTE_ASSIST_PORT}/tcp']), capture_output=True)
            plog(f'  ✓ ufw deny {REMOTE_ASSIST_PORT}/tcp (loopback/Caddy-only)')
            _sp.run(_sudo_wrap(['ufw', 'allow', f'{REMOTE_ASSIST_DEVICE_PORT}/tcp']), capture_output=True)
            plog(f'  ✓ ufw allow {REMOTE_ASSIST_DEVICE_PORT}/tcp (Android device API)')
        s = load_settings()
        s['remote_assist_enabled'] = True
        s['remote_assist_pg_password'] = pg_password
        s['remote_assist_commit_sha'] = commit_sha
        s['remote_assist_oidc_client_id'] = client_id
        if ra_version:
            s['remote_assist_version'] = ra_version
        save_settings(s)
        generate_caddyfile(s)
        _sp.run(_sudo_wrap(['systemctl', 'restart', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        plog('✓ Caddy restarted (8448 listener requires full restart)')

        portal_url = f'https://{_get_service_domain(s, "remote_assist")}'
        device_url = f'{portal_url}:{REMOTE_ASSIST_DEVICE_PORT}'
        plog('')
        plog('🎉 Remote Assist deployed successfully!')
        plog(f'Admin portal: {portal_url}')
        plog(f'Device API:   {device_url}')
        plog('Sign in with Authentik — infra-TAK administrators only (authentik Admins group).')
        _remote_assist_deploy_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as exc:
        plog(f'✗ Deployment failed: {exc}')
        _remote_assist_deploy_status.update({'running': False, 'error': True})


REMOTE_ASSIST_UPSTREAM_CACHE_TTL = 1800  # 30 min — dashboard polls; /api/remote-assist/version bypasses via fresh=True

_remote_assist_upstream_cache = {'version': None, 'sha': None, 'version_ts': 0, 'sha_ts': 0}


def _remote_assist_github_repo_path():
    """cfd2474/EUD_Remote_Assist_Portal from REMOTE_ASSIST_REPO."""
    import re as _re
    m = _re.search(r'github\.com[:/]([^/]+/[^/.]+)', REMOTE_ASSIST_REPO or '')
    return m.group(1) if m else 'cfd2474/EUD_Remote_Assist_Portal'


def _remote_assist_github_headers():
    return {'Accept': 'application/vnd.github+json', 'User-Agent': 'infra-TAK'}


def _remote_assist_version_tuple(ver):
    """Parse semver-ish tag (v1.3.3) to comparable tuple."""
    import re as _re
    v = (ver or '').strip().lstrip('vV')
    parts = []
    for p in v.split('.')[:3]:
        try:
            parts.append(int(_re.sub(r'[^0-9].*', '', p) or '0'))
        except ValueError:
            parts.append(0)
    while len(parts) < 3:
        parts.append(0)
    return tuple(parts)


def _fetch_remote_assist_upstream(*, fresh=False):
    """Upstream VERSION + main SHA via GitHub API (contents + git ref — not raw.githubusercontent.com).

    Two lightweight API calls replace the old raw VERSION fetch plus commits/tags list (which
    burned unauthenticated rate limit and cached stale semver for 4h). Separate TTLs per field;
    fresh=True bypasses cache (used by /api/remote-assist/version and page load).
    Returns stale cache on failure rather than None."""
    import time as _time
    import base64 as _b64
    import urllib.request as _ur
    repo = _remote_assist_github_repo_path()
    now = _time.time()
    c = _remote_assist_upstream_cache
    out = {'version': c.get('version'), 'sha': c.get('sha')}

    need_version = fresh or not c.get('version') or (now - c.get('version_ts', 0) >= REMOTE_ASSIST_UPSTREAM_CACHE_TTL)
    need_sha = fresh or not c.get('sha') or (now - c.get('sha_ts', 0) >= REMOTE_ASSIST_UPSTREAM_CACHE_TTL)
    if not need_version and not need_sha:
        return out

    if need_version:
        try:
            req = _ur.Request(
                f'https://api.github.com/repos/{repo}/contents/VERSION?ref=main',
                headers=_remote_assist_github_headers())
            with _ur.urlopen(req, timeout=12) as resp:
                data = json.loads(resp.read().decode())
            raw = (data.get('content') or '').replace('\n', '')
            ver = (_b64.b64decode(raw).decode().strip().lstrip('vV') or None) if raw else None
            if ver:
                c['version'] = ver
                c['version_ts'] = now
                out['version'] = ver
        except Exception as e:
            print(f"version-info: remote-assist GitHub VERSION fetch failed (non-fatal): {e}", flush=True)

    if need_sha:
        try:
            req = _ur.Request(
                f'https://api.github.com/repos/{repo}/git/ref/heads/main',
                headers=_remote_assist_github_headers())
            with _ur.urlopen(req, timeout=12) as resp:
                data = json.loads(resp.read().decode())
            sha = ((data.get('object') or {}).get('sha') or '').strip() or None
            if sha:
                c['sha'] = sha
                c['sha_ts'] = now
                out['sha'] = sha
        except Exception as e:
            print(f"version-info: remote-assist GitHub main ref fetch failed (non-fatal): {e}", flush=True)

    return out


def _get_remote_assist_running_version():
    """Running portal version from loopback /version (device API path on nginx)."""
    import urllib.request as _ur
    try:
        req = _ur.Request(
            f'http://127.0.0.1:{REMOTE_ASSIST_PORT}/version',
            headers={'User-Agent': 'infra-TAK'})
        with _ur.urlopen(req, timeout=5) as resp:
            data = json.loads(resp.read().decode())
            return (data.get('version') or '').strip().lstrip('vV')
    except Exception:
        return ''


def _get_remote_assist_version_info(*, fresh=False):
    """Return {version, update_available, latest, latest_tag, running, is_current} for EUD Remote Assist.

    Compares local VERSION to upstream main VERSION via GitHub API (per docs/versioning.md).
    Falls back to git SHA when VERSION is missing on old checkouts. Pass fresh=True to bypass
    the 30-minute upstream cache (page load + /api/remote-assist/version polling).
    """
    import subprocess as _sp
    info = {'version': '', 'update_available': False, 'latest': None, 'latest_tag': None,
            'running': '', 'is_current': False}
    ra_dir = REMOTE_ASSIST_INSTALL_DIR
    settings = load_settings()
    local_ver = ''
    if os.path.isdir(ra_dir):
        local_ver = _remote_assist_read_version_file(ra_dir)
    if not local_ver:
        local_ver = (settings.get('remote_assist_version') or '').strip()
    local_full = ''
    if os.path.isdir(os.path.join(ra_dir, '.git')):
        try:
            r = _sp.run(['git', 'rev-parse', 'HEAD'],
                        capture_output=True, text=True, timeout=5, cwd=ra_dir)
            if r.returncode == 0:
                local_full = r.stdout.strip()
        except Exception:
            pass
    if local_ver:
        info['version'] = local_ver
    elif local_full:
        info['version'] = local_full[:7]
    elif settings.get('remote_assist_commit_sha'):
        info['version'] = settings['remote_assist_commit_sha']

    upstream = _fetch_remote_assist_upstream(fresh=fresh)
    latest_ver = upstream.get('version')
    latest_full = upstream.get('sha')
    if latest_ver:
        info['latest'] = latest_ver
        info['latest_tag'] = latest_ver
        if local_ver and _remote_assist_version_tuple(latest_ver) > _remote_assist_version_tuple(local_ver):
            info['update_available'] = True
    if not info['update_available'] and latest_full and local_full and local_full != latest_full:
        info['update_available'] = True
        if not info['latest']:
            info['latest'] = latest_full[:7]
    if not info['update_available']:
        if local_ver and latest_ver and _remote_assist_version_tuple(local_ver) >= _remote_assist_version_tuple(latest_ver):
            if not local_full or not latest_full or local_full == latest_full:
                info['is_current'] = True
        elif local_full and latest_full and local_full == latest_full:
            info['is_current'] = True
    running = _get_remote_assist_running_version()
    if running:
        info['running'] = running
    return info


_remote_assist_update_status = {'running': False, 'complete': False, 'error': False, 'log': []}


def _run_remote_assist_update():
    import subprocess as _sp
    import secrets as _sec
    global _remote_assist_update_status
    log = []
    def plog(msg):
        log.append(msg)
        _remote_assist_update_status['log'] = list(log)
    ra_dir = REMOTE_ASSIST_INSTALL_DIR
    try:
        settings = load_settings()
        plog('━━━ Step 1/5: Pulling latest source ━━━')
        _remote_assist_restore_tracked_files(ra_dir)
        # Ensure remote URL is correct (handles repository rename)
        _sp.run(['git', '-C', ra_dir, 'remote', 'set-url', 'origin', REMOTE_ASSIST_REPO],
                capture_output=True, text=True, timeout=10)
        # Explicitly fetch main to handle shallow clones properly
        _sp.run(['git', '-C', ra_dir, 'fetch', 'origin', 'main', '--depth', '1'],
                capture_output=True, text=True, timeout=120)
        r = _sp.run(['git', '-C', ra_dir, 'reset', '--hard', 'origin/main'],
                    capture_output=True, text=True, timeout=120)
        plog((r.stdout + r.stderr).strip() or '(no output)')
        if r.returncode != 0:
            raise RuntimeError(f'git pull failed: {r.stderr[:300]}')
        _sp.run(['git', '-C', ra_dir, 'fetch', '--tags', '--depth', '1'],
                capture_output=True, text=True, timeout=60)

        plog('')
        plog('━━━ Step 2/5: Refreshing Authentik + .env ━━━')
        client_id = settings.get('remote_assist_oidc_client_id')
        if not client_id:
            client_id, _ = _ensure_authentik_remote_assist_app(settings, plog=plog)
        if not client_id:
            raise RuntimeError('Authentik OIDC client_id missing')
        pg_password = settings.get('remote_assist_pg_password') or _sec.token_hex(24)
        _remote_assist_write_env(ra_dir, settings, client_id, pg_password)
        ra_version = _remote_assist_read_version_file(ra_dir)
        plog(f'✓ .env written (loopback nginx → 127.0.0.1:{REMOTE_ASSIST_PORT})')
        if ra_version:
            plog(f'  Portal release: v{ra_version}')

        plog('')
        plog('━━━ Step 3/5: Rebuilding containers ━━━')
        r = _sp.run(_remote_assist_compose_cmd(ra_dir, 'up', '-d', '--build'),
                    capture_output=True, text=True, timeout=900, cwd=ra_dir)
        plog((r.stdout + r.stderr).strip()[-600:] or '(no output)')
        if r.returncode != 0:
            raise RuntimeError(f'docker compose build failed: {r.stderr[:300]}')
        _sp.run(_remote_assist_compose_cmd(ra_dir, 'up', '-d', '--force-recreate', 'nginx'),
                capture_output=True, text=True, timeout=120, cwd=ra_dir)
        plog('✓ nginx recreated (picks up host nginx.conf + loopback bind)')

        plog('')
        plog('━━━ Step 4/5: Verifying running version ━━━')
        running_ver = _get_remote_assist_running_version()
        if running_ver:
            plog(f'  GET /version → v{running_ver}')
            if ra_version and running_ver != ra_version:
                plog(f'  ⚠ VERSION file is v{ra_version} but container reports v{running_ver}')

        plog('')
        plog('━━━ Step 5/5: Saving new version ━━━')
        sha_r = _sp.run(['git', '-C', ra_dir, 'rev-parse', '--short', 'HEAD'],
                        capture_output=True, text=True, timeout=5)
        new_sha = sha_r.stdout.strip() or 'unknown'
        s = load_settings()
        s['remote_assist_commit_sha'] = new_sha
        s['remote_assist_pg_password'] = pg_password
        s['remote_assist_oidc_client_id'] = client_id
        if ra_version:
            s['remote_assist_version'] = ra_version
        save_settings(s)
        label = f'v{ra_version}' if ra_version else new_sha
        plog(f'✓ EUD Remote Assist updated to {label}')
        _remote_assist_upstream_cache.update({'version_ts': 0, 'sha_ts': 0})
        _fetch_remote_assist_upstream(fresh=True)
        _remote_assist_update_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as exc:
        plog(f'ERROR: {exc}')
        _remote_assist_update_status.update({'running': False, 'complete': False, 'error': str(exc)})


