@app.route('/guarddog')
@login_required
def guarddog_page():
    settings = load_settings()
    modules = detect_modules()
    gd = modules.get('guarddog', {})
    tak = modules.get('takserver', {})
    relay = settings.get('email_relay', {})
    email_relay_configured = bool(relay.get('relay_host') and relay.get('smtp_user'))
    tak_cfg = _get_tak_deployment_config(settings)
    is_two_server = tak_cfg.get('mode') == 'two_server'
    s1_host = (tak_cfg.get('server_one', {}).get('host') or '').strip() if is_two_server else ''
    guarddog_monitors_tak = [
        {'name': 'Port 8089', 'id': 'port8089', 'interval': '1 min', 'desc': 'Checks that TAK Server port 8089 is listening and accepting connections. Auto-restarts TAK Server after 3 consecutive failures.'},
        {'name': 'Process', 'id': 'process', 'interval': '1 min', 'desc': 'Verifies all 5 TAK Server Java processes (messaging, api, config, plugins, retention). Auto-restart after 3 consecutive failures.'},
        {'name': 'Network', 'id': 'network', 'interval': '1 min', 'desc': 'Pings Cloudflare (1.1.1.1) and Google (8.8.8.8); if ICMP is blocked (common on Azure/cloud) it falls back to a TCP connect to confirm egress. Alerts only (no restart) after 3 failures — helps distinguish network issues from server issues.'},
    ]
    if not is_two_server:
        guarddog_monitors_tak.extend([
            {'name': 'PostgreSQL', 'id': 'postgresql', 'interval': '5 min', 'desc': 'Checks that the PostgreSQL service is running. Attempts restart if down; sends alert.'},
        ])
    guarddog_monitors_tak.extend([
        {'name': 'CoT database size', 'id': 'cotdb', 'interval': '6 hours', 'desc': 'CoT DB size. Alert at 25GB (warning) or 40GB (critical). Retention deletes rows; run VACUUM to reclaim disk. Works for both local and remote databases.'},
        {'name': 'Auto-VACUUM', 'id': 'autovacuum', 'interval': 'Daily (3am)', 'desc': 'Checks dead tuple count daily. Runs VACUUM ANALYZE automatically if dead tuples exceed 1M. Prevents database bloat from data retention.'},
    ])
    guarddog_monitors_tak.extend([
        {'name': 'OOM', 'id': 'oom', 'interval': '1 min', 'desc': 'Scans TAK Server logs for OutOfMemoryError. Auto-restarts TAK Server and sends alert when detected.'},
        {'name': 'Disk', 'id': 'disk', 'interval': '1 hour', 'desc': 'Checks root and TAK logs filesystem usage. Alert only when usage exceeds 80% (warning) or 90% (critical).'},
        {'name': 'Docker build-cache reclaim', 'id': 'buildcache', 'interval': 'Hourly', 'desc': 'Reclaims dead Docker BuildKit build cache (the disk that quietly fills from repeated CloudTAK/image rebuilds). At 70%+ root disk it prunes cache older than 7 days (keeps recent cache so rebuilds stay fast); at 85%+ it reclaims ALL unused cache to rescue a filling disk. Never touches images, containers, or volumes.'},
        {'name': 'Certificate', 'id': 'cert', 'interval': 'Daily', 'desc': 'Checks TAK Server Let\'s Encrypt JKS cert expiry. Auto-renewal runs at 35 days remaining. Alert fires at 25 days — meaning renewal failed and action is required.'},
        {'name': 'Root CA / Intermediate CA', 'id': 'intca', 'interval': 'Escalating', 'desc': 'Monitors Root CA and Intermediate CA certificate expiry. First alert at 90 days, then at 75, 60, 45, 30 days, then daily until expiry.'},
    ])
    guarddog_services = [
        {'id': 'takserver', 'name': 'TAK Server', 'monitored': gd.get('installed'), 'monitors': guarddog_monitors_tak},
    ]
    if is_two_server and s1_host:
        guarddog_services.append({'id': 'remotedb', 'name': f'Remote Database ({s1_host})', 'monitored': gd.get('installed'), 'monitors': [
            {'name': 'TCP + SSH', 'id': 'remotedb_tcp', 'interval': '2 min', 'desc': f'Checks port 5432 on Server One / remote server ({s1_host}) is reachable and PostgreSQL cluster is up. Auto-restarts PG via SSH after 3 consecutive failures. Alerts on persistent failure.'},
            {'name': 'Health Agent', 'id': 'remotedb_agent', 'interval': 'Always', 'desc': f'Lightweight health endpoint on Server One / remote server ({s1_host}:8080/health) — checks PG ready, cot database, disk usage. If red, click "Deploy health agent to Server One / remote server" below.'},
            {'name': 'DB Auth', 'id': 'remotedb_auth', 'interval': '2 min', 'desc': f'Validates martiuser password from CoreConfig.xml against PostgreSQL on Server One / remote server ({s1_host}). Red means credential drift — Guard Dog auto-resyncs and notifies you.'},
        ]})
    fh_cfg = _get_fedhub_deployment_config(settings)
    fh_deployed = fh_cfg.get('deployed') and fh_cfg.get('target_mode') == 'remote'
    fh_host = (fh_cfg.get('remote', {}).get('host') or '').strip() if fh_deployed else ''
    if fh_deployed and fh_host:
        guarddog_services.append({'id': 'federation_hub', 'name': f'Federation Hub ({fh_host})', 'monitored': gd.get('installed'), 'monitors': [
            {'name': 'Service', 'id': 'fedhub_svc', 'interval': '1 min', 'desc': f'Checks federation-hub systemd service on {fh_host} via SSH. Auto-restarts after 3 consecutive failures.'},
            {'name': 'Port 9100 (UI)', 'id': 'fedhub_port', 'interval': '1 min', 'desc': f'Checks that Federation Hub UI port 9100 is listening on {fh_host}. Alerts after 3 failures.'},
            {'name': 'MongoDB', 'id': 'fedhub_mongo', 'interval': '5 min', 'desc': f'Checks mongod service is active on {fh_host}. Alerts on failure.'},
            {'name': 'Disk', 'id': 'fedhub_disk', 'interval': '1 hour', 'desc': f'Checks root filesystem usage on {fh_host}. Alert at 80%+ (warning) or 90%+ (critical).'},
            {'name': 'TLS certificate', 'id': 'fedhub_cert', 'interval': 'Daily', 'desc': f'Checks Federation Hub server TLS cert (<hostname>.pem) on {fh_host}. Alert when 25 days or less remaining (below auto-renewal window).'},
            {'name': 'Root CA / Intermediate CA', 'id': 'fedhub_intca', 'interval': 'Escalating', 'desc': f'Monitors Root CA and Intermediate CA expiry on {fh_host} (same 90-day escalation as TAK Server intca).'},
        ]})
    guarddog_services.extend([
        {'id': 'authentik', 'name': 'Authentik', 'monitored': modules.get('authentik', {}).get('installed'), 'monitors': [
            {'name': 'Container / HTTP', 'id': 'authentik_http', 'interval': '1 min', 'desc': 'Checks Authentik HTTP (9090). Alert and restart after 3 failures. 15 min boot skip + cooldown to avoid restart loops.'},
            {'name': 'Channels table', 'id': 'authentik_channels', 'interval': '10 min', 'desc': 'Size of the django_channels_postgres_message table (websocket message backlog). Green under 1GB; red at 1GB+ means the in-process reaper is failing and the table is bloating toward a disk-fill (the NE-TAK 605GB incident). Size-based check — never count(*).'},
        ]},
        {'id': 'takportal', 'name': 'TAK Portal', 'monitored': modules.get('takportal', {}).get('installed'), 'monitors': [{'name': 'Container', 'id': 'takportal_ctr', 'interval': '1 min', 'desc': 'Checks TAK Portal container is running. Alert and auto-restart after 3 failures. 15 min boot skip + cooldown to avoid restart loops.'}]},
        {'id': 'mediamtx', 'name': 'MediaMTX', 'monitored': modules.get('mediamtx', {}).get('installed'), 'monitors': [{'name': 'Service', 'id': 'mediamtx_svc', 'interval': '1 min', 'desc': 'Checks systemd mediamtx. Alert and restart after 3 failures. 15 min boot skip + cooldown to avoid restart loops.'}]},
        {'id': 'tak_video_restreamer', 'name': 'TAK Video Restreamer', 'monitored': modules.get('tak_video_restreamer', {}).get('installed'), 'monitors': [{'name': 'Container / HTTP', 'id': 'tvr_http', 'interval': '1 min', 'desc': 'Checks tak-video-restreamer container health (GET /login on port 3100). Alert and restart after 3 failures. 15 min boot skip + cooldown to avoid restart loops.'}]},
        {'id': 'nodered', 'name': 'Node-RED', 'monitored': modules.get('nodered', {}).get('installed'), 'monitors': [{'name': 'Container / HTTP', 'id': 'nodered_http', 'interval': '1 min', 'desc': 'Checks Node-RED HTTP (1880). Alert and restart after 3 failures. 15 min boot skip + cooldown to avoid restart loops.'}]},
        {'id': 'cloudtak', 'name': 'CloudTAK', 'monitored': modules.get('cloudtak', {}).get('installed'), 'monitors': [{'name': 'Container', 'id': 'cloudtak_ctr', 'interval': '1 min', 'desc': 'Checks CloudTAK container. Alert and restart after 3 failures. 15 min boot skip + cooldown to avoid restart loops.'}]},
        {'id': 'updates', 'name': 'Updates', 'monitored': gd.get('installed'), 'monitors': [{'name': 'Update check', 'id': 'updates_check', 'interval': '6 h', 'desc': 'Checks for newer versions of infra-TAK, Authentik, MediaMTX, CloudTAK, and TAK Portal (same sources as the console update icons). Sends one email when any update is available (or when the set of available updates changes). Uses same alert email as other monitors. If this monitor is red or missing, click Update Guard Dog above to reinstall/update timers and scripts.'}]},
    ])
    # v10.1.0 Leg 7: relay (connectivity anchor) health — only shown once a relay is
    # configured. When up, the relay IS the box's ingress; a stale tunnel = clients
    # can't reach the box, so it belongs on the health board next to everything else.
    if (settings.get('connectivity_anchor') or {}).get('anchor_ip'):
        _anchor_ip = settings['connectivity_anchor'].get('anchor_ip')
        guarddog_services.append({'id': 'relay', 'name': f'Relay ({_anchor_ip})', 'monitored': gd.get('installed'), 'monitors': [
            {'name': 'Tunnel', 'id': 'relay_tunnel', 'interval': '1 min', 'desc': f'Checks the WireGuard tunnel to the relay ({_anchor_ip}) by handshake age (fresh = healthy). Alerts after 3 consecutive stale checks (~3 min) and auto-clears on recovery. While the tunnel is down, no-VPN clients cannot reach this box through the relay address.'},
        ]})
    guarddog_docs_url = f'https://github.com/{GITHUB_REPO}/blob/main/docs/GUARDDOG.md'
    notifications_configured = bool((settings.get('guarddog_alert_email') or '').strip())
    # Detect if Guard Dog config is current or needs re-deploy
    _gd_dep_ver = settings.get('guarddog_deployed_version', '')
    _gd_dep_email = settings.get('guarddog_deployed_email', '')
    _gd_dep_nick = settings.get('guarddog_deployed_nickname', '')
    _gd_cur_email = (settings.get('guarddog_alert_email') or '').strip()
    _gd_cur_nick = (settings.get('guarddog_server_nickname') or '').strip()
    gd_needs_update = (
        gd.get('installed') and (
            _gd_dep_ver != VERSION or
            _gd_dep_email != _gd_cur_email or
            _gd_dep_nick != _gd_cur_nick
        )
    )
    # Last-run timestamps for scheduled maintenance timers
    def _timer_last_run(stamp_file):
        """Read last-run UTC timestamp written by the script itself, or fall back to systemd."""
        try:
            with open(stamp_file) as _f:
                ts = _f.read().strip()
                if ts:
                    return ts
        except Exception:
            pass
        return None

    _autovacuum_last    = _timer_last_run('/var/log/takguard/autovacuum_last.txt')
    _buildcache_last    = _timer_last_run('/var/log/takguard/buildcache_reclaim_last.txt')
    _ak_tasklog_installed = os.path.isfile('/opt/tak-guarddog/tak-authentik-tasklog-purge.sh')
    _ak_tasklog_last      = _timer_last_run('/opt/tak-guarddog/authentik_tasklog_purge_last.txt')

    return render_template_string(GUARDDOG_TEMPLATE,
        settings=settings, gd=gd, tak=tak, version=VERSION,
        gd_needs_update=gd_needs_update, gd_deployed_version=_gd_dep_ver,
        guarddog_alert_email=settings.get('guarddog_alert_email', ''),
        guarddog_server_nickname=settings.get('guarddog_server_nickname', ''),
        guarddog_diskio_monitor_enabled=_guarddog_diskio_monitor_enabled(settings),
        guarddog_diskio_email_enabled=_guarddog_diskio_email_enabled(settings),
        guarddog_sms=settings.get('guarddog_sms', {}),
        guarddog_services=guarddog_services,
        guarddog_docs_url=guarddog_docs_url,
        notifications_configured=notifications_configured,
        email_relay_configured=email_relay_configured,
        health_url=_guarddog_health_url(settings),
        deploying=guarddog_deploy_status.get('running', False),
        deploy_done=guarddog_deploy_status.get('complete', False),
        autovacuum_last=_autovacuum_last,
        buildcache_last=_buildcache_last,
        ak_tasklog_installed=_ak_tasklog_installed,
        ak_tasklog_last=_ak_tasklog_last)

@app.route('/api/guarddog/deploy', methods=['POST'])
@login_required
def guarddog_deploy_api():
    if guarddog_deploy_status.get('running'):
        return jsonify({'error': 'Deployment already in progress'}), 409
    data = request.json or {}
    alert_email = (data.get('alert_email') or '').strip()
    settings = load_settings()
    if not alert_email:
        alert_email = (settings.get('guarddog_alert_email') or '').strip()
    # Allow deploy with no email (monitors run; alerts only after user configures email)
    settings['guarddog_alert_email'] = alert_email
    nickname = (data.get('server_nickname') or '').strip()
    settings['guarddog_server_nickname'] = nickname
    save_settings(settings)
    guarddog_deploy_log.clear()
    guarddog_deploy_status.update({'running': True, 'complete': False, 'error': False})
    threading.Thread(target=run_guarddog_deploy, args=(alert_email,), daemon=True).start()
    return jsonify({'success': True})

def _remote_healthagent_fw_step(db_port, extra_src_ip=''):
    """Shell snippet (run over SSH on Server One with sudo NOPASSWD) that opens 8080 — and,
    on ufw, converges db_port — for the console's source IP(s), on whichever host firewall
    Server One runs: firewalld (RHEL/Rocky), ufw (Debian), or no-op if neither. The caller
    MUST set $SRC (console IP via $SSH_CLIENT) in the same shell before invoking this.

    v10.0.5: the old code hard-coded `sudo ufw …`, which silently no-ops on a RHEL/Rocky
    Server One (firewalld, no ufw) → 8080 either stayed closed (firewalld active) or was left
    to the deploy's scoping. On firewalld we ONLY add a source-scoped 8080 rich-rule and drop
    any broad 8080 open — db_port is left exactly as the split deploy scoped it, so TAK↔DB is
    never touched here."""
    dp = int(db_port)
    esi = (extra_src_ip or '').strip()
    fd = (
        'for A in "$SRC" "' + esi + '"; do [ -n "$A" ] || continue; '
        'sudo firewall-cmd --permanent --add-rich-rule="rule family=\'ipv4\' source address=\'$A\' '
        'port port=\'8080\' protocol=\'tcp\' accept" >/dev/null 2>&1; done; '
        'sudo firewall-cmd --permanent --remove-port=8080/tcp >/dev/null 2>&1; '
        'sudo firewall-cmd --reload >/dev/null 2>&1; '
    )
    esi_ufw = ''
    if esi:
        esi_ufw = (f'sudo ufw allow from {esi} to any port 8080 proto tcp >/dev/null 2>&1; '
                   f'sudo ufw allow from {esi} to any port {dp} proto tcp >/dev/null 2>&1; ')
    ufw = (
        'sudo ufw delete deny 8080/tcp >/dev/null 2>&1; '
        f'sudo ufw delete deny {dp}/tcp >/dev/null 2>&1; '
        f'sudo ufw delete allow {dp}/tcp >/dev/null 2>&1; '
        'if [ -n "$SRC" ]; then sudo ufw allow from "$SRC" to any port 8080 proto tcp >/dev/null 2>&1; '
        f'sudo ufw allow from "$SRC" to any port {dp} proto tcp >/dev/null 2>&1; fi; '
        + esi_ufw +
        'sudo ufw deny 8080/tcp >/dev/null 2>&1; '
        f'sudo ufw deny {dp}/tcp >/dev/null 2>&1; '
    )
    return ('if command -v firewall-cmd >/dev/null 2>&1 && sudo firewall-cmd --state >/dev/null 2>&1; then '
            + fd + 'elif command -v ufw >/dev/null 2>&1; then ' + ufw + 'fi; ')

def _deploy_health_agent_to_server_one(s1_cfg):
    """Deploy Guard Dog health agent to Server One (SCP + systemd + 8080). Returns (ok, message).

    v0.9.12 hardening: host firewall for port 8080 is source-scoped to the console's
    source IP and explicitly denied otherwise. The health endpoint exposes Postgres state —
    it was publicly reachable pre-v0.9.12. Falls back to public-allow only when no source IP.
    """
    scripts_dir = os.path.join(BASE_DIR, 'scripts', 'guarddog')
    agent_src = os.path.join(scripts_dir, 'tak-db-health-agent.py')
    if not os.path.isfile(agent_src):
        return False, 'tak-db-health-agent.py not found'
    # v10.0.5: land in /tmp, not /opt — Server One's SSH user (e.g. rocky) is NOT root and
    # scp can't sudo, so a direct scp to the root-owned /opt failed with "Permission denied".
    # setup_cmd then `sudo mv`s it from /tmp into /opt/tak-guarddog.
    scp_ok, scp_out = _scp_to_host(s1_cfg, agent_src, '/tmp/', timeout=30)
    if not scp_ok:
        return False, f'SCP failed: {(scp_out or "")[:150]}'
    # v0.9.46: scope 8080 to the source IP Server One ACTUALLY sees from the console
    # ($SSH_CLIENT — free, we're already SSH'd in) unioned with server_ip. The old
    # code pinned only server_ip, which is wrong on private-LAN splits where the
    # console egresses a different IP → health poll silently denied → permanent yellow.
    # Also converge the legacy 5432 ALLOW Anywhere (Postgres-to-internet) closed here,
    # since this deploy is the button operators click when the remote DB is unhealthy.
    _settings = load_settings()
    _src_ip = _fedhub_caddy_source_ip(_settings) or ''
    try:
        _dbh, _dbp = _remotedb_host_port_from_tak_settings()
        _db_port = int(_dbp or 5432)
    except Exception:
        _db_port = 5432
    # Backend-aware (firewalld on RHEL/Rocky, ufw on Debian). $SRC is computed in setup_cmd
    # below (the console IP Server One sees via $SSH_CLIENT), unioned with _src_ip.
    _fw_step = _remote_healthagent_fw_step(_db_port, _src_ip)
    setup_cmd = (
        'SRC=$(echo "$SSH_CLIENT" | awk \'{print $1}\'); '
        'sudo mkdir -p /opt/tak-guarddog && '
        'sudo mv /tmp/tak-db-health-agent.py /opt/tak-guarddog/tak-db-health-agent.py && '
        'sudo chmod 644 /opt/tak-guarddog/tak-db-health-agent.py && '
        "cat > /tmp/tak-db-health.service << 'UNIT'\n"
        '[Unit]\n'
        'Description=TAK Database Health Endpoint\n'
        'After=network.target postgresql.service\n\n'
        '[Service]\n'
        'Type=simple\n'
        'ExecStart=/usr/bin/python3 /opt/tak-guarddog/tak-db-health-agent.py\n'
        'Restart=always\n'
        'RestartSec=10\n\n'
        '[Install]\n'
        'WantedBy=multi-user.target\n'
        "UNIT\n"
        'sudo mv /tmp/tak-db-health.service /etc/systemd/system/tak-db-health.service && '
        # RHEL/SELinux: a unit mv'd in from /tmp keeps the tmp context → systemd (init_t) gets
        # "Failed to open …: Permission denied" and the service never starts. restorecon fixes the
        # unit + agent dir contexts; no-op on Ubuntu (no restorecon). `; true` keeps the && chain.
        '{ command -v restorecon >/dev/null 2>&1 && sudo restorecon -RF /opt/tak-guarddog /etc/systemd/system/tak-db-health.service 2>/dev/null; true; } && '
        'sudo systemctl daemon-reload && '
        'sudo systemctl enable tak-db-health.service && '
        'sudo systemctl restart tak-db-health.service && '
        + _fw_step +
        'echo AGENT_OK'
    )
    ok, out = _ssh_probe(s1_cfg, setup_cmd, timeout=30)
    if not ok or 'AGENT_OK' not in (out or ''):
        return False, f'Setup failed: {(out or "")[:150]}'
    return True, 'Health agent deployed (port 8080/health for Guard Dog).'


def _find_ssh_key_for_server_one(s1_cfg):
    """Return path to a usable SSH private key: from config if set and exists, else first of default paths that exists."""
    p = (s1_cfg.get('ssh_key_path') or '').strip()
    if p:
        expanded = os.path.expanduser(p)
        if os.path.exists(expanded):
            return expanded
    for candidate in [
        os.path.expanduser('~/.ssh/id_rsa'),
        os.path.expanduser('~/.ssh/id_ed25519'),
        os.path.expanduser('~/.ssh/infratak_serverone'),  # canonical Server One key name (see key_path at deploy)
    ]:
        if os.path.exists(candidate):
            return candidate
    return None


def _sync_guarddog_remote_db_from_settings(settings=None):
    """Rewrite guarddog.conf + tak-remotedb-*.sh from saved TAK deployment.
    Handles two-server (SSH-managed DB) and external_db (managed DB, no SSH).
    Also try-restarts tak-health.service so it reloads guarddog.conf."""
    if settings is None:
        settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    mode = tak_cfg.get('mode', 'single_server')
    if mode not in ('two_server', 'external_db'):
        return True, 'skipped (single-server mode)'

    gd_dir = '/opt/tak-guarddog'
    scripts_dir = os.path.join(BASE_DIR, 'scripts', 'guarddog')
    if not os.path.isdir(gd_dir):
        return True, 'skipped (Guard Dog not installed)'

    is_external = (mode == 'external_db')

    if is_external:
        edb = tak_cfg.get('external_db', {})
        db_host = (edb.get('host') or '').strip()
        db_port = str(int(edb.get('port') or 5432))
        # No SSH for managed DB — Guard Dog does TCP-only monitoring
        ssh_key_path = ''
        s1_user = ''
    else:
        s1 = dict(tak_cfg.get('server_one', {}))
        db_host = (s1.get('host') or '').strip()
        db_port = str(int(tak_cfg.get('database', {}).get('port') or 5432))
        kp = _find_ssh_key_for_server_one(s1) or ''
        ssh_key_path = os.path.expanduser(kp) if kp else ''
        s1_user = (s1.get('ssh_user') or 'root').strip() or 'root'

    if not db_host:
        return False, 'no database host in settings'

    alert_email = (settings.get('guarddog_alert_email') or '').strip()
    try:
        gd_conf = {
            'two_server': not is_external,
            'external_db': is_external,
            'db_host': db_host,
            'db_port': int(db_port),
        }
        _write_priv(os.path.join(gd_dir, 'guarddog.conf'), json.dumps(gd_conf))
    except Exception as e:
        return False, f'guarddog.conf: {e}'

    # v0.9.29 CRIT-08 fix: provision a pinned SSH known_hosts file for the
    # watchdog scripts. Watchdog SSH calls use StrictHostKeyChecking=accept-new
    # against this file, so first contact pins the DB host's key and any later
    # MITM attempt fails. Empty file on first install — scripts append on first
    # successful connect. Operators rotating the DB host key can clear this
    # with `: > /opt/tak-guarddog/known_hosts`.
    try:
        # v10.0.5 non-root: provision known_hosts via the broker — /opt/tak-guarddog is
        # root-owned, so raw open()/chmod/chown by takwerx hit [Errno 13]. `touch` never
        # truncates, so accumulated host keys survive a re-sync.
        kh_path = os.path.join(gd_dir, 'known_hosts')
        subprocess.run(_sudo_wrap(['touch', kh_path]), capture_output=True)
        subprocess.run(_sudo_wrap(['chmod', '600', kh_path]), capture_output=True)
    except Exception as e:
        return False, f'known_hosts: {e}'

    cert_pass = _get_tak_cert_password(settings)
    external_db_flag = 'true' if is_external else ''
    # Skip scripts that require SSH to Server One when in external_db mode
    scripts_to_skip_for_external = {'tak-remotedb-auth-watch.sh'}
    for name in ('tak-remotedb-watch.sh', 'tak-remotedb-auth-watch.sh', 'tak-cotdb-watch.sh', 'tak-auto-vacuum.sh', 'tak-db-repack.sh', 'tak-retention-guard.sh'):
        if is_external and name in scripts_to_skip_for_external:
            continue
        src = os.path.join(scripts_dir, name)
        dest = os.path.join(gd_dir, name)
        if not os.path.isfile(src):
            continue
        try:
            content = open(src, 'r', encoding='utf-8').read()
            content = (content
                .replace('ALERT_EMAIL_PLACEHOLDER', alert_email)
                .replace('ALERT_SMS_PLACEHOLDER', '')
                .replace('CERT_PASS_PLACEHOLDER', cert_pass)
                .replace('CONSOLE_VERSION_PLACEHOLDER', VERSION)
                .replace('EXTERNAL_DB_PLACEHOLDER', external_db_flag))
            content = (content
                .replace('DB_HOST_PLACEHOLDER', db_host)
                .replace('DB_PORT_PLACEHOLDER', db_port)
                .replace('SSH_KEY_PLACEHOLDER', ssh_key_path)
                .replace('SSH_USER_PLACEHOLDER', s1_user))
            _write_priv(dest, content, perm=0o755)   # v10.0.5 non-root: /opt/tak-guarddog is root-owned
        except Exception as e:
            return False, f'{name}: {e}'
    try:
        subprocess.run(
            _sudo_wrap(['systemctl', 'try-restart', 'tak-health.service']),
            capture_output=True, text=True, timeout=20,
        )
    except Exception:
        pass
    mode_label = 'external managed DB' if is_external else 'two-server'
    return True, f'synced {mode_label} DB monitors to {db_host}:{db_port}'


def _remotedb_host_port_from_tak_settings():
    """Current Server One DB endpoint from saved tak_deployment (source of truth after migration)."""
    settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    if tak_cfg.get('mode') != 'two_server':
        return '', 0
    h = (tak_cfg.get('server_one', {}).get('host') or '').strip()
    try:
        p = int(tak_cfg.get('database', {}).get('port') or 5432)
    except (TypeError, ValueError):
        p = 5432
    return h, p


def _tak_db_topology(settings=None):
    """v10.1.1 (F7): ground truth for WHERE TAK's CoT database actually lives —
    read from CoreConfig.xml's `<connection url="jdbc:postgresql://HOST:PORT/cot">`
    (what TAK Server itself connects to), NOT from settings alone. NE-TAK is a
    split box whose CoreConfig points at a remote DB (172.93.50.224) but whose
    console settings never recorded two-server mode, so the GD monitors checked a
    nonexistent LOCAL postgres and showed permanent false-red — while a REAL
    remote-DB outage was invisible.

    Returns (mode, host, port):
      'container' — TAK runs its own DB container (host is the container name)
      'remote'    — CoreConfig url host is not loopback/localhost
      'local'     — loopback DB (native single-server), or CoreConfig unreadable
    """
    import re as _re_topo
    # Container TAK: its DB is the takserver-db container regardless of the url.
    if _tak_is_container():
        return 'container', TAK_DB_CONTAINER, 5432
    # Parse the live CoreConfig connection url (may be root-owned → broker read).
    url_host, url_port = '', 5432
    try:
        content = ''
        try:
            with open('/opt/tak/CoreConfig.xml') as _f:
                content = _f.read()
        except (PermissionError, FileNotFoundError):
            try:
                content = _read_priv('/opt/tak/CoreConfig.xml') or ''
            except Exception:
                content = ''
        m = _re_topo.search(r'jdbc:postgresql://([^:/]+)(?::(\d+))?/cot', content)
        if m:
            url_host = (m.group(1) or '').strip()
            if m.group(2):
                url_port = int(m.group(2))
    except Exception:
        pass
    if url_host and url_host not in ('127.0.0.1', 'localhost', '::1'):
        return 'remote', url_host, url_port
    # Fall back to saved two-server settings (post-migration source of truth).
    _sh, _sp = _remotedb_host_port_from_tak_settings()
    if _sh:
        return 'remote', _sh, (_sp or 5432)
    return 'local', '127.0.0.1', url_port


def _read_martiuser_password_from_local_coreconfig():
    """Return (password, source) for TAK's martiuser DB user from the LOCAL
    CoreConfig.xml — what TAK Server actually authenticates with. XML-unescaped
    (TAK's JDBC decodes &amp; etc.; we must match). ('', reason) if not found."""
    try:
        try:
            cc = _read_priv('/opt/tak/CoreConfig.xml')  # v10.0.5 non-root: read via broker
        except Exception:
            try:
                with open('/opt/tak/CoreConfig.xml') as _f:
                    cc = _f.read()
            except Exception:
                cc = ''
        for pat in (
            r'<connection[^>]*url\s*=\s*["\']jdbc:postgresql://[^"\']+/cot["\'][^>]*password\s*=\s*["\']([^"\']*)["\']',
            r'<connection[^>]*username\s*=\s*["\']martiuser["\'][^>]*password\s*=\s*["\']([^"\']*)["\']',
            r'<connection[^>]*password\s*=\s*["\']([^"\']*)["\']',
        ):
            m = re.search(pat, cc)
            if m and (m.group(1) or '').strip():
                return html.unescape(m.group(1).strip()), 'CoreConfig.xml'
    except Exception:
        pass
    return '', 'martiuser password not found in local CoreConfig.xml'


@app.route('/api/guarddog/deploy-health-agent', methods=['POST'])
@login_required
def guarddog_deploy_health_agent_api():
    """Deploy only the health agent to Server One (two-server). Does not run full Guard Dog deploy."""
    settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    if tak_cfg.get('mode') != 'two_server':
        return jsonify({'success': False, 'error': 'Not in two-server mode'}), 400
    s1_host = (tak_cfg.get('server_one', {}).get('host') or '').strip()
    if not s1_host:
        return jsonify({'success': False, 'error': 'Server One host not set in TAK deployment'}), 400
    s1_cfg = dict(tak_cfg.get('server_one', {}))
    key_path = _find_ssh_key_for_server_one(s1_cfg)
    if not key_path:
        return jsonify({'success': False, 'error': 'No SSH key found. In TAK Server run step 2 (Setup SSH key) and step 3 (Copy key to Server One), then try again.'}), 400
    s1_cfg['ssh_key_path'] = key_path
    # Persist so TAK Server page shows it and future deploy-health-agent calls don't need to search
    if tak_cfg.get('server_one', {}).get('ssh_key_path') != key_path:
        tak_cfg['server_one'] = dict(tak_cfg.get('server_one', {}))
        tak_cfg['server_one']['ssh_key_path'] = key_path
        settings['tak_deployment'] = tak_cfg
        save_settings(settings)
    ok, msg = _deploy_health_agent_to_server_one(s1_cfg)
    if not ok:
        return jsonify({'success': False, 'error': msg}), 400
    _sg_ok, _sg_msg = _sync_guarddog_remote_db_from_settings(load_settings())
    extra = f' {_sg_msg}' if _sg_ok and 'synced' in (_sg_msg or '') else ''
    return jsonify({
        'success': True,
        'message': f'Health agent deployed on {s1_host}. It may take a moment to show green.{extra}',
    })

@app.route('/api/guarddog/deploy/log')
@login_required
def guarddog_deploy_log_api():
    idx = request.args.get('index', 0, type=int)
    return jsonify({'entries': guarddog_deploy_log[idx:], 'total': len(guarddog_deploy_log),
        'running': guarddog_deploy_status['running'], 'complete': guarddog_deploy_status['complete'],
        'error': guarddog_deploy_status['error']})

def _parse_firewalld_rich(rule):
    """Parse a firewalld rich-rule string into (to, action, frm) mirroring UFW columns.
    e.g. 'rule family="ipv4" source address="10.0.0.5" port port="389" protocol="tcp" accept'
    → ('389/tcp', 'ALLOW IN', '10.0.0.5')."""
    import re
    src = ''
    m = re.search(r'source address="([^"]+)"', rule)
    if m:
        src = m.group(1)
    pm = re.search(r'port port="([^"]+)" protocol="([^"]+)"', rule)
    to = (f'{pm.group(1)}/{pm.group(2)}' if pm else (rule[:24] + '…'))
    action = 'DENY IN' if (' reject' in rule or ' drop' in rule) else 'ALLOW IN'
    return (to, action, src or 'Anywhere')


def _firewalld_status_local():
    """Return local firewall status NORMALIZED to the exact same shape + line format
    UFW produces, so the Firewall UI renders identically on every OS — firewalld is
    just the backend. Rows are '<to>  ALLOW IN/DENY IN  <Anywhere|source>'; a parallel
    rules_meta lets delete-by-number map a row back to the precise firewalld object."""
    try:
        rs = subprocess.run(_sudo_wrap(['firewall-cmd', '--state']),
                            capture_output=True, text=True, timeout=12)
        enabled = (rs.stdout or '').strip() == 'running'
        rp = subprocess.run(_sudo_wrap(['firewall-cmd', '--zone=public', '--list-ports']),
                            capture_output=True, text=True, timeout=12)
        svc = subprocess.run(_sudo_wrap(['firewall-cmd', '--zone=public', '--list-services']),
                             capture_output=True, text=True, timeout=12)
        rr = subprocess.run(_sudo_wrap(['firewall-cmd', '--zone=public', '--list-rich-rules']),
                            capture_output=True, text=True, timeout=12)
        ports = [p for p in (rp.stdout or '').split() if p.strip()]
        services = [s for s in (svc.stdout or '').split() if s.strip()]
        rich = [r.strip() for r in (rr.stdout or '').splitlines() if r.strip()]
        # Normalize to UFW's columns + a parallel meta list. firewalld has no native
        # rule numbers, so we synthesize stable [ N] positions; the default-drop public
        # zone denies unopened ports implicitly, and explicit reject rich-rules render
        # as DENY IN to mirror UFW's deny rows.
        rows, meta = [], []
        for p in ports:
            rows.append((p, 'ALLOW IN', 'Anywhere')); meta.append({'kind': 'port', 'value': p})
        for s in services:
            rows.append((s, 'ALLOW IN', 'Anywhere')); meta.append({'kind': 'service', 'value': s})
        for r in rich:
            to, action, frm = _parse_firewalld_rich(r)
            rows.append((to, action, frm)); meta.append({'kind': 'rich', 'value': r})

        def _fmt(idx, row, numbered):
            to, action, frm = row
            pfx = f'[{idx + 1:2d}] ' if numbered else ''
            return f'{pfx}{to:<26}{action:<12}{frm}'
        rules = [_fmt(i, row, False) for i, row in enumerate(rows)]
        numbered = [_fmt(i, row, True) for i, row in enumerate(rows)]
        raw = f"state: {'running' if enabled else 'not running'}\n" + "\n".join(numbered)
        return {'supported': True, 'enabled': enabled, 'rules': rules,
                'rules_numbered': numbered, 'rules_meta': meta,
                'raw': raw, 'raw_numbered': raw, 'backend': 'firewalld'}
    except Exception as e:
        return {'supported': False, 'error': str(e)[:160], 'enabled': False, 'rules': [], 'rules_numbered': []}


def _firewall_status_local():
    """Return local firewall status for UI (UFW or firewalld)."""
    be = _fw_backend()
    if be == 'firewalld':
        return _firewalld_status_local()
    has_ufw = subprocess.run('command -v ufw >/dev/null 2>&1', shell=True).returncode == 0
    if not has_ufw:
        return {'supported': False, 'error': 'No supported firewall (UFW/firewalld) installed on this host', 'enabled': False, 'rules': [], 'rules_numbered': []}
    try:
        r = subprocess.run(
            _sudo_wrap(['ufw', 'status']), capture_output=True, text=True, timeout=12
        )
        out = (r.stdout or '').strip()
        lines = [ln.rstrip() for ln in out.splitlines() if ln.strip()]
        enabled = any(ln.lower().startswith('status: active') for ln in lines)
        rules = []
        for ln in lines:
            if ln.lower().startswith('status:'):
                continue
            if ln.startswith('To') and 'Action' in ln and 'From' in ln:
                continue
            if set(ln.strip()) <= {'-'}:
                continue
            rules.append(ln)
        rn = subprocess.run(
            _sudo_wrap(['ufw', 'status', 'numbered']), capture_output=True, text=True, timeout=12
        )
        out_n = (rn.stdout or '').strip()
        lines_n = [ln.rstrip() for ln in out_n.splitlines() if ln.strip()]
        rules_numbered = []
        for ln in lines_n:
            if ln.lower().startswith('status:'):
                continue
            if ln.startswith('To') and 'Action' in ln and 'From' in ln:
                continue
            if set(ln.strip()) <= {'-'}:
                continue
            rules_numbered.append(ln)
        return {'supported': True, 'enabled': enabled, 'rules': rules, 'rules_numbered': rules_numbered, 'raw': out, 'raw_numbered': out_n}
    except Exception as e:
        return {'supported': False, 'error': str(e)[:160], 'enabled': False, 'rules': [], 'rules_numbered': []}


# ==========================================================================
# v10.0.4 — Service-Exposure panel (read-only network-posture audit)
# ==========================================================================
# Compares each installed service's DECLARED exposure tier (docs/PORT-EXPOSURE-
# POLICY.md) against the box's LIVE bind + firewall state, and surfaces any
# UNDECLARED public listener — the v0.9.11 CloudTAK PGMiner class, where a Tier-4
# port silently bound to 0.0.0.0 with weak creds got cryptojacked. PURE READER:
# it reports drift, it never changes a firewall rule (remediation stays with the
# existing _auto_harden_* overrides + the manual controls below on /firewall).
# Tiers: 1 Public · 3 Caddy-loopback · 4 Docker-internal · 5 Source-scoped.

# module = detect_modules() key (None = always shown). port=None → resolved live.
PORT_EXPOSURE_POLICY = [
    {'module': None,        'label': 'infra-TAK Console',   'port': None, 'tier': 1, 'why': 'Operator web UI (direct-IP backdoor)'},
    {'module': 'caddy',     'label': 'Caddy HTTP',          'port': 80,   'tier': 1, 'why': 'ACME + redirect to 443'},
    {'module': 'caddy',     'label': 'Caddy HTTPS',         'port': 443,  'tier': 1, 'why': 'TLS terminator + auth gate'},
    {'module': 'takserver', 'label': 'TAK Server (mTLS)',   'port': 8089, 'tier': 1, 'why': 'TAK client mutual-TLS'},
    {'module': 'takserver', 'label': 'TAK Admin WebGUI',    'port': 8443, 'tier': 1, 'why': 'Admin WebGUI (client-cert)'},
    {'module': 'takserver', 'label': 'TAK Admin (LE cert)', 'port': 8446, 'tier': 1, 'why': 'Admin WebGUI (LE cert)'},
    {'module': 'authentik', 'label': 'Authentik HTTP',      'port': 9000, 'tier': 3, 'why': 'Reached via Caddy 443'},
    {'module': 'authentik', 'label': 'Authentik HTTPS',     'port': 9443, 'tier': 3, 'why': 'Reached via Caddy 443'},
    {'module': 'takportal',  'label': 'TAK Portal',         'port': 3000, 'tier': 3, 'why': 'Reached via Caddy + forward_auth'},
    {'module': 'nodered',    'label': 'Node-RED',           'port': 1880, 'tier': 3, 'why': 'Reached via Caddy + forward_auth'},
    {'module': 'cloudtak',   'label': 'CloudTAK API',       'port': 5000, 'tier': 3, 'why': 'Reached via Caddy 443'},
    {'module': 'cloudtak',   'label': 'CloudTAK Tiles',     'port': 5002, 'tier': 3, 'why': 'Reached via Caddy 443'},
    {'module': 'mediamtx',   'label': 'MediaMTX RTSP',      'port': 8554, 'tier': 1, 'why': 'Streaming clients (auth+token)'},
    {'module': 'mediamtx',   'label': 'MediaMTX HLS',       'port': 8888, 'tier': 3, 'why': 'Reached via Caddy 443'},
    {'module': 'mediamtx',   'label': 'MediaMTX web-editor','port': 5080, 'tier': 3, 'why': 'Reached via Caddy 443'},
    {'module': 'remote_assist', 'label': 'CoTURN STUN/TURN', 'port': 3478, 'tier': 1, 'why': 'WebRTC NAT traversal — peers connect directly (public by design)'},
    {'module': 'guarddog',   'label': 'Guard Dog health agent', 'port': 8080, 'tier': 5, 'why': 'Reachable from console only (two-server)'},
]

# Every host port the stack may LEGITIMATELY open publicly — used only to decide
# whether a live 0.0.0.0 listener is "undeclared" (worth a look). Streaming uses
# many ephemeral/media ports; listing them here keeps the undeclared check from
# crying wolf. SSH + the console port are added live.
_KNOWN_PUBLIC_PORTS = {
    80, 443, 8089, 8443, 8446, 8444,      # console/caddy/TAK (8444 = TAK aux HTTPS connector)
    8554, 8322, 8890, 8892, 8000, 8001,   # MediaMTX streaming (8892 = aux listener)
    18554, 11935, 18890, 18888,           # CloudTAK media streaming
    8448,                                 # Caddy auxiliary vhost listener
    1935, 8555, 3100,                     # TAK Video Restreamer (RTMP 1935, RTSP 8554-8555, web 3100)
    25,                                   # Email Relay (localhost-bound normally)
    8080,                                 # Guard Dog health agent (two-server, source-scoped)
    3478,                                 # CoTURN STUN/TURN (public by design; UDP relay range 50000-50050 never shows in the TCP-only sweep)
}

_exposure_cache = {'ts': 0.0, 'data': None}
_EXPOSURE_TTL = 30  # seconds — cheap enough for the badge, fresh enough to trust


def _exposure_listen_map():
    """port -> {'scopes': set('public'|'loopback'|'scoped'), 'procs': set(names)}
    from `ss -tlnpH`. Captures native listeners AND docker-published ports (the
    docker-proxy/userland binding shows here), so one reader covers both."""
    m = {}
    try:
        r = subprocess.run(_sudo_wrap(['ss', '-tlnpH']), capture_output=True, text=True, timeout=8)
        out = r.stdout or ''
    except Exception:
        out = ''
    for ln in out.splitlines():
        cols = ln.split()
        if len(cols) < 4:
            continue
        local = cols[3]
        addr, sep, port = local.rpartition(':')
        if not sep or not port.isdigit():
            continue
        addr = addr.strip('[]')
        p = int(port)
        if addr in ('0.0.0.0', '::', '*', ''):
            scope = 'public'
        elif addr in ('127.0.0.1', '::1'):
            scope = 'loopback'
        else:
            scope = 'scoped'
        ent = m.setdefault(p, {'scopes': set(), 'procs': set(), 'pids': set()})
        ent['scopes'].add(scope)
        mp = re.search(r'"([^"]+)"', ln)
        if mp:
            ent['procs'].add(mp.group(1))
        for pid in re.findall(r'pid=(\d+)', ln):
            ent['pids'].add(int(pid))
    return m


def _pid_is_takserver(pid):
    """True if the process owning a listener is the TAK Server JVM — read from
    /proc/<pid>/cmdline. Lets the exposure audit attribute TAK Server's per-box
    connector ports (federation, extra HTTPS, operator-defined CoreConfig inputs)
    as expected rather than flagging them as undeclared. Native installs only;
    a containerized TAK publishes via docker-proxy (handled as a normal listener)."""
    try:
        with open(f'/proc/{pid}/cmdline', 'rb') as f:
            cmd = f.read().replace(b'\x00', b' ').decode('utf-8', 'ignore').lower()
        return ('takserver' in cmd) or ('/opt/tak' in cmd)
    except Exception:
        return False


def _exposure_bind_of(port, listen_map):
    ent = listen_map.get(port)
    if not ent:
        return 'none'
    sc = ent['scopes']
    if 'public' in sc:
        return 'public'
    if 'scoped' in sc:
        return 'scoped'
    if 'loopback' in sc:
        return 'loopback'
    return 'none'


def _exposure_fw_states(fwstatus):
    """port -> {'open':bool,'deny':bool,'scoped':[sources]} parsed from the
    normalized firewall rules (same line shape for ufw + firewalld)."""
    states = {}
    for ln in (fwstatus.get('rules') or []):
        parts = ln.split()
        if not parts:
            continue
        to = parts[0]
        mm = re.match(r'^(\d{1,5})(?:/(?:tcp|udp|any))?$', to)
        if not mm:
            continue
        port = int(mm.group(1))
        upper = ln.upper()
        st = states.setdefault(port, {'open': False, 'deny': False, 'scoped': []})
        if 'DENY' in upper:
            st['deny'] = True
        elif 'ALLOW' in upper:
            if 'ANYWHERE' in upper:
                st['open'] = True
            else:
                ipm = re.search(r'(\d{1,3}(?:\.\d{1,3}){3}(?:/\d+)?)', ln)
                if ipm:
                    st['scoped'].append(ipm.group(1))
                else:
                    st['open'] = True  # unknown source — assume open (conservative)
    return states


def _exposure_verdict(tier, bind, fw):
    """('ok'|'warn'|'alert'|'na', note). alert = dangerous drift (red)."""
    fw = fw or {}
    fw_open = fw.get('open')
    fw_deny = fw.get('deny')
    fw_scoped = fw.get('scoped')
    if bind == 'none':
        if tier in (4, 5):
            return ('ok', 'no host listener')
        return ('na', 'not listening')
    if tier == 1:
        if bind == 'public':
            return ('ok', 'public (by design)')
        return ('warn', f'{bind}-bound (expected public)')
    if tier == 3:
        if bind == 'loopback':
            return ('ok', 'loopback' + ('' if fw_deny else ' (no belt-and-braces deny)'))
        if bind == 'public':
            if fw_open:
                return ('alert', 'EXPOSED: public + firewall open (should be loopback)')
            return ('warn', 'public-bound but firewall not open')
        return ('warn', f'{bind}-bound (expected loopback)')
    if tier == 4:
        if bind == 'public':
            if fw_open:
                return ('alert', 'EXPOSED: internal port public + firewall open')
            return ('warn', 'public-bound but firewall not open (expected no host port)')
        if bind == 'loopback':
            return ('warn', 'loopback (expected no host port)')
        return ('ok', 'docker-internal')
    if tier == 5:
        if bind == 'public':
            if fw_open:
                return ('alert', 'source-scope defeated by an unconditional allow')
            if fw_scoped:
                return ('ok', 'source-scoped: ' + ', '.join(fw_scoped))
            return ('warn', 'public but no firewall scope found')
        return ('ok', f'{bind}-bound')
    return ('na', '')


def _exposure_report(force=False):
    """Full read-only exposure audit. Cached (_EXPOSURE_TTL) so the dashboard badge
    and repeated /firewall loads stay cheap. Never raises."""
    now = time.time()
    if not force and _exposure_cache['data'] and (now - _exposure_cache['ts']) < _EXPOSURE_TTL:
        return _exposure_cache['data']
    try:
        settings = load_settings()
    except Exception:
        settings = {}
    try:
        installed = {k for k, v in detect_modules().items() if v.get('installed')}
    except Exception:
        installed = set()
    try:
        console_port = int(settings.get('console_port') or 5001)
    except Exception:
        console_port = 5001
    listen_map = _exposure_listen_map()
    try:
        fwstatus = _firewall_status_local()
    except Exception:
        fwstatus = {'supported': False, 'rules': []}
    fw_states = _exposure_fw_states(fwstatus)

    rows = []
    red = yellow = 0
    try:
        coturn_port = int(settings.get('coturn_port') or 3478)
    except Exception:
        coturn_port = 3478
    for ent in PORT_EXPOSURE_POLICY:
        mod = ent['module']
        if mod is not None and mod not in installed:
            continue
        port = ent['port'] if ent['port'] is not None else console_port
        if mod == 'remote_assist' and ent['port'] == 3478:
            port = coturn_port  # CoTURN can run on an alternate port beside NetBird
        bind = _exposure_bind_of(port, listen_map)
        sev, note = _exposure_verdict(ent['tier'], bind, fw_states.get(port))
        if sev == 'alert':
            red += 1
        elif sev == 'warn':
            yellow += 1
        rows.append({'label': ent['label'], 'port': port, 'proto': 'tcp',
                     'tier': ent['tier'], 'bind': bind, 'severity': sev,
                     'note': note, 'why': ent['why']})

    # Undeclared public listeners — the catch-all that would have caught PGMiner.
    # Firewall-aware: a 0.0.0.0 listener that the host firewall actively BLOCKS is
    # not reachable (e.g. rpcbind :111, which start.sh never opens), so it's not an
    # exposure — only flag listeners that are firewall-open, or where there's no
    # enabled host firewall to stop them.
    known = set(_KNOWN_PUBLIC_PORTS) | {console_port, 22, coturn_port}
    fw_enabled = bool(fwstatus.get('enabled'))
    blocked = 0
    undeclared = []
    tak_connectors = []
    for p in sorted(listen_map):
        ent = listen_map[p]
        if 'public' not in ent['scopes']:
            continue
        if p in known:
            continue
        st = fw_states.get(p)
        reachable = (not fw_enabled) or bool(st and st.get('open'))
        if not reachable:
            blocked += 1
            continue
        # TAK Server opens a per-box-varying set of connector/input ports
        # (federation, extra HTTPS, operator CoreConfig inputs). Attribute those
        # to TAK Server (expected, Tier-1) instead of flagging them for review.
        if 'takserver' in installed and any(_pid_is_takserver(pid) for pid in ent.get('pids', ())):
            tak_connectors.append({'port': p, 'procs': sorted(ent['procs']) or ['java']})
            continue
        undeclared.append({'port': p, 'procs': sorted(ent['procs']) or ['?']})
    yellow += len(undeclared)

    if red:
        status = 'issue'
    elif yellow:
        status = 'warn'
    else:
        status = 'ok'
    report = {
        'rows': rows,
        'undeclared': undeclared,
        'tak_connectors': tak_connectors,
        'firewall_blocked': blocked,
        'firewall_supported': bool(fwstatus.get('supported')),
        'firewall_enabled': bool(fwstatus.get('enabled')),
        'backend': fwstatus.get('backend') or ('ufw' if fwstatus.get('supported') else None),
        'summary': {'status': status, 'issue_count': red, 'warn_count': yellow},
    }
    _exposure_cache['ts'] = now
    _exposure_cache['data'] = report
    return report


@app.route('/api/firewall/exposure')
@login_required
def firewall_exposure_api():
    return jsonify(_exposure_report())


@app.route('/api/firewall/exposure/summary')
@login_required
def firewall_exposure_summary_api():
    return jsonify(_exposure_report().get('summary', {'status': 'unknown', 'issue_count': 0, 'warn_count': 0}))


@app.route('/api/firewall/status')
@login_required
def firewall_status_api():
    return jsonify(_firewall_status_local())


@app.route('/api/firewall/open-port', methods=['POST'])
@login_required
def firewall_open_port_api():
    data = request.json if request.is_json else {}
    port = data.get('port')
    proto = (data.get('protocol') or 'tcp').strip().lower()
    if not isinstance(port, int) or port < 1 or port > 65535:
        return jsonify({'success': False, 'error': 'Invalid port (1-65535 required)'}), 400
    if proto not in ('tcp', 'udp'):
        return jsonify({'success': False, 'error': 'Protocol must be tcp or udp'}), 400
    st = _firewall_status_local()
    if not st.get('supported'):
        return jsonify({'success': False, 'error': st.get('error') or 'No supported firewall (UFW/firewalld) available'}), 400
    try:
        ok, msg = _fw_allow(port, proto)
        st2 = _firewall_status_local()
        if not ok:
            return jsonify({'success': False, 'error': (msg or 'firewall command failed')[:160], 'status': st2}), 500
        return jsonify({'success': True, 'message': f'Opened {port}/{proto}', 'status': st2})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:160]}), 500


@app.route('/api/firewall/close-port', methods=['POST'])
@login_required
def firewall_close_port_api():
    data = request.json if request.is_json else {}
    port = data.get('port')
    proto = (data.get('protocol') or 'tcp').strip().lower()
    if not isinstance(port, int) or port < 1 or port > 65535:
        return jsonify({'success': False, 'error': 'Invalid port (1-65535 required)'}), 400
    if proto not in ('tcp', 'udp'):
        return jsonify({'success': False, 'error': 'Protocol must be tcp or udp'}), 400
    st = _firewall_status_local()
    if not st.get('supported'):
        return jsonify({'success': False, 'error': st.get('error') or 'No supported firewall (UFW/firewalld) available'}), 400
    try:
        ok, msg = _fw_remove(port, proto)
        st2 = _firewall_status_local()
        if not ok:
            return jsonify({'success': False, 'error': (msg or 'firewall command failed')[:160], 'status': st2}), 500
        return jsonify({'success': True, 'message': f'Closed {port}/{proto}', 'status': st2})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:160]}), 500


@app.route('/api/firewall/restrict-source', methods=['POST'])
@login_required
def firewall_restrict_source_api():
    data = request.json if request.is_json else {}
    source = str(data.get('source') or '').strip()
    port = data.get('port')
    proto = (data.get('protocol') or 'tcp').strip().lower()
    action = (data.get('action') or 'allow').strip().lower()
    if not source:
        return jsonify({'success': False, 'error': 'Source IP/CIDR is required'}), 400
    try:
        ipaddress.ip_network(source, strict=False)
    except Exception:
        return jsonify({'success': False, 'error': 'Invalid source IP/CIDR'}), 400
    if not isinstance(port, int) or port < 1 or port > 65535:
        return jsonify({'success': False, 'error': 'Invalid port (1-65535 required)'}), 400
    if proto not in ('tcp', 'udp'):
        return jsonify({'success': False, 'error': 'Protocol must be tcp or udp'}), 400
    if action not in ('allow', 'deny'):
        return jsonify({'success': False, 'error': 'Action must be allow or deny'}), 400
    st = _firewall_status_local()
    if not st.get('supported'):
        return jsonify({'success': False, 'error': st.get('error') or 'No supported firewall (UFW/firewalld) available'}), 400
    try:
        be = _fw_backend()
        if be == 'firewalld':
            # ufw `allow/deny from X to any port Y` ↔ firewalld rich rule (accept/reject).
            fam = 'ipv6' if ':' in source else 'ipv4'
            verb = 'accept' if action == 'allow' else 'reject'
            rule = (f'rule family="{fam}" source address="{source}" '
                    f'port port="{port}" protocol="{proto}" {verb}')
            subprocess.run(_sudo_wrap(['firewall-cmd', '--zone=public', '--permanent',
                                       f'--add-rich-rule={rule}']),
                           capture_output=True, text=True, timeout=15)
            subprocess.run(_sudo_wrap(['firewall-cmd', '--reload']),
                           capture_output=True, text=True, timeout=15)
        else:
            # v10.0.5 non-root: literal `sudo ufw` fails (takwerx not in sudoers) and `|| true`
            # masked it as success — route through the broker shim.
            subprocess.run(_sudo_wrap(['ufw', action, 'from', source, 'to', 'any', 'port', str(port), 'proto', proto]),
                           capture_output=True, text=True, timeout=12)
        st2 = _firewall_status_local()
        return jsonify({'success': True, 'message': f'{action.upper()} from {source} to {port}/{proto}', 'status': st2})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:160]}), 500


@app.route('/api/firewall/delete-rule', methods=['POST'])
@login_required
def firewall_delete_rule_api():
    data = request.json if request.is_json else {}
    number = data.get('number')
    if not isinstance(number, int) or number < 1:
        return jsonify({'success': False, 'error': 'Rule number must be a positive integer'}), 400
    st = _firewall_status_local()
    if not st.get('supported'):
        return jsonify({'success': False, 'error': st.get('error') or 'No supported firewall (UFW/firewalld) available'}), 400
    try:
        be = _fw_backend()
        if be == 'firewalld':
            # firewalld has no rule numbering — map the displayed [ N] to the Nth entry
            # of rules_meta (same order as the rendered rows) and remove the precise
            # firewalld object (port / service / rich-rule).
            meta = st.get('rules_meta') or []
            if number > len(meta):
                return jsonify({'success': False, 'error': f'No rule #{number} (only {len(meta)} present)'}), 400
            m = meta[number - 1]
            if m['kind'] == 'rich':
                arg = f"--remove-rich-rule={m['value']}"
            elif m['kind'] == 'service':
                arg = f"--remove-service={m['value']}"
            else:
                arg = f"--remove-port={m['value']}"
            subprocess.run(_sudo_wrap(['firewall-cmd', '--zone=public', '--permanent', arg]),
                           capture_output=True, text=True, timeout=15)
            subprocess.run(_sudo_wrap(['firewall-cmd', '--reload']),
                           capture_output=True, text=True, timeout=15)
        else:
            # v10.0.5 non-root: literal `sudo ufw` failed (not in sudoers) — route via broker shim.
            subprocess.run(_sudo_wrap(['ufw', '--force', 'delete', str(number)]), capture_output=True, text=True, timeout=12)
        st2 = _firewall_status_local()
        return jsonify({'success': True, 'message': f'Deleted rule #{number}', 'status': st2})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:160]}), 500

@app.route('/fail2ban')
@login_required
def fail2ban_page():
    """Fail2ban: brute-force protection dashboard."""
    settings = load_settings()
    from flask import make_response
    r = make_response(render_template_string(FAIL2BAN_TEMPLATE,
        settings=settings, version=VERSION,
        installed=os.path.exists('/etc/fail2ban'),
        setup=settings.get('fail2ban_setup', {})))
    r.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    return r

def _f2b_is_available():
    """Return True if fail2ban is actually installed. v10.0.5: `which fail2ban-client` is
    POISONED by the broker shim — a fail2ban-client shim sits on the console PATH even when
    fail2ban isn't installed, so `which` returned 0 and the installer falsely refused with
    'fail2ban is already installed'. Check /etc/fail2ban (created by the package, never by
    the shim) — matches the detect_modules card's `installed` logic."""
    return os.path.exists('/etc/fail2ban')

def _f2b_parse_status(raw):
    """Parse fail2ban-client status authentik output into a dict."""
    result = {'currently_failed': 0, 'total_failed': 0, 'currently_banned': 0,
              'total_banned': 0, 'banned_ips': []}
    if not raw:
        return result
    for line in raw.splitlines():
        line = line.strip()
        if 'Currently failed:' in line:
            try: result['currently_failed'] = int(line.split(':')[1].strip())
            except Exception: pass
        elif 'Total failed:' in line:
            try: result['total_failed'] = int(line.split(':')[1].strip())
            except Exception: pass
        elif 'Currently banned:' in line:
            try: result['currently_banned'] = int(line.split(':')[1].strip())
            except Exception: pass
        elif 'Total banned:' in line:
            try: result['total_banned'] = int(line.split(':')[1].strip())
            except Exception: pass
        elif 'Banned IP list:' in line:
            ips_raw = line.split(':', 1)[1].strip()
            result['banned_ips'] = [ip.strip() for ip in ips_raw.split() if ip.strip()]
    return result

# Virtual / container / overlay interface prefixes whose subnets must NOT be auto-trusted:
# docker bridges (172.17-31/16), libvirt, k8s CNIs, VPN/mesh links. These are RFC1918 but
# are NOT the LAN/VNet a real upstream gateway lives on — auto-trusting them just bloats
# ignoreip with noise (a box can have ~10 docker /16s). Only the physical NIC's subnet is
# the one a proxy/gateway shares. (Found during v0.9.58 #6 field test: the test fleet's
# jails would have picked up 9 docker bridges each.)
_F2B_VIRTUAL_IFACE_PREFIXES = ('lo', 'docker', 'br-', 'br0', 'veth', 'virbr', 'vnet',
                               'flannel', 'cni', 'cali', 'kube', 'tailscale', 'nb-',
                               'wg', 'zt', 'tun', 'tap', 'cilium', 'ovs', 'weave')

def _f2b_local_subnets():
    """Derive the box's directly-attached *private* IPv4 subnets (CIDR) from the
    global-scope addresses on its PHYSICAL NICs. On a gateway/proxy/VNet-fronted deploy
    the upstream gateway usually lives on the box's own attached subnet, so trusting that
    subnet keeps the gateway from ever being banned — the CORAZ total-outage failure mode
    ([[fail2ban-bans-azure-gateway]]). Two guards: RFC1918 only (a direct-public box's
    attached subnet is public — never whitelist public neighbours), and virtual/container
    interfaces are skipped (docker bridges, CNIs, VPN links — noise, not a gateway LAN).
    Best-effort; returns [] on any failure (so the jail still gets localhost)."""
    subnets = []
    try:
        r = subprocess.run(['ip', '-o', '-4', 'addr', 'show', 'scope', 'global'],
                           capture_output=True, text=True, timeout=5)
        for line in r.stdout.splitlines():
            parts = line.split()
            if len(parts) < 4:
                continue
            ifname = parts[1].split('@')[0]  # strip veth peer suffix (eth0@if5)
            if ifname.startswith(_F2B_VIRTUAL_IFACE_PREFIXES):
                continue
            for i, tok in enumerate(parts):
                if tok == 'inet' and i + 1 < len(parts):
                    try:
                        net = ipaddress.ip_network(parts[i + 1], strict=False)
                        if net.is_private and str(net) not in subnets:
                            subnets.append(str(net))
                    except Exception:
                        pass
    except Exception:
        pass
    return subnets

def _f2b_fleet_ignore_cidrs():
    """Operator-configured fleet-wide trusted CIDRs (settings 'fail2ban_ignore_cidrs').
    Use this for an upstream gateway/proxy/LB that does NOT share the box's attached
    subnet (e.g. Azure App Gateway backends on a sibling /24). Survives a jail regen
    because every writer re-derives ignoreip from settings on each write."""
    try:
        raw = load_settings().get('fail2ban_ignore_cidrs', '') or ''
    except Exception:
        raw = ''
    return [c.strip() for c in raw.replace(',', ' ').split() if c.strip()]

def _f2b_trusted_ignoreip(extra=''):
    """Build the full ignoreip whitelist for ANY infra-TAK jail, fleet-uniform:
    localhost + the box's attached private subnet(s) + operator fleet CIDRs + the
    per-jail operator whitelist (extra). Identical code path on every box; dedups so
    it is idempotent even if `extra` still carries the localhost tokens."""
    parts, seen = [], set()
    candidates = ['127.0.0.1/8', '::1']
    candidates += _f2b_local_subnets()
    candidates += _f2b_fleet_ignore_cidrs()
    candidates += str(extra or '').replace(',', ' ').split()
    for c in candidates:
        c = c.strip()
        if c and c not in seen:
            seen.add(c)
            parts.append(c)
    return ' '.join(parts)

def _f2b_operator_extra(stored):
    """Strip the fleet-computed tokens (localhost + attached private subnets + fleet CIDRs)
    from a jail's stored ignoreip, leaving ONLY the per-jail operator entries. Lets a
    re-write re-derive the fleet part fresh each time, so a REMOVED fleet/gateway CIDR
    actually propagates out of every jail instead of staying baked into the stored line."""
    fleet = {'127.0.0.1/8', '::1'}
    fleet.update(_f2b_local_subnets())
    fleet.update(_f2b_fleet_ignore_cidrs())
    return ' '.join(t for t in str(stored or '').split() if t not in fleet)

def _f2b_read_jail_config():
    """Read current thresholds and ignoreip from the infratak-authentik jail config file."""
    jail_path = '/etc/fail2ban/jail.d/infratak-authentik.conf'
    cfg = {'maxretry': 5, 'findtime': 600, 'bantime': 3600, 'ignoreip': ''}
    if not os.path.exists(jail_path):
        return cfg
    try:
        with open(jail_path) as _f:
            for line in _f:
                line = line.strip()
                for key in ('maxretry', 'findtime', 'bantime'):
                    if line.startswith(key):
                        try: cfg[key] = int(line.split('=')[1].strip())
                        except Exception: pass
                if line.startswith('ignoreip'):
                    cfg['ignoreip'] = line.split('=', 1)[1].strip()
    except Exception:
        pass
    return cfg

def _f2b_banaction():
    """fail2ban ban action per host firewall family. Debian → 'ufw' (bans the IP on
    ALL traffic). RHEL has no ufw → 'iptables-allports', the all-ports equivalent
    (NOT iptables-multiport — that needs a port list and only blocks specific ports).
    Works on Rocky 9 via nft-backed iptables, with OR without firewalld active
    (firewalld is off on cloud boxes that rely on the security group). The
    infratak-guarddog notify action is appended on top by each jail. (Firewalld-
    native banaction — firewallcmd-* — is part of the broader firewall-parity work.)"""
    return 'iptables-allports' if _distro_family() == 'rhel' else 'ufw'


def _f2b_sshd_logpath():
    """sshd auth log path: Debian → /var/log/auth.log; RHEL → /var/log/secure."""
    return '/var/log/secure' if _distro_family() == 'rhel' else '/var/log/auth.log'


def _f2b_selfheal_rhel_jails(plog=None):
    """RHEL self-heal: repair fail2ban jail configs written by a pre-RHEL-port build.
    A jail with `action = ufw` (no ufw on RHEL) makes the WHOLE fail2ban daemon fail
    to start ('Unable to read action ufw'); and the sshd jail's
    `logpath = /var/log/auth.log` never matches (RHEL logs to /var/log/secure).
    Rewrite both in place across /etc/fail2ban/jail.d/*.conf, then reload (or restart
    if it's down) so the fix takes effect. No-op on Debian / when nothing is stale /
    when fail2ban isn't installed. Idempotent."""
    if _distro_family() != 'rhel':
        return False
    _log = plog or (lambda m: None)
    jaild = '/etc/fail2ban/jail.d'
    if not os.path.isdir(jaild):
        return False
    try:
        import glob as _glob
        banaction = _f2b_banaction()  # iptables-allports on RHEL
        changed = False
        for path in _glob.glob(os.path.join(jaild, '*.conf')):
            try:
                with open(path) as f:
                    txt = f.read()
            except Exception:
                continue
            new = re.sub(r'(?m)^(\s*action\s*=\s*)ufw\b', r'\g<1>' + banaction, txt)
            new = new.replace('/var/log/auth.log', '/var/log/secure')
            if new != txt:
                _write_priv(path, new)   # v10.0.5 non-root: /etc/fail2ban is root-owned
                changed = True
                _log(f"  fail2ban self-heal: patched {os.path.basename(path)} (ufw→{banaction}, auth.log→secure)")
        # The recidive jail reads fail2ban's OWN log (/var/log/fail2ban.log). On a box
        # where fail2ban never started cleanly (it was failing on the ufw action), that
        # file was never created → "Have not found any log file for recidive jail" →
        # fail2ban still won't start. Pre-create it (logtarget already points there) so
        # the jail loads on this start.
        if not os.path.exists('/var/log/fail2ban.log'):
            subprocess.run(_sudo_wrap(['touch', '/var/log/fail2ban.log']), capture_output=True, timeout=10)
            changed = True
            _log("  fail2ban self-heal: created /var/log/fail2ban.log (recidive jail reads it)")
        # Bring fail2ban up if jails are configured but it isn't running (clears the
        # failed state left by the pre-fix ufw config).
        act = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'fail2ban']),
                             capture_output=True, text=True).stdout.strip()
        if changed or act != 'active':
            if act == 'active':
                subprocess.run(_sudo_wrap(['fail2ban-client', 'reload']), capture_output=True, text=True, timeout=30)
            else:
                subprocess.run(_sudo_wrap(['systemctl', 'restart', 'fail2ban']), capture_output=True, text=True, timeout=30)
            _log("  ✓ fail2ban self-heal: jails repaired for RHEL and fail2ban (re)started")
        return changed
    except Exception as e:
        _log(f"  ⚠ fail2ban self-heal error (non-fatal): {str(e)[:120]}")
        return False


def _f2b_write_jail_config(maxretry, findtime, bantime, ignoreip=''):
    """Rewrite the infratak-authentik jail config with new thresholds and ignoreip whitelist."""
    jail_path = '/etc/fail2ban/jail.d/infratak-authentik.conf'
    _makedirs_priv('/etc/fail2ban/jail.d', exist_ok=True)
    guarddog_action = ""
    if os.path.exists('/etc/fail2ban/action.d/infratak-guarddog.conf'):
        guarddog_action = "\n         infratak-guarddog"
    ignoreip_line = f"ignoreip = {_f2b_trusted_ignoreip(ignoreip)}\n"
    jail_conf = (
        "[authentik]\n"
        "enabled  = true\n"
        "filter   = authentik\n"
        "logpath  = /var/log/authentik/auth.log\n"
        f"maxretry = {maxretry}\n"
        f"findtime = {findtime}\n"
        f"bantime  = {bantime}\n"
        f"{ignoreip_line}"
        f"action   = {_f2b_banaction()}{guarddog_action}\n"
    )
    _write_priv(jail_path, jail_conf)

