# fail2ban install status dict (tracks background install progress)
_f2b_install_status = {'running': False, 'log': [], 'done': False, 'ok': False}

@app.route('/api/fail2ban/install', methods=['POST'])
@login_required
def fail2ban_install_api():
    """Install fail2ban via the Marketplace. Runs in background; poll /api/fail2ban/install/status."""
    global _f2b_install_status
    if _f2b_install_status.get('running'):
        return jsonify({'ok': False, 'error': 'Install already in progress'}), 400
    if _f2b_is_available():
        return jsonify({'ok': False, 'error': 'fail2ban is already installed'}), 400

    _f2b_install_status = {'running': True, 'log': [], 'done': False, 'ok': False}

    def _plog(msg):
        _f2b_install_status['log'].append(msg)
        print(f"fail2ban install: {msg}", flush=True)

    def _run():
        global _f2b_install_status
        try:
            ok1 = _fail2ban_install_and_configure(_plog)
            if not ok1 and not _f2b_is_available():
                _f2b_install_status.update({'running': False, 'done': True, 'ok': False})
                return
            _fail2ban_add_guarddog_hook(_plog)
            _fail2ban_takserver_filter(_plog)
            _f2b_install_status.update({'running': False, 'done': True, 'ok': True})
        except Exception as e:
            _plog(f"ERROR: {e}")
            _f2b_install_status.update({'running': False, 'done': True, 'ok': False})

    import threading
    threading.Thread(target=_run, daemon=True).start()
    return jsonify({'ok': True, 'message': 'Install started'})

@app.route('/api/fail2ban/install/status')
@login_required
def fail2ban_install_status_api():
    """Poll install progress."""
    return jsonify({
        'running': _f2b_install_status.get('running', False),
        'done':    _f2b_install_status.get('done', False),
        'ok':      _f2b_install_status.get('ok', False),
        'log':     _f2b_install_status.get('log', []),
    })

@app.route('/api/fail2ban/uninstall', methods=['POST'])
@login_required
def fail2ban_uninstall_api():
    """Remove fail2ban, its configs, and clear settings.fail2ban_setup."""
    log = []
    def _plog(msg):
        log.append(msg)
        print(f"fail2ban uninstall: {msg}", flush=True)
    try:
        # Stop and disable services
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'fail2ban']), capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', 'fail2ban']), capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'authentik-log-forwarder']), capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', 'authentik-log-forwarder']), capture_output=True)
        _plog("Services stopped and disabled")
        # Remove package
        s = load_settings()
        pkg_mgr = s.get('pkg_mgr', 'apt')
        if pkg_mgr == 'apt':
            subprocess.run(_sudo_wrap(['apt-get', 'remove', '-y', 'fail2ban']), capture_output=True)
        else:
            subprocess.run(_sudo_wrap(['yum', 'remove', '-y', 'fail2ban']), capture_output=True)
        _plog("fail2ban package removed")
        # Remove config files
        for path in [
            '/etc/fail2ban/jail.d/infratak-authentik.conf',
            '/etc/fail2ban/jail.d/infratak-takserver.conf',
            '/etc/fail2ban/filter.d/authentik.conf',
            '/etc/fail2ban/filter.d/takserver.conf',
            '/etc/fail2ban/action.d/infratak-guarddog.conf',
            '/etc/fail2ban/action.d/infratak-guarddog-takserver.conf',
            '/etc/systemd/system/authentik-log-forwarder.service',
            '/usr/local/sbin/infratak-f2b-notify',
        ]:
            subprocess.run(_sudo_wrap(['rm', '-f', path]), capture_output=True)  # v10.0.5 non-root
        subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True)
        _plog("Config files and systemd unit removed")
        # Clear settings
        s2 = load_settings()
        s2.pop('fail2ban_setup', None)
        save_settings(s2)
        _plog("Settings cleared")
        return jsonify({'ok': True, 'log': log})
    except Exception as e:
        _plog(f"ERROR: {e}")
        return jsonify({'ok': False, 'error': str(e)[:200], 'log': log}), 500


def _parse_guarddog_log_date(line):
    """Return (date, display_str) for a restarts.log line, or (None, line) if unparseable."""
    line = line.strip()
    if not line:
        return None, line
    # ISO: 2026-03-03T15:00:00Z | ...
    if len(line) >= 20 and line[10] == 'T' and line[19] in 'Z| ':
        try:
            dt = datetime.strptime(line[:19], '%Y-%m-%dT%H:%M:%S')
            return dt.date(), line[:19].replace('T', ' ')
        except ValueError:
            pass
    # date(1): Tue Mar  3 15:00:00 UTC 2026: message
    idx = line.find(': ')
    if idx > 20:
        prefix = line[:idx].strip()
        try:
            dt = datetime.strptime(prefix, '%a %b %d %H:%M:%S %Z %Y')
            return dt.date(), prefix
        except ValueError:
            pass
    return None, ''

def _guarddog_health_check(service_id):
    """Quick health check for one service. Returns True if healthy, False otherwise. Used for UI and optional monitors."""
    try:
        if service_id == 'takserver':
            # v10.0.1: container-aware liveness (docker inspect vs systemctl).
            if not _takserver_running_local():
                return False
            # Also check 8089 is listening (host-published for the container).
            r2 = subprocess.run('ss -ltn "sport = :8089" 2>/dev/null', shell=True, capture_output=True, text=True, timeout=2)
            return 'LISTEN' in (r2.stdout or '')
        if service_id == 'authentik':
            settings = load_settings()
            ak_url = _get_authentik_api_url(settings)
            req = urllib.request.Request(ak_url + '/', method='GET')
            with urllib.request.urlopen(req, timeout=8) as resp:
                return resp.status in (200, 302, 301)
        if service_id == 'takportal':
            r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '--format', '{{.Status}}']), capture_output=True, text=True, timeout=5)
            return bool(r.stdout and 'Up' in r.stdout)
        if service_id == 'mediamtx':
            settings = load_settings()
            mtx_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
            if mtx_cfg.get('target_mode') == 'remote' and mtx_cfg.get('deployed') and (mtx_cfg.get('remote', {}).get('host') or '').strip():
                ok, out = _ssh_probe(mtx_cfg.get('remote', {}), 'systemctl is-active mediamtx 2>/dev/null', timeout=8)
                return bool(ok and out and out.strip() == 'active')
            r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'mediamtx']), capture_output=True, text=True, timeout=3)
            return r.returncode == 0
        if service_id == 'tak_video_restreamer':
            r = subprocess.run(
                _sudo_wrap(['docker', 'inspect', '--format', '{{.State.Running}}', 'tak-video-restreamer']),
                capture_output=True, text=True, timeout=5)
            return r.stdout.strip() == 'true'
        if service_id == 'nodered':
            settings = load_settings()
            nr_cfg = _get_module_deployment_config(settings, 'nodered_deployment')
            if nr_cfg.get('target_mode') == 'remote' and nr_cfg.get('deployed') and (nr_cfg.get('remote', {}).get('host') or '').strip():
                ok, out = _ssh_probe(nr_cfg.get('remote', {}),
                    "curl -s -o /dev/null -w '%{http_code}' --connect-timeout 4 http://127.0.0.1:1880/ 2>/dev/null || echo 000", timeout=10)
                return bool(ok and out and out.strip() in ('200', '301', '302'))
            req = urllib.request.Request('http://127.0.0.1:1880/', method='GET')
            with urllib.request.urlopen(req, timeout=5) as resp:
                return resp.status in (200, 302, 301)
        if service_id == 'cloudtak':
            settings = load_settings()
            cfg = _get_cloudtak_deployment_config(settings)
            if cfg.get('target_mode') == 'remote':
                rcfg = cfg.get('remote', {})
                if cfg.get('deployed') and (rcfg.get('host') or '').strip():
                    ok, out = _ssh_probe(rcfg, "docker ps --filter name=cloudtak-api --format '{{.Status}}' 2>/dev/null", timeout=10)
                    return bool(ok and out and 'Up' in out)
                return False
            r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=cloudtak-api', '--format', '{{.Status}}']), capture_output=True, text=True, timeout=5)
            return bool(r.stdout and 'Up' in r.stdout)
        if service_id == 'federation_hub':
            settings = load_settings()
            fh_cfg = _get_fedhub_deployment_config(settings)
            if not fh_cfg.get('deployed') or fh_cfg.get('target_mode') != 'remote':
                return None
            fh_remote = fh_cfg.get('remote', {})
            if not (fh_remote.get('host') or '').strip():
                return None
            ok, out = _ssh_probe(fh_remote, 'systemctl is-active federation-hub 2>/dev/null', timeout=8)
            return bool(ok and out and out.strip() == 'active')
        if service_id == 'remotedb':
            import socket
            db_host, db_port = _remotedb_host_port_from_tak_settings()
            if not db_host or not db_port:
                conf_path = '/opt/tak-guarddog/guarddog.conf'
                if not os.path.isfile(conf_path):
                    return None
                with open(conf_path) as f:
                    conf = json.load(f)
                db_host = conf.get('db_host', '')
                db_port = int(conf.get('db_port', 0))
            if not db_host or not db_port:
                return None
            s = socket.create_connection((db_host, db_port), timeout=5)
            s.close()
            return True
    except Exception:
        return False
    return False

# Monitor IDs per service for overall status (ok / caution / fail). Services with multiple monitors get caution when some are down.
def _guarddog_service_monitor_ids(settings):
    tak_cfg = _get_tak_deployment_config(settings)
    is_two_server = tak_cfg.get('mode') == 'two_server'
    takserver_ids = ['port8089', 'process', 'network']
    if not is_two_server:
        takserver_ids.extend(['postgresql', 'cotdb'])
    takserver_ids.extend(['oom', 'disk', 'cert', 'intca'])
    multi = {
        'takserver': takserver_ids,
        'remotedb': ['remotedb_tcp', 'remotedb_agent', 'remotedb_auth'],
        'federation_hub': ['fedhub_svc', 'fedhub_port', 'fedhub_mongo', 'fedhub_disk', 'fedhub_cert', 'fedhub_intca'],
        'authentik': ['authentik_http', 'authentik_channels'],
        'takportal': ['takportal_ctr'],
        'mediamtx': ['mediamtx_svc'],
        'tak_video_restreamer': ['tvr_http'],
        'nodered': ['nodered_http'],
        'cloudtak': ['cloudtak_ctr'],
        'updates': ['updates_check'],
        'relay': ['relay_tunnel'],
    }
    return multi


def _guarddog_monitored_service_ids(settings):
    """Return service IDs that Guard Dog should currently include in health rollups."""
    modules = detect_modules()
    tak_cfg = _get_tak_deployment_config(settings)
    is_two_server = tak_cfg.get('mode') == 'two_server'
    s1_host = (tak_cfg.get('server_one', {}).get('host') or '').strip() if is_two_server else ''

    ids = ['takserver']
    if is_two_server and s1_host:
        ids.append('remotedb')
    fh_cfg = _get_fedhub_deployment_config(settings)
    if fh_cfg.get('deployed') and fh_cfg.get('target_mode') == 'remote' and (fh_cfg.get('remote', {}).get('host') or '').strip():
        ids.append('federation_hub')
    if modules.get('authentik', {}).get('installed'):
        ids.append('authentik')
    if modules.get('takportal', {}).get('installed'):
        ids.append('takportal')
    if modules.get('mediamtx', {}).get('installed'):
        ids.append('mediamtx')
    if modules.get('tak_video_restreamer', {}).get('installed'):
        ids.append('tak_video_restreamer')
    if modules.get('nodered', {}).get('installed'):
        ids.append('nodered')
    if modules.get('cloudtak', {}).get('installed'):
        ids.append('cloudtak')
    if modules.get('guarddog', {}).get('installed'):
        ids.append('updates')
    if (settings.get('connectivity_anchor') or {}).get('anchor_ip'):
        ids.append('relay')
    return ids


def _guarddog_run_one_service(sid, monitor_ids):
    """Run checks for one service (multi-monitor or single). Returns (sid, 'ok'|'fail'|'caution'|None)."""
    if monitor_ids:
        vals = []
        for mid in monitor_ids:
            v = _monitor_health_check(mid)
            if v is not None:
                vals.append(v)
        if not vals:
            return (sid, None)
        if all(vals):
            return (sid, 'ok')
        if not any(vals):
            return (sid, 'fail')
        return (sid, 'caution')
    val = _guarddog_health_check(sid)
    if val is not None:
        return (sid, 'ok' if val else 'fail')
    return (sid, None)


@app.route('/api/guarddog/health')
@login_required
def guarddog_health_api():
    """Return health status per service. Always return cache when present so page shows colors in ~1s; background thread keeps cache warm."""
    from flask import make_response
    # Start background refresh on first request so cache is kept warm
    global _guarddog_background_started
    if not _guarddog_background_started:
        with _guarddog_background_lock:
            if not _guarddog_background_started:
                _guarddog_background_started = True
                threading.Thread(target=_guarddog_background_loop, daemon=True).start()
    # Return cache immediately when we have it (even if slightly stale)
    if _guarddog_page_cache['health'] is not None:
        r = make_response(jsonify(_guarddog_page_cache['health']))
        r.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
        return r
    # Cold load: populate cache once then return
    _guarddog_refresh_page_cache()
    r = make_response(jsonify(_guarddog_page_cache['health'] or {}))
    r.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    return r


def _guarddog_overall_from_result(result):
    """Compute single overall status from per-service result dict."""
    if not result:
        return 'ok'
    vals = list(result.values())
    if all(v == 'ok' for v in vals):
        return 'ok'
    if all(v == 'fail' for v in vals):
        return 'fail'
    return 'caution'


# Cache overall health so we don't re-run all checks every 8s from the Console.
# The cache holds for 30s. On caution it holds for 10s so we re-check sooner.
_guarddog_overall_cache = {'overall': 'ok', 'ts': 0}

# Cache for Guard Dog page: service and monitor health so the monitors page shows status quickly (TTL 25s).
_guarddog_page_cache = {'health': None, 'health_ts': 0, 'monitor_key': None, 'monitor_result': None, 'monitor_ts': 0}
_GD_PAGE_CACHE_TTL = 25
_guarddog_background_started = False
_guarddog_background_lock = threading.Lock()


def _guarddog_refresh_page_cache():
    """Run health + monitor checks and update _guarddog_page_cache. Used by background thread and cold load."""
    from concurrent.futures import ThreadPoolExecutor, as_completed
    try:
        settings = load_settings()
        multi = _guarddog_service_monitor_ids(settings)
        service_ids = _guarddog_monitored_service_ids(settings)
        # Health
        result = {}
        with ThreadPoolExecutor(max_workers=min(16, len(service_ids) * 3)) as ex:
            futures = {ex.submit(_guarddog_run_one_service, sid, multi.get(sid)): sid for sid in service_ids}
            for fut in as_completed(futures):
                try:
                    sid, status = fut.result()
                    if status is not None:
                        result[sid] = status
                except Exception:
                    pass
        _guarddog_page_cache['health'] = result
        _guarddog_page_cache['health_ts'] = time.time()
        # All monitor ids used by services
        all_mids = []
        for sid in service_ids:
            all_mids.extend(multi.get(sid) or [])
        all_mids = list(dict.fromkeys(all_mids))
        if not all_mids:
            return
        mon_result = {}
        with ThreadPoolExecutor(max_workers=min(16, len(all_mids) or 1)) as ex:
            futures = {ex.submit(_monitor_health_check, mid): mid for mid in all_mids}
            for fut in as_completed(futures):
                mid = futures[fut]
                try:
                    val = fut.result()
                    if val is not None:
                        mon_result[mid] = val
                except Exception:
                    pass
        _guarddog_page_cache['monitor_key'] = tuple(sorted(all_mids))
        _guarddog_page_cache['monitor_result'] = mon_result
        _guarddog_page_cache['monitor_ts'] = time.time()
    except Exception:
        pass


def _guarddog_background_loop():
    """Daemon thread: refresh Guard Dog page cache every 25s so page load is instant."""
    time.sleep(2)  # Let first request do cold load, then we keep cache warm
    while True:
        _guarddog_refresh_page_cache()
        time.sleep(_GD_PAGE_CACHE_TTL)


def _compute_guarddog_overall():
    """Run all Guard Dog health checks and return overall status."""
    settings = load_settings()
    multi = _guarddog_service_monitor_ids(settings)
    result = {}
    for sid in _guarddog_monitored_service_ids(settings):
        monitor_ids = multi.get(sid)
        if monitor_ids:
            vals = []
            for mid in monitor_ids:
                v = _monitor_health_check(mid)
                if v is not None:
                    vals.append(v)
            if not vals:
                continue
            result[sid] = 'ok' if all(vals) else ('fail' if not any(vals) else 'caution')
        else:
            val = _guarddog_health_check(sid)
            if val is not None:
                result[sid] = 'ok' if val else 'fail'
    return _guarddog_overall_from_result(result)


@app.route('/api/guarddog/overall-health')
@login_required
def guarddog_overall_health_api():
    """Overall Guard Dog health for Console card. Cached to avoid re-running all checks on every request."""
    now = time.time()
    age = now - _guarddog_overall_cache['ts']
    cached = _guarddog_overall_cache['overall']
    ttl = 10 if cached == 'caution' else 30
    if age < ttl:
        from flask import make_response
        r = make_response(jsonify({'overall': cached}))
        r.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
        return r
    overall = _compute_guarddog_overall()
    _guarddog_overall_cache['overall'] = overall
    _guarddog_overall_cache['ts'] = now
    from flask import make_response
    r = make_response(jsonify({'overall': overall}))
    r.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    return r


def _monitor_health_check(monitor_id):
    """Quick health check for individual monitors. Returns True/False/None."""
    import socket
    try:
        if monitor_id == 'relay_tunnel':
            # Healthy = a fresh WireGuard handshake (<180s). Mirrors the Leg 7
            # watcher's threshold. None if no relay configured / interface absent.
            st = _conn_anchor_status()
            if not st.get('configured'):
                return None
            hs = st.get('handshake_secs')
            if hs is None:
                return False
            return hs <= 180
        if monitor_id == 'port8089':
            r = subprocess.run('ss -ltn "sport = :8089" 2>/dev/null', shell=True, capture_output=True, text=True, timeout=2)
            return 'LISTEN' in (r.stdout or '')
        if monitor_id == 'process':
            r = subprocess.run('pgrep -f "takserver" 2>/dev/null | head -1', shell=True, capture_output=True, text=True, timeout=3)
            return bool(r.stdout.strip())
        if monitor_id == 'network':
            # ICMP first — fast path where ping is allowed.
            for host in ('1.1.1.1', '8.8.8.8'):
                r = subprocess.run(['ping', '-c', '1', '-W', '2', host], capture_output=True, timeout=4)
                if r.returncode == 0:
                    return True
            # ICMP filtered (e.g. Azure NSG blocks outbound ping) — confirm real egress
            # via TCP before declaring the network down. Mirrors _detect_local_ip()'s
            # trust model: TCP/UDP egress is the truth, ICMP is not.
            for host, port in (('1.1.1.1', 443), ('8.8.8.8', 53)):
                try:
                    with socket.create_connection((host, port), timeout=2):
                        return True
                except OSError:
                    continue
            return False
        if monitor_id == 'postgresql':
            # v10.1.1 (F7): key off TAK's real DB topology (CoreConfig ground truth),
            # not a hardcoded local assumption. A split box whose CoreConfig points at
            # a remote DB was checking a nonexistent local postgres → permanent false-red.
            _db_mode, _db_host, _db_port = _tak_db_topology()
            if _db_mode == 'remote':
                # Remote DB: TCP-connect to the CoreConfig host:port (no SSH). A real
                # outage of the remote DB now turns this dot red instead of hiding it.
                try:
                    with socket.create_connection((_db_host, _db_port), timeout=2):
                        return True
                except OSError:
                    return False
            # v10.0.1: container TAK runs PostgreSQL in the takserver-db container,
            # not a host postgresql.service — check the container's running state
            # there (native is byte-identical: systemctl is-active postgresql).
            if _db_mode == 'container' or _tak_is_container():
                r = subprocess.run(_sudo_wrap(['docker', 'inspect', '-f', '{{.State.Running}}', TAK_DB_CONTAINER]),
                                   capture_output=True, text=True, timeout=5)
                return r.returncode == 0 and r.stdout.strip() == 'true'
            # native: Debian/Ubuntu uses the `postgresql` meta-service; RHEL/EL uses
            # `postgresql-15.service` (PGDG). Either being active means PG is up.
            for _pgsvc in ('postgresql', 'postgresql-15'):
                r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', _pgsvc]), capture_output=True, text=True, timeout=3)
                if r.returncode == 0 and r.stdout.strip() == 'active':
                    return True
            return False
        if monitor_id == 'cotdb':
            # v10.1.1 (F7): remote DB → psql over TCP with CoreConfig's martiuser creds;
            # fall back to TCP-reachable-only if auth fails (so the dot reflects "DB up"
            # even when the console can't read the size). Split boxes no longer false-red.
            _db_mode, _db_host, _db_port = _tak_db_topology()
            if _db_mode == 'remote':
                _pw, _ = _read_martiuser_password_from_local_coreconfig()
                if _pw:
                    _env = dict(os.environ, PGPASSWORD=_pw, PGCONNECT_TIMEOUT='4')
                    try:
                        r = subprocess.run(
                            ['psql', '-h', _db_host, '-p', str(_db_port), '-U', 'martiuser',
                             '-d', 'cot', '-tAc', "SELECT pg_database_size('cot')"],
                            capture_output=True, text=True, timeout=8, env=_env)
                        if r.returncode == 0 and r.stdout.strip().isdigit():
                            return True
                    except FileNotFoundError:
                        pass  # no psql client on this box — fall through to TCP reachability
                # Auth failed / no password / no psql client — degrade to TCP reachability.
                try:
                    with socket.create_connection((_db_host, _db_port), timeout=3):
                        return True
                except OSError:
                    return False
            # v10.0.1: container → docker exec -u postgres (peer auth); native →
            # sudo -u postgres psql. Both query the same cot database size.
            if _tak_is_container():
                r = subprocess.run(
                    _sudo_wrap(['docker', 'exec', '-u', 'postgres', TAK_DB_CONTAINER,
                     'psql', '-tAc', "SELECT pg_database_size('cot')"]),
                    capture_output=True, text=True, timeout=8)
                return r.returncode == 0 and r.stdout.strip().isdigit()
            r = _pg_exec(['psql', '-tAc', "SELECT pg_database_size('cot')"], timeout=5)
            return r.returncode == 0 and r.stdout.strip().isdigit()
        if monitor_id == 'oom':
            # Only count OOM entries logged after TAK's last start so a pre-restart OOM
            # doesn't keep the monitor permanently red after a successful recovery.
            log_path = '/opt/tak/logs/takserver-messaging.log'
            if not os.path.isfile(log_path):
                return None
            tr = subprocess.run(
                _sudo_wrap(['systemctl', 'show', 'takserver', '--property=ActiveEnterTimestamp', '--value']), capture_output=True, text=True, timeout=3)
            tak_ts = tr.stdout.strip()  # e.g. "Tue 2026-05-19 14:32:38 UTC"
            tak_prefix = ''
            try:
                parts = tak_ts.split()  # ['Tue', '2026-05-19', '14:32:38', 'UTC']
                if len(parts) >= 3:
                    tak_prefix = f'{parts[1]}-{parts[2]}'  # "2026-05-19-14:32:38"
            except Exception:
                pass
            if tak_prefix:
                # awk: track timestamped lines >= TAK start, count OOM in that window only
                r = subprocess.run(
                    f'awk -v s="{tak_prefix}" \'/^[0-9]{{4}}-[0-9]{{2}}-[0-9]{{2}}-/{{a=($0>=s)}} a&&/OutOfMemoryError/{{c++}} END{{print c+0}}\' "{log_path}" 2>/dev/null',
                    shell=True, capture_output=True, text=True, timeout=10)
            else:
                r = subprocess.run(
                    f'tail -n 10000 "{log_path}" | grep -c "OutOfMemoryError" 2>/dev/null',
                    shell=True, capture_output=True, text=True, timeout=5)
            return (r.stdout.strip() or '0') == '0'
        if monitor_id == 'disk':
            r = subprocess.run("df / --output=pcent 2>/dev/null | tail -1", shell=True, capture_output=True, text=True, timeout=3)
            pct = int(r.stdout.strip().rstrip('%'))
            return pct < 80
        if monitor_id == 'cert':
            cert_path = '/opt/tak/certs/files/admin.pem'
            if not os.path.isfile(cert_path):
                cert_path = '/opt/tak/certs/files/takserver.pem'
            if not os.path.isfile(cert_path):
                return None
            r = subprocess.run(f'openssl x509 -in {cert_path} -checkend 3456000 2>/dev/null', shell=True, capture_output=True, timeout=3)
            return r.returncode == 0
        if monitor_id == 'intca':
            for name in ('ca.pem', 'ca-do-not-delete.pem', 'intermediate-ca.pem'):
                p = f'/opt/tak/certs/files/{name}'
                if os.path.isfile(p):
                    r = subprocess.run(f'openssl x509 -in {p} -checkend 7776000 2>/dev/null', shell=True, capture_output=True, timeout=3)
                    if r.returncode != 0:
                        return False
            return True
        if monitor_id == 'remotedb_tcp':
            db_host, db_port = _remotedb_host_port_from_tak_settings()
            if not db_host or not db_port:
                conf_path = '/opt/tak-guarddog/guarddog.conf'
                if not os.path.isfile(conf_path):
                    return None
                with open(conf_path) as f:
                    conf = json.load(f)
                db_host = conf.get('db_host', '')
                db_port = int(conf.get('db_port', 0))
            if not db_host or not db_port:
                return None
            try:
                s = socket.create_connection((db_host, db_port), timeout=5)
                s.close()
                return True
            except (OSError, socket.timeout):
                return False
        if monitor_id == 'remotedb_agent':
            db_host, _dbp = _remotedb_host_port_from_tak_settings()
            if not db_host:
                conf_path = '/opt/tak-guarddog/guarddog.conf'
                if not os.path.isfile(conf_path):
                    return None
                with open(conf_path) as f:
                    conf = json.load(f)
                db_host = conf.get('db_host', '')
            if not db_host:
                return None
            # 1) Direct HTTP — works when 8080 is reachable from the console (host-firewall-scoped boxes).
            try:
                req = urllib.request.Request(f'http://{db_host}:8080/health', method='GET')
                with urllib.request.urlopen(req, timeout=4) as resp:
                    if resp.status == 200:
                        return True
            except Exception:
                pass
            # 2) Fallback: poll /health over the SSH channel we ALREADY have to Server One. On cloud
            # boxes Server One often has NO host firewall, so 8080 is governed by the provider security
            # group (allows 22/5432 but not 8080) — the direct hit can't reach it even though the agent
            # is healthy and SSH is open (TCP+SSH green). This also means 8080 never needs to be
            # network-exposed (the endpoint exposes PG state), so the monitor works AND stays private.
            try:
                _s1 = _get_tak_deployment_config(load_settings()).get('server_one', {})
                if _s1.get('host'):
                    ok, out = _ssh_probe(_s1, 'curl -s -m4 -o /dev/null -w "%{http_code}" http://127.0.0.1:8080/health', timeout=12)
                    if ok and (out or '').strip().endswith('200'):
                        return True
            except Exception:
                pass
            return False
        if monitor_id == 'remotedb_auth':
            settings = load_settings()
            tak_cfg = _get_tak_deployment_config(settings)
            if tak_cfg.get('mode') != 'two_server':
                return None
            s1_cfg = tak_cfg.get('server_one', {})
            # Read password from LOCAL CoreConfig.xml (what TAK Server actually uses).
            # v0.9.46: CoreConfig stores it XML-escaped; the helper unescapes so a
            # regenerated password with an XML-special char doesn't false-fail.
            local_pw, _ = _read_martiuser_password_from_local_coreconfig()
            if not local_pw:
                return False
            ok, _ = _verify_server_one_db_password(s1_cfg, local_pw)
            return ok
        if monitor_id == 'authentik_http':
            settings = load_settings()
            ak_url = _get_authentik_api_url(settings)
            req = urllib.request.Request(ak_url + '/', method='GET')
            with urllib.request.urlopen(req, timeout=8) as resp:
                return resp.status in (200, 302, 301)
        if monitor_id == 'authentik_channels':
            # v10.1.1 (F5): django_channels_postgres_message size, size-based (never
            # count(*) — that can't complete on a ballooned table, the NE-TAK 605GB
            # blind spot). Green < 1GB, red >= 1GB (the in-process reaper (F1–F4)
            # should keep it KB-range; a red dot means the reaper is failing and the
            # disk is at risk). None when Authentik isn't installed / PG not up.
            if not os.path.exists(os.path.expanduser('~/authentik/docker-compose.yml')):
                return None
            r = subprocess.run(
                _sudo_wrap(['docker', 'exec', 'authentik-postgresql-1', 'psql', '-U', 'authentik',
                 '-d', 'authentik', '-tA', '-c',
                 "SELECT COALESCE(pg_total_relation_size(to_regclass("
                 "'django_channels_postgres_message')),-1)"]),
                capture_output=True, text=True, timeout=10)
            if r.returncode != 0:
                return None
            try:
                _sz = int((r.stdout or '-1').strip())
            except ValueError:
                return None
            if _sz < 0:
                return None  # table absent (older Authentik)
            return _sz < 1024 * 1024 * 1024  # red at >= 1GB
        if monitor_id == 'mediamtx_svc':
            settings = load_settings()
            mtx_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
            if mtx_cfg.get('target_mode') == 'remote' and mtx_cfg.get('deployed') and (mtx_cfg.get('remote', {}).get('host') or '').strip():
                ok, out = _ssh_probe(mtx_cfg.get('remote', {}), 'systemctl is-active mediamtx 2>/dev/null', timeout=8)
                return bool(ok and out and out.strip() == 'active')
            r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'mediamtx']), capture_output=True, text=True, timeout=3)
            return r.returncode == 0
        if monitor_id == 'nodered_http':
            settings = load_settings()
            nr_cfg = _get_module_deployment_config(settings, 'nodered_deployment')
            if nr_cfg.get('target_mode') == 'remote' and nr_cfg.get('deployed') and (nr_cfg.get('remote', {}).get('host') or '').strip():
                ok, out = _ssh_probe(nr_cfg.get('remote', {}),
                    "curl -s -o /dev/null -w '%{http_code}' --connect-timeout 4 http://127.0.0.1:1880/ 2>/dev/null || echo 000", timeout=10)
                return bool(ok and out and out.strip() in ('200', '301', '302'))
            req = urllib.request.Request('http://127.0.0.1:1880/', method='GET')
            with urllib.request.urlopen(req, timeout=5) as resp:
                return resp.status in (200, 302, 301)
        if monitor_id == 'tvr_http':
            # TVR Flask app has no /api/health — use /login which always returns 200
            try:
                req = urllib.request.Request('http://127.0.0.1:3100/login', method='GET')
                with urllib.request.urlopen(req, timeout=5) as resp:
                    return resp.status == 200
            except Exception:
                return False
        if monitor_id == 'takportal_ctr':
            r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '--format', '{{.Status}}']), capture_output=True, text=True, timeout=5)
            return bool(r.stdout and 'Up' in r.stdout)
        if monitor_id == 'cloudtak_ctr':
            settings = load_settings()
            cfg = _get_cloudtak_deployment_config(settings)
            if cfg.get('target_mode') == 'remote':
                rcfg = cfg.get('remote', {})
                if not cfg.get('deployed') or not (rcfg.get('host') or '').strip():
                    return False
                ok, out = _ssh_probe(rcfg, "docker ps --filter name=cloudtak-api --format '{{.Status}}' 2>/dev/null", timeout=10)
                return bool(ok and out and 'Up' in out)
            r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=cloudtak-api', '--format', '{{.Status}}']), capture_output=True, text=True, timeout=5)
            return bool(r.stdout and 'Up' in r.stdout)
        if monitor_id == 'updates_check':
            r = subprocess.run(_sudo_wrap(['systemctl', 'is-enabled', 'takupdatesguard.timer']), capture_output=True, text=True, timeout=3)
            return r.returncode == 0 and (r.stdout or '').strip() == 'enabled'
        # Federation Hub monitors (all remote via SSH)
        if monitor_id.startswith('fedhub_'):
            settings = load_settings()
            fh_cfg = _get_fedhub_deployment_config(settings)
            if not fh_cfg.get('deployed') or fh_cfg.get('target_mode') != 'remote':
                return None
            fh_remote = fh_cfg.get('remote', {})
            if not (fh_remote.get('host') or '').strip():
                return None
            if monitor_id == 'fedhub_svc':
                ok, out = _ssh_probe(fh_remote, 'systemctl is-active federation-hub 2>/dev/null', timeout=8)
                return bool(ok and out and out.strip() == 'active')
            if monitor_id == 'fedhub_port':
                ok, out = _ssh_probe(fh_remote, 'ss -ltn "sport = :9100" 2>/dev/null', timeout=8)
                return bool(ok and out and 'LISTEN' in out)
            if monitor_id == 'fedhub_mongo':
                ok, out = _ssh_probe(fh_remote, 'systemctl is-active mongod 2>/dev/null', timeout=8)
                return bool(ok and out and out.strip() == 'active')
            if monitor_id == 'fedhub_disk':
                ok, out = _ssh_probe(fh_remote, "df / --output=pcent 2>/dev/null | tail -1", timeout=8)
                if not ok or not out:
                    return None
                try:
                    pct = int(out.strip().rstrip('%'))
                    return pct < 80
                except ValueError:
                    return None
            if monitor_id == 'fedhub_cert':
                ok_h, hn = _ssh_probe(fh_remote, 'hostname 2>/dev/null', timeout=8)
                hshort = ((hn or '').strip().split('.') or [''])[0]
                if not hshort:
                    return None
                cert_path = f'/opt/tak/federation-hub/certs/files/{hshort}.pem'
                ok2, out2 = _ssh_probe(
                    fh_remote,
                    f'test -f {shlex.quote(cert_path)} && openssl x509 -in {shlex.quote(cert_path)} -checkend 3456000 >/dev/null 2>&1 && echo OK',
                    timeout=12,
                )
                return bool(ok2 and 'OK' in (out2 or ''))
            if monitor_id == 'fedhub_intca':
                rca = '/opt/tak/federation-hub/certs/files/root-ca.pem'
                ica = '/opt/tak/federation-hub/certs/files/ca.pem'
                ok2, out2 = _ssh_probe(
                    fh_remote,
                    f'test -f {rca} && test -f {ica} && '
                    f'openssl x509 -in {rca} -checkend 7776000 >/dev/null 2>&1 && '
                    f'openssl x509 -in {ica} -checkend 7776000 >/dev/null 2>&1 && echo OK',
                    timeout=15,
                )
                if not ok2:
                    return None
                return 'OK' in (out2 or '')
    except Exception:
        return False
    return None


@app.route('/api/guarddog/monitor-health')
@login_required
def guarddog_monitor_health_api():
    """Return health status per individual monitor. Return from cache when we have it (same as health API for fast load)."""
    monitor_ids = [m.strip() for m in request.args.get('ids', '').split(',') if m.strip()]
    cached = _guarddog_page_cache['monitor_result']
    # If cache has all requested ids, return subset immediately
    if cached and monitor_ids and all(mid in cached for mid in monitor_ids):
        subset = {mid: cached[mid] for mid in monitor_ids}
        return jsonify(subset)
    # Cold or partial: ensure full cache then return subset
    if not cached or not all(mid in cached for mid in monitor_ids):
        _guarddog_refresh_page_cache()
        cached = _guarddog_page_cache['monitor_result'] or {}
    subset = {mid: cached[mid] for mid in monitor_ids if mid in cached}
    return jsonify(subset)


@app.route('/api/guarddog/activity-log')
@login_required
def guarddog_activity_log():
    """Return Guard Dog restarts/alert log entries, optionally filtered by date. Newest first."""
    from_arg = request.args.get('from', '').strip()
    to_arg = request.args.get('to', '').strip()
    date_from = None
    date_to = None
    try:
        if from_arg:
            date_from = datetime.strptime(from_arg, '%Y-%m-%d').date()
        if to_arg:
            date_to = datetime.strptime(to_arg, '%Y-%m-%d').date()
    except ValueError:
        return jsonify({'error': 'Invalid date; use YYYY-MM-DD'}), 400
    log_path = '/var/log/takguard/restarts.log'
    entries = []
    try:
        if not os.path.exists(log_path):
            return jsonify({'entries': [], 'log_path': log_path})
        with open(log_path, 'r') as f:
            lines = f.readlines()
    except (OSError, PermissionError):
        return jsonify({'entries': [], 'error': 'Could not read log file', 'log_path': log_path})
    for raw in reversed(lines):
        raw = raw.rstrip('\n')
        if not raw:
            continue
        parsed_date, display_ts = _parse_guarddog_log_date(raw)
        if date_from is not None and parsed_date is not None and parsed_date < date_from:
            continue
        if date_to is not None and parsed_date is not None and parsed_date > date_to:
            continue
        entries.append({'raw': raw, 'date': parsed_date.isoformat() if parsed_date else None, 'time_display': display_ts})
    return jsonify({'entries': entries, 'log_path': log_path})

@app.route('/api/guarddog/diskio-history')
@login_required
def guarddog_diskio_history():
    """Return disk I/O benchmark history from CSV. Optional ?hours=N (default 24)."""
    try:
        hours = int(request.args.get('hours', 24))
        csv_path = '/var/lib/takguard/diskio_history.csv'
        # v10.0.5 non-root: 0600 root:root — read via the broker (a plain open()
        # EPERMs and 500s the whole panel). None -> treat as "no data yet".
        import io as _io
        hist_text = _read_guarddog_csv_text(csv_path)
        if hist_text is None:
            return jsonify({'entries': [], 'avg_1h': None, 'avg_24h': None})
        import csv as csv_mod
        cutoff = datetime.utcnow() - timedelta(hours=hours)
        entries = []
        reader = csv_mod.DictReader(_io.StringIO(hist_text))
        for row in reader:
            try:
                ts = datetime.strptime(row['timestamp'], '%Y-%m-%dT%H:%M:%SZ')
                if ts >= cutoff:
                    entries.append({'t': row['timestamp'], 'v': float(row['mb_per_sec'])})
            except (ValueError, KeyError):
                continue
        now = datetime.utcnow()
        vals_1h = [e['v'] for e in entries if (now - datetime.strptime(e['t'], '%Y-%m-%dT%H:%M:%SZ')).total_seconds() <= 3600]
        vals_all = [e['v'] for e in entries]
        avg_1h = round(sum(vals_1h) / len(vals_1h), 1) if vals_1h else None
        avg_all = round(sum(vals_all) / len(vals_all), 1) if vals_all else None
        min_val = round(min(vals_all), 1) if vals_all else None
        max_val = round(max(vals_all), 1) if vals_all else None
        # v0.9.54: latency-series parity (4 KB ms/commit). Additive — existing throughput
        # fields above are untouched. Charts ms/commit alongside MB/s; absent on boxes that
        # have not yet run the new probe (lat_* come back null, entries[] is [] → no break).
        lat_entries = []
        lat_path = '/var/lib/takguard/diskio_latency.csv'
        lat_text = _read_guarddog_csv_text(lat_path)
        if lat_text is not None:
            for row in csv_mod.DictReader(_io.StringIO(lat_text)):
                try:
                    ts = datetime.strptime(row['timestamp'], '%Y-%m-%dT%H:%M:%SZ')
                    if ts >= cutoff:
                        lat_entries.append({'t': row['timestamp'],
                                            'ms': float(row['ms_per_commit']),
                                            'kbps': float(row['kb_per_sec'])})
                except (ValueError, KeyError):
                    continue
        lat_1h = [e['ms'] for e in lat_entries if (now - datetime.strptime(e['t'], '%Y-%m-%dT%H:%M:%SZ')).total_seconds() <= 3600]
        lat_all = [e['ms'] for e in lat_entries]
        lat_avg_1h = round(sum(lat_1h) / len(lat_1h), 2) if lat_1h else None
        lat_avg_24h = round(sum(lat_all) / len(lat_all), 2) if lat_all else None
        return jsonify({'entries': entries, 'avg_1h': avg_1h, 'avg_24h': avg_all,
                        'min': min_val, 'max': max_val, 'samples': len(entries),
                        'latency': lat_entries, 'lat_avg_1h': lat_avg_1h, 'lat_avg_24h': lat_avg_24h,
                        'lat_ceiling_ms': _GUARDDOG_LAT_CEILING_MS})
    except Exception as e:
        import traceback
        return jsonify({'entries': [], 'error': f'{type(e).__name__}: {e}', 'traceback': traceback.format_exc()}), 500

# ── v0.9.47: network / fanout metrics (Guard Dog metrics collector → metrics.db) ──
_GD_METRICS_DB = '/var/lib/takguard/metrics.db'
# Whitelist: series key → (table, column). Keys/values are fixed here (never user input),
# so f-string interpolation into SQL is safe — the ?series= param is validated against this map.
_GD_SERIES = {
    'host_tx':          ('host_net',  'tx_bytes_s'),
    'host_rx':          ('host_net',  'rx_bytes_s'),
    'host_tx_pkts':     ('host_net',  'tx_pkts_s'),
    'host_rx_pkts':     ('host_net',  'rx_pkts_s'),
    'tcp_tx_queue':         ('tcp_queue', 'tx_queue_sum'),
    'tcp_tx_queue_max':     ('tcp_queue', 'tx_queue_max'),
    'tcp_tx_queue_active':     ('tcp_queue', 'tx_queue_active'),
    'tcp_tx_queue_active_max': ('tcp_queue', 'tx_queue_active_max'),
    'tcp_stalled_conns':    ('tcp_queue', 'stalled_conns'),
    'tcp_rx_queue':     ('tcp_queue', 'rx_queue_sum'),
    'tcp_conns':        ('tcp_queue', 'conn_count'),
    'clients':          ('marti',     'clients_connected'),
    'heap':             ('marti',     'heap_used_mb'),
    'heap_committed':   ('marti',     'heap_committed_mb'),
    'cpu':              ('host_sys',  'cpu_pct'),
    'mem_used':         ('host_sys',  'mem_used_mb'),
    'load1':            ('host_sys',  'load_1'),
}

def _gd_metrics_ro():
    """Open metrics.db read-only, or None if the collector hasn't produced it yet."""
    import sqlite3
    if not os.path.exists(_GD_METRICS_DB):
        return None
    try:
        return sqlite3.connect(f'file:{_GD_METRICS_DB}?mode=ro', uri=True, timeout=3)
    except Exception:
        return None

def _gd_bucketed(con, table, col, hours, where='', params=(), points=240):
    """Time-bucketed AVG of `col` over the last `hours`, ~`points` samples. Returns entry list."""
    now = int(time.time())
    cutoff = now - hours * 3600
    bucket = max(30, (hours * 3600) // points)
    q = (f"SELECT (ts/{bucket})*{bucket} AS b, AVG({col}) FROM {table} "
         f"WHERE ts >= ? {where} GROUP BY b ORDER BY b")
    rows = con.execute(q, (cutoff,) + tuple(params)).fetchall()
    return [{'t': datetime.utcfromtimestamp(b).strftime('%Y-%m-%dT%H:%M:%SZ'),
             'v': round(v, 2) if v is not None else 0} for b, v in rows]

def _gd_envelope(entries):
    """Mirror the diskio-history envelope: avg_1h / avg_24h / min / max / samples."""
    now = datetime.utcnow()
    vals = [e['v'] for e in entries]
    v1h = [e['v'] for e in entries
           if (now - datetime.strptime(e['t'], '%Y-%m-%dT%H:%M:%SZ')).total_seconds() <= 3600]
    return {
        'entries': entries,
        'avg_1h':  round(sum(v1h) / len(v1h), 2) if v1h else None,
        'avg_24h': round(sum(vals) / len(vals), 2) if vals else None,
        'min': round(min(vals), 2) if vals else None,
        'max': round(max(vals), 2) if vals else None,
        'samples': len(entries),
    }

@app.route('/api/guarddog/net-metrics')
@login_required
def guarddog_net_metrics():
    """One fanout series over the last ?hours=. ?series= ∈ _GD_SERIES keys (default host_tx)."""
    try:
        series = request.args.get('series', 'host_tx')
        hours = max(1, min(168, int(request.args.get('hours', 1))))
        if series not in _GD_SERIES:
            return jsonify({'entries': [], 'error': f'unknown series: {series}'}), 400
        con = _gd_metrics_ro()
        if con is None:
            return jsonify({'entries': [], 'deployed': False})
        try:
            table, col = _GD_SERIES[series]
            entries = _gd_bucketed(con, table, col, hours)
        finally:
            con.close()
        env = _gd_envelope(entries)
        env['series'] = series
        return jsonify(env)
    except Exception as e:
        import traceback
        return jsonify({'entries': [], 'error': f'{type(e).__name__}: {e}', 'traceback': traceback.format_exc()}), 500

@app.route('/api/guarddog/net-metrics/bridges')
@login_required
def guarddog_net_bridges():
    """Per-Docker-bridge (+lo) TX/RX bytes/s over the last ?hours=."""
    try:
        hours = max(1, min(168, int(request.args.get('hours', 1))))
        con = _gd_metrics_ro()
        if con is None:
            return jsonify({'series': [], 'deployed': False})
        try:
            cutoff = int(time.time()) - hours * 3600
            ifaces = con.execute(
                "SELECT iface, MAX(network_name) FROM bridge_net WHERE ts >= ? "
                "GROUP BY iface ORDER BY iface", (cutoff,)).fetchall()
            out = []
            for iface, name in ifaces:
                out.append({
                    'iface': iface, 'network_name': name,
                    'tx': _gd_bucketed(con, 'bridge_net', 'tx_bytes_s', hours,
                                       where='AND iface = ?', params=(iface,)),
                    'rx': _gd_bucketed(con, 'bridge_net', 'rx_bytes_s', hours,
                                       where='AND iface = ?', params=(iface,)),
                })
        finally:
            con.close()
        return jsonify({'series': out})
    except Exception as e:
        import traceback
        return jsonify({'series': [], 'error': f'{type(e).__name__}: {e}', 'traceback': traceback.format_exc()}), 500

@app.route('/api/guarddog/net-metrics/containers')
@login_required
def guarddog_net_containers():
    """Per-container net TX/RX bytes/s over the last ?hours=."""
    try:
        hours = max(1, min(168, int(request.args.get('hours', 1))))
        con = _gd_metrics_ro()
        if con is None:
            return jsonify({'series': [], 'deployed': False})
        try:
            cutoff = int(time.time()) - hours * 3600
            names = con.execute(
                "SELECT container FROM docker_stats WHERE ts >= ? "
                "GROUP BY container ORDER BY container", (cutoff,)).fetchall()
            out = []
            for (name,) in names:
                out.append({
                    'container': name,
                    'tx': _gd_bucketed(con, 'docker_stats', 'net_tx_bytes_s', hours,
                                       where='AND container = ?', params=(name,)),
                    'rx': _gd_bucketed(con, 'docker_stats', 'net_rx_bytes_s', hours,
                                       where='AND container = ?', params=(name,)),
                })
        finally:
            con.close()
        return jsonify({'series': out})
    except Exception as e:
        import traceback
        return jsonify({'series': [], 'error': f'{type(e).__name__}: {e}', 'traceback': traceback.format_exc()}), 500

@app.route('/api/guarddog/diskio-report')
@login_required
def guarddog_diskio_report():
    """Download disk I/O history as a CSV report with summary header."""
    try:
        return _guarddog_diskio_report_inner()
    except Exception as e:
        import traceback
        return f'Error: {type(e).__name__}: {e}\n\n{traceback.format_exc()}', 500, {'Content-Type': 'text/plain'}

def _guarddog_diskio_report_inner():
    hours = int(request.args.get('hours', 72))
    csv_path = '/var/lib/takguard/diskio_history.csv'
    import io as _io
    # v10.0.5 non-root: 0600 root:root — read via the broker, not a plain open().
    hist_text = _read_guarddog_csv_text(csv_path)
    if hist_text is None:
        return 'No disk I/O data available yet.\n', 404, {'Content-Type': 'text/plain'}
    import csv as csv_mod
    cutoff = datetime.utcnow() - timedelta(hours=hours)
    entries = []
    for row in csv_mod.DictReader(_io.StringIO(hist_text)):
        try:
            ts = datetime.strptime(row['timestamp'], '%Y-%m-%dT%H:%M:%SZ')
            if ts >= cutoff:
                entries.append((row['timestamp'], float(row['mb_per_sec'])))
        except (ValueError, KeyError):
            continue
    if not entries:
        return 'No data in the requested time range.\n', 404, {'Content-Type': 'text/plain'}
    vals = [e[1] for e in entries]
    now = datetime.utcnow()
    vals_1h = [e[1] for e in entries if (now - datetime.strptime(e[0], '%Y-%m-%dT%H:%M:%SZ')).total_seconds() <= 3600]
    avg_1h = round(sum(vals_1h) / len(vals_1h), 1) if vals_1h else 'N/A'
    avg_all = round(sum(vals) / len(vals), 1)
    hostname = subprocess.run(['hostname'], capture_output=True, text=True, timeout=5).stdout.strip()
    server_id = 'unknown'
    try:
        with open('/opt/tak-guarddog/server_identifier', 'r') as f:
            server_id = f.read().strip()
    except Exception:
        server_id = hostname
    import io
    output = io.StringIO()
    output.write(f'# Disk I/O Performance Report\n')
    output.write(f'# Server: {server_id}\n')
    output.write(f'# Generated: {now.strftime("%Y-%m-%dT%H:%M:%SZ")}\n')
    output.write(f'# Period: last {hours} hours ({len(entries)} readings)\n')
    output.write(f'# 1h average: {avg_1h} MB/s\n')
    output.write(f'# {hours}h average: {avg_all} MB/s\n')
    output.write(f'# Min: {round(min(vals), 1)} MB/s | Max: {round(max(vals), 1)} MB/s\n')
    # v0.9.54: small-block commit-latency summary — the regime that matches the provider's
    # 4 KB numbers and Postgres commits (a throttled disk reads 80 MB/s sequentially while
    # a 4 KB fsync takes 16 ms). Header-only; data rows below stay the throughput series.
    lat_path = '/var/lib/takguard/diskio_latency.csv'
    lat_text = _read_guarddog_csv_text(lat_path)
    if lat_text is not None:
        lat_vals = []
        for row in csv_mod.DictReader(_io.StringIO(lat_text)):
            try:
                ts = datetime.strptime(row['timestamp'], '%Y-%m-%dT%H:%M:%SZ')
                if ts >= cutoff:
                    lat_vals.append(float(row['ms_per_commit']))
            except (ValueError, KeyError):
                continue
        if lat_vals:
            output.write(f'# Commit latency (4 KB sync): {hours}h average {round(sum(lat_vals)/len(lat_vals), 2)} ms/commit '
                         f'| Min {round(min(lat_vals), 2)} | Max {round(max(lat_vals), 2)} ms (ceiling 10 ms)\n')
    output.write(f'#\n')
    output.write('timestamp,mb_per_sec\n')
    for ts, v in entries:
        output.write(f'{ts},{v}\n')
    csv_data = output.getvalue()
    fn = f'diskio-report-{server_id}-{now.strftime("%Y%m%d-%H%M")}.csv'
    return csv_data, 200, {
        'Content-Type': 'text/csv',
        'Content-Disposition': f'attachment; filename="{fn}"'
    }

def _guarddog_timer_list():
    """All Guard Dog timer unit names (core + optional service monitors)."""
    return ['tak8089guard.timer', 'takoomguard.timer', 'takdiskguard.timer', 'takdiskioguard.timer',
            'takdbguard.timer', 'takcotdbguard.timer', 'taknetguard.timer', 'takrelayguard.timer',
            'takwerxsetupapwatch.timer',
            'takprocessguard.timer', 'takcertguard.timer', 'takintcaguard.timer',
            'takauthentikguard.timer', 'takauthentiktasklogpurge.timer',
            'takdbrepack.timer', 'takretentionguard.timer',
            'takmediamtxguard.timer', 'taknoderedguard.timer', 'takcloudtakguard.timer',
            'taktakportalguard.timer', 'takfedhubguard.timer']

GUARDDOG_DISKIO_TIMER = 'takdiskioguard.timer'


def _guarddog_diskio_monitor_enabled(settings=None):
    """Whether the disk I/O benchmark timer should run (default True). Stored in settings.json."""
    if settings is None:
        settings = load_settings()
    v = settings.get('guarddog_diskio_monitor_enabled')
    if v is None:
        return True
    return bool(v)


def _guarddog_diskio_email_enabled(settings=None):
    """Whether disk I/O degradation sends email/SMS (default True). Benchmark still runs if disabled."""
    if settings is None:
        settings = load_settings()
    v = settings.get('guarddog_diskio_email_enabled')
    if v is None:
        return True
    return bool(v)


def _guarddog_sync_diskio_email_off_file(settings=None):
    """Create/remove diskio_email_off so tak-diskio-watch.sh skips notifications only."""
    if not os.path.exists('/opt/tak-guarddog'):
        return
    if settings is None:
        settings = load_settings()
    path = '/opt/tak-guarddog/diskio_email_off'
    if not _guarddog_diskio_email_enabled(settings):
        try:
            _write_priv(path, '')   # v10.0.5 non-root: /opt/tak-guarddog is root-owned
        except Exception:
            pass
    else:
        subprocess.run(_sudo_wrap(['rm', '-f', path]), capture_output=True)


def _guarddog_apply_diskio_timer(settings=None):
    """Enable or disable takdiskioguard.timer per settings. No-op if Guard Dog not installed or globally disabled."""
    if not os.path.exists('/opt/tak-guarddog'):
        return
    if not _guarddog_is_enabled():
        return
    if settings is None:
        settings = load_settings()
    if _guarddog_diskio_monitor_enabled(settings):
        subprocess.run(_sudo_wrap(['systemctl', 'enable', '--now', GUARDDOG_DISKIO_TIMER]), capture_output=True, text=True, timeout=15)
    else:
        subprocess.run(_sudo_wrap(['systemctl', 'stop', GUARDDOG_DISKIO_TIMER]), capture_output=True, timeout=8)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', GUARDDOG_DISKIO_TIMER]), capture_output=True, timeout=8)


def _guarddog_is_enabled():
    """True if Guard Dog timers are enabled (at least the core 8089 timer)."""
    r = subprocess.run(_sudo_wrap(['systemctl', 'is-enabled', 'tak8089guard.timer']), capture_output=True, text=True, timeout=5)
    return r.returncode == 0 and r.stdout.strip() == 'enabled'

@app.route('/api/guarddog/disable', methods=['POST'])
@login_required
def guarddog_disable():
    """Stop and disable all Guard Dog timers and health service. Scripts stay installed; user can enable again."""
    if not os.path.exists('/opt/tak-guarddog'):
        return jsonify({'error': 'Guard Dog is not installed'}), 400
    for t in _guarddog_timer_list():
        subprocess.run(_sudo_wrap(['systemctl', 'stop', t]), capture_output=True, timeout=5)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', t]), capture_output=True, timeout=5)
    subprocess.run(_sudo_wrap(['systemctl', 'stop', 'tak-health.service']), capture_output=True, timeout=5)
    subprocess.run(_sudo_wrap(['systemctl', 'disable', 'tak-health.service']), capture_output=True, timeout=5)
    return jsonify({'success': True, 'enabled': False})

@app.route('/api/guarddog/enable', methods=['POST'])
@login_required
def guarddog_enable():
    """Enable and start all Guard Dog timers and health service."""
    if not os.path.exists('/opt/tak-guarddog'):
        return jsonify({'error': 'Guard Dog is not installed'}), 400
    subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=10)
    for t in _guarddog_timer_list():
        subprocess.run(_sudo_wrap(['systemctl', 'enable', t]), capture_output=True, timeout=5)
        subprocess.run(_sudo_wrap(['systemctl', 'start', t]), capture_output=True, timeout=5)
    subprocess.run(_sudo_wrap(['systemctl', 'enable', 'tak-health.service']), capture_output=True, timeout=5)
    subprocess.run(_sudo_wrap(['systemctl', 'start', 'tak-health.service']), capture_output=True, timeout=5)
    _s = load_settings()
    _auto_harden_guarddog_8080(_s)   # v0.9.12 A6
    _guarddog_apply_diskio_timer(_s)
    _guarddog_sync_diskio_email_off_file(_s)
    return jsonify({'success': True, 'enabled': True})

@app.route('/api/guarddog/diskio-monitor', methods=['POST'])
@login_required
def guarddog_diskio_monitor_save():
    """Save disk I/O benchmark on/off and/or email/SMS for disk I/O alerts; sync systemd + diskio_email_off file."""
    if not os.path.exists('/opt/tak-guarddog'):
        return jsonify({'success': False, 'error': 'Guard Dog is not installed'}), 400
    data = request.json or {}
    if 'enabled' not in data and 'email_enabled' not in data:
        return jsonify({'success': False, 'error': 'Provide enabled and/or email_enabled (booleans)'}), 400
    settings = load_settings()
    if 'enabled' in data:
        if not isinstance(data['enabled'], bool):
            return jsonify({'success': False, 'error': 'enabled must be a boolean'}), 400
        settings['guarddog_diskio_monitor_enabled'] = data['enabled']
    if 'email_enabled' in data:
        if not isinstance(data['email_enabled'], bool):
            return jsonify({'success': False, 'error': 'email_enabled must be a boolean'}), 400
        settings['guarddog_diskio_email_enabled'] = data['email_enabled']
    save_settings(settings)
    _guarddog_apply_diskio_timer(settings)
    _guarddog_sync_diskio_email_off_file(settings)
    return jsonify({
        'success': True,
        'enabled': _guarddog_diskio_monitor_enabled(settings),
        'email_enabled': _guarddog_diskio_email_enabled(settings),
    })

@app.route('/api/guarddog/apply-docker-log-limits', methods=['POST'])
@login_required
def guarddog_apply_docker_log_limits():
    """Apply Docker log limits (50m × 3 per container) so Node-RED/Authentik etc. cannot fill the disk. No redeploy needed."""
    restarted, err = _ensure_docker_log_limits()
    if err:
        return jsonify({'success': False, 'error': err}), 500
    return jsonify({
        'success': True,
        'docker_restarted': restarted,
        'message': 'Docker log limits applied (50 MB × 3 files per container).' + (' Docker was restarted — start other containers from their pages if needed.' if restarted else ' Limits were already set.')
    })

@app.route('/api/guarddog/update', methods=['POST'])
@login_required
def guarddog_update():
    """Re-deploy Guard Dog scripts and timers from latest console version."""
    if not os.path.exists('/opt/tak-guarddog'):
        return jsonify({'success': False, 'error': 'Guard Dog not installed'}), 400
    try:
        _auto_update_guarddog()
        # Ensure update-check units exist and are enabled.
        # Older installs may have scripts but miss takupdatesguard.timer, which keeps Updates monitor red.
        service_path = '/etc/systemd/system/takupdatesguard.service'
        timer_path = '/etc/systemd/system/takupdatesguard.timer'
        _updates_home = os.path.expanduser('~')
        service_content = (
            '[Unit]\n'
            'Description=Guard Dog Updates Check (infra-TAK, Authentik, MediaMTX, CloudTAK)\n\n'
            '[Service]\n'
            'Type=oneshot\n'
            f'Environment=HOME={_updates_home}\n'
            'ExecStart=/opt/tak-guarddog/tak-updates-watch.sh\n'
        )
        timer_content = (
            '[Unit]\n'
            'Description=Check for updates every 6 hours\n\n'
            '[Timer]\n'
            'OnBootSec=30min\n'
            'OnUnitActiveSec=6h\n'
            'Unit=takupdatesguard.service\n\n'
            '[Install]\n'
            'WantedBy=timers.target\n'
        )
        _write_priv(service_path, service_content)
        _write_priv(timer_path, timer_content)
        # Auto-vacuum timer (daily 3am) — install if script exists but timer doesn't
        av_script = '/opt/tak-guarddog/tak-auto-vacuum.sh'
        av_svc_path = '/etc/systemd/system/takautovacuum.service'
        av_tmr_path = '/etc/systemd/system/takautovacuum.timer'
        if os.path.isfile(av_script) and not os.path.isfile(av_tmr_path):
            _settings = load_settings()
            _tak_cfg = _get_tak_deployment_config(_settings)
            _is_two = _tak_cfg.get('mode') == 'two_server'
            _after = 'network-online.target' if _is_two else 'postgresql.service postgresql-15.service'
            _write_priv(av_svc_path, f'[Unit]\nDescription=Guard Dog Smart Auto-VACUUM\nAfter={_after}\n\n[Service]\nType=oneshot\nExecStart={av_script}\n')
            _write_priv(av_tmr_path, '[Unit]\nDescription=Run smart auto-VACUUM daily at 3am\n\n[Timer]\nOnCalendar=*-*-* 03:00:00\nPersistent=true\nUnit=takautovacuum.service\n\n[Install]\nWantedBy=timers.target\n')
        # CoT DB size timer — install for two-server if missing
        cotdb_svc_path = '/etc/systemd/system/takcotdbguard.service'
        cotdb_tmr_path = '/etc/systemd/system/takcotdbguard.timer'
        if os.path.isfile('/opt/tak-guarddog/tak-cotdb-watch.sh') and not os.path.isfile(cotdb_tmr_path):
            _settings2 = load_settings()
            _tak_cfg2 = _get_tak_deployment_config(_settings2)
            _is_two2 = _tak_cfg2.get('mode') == 'two_server'
            _after2 = 'network-online.target' if _is_two2 else 'postgresql.service postgresql-15.service'
            _write_priv(cotdb_svc_path, f'[Unit]\nDescription=TAK CoT Database Size Monitor\nAfter={_after2}\n\n[Service]\nType=oneshot\nExecStart=/opt/tak-guarddog/tak-cotdb-watch.sh\n')
            _write_priv(cotdb_tmr_path, '[Unit]\nDescription=Run TAK CoT DB size monitor every 6 hours\n\n[Timer]\nOnBootSec=30min\nOnUnitActiveSec=6h\nUnit=takcotdbguard.service\n\n[Install]\nWantedBy=timers.target\n')
        # DB repack timer (weekly Sunday 4am) — install if script exists but timer doesn't
        rp_script = '/opt/tak-guarddog/tak-db-repack.sh'
        rp_svc_path = '/etc/systemd/system/takdbrepack.service'
        rp_tmr_path = '/etc/systemd/system/takdbrepack.timer'
        if os.path.isfile(rp_script) and not os.path.isfile(rp_tmr_path):
            _settings3 = load_settings()
            _tak_cfg3 = _get_tak_deployment_config(_settings3)
            _is_two3 = _tak_cfg3.get('mode') == 'two_server'
            _after3 = 'network-online.target' if _is_two3 else 'postgresql.service postgresql-15.service'
            _write_priv(rp_svc_path, f'[Unit]\nDescription=Guard Dog Online DB Repack (pg_repack)\nAfter={_after3}\n\n[Service]\nType=oneshot\nTimeoutStartSec=3600\nExecStart={rp_script}\n')
            _write_priv(rp_tmr_path, '[Unit]\nDescription=Run online DB repack weekly (Sunday 4am)\n\n[Timer]\nOnCalendar=Sun *-*-* 04:00:00\nPersistent=true\nUnit=takdbrepack.service\n\n[Install]\nWantedBy=timers.target\n')
        # Retention guard timer (every 15min) — install if script exists but timer doesn't
        rg_script = '/opt/tak-guarddog/tak-retention-guard.sh'
        rg_svc_path = '/etc/systemd/system/takretentionguard.service'
        rg_tmr_path = '/etc/systemd/system/takretentionguard.timer'
        if os.path.isfile(rg_script) and not os.path.isfile(rg_tmr_path):
            _settings4 = load_settings()
            _tak_cfg4 = _get_tak_deployment_config(_settings4)
            _is_two4 = _tak_cfg4.get('mode') == 'two_server'
            _after4 = 'network-online.target' if _is_two4 else 'postgresql.service postgresql-15.service'
            _write_priv(rg_svc_path, f'[Unit]\nDescription=Guard Dog CoT Retention Safety Net\nAfter={_after4}\n\n[Service]\nType=oneshot\nTimeoutStartSec=1800\nExecStart={rg_script}\n')
            _write_priv(rg_tmr_path, '[Unit]\nDescription=Run CoT retention guard every 15 minutes\n\n[Timer]\nOnBootSec=10min\nOnUnitActiveSec=15min\nUnit=takretentionguard.service\n\n[Install]\nWantedBy=timers.target\n')
        # Build-cache reclaim timer (daily 4:30am) — install if script exists but timer doesn't.
        # Cross-platform (docker + df only); no DB/SSH placeholders, no After= DB ordering.
        bc_script = '/opt/tak-guarddog/tak-buildcache-reclaim.sh'
        bc_svc_path = '/etc/systemd/system/takbuildcachereclaim.service'
        bc_tmr_path = '/etc/systemd/system/takbuildcachereclaim.timer'
        if os.path.isfile(bc_script) and not os.path.isfile(bc_tmr_path):
            _write_priv(bc_svc_path, f'[Unit]\nDescription=Guard Dog Docker build-cache reclaim (disk-capacity hygiene)\nAfter=docker.service\n\n[Service]\nType=oneshot\nExecStart={bc_script}\n')
            _write_priv(bc_tmr_path, '[Unit]\nDescription=Run Docker build-cache reclaim hourly (disk-capacity hygiene)\n\n[Timer]\nOnBootSec=45min\nOnUnitActiveSec=1h\nUnit=takbuildcachereclaim.service\n\n[Install]\nWantedBy=timers.target\n')
        # TAK Portal timer — install if script exists but timer doesn't
        tp_script = '/opt/tak-guarddog/tak-takportal-watch.sh'
        tp_svc_path = '/etc/systemd/system/taktakportalguard.service'
        tp_tmr_path = '/etc/systemd/system/taktakportalguard.timer'
        if os.path.isfile(tp_script) and not os.path.isfile(tp_tmr_path):
            _write_priv(tp_svc_path, f'[Unit]\nDescription=Guard Dog TAK Portal Monitor\n\n[Service]\nType=oneshot\nExecStart={tp_script}\n')
            _write_priv(tp_tmr_path, '[Unit]\nDescription=Run TAK Portal guard every 1 minute\n\n[Timer]\nOnBootSec=15min\nOnUnitActiveSec=1min\nUnit=taktakportalguard.service\n\n[Install]\nWantedBy=timers.target\n')
        # Authentik task log purge timer — install if Authentik is present but timer doesn't exist yet
        _ak_tl_svc_path = '/etc/systemd/system/takauthentiktasklogpurge.service'
        _ak_tl_tmr_path = '/etc/systemd/system/takauthentiktasklogpurge.timer'
        _ak_tl_script   = '/opt/tak-guarddog/tak-authentik-tasklog-purge.sh'
        _ak_compose_path = os.path.expanduser('~/authentik/docker-compose.yml')
        if os.path.exists(_ak_compose_path) and not os.path.isfile(_ak_tl_tmr_path):
            # v0.9.26: script body comes from the canonical _AUTHENTIK_TASKLOG_PURGE_SCRIPT
            # constant (see app.py around line 33985). Fixed the v0.9.5 VACUUM-in-transaction
            # bug + replaced the 30-day-only window with a 7d → 24h → 1h tier ladder.
            _write_priv(_ak_tl_script, _AUTHENTIK_TASKLOG_PURGE_SCRIPT, perm=0o755)
            _write_priv(_ak_tl_svc_path, '[Unit]\nDescription=Guard Dog Authentik Task Log Purge\n\n[Service]\nType=oneshot\nExecStart=/opt/tak-guarddog/tak-authentik-tasklog-purge.sh\n')
            _write_priv(_ak_tl_tmr_path, '[Unit]\nDescription=Purge Authentik task logs weekly (Sunday 03:00)\n\n[Timer]\nOnCalendar=Sun *-*-* 03:00:00\nPersistent=true\nUnit=takauthentiktasklogpurge.service\n\n[Install]\nWantedBy=timers.target\n')
        subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=10)
        new_timers = ['takupdatesguard.timer']
        if os.path.isfile(av_tmr_path):
            new_timers.append('takautovacuum.timer')
        if os.path.isfile(cotdb_tmr_path):
            new_timers.append('takcotdbguard.timer')
        if os.path.isfile(rp_tmr_path):
            new_timers.append('takdbrepack.timer')
        # v10.1.1 (F8): takretentionguard.timer was WRITTEN by run_guarddog_deploy but
        # never added to the enable list, so every full deploy left it loaded/disabled
        # and it never ran once (test6: cot_router bloated to 53GB / 2.9k live rows —
        # the "deletes don't return disk" pathology the online repack is meant to cure).
        if os.path.isfile(rg_tmr_path):
            new_timers.append('takretentionguard.timer')
        if os.path.isfile(bc_tmr_path):
            new_timers.append('takbuildcachereclaim.timer')
        if os.path.isfile(tp_tmr_path):
            new_timers.append('taktakportalguard.timer')
        if os.path.isfile(_ak_tl_tmr_path):
            new_timers.append('takauthentiktasklogpurge.timer')
        for t in new_timers:
            subprocess.run(_sudo_wrap(['systemctl', 'enable', '--now', t]), capture_output=True, text=True, timeout=10)
        # Stamp deployed version + settings so UI knows when re-deploy is needed
        try:
            _s = load_settings()
            _s['guarddog_deployed_version'] = VERSION
            _s['guarddog_deployed_email'] = (_s.get('guarddog_alert_email') or '').strip()
            _s['guarddog_deployed_nickname'] = (_s.get('guarddog_server_nickname') or '').strip()
            save_settings(_s)
        except Exception:
            pass
        # Refresh Guard Dog monitor cache so UI flips without waiting for background refresh.
        _guarddog_refresh_page_cache()
        _su = load_settings()
        _guarddog_apply_diskio_timer(_su)
        _guarddog_sync_diskio_email_off_file(_su)
        return jsonify({'success': True, 'message': 'Guard Dog scripts updated, timers installed, and reloaded.'})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:300]}), 500


@app.route('/api/guarddog/uninstall', methods=['POST'])
@login_required
def guarddog_uninstall():
    data = request.json or {}
    password = data.get('password', '')
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'error': 'Invalid admin password'}), 403
    timers = _guarddog_timer_list()
    for t in timers:
        subprocess.run(_sudo_wrap(['systemctl', 'stop', t]), capture_output=True, timeout=5)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', t]), capture_output=True, timeout=5)
    subprocess.run(_sudo_wrap(['systemctl', 'stop', 'tak-health.service']), capture_output=True, timeout=5)
    subprocess.run(_sudo_wrap(['systemctl', 'disable', 'tak-health.service']), capture_output=True, timeout=5)
    services_extra = ['tak8089guard.service', 'takoomguard.service', 'takdiskguard.service', 'takdiskioguard.service', 'takdbguard.service',
                      'takcotdbguard.service', 'taknetguard.service', 'takprocessguard.service', 'takcertguard.service',
                      'takintcaguard.service',
                      'takauthentikguard.service', 'takmediamtxguard.service', 'taknoderedguard.service', 'takcloudtakguard.service', 'taktakportalguard.service', 'tak-health.service']
    for name in timers + services_extra:
        # v10.0.5 non-root: /etc/systemd/system is root-owned — remove via broker.
        subprocess.run(_sudo_wrap(['rm', '-f', os.path.join('/etc/systemd/system', name)]), capture_output=True)
    if os.path.exists('/opt/tak-guarddog'):
        subprocess.run(_sudo_wrap(['rm', '-rf', '/opt/tak-guarddog']), capture_output=True, timeout=30)
    subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=10)
    return jsonify({'success': True})

def _guarddog_send_alert_email_via_relay(to_addr, subject, body):
    """Send email via Email Relay (localhost:25 → Postfix → Brevo). Used by test email and send-alert-email endpoint."""
    import smtplib
    from email.mime.text import MIMEText
    settings = load_settings()
    relay = settings.get('email_relay', {})
    from_addr = relay.get('from_addr', 'noreply@localhost')
    from_name = relay.get('from_name', 'Guard Dog')
    msg = MIMEText(body or '', 'plain', 'utf-8')
    msg['From'] = f'{from_name} <{from_addr}>'
    msg['To'] = to_addr
    msg['Subject'] = subject or 'Guard Dog Alert'
    with smtplib.SMTP('localhost', 25, timeout=15) as s:
        s.sendmail(from_addr, [to_addr], msg.as_string())


_GUARDDOG_SPIRAL_CORR_SENTINEL = '/var/lib/takguard/spiral_correlation_alert_sent'


def _guarddog_spiral_correlation_check(cl_waiting):
    """v0.9.54 §4c: correlate a disk commit-latency stall with real DB demand.

    When the 1h-avg 4 KB commit latency is over the fleet ceiling AND PgBouncer has
    clients waiting (cl_waiting > 0) in the same window, the disk is throttling
    Postgres commits while Authentik genuinely needs the DB — the unambiguous
    fingerprint of provider-disk-contention (the 2026-06-10 test12 incident). Emit a
    distinct, attributed alert BEFORE the outage. Detection/attribution ONLY —
    remediation stays with the existing watchdog/autotune.

    Best-effort and read-only: callers wrap in try/except so the safety net is never
    blocked. journald line fires every time the correlation holds; the email/SMS
    notification is debounced 6h via a sentinel and honors diskio_email_off (this is
    fundamentally a disk-attribution alert)."""
    if not cl_waiting or cl_waiting <= 0:
        return
    lat_1h = _guarddog_diskio_latency_1h_avg()
    if lat_1h is None or lat_1h <= _GUARDDOG_LAT_CEILING_MS:
        return
    print(f"[ak-pg-watchdog] SPIRAL-INCOMING: disk commit latency {lat_1h:.1f} ms/commit "
          f"(ceiling {_GUARDDOG_LAT_CEILING_MS} ms) with cl_waiting={cl_waiting} — provider "
          f"disk contention starving Postgres; Authentik/feed spiral likely imminent.", flush=True)
    # 6h debounce on the notification (the journald line above always fires).
    try:
        import time as _t
        if (os.path.exists(_GUARDDOG_SPIRAL_CORR_SENTINEL)
                and (_t.time() - os.path.getmtime(_GUARDDOG_SPIRAL_CORR_SENTINEL)) < 21600):
            return
    except Exception:
        pass
    if os.path.exists('/opt/tak-guarddog/diskio_email_off'):
        print("[ak-pg-watchdog] spiral-incoming notification suppressed (diskio_email_off set)", flush=True)
        return
    settings = load_settings()
    alert_email = (settings.get('guarddog_alert_email') or '').strip()
    try:
        with open('/opt/tak-guarddog/server_identifier') as f:
            server_id = f.read().strip()
    except Exception:
        server_id = socket.gethostname()
    subj = f"⚠ Spiral incoming on {server_id} — provider disk contention"
    body = (f"Guard Dog detected the disk-latency / DB-demand correlation that precedes "
            f"an Authentik spiral.\n\n"
            f"Server: {server_id}\n"
            f"Commit latency (1h avg): {lat_1h:.1f} ms/commit (ceiling {_GUARDDOG_LAT_CEILING_MS} ms)\n"
            f"PgBouncer cl_waiting: {cl_waiting}\n\n"
            f"A throttled disk is stalling small-block (4 KB) Postgres commits while "
            f"Authentik genuinely needs the database. This is hosting-provider disk "
            f"contention — NOT an infra-TAK fault. If it persists, request a node "
            f"migration from your VPS provider.\n\n"
            f"— Guard Dog")
    # Touch the sentinel BEFORE sending (matches the disk script) so a send failure
    # can't re-spam every tick inside the 6h window.
    try:
        _makedirs_priv('/var/lib/takguard', exist_ok=True)
        _write_priv(_GUARDDOG_SPIRAL_CORR_SENTINEL, '')   # v10.0.5 non-root: /var/lib/takguard root-owned
    except Exception:
        pass
    if alert_email:
        try:
            _guarddog_send_alert_email_via_relay(alert_email, subj, body)
            print(f"[ak-pg-watchdog] spiral-incoming email sent to {alert_email}", flush=True)
        except Exception as _e:
            print(f"[ak-pg-watchdog] spiral-incoming email failed: {_e}", flush=True)
    if os.path.exists('/opt/tak-guarddog/sms_send.sh'):
        try:
            _tmp = f'/tmp/gd-spiral-sms-{os.getpid()}.txt'
            with open(_tmp, 'w') as f:
                f.write(body)
            subprocess.run(['/opt/tak-guarddog/sms_send.sh', subj, _tmp], capture_output=True, timeout=20)
            os.remove(_tmp)
        except Exception:
            pass


