def guarddog_send_sms():
    """Called by Guard Dog scripts (localhost only) to send SMS via Twilio or Brevo."""
    if request.remote_addr not in ('127.0.0.1', '::1'):
        return jsonify({'error': 'Forbidden'}), 403
