@app.route('/cloudtak')
@login_required
def cloudtak_page():
    settings = load_settings()
    cloudtak_cfg = _get_cloudtak_deployment_config(settings)
    cloudtak_tak_suggest = _suggest_tak_core_host(settings)
    ct_bootstrap_user, ct_bootstrap_pass = _get_webadmin_defaults(settings)
    ct_cert_pass = _get_tak_cert_password(settings)
    cloudtak = detect_modules().get('cloudtak', {})
    container_info = {}
    if cloudtak.get('running'):
        containers = []
        if cloudtak_cfg.get('target_mode') == 'remote':
            rcfg = cloudtak_cfg.get('remote', {})
            ok, out = _ssh_probe(rcfg, "docker ps --filter 'name=cloudtak' --format '{{.Names}}|||{{.Status}}' 2>/dev/null", timeout=12)
            if ok:
                for line in (out or '').strip().split('\n'):
                    if line.strip():
                        parts = line.split('|||')
                        containers.append({'name': parts[0], 'status': parts[1] if len(parts) > 1 else ''})
        else:
            r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=cloudtak', '--format', '{{.Names}}|||{{.Status}}']), capture_output=True, text=True, timeout=5)
            for line in (r.stdout or '').strip().split('\n'):
                if line.strip():
                    parts = line.split('|||')
                    containers.append({'name': parts[0], 'status': parts[1] if len(parts) > 1 else ''})
        container_info['containers'] = containers
    ct_vinfo = _get_cloudtak_version_info() if cloudtak.get('installed') else {}
    ct_version = ct_vinfo.get('version', '')
    ct_update_available = ct_vinfo.get('update_available', False)
    ct_latest = ct_vinfo.get('latest', '')
    # v0.9.11 security advisory state — drives the in-UI banner.
    # compromise_detected: ~/CloudTAK/COMPROMISE-DETECTED.txt was written by
    #   _auto_harden_cloudtak() because malware persistence (.so + shared_preload_libraries)
    #   was found in the postgis data volume during the last Update Now.
    # legacy_install: the install pre-dates v0.9.11 (no .postgres-password file). Postgis
    #   still has the upstream 'docker' password baked into pg_authid — Remove + Reinstall
    #   is required to rotate to the strong random value, even though network is locked.
    sec_compromised = False
    sec_legacy_install = False
    try:
        _ct_dir = os.path.expanduser('~/CloudTAK')
        if cloudtak.get('installed') and cloudtak_cfg.get('target_mode') != 'remote':
            sec_compromised = os.path.exists(os.path.join(_ct_dir, 'COMPROMISE-DETECTED.txt'))
            sec_legacy_install = not os.path.exists(os.path.join(_ct_dir, '.postgres-password'))
    except Exception:
        pass
    # Only probe plugin dirs when CloudTAK is installed locally — skip for remote
    ct_plugins = []
    if cloudtak.get('installed') and cloudtak_cfg.get('target_mode') != 'remote':
        try:
            ct_plugins = _detect_cloudtak_plugins()
        except Exception:
            ct_plugins = []
    return render_template_string(CLOUDTAK_TEMPLATE,
        settings=settings, cloudtak=cloudtak,
        version=VERSION,
        cloudtak_version=ct_version,
        cloudtak_update_available=ct_update_available,
        cloudtak_latest=ct_latest,
        cloudtak_icon=CLOUDTAK_ICON,
        cloudtak_cfg=cloudtak_cfg,
        cloudtak_tak_suggest=cloudtak_tak_suggest,
        cloudtak_bootstrap_user=ct_bootstrap_user,
        cloudtak_bootstrap_pass=ct_bootstrap_pass,
        cloudtak_cert_password=ct_cert_pass,
        container_info=container_info,
        sec_compromised=sec_compromised,
        sec_legacy_install=sec_legacy_install,
        cloudtak_plugins=ct_plugins,
        deploying=cloudtak_deploy_status.get('running', False),
        deploy_done=cloudtak_deploy_status.get('complete', False),
        deploy_error=cloudtak_deploy_status.get('error', False))

