def _caddy_letsencrypt_days_left(settings):
    """Return days until the active Caddy cert expires (for primary FQDN), or None if unavailable.
    In custom mode (ssl_mode='custom') this reads the uploaded custom cert's expiry instead of
    an ACME-issued cert, so the page countdown + Guard Dog expiry alerting keep working."""
    from datetime import datetime
    # v0.9.51 — custom (bring-your-own) cert: expiry comes from the stored PEM, not ACME.
    if (settings.get('ssl_mode') or '') == 'custom':
        cert_path, _ = _custom_cert_paths()
        if not os.path.isfile(cert_path):
            return None
        try:
            r = subprocess.run(['openssl', 'x509', '-enddate', '-noout', '-in', cert_path],
                               capture_output=True, text=True, timeout=10)
            if r.returncode != 0:
                return None
            raw = (r.stdout or '').strip().split('=', 1)[-1].strip()
            for fmt in ('%b %d %H:%M:%S %Y %Z', '%b %d %H:%M:%S %Y GMT', '%b %d %H:%M:%S %Y UTC'):
                try:
                    expiry = datetime.strptime(raw, fmt)
                    break
                except ValueError:
                    continue
            else:
                return None
            return max(0, (expiry - datetime.utcnow()).days)
        except Exception:
            return None
    fqdn = (settings.get('fqdn') or '').strip().split(':')[0]
    if not fqdn:
        return None
    # Try s_client with servername (Caddy may serve cert for base domain or infratak.<fqdn>)
    for servername in (fqdn, f'infratak.{fqdn}'):
        if not re.match(r'^[a-zA-Z0-9][a-zA-Z0-9._-]*$', servername):
            continue
        try:
            cmd = (
                f'echo | openssl s_client -connect localhost:443 -servername {shlex.quote(servername)} 2>/dev/null '
                '| openssl x509 -noout -enddate 2>/dev/null'
            )
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=10)
            out = (r.stdout or '').strip()
            if not out or 'notAfter=' not in out:
                continue
            date_str = out.replace('notAfter=', '').strip()
            # Accept GMT or UTC
            for fmt in ('%b %d %H:%M:%S %Y %Z', '%b %d %H:%M:%S %Y GMT', '%b %d %H:%M:%S %Y UTC'):
                try:
                    expiry = datetime.strptime(date_str, fmt)
                    break
                except ValueError:
                    continue
            else:
                continue
            now = datetime.utcnow()
            if getattr(expiry, 'tzinfo', None):
                expiry = expiry.replace(tzinfo=None)
            delta = expiry - now
            return max(0, delta.days)
        except Exception:
            continue
    # Fallback: read cert from Caddy's storage (primary domain or infratak)
    cert_base = '/var/lib/caddy/.local/share/caddy/certificates/acme-v02.api.letsencrypt.org-directory'
    for name in (fqdn, f'infratak.{fqdn}'):
        crt = os.path.join(cert_base, name, f'{name}.crt')
        if not os.path.isfile(crt):
            continue
        try:
            r = subprocess.run(
                ['openssl', 'x509', '-enddate', '-noout', '-in', crt],
                capture_output=True, text=True, timeout=5
            )
            if r.returncode != 0:
                continue
            raw = (r.stdout or '').strip().split('=', 1)[-1]
            for fmt in ('%b %d %H:%M:%S %Y %Z', '%b %d %H:%M:%S %Y GMT', '%b %d %H:%M:%S %Y UTC'):
                try:
                    expiry = datetime.strptime(raw, fmt)
                    break
                except ValueError:
                    continue
            else:
                continue
            now = datetime.utcnow()
            return max(0, (expiry - now).days)
        except Exception:
            continue
    return None


def _caddy_cert_days_color(days_left):
    """Return color for Caddy Let's Encrypt cert display.
    Renewal script fires at <=35d, Caddy renews at <=30d. If we're below 30d
    the renewal already ran and failed — go straight to red, no yellow.
    """
    if days_left is None:
        return None
    if days_left < 30:
        return 'red'    # Renewal should have fired and rebuilt the JKS — it didn't
    return 'green'


def _fmt_caddy_cert_days(days_left):
    """Format days like dashboard card: e.g. '42d' or '1y 2mo 5d'. Returns (text, None) for no cert."""
    if days_left is None:
        return None, None
    y = days_left // 365
    r = days_left % 365
    m = r // 30
    dd = r % 30
    parts = []
    if y > 0:
        parts.append(f'{y}y')
    if m > 0:
        parts.append(f'{m}mo')
    if dd > 0 or not parts:
        parts.append(f'{dd}d')
    return ' '.join(parts), _caddy_cert_days_color(days_left)


def _caddy_configured_urls(settings, modules):
    """Build list of configured subdomain → service for the Caddy page. Only when FQDN is set."""
    fqdn = settings.get('fqdn', '').strip()
    if not fqdn:
        return []
    sd = _get_all_service_domains(settings)
    urls = []
    ak = modules.get('authentik', {})
    infratak_desc = 'Console (Authentik when enabled)' if ak.get('installed') else 'Console (after login)'
    urls.append({'name': 'infra-TAK', 'host': sd['infratak'], 'url': f'https://{sd["infratak"]}', 'desc': infratak_desc})
    tak = modules.get('takserver', {})
    if tak.get('installed'):
        urls.append({'name': 'TAK Server', 'host': sd['takserver'], 'url': f'https://{sd["takserver"]}', 'desc': 'WebGUI, Marti API'})
    if ak.get('installed'):
        urls.append({'name': 'Authentik', 'host': sd['authentik'], 'url': f'https://{sd["authentik"]}', 'desc': 'Identity provider'})
    portal = modules.get('takportal', {})
    if portal.get('installed'):
        urls.append({'name': 'TAK Portal', 'host': sd['takportal'], 'url': f'https://{sd["takportal"]}', 'desc': 'User & cert management'})
    nodered = modules.get('nodered', {})
    if nodered.get('installed'):
        urls.append({'name': 'Node-RED', 'host': sd['nodered'], 'url': f'https://{sd["nodered"]}', 'desc': 'Flow editor (Authentik when enabled)'})
    cloudtak = modules.get('cloudtak', {})
    if cloudtak.get('installed'):
        urls.append({'name': 'CloudTAK (map)', 'host': sd['cloudtak_map'], 'url': f'https://{sd["cloudtak_map"]}', 'desc': 'Browser TAK client'})
        urls.append({'name': 'CloudTAK (tiles)', 'host': sd['cloudtak_tiles'], 'url': f'https://{sd["cloudtak_tiles"]}', 'desc': 'Tile server'})
        urls.append({'name': 'CloudTAK (video)', 'host': sd['cloudtak_video'], 'url': f'https://{sd["cloudtak_video"]}', 'desc': 'Map video / HLS'})
    mtx = modules.get('mediamtx', {})
    if mtx.get('installed'):
        urls.append({'name': 'MediaMTX', 'host': sd['mediamtx'], 'url': f'https://{sd["mediamtx"]}', 'desc': 'Stream web console & HLS'})
    fedhub = modules.get('fedhub', {})
    if fedhub.get('installed'):
        urls.append({'name': 'Federation Hub', 'host': sd['fedhub'], 'url': f'https://{sd["fedhub"]}', 'desc': 'Hub web UI (TLS at Caddy; see TAK.gov for admin login)'})
    return urls

