def _suggest_tak_core_host(settings):
    """Best-effort TAK core host for CloudTAK bootstrap wizard."""
    # Prefer TAK Server domain (cert hostname) when available.
    try:
        tak_host = (_get_takserver_host(settings) or '').strip()
        if tak_host:
            return tak_host
    except Exception:
        pass
    try:
        tak_cfg = _get_tak_deployment_config(settings)
        s2 = tak_cfg.get('server_two', {}) if isinstance(tak_cfg.get('server_two'), dict) else {}
        host = (s2.get('host') or '').strip()
        if host and host not in ('127.0.0.1', 'localhost'):
            return host
    except Exception:
        pass
    return (settings.get('server_ip') or '').strip()


def _is_ipv4_host(value):
    try:
        parts = (value or '').strip().split('.')
        return len(parts) == 4 and all(p.isdigit() and 0 <= int(p) <= 255 for p in parts)
    except Exception:
        return False


def _cloudtak_api_base_urls(settings, cfg):
    """Candidate base URLs for CloudTAK API from infra-TAK host."""
    urls = []
    if cfg.get('target_mode') == 'remote':
        h = (cfg.get('remote', {}).get('host') or '').strip()
        if h:
            urls.append(f'http://{h}:5000')
    else:
        urls.append('http://127.0.0.1:5000')
    if settings.get('fqdn'):
        try:
            sd = _get_all_service_domains(settings)
            ct_host = (sd.get('cloudtak_map') or '').strip()
            if ct_host:
                urls.append(f'https://{ct_host}')
        except Exception:
            pass
    out = []
    for u in urls:
        if u not in out:
            out.append(u)
    return out


def _cloudtak_request_json(method, url, payload=None, timeout=25, headers=None):
    import urllib.error as _uerr
    data = None
    req_headers = {'Accept': 'application/json'}
    if isinstance(headers, dict):
        req_headers.update(headers)
    if payload is not None:
        data = json.dumps(payload).encode('utf-8')
        req_headers['Content-Type'] = 'application/json'
    req = urllib.request.Request(url, data=data, headers=req_headers, method=method.upper())
    ctx = ssl._create_unverified_context() if url.lower().startswith('https://') else None
    try:
        with urllib.request.urlopen(req, timeout=timeout, context=ctx) as resp:
            body = resp.read().decode('utf-8', errors='replace') if resp else ''
            return True, resp.getcode(), json.loads(body) if body else {}
    except _uerr.HTTPError as e:
        raw = e.read().decode('utf-8', errors='replace') if hasattr(e, 'read') else ''
        try:
            parsed = json.loads(raw) if raw else {'status': e.code, 'message': str(e)}
        except Exception:
            parsed = {'status': e.code, 'message': raw or str(e)}
        return False, e.code, parsed
    except Exception as e:
        return False, 0, {'status': 0, 'message': str(e)}


def _p12_bytes_to_pem(p12_bytes, password=''):
    """Convert P12/PFX bytes to PEM cert/key using openssl. Raises RuntimeError on failure."""
    tmp_dir = tempfile.mkdtemp(prefix='cloudtak-p12-')
    try:
        p12_path = os.path.join(tmp_dir, 'bundle.p12')
        with open(p12_path, 'wb') as f:
            f.write(p12_bytes)
        passin = f'pass:{password or ""}'

        def _run_openssl(args):
            r = subprocess.run(args, capture_output=True, text=True, timeout=25)
            ok = r.returncode == 0
            return (r.stdout or '').strip() if ok else '', (r.stderr or '').strip()

        cert_cmd = ['openssl', 'pkcs12', '-in', p12_path, '-clcerts', '-nokeys', '-passin', passin]
        key_cmd = ['openssl', 'pkcs12', '-in', p12_path, '-nocerts', '-nodes', '-passin', passin]
        cert_pem, cert_err = _run_openssl(cert_cmd)
        key_pem, key_err = _run_openssl(key_cmd)
        if not cert_pem or not key_pem:
            cert_pem, cert_err = _run_openssl(cert_cmd + ['-legacy'])
            key_pem, key_err = _run_openssl(key_cmd + ['-legacy'])
        if 'BEGIN CERTIFICATE' not in cert_pem or 'BEGIN' not in key_pem:
            err = cert_err or key_err or 'Could not parse P12 certificate/key'
            raise RuntimeError(err[:260])
        return cert_pem.strip() + '\n', key_pem.strip() + '\n'
    finally:
        shutil.rmtree(tmp_dir, ignore_errors=True)


def _ensure_cloudtak_container_connectivity(settings, rcfg, tak_host, marti_port):
    """Ensure the remote CloudTAK Docker container can reach TAK Server.

    Host-level preflight passes but containers may fail due to:
    1) Docker DNS can't resolve the FQDN — fixed by pushing updated override with extra_hosts
    2) iptables FORWARD chain drops outbound Docker traffic — fixed by adding ACCEPT rule
    """
    container_test_cmd = (
        f'docker exec $(docker ps -qf name=api 2>/dev/null | head -1) '
        f'node -e "'
        f"const s=require('net').connect({marti_port},'{tak_host}',()=>{{console.log('OK');s.end();process.exit(0)}});"
        f"s.on('error',e=>{{console.log('FAIL:'+e.code);process.exit(1)}});"
        f"s.setTimeout(4000,()=>{{console.log('TIMEOUT');s.destroy();process.exit(1)}});"
        f'"'
    )
    ok, out = _ssh_probe(rcfg, container_test_cmd, timeout=20)
    result = (out or '').strip().splitlines()[-1] if out else ''
    if ok and result == 'OK':
        return

    # Container can't reach TAK Server. Push updated override with extra_hosts and fix iptables.
    override_yml = _cloudtak_build_override_yml(settings)
    tmp_dir = tempfile.mkdtemp(prefix='cloudtak-fixconn-')
    try:
        ov_tmp = os.path.join(tmp_dir, 'docker-compose.override.yml')
        with open(ov_tmp, 'w') as f:
            f.write(override_yml)
        _scp_to_host(rcfg, ov_tmp, '~/CloudTAK/docker-compose.override.yml')
    finally:
        import shutil
        shutil.rmtree(tmp_dir, ignore_errors=True)

    # Ensure iptables FORWARD allows Docker outbound traffic
    _ssh_probe(rcfg, (
        'sudo iptables -C FORWARD -j ACCEPT 2>/dev/null || '
        'sudo iptables -I FORWARD 1 -j ACCEPT 2>/dev/null || true'
    ), timeout=10)

    # Restart containers to pick up new override
    _ssh_probe(rcfg, (
        'cd ~/CloudTAK && '
        '(docker compose up -d 2>/dev/null || docker-compose up -d 2>/dev/null || true)'
    ), timeout=60)

    # Brief wait for containers to be ready
    import time
    time.sleep(5)

    # Re-test connectivity from inside container
    ok2, out2 = _ssh_probe(rcfg, container_test_cmd, timeout=20)
    result2 = (out2 or '').strip().splitlines()[-1] if out2 else ''
    if not ok2 or result2 != 'OK':
        app.logger.warning(
            'CloudTAK container still cannot reach TAK Server after fix attempt: %s', result2
        )


def _cloudtak_bootstrap_preflight(cfg, tak_host, cot_port, marti_port, webtak_port):
    """Connectivity check to TAK ports from CloudTAK target host perspective."""
    import socket
    ports = [int(cot_port), int(marti_port), int(webtak_port)]
    if cfg.get('target_mode') == 'remote':
        rcfg = cfg.get('remote', {})
        cmd = (
            "python3 - <<'PY'\n"
            "import socket, json\n"
            f"host={json.dumps(tak_host)}\n"
            f"ports={json.dumps(ports)}\n"
            "out={}\n"
            "for p in ports:\n"
            "  s=socket.socket(); s.settimeout(3)\n"
            "  try:\n"
            "    s.connect((host,int(p))); out[str(p)]='ok'\n"
            "  except Exception as e:\n"
            "    out[str(p)]='fail:'+str(e)\n"
            "  finally:\n"
            "    try: s.close()\n"
            "    except Exception: pass\n"
            "print(json.dumps(out))\n"
            "PY"
        )
        ok, out = _ssh_probe(rcfg, cmd, timeout=25)
        if not ok:
            return False, {'error': f'Could not run preflight on remote CloudTAK host: {(out or "")[:220]}'}
        try:
            result = json.loads((out or '').strip().splitlines()[-1])
        except Exception:
            return False, {'error': f'Unexpected preflight output: {(out or "")[:220]}'}
    else:
        result = {}
        for p in ports:
            s = socket.socket()
            s.settimeout(3)
            try:
                s.connect((tak_host, int(p)))
                result[str(p)] = 'ok'
            except Exception as e:
                result[str(p)] = f'fail:{e}'
            finally:
                try:
                    s.close()
                except Exception:
                    pass
    required = [str(int(marti_port)), str(int(webtak_port))]
    healthy = all(str(result.get(p, '')).startswith('ok') for p in required)
    return healthy, result


_CERT_PASS_SAFE_RE = re.compile(r'^[a-zA-Z0-9!@#%^+=_.,:-]+$')

_TAK_CERT_PW_CACHE = {}  # (configured, admin.p12 mtime) -> resolved password; mtime change re-probes

def _get_tak_cert_password(settings):
    """The password the TAK cert actually opens with — ground truth over a possibly-stale
    settings field. Probes admin.p12 with the configured value then 'atakatak' (legacy RC2 +
    modern) and returns whichever decrypts it; falls back to the configured value or the fleet
    default when there's nothing to probe. Never raises; always returns a non-empty string.
    Every caller (cert open/gen, Portal TAK_API_P12_PASSPHRASE, metrics, FedHub) only ever gets
    a value that works, so they strictly improve. Result is memoised on the admin.p12 mtime so
    the 18 callers don't each spawn openssl (cache invalidates when the cert is regenerated).
    v0.9.56: fixes Portal sync when the configured passphrase diverged from the cert (CORAZ:
    settings 'Takserver#atak!', cert 'atakatak'). NOTE: cert-metadata.sh is deliberately NOT
    used — its CAPASS line is a shell default expression (CAPASS=${CAPASS:-atakatak}) that is
    unreliable read literally (returns the expression) OR sourced (resolved EMPTY on test6)."""
    configured = (settings.get('tak_cert_password') or '').strip()
    p12 = '/opt/tak/certs/files/admin.p12'
    try:
        mtime = os.path.getmtime(p12) if os.path.exists(p12) else None
    except Exception:
        mtime = None
    if mtime is None:
        return configured or 'atakatak'      # nothing to probe → today's behavior
    key = (configured, mtime)
    if key in _TAK_CERT_PW_CACHE:
        return _TAK_CERT_PW_CACHE[key]
    result = None
    seen = set()
    # v10.0.5 non-root: admin.p12 is 0600 tak:tak — the takwerx console can't openssl it
    # directly (it would silently fall back to the configured/default password, which is
    # WRONG on boxes where the cert pass diverged → Portal gets the wrong P12 passphrase →
    # Marti stats 503). Pull the ~4KB p12 via the broker (cat as root) into a console-owned
    # temp and probe that. (runuser -u tak only allows keytool/cert-scripts, not openssl.)
    _p12_probe, _tmp_p12 = p12, None
    try:
        _cat = subprocess.run(_sudo_wrap(['cat', p12]), capture_output=True, timeout=10)
        if _cat.returncode == 0 and _cat.stdout:
            import tempfile as _tf
            _fd, _tmp_p12 = _tf.mkstemp(suffix='.p12')
            with os.fdopen(_fd, 'wb') as _f:
                _f.write(_cat.stdout)
            _p12_probe = _tmp_p12
    except Exception:
        pass
    try:
        for cand in (configured, 'atakatak'):
            if not cand or cand in seen:
                continue
            seen.add(cand)
            for extra in (['-legacy'], []):
                try:
                    r = subprocess.run(['openssl', 'pkcs12', '-in', _p12_probe, '-passin', 'pass:' + cand,
                                        '-noout'] + extra, capture_output=True, timeout=10)
                    if r.returncode == 0:
                        result = cand
                        break
                except Exception:
                    continue
            if result:
                break
    finally:
        if _tmp_p12:
            try:
                os.remove(_tmp_p12)
            except Exception:
                pass
    if result is None:
        result = configured or 'atakatak'    # cert opens with neither candidate → don't guess
    _TAK_CERT_PW_CACHE[key] = result
    return result


def _get_fedhub_cert_password(settings):
    """Fed Hub keystore / webadmin.p12 password: optional override, else TAK console password."""
    return (
        (settings.get('fedhub_cert_password') or settings.get('tak_cert_password') or 'atakatak').strip()
        or 'atakatak'
    )


def _fedhub_cert_dn(settings):
    """Resolved DN fields for Federation Hub cert-metadata (fedhub_* overrides, else console cert_*)."""
    def pick(fed_key, global_key, default):
        v = (settings.get(fed_key) or settings.get(global_key) or default or '').strip()
        return v if v else default

    return {
        'country': pick('fedhub_cert_country', 'cert_country', 'US'),
        'state': pick('fedhub_cert_state', 'cert_state', 'State'),
        'city': pick('fedhub_cert_city', 'cert_city', 'City'),
        'org': pick('fedhub_cert_org', 'cert_org', 'TAK'),
        'ou': pick('fedhub_cert_ou', 'cert_ou', 'FederationHub'),
    }


def _merge_fedhub_cert_request_into_settings(settings, fc):
    """Apply fedhub_cert dict from JSON into settings. Returns error string or None."""
    if not isinstance(fc, dict):
        return None
    errs = []
    mapping = [
        ('cert_country', 'fedhub_cert_country', 'Country'),
        ('cert_state', 'fedhub_cert_state', 'State'),
        ('cert_city', 'fedhub_cert_city', 'City'),
        ('cert_org', 'fedhub_cert_org', 'Organization'),
        ('cert_ou', 'fedhub_cert_ou', 'Org Unit'),
    ]
    for json_key, set_key, label in mapping:
        if json_key not in fc:
            continue
        raw = (fc.get(json_key) or '').strip()
        if not raw:
            settings.pop(set_key, None)
            continue
        try:
            settings[set_key] = _sanitize_cert_field(raw, label).upper()
        except ValueError as e:
            errs.append(str(e))
    for json_key, set_key, default in [
        ('root_ca_name', 'fedhub_root_ca', 'FEDHUB-ROOT-CA'),
        ('intermediate_ca_name', 'fedhub_intermediate_ca', 'FEDHUB-INT-CA'),
    ]:
        if json_key not in fc:
            continue
        raw = (fc.get(json_key) or '').strip()
        if not raw:
            settings.pop(set_key, None)
            continue
        safe = re.sub(r'[^a-zA-Z0-9._-]', '-', raw).strip('-') or default
        settings[set_key] = safe
    if 'cert_password' in fc:
        pw = (fc.get('cert_password') or '').strip()
        if pw:
            if not _validate_cert_password(pw):
                errs.append(
                    'Certificate password contains unsupported characters for remote shell scripts '
                    '(use letters, digits, and limited punctuation only).'
                )
            else:
                settings['fedhub_cert_password'] = pw
        else:
            settings.pop('fedhub_cert_password', None)
    if errs:
        return '; '.join(errs)[:800]
    return None


def _validate_cert_password(pw):
    """Return True if password is safe for shell interpolation (no metacharacters like $, `, ;, &, |, etc.)."""
    return bool(pw) and bool(_CERT_PASS_SAFE_RE.match(pw))


def _patch_cert_metadata_password(cert_pass):
    """Patch cert-metadata.sh with the given password so makeRootCa/makeCert create JKS files with it.

    TAK Server's cert-metadata.sh uses CAPASS and PASS; older or custom scripts may use other names.
    """
    path = '/opt/tak/certs/cert-metadata.sh'
    if not os.path.exists(path):
        return
    if not cert_pass or cert_pass == 'atakatak':
        return
    try:
        # v10.0.5/v10.0.1 non-root + container: cert-metadata.sh is tak-owned (native, 0640)
        # or ROOT-owned in the bundle (container) — the takwerx console can't raw read/write it,
        # and there's no host `tak` user to chown to on a container box. Route through the broker.
        content = _read_priv(path)
        if not content:
            return
        lines = content.splitlines(keepends=True)
        changed = False
        for var in ('CAPASS', 'PASS', 'CERT_PASS', 'PASSWORD', 'KEYSTORE_PASS', 'CA_PASS', 'JKS_PASS'):
            for i, line in enumerate(lines):
                if line.strip().startswith(var + '='):
                    lines[i] = f'{var}="{cert_pass.replace(chr(34), chr(92)+chr(34))}"\n'
                    changed = True
                    break
        if changed:
            _write_priv(path, ''.join(lines))
    except Exception:
        pass


def _patch_coreconfig_passwords(cert_pass, log_fn=None):
    """Ensure every keystorePass / truststorePass in CoreConfig.xml matches cert_pass."""
    cc_path = '/opt/tak/CoreConfig.xml'
    if not cert_pass or not os.path.exists(cc_path):
        return
    try:
        import re
        # v10.0.5 non-root: CoreConfig is tak-owned 0640; read/write via the broker.
        content = _read_priv(cc_path)
        updated = content
        for attr in ('keystorePass', 'truststorePass'):
            for m in re.finditer(rf'{attr}="([^"]*)"', content):
                old_val = m.group(1)
                if old_val != cert_pass:
                    updated = updated.replace(f'{attr}="{old_val}"', f'{attr}="{cert_pass}"')
        if updated != content:
            _write_priv(cc_path, updated)
            if log_fn:
                log_fn("✓ CoreConfig.xml keystore/truststore passwords updated")
    except Exception:
        pass


def _patch_coreconfig_cert_enrollment(coreconfig_path, int_ca, cert_pass, config, log_fn=None):
    """v10.0.1 — version-tolerant CoreConfig patching for cert ENROLLMENT, via
    ElementTree (NOT sed). Used by the CONTAINER deploy: the takserver-docker
    bundle ships CoreConfig.example.xml formatted differently from the .deb
    (absolute cert paths, `<vbm/>` with no attrs), which silently broke the
    .deb path's string-seds when copied into the container. ElementTree matches
    elements by tag/attribute regardless of formatting, so it's correct on any
    TAK version/bundle. The native .deb path is untouched (its seds work on the
    .deb's CoreConfig format — field-validated on 5.7-RELEASE43).

    Three patches (all confirmed against TAK Server Config Guide v5.7):
      1. §21.1 — the main <security>/<tls> truststoreFile → certs/files/
         truststore-<int_ca>.jks. With a CUSTOM intermediate CA the default
         `truststore-root.jks` does NOT exist (makeCert names it after the CA),
         so leaving it dangling = "peer not verified" on 8089 (the red dot).
      2. §22/App C — add <certificateSigning CA="TAKServer"> with the makeCert
         signing keystore so 8446 can issue client certs (else getCertificateConfig
         500 → "registration failed").
      3. §9.6 — auth="x509" on the 8089 tls <input> so LDAP group lookup uses the
         cert CN. (Connection works without it; groups need it.)
    Returns (ok, changed_summary). Non-fatal on parse error (returns False)."""
    import xml.etree.ElementTree as ET
    import re as _re_ce
    org = config.get('cert_org', '') or ''
    ou = config.get('cert_ou', '') or ''
    try:
        issued_days = str(int(config.get('issued_cert_validity_days')
                              or config.get('intermediate_ca_validity_days') or 730))
    except (TypeError, ValueError):
        issued_days = '730'
    try:
        with open(coreconfig_path, 'r', encoding='utf-8') as f:
            raw = f.read()
        m = _re_ce.search(r'<[A-Za-z][\w-]*[^>]*?\bxmlns(?::[\w-]+)?="([^"]+)"', raw)
        ns_uri = m.group(1) if m else 'http://bbn.com/marti/xml/config'
        ET.register_namespace('', ns_uri)
        tree = ET.parse(coreconfig_path)
        root = tree.getroot()
    except Exception as e:
        if log_fn:
            log_fn(f"  ⚠ cert-enrollment patch: CoreConfig parse failed ({str(e)[:120]}) — patch manually")
        return False, f'parse failed: {e}'
    nsp = root.tag.split('}')[0] + '}' if '}' in root.tag else ''
    def q(tag):
        return f'{nsp}{tag}'
    def lt(e):
        return e.tag.split('}', 1)[1] if '}' in e.tag else e.tag
    changed = []

    # (1) main <tls> truststore (the non-fed one, under <security>)
    sec = root.find(q('security'))
    if sec is None:
        sec = root.find('security')
    if sec is not None:
        for tls in list(sec):
            if lt(tls) != 'tls':
                continue
            tf = tls.get('truststoreFile') or ''
            if 'fed' in tf.lower():   # skip the federation tls block
                continue
            new_tf = f'certs/files/truststore-{int_ca}.jks'
            if tf != new_tf:
                tls.set('truststoreFile', new_tf)
                changed.append('truststore')
            break

    # (2) <certificateSigning> — remove any existing (incl. template) and add clean
    existing_cs = root.find(q('certificateSigning'))
    if existing_cs is None:
        existing_cs = root.find('certificateSigning')
    if existing_cs is not None:
        root.remove(existing_cs)
    cs = ET.SubElement(root, q('certificateSigning'))
    cs.set('CA', 'TAKServer')
    cc = ET.SubElement(cs, q('certificateConfig'))
    ne = ET.SubElement(cc, q('nameEntries'))
    for nm, val in (('O', org), ('OU', ou)):
        e = ET.SubElement(ne, q('nameEntry'))
        e.set('name', nm)
        e.set('value', val)
    cacfg = ET.SubElement(cs, q('TAKServerCAConfig'))
    cacfg.set('keystore', 'JKS')
    cacfg.set('keystoreFile', f'certs/files/{int_ca}-signing.jks')
    cacfg.set('keystorePass', cert_pass)
    cacfg.set('validityDays', issued_days)
    cacfg.set('signatureAlg', 'SHA256WithRSA')
    changed.append('certificateSigning')

    # (3) auth="x509" on the 8089 tls <input>
    net = root.find(q('network'))
    if net is None:
        net = root.find('network')
    if net is not None:
        for inp in list(net):
            if lt(inp) != 'input':
                continue
            if inp.get('port') == '8089' and inp.get('protocol') == 'tls':
                if inp.get('auth') != 'x509':
                    inp.set('auth', 'x509')
                    changed.append('8089 x509')
                break

    # v10.0.5 non-root: write CoreConfig via the broker (literal `sudo cp` fallback failed
    # as takwerx; /opt/tak is tak-owned on native, a home-symlink on container — broker handles both).
    import io as _io_ce
    _buf_ce = _io_ce.BytesIO()
    tree.write(_buf_ce, encoding='UTF-8', xml_declaration=True)
    _write_priv(coreconfig_path, _buf_ce.getvalue())
    if log_fn:
        log_fn(f"  ✓ CoreConfig cert-enrollment patched ({', '.join(changed) if changed else 'already ok'})")
    return True, ', '.join(changed)


import re as _re_module
_ASN1_PRINTABLE_RE = _re_module.compile(r"^[A-Za-z0-9 '()+,\-./:=?]*$")


def _sanitize_cert_field(value, field_name):
    """Validate and sanitize a certificate metadata field for ASN1 PrintableString.

    Rejects underscores, @, #, !, and other chars that break strict ASN1 parsers
    (e.g. TakAware's Swift ASN1 library). Returns sanitized value or raises ValueError.
    """
    value = (value or '').strip()
    if not value:
        return value
    if not _ASN1_PRINTABLE_RE.match(value):
        bad = ''.join(c for c in value if not _ASN1_PRINTABLE_RE.match(c))
        raise ValueError(f'{field_name} contains invalid characters for certificate fields: {bad!r}  — only A-Z, a-z, 0-9, spaces, and \' ( ) + , - . / : = ? are allowed')
    return value


def _patch_openssl_string_mask(log_fn=None):
    """Patch system openssl.cnf to use PrintableString instead of UTF8String.

    Many modern distros ship string_mask = utf8only which encodes cert subject
    fields as UTF8STRING. Some TAK clients (TakAware/Swift) require the standard
    PRINTABLESTRING encoding. This patches the system config to use 'nombstr'
    which selects PrintableString for ASCII-only values.
    """
    cnf = '/etc/ssl/openssl.cnf'
    if not os.path.exists(cnf):
        return
    try:
        with open(cnf, 'r') as f:
            content = f.read()
    except Exception:
        return
    if 'string_mask = utf8only' not in content:
        return
    patched = content.replace('string_mask = utf8only', 'string_mask = nombstr')
    # v10.0.5 non-root: write /etc/ssl/openssl.cnf via the broker. The old raw
    # open()→`sudo cp` fallback FAILS on the non-root console (takwerx isn't in
    # sudoers — `sudo` prompts and exits) AND then falsely logged "✓ Patched".
    try:
        _write_priv(cnf, patched)
    except Exception as _e:
        if log_fn:
            log_fn(f"  ⚠ Could not patch OpenSSL string_mask ({str(_e)[:80]}) — non-fatal (PrintableString compat skipped)")
        return
    if log_fn:
        log_fn("✓ Patched OpenSSL config: string_mask = nombstr (PrintableString for TAK client compatibility)")


def _sanitize_coreconfig_name_entries():
    """Fix invalid characters in CoreConfig.xml nameEntry values (e.g. underscores).

    TAK clients like TakAware use nameEntry values from the signing config to
    build CSRs with PrintableString encoding. Characters like underscores are
    not allowed in PrintableString and cause enrollment failures.
    Called automatically before TAK Server start/restart from the console.
    Returns (changed: bool, message: str).
    """
    coreconfig = '/opt/tak/CoreConfig.xml'
    if not os.path.exists(coreconfig):
        return False, 'no_coreconfig'
    try:
        with open(coreconfig, 'r') as f:
            content = f.read()
    except Exception:
        return False, 'coreconfig_unreadable'
    if '<nameEntry' not in content:
        return False, 'no_name_entries'
    import re as _re
    changed = False
    def fix_value(m):
        nonlocal changed
        name, val = m.group(1), m.group(2)
        cleaned = _re_module.sub(r'[^A-Za-z0-9 \'()+,\-./:=?]', ' ', val).strip()
        if cleaned != val:
            changed = True
        return f'<nameEntry name="{name}" value="{cleaned}"/>'
    patched = _re.sub(
        r'<nameEntry\s+name="([^"]+)"\s+value="([^"]*)"\s*/>',
        fix_value, content
    )
    if not changed:
        return False, 'name_entries_ok'
    _write_priv(coreconfig, patched)   # v10.0.5 non-root: broker write to tak-owned /opt/tak
    return True, 'Fixed invalid characters in CoreConfig.xml nameEntry values (replaced underscores with spaces)'


def _get_webadmin_defaults(settings):
    """Default CloudTAK bootstrap TAK user creds."""
    return 'webadmin', (settings.get('webadmin_password') or '').strip()


def _load_admin_p12_bytes_from_tak_core(settings):
    """Best-effort load of admin.p12 from TAK core (local preferred, remote fallback)."""
    local_path = '/opt/tak/certs/files/admin.p12'
    if os.path.exists(local_path):
        try:
            with open(local_path, 'rb') as f:
                return f.read(), local_path, ''
        except Exception as e:
            return b'', local_path, f'Could not read local admin.p12: {e}'

    # Fallback: if TAK server two is remote, try reading via SSH.
    try:
        tak_cfg = _get_tak_deployment_config(settings)
        s2 = tak_cfg.get('server_two', {}) if isinstance(tak_cfg.get('server_two'), dict) else {}
        s2_host = (s2.get('host') or '').strip()
        if s2_host and s2_host not in ('127.0.0.1', 'localhost'):
            cmd = (
                "python3 - <<'PY'\n"
                "import base64,sys\n"
                "p='/opt/tak/certs/files/admin.p12'\n"
                "try:\n"
                "  b=open(p,'rb').read()\n"
                "  print(base64.b64encode(b).decode())\n"
                "except Exception as e:\n"
                "  print('ERR:'+str(e))\n"
                "  sys.exit(1)\n"
                "PY"
            )
            ok, out = _ssh_probe(s2, cmd, timeout=20)
            if ok and out:
                import base64
                try:
                    data = base64.b64decode((out or '').strip().splitlines()[-1])
                    if data:
                        return data, f'{s2_host}:/opt/tak/certs/files/admin.p12', ''
                except Exception:
                    pass
            return b'', f'{s2_host}:/opt/tak/certs/files/admin.p12', (out or 'Could not read remote admin.p12')[:260]
    except Exception as e:
        return b'', local_path, str(e)[:220]
    return b'', local_path, 'admin.p12 not found on TAK core'

def _get_authentik_host(settings):
    """Return the hostname for the Authentik service (configurable via Caddy/Domains, default tak.<fqdn> = hub)."""
    return _get_service_domain(settings, 'authentik')

def _get_takserver_host(settings):
    """Return the hostname for TAK Server WebGUI (configurable via Caddy/Domains, default takserver.<fqdn>)."""
    return _get_service_domain(settings, 'takserver')

def _get_takserver_base_url(settings):
    """Return https://<takserver_host> or https://<server_ip> for TAK Server (no port)."""
    host = _get_takserver_host(settings)
    if host:
        return f'https://{host}'
    server_ip = (settings.get('server_ip') or '').strip() or 'localhost'
    return f'https://{server_ip}'

def _get_authentik_base_url(settings):
    """Return the full base URL for Authentik (for links, AUTHENTIK_PUBLIC_URL, brand, outposts)."""
    host = _get_authentik_host(settings)
    if host:
        return f'https://{host}'
    server_ip = (settings.get('server_ip') or '').strip() or 'localhost'
    return f'http://{server_ip}:9090'


def _get_authentik_upstream(settings):
    """Return Authentik upstream for Caddy (127.0.0.1:9090 or remote_host:9090)."""
    cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    if cfg.get('target_mode') == 'remote':
        host = (cfg.get('remote', {}).get('host') or '').strip()
        if host:
            return f'{host}:9090'
    return '127.0.0.1:9090'


def _get_authentik_api_url(settings):
    """Return Authentik API base URL for server-side HTTP calls (e.g. LDAP flow, WebAdmin)."""
    upstream = _get_authentik_upstream(settings)
    return f'http://{upstream}'


INFRATAK_DOCKER_NETWORK = 'infratak'


def _ensure_infratak_docker_network():
    """Create the shared 'infratak' Docker bridge network if it doesn't exist.

    This network allows containers from different compose stacks (e.g. TAK Portal,
    Authentik) to communicate directly using container hostnames, which is required
    because published ports are hardened to 127.0.0.1 and unreachable between containers.
    """
    try:
        r = subprocess.run(
            _sudo_wrap(['docker', 'network', 'inspect', INFRATAK_DOCKER_NETWORK]), capture_output=True, text=True, timeout=10)
        if r.returncode != 0:
            subprocess.run(
                _sudo_wrap(['docker', 'network', 'create', INFRATAK_DOCKER_NETWORK]), capture_output=True, text=True, timeout=10)
    except Exception:
        pass


def _connect_container_to_infratak_network(container_name):
    """Connect a running container to the shared infratak Docker network (idempotent)."""
    try:
        _ensure_infratak_docker_network()
        subprocess.run(
            _sudo_wrap(['docker', 'network', 'connect', INFRATAK_DOCKER_NETWORK, container_name]), capture_output=True, text=True, timeout=10)
    except Exception:
        pass


def _ensure_infratak_network_for_authentik():
    """Connect Authentik server container to the infratak network."""
    _connect_container_to_infratak_network('authentik-server-1')


def _ensure_infratak_network_for_portal():
    """Connect TAK Portal container to the infratak network."""
    _connect_container_to_infratak_network('tak-portal')


def _write_takportal_override():
    """Write ~/TAK-Portal/docker-compose.override.yml with network + port hardening.

    Uses the override file (never tracked by git) so that git pull during
    TAK Portal updates never conflicts with our local modifications.  This
    replaces the old approach of patching docker-compose.yml directly, which
    caused git stash conflicts and left the repo on the old version after
    every update.

    v0.9.12 — port hardening (Tier 3, Caddy-loopback):
      Upstream `AdventureSeeker423/TAK-Portal`'s docker-compose.yml binds
      `${WEB_UI_PORT:-3000}:${WEB_UI_PORT:-3000}` which defaults to
      `0.0.0.0:3000:3000`. Authentication is delegated to Authentik via
      Caddy forward_auth, so anyone hitting port 3000 directly bypasses
      that auth boundary entirely. Same class of issue as the CloudTAK
      `5433` bug (Tier 3 service published publicly when only Caddy
      legitimately consumes it).
      Fix: `!reset` the port list to bind 3000 to loopback only. Browsers
      reach the portal via `https://portal.example.com` → Caddy on 443 →
      forward_auth → upstream `127.0.0.1:3000`.
    """
    portal_dir = os.path.expanduser('~/TAK-Portal')
    override_path = os.path.join(portal_dir, 'docker-compose.override.yml')
    if not os.path.isdir(portal_dir):
        return False
    try:
        _ensure_infratak_docker_network()
        settings = load_settings()
        tak_dns = (_get_takserver_host(settings) or '').strip()
        # v0.9.57: container host aliases for the Portal's server-side mTLS to the local TAK JVM.
        # host.docker.internal always maps to the docker host (172.17.0.1). When TAK is on-box
        # AND an FQDN is set, ALSO alias takserver.<fqdn> → host-gateway so the Portal's mTLS to
        # https://takserver.<fqdn>:8443/Marti resolves to the local JVM INSIDE the container —
        # on both normal boxes (skips the public-IP hairpin) and gateway-fronted boxes (skips the
        # App Gateway cert mismatch; the Portal validates the CA chain, not the hostname). That
        # lets TAK_URL stay the real FQDN so QR enrollment hosts are correct (see
        # _takportal_build_settings_dict). extra_hosts take effect on container RECREATE
        # (compose up -d), not a plain restart.
        _extra_hosts = "      - \"host.docker.internal:host-gateway\"\n"
        if settings.get('fqdn') and tak_dns and os.path.isdir('/opt/tak'):
            _extra_hosts += f"      - \"{tak_dns}:host-gateway\"\n"
        content = (
            "# TAKWERX: TAK Portal runtime overrides — do not edit manually\n"
            "# Port hardening is applied directly to docker-compose.yml by\n"
            "# _patch_takportal_compose_ports() (compose-version-agnostic).\n"
            "services:\n"
            "  tak-portal:\n"
            "    extra_hosts:\n"
            f"{_extra_hosts}"
            "    networks:\n"
            "      - default\n"
            f"      - {INFRATAK_DOCKER_NETWORK}\n"
            "\n"
            "networks:\n"
            "  default: {}\n"
            f"  {INFRATAK_DOCKER_NETWORK}:\n"
            "    external: true\n"
        )
        existing = ''
        if os.path.exists(override_path):
            with open(override_path) as f:
                existing = f.read()
        if existing == content:
            return False  # already current
        with open(override_path, 'w') as f:
            f.write(content)
        return True
    except Exception:
        return False


def _patch_takportal_compose_network():
    """Add the infratak external network to TAK Portal compose config.

    v0.9.2+: writes docker-compose.override.yml instead of modifying the
    git-tracked docker-compose.yml, preventing stash conflicts on git pull.
    """
    return _write_takportal_override()


def _patch_takportal_compose_ports(portal_dir=None):
    """Patch ~/TAK-Portal/docker-compose.yml to bind WEB_UI_PORT to loopback only.

    Upstream AdventureSeeker423/TAK-Portal binds
    `${WEB_UI_PORT:-3000}:${WEB_UI_PORT:-3000}` (0.0.0.0). We rewrite it to
    `127.0.0.1:${WEB_UI_PORT:-3000}:${WEB_UI_PORT:-3000}`.

    Must be called after every `git pull` and before `docker compose up`, so
    that git resets don't leave the container exposed on 0.0.0.0.

    Idempotent — already-patched files are not re-patched.
    Returns True if the file was modified.

    Corruption recovery: if the file contains the corruption signature from
    a prior bad patch (`ports:J7.0.0.1`), restore from git first, then patch.

    Note: `ports: !reset` in the override is NOT used for this because Docker
    Compose v5.x (shipped with Docker Engine 27+) does not support the !reset
    YAML tag; the tagged sequence resolves to null, silently dropping ALL port
    bindings (both base and override). Direct base-file patching is
    version-agnostic and reliable.

    IMPORTANT: backrefs use \\g<N> syntax (NOT \\N) because the previous
    `r'\\1127.0.0.1:\\2"'` form was parsed by Python's re engine as octal
    \\112 (= ASCII 'J') + literal '7.0.0.1:' + group2, corrupting every file
    it touched. `\\g<1>127.0.0.1` is unambiguous and safe.
    """
    import re as _re
    if portal_dir is None:
        portal_dir = os.path.expanduser('~/TAK-Portal')
    compose_path = os.path.join(portal_dir, 'docker-compose.yml')
    if not os.path.exists(compose_path):
        return False
    try:
        # Corruption recovery from the v0.9.12 bad-backref bug
        with open(compose_path) as f:
            _pre = f.read()
        if 'ports:J' in _pre or 'J7.0.0.1' in _pre:
            try:
                subprocess.run(
                    f'cd {shlex.quote(portal_dir)} && '
                    f'git -c safe.directory={shlex.quote(portal_dir)} checkout -- docker-compose.yml',
                    shell=True, capture_output=True, timeout=10
                )
            except Exception:
                pass

        with open(compose_path) as f:
            content = f.read()
        orig = content
        # Change bare `PORT:PORT` → `127.0.0.1:PORT:PORT`
        # Idempotent: pattern won't match if 127.0.0.1: prefix is already present
        content = _re.sub(
            r'(\s+- ")(\$\{WEB_UI_PORT:-3000\}:\$\{WEB_UI_PORT:-3000\})"',
            r'\g<1>127.0.0.1:\g<2>"',
            content
        )
        if content != orig:
            with open(compose_path, 'w') as f:
                f.write(content)
            return True
        return False
    except Exception:
        return False


def _patch_authentik_compose_network():
    """Add the infratak external network to Authentik's docker-compose.yml.

    Ensures the server container stays on the infratak network even after
    'docker compose down && up' or Docker-initiated restarts — not just
    console-driven restarts that call _ensure_infratak_network_for_authentik().
    """
    compose_path = os.path.expanduser('~/authentik/docker-compose.yml')
    if not os.path.exists(compose_path):
        return False
    try:
        _ensure_infratak_docker_network()
        with open(compose_path) as f:
            content = f.read()
        if INFRATAK_DOCKER_NETWORK in content:
            return False
        service_network = "    networks:\n      - default\n      - infratak\n"
        if '    command: server\n' in content:
            content = content.replace(
                '    command: server\n',
                '    command: server\n' + service_network, 1)
        networks_block = (
            f"\nnetworks:\n"
            f"  default:\n"
            f"  {INFRATAK_DOCKER_NETWORK}:\n"
            f"    external: true\n"
        )
        content = content.rstrip() + '\n' + networks_block
        with open(compose_path, 'w') as f:
            f.write(content)
        return True
    except Exception:
        return False


def _check_authentik_api_reachable(settings):
    """Verify we can reach the Authentik API (for remote: ensures firewall allows console -> Authentik:9090).
    Returns (True, None) if reachable, (False, error_msg) otherwise."""
    import urllib.request as _req
    import urllib.error
    url = _get_authentik_api_url(settings)
    token = _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN') or _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN')
    if not token:
        return False, 'Authentik .env not found (no token)'
    headers = {'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'}
    try:
        r = _req.Request(f'{url}/api/v3/flows/instances/?page_size=1', headers=headers)
        _req.urlopen(r, timeout=15)
        return True, None
    except urllib.error.HTTPError as e:
        if e.code in (401, 403):
            return False, f'Authentik API rejected token ({e.code}). Check AUTHENTIK_BOOTSTRAP_TOKEN or AUTHENTIK_TOKEN in Authentik .env.'
        return False, f'Authentik API returned {e.code}'
    except OSError as e:
        err = str(e).lower()
        if 'timed out' in err or 'timeout' in err:
            return False, f'Cannot reach Authentik at {url} (timeout). For remote Authentik, open port 9090 from this host to the Authentik server.'
        if 'refused' in err or 'connection' in err:
            return False, f'Cannot reach Authentik at {url} (connection refused). For remote Authentik, ensure Authentik is running and port 9090 is open from this host.'
        return False, f'Authentik unreachable: {str(e)[:120]}'


def _get_authentik_env_content(settings):
    """Return raw content of Authentik .env (local file or fetched via SSH when remote). None if unavailable.

    v10.0.9: on a non-root (takwerx) console the Authentik .env may be (a) still at the root-era
    /root/authentik/.env, or (b) present at ~/authentik/.env but owned root:root — a raw open()
    then returns nothing, so callers read an EMPTY token and (e.g.) overwrite TAK Portal's good
    token with "" during the non-root flip window. Try both candidate paths, and for each fall
    back to a privileged read (_read_priv → broker/sudo) so a root-owned or not-yet-re-homed .env
    is still reachable. (memory nonroot-flip-strands-root-era-module-dirs)"""
    cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    if cfg.get('target_mode') == 'remote' and (cfg.get('remote', {}).get('host') or '').strip():
        ok, out = _ssh_probe(cfg['remote'], 'cat ~/authentik/.env 2>/dev/null', timeout=15)
        if ok and out and out.strip():
            return out.strip()
        return None
    for path in (os.path.expanduser('~/authentik/.env'), '/root/authentik/.env'):
        # Fast path: direct read when the console can read it.
        try:
            if os.path.isfile(path):
                with open(path) as f:
                    txt = f.read()
                if txt and txt.strip():
                    return txt
        except Exception:
            pass
        # Privileged read: reaches a root-owned / not-yet-re-homed .env from the takwerx console.
        try:
            txt = _read_priv(path)
            if txt and txt.strip():
                return txt
        except Exception:
            pass
    return None


def _get_authentik_env_value(settings, key):
    """Return value for KEY= from Authentik .env (local or remote). Strips quotes. None if missing."""
    content = _get_authentik_env_content(settings)
    if not content:
        return None
    for line in content.splitlines():
        line = line.strip()
        if line.startswith(key + '='):
            val = line.split('=', 1)[1].strip()
            if val.startswith('"') and val.endswith('"'):
                val = val[1:-1]
            elif val.startswith("'") and val.endswith("'"):
                val = val[1:-1]
            return val
    return None


def _authentik_application_open_in_new_tab(ak_url, ak_headers, slug, plog=None):
    """PATCH Authentik application so My applications uses target=_blank for the launch URL.
    Logs HTTP/parse failures via plog when provided (previously all errors were swallowed)."""
    import urllib.request as _ur
    import urllib.error as _ue
    import urllib.parse as _uparse
    _log = plog or (lambda _m: None)
    if not ak_url or not ak_headers or not slug:
        return
    slug = str(slug).strip().strip('/')
    if not slug:
        return
    enc = _uparse.quote(slug, safe='')
    url = f'{ak_url.rstrip("/")}/api/v3/core/applications/{enc}/'
    headers = dict(ak_headers)
    headers.setdefault('Accept', 'application/json')
    try:
        req = _ur.Request(
            url,
            data=json.dumps({'open_in_new_tab': True}).encode(),
            headers=headers, method='PATCH')
        with _ur.urlopen(req, timeout=10) as resp:
            raw = (resp.read() or b'').decode()
        data = {}
        if raw.strip():
            try:
                data = json.loads(raw)
            except json.JSONDecodeError:
                _log(f"  ⚠ open_in_new_tab ({slug}): PATCH response not JSON ({raw[:80]!r})")
                return
        else:
            try:
                gr = _ur.Request(url, headers=headers, method='GET')
                with _ur.urlopen(gr, timeout=10) as grsp:
                    data = json.loads((grsp.read() or b'{}').decode())
            except Exception as ge:
                _log(f"  ⚠ open_in_new_tab ({slug}): empty PATCH body, GET verify failed: {str(ge)[:100]}")
                return
        oint = data.get('open_in_new_tab')
        if oint is None:
            oint = data.get('openInNewTab')
        if oint is not True:
            _log(
                f"  ⚠ open_in_new_tab ({slug}): field still false after PATCH "
                f"(got {oint!r}) — check Authentik version / API token permissions"
            )
    except _ue.HTTPError as e:
        try:
            err_body = (e.read() or b'').decode()[:400]
        except Exception:
            err_body = ''
        _log(f"  ⚠ open_in_new_tab ({slug}): HTTP {e.code} {err_body}")
    except Exception as ex:
        _log(f"  ⚠ open_in_new_tab ({slug}): {str(ex)[:160]}")


def _tak_deployment_defaults():
    """Default TAK deployment shape (single-server by default, optional two-server fields)."""
    return {
        'mode': 'single_server',  # single_server | two_server | external_db
        'server_one': {  # Manual naming from TAK guide: "Server One: Database Server"
            'host': '',
            'ssh_user': 'root',
            'ssh_port': 22,
            'auth_method': 'ssh_key',  # ssh_key | password
            'ssh_key_path': '',
            'ssh_password': '',
            'os_family': 'ubuntu',
        },
        'server_two': {  # Manual naming from TAK guide: "Server Two: Core Server"
            'host': '127.0.0.1',
            'ssh_user': 'root',
            'ssh_port': 22,
            'use_localhost': True,
            'auth_method': 'ssh_key',  # ssh_key | password
            'ssh_key_path': '',
            'ssh_password': '',
            'os_family': 'ubuntu',
        },
        'database': {
            'port': 5432,
            'name': 'cot',
            'user': 'martiuser',
            'password': '',
            'enable_postgres_tls': True,
        },
        # External / managed database (AWS RDS, Azure Database for PostgreSQL, etc.)
        # Used when mode == 'external_db'. TAK Server runs on this VM; PostgreSQL is
        # fully managed externally (no SSH, no infra-TAK management of the DB host).
        'external_db': {
            'host': '',        # RDS endpoint / FQDN / IP
            'port': 5432,
            'name': 'cot',
            'user': 'martiuser',
            'password': '',
        },
    }

def _deep_merge_dict(base, override):
    """Return a deep-merged copy of dicts (override values win)."""
    merged = copy.deepcopy(base)
    for k, v in (override or {}).items():
        if isinstance(v, dict) and isinstance(merged.get(k), dict):
            merged[k] = _deep_merge_dict(merged[k], v)
        else:
            merged[k] = v
    return merged

def _normalize_tak_deployment_config(cfg):
    """Validate and normalize TAK deployment settings for persistence/runtime use."""
    c = _deep_merge_dict(_tak_deployment_defaults(), cfg or {})
    mode = (c.get('mode') or 'single_server').strip().lower()
    if mode == 'two_server':
        c['mode'] = 'two_server'
    elif mode == 'external_db':
        c['mode'] = 'external_db'
    else:
        c['mode'] = 'single_server'
    # Normalize external_db block
    edb = c.get('external_db', {}) if isinstance(c.get('external_db'), dict) else {}
    edb['host'] = (edb.get('host') or '').strip()
    try:
        edb['port'] = int(edb.get('port') or 5432)
    except Exception:
        edb['port'] = 5432
    edb['name'] = (edb.get('name') or 'cot').strip() or 'cot'
    edb['user'] = (edb.get('user') or 'martiuser').strip() or 'martiuser'
    edb['password'] = (edb.get('password') or '').strip()
    c['external_db'] = edb
    for key in ('server_one', 'server_two'):
        host_cfg = c.get(key, {}) if isinstance(c.get(key), dict) else {}
        host_cfg['host'] = (host_cfg.get('host') or '').strip()
        host_cfg['ssh_user'] = (host_cfg.get('ssh_user') or 'root').strip() or 'root'
        try:
            host_cfg['ssh_port'] = int(host_cfg.get('ssh_port') or 22)
        except Exception:
            host_cfg['ssh_port'] = 22
        auth_method = (host_cfg.get('auth_method') or 'ssh_key').strip().lower()
        host_cfg['auth_method'] = 'password' if auth_method == 'password' else 'ssh_key'
        host_cfg['ssh_key_path'] = (host_cfg.get('ssh_key_path') or '').strip()
        host_cfg['ssh_password'] = (host_cfg.get('ssh_password') or '').strip()
        host_cfg['use_localhost'] = bool(host_cfg.get('use_localhost', False))
        if key == 'server_two' and host_cfg.get('use_localhost'):
            host_cfg['host'] = '127.0.0.1'
            host_cfg['auth_method'] = 'ssh_key'
            host_cfg['ssh_key_path'] = ''
            host_cfg['ssh_password'] = ''
        if key == 'server_two' and not host_cfg.get('host'):
            host_cfg['host'] = '127.0.0.1'
        host_cfg['os_family'] = (host_cfg.get('os_family') or 'ubuntu').strip().lower() or 'ubuntu'
        c[key] = host_cfg
    db_cfg = c.get('database', {}) if isinstance(c.get('database'), dict) else {}
    try:
        db_cfg['port'] = int(db_cfg.get('port') or 5432)
    except Exception:
        db_cfg['port'] = 5432
    db_cfg['name'] = (db_cfg.get('name') or 'cot').strip() or 'cot'
    db_cfg['user'] = (db_cfg.get('user') or 'martiuser').strip() or 'martiuser'
    db_cfg['password'] = (db_cfg.get('password') or '').strip()
    db_cfg['enable_postgres_tls'] = bool(db_cfg.get('enable_postgres_tls', True))
    c['database'] = db_cfg
    return c

def _get_tak_deployment_config(settings):
    return _normalize_tak_deployment_config(settings.get('tak_deployment', {}))

_SSH_USER_RE = re.compile(r'^[a-z_][a-z0-9_-]{0,31}\$?$')


def _validate_ssh_target(host, user, port):
    """v0.9.12 — validate SSH host/user/port before invoking ssh.

    Defends against operator/API-supplied values that contain SSH option
    flags (e.g. host = '-oProxyCommand=touch /tmp/x') or shell metacharacters
    via the `user@host` argument. Without this guard a remote-host setting
    would have allowed a logged-in console user (or any compromised settings
    file) to execute arbitrary commands locally.
    """
    if not host or len(host) > 253:
        return False, 'host empty or too long'
    if not _safe_migration_db_host(host):
        return False, f'host {host!r} fails IP/DNS validation'
    if not user or not _SSH_USER_RE.fullmatch(user):
        return False, f'ssh_user {user!r} fails POSIX username validation'
    try:
        p = int(port)
        if not (1 <= p <= 65535):
            return False, 'ssh_port out of range'
    except Exception:
        return False, 'ssh_port not an integer'
    return True, ''


def _ssh_probe(host_cfg, cmd='echo ok', timeout=15):
    """Run a non-interactive SSH probe command. Returns (ok, output)."""
    host = (host_cfg.get('host') or '').strip()
    user = (host_cfg.get('ssh_user') or 'root').strip() or 'root'
    port = int(host_cfg.get('ssh_port') or 22)
    if not host:
        return False, 'host not set'
    is_local = bool(host_cfg.get('use_localhost')) or host in ('127.0.0.1', 'localhost', '::1')
    if not is_local:
        _ok, _err = _validate_ssh_target(host, user, port)
        if not _ok:
            return False, f'SSH target validation failed: {_err}'
    if is_local:
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=timeout)
            if r.returncode == 0:
                return True, (r.stdout or '').strip()
            return False, ((r.stderr or '') + '\n' + (r.stdout or '')).strip()
        except Exception as e:
            return False, str(e)
    auth_method = (host_cfg.get('auth_method') or 'ssh_key').strip().lower()
    batch_mode = 'no' if auth_method == 'password' else 'yes'
    ssh_cmd = [
        'ssh',
        '-o', f'BatchMode={batch_mode}',
        '-o', 'StrictHostKeyChecking=accept-new',
        '-o', f'ConnectTimeout={max(3, min(10, timeout))}',
        '-p', str(port),
    ]
    key_path = (host_cfg.get('ssh_key_path') or '').strip()
    if auth_method == 'password':
        ssh_password = (host_cfg.get('ssh_password') or '').strip()
        if not ssh_password:
            return False, 'auth_method=password but ssh_password is empty'
        if shutil.which('sshpass') is None:
            return False, 'sshpass not installed on infra host (required for password-based preflight)'
        ssh_cmd = ['sshpass', '-e'] + ssh_cmd
        ssh_run_env = {**os.environ, 'SSHPASS': ssh_password}
    elif key_path:
        expanded = os.path.expanduser(key_path)
        if os.path.exists(expanded):
            ssh_cmd.extend(['-i', expanded])
        else:
            return False, f'ssh key not found: {expanded}'
    ssh_cmd.extend([f'{user}@{host}', cmd])
    try:
        run_kw = dict(capture_output=True, text=True, timeout=timeout)
        if auth_method == 'password':
            run_kw['env'] = ssh_run_env
        r = subprocess.run(ssh_cmd, **run_kw)
        if r.returncode == 0:
            return True, (r.stdout or '').strip()
        combined = ((r.stderr or '') + '\n' + (r.stdout or '')).strip()
        if not combined:
            safe_cmd = ' '.join(ssh_cmd[:ssh_cmd.index(f'{user}@{host}') + 1]) + ' <cmd>'
            combined = f'exit {r.returncode}, no output. cmd: {safe_cmd}'
        return False, combined
    except Exception as e:
        return False, str(e)


def _remote_takserver_database_version(host_cfg):
    """Installed takserver-database Version on host via SSH, or None if missing/unreadable."""
    cmd = r"dpkg-query -W -f '${Version}' takserver-database 2>/dev/null || true"
    ok, out = _ssh_probe(host_cfg, cmd, timeout=25)
    if not ok:
        return None, (out or 'ssh failed')[:300]
    v = (out or '').strip()
    return (v if v else None), None


def _local_deb_control_fields(deb_path):
    """Return (package_name, version) from .deb control, or (None, None)."""
    try:
        if not deb_path or not os.path.isfile(deb_path):
            return None, None
        rp = subprocess.run(['dpkg-deb', '-f', deb_path, 'Package'], capture_output=True, text=True, timeout=30)
        rv = subprocess.run(['dpkg-deb', '-f', deb_path, 'Version'], capture_output=True, text=True, timeout=30)
        if rp.returncode != 0 or rv.returncode != 0:
            return None, None
        pkg = (rp.stdout or '').strip()
        ver = (rv.stdout or '').strip()
        return (pkg or None, ver or None)
    except Exception:
        return None, None


def _validate_fedhub_deb_path(deb_path):
    """True if .deb is the TAK Federation Hub package (dpkg-deb Package contains fed + hub)."""
    pkg, _ver = _local_deb_control_fields(deb_path)
    if not pkg:
        return False, 'Could not read package name from .deb (dpkg-deb -f). Run upload from a Linux console host.'
    pl = pkg.lower()
    if 'fed' in pl and 'hub' in pl:
        return True, None
    return False, f'Wrong package: "{pkg}" — upload takserver-fed-hub .deb from TAK.gov'


def _find_fedhub_deb_in_uploads():
    """Newest valid Federation Hub .deb in UPLOAD_DIR. Returns (filename, full_path) or (None, None)."""
    candidates = []
    try:
        names = os.listdir(UPLOAD_DIR)
    except OSError:
        return None, None
    for fn in names:
        if not fn.endswith('.deb'):
            continue
        fp = os.path.join(UPLOAD_DIR, fn)
        if not os.path.isfile(fp):
            continue
        ok_m, _err = _validate_fedhub_deb_path(fp)
        if ok_m:
            candidates.append((fn, fp, os.path.getmtime(fp)))
    if not candidates:
        return None, None
    candidates.sort(key=lambda x: x[2], reverse=True)
    return candidates[0][0], candidates[0][1]


def _fedhub_remote_apt_unlock_cmd():
    """Same lock cleanup pattern as TAK Server One database deploy."""
    return (
        'sudo killall -q apt-get dpkg unattended-upgr 2>/dev/null; '
        'for i in 1 2 3 4 5 6; do '
        'fuser /var/lib/dpkg/lock /var/lib/apt/lists/lock /var/cache/apt/archives/lock >/dev/null 2>&1 || break; '
        'echo "Waiting for apt lock ($i)…"; sleep 5; done; '
        'sudo rm -f /var/lib/dpkg/lock /var/lib/dpkg/lock-frontend /var/lib/apt/lists/lock /var/cache/apt/archives/lock 2>/dev/null; '
        'sudo dpkg --configure -a 2>/dev/null; '
        'sudo apt-get -f install -y 2>/dev/null; true'
    )


def _assert_uploaded_db_deb_matches_server_one(s1_ref_cfg, local_deb_path, deb_filename):
    """
    Ensure uploaded takserver-database .deb Version matches installed package on current Server One.
    s1_ref_cfg: SSH config for the existing DB host (saved server_one, not the migrate target).
    Returns (ok, error_message).
    """
    pkg, deb_ver = _local_deb_control_fields(local_deb_path)
    if not deb_ver:
        return False, f'Could not read Version from uploaded {deb_filename} (dpkg-deb -f failed).'
    if pkg and 'database' not in pkg.lower():
        return False, f'Uploaded .deb is package "{pkg}" — use takserver-database for this check.'
    remote_ver, qerr = _remote_takserver_database_version(s1_ref_cfg)
    if qerr:
        return False, f'Could not read takserver-database version on current Server One: {qerr}'
    if not remote_ver:
        return False, (
            'takserver-database does not appear to be installed on the current Server One (no dpkg version). '
            'Confirm SSH/key points at the live DB host, or install the package there first.'
        )
    if remote_ver != deb_ver:
        return False, (
            f'takserver-database version mismatch: current Server One has {remote_ver}, '
            f'uploaded .deb is {deb_ver}. Upload the matching database .deb from tak.gov, then retry.'
        )
    return True, None


def _scp_to_host(host_cfg, local_path, remote_path, timeout=120):
    """Copy local_path to remote_path on host. remote_path is like /tmp/ or /tmp/file.deb. Returns (ok, output)."""
    host = (host_cfg.get('host') or '').strip()
    user = (host_cfg.get('ssh_user') or 'root').strip() or 'root'
    port = int(host_cfg.get('ssh_port') or 22)
    if not host or not os.path.isfile(local_path):
        return False, 'host not set or file not found'
    is_local = bool(host_cfg.get('use_localhost')) or host in ('127.0.0.1', 'localhost', '::1')
    if not is_local:
        _ok, _err = _validate_ssh_target(host, user, port)
        if not _ok:
            return False, f'SSH target validation failed: {_err}'
    if is_local:
        try:
            shutil.copy2(local_path, remote_path.rstrip('/') if not remote_path.endswith('/') else os.path.join(remote_path, os.path.basename(local_path)))
            return True, ''
        except Exception as e:
            return False, str(e)
    scp_cmd = ['scp', '-o', 'StrictHostKeyChecking=accept-new', '-o', f'ConnectTimeout=15', '-P', str(port)]
    key_path = (host_cfg.get('ssh_key_path') or '').strip()
    auth_method = (host_cfg.get('auth_method') or 'ssh_key').strip().lower()
    if auth_method == 'password':
        pw = (host_cfg.get('ssh_password') or '').strip()
        if not pw or not shutil.which('sshpass'):
            return False, 'password auth requires sshpass'
        scp_cmd = ['sshpass', '-e'] + scp_cmd
        scp_run_env = {**os.environ, 'SSHPASS': pw}
    elif key_path:
        expanded = os.path.expanduser(key_path)
        if os.path.exists(expanded):
            scp_cmd.extend(['-i', expanded])
    scp_cmd.extend([local_path, f'{user}@{host}:{remote_path}'])
    try:
        run_kw = dict(capture_output=True, text=True, timeout=timeout)
        if auth_method == 'password':
            run_kw['env'] = scp_run_env
        r = subprocess.run(scp_cmd, **run_kw)
        out = (r.stdout or r.stderr or '').strip()
        return r.returncode == 0, out
    except Exception as e:
        return False, str(e)


def _scp_from_host(host_cfg, remote_path, local_path, timeout=600):
    """Copy remote_path on host to local_path. Returns (ok, output)."""
    host = (host_cfg.get('host') or '').strip()
    user = (host_cfg.get('ssh_user') or 'root').strip() or 'root'
    port = int(host_cfg.get('ssh_port') or 22)
    if not host:
        return False, 'host not set'
    is_local = bool(host_cfg.get('use_localhost')) or host in ('127.0.0.1', 'localhost', '::1')
    if is_local:
        try:
            shutil.copy2(remote_path, local_path)
            return True, ''
        except Exception as e:
            return False, str(e)
    scp_cmd = ['scp', '-o', 'StrictHostKeyChecking=accept-new', '-o', 'ConnectTimeout=15', '-P', str(port)]
    key_path = (host_cfg.get('ssh_key_path') or '').strip()
    auth_method = (host_cfg.get('auth_method') or 'ssh_key').strip().lower()
    if auth_method == 'password':
        pw = (host_cfg.get('ssh_password') or '').strip()
        if not pw or not shutil.which('sshpass'):
            return False, 'password auth requires sshpass'
        scp_cmd = ['sshpass', '-e'] + scp_cmd
        scp_run_env = {**os.environ, 'SSHPASS': pw}
    elif key_path:
        expanded = os.path.expanduser(key_path)
        if os.path.exists(expanded):
            scp_cmd.extend(['-i', expanded])
    scp_cmd.extend([f'{user}@{host}:{remote_path}', local_path])
    try:
        run_kw = dict(capture_output=True, text=True, timeout=timeout)
        if auth_method == 'password':
            run_kw['env'] = scp_run_env
        r = subprocess.run(scp_cmd, **run_kw)
        out = (r.stdout or r.stderr or '').strip()
        return r.returncode == 0, out
    except Exception as e:
        return False, str(e)


def _safe_migration_db_host(hostname):
    """Allow IPv4 or simple DNS hostname for new Server One (SSH/SCP target)."""
    h = (hostname or '').strip()
    if not h or len(h) > 253:
        return False
    if re.match(r'^(\d{1,3}\.){3}\d{1,3}$', h):
        return True
    if re.match(r'^[a-zA-Z0-9]([a-zA-Z0-9.-]*[a-zA-Z0-9])?$', h):
        return True
    return False


def _get_service_alias(settings, service_key):
    """Return the configured alias domain for a service (or empty string)."""
    return settings.get(f'{service_key}_domain_alias', '').strip()

def generate_caddyfile(settings=None):
    """Generate Caddyfile based on current settings and deployed services.
    Each service gets its own domain (customizable per-service, defaults to subdomain of base FQDN)."""
    if settings is None:
        settings = load_settings()
    domain = settings.get('fqdn', '')
    if not domain:
        return
    modules = detect_modules()

    lines = [f"# infra-TAK - Auto-generated Caddyfile", f"# Base Domain: {domain}", ""]
    sd = _get_all_service_domains(settings)

    def _emit_alias_redirect(alias, canonical):
        """Emit a 301-redirect stanza: alias → canonical."""
        if not alias or alias == canonical:
            return
        lines.append(f"# Alias → redirect to canonical {canonical}")
        lines.append(f"{alias} {{")
        lines.append(f"    redir https://{canonical}{{uri}} permanent")
        lines.append(f"}}")
        lines.append("")
    ak_up = _get_authentik_upstream(settings)

    ak = modules.get('authentik', {})
    nodered = modules.get('nodered', {})
    infratak_host = sd['infratak']
    lines.append(f"{infratak_host} {{")
    # Public health endpoint for external monitors (Uptime Robot) on normal HTTPS/443.
    # This avoids requiring port 8080 to be open to the internet.
    lines.append(f"    route /health* {{")
    lines.append(f"        reverse_proxy 127.0.0.1:8080")
    lines.append(f"    }}")
    # SECURITY (v10.1.0): the send-alert-email / send-sms endpoints have NO @login_required
    # and gate on loopback IP only — meant for the box's own Guard Dog scripts, which POST
    # to 127.0.0.1:5001 DIRECTLY (never via Caddy). Reached through Caddy 443 they'd let an
    # unauthenticated internet client send arbitrary email/SMS from the box. Block them at
    # the public edge (404). Internal loopback callers are unaffected (they don't traverse
    # Caddy). Ordered before the proxy routes so it wins.
    lines.append(f"    route /api/guarddog/send-alert-email* {{")
    lines.append(f"        respond 404")
    lines.append(f"    }}")
    lines.append(f"    route /api/guarddog/send-sms* {{")
    lines.append(f"        respond 404")
    lines.append(f"    }}")
    # v10.1.1 S2: same class — restart-safe is a loopback-only readiness probe for
    # the console-restart timer (calls 127.0.0.1:5001 directly, never via Caddy).
    # Through Caddy it would pass the loopback gate and leak deploy-in-flight
    # state to unauthenticated clients. No legitimate edge caller exists → 404.
    lines.append(f"    route /api/console/restart-safe* {{")
    lines.append(f"        respond 404")
    lines.append(f"    }}")
    # SECURITY (v10.1.0, CVE-class): the console trusts X-Authentik-Username from any
    # 127.0.0.1 caller (that is how forward_auth logs the SSO user in). Caddy does NOT
    # strip client-supplied X-Authentik-* by default, and the plain reverse_proxy paths
    # (/login, and /api/* which is EXCLUDED from forward_auth) pass it straight through
    # to the console → a public request `X-Authentik-Username: admin` got a full admin
    # session with no password (confirmed exploitable). Strip every X-Authentik-* from
    # the CLIENT at the top of each console route, inside `route {}` (which preserves
    # directive order) so it runs BEFORE forward_auth re-injects the AUTHENTIC value
    # from the auth response. Non-forward_auth paths then get nothing → bypass closed;
    # the SSO path is unchanged (forward_auth adds the real header after the strip).
    # v10.1.1 S1: X-Infratak-Proxy-Auth is stripped from clients here too — only
    # Caddy itself may attach it (below, after forward_auth passes).
    _AK_FWD_HEADERS = ('X-Authentik-Username', 'X-Authentik-Groups', 'X-Authentik-Email',
                       'X-Authentik-Name', 'X-Authentik-Uid', 'X-Infratak-Proxy-Auth')
    def _emit_ak_header_strip(indent):
        for _h in _AK_FWD_HEADERS:
            lines.append(f"{indent}request_header -{_h}")
    if ak.get('installed'):
        # W1 (Hardened posture): drop the unauthenticated /login bypass so the
        # shared-password page is no longer a network ingress — SSO+MFA only.
        # Standard posture keeps it so password login works without Authentik.
        if not _w1_console_locked():
            lines.append(f"    route /login* {{")
            _emit_ak_header_strip("        ")
            lines.append(f"        reverse_proxy 127.0.0.1:5001 {{")
            lines.append(f"            transport http {{")
            lines.append(f"                tls")
            lines.append(f"                tls_insecure_skip_verify")
            lines.append(f"                read_timeout 1h")
            lines.append(f"                write_timeout 1h")
            lines.append(f"            }}")
            lines.append(f"        }}")
            lines.append(f"    }}")
        lines.append(f"    route {{")
        _emit_ak_header_strip("        ")
        lines.append(f"        reverse_proxy /outpost.goauthentik.io/* {ak_up}")
        # v0.9.58: background /api XHR must NOT go through forward_auth. An unauthenticated
        # XHR gets 302-redirected to the cross-origin Authentik OAuth URL (tak.<fqdn>), which
        # the browser CORS-blocks — that is the console "request failed" on the CPU/RAM,
        # check-release, etc. buttons once the proxy session lapses. /api is still protected
        # by the console's own @login_required (clean SAME-origin 401) and the W2 idle-lock,
        # so SSO+MFA on every PAGE is unchanged; only the silent API calls skip the redirect.
        lines.append(f"        @needs_sso {{")
        lines.append(f"            not path /api/*")
        lines.append(f"        }}")
        lines.append(f"        forward_auth @needs_sso {ak_up} {{")
        lines.append(f"            uri /outpost.goauthentik.io/auth/caddy")
        lines.append(f"            copy_headers X-Authentik-Username X-Authentik-Groups X-Authentik-Email X-Authentik-Name X-Authentik-Uid")
        lines.append(f"            trusted_proxies private_ranges")
        lines.append(f"        }}")
        # v10.1.1 S1: attach the proxy-auth secret AFTER forward_auth, on the same
        # matcher — so it is present exactly when forward_auth passed (a 302'd
        # request never reaches this directive; /api/* skips both). The console
        # requires it alongside X-Authentik-Username once the gate is armed, so a
        # forged identity header alone is dead even if the client strip above ever
        # regresses on a future plain-proxy path.
        _pa_secret = (_proxy_auth_state(create=True).get('secret') or '').strip()
        if _pa_secret:
            lines.append(f"        request_header @needs_sso X-Infratak-Proxy-Auth {_pa_secret}")
        lines.append(f"        reverse_proxy 127.0.0.1:5001 {{")
        lines.append(f"            transport http {{")
        lines.append(f"                tls")
        lines.append(f"                tls_insecure_skip_verify")
        lines.append(f"                read_timeout 1h")
        lines.append(f"                write_timeout 1h")
        lines.append(f"            }}")
        lines.append(f"        }}")
        lines.append(f"    }}")
    else:
        # No Authentik: the whole vhost is a plain proxy — strip client X-Authentik-*
        # so a forged header can't reach the console's loopback-trust (same bypass).
        lines.append(f"    route {{")
        _emit_ak_header_strip("        ")
        lines.append(f"        reverse_proxy 127.0.0.1:5001 {{")
        lines.append(f"            transport http {{")
        lines.append(f"                tls")
        lines.append(f"                tls_insecure_skip_verify")
        lines.append(f"                read_timeout 1h")
        lines.append(f"                write_timeout 1h")
        lines.append(f"            }}")
        lines.append(f"        }}")
        lines.append(f"    }}")
    lines.append(f"}}")
    lines.append("")
    _emit_alias_redirect(_get_service_alias(settings, 'infratak'), infratak_host)

    if nodered.get('installed'):
        nodered_host = sd['nodered']
        nodered_up = _get_nodered_upstream(settings)
        lines.append(f"# Node-RED flow editor")
        lines.append(f"{nodered_host} {{")
        if ak.get('installed'):
            lines.append(f"    route {{")
            lines.append(f"        reverse_proxy /outpost.goauthentik.io/* {ak_up}")
            lines.append(f"        @nodered_public {{")
            lines.append(f"            path /ipaws/alerts.kml /icons/ipaws/*")
            lines.append(f"        }}")
            lines.append(f"        handle @nodered_public {{")
            lines.append(f"            reverse_proxy {nodered_up}")
            lines.append(f"        }}")
            lines.append(f"        forward_auth {ak_up} {{")
            lines.append(f"            uri /outpost.goauthentik.io/auth/caddy")
            lines.append(f"            trusted_proxies private_ranges")
            lines.append(f"        }}")
            lines.append(f"        reverse_proxy {nodered_up}")
            lines.append(f"    }}")
        else:
            lines.append(f"    reverse_proxy {nodered_up}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'nodered'), nodered_host)

    tak = modules.get('takserver', {})
    if tak.get('installed'):
        tak_host = sd['takserver']
        lines.append(f"# TAK Server")
        lines.append(f"{tak_host} {{")
        lines.append(f"    reverse_proxy 127.0.0.1:8446 {{")
        lines.append(f"        transport http {{")
        lines.append(f"            tls")
        lines.append(f"            tls_insecure_skip_verify")
        lines.append(f"        }}")
        lines.append(f"        header_down Location 127.0.0.1:8446 {tak_host}")
        lines.append(f"        header_down Location http:// https://")
        lines.append(f"    }}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'takserver'), tak_host)

    ak = modules.get('authentik', {})
    if ak.get('installed'):
        ak_host = sd['authentik']
        lines.append(f"# Authentik")
        lines.append(f"{ak_host} {{")
        lines.append(f"    reverse_proxy {ak_up}")
        lines.append(f"}}")
        lines.append("")
        # If default is tak.<fqdn>, also serve Authentik on authentik.<fqdn> so redirects to authentik.* don't break (TLS works)
        fqdn_base = domain.split(':')[0].split('/')[0] if domain else ''
        if fqdn_base and ak_host == f'tak.{fqdn_base}':
            lines.append(f"# Authentik (alternate hostname — same backend)")
            lines.append(f"authentik.{fqdn_base} {{")
            lines.append(f"    reverse_proxy {ak_up}")
            lines.append(f"}}")
            lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'authentik'), ak_host)

    portal = modules.get('takportal', {})
    if portal.get('installed'):
        portal_up = _get_takportal_upstream(settings)
        portal_host = sd['takportal']
        lines.append(f"# TAK Portal")
        lines.append(f"{portal_host} {{")
        if ak.get('installed'):
            lines.append(f"    route {{")
            lines.append(f"        reverse_proxy /outpost.goauthentik.io/* {ak_up}")
            lines.append(f"")
            lines.append(f"        @public {{")
            lines.append(f"            path /request-access* /lookup* /locate/* /styles.css /favicon.ico /branding/* /public/*")
            lines.append(f"        }}")
            lines.append(f"")
            lines.append(f"        handle @public {{")
            lines.append(f"            reverse_proxy {portal_up}")
            lines.append(f"        }}")
            lines.append(f"")
            lines.append(f"        forward_auth {ak_up} {{")
            lines.append(f"            uri /outpost.goauthentik.io/auth/caddy")
            lines.append(f"            copy_headers X-Authentik-Username X-Authentik-Groups X-Authentik-Entitlements X-Authentik-Email X-Authentik-Name X-Authentik-Uid X-Authentik-Jwt X-Authentik-Meta-Jwks X-Authentik-Meta-Outpost X-Authentik-Meta-Provider X-Authentik-Meta-App X-Authentik-Meta-Version")
            lines.append(f"            trusted_proxies private_ranges")
            lines.append(f"        }}")
            lines.append(f"")
            lines.append(f"        reverse_proxy {portal_up}")
            lines.append(f"    }}")
        else:
            lines.append(f"    reverse_proxy {portal_up}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'takportal'), portal_host)

    cloudtak = modules.get('cloudtak', {})
    if cloudtak.get('installed'):
        ct_map = sd['cloudtak_map']
        ct_tiles = sd['cloudtak_tiles']
        ct_video = sd['cloudtak_video']
        ct_up = _get_cloudtak_upstreams(settings)
        lines.append(f"# CloudTAK Web UI (flush for SSE channels / WebSocket; longer timeouts for channel sync)")
        lines.append(f"{ct_map} {{")
        lines.append(f"    reverse_proxy {ct_up['map']} {{")
        lines.append(f"        flush_interval -1")
        lines.append(f"        transport http {{")
        lines.append(f"            read_timeout 120s")
        lines.append(f"            write_timeout 120s")
        lines.append(f"        }}")
        lines.append(f"    }}")
        lines.append(f"    # sw.js ships no Cache-Control from the CloudTAK image, so browsers may")
        lines.append(f"    # heuristically cache the service-worker script and miss a new build for")
        lines.append(f"    # hours. Force revalidation so an updated SW is detected on the next load.")
        lines.append(f"    # (Hygiene only — it does NOT fix the SW 'waiting' stall; that needs")
        lines.append(f"    # skipWaiting()/clients.claim() in CloudTAK's own service worker.)")
        lines.append(f"    @ct_swjs path /sw.js")
        lines.append(f"    header @ct_swjs Cache-Control \"no-cache, no-store, must-revalidate\"")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'cloudtak_map'), ct_map)
        lines.append(f"# CloudTAK Tile Server")
        lines.append(f"{ct_tiles} {{")
        lines.append(f"    reverse_proxy {ct_up['tiles']}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'cloudtak_tiles'), ct_tiles)
        lines.append(f"# CloudTAK Media (video) — /stream/* → HLS, rest → MediaMTX API")
        lines.append(f"{ct_video} {{")
        lines.append(f"    handle_path /stream/* {{")
        lines.append(f"        reverse_proxy {ct_up['video_hls']}")
        lines.append(f"    }}")
        lines.append(f"    handle {{")
        lines.append(f"        reverse_proxy {ct_up['video_api']}")
        lines.append(f"    }}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'cloudtak_video'), ct_video)
        # v0.9.48: CloudTAK force-appends :9997 to EVERY media URL it builds
        # (video-service.ts sets url.port='9997' for both the MediaMTX control API
        # and the /stream HLS URL). The 443 vhost above is therefore never hit by
        # CloudTAK itself → the whole Video Lease subsystem (proxy + normal leases)
        # times out. Add a second listener on :9997 with the SAME routing so the
        # upstream CloudTAK image works unmodified and survives its own rebuilds.
        # MUST bind a specific non-loopback IP: 127.0.0.1:9997 is the cloudtak-media
        # container's docker publish, so a 0.0.0.0:9997 listener collides and Caddy
        # won't start. Caddy reuses the hostname's existing cert on :9997 (no ACME conflict).
        # v0.9.51 — universal bind: settings.server_ip may be a PUBLIC/NAT address (Azure,
        # GCP, any load-balanced box) that isn't assigned to a local interface; binding it
        # fails with "cannot assign requested address" and kills Caddy on every regen. Bind
        # a locally-assigned IP: keep server_ip when it's on the NIC, else fall back to the
        # box's primary local IP (NAT forwards the public :9997 to it). If neither resolves,
        # skip the listener rather than crash Caddy.
        ct_bind_ip = (settings.get('server_ip') or '').strip()
        if ct_bind_ip and ct_bind_ip not in _list_local_ipv4s():
            ct_bind_ip = _primary_local_ipv4()
        if ct_bind_ip:
            ct_video_host = ct_video.split()[0].strip()  # hostname only (drop any TLS/options)
            lines.append(f"# CloudTAK Media (video) on :9997 — CloudTAK hardcodes this port for all media URLs")
            lines.append(f"{ct_video_host}:9997 {{")
            lines.append(f"    bind {ct_bind_ip}")
            lines.append(f"    handle_path /stream/* {{")
            lines.append(f"        reverse_proxy {ct_up['video_hls']}")
            lines.append(f"    }}")
            lines.append(f"    handle {{")
            lines.append(f"        reverse_proxy {ct_up['video_api']}")
            lines.append(f"    }}")
            lines.append(f"}}")
            lines.append("")

    mtx = modules.get('mediamtx', {})
    if mtx.get('installed'):
        mtx_host = sd['mediamtx']
        mtx_up = _get_mediamtx_upstream(settings)
        mtx_hls, hls_enc = _get_mediamtx_hls_upstream(settings)
        lines.append(f"# MediaMTX Web Console")
        lines.append(f"{mtx_host} {{")
        lines.append(f"    handle_path /hls-proxy/* {{")
        if hls_enc:
            lines.append(f"        reverse_proxy https://{mtx_hls} {{")
            lines.append(f"            transport http {{")
            lines.append(f"                tls_server_name {mtx_host}")
            lines.append(f"            }}")
            lines.append(f"            header_down Location ^ /hls-proxy")
            lines.append(f"        }}")
        else:
            lines.append(f"        reverse_proxy {mtx_hls} {{")
            lines.append(f"            header_down Location ^ /hls-proxy")
            lines.append(f"        }}")
        lines.append(f"    }}")
        if ak.get('installed'):
            lines.append(f"    route /watch/* {{")
            lines.append(f"        reverse_proxy {mtx_up}")
            lines.append(f"    }}")
            lines.append(f"    route /shared/* {{")
            lines.append(f"        reverse_proxy {mtx_up}")
            lines.append(f"    }}")
            lines.append(f"    route /shared-hls/* {{")
            lines.append(f"        reverse_proxy {mtx_up}")
            lines.append(f"    }}")
            lines.append(f"    route {{")
            lines.append(f"        reverse_proxy /outpost.goauthentik.io/* {ak_up}")
            lines.append(f"        forward_auth {ak_up} {{")
            lines.append(f"            uri /outpost.goauthentik.io/auth/caddy")
            lines.append(f"            copy_headers X-Authentik-Username X-Authentik-Groups X-Authentik-Email X-Authentik-Name X-Authentik-Uid")
            lines.append(f"            trusted_proxies private_ranges")
            lines.append(f"        }}")
            lines.append(f"        reverse_proxy {mtx_up}")
            lines.append(f"    }}")
        else:
            lines.append(f"    reverse_proxy {mtx_up}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'mediamtx'), mtx_host)

    fedhub = modules.get('fedhub', {})
    if fedhub.get('installed'):
        fhcfg = _get_fedhub_deployment_config(settings)
        fh_remote = (fhcfg.get('remote', {}).get('host') or '').strip()
        if fh_remote and fhcfg.get('target_mode') == 'remote':
            fh_host = sd['fedhub']
            fh_port = int(fhcfg.get('web_ui_port') or 8080)
            fh_upstream = f'{fh_remote}:{fh_port}'
            fh_upstream_scheme = 'https' if fh_port in (9100, 8446) else 'http'
            fh_rp_block = []
            fh_rp_block.append(f"reverse_proxy {fh_upstream_scheme}://{fh_upstream} {{")
            fh_rp_block.append(f"    header_up X-Forwarded-Port 443")
            fh_rp_block.append(f"    header_up X-Forwarded-Proto https")
            fh_rp_block.append(f"    header_up X-Forwarded-Host {{host}}")
            fh_rp_block.append(f"    header_up Host {{host}}")
            fh_rp_block.append(f"    transport http {{")
            if fh_upstream_scheme == 'https':
                fh_rp_block.append(f"        tls")
                fh_rp_block.append(f"        tls_insecure_skip_verify")
            fh_rp_block.append(f"        read_timeout 120s")
            fh_rp_block.append(f"        write_timeout 120s")
            fh_rp_block.append(f"    }}")
            fh_rp_block.append(f"}}")

            # Fed Hub: Caddy forward_auth (Authentik) when Authentik is installed — matches “My applications”
            # launch after tak.<fqdn> login (session already at edge; often skips Fed Hub’s local OIDC screen).
            # OAuth provider + federation-hub-ui.yml still used for Fed Hub’s own OIDC when needed.
            lines.append(f"# TAK Federation Hub — Caddy terminates public TLS and proxies to remote hub web port")
            lines.append(f"{fh_host} {{")
            if ak.get('installed'):
                # Static/UI assets must not go through forward_auth — Authentik returns HTML and the browser
                # rejects CSS/JS as wrong MIME type. Fed Hub also serves some files from site root (poly-*.js, PNG).
                lines.append(f"    route {{")
                lines.append(f"        @fh_pub {{")
                lines.append(f"            path /static/* /favicon.ico /Parsons_TAK.png /poly-*")
                lines.append(f"        }}")
                lines.append(f"        handle @fh_pub {{")
                for rp_line in fh_rp_block:
                    lines.append(f"            {rp_line}")
                lines.append(f"        }}")
                lines.append(f"        handle {{")
                lines.append(f"            reverse_proxy /outpost.goauthentik.io/* {ak_up}")
                lines.append(f"            forward_auth {ak_up} {{")
                lines.append(f"                uri /outpost.goauthentik.io/auth/caddy")
                lines.append(f"                copy_headers X-Authentik-Username X-Authentik-Groups X-Authentik-Email X-Authentik-Name X-Authentik-Uid")
                lines.append(f"                trusted_proxies private_ranges")
                lines.append(f"            }}")
                for rp_line in fh_rp_block:
                    lines.append(f"            {rp_line}")
                lines.append(f"        }}")
                lines.append(f"    }}")
            else:
                for rp_line in fh_rp_block:
                    lines.append(f"    {rp_line}")
            lines.append(f"}}")
            lines.append("")
            _emit_alias_redirect(_get_service_alias(settings, 'fedhub'), fh_host)

    ct_mod = modules.get('cesium_tiles', {})
    if ct_mod.get('installed'):
        ct_host = sd.get('cesium_tiles') or _get_service_domain(settings, 'cesium_tiles')
        ct_dir_abs = _cesium_dir()
        lines.append(f"# Cesium 3D Tiles — static file server (CORS enabled for ATAK WebView)")
        lines.append(f"{ct_host} {{")
        lines.append(f"    root * {ct_dir_abs}")
        lines.append(f"    file_server")
        lines.append(f"    header Access-Control-Allow-Origin *")
        lines.append(f"    header Access-Control-Allow-Methods \"GET, HEAD, OPTIONS\"")
        lines.append(f"    header Cache-Control \"public, max-age=3600\"")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'cesium_tiles'), ct_host)

    wo_mod = modules.get('webodm', {})
    if wo_mod.get('installed'):
        wo_host = sd.get('webodm') or _get_service_domain(settings, 'webodm')
        wo_port = settings.get('webodm_port', 8765)
        _wo_deploy_cfg = _get_module_deployment_config(settings, 'webodm_deployment')
        if _wo_deploy_cfg.get('target_mode') == 'remote':
            _wo_remote_host = (_wo_deploy_cfg.get('remote', {}).get('host') or '').strip()
            wo_up = f'{_wo_remote_host}:{wo_port}' if _wo_remote_host else f'127.0.0.1:{wo_port}'
        else:
            wo_up = f'127.0.0.1:{wo_port}'
        lines.append(f"# WebODM — drone photogrammetry + TAK overlay")
        lines.append(f"{wo_host} {{")
        if ak.get('installed'):
            lines.append(f"    route {{")
            lines.append(f"        reverse_proxy /outpost.goauthentik.io/* {ak_up}")
            lines.append(f"        forward_auth {ak_up} {{")
            lines.append(f"            uri /outpost.goauthentik.io/auth/caddy")
            lines.append(f"            trusted_proxies private_ranges")
            lines.append(f"        }}")
            lines.append(f"        reverse_proxy {wo_up}")
            lines.append(f"    }}")
        else:
            lines.append(f"    reverse_proxy {wo_up}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'webodm'), wo_host)

    tvr_mod = modules.get('tak_video_restreamer', {})
    if tvr_mod.get('installed'):
        tvr_host = sd.get('tak_video_restreamer') or _get_service_domain(settings, 'tak_video_restreamer')
        lines.append(f"# TAK Video Restreamer — Flask + MediaMTX streaming server")
        lines.append(f"{tvr_host} {{")
        # Public paths: bypass Authentik (auth handled by the app itself or not needed)
        for pub_path in ['/hls/*', '/api/hls/proxy/*', '/login*', '/static/*',
                         '/api/auth/*', '/api/health*']:
            lines.append(f"    handle {pub_path} {{")
            lines.append(f"        reverse_proxy 127.0.0.1:3100")
            lines.append(f"    }}")
        # Native MediaMTX HLS (loopback :8888) available via /hls-proxy/
        lines.append(f"    handle_path /hls-proxy/* {{")
        lines.append(f"        reverse_proxy 127.0.0.1:8888 {{")
        lines.append(f"            header_down Location ^ /hls-proxy")
        lines.append(f"        }}")
        lines.append(f"    }}")
        # TVR has its own Flask login — no Authentik forward_auth wrapper needed
        lines.append(f"    reverse_proxy 127.0.0.1:3100")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'tak_video_restreamer'), tvr_host)

    nb_mod = modules.get('netbird', {})
    if nb_mod.get('installed'):
        nb_host = sd.get('netbird') or _get_service_domain(settings, 'netbird')
        lines.append(f"# NetBird VPN")
        lines.append(f"{nb_host} {{")
        # Management API and gRPC
        lines.append(f"    @netbird_mgmt {{")
        lines.append(f"        path /api* /management.*")
        lines.append(f"    }}")
        lines.append(f"    handle @netbird_mgmt {{")
        lines.append(f"        reverse_proxy h2c://127.0.0.1:33073")
        lines.append(f"    }}")
        # Signal exchange (gRPC)
        lines.append(f"    @netbird_signal {{")
        lines.append(f"        path /signalexchange.*")
        lines.append(f"    }}")
        lines.append(f"    handle @netbird_signal {{")
        lines.append(f"        reverse_proxy h2c://127.0.0.1:10000")
        lines.append(f"    }}")
        # Embedded Dex IDP OIDC endpoints + relay WebSocket
        lines.append(f"    @netbird_idp {{")
        lines.append(f"        path /oauth2 /oauth2/* /.well-known/* /auth /auth/* /token /keys /callback /userinfo /device /device/* /approval /approval/* /relay")
        lines.append(f"    }}")
        lines.append(f"    handle @netbird_idp {{")
        lines.append(f"        reverse_proxy h2c://127.0.0.1:33073")
        lines.append(f"    }}")
        # Dashboard UI (catch-all)
        lines.append(f"    handle {{")
        lines.append(f"        reverse_proxy 127.0.0.1:8642")
        lines.append(f"    }}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'netbird'), nb_host)

    ra_mod = modules.get('remote_assist', {})
    if ra_mod.get('installed'):
        ra_host = sd.get('remote_assist') or _get_service_domain(settings, 'remote_assist')
        ra_up = f'127.0.0.1:{REMOTE_ASSIST_PORT}'
        ra_proxy = (
            f'        flush_interval -1\n'
            f'        transport http {{\n'
            f'            read_timeout 1h\n'
            f'            write_timeout 1h\n'
            f'        }}'
        )
        lines.append(f"# EUD Remote Assist — admin portal (443). Device API is on :{REMOTE_ASSIST_DEVICE_PORT} only.")
        lines.append(f"{ra_host} {{")
        lines.append(f"    header Strict-Transport-Security \"max-age=31536000;\"")
        lines.append(f"    @ra_device path /api/v1/* /ws/device /health /version")
        lines.append(f"    respond @ra_device 404")
        lines.append(f"    reverse_proxy {ra_up} {{")
        lines.append(ra_proxy)
        lines.append(f"    }}")
        lines.append(f"}}")
        lines.append("")
        _emit_alias_redirect(_get_service_alias(settings, 'remote_assist'), ra_host)
        lines.append(f"# EUD Remote Assist — Android device API (TLS :{REMOTE_ASSIST_DEVICE_PORT})")
        lines.append(f"{ra_host}:{REMOTE_ASSIST_DEVICE_PORT} {{")
        lines.append(f"    header Strict-Transport-Security \"max-age=31536000;\"")
        lines.append(f"    @ra_device path /api/v1/* /ws/device /health /version")
        lines.append(f"    handle @ra_device {{")
        lines.append(f"        reverse_proxy {ra_up} {{")
        lines.append(ra_proxy)
        lines.append(f"        }}")
        lines.append(f"    }}")
        lines.append(f"    respond 404")
        lines.append(f"}}")
        lines.append("")

    # v0.9.51 — Custom certificate (bring-your-own-cert) mode. When ssl_mode == 'custom'
    # the operator has uploaded a full-chain PEM + key on the Caddy page; Caddy must serve
    # THAT cert (no ACME) on every site. We inject a `tls <cert> <key>` directive into each
    # site address block (covers the wildcard case — one cert for all subdomains). Per-site
    # tls disables ACME for that site without needing a global `auto_https off`, so the
    # automatic HTTP→HTTPS redirect on :80 is preserved.
    # NOTE: this runs LAST so it also injects tls into the NetBird vhost appended above.
    if (settings.get('ssl_mode') or '') == 'custom':
        # Caddy runs unprivileged and can't read .config — deploy a caddy-readable copy
        # and point `tls` at THAT (see _sync_custom_cert_for_caddy).
        cert_path, key_path = _sync_custom_cert_for_caddy()
        if cert_path and key_path:
            tls_directive = f"    tls {cert_path} {key_path}"
            injected = []
            for ln in lines:
                injected.append(ln)
                stripped = ln.rstrip()
                # A site address block opens at column 0 (no indent), ends with '{', and is
                # neither a comment, a snippet/global block, nor a bare '{'. Nested blocks
                # (route {, handle {, transport http {) are indented, so they're skipped.
                if (stripped.endswith('{') and stripped != '{'
                        and not stripped[0].isspace()
                        and not stripped.startswith(('#', '('))):
                    injected.append(tls_directive)
            lines = injected

    caddyfile = '\n'.join(lines)
    # Preserve user-added blocks (e.g. health.tntak.net for Uptime Robot) that sit below the marker.
    # v10.1.0: the marker is now ALWAYS emitted at the end of the generated file. It used to
    # exist only if an operator already knew the magic string and typed it in by hand — so in
    # practice every regeneration (module deploy/remove, domain change, cert-mode flip, W1,
    # Fed Hub) silently wiped custom entries. Field complaint 2026-07-08. Capture takes the
    # content AFTER the marker line (not including it) so exactly one marker section exists.
    user_blocks = ''
    if os.path.exists(CADDYFILE_PATH):
        try:
            with open(CADDYFILE_PATH) as f:
                existing = f.read()
            if CADDYFILE_USER_BLOCKS_MARKER in existing:
                after = existing.split(CADDYFILE_USER_BLOCKS_MARKER, 1)[1]
                # Drop our own help comments (re-emitted fresh below on every regen — they must
                # not accumulate as "user content"); keep everything else verbatim.
                _help_prefixes = ('# Anything below this line survives',
                                  '# Add custom site blocks here')
                user_lines = [l for l in after.splitlines()
                              if not l.strip().startswith(_help_prefixes)]
                user_blocks = '\n'.join(user_lines).strip('\n')
        except Exception:
            pass
    caddyfile = (caddyfile.rstrip() + '\n\n'
                 + CADDYFILE_USER_BLOCKS_MARKER + '\n'
                 + '# Anything below this line survives every infra-TAK regeneration.\n'
                 + '# Add custom site blocks here (extra domains, redirects, monitors).\n')
    if user_blocks:
        caddyfile += '\n' + user_blocks + '\n'
    # v10.0.5 non-root: /etc/caddy may not exist yet (RHEL copr caddy doesn't
    # pre-create it) — a raw os.makedirs EPERM'd as the takwerx console ([Errno 13]
    # '/etc/caddy'), failing the deploy before the broker-routed write below.
    _makedirs_priv(os.path.dirname(CADDYFILE_PATH))
    _write_priv(CADDYFILE_PATH, caddyfile)
    # RHEL: Caddy runs confined as httpd_t, which can only bind ports in
    # http_port_t (80/443/8443/9000…). A non-standard listener — e.g. the
    # CloudTAK video vhost on :9997 — is denied (name_bind) so the reload fails
    # and that 443 vhost serves nothing (ERR_SSL_PROTOCOL_ERROR). Label any
    # non-standard listener port we just wrote BEFORE callers reload Caddy.
    # No-op on Debian / non-enforcing. Single choke point — covers every reload
    # site. Root-caused on aws-rocky (CloudTAK) 2026-06-20.
    try:
        _selinux_sync_caddy_ports()
    except Exception:
        pass
    return caddyfile


def _caddy_regenerate_if_fqdn():
    """Rewrite Caddyfile and reload Caddy when a base FQDN is set (e.g. after Fed Hub register/deploy)."""
    try:
        s = load_settings()
        if not (s.get('fqdn') or '').strip():
            return
        generate_caddyfile(s)
        threading.Thread(target=_caddy_restart_after_response, daemon=True).start()
    except Exception:
        pass


def wait_for_apt_lock(log_fn, log_list):
    """
    Wait for unattended-upgrades / apt locks to release before installing packages.
    Called at the start of every deploy that uses apt/dpkg.
    If unattended-upgrades is disabled but a process is still running, we kill it and wait briefly.
    Otherwise waits until lock clears (no timeout when upgrades are enabled).
    Appends a ⏳ ticker line every 10s — the frontend JS overwrites it in place.
    """
    uu = _get_unattended_upgrades_status()
    uu_disabled = not uu.get('enabled', True)

    def _unattended_process_running():
        # Match full path and truncated process name (ps may show "unattended-upgr")
        r = subprocess.run(
            'ps aux | grep -E "unattended-upgrade|unattended-upgr" | grep -v shutdown | grep -v grep',
            shell=True, capture_output=True, text=True)
        return bool(r.stdout.strip())

    def is_locked():
        # Check dpkg lock file via the broker (literal `sudo lsof` threw 'user NOT in sudoers' on
        # the non-root console; route through _sudo_wrap so it runs as root or fails open cleanly).
        lock = subprocess.run(_sudo_wrap(['lsof', '/var/lib/dpkg/lock-frontend']),
            capture_output=True, text=True)
        if lock.stdout.strip():
            return True
        # Check for active upgrade process (exclude the shutdown watcher)
        return _unattended_process_running()

    if not is_locked():
        return True

    # Unattended-upgrades is disabled but process/lock still present (e.g. user just turned it off)
    if uu_disabled:
        log_fn("Unattended-upgrades is disabled; stopping any remaining upgrade process...")
        subprocess.run('pkill -TERM -f "unattended-upgrade" 2>/dev/null; true', shell=True, timeout=5)
        # Wait up to 60s for process to exit and lock to release
        for _ in range(12):
            time.sleep(5)
            if not is_locked():
                log_fn("✓ Clear to proceed.")
                return True
        log_fn("⚠ Lock still held after 60s; continuing anyway (dpkg may be in use elsewhere).")
        return True

    log_fn("⏳ Unattended-upgrades is running — waiting for it to finish...")
    log_fn("  This can take 20-45 minutes on a fresh VPS. Do not cancel.")
    waited = 0
    while True:
        time.sleep(10)
        waited += 10
        if not is_locked():
            m, s = divmod(waited, 60)
            log_fn(f"✓ System upgrades complete (waited {m}m {s}s)")
            time.sleep(5)
            return True
        m, s = divmod(waited, 60)
        log_list.append(f"  ⏳ {m:02d}:{s:02d}")


def wait_for_unattended_upgrade_worker(log_fn, log_list, cancelled_check=None):
    """Wait until no /usr/bin/unattended-upgrade worker is running.

    Same check as the start of TAK Server deploy (wait_for_package_lock). Complements
    wait_for_apt_lock (dpkg lock + broader process grep): the worker can be mid-run
    before a lock appears, so both are used before apt installs in deploy and upgrade.
    No timeout — ticks every 10s. cancelled_check, if set, returns True to abort wait.
    """
    log_fn("Checking for system upgrades in progress...")
    r = subprocess.run(
        'ps aux | grep "/usr/bin/unattended-upgrade" | grep -v shutdown | grep -v grep',
        shell=True, capture_output=True, text=True)
    if r.stdout.strip() == '':
        log_fn("✓ No system upgrades in progress, continuing...")
        return True
    log_fn("⏳ System is running unattended-upgrades, waiting for completion...")
    log_fn("  This can take 20-45 minutes on a fresh VPS. Do not cancel.")
    waited = 0
    while True:
        time.sleep(10)
        waited += 10
        if cancelled_check and cancelled_check():
            log_fn("⚠ Cancelled during upgrade wait")
            return False
        r = subprocess.run(
            'ps aux | grep "/usr/bin/unattended-upgrade" | grep -v shutdown | grep -v grep',
            shell=True, capture_output=True, text=True)
        if r.stdout.strip() == '':
            m, s = divmod(waited, 60)
            log_fn(f"✓ System upgrades complete! (waited {m}m {s}s)")
            time.sleep(5)
            return True
        m, s = divmod(waited, 60)
        log_list.append(f"  ⏳ {m:02d}:{s:02d}")


def _stage_le_cert_local(cert_crt, cert_key, wait_for_cert, log_fn, label='LE'):
    """v10.0.5 non-root: Caddy's cert dir is 0750 caddy:caddy, so the takwerx console
    CANNOT stat or read it — raw os.path.exists() returns False (and openssl -in
    <caddy cert> EPERM-fails) even though the cert exists, silently skipping the 8446
    wire-up. (Pre-v10 the ROOT console read it directly.) This silent EPERM never
    reaches the broker, so it does not show up as a DENY.

    Read the cert+key THROUGH THE BROKER (root) and stage console-owned copies for the
    deploy-time openssl/keytool. Returns (local_crt, local_key) or (None, None). On a
    root console _read_priv reads directly, so behavior is unchanged there.

    NOTE: callers keep the ORIGINAL Caddy paths for the renewal script (that runs as a
    root systemd unit and CAN read them) — only the deploy-time openssl uses these
    staged copies."""
    import tempfile
    waited = 0
    crt = key = None
    while True:
        try:
            crt = _read_priv(cert_crt)
            key = _read_priv(cert_key)
        except Exception:
            crt = key = None
        if (crt and key) or not wait_for_cert or waited >= 120:
            break
        log_fn(f"  Waiting for {label} cert files... ({waited}s)")
        time.sleep(10)
        waited += 10
    if not (crt and key):
        return None, None
    d = tempfile.mkdtemp(prefix='le8446-')
    local_crt = os.path.join(d, 'le.crt')
    local_key = os.path.join(d, 'le.key')
    with open(local_crt, 'w') as f:
        f.write(crt)
    with open(local_key, 'w') as f:
        f.write(key)
    os.chmod(local_key, 0o600)
    return local_crt, local_key


def _install_le_cert_on_8446_container(takserver_host, log_fn, wait_for_cert=True):
    """v10.0.1 — container variant of install_le_cert_on_8446. Same outcome (wire
    the Caddy LE / custom cert onto TAK's 8446 enrollment connector so clients
    trust it), adapted for the Docker TAK path: openssl on the host writes the p12
    to the SHARED /opt/tak mount, keytool runs via `docker exec` (no Java on the
    host), ownership is the container uid (1000), and lifecycle uses `docker` not
    systemctl. Mirrors the live-validated sequence. Returns True on success."""
    import re, shutil, time as _t
    s = load_settings()
    cert_pass = _get_tak_cert_password(s)
    custom_mode = (s.get('ssl_mode') or '') == 'custom'
    if custom_mode:
        cert_crt, cert_key = _custom_cert_paths()
        cert_dir = os.path.dirname(cert_crt); cert_label = 'custom'
    else:
        cert_dir = (f"/var/lib/caddy/.local/share/caddy/certificates/"
                    f"acme-v02.api.letsencrypt.org-directory/{takserver_host}")
        cert_crt = f"{cert_dir}/{takserver_host}.crt"
        cert_key = f"{cert_dir}/{takserver_host}.key"
        cert_label = 'LE'
    core_config = '/opt/tak/CoreConfig.xml'
    # v10.0.5 non-root: read Caddy's caddy:caddy-owned cert via the broker into
    # console-readable copies for openssl (raw os.path.exists/openssl EPERM-fail
    # SILENTLY as takwerx — the cert exists but the deploy skipped the 8446 wire-up).
    local_crt, local_key = _stage_le_cert_local(cert_crt, cert_key, wait_for_cert and not custom_mode, log_fn, cert_label)
    if not local_crt:
        log_fn(f"  ⚠ {cert_label} cert not readable at {cert_dir} — skipping 8446 cert wire-up")
        return False
    log_fn(f"  ✓ {cert_label} cert files found for {takserver_host}")
    p12 = '/opt/tak/certs/files/takserver-le.p12'
    jks = '/opt/tak/certs/files/takserver-le.jks'
    # Step A: cert → PKCS12. v10.0.5 non-root: takwerx can't write into tak-owned
    # /opt/tak/certs/files, so write the p12 to a host-writable /tmp path, then broker-cp it
    # onto the shared mount where the container's keytool (Step B) reads it. (Raw -out into
    # /opt/tak EPERM'd with an empty error -> "PKCS12 conversion failed" -> no 8446 LE cert.)
    _tmp_p12 = '/tmp/takserver-le.p12'
    r = subprocess.run(
        f'openssl pkcs12 -export -in {shlex.quote(local_crt)} -inkey {shlex.quote(local_key)} '
        f'-out {shlex.quote(_tmp_p12)} -name {shlex.quote(takserver_host)} -password pass:{shlex.quote(cert_pass)} 2>&1',
        shell=True, capture_output=True, text=True)
    if r.returncode != 0:
        log_fn(f"  ⚠ PKCS12 conversion failed: {(r.stdout or r.stderr).strip()[:200]}"); return False
    subprocess.run(_sudo_wrap(['cp', _tmp_p12, p12]), capture_output=True)
    try:
        os.remove(_tmp_p12)
    except Exception:
        pass
    # Step B: PKCS12 → JKS via docker exec (the container has Java/keytool; host arm64 does not)
    r = subprocess.run(
        _tak_exec('cd /opt/tak/certs/files && rm -f takserver-le.jks && '
                  f'keytool -importkeystore -srcstorepass {shlex.quote(cert_pass)} '
                  f'-deststorepass {shlex.quote(cert_pass)} -destkeystore takserver-le.jks '
                  '-srckeystore takserver-le.p12 -srcstoretype pkcs12 -noprompt') + ' 2>&1',
        shell=True, capture_output=True, text=True)
    if r.returncode != 0:
        log_fn(f"  ⚠ JKS conversion failed: {(r.stderr or r.stdout).strip()[:200]}"); return False
    subprocess.run(_sudo_wrap(['chown', '1000:1000', jks, p12]))
    log_fn("  ✓ JKS installed to /opt/tak/certs/files/takserver-le.jks")
    # Step C: patch CoreConfig 8446 connector → LetsEncrypt keystore (host-side via symlink).
    # TAK-in-container preserves CoreConfig across docker restart (verified), so no stop-first.
    try:
        # v10.0.5 non-root: read/back-up/patch CoreConfig via the broker — /opt/tak is
        # tak:tak 0755 + CoreConfig.xml 0640, so raw open('w')/shutil.copy by the
        # non-root console hit [Errno 13] and the 8446 connector was never patched →
        # 8446 served the wrong keystore → WebGUI 403.
        content = _read_priv(core_config)
        _write_priv(core_config + '.bak-le', content)
        new_connector = (
            '<connector port="8446" clientAuth="false" _name="LetsEncrypt" '
            'keystore="JKS" keystoreFile="certs/files/takserver-le.jks" '
            f'keystorePass="{cert_pass}" enableAdminUI="true" enableWebtak="true" '
            'enableNonAdminUI="false"/>')
        patched = re.sub(r'<(?:[A-Za-z][\w-]*:)?connector\s+port="8446"[^/]*/\s*>',
                         new_connector, content, count=1)
        if patched != content and '_name="LetsEncrypt"' in patched and 'takserver-le.jks' in patched:
            _write_priv(core_config, patched)
            log_fn("  ✓ CoreConfig.xml 8446 connector patched to LE cert")
        elif '_name="LetsEncrypt"' in content and 'takserver-le.jks' in content:
            # Already wired to the LE keystore — re.sub was a no-op (patched==content).
            # This is the IDEMPOTENT re-run path (e.g. the LE-cert self-heal re-establishing
            # the renewal script after a container redeploy re-extracted /opt/tak and wiped
            # only the script — CoreConfig is preserved across redeploy). NOT a failure:
            # fall through to Step D so the renewal script + timer get rewritten. Returning
            # False here is exactly what left arm's cert-renewal unit stuck in 203/EXEC.
            log_fn("  ✓ CoreConfig.xml 8446 connector already on LE cert")
        else:
            log_fn("  ⚠ 8446 connector not matched — check CoreConfig.xml manually"); return False
    except Exception as ce:
        log_fn(f"  ⚠ CoreConfig patch error: {ce}"); return False
    # Step D: renewal script (container-flavored) + host systemd timer (Caddy auto-renews;
    # re-import whenever TAK's keystore cert differs from Caddy's current cert).
    renewal = f'''#!/bin/bash
set -euo pipefail
TAK_DOMAIN={shlex.quote(takserver_host)}
CERT_CRT={shlex.quote(cert_crt)}
CERT_KEY={shlex.quote(cert_key)}
P12={p12}
JKS={jks}
LOG=/var/log/takserver-cert-renewal.log
log(){{ echo "[$(date -Is)] $*" | tee -a "$LOG"; }}
[ -f "$CERT_CRT" ] && [ -f "$CERT_KEY" ] || {{ log "ERROR: Caddy cert files not found for $TAK_DOMAIN"; exit 1; }}
CADDY_FP=$(openssl x509 -in "$CERT_CRT" -noout -fingerprint -sha256 2>/dev/null | cut -d= -f2)
TAK_FP=$(docker exec {TAK_CONTAINER} keytool -list -rfc -keystore "$JKS" -storepass {shlex.quote(cert_pass)} 2>/dev/null | openssl x509 -noout -fingerprint -sha256 2>/dev/null | cut -d= -f2 || true)
[ -n "$TAK_FP" ] && [ "$TAK_FP" = "$CADDY_FP" ] && {{ log "TAK keystore already current."; exit 0; }}
log "Refreshing TAK keystore from Caddy's current cert..."
openssl pkcs12 -export -in "$CERT_CRT" -inkey "$CERT_KEY" -out "$P12" -name "$TAK_DOMAIN" -password pass:{shlex.quote(cert_pass)}
docker exec {TAK_CONTAINER} bash -c "cd /opt/tak/certs/files && rm -f takserver-le.jks && keytool -importkeystore -srcstorepass {shlex.quote(cert_pass)} -deststorepass {shlex.quote(cert_pass)} -destkeystore takserver-le.jks -srckeystore takserver-le.p12 -srcstoretype pkcs12 -noprompt"
chown 1000:1000 "$JKS" "$P12" 2>/dev/null || true
docker restart {TAK_CONTAINER}
log "TAK keystore refreshed and container restarted."
'''
    try:
        _write_priv('/opt/tak/renew-letsencrypt.sh', renewal)
        subprocess.run(_sudo_wrap(['chmod', '+x', '/opt/tak/renew-letsencrypt.sh']))
        svc = ('[Unit]\nDescription=TAK Server LE Cert Renewal (container)\n'
               'After=network.target docker.service\n\n[Service]\nType=oneshot\n'
               'ExecStart=/opt/tak/renew-letsencrypt.sh\n')
        timer = ('[Unit]\nDescription=TAK Server Certificate Renewal Timer\n'
                 'Requires=takserver-cert-renewal.service\n\n[Timer]\nOnCalendar=daily\n'
                 'Persistent=true\n\n[Install]\nWantedBy=timers.target\n')
        _write_priv('/etc/systemd/system/takserver-cert-renewal.service', svc)
        _write_priv('/etc/systemd/system/takserver-cert-renewal.timer', timer)
        _run_priv_chain([['systemctl', 'daemon-reload'], ['systemctl', 'enable', '--now', 'takserver-cert-renewal.timer']], 'and')
        log_fn("  ✓ Auto-renewal timer enabled (daily, content-based)")
    except Exception as _re:
        log_fn(f"  ⚠ renewal timer setup skipped: {str(_re)[:120]}")
    # Step E: restart container so 8446 picks up the LE keystore
    subprocess.run(_tak_systemctl('restart'), shell=True, capture_output=True, timeout=120)
    log_fn("  ✓ TAK Server (container) restarted — 8446 now serving the trusted cert")
    return True


def install_le_cert_on_8446(takserver_host, log_fn, wait_for_cert=True):
    """
    Install the Caddy-managed Let's Encrypt cert on TAK Server's port 8446
    so TAK clients trust the enrollment endpoint without a data package.

    Called from:
      - run_caddy_deploy  (Step 5/5) — wait_for_cert=True  (Caddy just started, cert may need a moment)
      - run_takserver_deploy (end)   — wait_for_cert=False (Caddy already running, cert should exist)

    Args:
        takserver_host: TAK Server hostname (e.g. "takserver.example.com"), must match Caddy vhost
        log_fn:         Logging function (plog or log_step)
        wait_for_cert:  If True, poll up to 120s for cert files before giving up
    """
    # v10.0.1: Docker TAK uses a container-adapted path (keytool via docker exec,
    # JKS on the shared /opt/tak mount, docker lifecycle). Native .deb path below
    # is byte-identical to pre-v10.
    if _tak_is_container():
        return _install_le_cert_on_8446_container(takserver_host, log_fn, wait_for_cert)
    import re, shutil

    _s8446 = load_settings()
    cert_pass = _get_tak_cert_password(_s8446)
    # v0.9.51 — in custom (bring-your-own-cert) mode, source 8446's keystore from the
    # operator-uploaded PEM instead of Caddy's ACME store. The CoreConfig connector patch
    # below is identical either way; only the cert/key file paths differ.
    custom_mode = (_s8446.get('ssl_mode') or '') == 'custom'
    if custom_mode:
        cert_crt, cert_key = _custom_cert_paths()
        cert_dir = os.path.dirname(cert_crt)
        cert_label = "custom"
    else:
        cert_dir = (f"/var/lib/caddy/.local/share/caddy/certificates/"
                    f"acme-v02.api.letsencrypt.org-directory/{takserver_host}")
        cert_crt = f"{cert_dir}/{takserver_host}.crt"
        cert_key = f"{cert_dir}/{takserver_host}.key"
        cert_label = "LE"
    core_config = "/opt/tak/CoreConfig.xml"

    # Optionally wait for Caddy to finish obtaining the cert (ACME only — a custom cert
    # is already on disk, so there is nothing to wait for).
    # v10.0.5 non-root: read Caddy's caddy:caddy-owned cert via the broker into
    # console-readable copies for openssl (raw os.path.exists/openssl EPERM-fail
    # SILENTLY as takwerx — the cert exists but the deploy skipped the 8446 wire-up).
    local_crt, local_key = _stage_le_cert_local(cert_crt, cert_key, wait_for_cert and not custom_mode, log_fn, cert_label)
    if not local_crt:
        log_fn(f"  ⚠ {cert_label} cert not readable at {cert_dir}")
        if custom_mode:
            log_fn("  Skipping 8446 cert install — upload a custom certificate first")
        else:
            log_fn("  Skipping 8446 cert install — cert not yet issued by Caddy")
        return False

    log_fn(f"  ✓ {cert_label} cert files found for {takserver_host}")

    # Step A: LE cert → PKCS12
    r = subprocess.run(
        f'openssl pkcs12 -export -in {shlex.quote(local_crt)} -inkey {shlex.quote(local_key)} '
        f'-out /tmp/takserver-le.p12 -name {shlex.quote(takserver_host)} -password pass:{shlex.quote(cert_pass)} 2>&1',
        shell=True, capture_output=True, text=True)
    if r.returncode != 0:
        log_fn(f"  ⚠ PKCS12 conversion failed: {r.stderr.strip()[:200]}")
        return False
    log_fn("  ✓ PKCS12 created")

    # Step B: PKCS12 → JKS
    r = subprocess.run(
        f'keytool -importkeystore -srcstorepass {shlex.quote(cert_pass)} -deststorepass {shlex.quote(cert_pass)} '
        f'-destkeystore /tmp/takserver-le.jks -srckeystore /tmp/takserver-le.p12 '
        f'-srcstoretype pkcs12 2>&1',
        shell=True, capture_output=True, text=True)
    if r.returncode != 0:
        log_fn(f"  ⚠ JKS conversion failed: {r.stderr.strip()[:200]}")
        return False

    # install(1) reads the /tmp source (broker source-permissive) and writes the
    # allowlisted /opt/tak dest as tak:tak in one step (replaces mv + chown).
    subprocess.run(_sudo_wrap([
        'install', '-o', 'tak', '-g', 'tak', '-m', '644',
        '/tmp/takserver-le.jks', '/opt/tak/certs/files/takserver-le.jks']),
        capture_output=True, text=True)
    try:
        os.remove('/tmp/takserver-le.jks')  # console-owned /tmp scratch; direct
    except OSError:
        pass
    log_fn("  ✓ JKS installed to /opt/tak/certs/files/takserver-le.jks")

    # Step C: Stop TAK Server, patch CoreConfig.xml 8446 connector, then start.
    # TAK Server overwrites CoreConfig.xml on restart with its in-memory state,
    # so we must stop it first to prevent our patch from being reverted.
    subprocess.run(_sudo_wrap(['systemctl', 'stop', 'takserver']), capture_output=True)
    time.sleep(10)
    subprocess.run('pkill -9 -f takserver 2>/dev/null; true', shell=True, capture_output=True)
    time.sleep(5)
    try:
        # v10.0.5 non-root: read/back-up/patch CoreConfig via the broker — /opt/tak is
        # tak:tak 0755 + CoreConfig.xml 0640, so raw open('w')/shutil.copy by the
        # non-root console hit [Errno 13] ('/opt/tak/CoreConfig.xml.bak-le') and the
        # 8446 connector was never patched → 8446 served the wrong keystore → WebGUI 403.
        content = _read_priv(core_config)
        _write_priv(core_config + '.bak-le', content)
        # v0.9.29 — defense-in-depth: if CoreConfig has ns0: prefixes (leftover from a
        # prior buggy _apply_coreconfig_ldap_auth_et run on an older release), strip
        # them BEFORE patching the connector. The original regex below only matched
        # `<connector ...>` and silently no-op'd on `<ns0:connector ...>`, leaving the
        # LE cert install incomplete. We also fix the regex to be namespace-tolerant
        # as a second layer of defense.
        if '<ns0:' in content or 'xmlns:ns0=' in content:
            log_fn("  ⚠ CoreConfig.xml has legacy ns0: prefixes — stripping before patch")
            content = re.sub(r'<ns0:', '<', content)
            content = re.sub(r'</ns0:', '</', content)
            content = re.sub(r'\s+xmlns:ns0="[^"]+"', '', content)
            if 'xmlns=' not in content:
                content = re.sub(
                    r'(<Configuration\b)',
                    '\\1 xmlns="http://bbn.com/marti/xml/config"',
                    content, count=1
                )
        new_connector = (
            '<connector port="8446" clientAuth="false" _name="LetsEncrypt" '
            'keystore="JKS" keystoreFile="certs/files/takserver-le.jks" '
            f'keystorePass="{cert_pass}" enableAdminUI="true" enableWebtak="true" '
            'enableNonAdminUI="false"/>'
        )
        # Namespace-tolerant regex: matches `<connector ...>` AND `<ns0:connector ...>`
        # (or any other prefix). The (?:[A-Za-z][\w-]*:)? group accepts an optional
        # XML namespace prefix before the element name. Also accept `/ >` (with space)
        # which ElementTree emits with short_empty_elements=True on some Python versions.
        patched = re.sub(
            r'<(?:[A-Za-z][\w-]*:)?connector\s+port="8446"[^/]*/\s*>',
            new_connector, content, count=1
        )
        if patched != content:
            _write_priv(core_config, patched)
            log_fn("  ✓ CoreConfig.xml 8446 connector patched to use LE cert")
            # v0.9.29 — verify the patch actually landed by reading back. Critical
            # because subtle whitespace differences or a stale file lock could leave
            # the patch unwritten, and a silent no-op here means 8446 serves the
            # cert_https default keystore instead of LE — making mobile/ATAK clients
            # show cert warnings on enrollment.
            try:
                _verify = _read_priv(core_config)
                if '_name="LetsEncrypt"' not in _verify or 'takserver-le.jks' not in _verify:
                    log_fn("  ⚠ Post-patch verify FAILED — 8446 connector did not pick up LE attrs")
                    log_fn("  ⚠ Restoring from .bak-le and aborting LE wire-up")
                    _write_priv(core_config, content)
                    return False
            except Exception as _ve:
                log_fn(f"  ⚠ Post-patch verify error: {_ve} (continuing — may need manual check)")
        else:
            log_fn("  ⚠ 8446 connector pattern not matched in CoreConfig.xml — check manually")
            log_fn(f"  ⚠ First 200 chars: {content[:200]!r}")
    except Exception as ce:
        log_fn(f"  ⚠ CoreConfig patch error: {ce}")

    # Step D: Write renewal script
    renewal_script = f'''#!/bin/bash
# TAK Server Let's Encrypt Certificate Renewal (v0.9.44)
# Re-imports Caddy's CURRENT cert into TAK's JKS whenever the keystore cert no longer
# matches Caddy's (Caddy auto-renews on its own schedule), then restarts TAK Server.
# Fixed from the old logic that gated on Caddy's days-left — which meant TAK never
# picked up Caddy's renewed cert and its keystore cert silently expired.
set -euo pipefail

TAK_DOMAIN={shlex.quote(takserver_host)}
CERT_CRT={shlex.quote(cert_crt)}
CERT_KEY={shlex.quote(cert_key)}
JKS="/opt/tak/certs/files/takserver-le.jks"
LOG_FILE="/var/log/takserver-cert-renewal.log"

log() {{ echo "[$(date -Is)] $*" | tee -a "$LOG_FILE"; }}

if [ ! -f "$CERT_CRT" ] || [ ! -f "$CERT_KEY" ]; then
  log "ERROR: Caddy cert files not found for $TAK_DOMAIN"
  exit 1
fi

# v0.9.44: sync on cert CONTENT, not Caddy's days-left. Caddy auto-renews on its own,
# so re-import whenever TAK's keystore cert differs from Caddy's current cert (or the
# keystore is missing) — otherwise the keystore keeps the old cert and silently expires.
CADDY_FP=$(openssl x509 -in "$CERT_CRT" -noout -fingerprint -sha256 2>/dev/null | cut -d= -f2)
TAK_FP=""
if [ -f "$JKS" ]; then
  TAK_FP=$(keytool -list -rfc -keystore "$JKS" -storepass {shlex.quote(cert_pass)} 2>/dev/null | openssl x509 -noout -fingerprint -sha256 2>/dev/null | cut -d= -f2)
fi

if [ -n "$TAK_FP" ] && [ "$TAK_FP" = "$CADDY_FP" ]; then
  log "TAK keystore already matches Caddy's current cert. No action."
  exit 0
fi

log "TAK keystore differs from Caddy's current cert (Caddy renewed) — refreshing keystore..."
rm -f /tmp/takserver-le.p12 /tmp/takserver-le.jks

openssl pkcs12 -export -in "$CERT_CRT" -inkey "$CERT_KEY" \\
  -out /tmp/takserver-le.p12 -name "$TAK_DOMAIN" -password pass:{shlex.quote(cert_pass)}

keytool -importkeystore -srcstorepass {shlex.quote(cert_pass)} -deststorepass {shlex.quote(cert_pass)} \\
  -destkeystore /tmp/takserver-le.jks -srckeystore /tmp/takserver-le.p12 \\
  -srcstoretype pkcs12

rm -f /opt/tak/certs/files/takserver-le.jks
mv /tmp/takserver-le.jks /opt/tak/certs/files/
chown tak:tak /opt/tak/certs/files/takserver-le.jks

systemctl restart takserver
log "TAK keystore refreshed and TAK Server restarted."
'''
    _write_priv('/opt/tak/renew-letsencrypt.sh', renewal_script, perm=0o755)
    log_fn("  ✓ Renewal script created at /opt/tak/renew-letsencrypt.sh")

    # Step E: Create systemd service + timer
    svc = '''[Unit]
Description=TAK Server Let's Encrypt Certificate Renewal
After=network.target

[Service]
Type=oneshot
ExecStart=/opt/tak/renew-letsencrypt.sh
'''
    timer = '''[Unit]
Description=TAK Server Certificate Renewal Timer
Requires=takserver-cert-renewal.service

[Timer]
OnCalendar=daily
Persistent=true

[Install]
WantedBy=timers.target
'''
    _write_priv('/etc/systemd/system/takserver-cert-renewal.service', svc)
    _write_priv('/etc/systemd/system/takserver-cert-renewal.timer', timer)
    _run_priv_chain([['systemctl', 'daemon-reload'], ['systemctl', 'enable', '--now', 'takserver-cert-renewal.timer']], 'and')
    log_fn("  ✓ Auto-renewal timer enabled (daily, content-based)")

    # Step F: Start TAK Server (was stopped in Step C before CoreConfig patch)
    log_fn("  Starting TAK Server with LE cert on port 8446...")
    subprocess.run(_sudo_wrap(['systemctl', 'start', 'takserver']), capture_output=True)
    log_fn("  ✓ TAK Server started")
    log_fn("✓ Port 8446 now serving Let's Encrypt cert — ready for TAK clients")
    return True


def _selfheal_takserver_le_cert(plog=None):
    """v0.9.44: re-sync TAK Server's 8446 Let's Encrypt cert when it has drifted from
    Caddy's current cert.

    Caddy auto-renews the LE cert on its own ~60-day cycle. The old renewal logic only
    re-imported into TAK's keystore when CADDY's cert was near expiry — so once Caddy
    renewed (resetting to ~90 days), the script said "no action" and TAK's keystore kept
    the OLD cert, which then silently expired. CloudTAK login hits TAK's 8446 enrollment
    API, so an expired keystore cert breaks login with CERT_HAS_EXPIRED (field: test6,
    2026-06-04 — every TAK CA/admin cert valid to 2028, but the 8446 LE cert lapsed).

    Here we compare the cert in TAK's keystore against Caddy's current cert and, if they
    differ or the keystore cert is expired/missing, re-run install_le_cert_on_8446() to
    repair. Runs daily via the console-restart timer; a no-op (no TAK restart) when the
    keystore already matches Caddy."""
    def _log(m):
        if plog:
            plog(m)
        else:
            print(m, flush=True)
    try:
        _renew_script = '/opt/tak/renew-letsencrypt.sh'
        _renew_unit   = '/etc/systemd/system/takserver-cert-renewal.service'
        script_present = os.path.exists(_renew_script)
        unit_present   = os.path.exists(_renew_unit)
        if not script_present and not unit_present:
            return  # box never had the LE-on-8446 setup
        settings = load_settings()
        host = _get_service_domain(settings, 'takserver')
        if not host:
            return
        # v10.0.5: a container-TAK redeploy/upgrade re-extracts /opt/tak and WIPES the
        # renewal script, while the /etc systemd unit SURVIVES — so the cert-renewal
        # timer 203/EXECs and (pre-fix) this self-heal early-returned on the missing
        # script, leaving the box stuck (renewal broken AND self-heal disabled). The
        # surviving unit is the real "LE-on-8446 was configured" sentinel; re-establish
        # the full setup (script + service + timer + keystore). Idempotent — the
        # rewritten script no-ops when the keystore already matches Caddy.
        if unit_present and not script_present:
            _log('takserver LE-cert self-heal: renewal script missing (a container '
                 'redeploy likely re-extracted /opt/tak) but box is LE-on-8446 — '
                 're-establishing renewal script + timer...')
            install_le_cert_on_8446(host, _log, wait_for_cert=False)
            return
        # v0.9.51 — source cert is the uploaded PEM in custom mode, else Caddy's ACME store.
        # v10.0.5 non-root: the takwerx console can't stat/read Caddy's 0750 store, so stage a
        # readable copy via the broker (cat as root) before os.path.exists/openssl — otherwise
        # this self-heal silently early-returns and the 8446 keystore drifts (CERT_HAS_EXPIRED).
        _heal_tmp = None
        if (settings.get('ssl_mode') or '') == 'custom':
            cert_crt, _ = _custom_cert_paths()
            if not os.path.exists(cert_crt):
                return
        else:
            _src = (f'/var/lib/caddy/.local/share/caddy/certificates/'
                    f'acme-v02.api.letsencrypt.org-directory/{host}/{host}.crt')
            _cc = subprocess.run(_sudo_wrap(['cat', _src]), capture_output=True, timeout=15)
            if _cc.returncode != 0 or not _cc.stdout:
                return  # no active cert for this host — nothing to sync from
            import tempfile as _tf
            _fd, _heal_tmp = _tf.mkstemp(suffix='.crt', prefix='le8446-heal-')
            with os.fdopen(_fd, 'wb') as _f:
                _f.write(_cc.stdout)
            cert_crt = _heal_tmp
        try:
            jks = '/opt/tak/certs/files/takserver-le.jks'
            cert_pass = _get_tak_cert_password(settings)
            caddy_fp = subprocess.run(
                f'openssl x509 -in {shlex.quote(cert_crt)} -noout -fingerprint -sha256 2>/dev/null',
                shell=True, capture_output=True, text=True, timeout=15).stdout.strip()
            tak_fp = ''
            tak_expired = True
            if os.path.exists(jks):
                kt = f'keytool -list -rfc -keystore {shlex.quote(jks)} -storepass {shlex.quote(cert_pass)} 2>/dev/null'
                tak_fp = subprocess.run(
                    f'{kt} | openssl x509 -noout -fingerprint -sha256 2>/dev/null',
                    shell=True, capture_output=True, text=True, timeout=20).stdout.strip()
                tak_expired = subprocess.run(
                    f'{kt} | openssl x509 -checkend 0 -noout',
                    shell=True, capture_output=True, timeout=20).returncode != 0
            if caddy_fp and tak_fp and caddy_fp == tak_fp and not tak_expired:
                return  # keystore already matches Caddy and is valid — nothing to do
            _log('takserver LE-cert self-heal: 8446 keystore cert stale/expired vs Caddy '
                 '— re-syncing and restarting TAK Server...')
            install_le_cert_on_8446(host, _log, wait_for_cert=False)
        finally:
            if _heal_tmp:
                try:
                    os.remove(_heal_tmp)
                except Exception:
                    pass
    except Exception as e:
        _log(f'takserver LE-cert self-heal error (non-fatal): {e}')


def run_caddy_deploy(domain):
    def plog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        caddy_deploy_log.append(entry)
        print(entry, flush=True)
    try:
        settings = load_settings()
        pkg_mgr = settings.get('pkg_mgr', 'apt')

        if pkg_mgr == 'apt':
            plog("Checking for package manager lock (unattended-upgrades)...")
            wait_for_apt_lock(plog, caddy_deploy_log)

        plog("━━━ Step 1/4: Installing Caddy ━━━")
        if pkg_mgr == 'apt':
            plog("  Adding Caddy repository...")
            cmds = [
                'apt-get install -y debian-keyring debian-archive-keyring apt-transport-https curl 2>&1',
                'curl -1sLf "https://dl.cloudsmith.io/public/caddy/stable/gpg.key" | gpg --batch --yes --dearmor -o /usr/share/keyrings/caddy-stable-archive-keyring.gpg 2>&1',
                'curl -1sLf "https://dl.cloudsmith.io/public/caddy/stable/debian.deb.txt" | tee /etc/apt/sources.list.d/caddy-stable.list 2>&1',
                'apt-get update -qq 2>&1',
            ]
            for cmd in cmds:
                # shell strings (apt-get / curl|gpg->keyring / curl|tee->sources.list):
                # the non-root console routes their privileged binaries through the
                # broker via the shim PATH (env). No-op env as root.
                r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=120,
                    env=_broker_shim_env({**os.environ, 'DEBIAN_FRONTEND': 'noninteractive', 'NEEDRESTART_MODE': 'a'}))
                if r.returncode != 0:
                    err = (r.stderr.strip() or r.stdout.strip())[:300]
                    plog(f"✗ Caddy install failed at: {cmd[:60]}")
                    plog(f"  Error: {err}")
                    caddy_deploy_status.update({'running': False, 'error': True})
                    return
            # Re-check lock before apt-get install caddy (unattended-upgrades may have started meanwhile)
            plog("  Checking package manager lock again before installing Caddy...")
            wait_for_apt_lock(plog, caddy_deploy_log)
            install_caddy_cmd = 'apt-get install -y caddy 2>&1'
            r = subprocess.run(install_caddy_cmd, shell=True, capture_output=True, text=True, timeout=120,
                env=_broker_shim_env({**os.environ, 'DEBIAN_FRONTEND': 'noninteractive', 'NEEDRESTART_MODE': 'a'}))
            if r.returncode != 0:
                err = (r.stderr.strip() or r.stdout.strip())[:300]
                if 'lock' in err.lower() or 'unattended-upgr' in err or 'unable to acquire' in err.lower():
                    plog("  System updates are using the package manager. Waiting 60s then retrying...")
                    time.sleep(60)
                    r = subprocess.run(install_caddy_cmd, shell=True, capture_output=True, text=True, timeout=120,
                        env=_broker_shim_env({**os.environ, 'DEBIAN_FRONTEND': 'noninteractive', 'NEEDRESTART_MODE': 'a'}))
                if r.returncode != 0:
                    err = (r.stderr.strip() or r.stdout.strip())[:300]
                    plog(f"✗ Caddy install failed at: apt-get install -y caddy")
                    plog(f"  Error: {err}")
                    caddy_deploy_status.update({'running': False, 'error': True})
                    return
        else:
            plog("  Installing Caddy via dnf...")
            subprocess.run(_sudo_wrap(['dnf', 'install', '-y', 'dnf-command(copr)']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=60)
            subprocess.run(_sudo_wrap(['dnf', 'copr', 'enable', '-y', '@caddy/caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=60)
            r = subprocess.run(_sudo_wrap(['dnf', 'install', '-y', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=120)
            if r.returncode != 0:
                plog(f"✗ Caddy install failed")
                caddy_deploy_status.update({'running': False, 'error': True})
                return

        # Verify install (if binary missing e.g. after uninstall, reinstall restores it)
        r = subprocess.run('which caddy', shell=True, capture_output=True, text=True)
        if r.returncode != 0 and pkg_mgr == 'apt':
            plog("  Binary missing after install; reinstalling package...")
            subprocess.run(_sudo_wrap(['apt-get', 'install', '--reinstall', '-y', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=120, env={**os.environ, 'DEBIAN_FRONTEND': 'noninteractive', 'NEEDRESTART_MODE': 'a'})
            r = subprocess.run('which caddy', shell=True, capture_output=True, text=True)
        elif r.returncode != 0 and pkg_mgr == 'dnf':
            # v10.0.1 (RHEL): on some EL9 boxes the @caddy/caddy COPR rpm reports a
            # successful install but its payload (the /usr/bin/caddy binary) never
            # extracts — `which caddy` then fails and the deploy dies here. The rpm
            # SCRIPTLETS do run, so the caddy user, systemd unit, SELinux fcontext
            # (httpd_exec_t on /usr/bin/caddy) and firewall ports are already set up;
            # only the binary is missing. Guarantee it by fetching the official
            # static build. Download to a TEMP file and VERIFY it runs before
            # installing — a partial/transient download would otherwise pass a
            # mere `which` check and then fail caddy.service with 203/EXEC. Then
            # atomically install + apply the fcontext the scriptlet set. Arch-aware.
            # Validated on Rocky 9.6 under SELinux Enforcing.
            plog("  Binary missing after dnf install (known EL9 COPR payload quirk) — installing official static binary...")
            _caddy_arch = 'arm64' if _host_arch() == 'arm64' else 'amd64'
            _caddy_dl = '/tmp/caddy.download'
            subprocess.run(f'rm -f {_caddy_dl}', shell=True, capture_output=True, text=True)
            subprocess.run(
                f'curl -fsSL --retry 3 --retry-delay 2 "https://caddyserver.com/api/download?os=linux&arch={_caddy_arch}" -o {_caddy_dl}',
                shell=True, capture_output=True, text=True, timeout=300)
            subprocess.run(_sudo_wrap(['chmod', '+x', _caddy_dl]), capture_output=True, text=True)
            # verify the downloaded binary actually executes before trusting it
            _caddy_ver = subprocess.run(f'{_caddy_dl} version', shell=True, capture_output=True, text=True, timeout=20)
            if _caddy_ver.returncode == 0:
                subprocess.run(_sudo_wrap(['install', '-m', '0755', _caddy_dl, '/usr/bin/caddy']), capture_output=True, text=True, timeout=30)
                # label for SELinux (rpm scriptlet already added the httpd_exec_t fcontext rule);
                # fall back to chcon if restorecon has no rule, no-op if SELinux disabled.
                _run_priv_chain([['restorecon', '-v', '/usr/bin/caddy'], ['chcon', '-t', 'httpd_exec_t', '/usr/bin/caddy']], 'or')
                subprocess.run(_sudo_wrap(['mkdir', '-p', '/etc/caddy']), capture_output=True, text=True)
                plog(f"  ✓ official static caddy {(_caddy_ver.stdout or '').split()[0] if _caddy_ver.stdout else ''} installed")
            else:
                plog(f"  ✗ static caddy download did not validate: {((_caddy_ver.stderr or _caddy_ver.stdout) or 'no output').strip()[:160]}")
            subprocess.run(f'rm -f {_caddy_dl}', shell=True, capture_output=True, text=True)
            # functional final check (not mere presence) so we never false-report success
            r = subprocess.run('caddy version', shell=True, capture_output=True, text=True)
        if r.returncode != 0:
            plog("✗ Caddy binary not found after install")
            caddy_deploy_status.update({'running': False, 'error': True})
            return
        plog("✓ Caddy installed")

        plog("")
        plog("━━━ Step 2/4: Generating Caddyfile ━━━")
        plog(f"  Domain: {domain}")
        caddyfile = generate_caddyfile(settings)
        plog(f"  Generated Caddyfile ({len(caddyfile)} bytes)")
        plog("✓ Caddyfile written to /etc/caddy/Caddyfile")

        plog("")
        plog("━━━ Step 3/4: Configuring Firewall ━━━")
        # Open ports 80, 443, and 5001 (backdoor) so console is reachable before/after Caddy
        # Open 80/443 (Caddy) + 5001 (console backdoor) via the family-gated backend.
        # Do NOT detect with `which ufw`/`which firewall-cmd`: the broker shims put BOTH
        # tools on the console PATH on EVERY platform, so `which` always matches and a
        # Debian box would wrongly drive firewalld (and a RHEL box ufw) → FileNotFound
        # ERROR in the broker audit. _fw_allow()/_fw_backend() gate on _distro_family().
        be = _fw_backend()
        for _p in (80, 443, 5001):
            _fw_allow(_p, 'tcp')
        if be:
            plog(f"  ✓ {be}: ports 80, 443, 5001 (backdoor) opened")
        plog("✓ Firewall configured")

        plog("")
        plog("━━━ Step 4/4: Starting Caddy ━━━")
        # v10.0.1 (RHEL): the @caddy/caddy COPR rpm intermittently leaves /usr/bin/caddy
        # MISSING even after a `which caddy` passed at install — the binary can extract and
        # then vanish before we get here (rpm -V shows it `missing`; systemd then dies with
        # 203/EXEC). Re-verify FUNCTIONALLY right before start and self-heal with the official
        # static binary, so a missing/broken binary can never reach systemd. Idempotent.
        if pkg_mgr == 'dnf' and subprocess.run('caddy version', shell=True, capture_output=True).returncode != 0:
            plog("  Caddy binary missing/non-functional before start — installing official static binary…")
            _ca = 'arm64' if _host_arch() == 'arm64' else 'amd64'
            subprocess.run('rm -f /tmp/caddy.download', shell=True, capture_output=True)
            subprocess.run(f'curl -fsSL --retry 3 --retry-delay 2 "https://caddyserver.com/api/download?os=linux&arch={_ca}" -o /tmp/caddy.download',
                           shell=True, capture_output=True, timeout=300)
            try:
                os.chmod('/tmp/caddy.download', 0o755)  # console-owned /tmp scratch; direct
            except OSError:
                pass
            _cv = subprocess.run('/tmp/caddy.download version', shell=True, capture_output=True, text=True, timeout=20)
            if _cv.returncode == 0:
                subprocess.run(_sudo_wrap(['install', '-m', '0755', '/tmp/caddy.download', '/usr/bin/caddy']), capture_output=True, timeout=30)
                _run_priv_chain([['restorecon', '-v', '/usr/bin/caddy'], ['chcon', '-t', 'httpd_exec_t', '/usr/bin/caddy']], 'or')
                plog(f"  ✓ official static caddy {(_cv.stdout or '').split()[0] if _cv.stdout else ''} installed")
            else:
                plog(f"  ✗ static caddy download did not validate: {((_cv.stderr or _cv.stdout) or 'no output').strip()[:160]}")
            subprocess.run('rm -f /tmp/caddy.download', shell=True, capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'enable', 'caddy']), capture_output=True)
        r = subprocess.run(_sudo_wrap(['systemctl', 'restart', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        if r.returncode != 0:
            plog(f"⚠ systemctl restart: {(r.stderr or r.stdout or '').strip()[:300]}")
        time.sleep(3)
        r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'caddy']), capture_output=True, text=True)
        if r.stdout.strip() == 'active':
            plog("✓ Caddy is running")
        else:
            plog("✗ Caddy did not start. Capturing status and logs:")
            status = subprocess.run(_sudo_wrap(['systemctl', 'status', 'caddy', '--no-pager', '-l']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10)
            if status.stdout:
                for line in (status.stdout or '').strip().split('\n')[:15]:
                    plog(f"  {line}")
            journal = subprocess.run('journalctl -u caddy -n 25 --no-pager 2>&1', shell=True, capture_output=True, text=True, timeout=10, env=_broker_shim_env())
            if journal.stdout:
                plog("  --- journalctl -u caddy (last 25 lines) ---")
                for line in (journal.stdout or '').strip().split('\n'):
                    plog(f"  {line}")
            caddy_deploy_status.update({'running': False, 'error': True})
            return

        # Update settings — preserve a custom SSL mode chosen at deploy time; only the
        # Let's Encrypt path owns ssl_mode='fqdn' (v0.9.51).
        custom_mode = (settings.get('ssl_mode') or '') == 'custom'
        if not custom_mode:
            settings['ssl_mode'] = 'fqdn'
        save_settings(settings)

        plog("")
        plog("=" * 50)
        plog(f"✓ Caddy deployed successfully!")
        plog(f"  Domain: https://{domain}")
        if custom_mode:
            plog(f"  SSL: Custom certificate (your uploaded cert — no ACME)")
        else:
            plog(f"  SSL: Let's Encrypt (automatic)")
            plog("  Note: DNS must point to this server's IP for SSL to activate")
        plog("=" * 50)
        caddy_deploy_status.update({'running': False, 'complete': True})

    except Exception as e:
        plog(f"✗ Error: {str(e)}")
        caddy_deploy_status.update({'running': False, 'error': True})

def _get_takportal_version_info():
    """Return {version: str, update_available: bool, latest: str|None} for TAK Portal.
    Version from package.json; update status from container logs [update-check] line."""
    import re
    portal_dir = os.path.expanduser('~/TAK-Portal')
    out = {'version': '', 'update_available': False, 'latest': None}
    # Prefer package.json version (semantic version)
    pkg_path = os.path.join(portal_dir, 'package.json')
    if os.path.isfile(pkg_path):
        try:
            with open(pkg_path) as f:
                data = json.load(f)
            out['version'] = (data.get('version') or '').strip()
        except Exception:
            pass
    if not out['version'] and os.path.isdir(os.path.join(portal_dir, '.git')):
        rv = subprocess.run(f'cd {portal_dir} && git describe --tags --always 2>/dev/null || git log -1 --format="%h"', shell=True, capture_output=True, text=True, timeout=5)
        if rv.returncode == 0 and rv.stdout.strip():
            out['version'] = rv.stdout.strip()
    # If container is running, parse last [update-check] line for update_available
    r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '-q']), capture_output=True, text=True, timeout=5)
    if r.returncode == 0 and (r.stdout or '').strip():
        log_r = subprocess.run(_sudo_wrap(['docker', 'logs', 'tak-portal', '--tail', '200']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10)
        if log_r.stdout:
            for line in reversed(log_r.stdout.strip().split('\n')):
                if '[update-check]' in line:
                    # e.g. [update-check] current=1.2.19 latest=1.2.20 update=true
                    m = re.search(r'latest=([^\s]+)', line)
                    if m:
                        out['latest'] = m.group(1).strip()
                    if 'update=true' in line:
                        out['update_available'] = True
                    break
    return out


def _get_takserver_version_info():
    """Return {version: str, update_available: bool, latest: None} for TAK Server from installed package."""
    out = {'version': '', 'update_available': False, 'latest': None}
    if not os.path.exists('/opt/tak') or not os.path.exists('/opt/tak/CoreConfig.xml'):
        return out
    # dpkg-query (NOT the shimmed `dpkg`) — runs direct as the console user, read-only and fast,
    # and is NOT routed through the broker. A shimmed `dpkg -s` round-trips the broker and can be
    # slow/denied under the live gunicorn console, which silently blanked the version on Ubuntu.
    for pkg in ('takserver', 'takserver-core', 'takserver-database'):
        try:
            r = subprocess.run(['dpkg-query', '-W', '-f=${Version}', pkg], capture_output=True, text=True, timeout=5)
        except (FileNotFoundError, OSError):
            break  # no dpkg-query on RHEL — fall through to the rpm check below
        if r.returncode == 0 and r.stdout.strip():
            out['version'] = r.stdout.strip()
            return out
    r = subprocess.run("rpm -q takserver 2>/dev/null", shell=True, capture_output=True, text=True, timeout=5)
    if r.returncode == 0 and r.stdout.strip():
        ver = r.stdout.strip()
        if ver.startswith('takserver-'):
            ver = ver.split('-', 1)[1]
        if '.noarch' in ver:
            ver = ver.replace('.noarch', '')
        if ver:
            out['version'] = ver
    # Container: TAK isn't a dpkg/rpm package — derive the version from the bundle dir name
    # (/opt/tak -> .../takserver-docker-X.X-RELEASE-XX/tak), so the cards/page show a version
    # on arm64/container the same as native dpkg/rpm.
    if not out['version'] and _tak_is_container():
        try:
            _base = os.path.basename(os.path.dirname(os.path.realpath('/opt/tak')))  # takserver-docker-X.X-RELEASE-XX
            _pfx = 'takserver-docker-'
            if _base.startswith(_pfx):
                out['version'] = _base[len(_pfx):].replace('RELEASE-', 'RELEASE')  # 5.7-RELEASE-43 -> 5.7-RELEASE43
        except Exception:
            pass
    return out


def _get_fedhub_version_info():
    """Return {version, update_available, latest} for takserver-fed-hub on the remote Fed Hub host (dpkg)."""
    out = {'version': '', 'update_available': False, 'latest': None}
    settings = load_settings()
    cfg = _get_fedhub_deployment_config(settings)
    if not cfg.get('deployed') or (cfg.get('target_mode') or '') != 'remote':
        return out
    remote = cfg.get('remote') or {}
    if not (remote.get('host') or '').strip():
        return out
    pkg = 'takserver-fed-hub'
    cmd = f"dpkg-query -W -f'${{Version}}' {shlex.quote(pkg)} 2>/dev/null"
    ok, ver_out = _ssh_probe(remote, cmd, timeout=15)
    ver = (ver_out or '').strip()
    if not ver:
        cmd2 = f"dpkg -s {shlex.quote(pkg)} 2>/dev/null | sed -n 's/^Version: //p'"
        ok2, ver2 = _ssh_probe(remote, cmd2, timeout=15)
        if ok2:
            ver = (ver2 or '').strip()
    if ver:
        out['version'] = ver
    return out


def _get_caddy_version_info():
    """Return {version: str, update_available: bool} for Caddy."""
    out = {'version': '', 'update_available': False}
    try:
        r = subprocess.run('caddy version 2>/dev/null', shell=True, capture_output=True, text=True, timeout=5)
        if r.returncode == 0 and r.stdout:
            import re
            m = re.search(r'v(\d+\.\d+\.\d+[^\s]*)', r.stdout)
            if m:
                out['version'] = 'v' + m.group(1).strip()
        if out['version']:
            # Family-branched: bare `apt` on RHEL raised FileNotFoundError every
            # poll (benign but noisy in the broker audit log — seen on aws-rocky).
            if _distro_family() == 'rhel':
                chk = _priv_pipe(['dnf', '-q', 'check-update', 'caddy'], ['grep', '-i', 'caddy'], timeout=15)
            else:
                chk = _priv_pipe(['apt', 'list', '--upgradable'], ['grep', '-i', 'caddy'], timeout=10)
            if chk.returncode == 0 and (chk.stdout or '').strip():
                out['update_available'] = True
    except (subprocess.TimeoutExpired, OSError):
        pass
    return out


_authentik_release_cache = {'tag': None, 'ts': 0}

def _get_authentik_latest_release_tag(use_cache=True):
    """Fetch the latest stable Authentik release tag from GitHub (e.g. '2026.2.1').
    Cached for 4 hours to avoid hitting GitHub API on every page load."""
    import time as _time
    if use_cache and _authentik_release_cache['tag'] and (_time.time() - _authentik_release_cache['ts'] < 14400):
        return _authentik_release_cache['tag']
    try:
        import urllib.request as _ur
        req = _ur.Request('https://api.github.com/repos/goauthentik/authentik/releases/latest',
                          headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'})
        resp = _ur.urlopen(req, timeout=10)
        data = json.loads(resp.read().decode())
        tag = (data.get('tag_name') or '').strip()
        if tag.startswith('version/'):
            tag = tag[len('version/'):]
        tag = tag.lstrip('vV').strip() or None
        if tag:
            _authentik_release_cache['tag'] = tag
            _authentik_release_cache['ts'] = _time.time()
        return tag
    except Exception:
        return _authentik_release_cache.get('tag')


def _get_authentik_target_release(settings=None):
    """Return the operator-approved Authentik version for this box's channel.

    Dev channel (update_channel='dev' in settings.json): AUTHENTIK_DEV_RELEASE — the
    version currently under validation by the operator.

    Main channel (default): AUTHENTIK_VETTED_RELEASE — the last fleet-validated release.
    Customers on main are never offered an Authentik version that hasn't been explicitly
    vetted and promoted by bumping AUTHENTIK_VETTED_RELEASE in a new infra-TAK release.
    """
    if settings is None:
        settings = load_settings()
    channel = (settings.get('update_channel') or 'main').strip().lower()
    return AUTHENTIK_DEV_RELEASE if channel == 'dev' else AUTHENTIK_VETTED_RELEASE


def _get_authentik_version_info():
    """Return {version: str, update_available: bool, latest: str|None} for Authentik."""
    out = {'version': '', 'update_available': False, 'latest': None}
    import re
    ak_dir = os.path.expanduser('~/authentik')
    compose_path = os.path.join(ak_dir, 'docker-compose.yml')
    if os.path.isfile(compose_path):
        try:
            with open(compose_path) as f:
                content = f.read()
            m = re.search(r'AUTHENTIK_TAG:-([^\s}]+)', content)
            if m:
                out['version'] = m.group(1).strip()
            if not out['version']:
                m = re.search(r'image:.*?/server:([^\s\n]+)', content)
                if m:
                    out['version'] = m.group(1).strip()
        except Exception:
            pass
    if not out['version']:
        try:
            r = subprocess.run(_sudo_wrap(['docker', 'images', '--format', '{{.Tag}}', 'ghcr.io/goauthentik/server']), capture_output=True, text=True, timeout=5)
            if r.returncode == 0 and r.stdout.strip():
                out['version'] = r.stdout.strip().split('\n')[0]
        except Exception:
            pass
    if not out['version']:
        try:
            settings = load_settings()
            ak_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
            if ak_cfg.get('target_mode') == 'remote' and ak_cfg.get('deployed') and (ak_cfg.get('remote', {}).get('host') or '').strip():
                ok, remote_out = _ssh_probe(ak_cfg['remote'],
                    'docker images ghcr.io/goauthentik/server --format "{{.Tag}}" 2>/dev/null | head -1', timeout=10)
                if ok and remote_out and remote_out.strip():
                    out['version'] = remote_out.strip()
                if not out['version']:
                    ok, remote_out = _ssh_probe(ak_cfg['remote'],
                        'grep -m1 "AUTHENTIK_TAG" ~/authentik/docker-compose.yml 2>/dev/null', timeout=10)
                    if ok and remote_out:
                        m = re.search(r'AUTHENTIK_TAG:-(\d+\.\d+\.\d+[^\s}\']*)', remote_out)
                        if m:
                            out['version'] = m.group(1).strip()
        except Exception:
            pass
    # Compare against channel-appropriate vetted target (not raw GitHub latest).
    # Main channel → AUTHENTIK_VETTED_RELEASE; dev channel → AUTHENTIK_DEV_RELEASE.
    # update_available is only True when target > installed (never show a downgrade badge).
    _s = load_settings()
    _channel = (_s.get('update_channel') or 'main').strip().lower()
    target = _get_authentik_target_release(_s)
    out['latest'] = target
    out['vetted_release'] = AUTHENTIK_VETTED_RELEASE
    out['dev_release'] = AUTHENTIK_DEV_RELEASE
    out['channel'] = _channel
    out['ahead_of_vetted'] = False
    if out['version']:
        installed = re.sub(r'^[vV\$\{AUTHENTIK_TAG:-]*', '', out['version']).rstrip('}').strip()
        out['version'] = installed
        if installed and installed != target:
            # Only flag as update_available if target is strictly newer (no downgrade badge)
            try:
                _t = tuple(int(x) for x in re.findall(r'\d+', target))
                _i = tuple(int(x) for x in re.findall(r'\d+', installed))
                if _t > _i:
                    out['update_available'] = True
                elif _i > _t and _channel == 'main':
                    # Installed is newer than fleet-vetted — flag so UI doesn't misleadingly show "vetted ✓"
                    out['ahead_of_vetted'] = True
            except Exception:
                out['update_available'] = True
    # Dev channel only: surface when UPSTREAM has shipped a release newer than our pin,
    # so the operator learns about new Authentik releases (e.g. a bugfix) without anyone
    # editing the pin first. Awareness ONLY — never changes what Update installs (the pin).
    # No GitHub call on main: main stays pinned-and-quiet by design.
    out['upstream_latest'] = None
    out['upstream_newer'] = False
    if _channel == 'dev':
        try:
            _up = _get_authentik_latest_release_tag()
            if _up:
                out['upstream_latest'] = _up
                _pin = tuple(int(x) for x in re.findall(r'\d+', target))
                _ut = tuple(int(x) for x in re.findall(r'\d+', _up))
                if _ut > _pin:
                    out['upstream_newer'] = True
        except Exception:
            pass
    return out


def _get_nodered_version_info():
    """Return {version: str, update_available: bool} for Node-RED from container or image."""
    out = {'version': '', 'update_available': False}
    r = subprocess.run(_sudo_wrap(['docker', 'ps', '-q', '-f', 'name=nodered']), capture_output=True, text=True, timeout=5)
    if not (r.returncode == 0 and (r.stdout or '').strip()):
        return out
    # Try to get version from container (Node-RED package.json)
    ex = subprocess.run(_sudo_wrap(['docker', 'exec', 'nodered', 'node', '-p', "try{require('/usr/src/node-red/package.json').version}catch(e){''}"]), capture_output=True, text=True, timeout=5)
    if ex.returncode == 0 and ex.stdout.strip():
        out['version'] = ex.stdout.strip().strip('"\'')
    if not out['version']:
        out['version'] = 'latest'
    return out


_cloudtak_release_cache = {'tag': None, 'ts': 0}

def _get_cloudtak_latest_release_tag(use_cache=True):
    """Fetch the latest stable release tag from GitHub (e.g. 'v12.94.0').
    Cached for 4 hours to avoid hitting GitHub API on every page load.
    Pass use_cache=False during deploy to get a fresh result.
    Returns the tag string, or None if the API call fails."""
    import time as _time
    if use_cache and _cloudtak_release_cache['tag'] and (_time.time() - _cloudtak_release_cache['ts'] < 14400):
        return _cloudtak_release_cache['tag']
    try:
        import urllib.request as _ur
        req = _ur.Request('https://api.github.com/repos/dfpc-coe/CloudTAK/releases/latest',
                          headers={'Accept': 'application/vnd.github+json', 'User-Agent': 'infra-TAK'})
        with _ur.urlopen(req, timeout=15) as resp:
            data = json.loads(resp.read().decode())
            tag = (data.get('tag_name') or '').strip() or None
            if tag:
                _cloudtak_release_cache['tag'] = tag
                _cloudtak_release_cache['ts'] = _time.time()
            return tag
    except Exception:
        # Stale cache is better than nothing — return it regardless of use_cache so that
        # a GitHub rate-limit or cold-start doesn't hard-block the update flow.
        return _cloudtak_release_cache.get('tag') or None


def _get_cloudtak_version_info():
    """Return {version: str, update_available: bool, latest: str|None} for CloudTAK.

    Version resolution order:
    0. The RUNNING cloudtak-api container's package.json — authoritative for what is
       actually serving. The git source tree is NOT a reliable version signal: a
       FAILED "Update Now" checks out the new tag BEFORE the (failed) image rebuild,
       so the source sits at e.g. v13.10.0 while the container still runs v13.4.0.
       Reading git first made the console report the un-built version (caught on
       test12 2026-06-07: source v13.10.0, container v13.4.0). Prefer the container.
    1. git describe --tags --exact-match: if HEAD is exactly at a release tag, use the
       tag name (authoritative even when package.json lags — dfpc-coe sometimes tags
       before bumping package.json). Used only when no container is running.
    2. package.json (api/ or web/) in the source tree.
    3. git describe --tags --always fallback for everything else.
    """
    import re
    out = {'version': '', 'update_available': False, 'latest': None}
    ct_dir = os.path.expanduser('~/CloudTAK')
    # Step 0: prefer the RUNNING container's version (what's actually serving).
    try:
        rcid = subprocess.run(_sudo_wrap(['docker', 'ps', '-q', '-f', 'name=cloudtak-api']), capture_output=True, text=True, timeout=5)
        _cid_lines = (rcid.stdout or '').strip().splitlines() if rcid.returncode == 0 else []
        _api_id = _cid_lines[0].strip() if _cid_lines else ''
        if _api_id:
            rv = subprocess.run(
                _sudo_wrap(['docker', 'exec', _api_id, 'node', '-e', "process.stdout.write(require('/home/etl/api/package.json').version)"]), capture_output=True, text=True, timeout=8)
            ver = (rv.stdout or '').strip()
            if rv.returncode == 0 and re.match(r'^\d+\.\d+\.\d+', ver):
                out['version'] = ver
    except Exception:
        pass
    # Step 1: prefer exact git tag — authoritative even when package.json lags
    if not out['version'] and os.path.isdir(os.path.join(ct_dir, '.git')):
        try:
            rv = subprocess.run(
                f'git -C {ct_dir} describe --tags --exact-match HEAD 2>/dev/null',
                shell=True, capture_output=True, text=True, timeout=5)
            if rv.returncode == 0 and rv.stdout.strip():
                out['version'] = rv.stdout.strip().lstrip('vV')
        except Exception:
            pass
    # Step 2: package.json when not at an exact tag
    if not out['version']:
        for pkg in ['package.json', 'api/package.json', 'web/package.json']:
            pkg_path = os.path.join(ct_dir, pkg)
            if os.path.isfile(pkg_path):
                try:
                    with open(pkg_path) as f:
                        data = json.load(f)
                    out['version'] = (data.get('version') or '').strip()
                    if out['version']:
                        break
                except Exception:
                    pass
    # Step 3: git describe fallback
    if not out['version'] and os.path.isdir(os.path.join(ct_dir, '.git')):
        rv = subprocess.run(f'cd {ct_dir} && git describe --tags --always 2>/dev/null || git log -1 --format="%h"', shell=True, capture_output=True, text=True, timeout=5)
        if rv.returncode == 0 and rv.stdout.strip():
            out['version'] = rv.stdout.strip().lstrip('vV')
    r = subprocess.run(_sudo_wrap(['docker', 'ps', '-q', '-f', 'name=cloudtak-api']), capture_output=True, text=True, timeout=5)
    # Guard: docker ps -q returns empty (rc 0) when no container is running — e.g.
    # the post-update recreate window. `''.splitlines()[0]` was an IndexError → 500
    # on /api/modules/version while CloudTAK was being recreated (caught in v0.9.48 T&E).
    _ct_lines = (r.stdout or '').strip().splitlines() if r.returncode == 0 else []
    _ct_api_id = _ct_lines[0].strip() if _ct_lines else ''
    if _ct_api_id:
        log_r = subprocess.run(_sudo_wrap(['docker', 'logs', _ct_api_id, '--tail', '150']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10)
        if log_r.stdout:
            for line in reversed(log_r.stdout.strip().split('\n')):
                if '[update-check]' in line:
                    m = re.search(r'latest=([^\s]+)', line)
                    if m:
                        out['latest'] = m.group(1).strip()
                    if 'update=true' in line:
                        out['update_available'] = True
                    break
    if out['version'] and not out['latest']:
        tag = _get_cloudtak_latest_release_tag()
        if tag:
            latest_ver = tag.lstrip('vV')
            out['latest'] = latest_ver
            if out['version'] != latest_ver:
                out['update_available'] = True
    # v0.9.54: suppress a FALSE "update available" caused by the container's
    # api/package.json lagging the git release tag. dfpc-coe ships release tags
    # whose api/package.json trails the tag — and the lag now crosses a MINOR
    # boundary (the v13.14.0 tag carries api/package.json 13.13.0, root 13.14.0).
    # The v0.9.49 gate compared the container's major.minor to the LATEST TAG's
    # major.minor (13.13 vs 13.14) and so wrongly kept the badge lit on a fully
    # up-to-date box, making every Update Now look like a no-op (caught on test12
    # 2026-06-12: HEAD v13.14.0, container 13.13.0, badge stuck).
    #
    # Correct signal: the box is current iff ~/CloudTAK HEAD is checked out
    # EXACTLY at the latest release tag AND the running container's version equals
    # the version baked into THAT tag's api/package.json (what a correct rebuild
    # produces — the container reads /home/etl/api/package.json, so compare against
    # the source api/package.json, never the tag string or root package.json).
    # If the container is behind the source api/package.json, the rebuild did not
    # land (source moved, image didn't) — keep showing the update.
    if out['update_available'] and out['version'] and out['latest']:
        try:
            _latest_norm = out['latest'].lstrip('vV')
            _src = subprocess.run(
                f'git -C {ct_dir} describe --tags --exact-match HEAD 2>/dev/null',
                shell=True, capture_output=True, text=True, timeout=5)
            _src_tag = (_src.stdout or '').strip().lstrip('vV')
            if _src_tag and _src_tag == _latest_norm:
                _src_api_ver = ''
                _api_pkg = os.path.join(ct_dir, 'api', 'package.json')
                if os.path.isfile(_api_pkg):
                    try:
                        with open(_api_pkg) as _f:
                            _src_api_ver = (json.load(_f).get('version') or '').strip()
                    except Exception:
                        _src_api_ver = ''
                if _src_api_ver and out['version'] == _src_api_ver:
                    out['update_available'] = False
                    # Display the tag version (e.g. 13.14.0), NOT the lagging
                    # container api/package.json string (13.13.0). The box runs
                    # the latest tag's code — only dfpc's internal version field
                    # lags (#1479) — so showing the stale number reads as "the
                    # update didn't take" even though the box is fully current.
                    out['version'] = _src_tag
        except Exception:
            pass
    return out


def _get_mediamtx_editor_version_info(deploy_cfg):
    """Return {version: str, update_available: bool, latest: str|None} for MediaMTX web editor (takwerx/mediamtx-installer).
    Current from CURRENT_VERSION in /opt/mediamtx-webeditor/mediamtx_config_editor.py on target."""
    import re as _re
    out = {'version': '', 'update_available': False, 'latest': None}
    # Current: grep CURRENT_VERSION from editor script on target
    cmd = 'grep -oE \'CURRENT_VERSION = "[^"]+"\' /opt/mediamtx-webeditor/mediamtx_config_editor.py 2>/dev/null | head -1'
    if deploy_cfg.get('target_mode') == 'remote' and (deploy_cfg.get('remote', {}).get('host') or '').strip():
        ok, raw = _module_run(deploy_cfg, cmd, timeout=10)
        if ok and raw:
            m = _re.search(r'"([^"]+)"', raw)
            if m:
                out['version'] = m.group(1).lstrip('vV')
    else:
        editor_path = '/opt/mediamtx-webeditor/mediamtx_config_editor.py'
        if os.path.isfile(editor_path):
            try:
                with open(editor_path) as f:
                    for line in f:
                        if 'CURRENT_VERSION' in line:
                            m = _re.search(r'["\']([vV]?[^"\']+)["\']', line)
                            if m:
                                out['version'] = m.group(1).lstrip('vV')
                            break
            except Exception:
                pass
    # Latest from takwerx/mediamtx-installer releases/latest
    try:
        req = _ur.Request(
            'https://api.github.com/repos/takwerx/mediamtx-installer/releases/latest',
            headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'})
        with _ur.urlopen(req, timeout=15) as resp:
            data = json.loads(resp.read().decode())
        tag = (data or {}).get('tag_name') or ''
        if tag:
            out['latest'] = tag.lstrip('vV')
            if out['version'] and out['latest']:
                cur_parts = [int(x) for x in _re.findall(r'\d+', out['version'])[:3]]
                lat_parts = [int(x) for x in _re.findall(r'\d+', out['latest'])[:3]]
                while len(cur_parts) < 3:
                    cur_parts.append(0)
                while len(lat_parts) < 3:
                    lat_parts.append(0)
                if lat_parts > cur_parts:
                    out['update_available'] = True
            elif out['latest']:
                out['update_available'] = True
    except Exception:
        pass
    return out


def _get_mediamtx_version_info():
    """Return version/update for MediaMTX binary (bluenviron/mediamtx) and web editor (takwerx/mediamtx-installer).
    Card shows update if either has an update; page shows both."""
    import re as _re
    out = {'version': '', 'update_available': False, 'latest': None,
           'editor_version': '', 'editor_update_available': False, 'editor_latest': None}
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
    # Binary: current from target, latest from bluenviron/mediamtx
    if deploy_cfg.get('target_mode') == 'remote' and (deploy_cfg.get('remote', {}).get('host') or '').strip():
        ok, raw = _module_run(deploy_cfg, '/usr/local/bin/mediamtx -version 2>/dev/null', timeout=10)
        if ok and raw:
            m = _re.search(r'v?(\d+\.\d+\.\d+)', raw)
            if m:
                out['version'] = m.group(1)
    else:
        # Local: try /usr/local/bin/mediamtx then PATH; capture both stdout and stderr; try --version if -version fails
        def _run_ver(cmd):
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=5)
            combined = (r.stdout or '') + (r.stderr or '')
            match = _re.search(r'v?(\d+\.\d+\.\d+)', combined)
            return match.group(1) if match else None
        for bin_path in ('/usr/local/bin/mediamtx', 'mediamtx'):
            if bin_path == 'mediamtx' or (os.path.isfile(bin_path) and os.access(bin_path, os.X_OK)):
                out['version'] = _run_ver(f'{bin_path} -version 2>&1') or _run_ver(f'{bin_path} --version 2>&1')
                if out['version']:
                    break
    try:
        req = _ur.Request(
            'https://api.github.com/repos/bluenviron/mediamtx/releases/latest',
            headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'})
        with _ur.urlopen(req, timeout=15) as resp:
            data = json.loads(resp.read().decode())
        tag = (data or {}).get('tag_name') or ''
        if tag:
            out['latest'] = tag.lstrip('vV')
            if out['version'] and out['latest']:
                cur_parts = [int(x) for x in _re.findall(r'\d+', out['version'])[:3]]
                lat_parts = [int(x) for x in _re.findall(r'\d+', out['latest'])[:3]]
                while len(cur_parts) < 3:
                    cur_parts.append(0)
                while len(lat_parts) < 3:
                    lat_parts.append(0)
                if lat_parts > cur_parts:
                    out['update_available'] = True
            elif out['latest']:
                out['update_available'] = True
    except Exception:
        pass
    # Web editor: current from CURRENT_VERSION on target, latest from takwerx/mediamtx-installer
    editor_info = _get_mediamtx_editor_version_info(deploy_cfg)
    out['editor_version'] = editor_info.get('version') or ''
    out['editor_update_available'] = editor_info.get('update_available', False)
    out['editor_latest'] = editor_info.get('latest')
    if out['editor_update_available']:
        out['update_available'] = True
    return out


def _get_fail2ban_version_info():
    """Return {version, update_available, latest} for the fail2ban console card."""
    import re as _re_f2bv
    installed_raw = _f2b_get_version()  # e.g. "Fail2Ban v1.1.0"
    installed = None
    if installed_raw:
        m = _re_f2bv.search(r'v?(\d[\d.]+)', installed_raw)
        installed = m.group(1) if m else None
    available = _f2b_get_available_version()  # e.g. "1.1.0-1"
    update_available = False
    if installed and available:
        av_clean = available.split('-')[0].split('+')[0]
        try:
            def _tv(v):
                return tuple(int(p) for p in v.split('.')[:3])
            update_available = _tv(av_clean) > _tv(installed)
        except Exception:
            pass
    return {'version': installed, 'update_available': update_available, 'latest': available}


def _get_webodm_version_info():
    """Return {version, update_available, latest} for the running WebODM instance."""
    import subprocess as _sp
    import json as _json
    info = {'version': '', 'update_available': False, 'latest': None}
    try:
        r = _sp.run(
            _sudo_wrap(['docker', 'exec', 'webapp', 'python3', '-c',
             'import json; d=json.load(open("/webodm/package.json")); print(d["version"])']),
            capture_output=True, text=True, timeout=10)
        v = r.stdout.strip()
        if v:
            info['version'] = v
    except Exception:
        pass
    try:
        import urllib.request as _ur
        req = _ur.Request('https://api.github.com/repos/WebODM/WebODM/releases/latest',
                          headers={'User-Agent': 'infra-TAK'})
        resp = _ur.urlopen(req, timeout=8)
        data = _json.loads(resp.read())
        latest = data.get('tag_name', '').lstrip('v')
        if latest:
            info['latest'] = latest
            if info['version']:
                def _tv(s):
                    try: return tuple(int(x) for x in s.replace('-alpha','').replace('-beta','').split('.')[:3])
                    except: return (0,)
                info['update_available'] = _tv(latest) > _tv(info['version'])
    except Exception:
        pass
    return info


_tvr_release_cache = {'sha': None, 'ts': 0}


def _get_tvr_latest_commit_sha(use_cache=True):
    """Latest commit SHA (full) on main for raytheonbbn/tak-video-restreamer.
    The repo ships off main with no releases, so the commit SHA is the only
    version signal. Cached 4h — like CloudTAK/Authentik — because this lookup
    runs on every dashboard poll AND every TVR page load; unauthenticated GitHub
    is 60 req/hr/IP, and a 403 would otherwise silently blank the update badge.
    Returns stale cache on failure rather than None so a rate-limit doesn't hide
    a known-available update. Pass use_cache=False to force a fresh check."""
    import time as _time
    if use_cache and _tvr_release_cache['sha'] and (_time.time() - _tvr_release_cache['ts'] < 14400):
        return _tvr_release_cache['sha']
    try:
        import urllib.request as _ur
        req = _ur.Request('https://api.github.com/repos/raytheonbbn/tak-video-restreamer/commits/main',
                          headers={'Accept': 'application/vnd.github+json', 'User-Agent': 'infra-TAK'})
        with _ur.urlopen(req, timeout=10) as resp:
            sha = (json.loads(resp.read().decode()).get('sha') or '').strip() or None
            if sha:
                _tvr_release_cache['sha'] = sha
                _tvr_release_cache['ts'] = _time.time()
            return sha
    except Exception as e:
        print(f"version-info: tvr latest-commit check failed (non-fatal): {e}", flush=True)
        return _tvr_release_cache.get('sha') or None


def _broker_compose(dirpath, action, timeout=300):
    """Run `docker compose <action>` for a module dir WITHOUT a shell (v10.0.8 §A:
    the broker denies bash, so the old `bash -lc cd <dir> && docker compose …`
    pattern WOULD-DENY'd on every poll). `--project-directory` is equivalent to
    the cd: project name (dir basename), .env discovery, and relative binds all
    resolve from the project directory."""
    return subprocess.run(
        _sudo_wrap(['docker', 'compose', '--project-directory', dirpath] + shlex.split(action)),
        capture_output=True, text=True, timeout=timeout)


def _module_git(repo_dir, *git_args, **kw):
    """Run git on a module repo (v10.0.8 §A — no `bash -lc cd … && git` through
    the broker). Home-resident repos (console-owned) run git DIRECTLY as the
    console user; root-era repos (/root/<module> on a flipped box) route through
    the broker, whose _check_git gate only admits root-era module dirs — the
    broker never runs git as root over a takwerx-writable repo (.git/hooks and
    .git/config there would be root-exec plants)."""
    timeout = kw.pop('timeout', 60)
    argv = ['git', '-C', repo_dir, '-c', 'safe.directory=%s' % repo_dir] + list(git_args)
    if repo_dir.startswith('/root/'):
        argv = _sudo_wrap(argv)
    return subprocess.run(argv, capture_output=True, text=True, timeout=timeout)


def _tvr_dir():
    """Resolve the real TAK Video Restreamer install dir. Fresh born-non-root installs live at
    ~/tak-video-restreamer; a box FLIPPED from root keeps it at /root/tak-video-restreamer (TVR is
    NOT auto-re-homed — its compose has ABSOLUTE /root binds + a bind-mounted data dir, like WebODM).
    Returns whichever holds a compose (broker-checked, since takwerx can't stat /root), else ~."""
    home = os.path.expanduser('~/tak-video-restreamer')
    if os.path.exists(os.path.join(home, 'docker-compose.yml')):
        return home
    try:
        if subprocess.run(_sudo_wrap(['test', '-f', '/root/tak-video-restreamer/docker-compose.yml']),
                          capture_output=True, timeout=10).returncode == 0:
            return '/root/tak-video-restreamer'
    except Exception:
        pass
    return home

def _tvr_compose(tvr_dir, action, timeout=120):
    """Run `docker compose <action>` in the TVR dir via the broker — root reaches /root on a
    flipped box; --project-directory replaces the old bash-cd (denied by the rulebook)."""
    return _broker_compose(tvr_dir, action, timeout=timeout)

def _get_tvr_version_info():
    """Return {version, update_available, latest} for TAK Video Restreamer (git SHA based).
    Compares FULL local vs remote SHAs — git's --short length is adaptive (7+ as the repo
    grows) so the old short-vs-[:7] compare could mismatch; display values stay 7 chars."""
    import subprocess as _sp
    info = {'version': '', 'update_available': False, 'latest': None}
    tvr_dir = _tvr_dir()
    local_full = ''
    try:
        r = _module_git(tvr_dir, 'rev-parse', 'HEAD', timeout=8)
        if r.returncode == 0:
            local_full = r.stdout.strip()
            info['version'] = local_full[:7]
    except Exception as e:
        print(f"version-info: tvr local SHA lookup failed (non-fatal): {e}", flush=True)
    latest_full = _get_tvr_latest_commit_sha()
    if latest_full:
        info['latest'] = latest_full[:7]
        if local_full and local_full != latest_full:
            info['update_available'] = True
    return info


_netbird_release_cache = {}


def _netbird_version_tuple(ver):
    """Parse semver-ish NetBird version to comparable tuple."""
    import re
    v = (ver or '').strip().lstrip('vV')
    parts = []
    for p in v.split('.')[:3]:
        try:
            parts.append(int(re.sub(r'[^0-9].*', '', p) or '0'))
        except ValueError:
            parts.append(0)
    while len(parts) < 3:
        parts.append(0)
    return tuple(parts)


def _get_netbird_github_latest(repo, use_cache=True):
    """Latest release tag from netbirdio/netbird or netbirdio/dashboard."""
    import time as _time
    import urllib.request as _ur
    cache_key = repo
    if use_cache:
        cached = _netbird_release_cache.get(cache_key)
        if cached and (_time.time() - cached.get('ts', 0) < 14400):
            return cached.get('tag')
    try:
        req = _ur.Request(
            f'https://api.github.com/repos/netbirdio/{repo}/releases/latest',
            headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'infra-TAK'})
        resp = _ur.urlopen(req, timeout=10)
        data = json.loads(resp.read().decode())
        tag = (data.get('tag_name') or '').strip()
        if tag:
            _netbird_release_cache[cache_key] = {'tag': tag, 'ts': _time.time()}
            return tag
    except Exception:
        pass
    return _netbird_release_cache.get(cache_key, {}).get('tag')


def _netbird_docker_image_version(container_name):
    """Read org.opencontainers.image.version from a running/stopped container."""
    try:
        r = subprocess.run(
            _sudo_wrap(['docker', 'inspect', container_name,
             '--format', '{{index .Config.Labels "org.opencontainers.image.version"}}']),
            capture_output=True, text=True, timeout=8)
        if r.returncode == 0 and (r.stdout or '').strip():
            return r.stdout.strip().lstrip('vV')
    except Exception:
        pass
    return ''


def _get_netbird_version_info():
    """Return {version, update_available, latest} for NetBird server + dashboard images."""
    out = {'version': '', 'update_available': False, 'latest': None}
    nb_dir = NETBIRD_INSTALL_DIR
    if not os.path.isfile(os.path.join(nb_dir, 'docker-compose.yml')):
        return out
    mgmt_ver = _netbird_docker_image_version('netbird-server')
    dash_ver = _netbird_docker_image_version('netbird-dashboard')
    parts = []
    if mgmt_ver:
        parts.append(mgmt_ver)
    if dash_ver:
        parts.append('dash ' + dash_ver)
    out['version'] = ' · '.join(parts)
    # NetBird is PINNED, dev/vetted like Authentik. "Update Now" installs the channel TARGET
    # (dev candidate on the dev channel, vetted pin on main) — never raw upstream. So the
    # update-available check compares the running version against the channel target, else the
    # badge never clears (chasing latest also breaks NetBird's auth — see v10.0.9).
    _s = load_settings()
    _channel = (_s.get('update_channel') or 'main').strip().lower()
    _srv_img, _dash_img = _get_netbird_target_images(_s)
    mgmt_pin = _srv_img.rsplit(':', 1)[-1].lstrip('vV')
    dash_pin = _dash_img.rsplit(':', 1)[-1].lstrip('vV')
    out['channel'] = _channel
    out['vetted'] = NETBIRD_SERVER_IMAGE.rsplit(':', 1)[-1].lstrip('vV')
    mgmt_behind = bool(mgmt_ver and mgmt_pin
                       and _netbird_version_tuple(mgmt_pin) > _netbird_version_tuple(mgmt_ver))
    dash_behind = bool(dash_ver and dash_pin
                       and _netbird_version_tuple(dash_pin) > _netbird_version_tuple(dash_ver))
    if mgmt_behind or dash_behind:
        out['update_available'] = True
        latest_parts = []
        if mgmt_behind:
            latest_parts.append(mgmt_pin)
        if dash_behind:
            latest_parts.append('dash ' + dash_pin)
        out['latest'] = ' · '.join(latest_parts)
    # Dev channel only: surface when netbirdio has shipped a server release newer than our
    # vetted pin, so you SEE there's something to try on dev (bump NETBIRD_SERVER_DEV_IMAGE to
    # try it, promote to vetted once login + a peer connect pass). Awareness ONLY — never
    # changes what Update installs. Main stays pinned-and-quiet (no GitHub call).
    out['upstream_latest'] = None
    out['upstream_newer'] = False
    if _channel == 'dev':
        try:
            _up = (_get_netbird_github_latest('netbird') or '').lstrip('vV')
            if _up and _netbird_version_tuple(_up) > _netbird_version_tuple(mgmt_pin):
                out['upstream_latest'] = _up
                out['upstream_newer'] = True
        except Exception:
            pass
    return out


def get_all_module_versions():
    """Return dict of module_key -> {version, update_available, latest?} for console cards.

    Each per-module lookup is INDEPENDENTLY GUARDED: a version helper that raises
    must not 500 the whole endpoint and blank every card. The helpers shell out to
    docker/git and parse package.json, so they can throw subprocess.TimeoutExpired
    (busy box), json.JSONDecodeError (malformed/partial package.json), or IndexError
    (container mid-recreate). v0.9.48 T&E (test8, the busy box) hit all three over a
    9h soak — each took down /api/modules/version once. Catch per module → that card
    just lacks a version that poll; the rest still render.
    """
    modules = detect_modules()
    result = {}

    def _set(key, fn):
        try:
            result[key] = fn()
        except Exception as e:
            print(f"version-info: {key} lookup failed (non-fatal): {e}", flush=True)

    if modules.get('caddy', {}).get('installed'):
        _set('caddy', _get_caddy_version_info)
    if modules.get('authentik', {}).get('installed'):
        _set('authentik', _get_authentik_version_info)
    if modules.get('nodered', {}).get('installed'):
        _set('nodered', _get_nodered_version_info)
    if modules.get('cloudtak', {}).get('installed'):
        _set('cloudtak', _get_cloudtak_version_info)
    if modules.get('mediamtx', {}).get('installed'):
        try:
            mtx = _get_mediamtx_version_info()
            # Card expects single 'version' string and update_available; label so MediaMTX vs editor are clear
            parts = []
            if mtx.get('version'):
                parts.append('MediaMTX v' + mtx['version'])
            if mtx.get('editor_version'):
                parts.append('editor v' + mtx['editor_version'])
            mtx['version'] = ' · '.join(parts) if parts else (mtx.get('editor_version') or mtx.get('version') or '')
            result['mediamtx'] = mtx
        except Exception as e:
            print(f"version-info: mediamtx lookup failed (non-fatal): {e}", flush=True)
    if modules.get('takportal', {}).get('installed'):
        _set('takportal', _get_takportal_version_info)
    if modules.get('takserver', {}).get('installed'):
        _set('takserver', _get_takserver_version_info)
    if modules.get('fedhub', {}).get('installed'):
        _set('fedhub', _get_fedhub_version_info)
    if modules.get('fail2ban', {}).get('installed'):
        _set('fail2ban', _get_fail2ban_version_info)
    if modules.get('webodm', {}).get('installed'):
        _set('webodm', _get_webodm_version_info)
    if modules.get('tak_video_restreamer', {}).get('installed'):
        _set('tak_video_restreamer', _get_tvr_version_info)
    if modules.get('netbird', {}).get('installed'):
        _set('netbird', _get_netbird_version_info)
    if modules.get('remote_assist', {}).get('installed'):
        _set('remote_assist', _get_remote_assist_version_info)
    # Guard Dog: version/update follow infra-TAK (scripts ship with console; "Update Guard Dog" uses same codebase)
    if modules.get('guarddog', {}).get('installed'):
        gd_latest = update_cache.get('latest')
        gd_update = False
        if gd_latest and (update_cache.get('checked') or 0) > 0:
            try:
                def _tv(v):
                    return tuple(int(p) for p in (v or '').replace('-alpha', '').replace('-beta', '').split('.')[:3])
                gd_update = _tv(gd_latest) > _tv(VERSION) and gd_latest.strip() != (VERSION or '').strip()
            except (ValueError, IndexError):
                pass
        result['guarddog'] = {'version': VERSION, 'update_available': gd_update, 'latest': gd_latest}
    return result


@app.route('/api/modules/version')
@login_required
def api_modules_version():
    """Return version and update_available for all installed services (for console cards)."""
    return jsonify(get_all_module_versions())


@app.route('/api/takportal/version')
@login_required
def takportal_version_api():
    """Return TAK Portal version and update-available for module/card UI."""
    info = _get_takportal_version_info()
    return jsonify(info)


@app.route('/takportal')
@login_required
def takportal_page():
    modules = detect_modules()
    portal = modules.get('takportal', {})
    settings = load_settings()
    # Reset deploy_done once TAK Portal is running so the running view shows
    if portal.get('installed') and portal.get('running') and not takportal_deploy_status.get('running', False):
        takportal_deploy_status.update({'complete': False, 'error': False})
    # Get container info if running
    container_info = {}
    if portal.get('running'):
        r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '--format', '{{.Names}}|||{{.Status}}']), capture_output=True, text=True)
        if r.stdout.strip():
            containers = []
            for line in r.stdout.strip().split('\n'):
                if line.strip():
                    parts = line.strip().split('|||')
                    containers.append({'name': parts[0] if len(parts) > 0 else 'tak-portal', 'status': parts[1] if len(parts) > 1 else ''})
            container_info['containers'] = containers
            container_info['status'] = containers[0]['status'] if containers else ''
    # Get portal port from .env if exists
    portal_port = '3000'
    env_path = os.path.expanduser('~/TAK-Portal/.env')
    if os.path.exists(env_path):
        with open(env_path) as f:
            for line in f:
                if line.strip().startswith('WEB_UI_PORT='):
                    portal_port = line.strip().split('=', 1)[1].strip() or '3000'
    # Real version (package.json) and update-available (from container logs)
    vinfo = _get_takportal_version_info()
    portal_version = vinfo['version'] or ''
    portal_update_available = vinfo['update_available']
    portal_latest = vinfo['latest']
    takportal_deploy_cfg = _get_module_deployment_config(settings, 'takportal_deployment')
    return render_template_string(TAKPORTAL_TEMPLATE,
        settings=settings, portal=portal, container_info=container_info,
        portal_port=portal_port, portal_version=portal_version,
        portal_update_available=portal_update_available, portal_latest=portal_latest,
        takportal_deploy_cfg=takportal_deploy_cfg,
        authentik_base_url=_get_authentik_base_url(settings),
        takserver_base_url=_get_takserver_base_url(settings),
        version=VERSION,
        deploying=takportal_deploy_status.get('running', False),
        deploy_done=takportal_deploy_status.get('complete', False))

# TAK Portal deploy state
takportal_deploy_log = []
takportal_deploy_status = {'running': False, 'complete': False, 'error': False}

# Keys in TAK Portal settings.json that are configurable in TAK Portal UI (e.g. custom logo/photo). We never overwrite these when pushing settings on update/reconfigure/deploy.
PRESERVE_TAKPORTAL_KEYS = frozenset(['BRAND_LOGO_URL', 'TAK_SSH_ONBOARDED', 'TAK_SSH_LAST_HANDSHAKE_AT'])


def _takportal_get_existing_settings():
    """Read current settings.json from TAK Portal container. Returns dict or {} if container missing or file invalid."""
    try:
        r = subprocess.run(
            _sudo_wrap(['docker', 'exec', 'tak-portal', 'cat', '/usr/src/app/data/settings.json']), capture_output=True, text=True, timeout=10)
        if r.returncode != 0 or not (r.stdout or '').strip():
            return {}
        return json.loads(r.stdout.strip())
    except Exception:
        return {}


def _takportal_build_settings_dict(settings):
    """Build infra-TAK managed TAK Portal settings dict (no merge)."""
    server_ip = (settings.get('server_ip') or '').strip() or 'localhost'
    ak_token = _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN') or _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN')
    # v10.0.9 preserve-on-empty: if the .env read comes back empty (e.g. a config rebuild racing
    # the non-root flip's authentik re-home), do NOT clobber a good token already in TAK Portal's
    # settings.json — reuse the existing one. Same "never overwrite good state with nothing" rule
    # as Node-RED config persistence. Only touches the empty case; healthy builds are unchanged.
    if not (ak_token or '').strip():
        _existing = _takportal_get_existing_settings()
        _prev_tok = (_existing.get('AUTHENTIK_TOKEN') or '').strip() if isinstance(_existing, dict) else ''
        if _prev_tok:
            ak_token = _prev_tok
    cloudtak_host = _get_service_domain(settings, 'cloudtak_map')
    cert_pass = _get_tak_cert_password(settings)
    ak_upstream = _get_authentik_upstream(settings)
    # Local Authentik: use the Docker-internal hostname on the shared infratak network.
    # Published ports are hardened to 127.0.0.1, so containers can't reach them via
    # the host's public IP. The infratak network lets Portal talk to Authentik directly.
    if ak_upstream == '127.0.0.1:9090':
        auth_url_host = 'authentik-server-1'
        auth_url_port = '9000'
    else:
        auth_url_host = ak_upstream.split(':')[0]
        auth_url_port = ak_upstream.split(':')[1] if ':' in ak_upstream else '9090'
    # TAK_URL host for HTTPS to :8443/Marti inside the portal container.
    # Prefer takserver.<fqdn> when FQDN is set — TAK certs are issued for DNS names; using
    # server_ip breaks TLS hostname verification ("identity could not be verified").
    # Fall back to server_ip for IP-only / no-FQDN installs; then Docker host aliases.
    # v0.9.57: TAK_URL host = takserver.<fqdn> when an FQDN is set, so the Portal's QR
    # enrollment host (derived from TAK_URL's hostname) points devices at the real DNS name,
    # NOT host.docker.internal. The Portal's server-side mTLS to the local JVM is handled
    # separately by a takserver.<fqdn>:host-gateway alias in the container's extra_hosts (see
    # _write_takportal_override) — that resolves the FQDN to 172.17.0.1 INSIDE the container on
    # both normal and gateway-fronted boxes (the Portal validates the CA chain, not the
    # hostname). Reverts c384fc8's host.docker.internal override, which leaked into every QR.
    # Recomputed every build (deterministic; never preserved — TAK_URL is intentionally NOT in
    # PRESERVE_TAKPORTAL_KEYS).
    tak_dns = (_get_takserver_host(settings) or '').strip()
    if settings.get('fqdn') and tak_dns:
        tak_url_host = tak_dns
    elif server_ip and server_ip not in ('localhost', '127.0.0.1'):
        tak_url_host = server_ip
    else:
        tak_url_host = tak_dns or 'host.docker.internal'
    # SSH: only pre-populate when TAK Server is on the same box
    tak_local = os.path.isdir('/opt/tak')
    ssh_host = ('host.docker.internal' if server_ip in ('localhost', '127.0.0.1', '') else server_ip) if tak_local else ''
    return {
        "AUTHENTIK_URL": f"http://{auth_url_host}:{auth_url_port}",
        "AUTHENTIK_TOKEN": ak_token or "",
        # v0.9.15 — akadmin and webadmin are both HIDDEN and ACTION-LOCKED in
        # TAK Portal so an operator cannot click Disable / Delete on either
        # protected admin account from the user-management UI. infra-TAK is
        # authoritative for both fields: every "Update config & reconnect"
        # and every post-update `_auto_harden_takportal_settings` push these
        # defaults back. The v0.9.13/v0.9.14 Protected Admin Accounts panel
        # on /authentik stays as the last-resort recovery if this guardrail
        # is ever bypassed (e.g. operator clears the lists in TAK Portal's
        # UI, future TAK Portal release exposes a way past the lock, or the
        # accounts are disabled directly through Authentik's native admin).
        "USERS_HIDDEN_PREFIXES": "akadmin,webadmin,ak-,adm_,nodered-,ma-",
        "GROUPS_HIDDEN_PREFIXES": "authentik, MA -, vid_, tak_ROLE_",
        "USERS_ACTIONS_HIDDEN_PREFIXES": "akadmin,webadmin",
        "GROUPS_ACTIONS_HIDDEN_PREFIXES": "",
        "DASHBOARD_AUTHENTIK_STATS_REFRESH_SECONDS": "300",
        "PORTAL_AUTH_ENABLED": "true" if settings.get('fqdn') else "false",
        "PORTAL_AUTH_REQUIRED_GROUP": "authentik Admins" if settings.get('fqdn') else "",
        "AUTHENTIK_PUBLIC_URL": _get_authentik_base_url(settings),
        "TAK_PORTAL_PUBLIC_URL": f"https://{_get_service_domain(settings, 'takportal')}" if settings.get('fqdn') else f"http://{server_ip}:3000",
        "TAK_URL": f"https://{tak_url_host}:8443/Marti",
        "TAK_API_P12_PATH": "data/certs/tak-client.p12",
        "TAK_API_P12_PASSPHRASE": cert_pass,
        "TAK_CA_PATH": "data/certs/tak-ca.pem",
        "TAK_REVOKE_ON_DISABLE": "true",
        "TAK_DEBUG": "false",
        "TAK_BYPASS_ENABLED": "false",
        "CLOUDTAK_URL": f"https://{cloudtak_host}" if cloudtak_host else "",
        **_portal_email_settings(settings),
        "BRAND_THEME": "dark",
        "BRAND_LOGO_URL": "",
        "TAK_SSH_HOST": ssh_host,
        "TAK_SSH_PORT": "22",
        "TAK_SSH_USER": "root",
        "TAK_SSH_PRIVATE_KEY_PATH": "data/ssh/tak_ssh_ed25519",
        "TAK_SSH_PUBLIC_KEY_PATH": "data/ssh/tak_ssh_ed25519.pub",
        "TAK_SSH_PASSPHRASE": "",
    }


def _takportal_merged_settings_json(settings):
    """Build settings JSON for TAK Portal, preserving user-configured keys (e.g. BRAND_LOGO_URL / custom photo) from existing container settings."""
    existing = _takportal_get_existing_settings()
    our = _takportal_build_settings_dict(settings)
    merged = dict(existing) if isinstance(existing, dict) else {}
    for k, v in our.items():
        if k in PRESERVE_TAKPORTAL_KEYS and (merged.get(k) or '').strip():
            continue
        merged[k] = v
    return json.dumps(merged, indent=2)


def _heal_takportal_authentik_token(plog=None):
    """v10.0.9: self-heal TAK Portal's AUTHENTIK_TOKEN when it was blanked by a config rebuild
    that raced the non-root flip's Authentik re-home (memory nonroot-flip-strands-root-era-module-dirs).

    On a box flipped to non-root, a TAK Portal 'update config' that ran BEFORE ~/authentik/.env
    became readable wrote AUTHENTIK_TOKEN:"" — freezing TAK Portal user management ('Missing
    AUTHENTIK_TOKEN in settings.json'). The token reads fine after the re-home, but settings.json
    was never rebuilt. This re-pushes a valid token on the next console boot so an affected box
    self-heals through the normal update (pull + restart) path — no manual 'Update config'.

    Idempotent: skips when the token is already present, TAK Portal isn't running, or no valid
    token can be read. Best-effort; never raises."""
    _log = plog or (lambda m: print(m, flush=True))
    try:
        r = subprocess.run(_sudo_wrap(['docker', 'inspect', '-f', '{{.State.Running}}', 'tak-portal']),
                           capture_output=True, text=True, timeout=8)
        if (r.stdout or '').strip() != 'true':
            return False  # container not running — nothing to heal / can't push
        existing = _takportal_get_existing_settings()
        if not isinstance(existing, dict):
            return False
        if (existing.get('AUTHENTIK_TOKEN') or '').strip():
            return False  # token present — healthy box, leave it alone
        settings = load_settings()
        new_tok = (_get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN')
                   or _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN') or '').strip()
        if not new_tok:
            _log("  takportal: AUTHENTIK_TOKEN blank but none readable from Authentik .env yet — skip heal")
            return False
        _log("  takportal: AUTHENTIK_TOKEN blank in settings.json — re-pushing valid token (non-root flip-window heal)")
        settings_json = _takportal_merged_settings_json(settings)
        fd, tmp = tempfile.mkstemp(suffix='.json', prefix='takportal-heal-')
        try:
            with os.fdopen(fd, 'w') as f:
                f.write(settings_json)
            cp = subprocess.run(_sudo_wrap(['docker', 'cp', tmp, 'tak-portal:/usr/src/app/data/settings.json']),
                                capture_output=True, text=True, timeout=20)
        finally:
            try:
                os.remove(tmp)
            except OSError:
                pass
        if cp.returncode != 0:
            _log(f"  takportal: heal docker cp failed: {(cp.stderr or cp.stdout or '').strip()[:200]}")
            return False
        subprocess.run(_sudo_wrap(['docker', 'restart', 'tak-portal']), capture_output=True, text=True, timeout=30)
        _log("  ✓ takportal: AUTHENTIK_TOKEN restored + container restarted")
        return True
    except Exception as e:
        _log(f"  takportal: AUTHENTIK_TOKEN heal error (non-fatal): {e}")
        return False


def _takportal_setup_ssh(log_fn=None):
    """Generate an ed25519 keypair, install it on the host, and copy it into the TAK Portal container.

    After this, TAK Portal can SSH to the host via host.docker.internal without a password handshake.
    Only runs when TAK Server is on the same box (i.e. /opt/tak exists). For remote TAK Server
    deployments, SSH must be configured manually in TAK Portal's UI.
    Returns True if the key was installed (or already existed) and is ready to use.
    """
    if not os.path.isdir('/opt/tak'):
        if log_fn:
            log_fn("  ⏭ TAK Server not on this host — skipping SSH auto-config (configure manually in TAK Portal)")
        return False
    key_dir = os.path.expanduser('~/TAK-Portal/data/ssh')
    priv_key = os.path.join(key_dir, 'tak_ssh_ed25519')
    pub_key = priv_key + '.pub'
    auth_keys = os.path.expanduser('~/.ssh/authorized_keys')

    try:
        os.makedirs(key_dir, mode=0o700, exist_ok=True)

        # Generate keypair if missing
        if not os.path.exists(priv_key):
            r = subprocess.run(
                ['ssh-keygen', '-t', 'ed25519', '-f', priv_key, '-N', '', '-C', 'tak-portal-auto'],
                capture_output=True, text=True, timeout=15)
            if r.returncode != 0 or not os.path.exists(pub_key):
                if log_fn:
                    log_fn(f"  ✗ SSH keygen failed: {(r.stderr or '').strip()[:200]}")
                return False
            if log_fn:
                log_fn("  ✓ SSH ed25519 keypair generated")
        else:
            if log_fn:
                log_fn("  ✓ SSH keypair already exists")

        # Install public key in host authorized_keys
        with open(pub_key, 'r') as f:
            pub_content = f.read().strip()
        os.makedirs(os.path.dirname(auth_keys), mode=0o700, exist_ok=True)
        existing_keys = ''
        if os.path.exists(auth_keys):
            with open(auth_keys, 'r') as f:
                existing_keys = f.read()
        if pub_content not in existing_keys:
            with open(auth_keys, 'a') as f:
                f.write(f'\n{pub_content}\n')
            os.chmod(auth_keys, 0o600)
            if log_fn:
                log_fn("  ✓ Public key added to ~/.ssh/authorized_keys")
        else:
            if log_fn:
                log_fn("  ✓ Public key already in authorized_keys")

        # Copy keypair into running container
        subprocess.run(
            _sudo_wrap(['docker', 'exec', 'tak-portal', 'mkdir', '-p', '/usr/src/app/data/ssh']), capture_output=True, text=True, timeout=10)
        subprocess.run(
            _sudo_wrap(['docker', 'cp', priv_key, 'tak-portal:/usr/src/app/data/ssh/tak_ssh_ed25519']), capture_output=True, text=True, timeout=10)
        subprocess.run(
            _sudo_wrap(['docker', 'cp', pub_key, 'tak-portal:/usr/src/app/data/ssh/tak_ssh_ed25519.pub']), capture_output=True, text=True, timeout=10)
        # Ensure correct permissions inside container
        subprocess.run(
            _sudo_wrap(['docker', 'exec', 'tak-portal', 'chmod', '600', '/usr/src/app/data/ssh/tak_ssh_ed25519']), capture_output=True, text=True, timeout=10)
        if log_fn:
            log_fn("  ✓ SSH keys copied into TAK Portal container")

        # Mark onboarded in container settings
        try:
            from datetime import datetime as _dt
            r = subprocess.run(
                _sudo_wrap(['docker', 'exec', 'tak-portal', 'cat', '/usr/src/app/data/settings.json']), capture_output=True, text=True, timeout=10)
            if r.returncode == 0 and r.stdout.strip():
                import json as _json
                portal_cfg = _json.loads(r.stdout)
                portal_cfg['TAK_SSH_ONBOARDED'] = 'true'
                portal_cfg['TAK_SSH_LAST_HANDSHAKE_AT'] = _dt.now().isoformat()
                fd, tmp = tempfile.mkstemp(suffix='.json', prefix='tak-portal-ssh-')
                try:
                    with os.fdopen(fd, 'w') as f:
                        _json.dump(portal_cfg, f, indent=2)
                    subprocess.run(
                        _sudo_wrap(['docker', 'cp', tmp, 'tak-portal:/usr/src/app/data/settings.json']), capture_output=True, text=True, timeout=10)
                finally:
                    try:
                        os.remove(tmp)
                    except OSError:
                        pass
        except Exception:
            pass

        return True
    except Exception as e:
        if log_fn:
            log_fn(f"  ✗ SSH setup error: {e}")
        return False


def _takportal_build_settings_json(settings):
    """Build TAK Portal settings dict and return (json_string, error). Uses Authentik env from local or remote. Prefer _takportal_merged_settings_json when pushing to container so user customizations (e.g. custom logo) are preserved."""
    d = _takportal_build_settings_dict(settings)
    return json.dumps(d, indent=2), None


@app.route('/api/takportal/control', methods=['POST'])
@login_required
def takportal_control():
    action = request.json.get('action')
    portal_dir = os.path.expanduser('~/TAK-Portal')
    if action == 'start':
        _patch_takportal_compose_network()
        _patch_takportal_compose_ports(portal_dir)
        subprocess.run(_sudo_wrap(['docker', 'compose', 'up', '-d', '--build']), cwd=portal_dir, capture_output=True, text=True, timeout=120)
        _ensure_infratak_network_for_portal()
        _ensure_infratak_network_for_authentik()
    elif action == 'stop':
        subprocess.run(_sudo_wrap(['docker', 'compose', 'down']), cwd=portal_dir, capture_output=True, text=True, timeout=60)
    elif action == 'restart':
        _patch_takportal_compose_network()
        _patch_takportal_compose_ports(portal_dir)
        _run_priv_chain([['docker', 'compose', 'down'], ['docker', 'compose', 'up', '-d']], 'and', timeout=120, cwd=portal_dir)
        _ensure_infratak_network_for_portal()
        _ensure_infratak_network_for_authentik()
    elif action == 'reconfigure':
        # Update config only: push settings into container and restart (no git pull / image build). Preserves user-configured keys (e.g. BRAND_LOGO_URL).
        settings = load_settings()
        settings_json = _takportal_merged_settings_json(settings)
        try:
            fd, tmp_settings = tempfile.mkstemp(suffix='.json', prefix='tak-portal-')
            try:
                with os.fdopen(fd, 'w') as f:
                    f.write(settings_json)
                cp = subprocess.run(_sudo_wrap(['docker', 'cp', tmp_settings, 'tak-portal:/usr/src/app/data/settings.json']), capture_output=True, text=True, timeout=20)
            finally:
                try:
                    os.remove(tmp_settings)
                except OSError:
                    pass
            if cp.returncode != 0:
                return jsonify({'success': False, 'error': (cp.stderr or cp.stdout or 'docker cp failed').strip()[:300]}), 500
            _takportal_setup_ssh()
            subprocess.run(_sudo_wrap(['docker', 'restart', 'tak-portal']), capture_output=True, text=True, timeout=30)
        except Exception as e:
            return jsonify({'success': False, 'error': str(e)[:300]}), 500
        # v0.9.31: run the full Authentik proxy chain heal for all deployed
        # services, not just TAK Portal. Catches the "deploy timed out, provider
        # never registered" class of bug fleet-wide. Uses 30s timeouts + retries
        # + verify-via-re-GET so silent failures actually surface in the log.
        chain_summary = {}
        try:
            chain_summary = _heal_authentik_proxy_chain_all_services(settings=settings)
        except Exception:
            pass
        # Back-compat: keep the legacy single-service call as a defensive second
        # pass (idempotent; no-op when chain healer already converged).
        try:
            _sync_authentik_takportal_provider_url(settings)
        except Exception:
            pass
        time.sleep(2)
        r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '--format', '{{.Status}}']), capture_output=True, text=True)
        running = 'Up' in (r.stdout or '')
        tp_state = (chain_summary or {}).get('takportal', {})
        ok = (tp_state.get('provider') in ('ok', 'created', 'fixed', 'adopted')
              and tp_state.get('app') in ('ok', 'created', 'fixed'))
        msg = 'Config updated and portal restarted.'
        if not chain_summary:
            # Healer didn't run (Authentik not installed, no token, etc.) — just report container state
            msg = 'Config updated and portal restarted (SSH configured).'
        elif ok:
            msg = 'Config updated, portal restarted, and Authentik proxy chain reconciled.'
        elif tp_state:
            msg = (f'Config updated and portal restarted, but Authentik proxy chain heal reported: '
                   f"provider={tp_state.get('provider')}, app={tp_state.get('app')}, outpost={tp_state.get('outpost')}. "
                   f"Check console logs and Authentik admin UI.")
        return jsonify({'success': True, 'running': running, 'action': action,
                        'message': msg, 'chain_summary': chain_summary})
    elif action == 'update':
        # Reset any local changes to tracked files before pulling — the network
        # and hardening patches now live in docker-compose.override.yml (not tracked
        # by git) so it's safe to discard dirty tracked files without losing anything.
        subprocess.run(
            f'git -c safe.directory={portal_dir} -C {portal_dir} checkout -- .',
            shell=True, capture_output=True, text=True, timeout=15)
        pull = subprocess.run(
            f'cd {portal_dir} && git -c safe.directory={portal_dir} pull --rebase',
            shell=True, capture_output=True, text=True, timeout=60)
        pull_msg = pull.stdout.strip().split('\n')[-1] if pull.stdout.strip() else ''
        # Rewrite the override file so network hardening survives the pull.
        # Also patch the base compose so port binding is loopback-only
        # (git pull resets the upstream 0.0.0.0 binding on every update).
        _write_takportal_override()
        _patch_takportal_compose_ports(portal_dir)
        build = subprocess.run(_sudo_wrap(['docker', 'compose', 'up', '-d', '--build']), cwd=portal_dir, capture_output=True, text=True, timeout=180)
        _ensure_infratak_network_for_portal()
        _ensure_infratak_network_for_authentik()
        if build.returncode != 0:
            err = (build.stderr or build.stdout or 'Build failed').strip()[:400]
            return jsonify({'success': False, 'error': 'Build failed. Container may have stopped — try Start below or check container logs.'}), 500
        settings_synced = False
        settings_sync_error = ''
        cloudtak_url = ''
        try:
            settings = load_settings()
            settings_json = _takportal_merged_settings_json(settings)
            cloudtak_url = ''
            try:
                import json as json_mod
                portal_settings = json_mod.loads(settings_json)
                cloudtak_url = portal_settings.get('CLOUDTAK_URL', '')
            except Exception:
                pass
            fd, tmp_settings = tempfile.mkstemp(suffix='.json', prefix='tak-portal-')
            try:
                with os.fdopen(fd, 'w') as f:
                    f.write(settings_json)
                cp = subprocess.run(_sudo_wrap(['docker', 'cp', tmp_settings, 'tak-portal:/usr/src/app/data/settings.json']), capture_output=True, text=True, timeout=20)
            finally:
                try:
                    os.remove(tmp_settings)
                except OSError:
                    pass
            if cp.returncode == 0:
                _takportal_setup_ssh()
                subprocess.run(_sudo_wrap(['docker', 'restart', 'tak-portal']), capture_output=True, text=True, timeout=30)
                settings_synced = True
            else:
                settings_sync_error = (cp.stderr or cp.stdout or 'docker cp failed').strip()[:300]
        except Exception as e:
            settings_sync_error = str(e)[:300]
        subprocess.run(_sudo_wrap(['docker', 'image', 'prune', '-f']), cwd=portal_dir, capture_output=True, text=True, timeout=30)
        time.sleep(3)
        vinfo = _get_takportal_version_info()
        new_version = vinfo['version'] or ''
        r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '--format', '{{.Status}}']), capture_output=True, text=True)
        running = 'Up' in (r.stdout or '')
        if not running:
            return jsonify({'success': False, 'error': 'Container not running after update — click Start below.'}), 500
        return jsonify({'success': True, 'running': running, 'action': action, 'pull': pull_msg, 'version': new_version, 'settings_synced': settings_synced, 'settings_sync_error': settings_sync_error, 'cloudtak_url': cloudtak_url})
    else:
        return jsonify({'error': 'Invalid action'}), 400
    time.sleep(3)
    r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '--format', '{{.Status}}']), capture_output=True, text=True)
    running = 'Up' in r.stdout
    return jsonify({'success': True, 'running': running, 'action': action})

@app.route('/api/takportal/deploy', methods=['POST'])
@login_required
def takportal_deploy():
    if takportal_deploy_status.get('running'):
        return jsonify({'error': 'Deployment already in progress'}), 409
    takportal_deploy_log.clear()
    takportal_deploy_status.update({'running': True, 'complete': False, 'error': False})
    threading.Thread(target=run_takportal_deploy, daemon=True).start()
    return jsonify({'success': True})

@app.route('/api/takportal/deploy/log')
@login_required
def takportal_deploy_log_api():
    idx = request.args.get('index', 0, type=int)
    return jsonify({'entries': takportal_deploy_log[idx:], 'total': len(takportal_deploy_log),
        'running': takportal_deploy_status['running'], 'complete': takportal_deploy_status['complete'],
        'error': takportal_deploy_status['error']})

@app.route('/api/takportal/logs')
@login_required
def takportal_container_logs():
    """Get recent container logs"""
    lines = request.args.get('lines', 50, type=int)
    r = subprocess.run(_sudo_wrap(['docker', 'logs', 'tak-portal', '--tail', str(lines)]), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10)
    entries = []
    skip_lines = {'npm error', 'npm ERR', 'signal SIGTERM', 'command failed', 'A complete log of this run'}
    for line in (r.stdout.strip().split('\n') if r.stdout.strip() else []):
        if not any(s in line for s in skip_lines):
            entries.append(line)
    return jsonify({'entries': entries})

@app.route('/api/takportal/uninstall', methods=['POST'])
@login_required
def takportal_uninstall():
    data = request.json or {}
    password = data.get('password', '')
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'error': 'Invalid admin password'}), 403
    portal_dir = os.path.expanduser('~/TAK-Portal')
    steps = []
    subprocess.run(_sudo_wrap(['docker', 'compose', 'down', '-v', '--rmi', 'local']), cwd=portal_dir, capture_output=True, timeout=120)
    steps.append('Stopped and removed Docker containers/volumes')
    if os.path.exists(portal_dir):
        subprocess.run(f'rm -rf {portal_dir}', shell=True, capture_output=True)
        steps.append('Removed ~/TAK-Portal')
    takportal_deploy_log.clear()
    takportal_deploy_status.update({'running': False, 'complete': False, 'error': False})
    # v0.9.31: regenerate Caddyfile so the takportal.<fqdn> vhost is removed.
    # Without this the stale vhost remained, Caddy reverse-proxied to a dead
    # upstream (or fell through to Authentik's forward-auth), and the operator
    # saw the Authentik "Not Found" page on takportal.<fqdn> after Remove.
    # Matches mediamtx_uninstall() which has done this correctly since v0.9.x.
    try:
        settings = load_settings()
        generate_caddyfile(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
        steps.append('Regenerated Caddyfile + reloaded Caddy')
    except Exception as caddy_err:
        steps.append(f'Caddy regen warning (non-fatal): {caddy_err}')
    _update_boot_stagger_service()
    return jsonify({'success': True, 'steps': steps})

def _portal_email_settings(settings):
    """Build TAK Portal email settings from the Email Relay config if deployed."""
    relay = settings.get('email_relay', {})
    if relay.get('relay_host') and relay.get('smtp_user'):
        from_addr = relay.get('from_addr', '')
        from_name = relay.get('from_name', 'TAK Admin')
        smtp_from = f"{from_name} <{from_addr}>" if from_name and from_addr else from_addr
        return {
            "EMAIL_ENABLED": "true",
            "EMAIL_PROVIDER": "smtp",
            "SMTP_HOST": relay.get('relay_host', ''),
            "SMTP_PORT": str(relay.get('relay_port', '587')),
            "SMTP_SECURE": "false",
            "SMTP_USER": relay.get('smtp_user', ''),
            "SMTP_PASS": relay.get('smtp_pass', ''),
            "SMTP_FROM": smtp_from,
            "EMAIL_ALWAYS_CC": "",
            "EMAIL_SEND_COPY_TO": "",
            "EMAIL_FAIL_HARD": "false",
        }
    return {
        "EMAIL_ENABLED": "false",
        "EMAIL_PROVIDER": "smtp",
        "SMTP_HOST": "",
        "SMTP_PORT": "587",
        "SMTP_SECURE": "false",
        "SMTP_USER": "",
        "SMTP_PASS": "",
        "SMTP_FROM": "",
        "EMAIL_ALWAYS_CC": "",
        "EMAIL_SEND_COPY_TO": "",
        "EMAIL_FAIL_HARD": "false",
    }

def run_takportal_deploy():
    def plog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        takportal_deploy_log.append(entry)
        print(entry, flush=True)
    try:
        portal_dir = os.path.expanduser('~/TAK-Portal')
        settings = load_settings()
        if settings.get('pkg_mgr', 'apt') == 'apt':
            wait_for_apt_lock(plog, takportal_deploy_log)
        # Step 1: Check Docker
        plog("\u2501\u2501\u2501 Step 1/6: Checking Docker \u2501\u2501\u2501")
        r = subprocess.run(_sudo_wrap(['docker', '--version']), capture_output=True, text=True)
        if r.returncode != 0:
            plog("Docker not found. Installing...")
            subprocess.run(_docker_install_cmd(), shell=True, capture_output=True, text=True, timeout=300)
            r2 = subprocess.run(_sudo_wrap(['docker', '--version']), capture_output=True, text=True)
            if r2.returncode != 0:
                plog("\u2717 Failed to install Docker")
                takportal_deploy_status.update({'running': False, 'error': True})
                return
            plog(f"  {r2.stdout.strip()}")
            plog("\u2713 Docker installed")
        else:
            plog(f"  {r.stdout.strip()}")
            plog("\u2713 Docker available")

        _ensure_docker_log_limits(plog)

        # Step 2: Clone repo
        plog("")
        plog("\u2501\u2501\u2501 Step 2/6: Cloning TAK Portal \u2501\u2501\u2501")
        if os.path.exists(portal_dir):
            plog("  TAK-Portal directory already exists, pulling latest...")
            subprocess.run(
                f'cd {portal_dir} && git -c safe.directory={portal_dir} pull --rebase --autostash',
                shell=True, capture_output=True, text=True, timeout=60)
        else:
            plog("  Cloning from GitHub (shallow, latest only)...")
            r = subprocess.run(f'git clone --depth 1 https://github.com/AdventureSeeker423/TAK-Portal.git {portal_dir}', shell=True, capture_output=True, text=True, timeout=180)
            if r.returncode != 0:
                plog(f"\u2717 Clone failed: {r.stderr.strip()}")
                takportal_deploy_status.update({'running': False, 'error': True})
                return
        plog("\u2713 Repository ready")

        # Step 3: Create .env if missing (exactly as main — no AUTHENTIK_URL here; set in settings.json in Step 6)
        plog("")
        plog("\u2501\u2501\u2501 Step 3/6: Configuring \u2501\u2501\u2501")
        env_path = os.path.join(portal_dir, '.env')
        if not os.path.exists(env_path):
            plog("  Creating default .env...")
            with open(env_path, 'w') as f:
                f.write("WEB_UI_PORT=3000\n")
            plog("\u2713 Default .env created (port 3000)")
        else:
            plog("\u2713 .env already exists")

        # Step 4: Build and start (exactly as main)
        plog("")
        plog("\u2501\u2501\u2501 Step 4/6: Building & Starting Docker Container \u2501\u2501\u2501")
        compose_path = os.path.join(portal_dir, 'docker-compose.yml')
        if os.path.exists(compose_path):
            with open(compose_path, 'r') as f:
                compose_content = f.read()
            if 'healthcheck' not in compose_content:
                healthcheck = (
                    "    healthcheck:\n"
                    "      test: [\"CMD-SHELL\", \"wget -qO- http://localhost:3000 2>&1 | grep -q setup-my-device && exit 0 || exit 1\"]\n"
                    "      interval: 30s\n"
                    "      timeout: 10s\n"
                    "      retries: 3\n"
                    "      start_period: 15s\n"
                )
                extra_hosts_block = (
                    "    extra_hosts:\n"
                    "      - \"host.docker.internal:host-gateway\"\n"
                )
                updated_compose_content = compose_content.replace(
                    'restart: unless-stopped',
                    'restart: unless-stopped\n' + healthcheck.rstrip('\n') + '\n' + extra_hosts_block.rstrip('\n')
                )
                if updated_compose_content != compose_content:
                    compose_content = updated_compose_content
                    with open(compose_path, 'w') as f:
                        f.write(compose_content)
                    plog("  ✓ Healthcheck + extra_hosts added to docker-compose.yml")
                else:
                    plog("  ⚠ Could not auto-patch docker-compose.yml (missing 'restart: unless-stopped'). Add extra_hosts manually if needed.")
            elif 'host.docker.internal' not in compose_content:
                extra_hosts_block = (
                    "    extra_hosts:\n"
                    "      - \"host.docker.internal:host-gateway\"\n"
                )
                updated_compose_content = compose_content.replace(
                    'restart: unless-stopped',
                    'restart: unless-stopped\n' + extra_hosts_block.rstrip('\n')
                )
                if updated_compose_content != compose_content:
                    compose_content = updated_compose_content
                    with open(compose_path, 'w') as f:
                        f.write(compose_content)
                    plog("  ✓ extra_hosts (host.docker.internal) added for container→host")
                else:
                    plog("  ⚠ Could not auto-add extra_hosts (missing 'restart: unless-stopped').")

            # NOTE: We deliberately do NOT inject cap_drop:ALL / no-new-privileges
            # into TAK Portal's docker-compose.yml. cap_drop:ALL removes
            # CAP_DAC_OVERRIDE which is required for the Node.js process to read
            # tak-client.p12 (owned by uid 889 with mode 600) — the dashboard
            # silently shows -- for all stats. Same lesson learned in commit
            # 7fe8191 for the override path; this code path was missed in that
            # commit and re-applied the broken hardening on every fresh deploy.
            # If a previous deploy injected cap_drop, strip it now so the next
            # `docker compose up` runs with default capabilities.
            _had_capdrop = False
            for _bad in (
                '\n    cap_drop:\n      - ALL\n    security_opt:\n      - no-new-privileges:true',
                '    cap_drop:\n      - ALL\n    security_opt:\n      - no-new-privileges:true\n',
            ):
                if _bad in compose_content:
                    compose_content = compose_content.replace(_bad, '', 1)
                    _had_capdrop = True
            if _had_capdrop:
                with open(compose_path, 'w') as f:
                    f.write(compose_content)
                plog("  ✓ Removed legacy cap_drop:ALL from docker-compose.yml (breaks cert reads)")

        if _patch_takportal_compose_network():
            plog("  ✓ infratak Docker network added to docker-compose.yml (Portal ↔ Authentik)")

        plog("  Building image (this may take a minute)...")
        # Build + create the container WITHOUT starting it. The first boot otherwise
        # runs TAK Portal's Authentik users-fetch against the shipped placeholder
        # settings ("your-authentik-url" / "your-real-token-here") and dumps a
        # harmless-but-alarming ENOTFOUND stack trace into the logs on every fresh
        # install. We seed real settings.json into the created container below, then
        # start — so the first boot already has live config. No-op-safe on redeploy
        # (an already-running container just gets re-seeded + restarted in Step 6).
        r = subprocess.run(_sudo_wrap(['docker', 'compose', 'up', '-d', '--build', '--no-start']), cwd=portal_dir, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=900)
        for line in r.stdout.strip().split('\n'):
            if line.strip() and 'NEEDRESTART' not in line:
                takportal_deploy_log.append(f"  {line.strip()}")
        if r.returncode != 0:
            plog(f"\u2717 Docker build failed")
            for line in r.stderr.strip().split('\n'):
                if line.strip():
                    takportal_deploy_log.append(f"  \u2717 {line.strip()}")
            takportal_deploy_status.update({'running': False, 'error': True})
            return

        _ensure_infratak_network_for_portal()
        _ensure_infratak_network_for_authentik()

        # Seed real settings.json into the created (not-yet-started) container so the
        # first boot uses live config instead of the placeholder defaults — kills the
        # ENOTFOUND startup noise. docker cp works on a created/stopped container, and
        # the infratak network was attached above so authentik-server-1 resolves on
        # boot. Step 6 re-writes settings.json idempotently (and adds the SSH-onboarded
        # flag) after the post-start cert/SSH sync, so this is purely a head-start.
        try:
            import json as _json_seed
            _seed_dict = _takportal_build_settings_dict(load_settings())
            _fd_seed, _tmp_seed = tempfile.mkstemp(suffix='.json', prefix='tak-portal-seed-')
            try:
                with os.fdopen(_fd_seed, 'w') as _sf:
                    _sf.write(_json_seed.dumps(_seed_dict, indent=2))
                subprocess.run(
                    _sudo_wrap(['docker', 'cp', _tmp_seed, 'tak-portal:/usr/src/app/data/settings.json']), capture_output=True, text=True, timeout=10)
                plog("  ✓ Seeded settings.json before first start (suppresses placeholder Authentik fetch)")
            finally:
                try:
                    os.remove(_tmp_seed)
                except OSError:
                    pass
        except Exception as _seed_e:
            plog(f"  ⚠ Could not pre-seed settings.json: {str(_seed_e)[:80]} (first boot may log a harmless placeholder error)")

        # Start the container now that real settings are in place
        subprocess.run(_sudo_wrap(['docker', 'compose', 'start']), cwd=portal_dir, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=120)

        # Wait for container to be healthy
        plog("  Waiting for container...")
        time.sleep(5)
        r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=tak-portal', '--format', '{{.Status}}']), capture_output=True, text=True)
        if 'Up' in r.stdout:
            plog("\u2713 TAK Portal is running")
        else:
            plog("\u26a0 Container may not be fully started yet")

        # Step 5: Copy TAK Server certs into container
        plog("")
        plog("\u2501\u2501\u2501 Step 5/6: Copying TAK Server Certificates \u2501\u2501\u2501")
        # v10.0.1: delegate to _takportal_sync_certs — copies BOTH the client cert
        # (admin.p12 re-encoded to modern PKCS12 via a temp file; the old stdin
        # pipe silently failed on OpenSSL 3 and shipped an unreadable legacy cert)
        # and the CA chain. restart=False: Step 6 writes settings.json and the
        # deploy restarts the container afterwards.
        _certs_ok, _certs_msg = _takportal_sync_certs(plog=plog)
        if _certs_ok:
            plog("\u2713 Certificates copied to container data volume")
        else:
            plog(f"\u26a0 Certificate copy: {_certs_msg}")

        # Step 6: Auto-configure settings.json — use _takportal_build_settings_dict which handles
        # localhost/127.0.0.1 -> host.docker.internal, remote Authentik, token lookup, etc.
        plog("")
        plog("\u2501\u2501\u2501 Step 6/6: Auto-configuring TAK Portal Settings \u2501\u2501\u2501")
        settings = load_settings()
        server_ip = (settings.get('server_ip') or '').strip() or 'localhost'
        import json as json_mod
        portal_settings = _takportal_build_settings_dict(settings)
        ak_token = portal_settings.get('AUTHENTIK_TOKEN', '')
        settings_json = json_mod.dumps(portal_settings, indent=2)
        fd, tmp_settings = tempfile.mkstemp(suffix='.json', prefix='tak-portal-')
        try:
            with os.fdopen(fd, 'w') as f:
                f.write(settings_json)
            subprocess.run(_sudo_wrap(['docker', 'cp', tmp_settings, 'tak-portal:/usr/src/app/data/settings.json']), capture_output=True, text=True)
        finally:
            try:
                os.remove(tmp_settings)
            except OSError:
                pass
        plog(f"  AUTHENTIK_URL (internal): {portal_settings['AUTHENTIK_URL']}")
        plog(f"  AUTHENTIK_PUBLIC_URL: {portal_settings.get('AUTHENTIK_PUBLIC_URL', '')}")
        plog(f"  TAK Server URL: {portal_settings['TAK_URL']}")
        plog(f"  Portal Auth: {portal_settings['PORTAL_AUTH_ENABLED']}")
        if portal_settings.get('EMAIL_ENABLED') == 'true':
            plog(f"  Email: enabled ({portal_settings.get('SMTP_HOST')}:{portal_settings.get('SMTP_PORT')} from {portal_settings.get('SMTP_FROM')})")
        else:
            plog("  Email: not configured (deploy Email Relay first for auto-config)")
        if ak_token:
            plog("  Authentik API token: configured")
        else:
            plog("\u26a0 Authentik not deployed yet - configure token in Server Settings")
        plog("\u2713 Settings auto-configured")

        # SSH: generate keypair and install so TAK Portal can reach host TAK Server
        plog("")
        plog("\u2501\u2501\u2501 Setting up SSH (container \u2192 host) \u2501\u2501\u2501")
        if _takportal_setup_ssh(log_fn=plog):
            plog(f"  SSH target: {portal_settings.get('TAK_SSH_HOST', 'host.docker.internal')}:22 as root")
            plog("\u2713 SSH ready (no handshake needed)")
        else:
            plog("\u26a0 SSH auto-setup failed — configure manually in TAK Portal settings")

        # Restart container to pick up settings
        subprocess.run(_sudo_wrap(['docker', 'restart', 'tak-portal']), capture_output=True, text=True, timeout=30)
        time.sleep(3)
        plog("\u2713 TAK Portal restarted with new settings")

        # Get port
        port = '3000'
        if os.path.exists(env_path):
            with open(env_path) as f:
                for line in f:
                    if line.strip().startswith('WEB_UI_PORT='):
                        port = line.strip().split('=', 1)[1].strip() or '3000'

        # Configure Authentik forward auth for TAK Portal (main: if fqdn and ak_token, single try block)
        fqdn = settings.get('fqdn', '')
        if fqdn and ak_token:
            plog("")
            plog("\u2501\u2501\u2501 Configuring Authentik Forward Auth \u2501\u2501\u2501")
            try:
                import urllib.request as _urlreq
                _ak_headers = {'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'}
                _ak_url = _get_authentik_api_url(settings)

                # Update brand domain
                try:
                    req = _urlreq.Request(f'{_ak_url}/api/v3/core/brands/', headers=_ak_headers)
                    resp = _urlreq.urlopen(req, timeout=10)
                    brands = json_mod.loads(resp.read().decode())['results']
                    if brands:
                        brand_id = brands[0]['brand_uuid']
                        ak_host = _get_authentik_host(settings)
                        if ak_host:
                            req = _urlreq.Request(f'{_ak_url}/api/v3/core/brands/{brand_id}/',
                                data=json_mod.dumps({'domain': ak_host}).encode(),
                                headers=_ak_headers, method='PATCH')
                            _urlreq.urlopen(req, timeout=10)
                            plog(f"  \u2713 Brand domain set to {ak_host}")
                except Exception as e:
                    plog(f"  \u26a0 Brand update: {str(e)[:80]}")

                # Wait up to 15 min for authorization flow
                flow_pk = None
                for attempt in range(180):
                    try:
                        req = _urlreq.Request(f'{_ak_url}/api/v3/flows/instances/?designation=authorization&ordering=slug', headers=_ak_headers)
                        resp = _urlreq.urlopen(req, timeout=10)
                        flows = json_mod.loads(resp.read().decode())['results']
                        for fl in flows:
                            if 'implicit' in fl.get('slug', ''):
                                flow_pk = fl['pk']
                                break
                        if not flow_pk and flows:
                            flow_pk = flows[0]['pk']
                        if flow_pk:
                            break
                    except Exception:
                        pass
                    if attempt % 6 == 0:
                        plog(f"  ⏳ Waiting for authorization flow... ({attempt * 5}s)")
                    else:
                        authentik_deploy_log.append(f"  ⏳ {attempt * 5 // 60:02d}:{attempt * 5 % 60:02d}")
                    time.sleep(5)
                if flow_pk:
                    plog(f"  ✓ Got authorization flow")
                else:
                    plog(f"  ⚠ No authorization flow found after 15 min — proxy provider skipped")

                # Wait up to 15 min for invalidation flow
                inv_flow_pk = None
                for attempt in range(180):
                    try:
                        req = _urlreq.Request(f'{_ak_url}/api/v3/flows/instances/?designation=invalidation', headers=_ak_headers)
                        resp = _urlreq.urlopen(req, timeout=10)
                        inv_flows = json_mod.loads(resp.read().decode())['results']
                        inv_flow_pk = next((f['pk'] for f in inv_flows if 'provider' not in f['slug']), inv_flows[0]['pk'] if inv_flows else None)
                        if inv_flow_pk:
                            break
                    except Exception:
                        pass
                    if attempt % 6 == 0:
                        plog(f"  ⏳ Waiting for invalidation flow... ({attempt * 5}s)")
                    else:
                        authentik_deploy_log.append(f"  ⏳ {attempt * 5 // 60:02d}:{attempt * 5 % 60:02d}")
                    time.sleep(5)
                if inv_flow_pk:
                    plog(f"  ✓ Got invalidation flow")
                else:
                    plog(f"  ⚠ No invalidation flow found after 15 min — proxy provider skipped")

                # Create proxy provider
                provider_pk = None
                if flow_pk and inv_flow_pk:
                    try:
                        _tp_host = f'https://{_get_service_domain(settings, "takportal") or f"takportal.{fqdn}"}'
                        _tp_cookie = f'.{fqdn.split(":")[0]}'
                        req = _urlreq.Request(f'{_ak_url}/api/v3/providers/proxy/',
                            data=json_mod.dumps({'name': 'TAK Portal Proxy', 'authorization_flow': flow_pk,
                                'invalidation_flow': inv_flow_pk,
                                'external_host': _tp_host, 'mode': 'forward_single',
                                'token_validity': 'hours=24', 'cookie_domain': _tp_cookie}).encode(),
                            headers=_ak_headers, method='POST')
                        resp = _urlreq.urlopen(req, timeout=10)
                        provider_pk = json_mod.loads(resp.read().decode())['pk']
                        plog(f"  \u2713 Proxy provider created")
                    except Exception as e:
                        if hasattr(e, 'code') and e.code == 400:
                            req = _urlreq.Request(f'{_ak_url}/api/v3/providers/proxy/?search=TAK+Portal', headers=_ak_headers)
                            resp = _urlreq.urlopen(req, timeout=10)
                            results = json_mod.loads(resp.read().decode())['results']
                            if results:
                                provider_pk = results[0]['pk']
                                try:
                                    req = _urlreq.Request(f'{_ak_url}/api/v3/providers/proxy/{provider_pk}/',
                                        data=json_mod.dumps({'external_host': _tp_host, 'cookie_domain': _tp_cookie}).encode(),
                                        headers=_ak_headers, method='PATCH')
                                    _urlreq.urlopen(req, timeout=10)
                                except Exception:
                                    pass
                            plog(f"  \u2713 Proxy provider already exists (external_host updated)")
                        else:
                            plog(f"  \u26a0 Proxy provider error: {str(e)[:100]}")

                # Create application (retry — Authentik API can be slow on fresh deploys)
                if provider_pk:
                    app_created = False
                    for app_attempt in range(1, 4):
                        try:
                            req = _urlreq.Request(f'{_ak_url}/api/v3/core/applications/',
                                data=json_mod.dumps({'name': 'TAK Portal', 'slug': 'tak-portal',
                                    'provider': provider_pk, 'open_in_new_tab': True}).encode(),
                                headers=_ak_headers, method='POST')
                            _urlreq.urlopen(req, timeout=30)
                            plog(f"  \u2713 Application 'TAK Portal' created")
                            app_created = True
                            break
                        except Exception as e:
                            if hasattr(e, 'code') and e.code == 400:
                                plog(f"  \u2713 Application 'TAK Portal' already exists")
                                app_created = True
                                break
                            elif app_attempt < 3:
                                plog(f"  \u26a0 Application create: {str(e)[:60]} (retry {app_attempt}/2)")
                                time.sleep(5)
                            else:
                                plog(f"  \u26a0 Application error: {str(e)[:80]}")
                    _authentik_application_open_in_new_tab(_ak_url, _ak_headers, 'tak-portal', plog=plog)

                    # Add to embedded outpost (retry-safe; API can still be warming up)
                    outpost_ok = False
                    for attempt in range(1, 6):
                        try:
                            req = _urlreq.Request(f'{_ak_url}/api/v3/outposts/instances/?search=embedded', headers=_ak_headers)
                            resp = _urlreq.urlopen(req, timeout=30)
                            outposts = json_mod.loads(resp.read().decode())['results']
                            embedded = next((o for o in outposts if 'embed' in o.get('name','').lower() or o.get('type') == 'proxy'), None)
                            if not embedded:
                                plog(f"  \u26a0 No embedded outpost found")
                                break
                            detail_req = _urlreq.Request(f'{_ak_url}/api/v3/outposts/instances/{embedded["pk"]}/', headers=_ak_headers)
                            detail = _urlreq.urlopen(detail_req, timeout=15)
                            full = json_mod.loads(detail.read().decode())
                            raw = full.get('providers') or []
                            current_pks = []
                            for p in raw:
                                if isinstance(p, int):
                                    current_pks.append(p)
                                elif isinstance(p, dict):
                                    pk = p.get('pk') or p.get('id')
                                    if pk is not None:
                                        current_pks.append(pk)
                            if provider_pk not in current_pks:
                                current_pks.append(provider_pk)
                                patch_req = _urlreq.Request(f'{_ak_url}/api/v3/outposts/instances/{embedded["pk"]}/',
                                    data=json_mod.dumps({'providers': current_pks}).encode(),
                                    headers=_ak_headers, method='PATCH')
                                _urlreq.urlopen(patch_req, timeout=30)
                            outpost_ok = True
                            plog(f"  \u2713 TAK Portal added to embedded outpost")
                            break
                        except Exception as e:
                            if attempt < 5:
                                plog(f"  \u26a0 Outpost error: {str(e)[:80]} (retry {attempt}/4)")
                                time.sleep(5)
                            else:
                                plog(f"  \u26a0 Outpost error: {str(e)[:80]}")
                    if not outpost_ok:
                        plog("  \u26a0 Continuing -- outpost attach can self-heal on Authentik reconfigure")
            except Exception as e:
                plog(f"  \u26a0 Forward auth setup error: {str(e)[:100]}")

        plog("")
        plog("=" * 50)
        plog(f"\u2713 TAK Portal deployed successfully!")
        plog(f"  Access: http://{server_ip}:{port}")
        # Regenerate Caddyfile if Caddy is configured
        if settings.get('fqdn'):
            generate_caddyfile(settings)
            subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True)
            plog(f"  \u2713 Caddy config updated for TAK Portal")
            plog(f"  Open: https://{_get_service_domain(settings, 'takportal')}")
        plog("=" * 50)
        plog("")
        plog("  Waiting 2 minutes for Authentik to fully sync...")
        for i in range(24):
            time.sleep(5)
            remaining = 120 - (i + 1) * 5
            if remaining % 30 == 0:
                plog(f"  ⏳ {remaining} seconds remaining...")
        plog("  ✓ Sync complete — TAK Portal is ready")
        _update_boot_stagger_service()
        takportal_deploy_status.update({'running': False, 'complete': True})
    except Exception as e:
        plog(f"\u2717 FATAL ERROR: {str(e)}")
        takportal_deploy_status.update({'running': False, 'error': True})

@app.route('/certs')
@login_required
def certs_page():
    settings = load_settings()
    cert_dir = '/opt/tak/certs/files'
    files = []
    if os.path.isdir(cert_dir):
        for fn in sorted(os.listdir(cert_dir)):
            fp = os.path.join(cert_dir, fn)
            if os.path.isfile(fp):
                sz = os.path.getsize(fp)
                if sz < 1024: sz_d = f"{sz} B"
                elif sz < 1048576: sz_d = f"{round(sz/1024,1)} KB"
                else: sz_d = f"{round(sz/1048576,1)} MB"
                ext = fn.split('.')[-1].lower() if '.' in fn else ''
                icon = {'p12':'🔑','pem':'📄','jks':'☕','crt':'📜','key':'🔐','crl':'📋','csr':'📝'}.get(ext, '📁')
                files.append({'name': fn, 'size': sz_d, 'icon': icon, 'ext': ext})
    return render_template_string(CERTS_TEMPLATE, settings=settings, files=files, version=VERSION)

