@app.route('/api/mediamtx/deploy', methods=['POST'])
@login_required
def mediamtx_deploy_api():
    if mediamtx_deploy_status.get('running'):
        return jsonify({'error': 'Deployment already in progress'}), 409
    data = request.get_json() or {}
    if data.get('config'):
        settings = load_settings()
        cfg = _normalize_module_deployment_config(data['config'])
        settings['mediamtx_deployment'] = cfg
        save_settings(settings)
    mediamtx_deploy_log.clear()
    mediamtx_deploy_status.update({'running': True, 'complete': False, 'error': False})
    threading.Thread(target=run_mediamtx_deploy, daemon=True).start()
    return jsonify({'success': True})

@app.route('/api/mediamtx/deploy/log')
@login_required
def mediamtx_deploy_log_api():
    idx = request.args.get('index', 0, type=int)
    return jsonify({'entries': mediamtx_deploy_log[idx:], 'total': len(mediamtx_deploy_log),
        'running': mediamtx_deploy_status['running'], 'complete': mediamtx_deploy_status['complete'],
        'error': mediamtx_deploy_status['error']})

@app.route('/api/mediamtx/control', methods=['POST'])
@login_required
def mediamtx_control():
    action = (request.json or {}).get('action', '')
    if action not in ('start', 'stop', 'restart'):
        return jsonify({'error': 'Invalid action'}), 400
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
    if deploy_cfg.get('target_mode') == 'remote':
        remote = deploy_cfg.get('remote', {})
        if not (remote.get('host') or '').strip():
            return jsonify({'error': 'Remote host not configured'}), 400
        cmd = f'systemctl {action} mediamtx mediamtx-webeditor 2>&1'
        ok, _ = _ssh_probe(remote, cmd, timeout=30)
        time.sleep(2)
        ok2, out = _ssh_probe(remote, 'systemctl is-active mediamtx 2>/dev/null', timeout=10)
        running = bool(ok2 and out and out.strip() == 'active')
        return jsonify({'success': True, 'running': running})
    if action == 'start':
        subprocess.run(_sudo_wrap(['systemctl', 'start', 'mediamtx', 'mediamtx-webeditor']), capture_output=True)
    elif action == 'stop':
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'mediamtx', 'mediamtx-webeditor']), capture_output=True)
    elif action == 'restart':
        subprocess.run(_sudo_wrap(['systemctl', 'restart', 'mediamtx', 'mediamtx-webeditor']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT)
    time.sleep(2)
    r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'mediamtx']), capture_output=True, text=True)
    running = r.stdout.strip() == 'active'
    return jsonify({'success': True, 'running': running})


MEDIAMTX_EDITOR_RAW_URL = f'https://raw.githubusercontent.com/takwerx/mediamtx-installer/{MEDIAMTX_EDITOR_REF}/config-editor/mediamtx_config_editor.py'


@app.route('/api/mediamtx/recovery', methods=['POST'])
@login_required
def mediamtx_recovery():
    """Patch web editor: refresh editor, apply endpoint patch, sync overlay file, install prestart script, restart."""
    import tempfile
    import urllib.request
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
    tmp_f = None
    editor_path = '/opt/mediamtx-webeditor/mediamtx_config_editor.py'
    try:
        # 1) Refresh editor from upstream so we fix corruption / duplicate UI from old or patched copies
        if deploy_cfg.get('target_mode') == 'remote' and (deploy_cfg.get('remote', {}).get('host') or '').strip():
            _module_run(
                deploy_cfg,
                "mkdir -p /opt/mediamtx-webeditor && curl -sL '" + MEDIAMTX_EDITOR_RAW_URL + "' -o /opt/mediamtx-webeditor/mediamtx_config_editor.py",
                timeout=90,
            )
            # v0.9.12: also bind webedit Flask app to 127.0.0.1 (Tier 3 — Caddy
            # is the only legitimate consumer; upstream defaults to 0.0.0.0).
            _module_run(
                deploy_cfg,
                "sed -i 's/port=5000/port=5080/' /opt/mediamtx-webeditor/mediamtx_config_editor.py 2>/dev/null; "
                "sed -i 's/9997/9898/g' /opt/mediamtx-webeditor/mediamtx_config_editor.py 2>/dev/null; "
                "sed -i \"s/host='0\\.0\\.0\\.0'/host='127.0.0.1'/\" /opt/mediamtx-webeditor/mediamtx_config_editor.py 2>/dev/null",
                timeout=10,
            )
        else:
            try:
                with urllib.request.urlopen(MEDIAMTX_EDITOR_RAW_URL, timeout=60) as r:
                    content = r.read().decode('utf-8')
                # v10.0.5 non-root: apply the bind-hardening patches in Python, then write via the
                # broker (/opt/mediamtx-webeditor is root-owned on root-era installs; the old
                # open('w') + `sed -i` failed as takwerx, leaving the editor bound to 0.0.0.0).
                content = (content.replace('port=5000', 'port=5080')
                                  .replace('9997', '9898')
                                  .replace("host='0.0.0.0'", "host='127.0.0.1'"))
                _write_priv(editor_path, content)
            except Exception:
                pass  # keep existing file and just re-apply patches
        # 2) Apply endpoint patch only (keep core External Sources rendering unchanged)
        if deploy_cfg.get('target_mode') == 'remote' and (deploy_cfg.get('remote', {}).get('host') or '').strip():
            for name, script in [
                ('mtx_endpoint_patch', MEDIAMTX_REMOTE_EP_PATCH_SCRIPT),
            ]:
                with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as pf:
                    pf.write(script)
                    tmp_patch = pf.name
                copy_ok, _cm = _module_copy(deploy_cfg, tmp_patch, f'/tmp/{name}.py', timeout=15)
                try:
                    os.unlink(tmp_patch)
                except Exception:
                    pass
                if copy_ok:
                    _module_run(deploy_cfg, f'python3 /tmp/{name}.py && rm -f /tmp/{name}.py', timeout=15)
        else:
            try:
                src = _read_priv(editor_path)   # v10.0.5 non-root: broker (root-owned dir)
                if src:
                    src = _mediamtx_editor_endpoint_patch(src)
                    _write_priv(editor_path, src)
            except Exception:
                pass
        # 3) Always sync live overlay file from current infra-TAK repo to target.
        # This prevents stale overlay scripts on existing installs from injecting old UI logic.
        try:
            overlay_src = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'mediamtx_ldap_overlay.py')
            if os.path.exists(overlay_src):
                _module_run(deploy_cfg, 'mkdir -p /opt/mediamtx-webeditor', timeout=10)
                _module_copy(
                    deploy_cfg,
                    overlay_src,
                    '/opt/mediamtx-webeditor/mediamtx_ldap_overlay.py',
                    timeout=20
                )
        except Exception:
            pass
        tmp_f = tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False)
        tmp_f.write(MEDIAMTX_ENSURE_OVERLAY_SCRIPT)
        tmp_f.close()
        copy_ok, _cm = _module_copy(deploy_cfg, tmp_f.name, '/tmp/ensure_overlay.py', timeout=15)
        if not copy_ok:
            return jsonify({'error': 'Failed to copy overlay script to target'}), 500
        # Install script, make ExecStartPre best-effort so a failing pre-step cannot block start, then restart
        cmd = (
            'mv /tmp/ensure_overlay.py /opt/mediamtx-webeditor/ensure_overlay.py && chmod 755 /opt/mediamtx-webeditor/ensure_overlay.py && '
            "sed -i 's|^ExecStartPre=/usr/bin/python3|ExecStartPre=-/usr/bin/python3|' /etc/systemd/system/mediamtx-webeditor.service 2>/dev/null; "
            'systemctl daemon-reload 2>/dev/null; systemctl restart mediamtx-webeditor 2>/dev/null; true'
        )
        ok_run, out = _module_run(deploy_cfg, cmd, timeout=25)
        if not ok_run:
            return jsonify({'error': 'Failed to install or restart web editor', 'detail': (out or '')[:500]}), 500
        # Check if web editor actually came up
        ok_check, check_out = _module_run(deploy_cfg, 'systemctl is-active mediamtx-webeditor 2>/dev/null', timeout=10)
        active = ok_check and (check_out or '').strip() == 'active'
        msg = 'Web editor patched; mediamtx-webeditor restarted and is running.' if active else (
            'Patch applied and service restarted, but mediamtx-webeditor may still be down. '
            'Click **Web editor logs** on this page to see why.'
        )
        return jsonify({'success': True, 'message': msg, 'webeditor_running': active})
    except Exception as e:
        return jsonify({'error': str(e)[:200]}), 500
    finally:
        if tmp_f and os.path.exists(tmp_f.name):
            try:
                os.unlink(tmp_f.name)
            except Exception:
                pass


_MEDIAMTX_LOG_UNITS = {'mediamtx', 'mediamtx-webeditor'}

@app.route('/api/mediamtx/logs')
@login_required
def mediamtx_logs():
    lines = min(max(request.args.get('lines', 60, type=int), 1), 10000)
    unit = request.args.get('unit', 'mediamtx')
    if unit not in _MEDIAMTX_LOG_UNITS:
        return jsonify({'error': 'Invalid unit'}), 400
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
    if deploy_cfg.get('target_mode') == 'remote' and (deploy_cfg.get('remote', {}).get('host') or '').strip():
        ok, out = _ssh_probe(deploy_cfg['remote'], f'journalctl -u {unit} --no-pager -n {lines} 2>&1', timeout=15)
        entries = [l for l in (out.strip().split('\n') if out and out.strip() else []) if l.strip()] if ok else []
        return jsonify({'entries': entries})
    r = subprocess.run(['journalctl', '-u', unit, '--no-pager', '-n', str(lines)], capture_output=True, text=True, timeout=10)
    entries = [l for l in (r.stdout.strip().split('\n') if r.stdout.strip() else []) if l.strip()]
    return jsonify({'entries': entries})

@app.route('/api/mediamtx/uninstall', methods=['POST'])
@login_required
def mediamtx_uninstall():
    data = request.json or {}
    password = data.get('password', '')
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'error': 'Invalid admin password'}), 403
    steps = []
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
    if deploy_cfg.get('target_mode') == 'remote':
        remote = deploy_cfg.get('remote', {})
        if (remote.get('host') or '').strip():
            ok, out = _ssh_probe(remote, 'systemctl stop mediamtx mediamtx-webeditor 2>/dev/null; systemctl disable mediamtx mediamtx-webeditor 2>/dev/null; true', timeout=15)
            _ssh_probe(remote, 'rm -f /etc/systemd/system/mediamtx.service /etc/systemd/system/mediamtx-webeditor.service /usr/local/bin/mediamtx /usr/local/etc/mediamtx.yml', timeout=10)
            _ssh_probe(remote, 'rm -rf /opt/mediamtx-webeditor', timeout=10)
            _ssh_probe(remote, 'systemctl daemon-reload 2>/dev/null; true', timeout=10)
            steps.append('Stopped and removed MediaMTX on remote host')
        settings['mediamtx_deployment'] = dict(deploy_cfg)
        settings['mediamtx_deployment']['deployed'] = False
        save_settings(settings)
    else:
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'mediamtx', 'mediamtx-webeditor']), capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', 'mediamtx', 'mediamtx-webeditor']), capture_output=True)
        for f in ['/etc/systemd/system/mediamtx.service', '/etc/systemd/system/mediamtx-webeditor.service',
                  '/usr/local/bin/mediamtx', '/usr/local/etc/mediamtx.yml']:
            subprocess.run(_sudo_wrap(['rm', '-f', f]), capture_output=True)  # v10.0.5 non-root: root-owned
        if os.path.exists('/opt/mediamtx-webeditor'):
            subprocess.run(_sudo_wrap(['rm', '-rf', '/opt/mediamtx-webeditor']), capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True)
        steps.append('Stopped and disabled mediamtx and mediamtx-webeditor services')
        steps.append('Removed binary, config, and web editor files')
    mediamtx_deploy_log.clear()
    mediamtx_deploy_status.update({'running': False, 'complete': False, 'error': False})
    generate_caddyfile(settings)
    subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True)
    steps.append('Updated Caddyfile')
    _deregister_authentik_proxy_app(settings, 'stream', 'MediaMTX', plog=lambda m: steps.append(m.strip()))
    return jsonify({'success': True, 'steps': steps})

def _run_mediamtx_deploy_remote(settings, deploy_cfg, plog):
    """Run MediaMTX deploy on a remote host via SSH."""
    import re as _re
    import secrets as _sec
    remote = deploy_cfg.get('remote', {})
    host = (remote.get('host') or '').strip()
    if not host:
        plog("✗ Remote host not configured")
        mediamtx_deploy_status.update({'running': False, 'error': True})
        return
    plog(f"  Deploying to remote host: {host}")

    # Step 1: Dependencies
    plog("━━━ Step 1/7: Installing Dependencies (remote) ━━━")
    ok, out = _module_run(deploy_cfg, 'apt-get update -qq && apt-get install -y wget tar curl ffmpeg openssl python3 python3-pip 2>&1', timeout=300, log_fn=plog)
    if not ok:
        plog(f"✗ apt install failed: {(out or '')[-300:]}")
        mediamtx_deploy_status.update({'running': False, 'error': True})
        return
    plog("✓ Dependencies installed")
    ok, _ = _module_run(deploy_cfg, 'pip3 install Flask ruamel.yaml requests psutil --break-system-packages 2>&1', timeout=120)
    if not ok:
        _module_run(deploy_cfg, 'pip3 install Flask ruamel.yaml requests psutil 2>&1', timeout=120)
    plog("✓ Python packages installed")

    # v0.9.31: ensure `takwerx` system user exists on the remote host before
    # any chown / unit install happens. See `_ensure_takwerx_system_user`
    # docstring for the full backstory. Idempotent.
    plog("  Ensuring takwerx system user on remote host...")
    created = _ensure_takwerx_system_user_remote(deploy_cfg, plog=plog)
    if not created:
        plog("  ✓ takwerx system user already present on remote host")

    # Step 2: Version + arch on remote
    plog("")
    plog("━━━ Step 2/7: Detecting MediaMTX Version ━━━")
    r = subprocess.run('curl -s https://api.github.com/repos/bluenviron/mediamtx/releases/latest', shell=True, capture_output=True, text=True, timeout=30)
    m = _re.search(r'"tag_name":\s*"v([^"]+)"', r.stdout or '')
    if not m:
        plog("✗ Could not detect latest MediaMTX version")
        mediamtx_deploy_status.update({'running': False, 'error': True})
        return
    version = m.group(1)
    ok, arch_out = _module_run(deploy_cfg, 'uname -m', timeout=10)
    arch_raw = (arch_out or '').strip() or 'x86_64'
    arch_map = {'x86_64': 'amd64', 'aarch64': 'arm64', 'armv7l': 'armv7'}
    mtx_arch = arch_map.get(arch_raw, 'amd64')
    plog(f"  Version: {version}, arch: {arch_raw} → {mtx_arch}")

    # Step 3: Download and install binary on remote
    plog("")
    plog("━━━ Step 3/7: Downloading & Installing MediaMTX (remote) ━━━")
    url = f"https://github.com/bluenviron/mediamtx/releases/download/v{version}/mediamtx_v{version}_linux_{mtx_arch}.tar.gz"
    # restorecon relabels the binary to bin_t on RHEL/SELinux (mv from /tmp keeps
    # tmp_t → systemd 203/EXEC); no-op on Debian (|| true). Universal one-liner.
    cmd = f'cd /tmp && wget -q -O mediamtx.tar.gz "{url}" && tar -xzf mediamtx.tar.gz && mv -f mediamtx /usr/local/bin/ && chmod +x /usr/local/bin/mediamtx && (restorecon /usr/local/bin/mediamtx 2>/dev/null || chcon -t bin_t /usr/local/bin/mediamtx 2>/dev/null || true) && rm -f mediamtx.tar.gz'
    ok, out = _module_run(deploy_cfg, cmd, timeout=120, log_fn=plog)
    if not ok:
        plog(f"✗ Download/install failed: {(out or '')[-200:]}")
        mediamtx_deploy_status.update({'running': False, 'error': True})
        return
    plog(f"✓ MediaMTX v{version} installed")

    # Step 4: Config
    plog("")
    plog("━━━ Step 4/7: Writing Configuration (remote) ━━━")
    hls_pass = _sec.token_hex(8)
    # apiAddress stays on 127.0.0.1 (webedit Flask calls it locally on the remote host).
    # hlsAddress is 0.0.0.0 so Caddy on the console can reverse-proxy HLS streams;
    # UFW below restricts port 8888 to the console IP only.
    mediamtx_yml = f"""# MediaMTX - infra-TAK remote
logLevel: info
logDestinations: [stdout]
readTimeout: 10s
writeTimeout: 10s
api: yes
apiAddress: 127.0.0.1:9898
apiEncryption: no
apiAllowOrigins: ['*']
rtsp: yes
rtspTransports: [tcp]
rtspAddress: :8554
rtspsAddress: :8322
rtpAddress: :8000
rtcpAddress: :8001
rtmp: no
rtmpAddress: :1935
hls: yes
hlsAddress: 0.0.0.0:8888
hlsAllowOrigins: ['*']
hlsTrustedProxies: ['127.0.0.1']
webrtc: no
srt: yes
srtAddress: :8890
authMethod: internal
authInternalUsers:
- user: any
  ips: ['127.0.0.1', '::1']
  permissions:
  - action: read
  - action: publish
  - action: api
- user: hlsviewer
  pass: {hls_pass}
  ips: []
  permissions:
  - action: read
- user: any
  pass: ''
  ips: []
  permissions:
  - action: read
    path: teststream
authHTTPAddress:
authHTTPExclude:
- action: api
- action: metrics
- action: pprof

rtspServerKey:
rtspServerCert:
rtspAuthMethods: [basic]
rtspEncryption: "no"
rtmpEncryption: "no"
rtmpsAddress: :1936
rtmpServerKey:
rtmpServerCert:
hlsEncryption: no
hlsServerKey:
hlsServerCert:
hlsAlwaysRemux: no
hlsVariant: mpegts
hlsSegmentCount: 3
hlsSegmentDuration: 500ms
hlsPartDuration: 200ms
hlsSegmentMaxSize: 50M
hlsDirectory: ''
hlsMuxerCloseAfter: 60s

paths:
  teststream: {{}}
  all_others: {{}}
"""
    tmp_yml = '/tmp/mediamtx_remote.yml'
    with open(tmp_yml, 'w') as f:
        f.write(mediamtx_yml)
    ok, _ = _module_copy(deploy_cfg, tmp_yml, '/tmp/mediamtx.yml', log_fn=plog)
    try:
        os.remove(tmp_yml)
    except Exception:
        pass
    if not ok:
        plog("✗ Failed to copy config to remote")
        mediamtx_deploy_status.update({'running': False, 'error': True})
        return
    ok, _ = _module_run(deploy_cfg, 'sudo mv /tmp/mediamtx.yml /usr/local/etc/mediamtx.yml', timeout=10)
    if not ok:
        _module_run(deploy_cfg, 'mv /tmp/mediamtx.yml /usr/local/etc/mediamtx.yml', timeout=10)
    plog("✓ Configuration written")
    plog(f"  HLS viewer password: {'*' * max(0, len(hls_pass) - 4) + hls_pass[-4:]}")

    # Step 5: systemd mediamtx.service
    plog("")
    plog("━━━ Step 5/7: Creating systemd Services (remote) ━━━")
    mediamtx_svc = "[Unit]\nDescription=MediaMTX RTSP/HLS/SRT Streaming Server\nAfter=network.target\n\n[Service]\nType=simple\nExecStart=/usr/local/bin/mediamtx /usr/local/etc/mediamtx.yml\nRestart=always\nRestartSec=5\nUser=takwerx\n\n[Install]\nWantedBy=multi-user.target\n"
    tmp_svc = '/tmp/mediamtx_remote.service'
    with open(tmp_svc, 'w') as f:
        f.write(mediamtx_svc)
    ok, _ = _module_copy(deploy_cfg, tmp_svc, '/tmp/mediamtx.service', log_fn=plog)
    try:
        os.remove(tmp_svc)
    except Exception:
        pass
    if not ok:
        plog("✗ Failed to copy systemd unit")
        mediamtx_deploy_status.update({'running': False, 'error': True})
        return
    _module_run(deploy_cfg, 'sudo mv /tmp/mediamtx.service /etc/systemd/system/mediamtx.service || mv /tmp/mediamtx.service /etc/systemd/system/mediamtx.service', timeout=10)
    # Web editor: clone on remote and install
    _module_run(deploy_cfg, 'mkdir -p /opt/mediamtx-webeditor', timeout=10)
    ok, _ = _module_run(deploy_cfg, f'rm -rf /tmp/mediamtx_editor_clone && git clone --depth 1 --branch "{MEDIAMTX_EDITOR_REF}" "{MEDIAMTX_EDITOR_REPO}" /tmp/mediamtx_editor_clone', timeout=90)
    if ok:
        _module_run(deploy_cfg, 'cp /tmp/mediamtx_editor_clone/config-editor/mediamtx_config_editor.py /opt/mediamtx-webeditor/ 2>/dev/null; rm -rf /tmp/mediamtx_editor_clone', timeout=15)
        # Remote: bind Flask webedit to 0.0.0.0 so Caddy on the console can reach it.
        # Port 5080 will be UFW source-scoped to the console IP only (Step 6/7).
        _module_run(deploy_cfg, "sed -i 's/port=5000/port=5080/' /opt/mediamtx-webeditor/mediamtx_config_editor.py 2>/dev/null; sed -i 's/9997/9898/g' /opt/mediamtx-webeditor/mediamtx_config_editor.py 2>/dev/null", timeout=10)
        # Patch HLS URLs to go through Caddy /hls-proxy/ instead of direct port 8888 (avoids mixed content)
        hls_patch_script = (
            "import re, sys\n"
            "f = '/opt/mediamtx-webeditor/mediamtx_config_editor.py'\n"
            "with open(f) as fh: s = fh.read()\n"
            "# Active streams API: hls_url\n"
            "s = re.sub(r\"stream_info\\['hls_url'\\] = f\\\"\\{hls_protocol\\}://\\{hls_domain\\}:8888/\\{path_name\\}/index\\.m3u8\\\"\",\n"
            "           \"stream_info['hls_url'] = f\\\"/hls-proxy/{path_name}/index.m3u8\\\"\", s)\n"
            "# Shared viewer hls_base\n"
            "s = re.sub(r'hls_base = f\"\\{streaming\\[.protocol.\\]\\}://\\{streaming\\[.domain.\\]\\}:8888\"',\n"
            "           'hls_base = \"/hls-proxy\"', s)\n"
            "s = re.sub(r'hls_base = f\"http://\\{request\\.host\\.split.*?:8888\"',\n"
            "           'hls_base = \"/hls-proxy\"', s)\n"
            "# Test stream URLs\n"
            "s = re.sub(r\"'hls': f'\\{protocol\\}://\\{domain\\}:8888/teststream/index\\.m3u8'\",\n"
            "           \"'hls': '/hls-proxy/teststream/index.m3u8'\", s)\n"
            "# Fix watchStream new URL() to handle relative paths\n"
            "s = s.replace('const url = new URL(streamUrl);', 'const url = new URL(streamUrl, window.location.origin);')\n"
            "with open(f, 'w') as fh: fh.write(s)\n"
        )
        with open('/tmp/mtx_hls_patcher.py', 'w') as pf:
            pf.write(hls_patch_script)
        _module_copy(deploy_cfg, '/tmp/mtx_hls_patcher.py', '/tmp/mtx_hls_patcher.py', log_fn=plog)
        _module_run(deploy_cfg, 'python3 /tmp/mtx_hls_patcher.py && rm -f /tmp/mtx_hls_patcher.py', timeout=15)
        try:
            os.remove('/tmp/mtx_hls_patcher.py')
        except Exception:
            pass
        plog("✓ HLS URLs patched for HTTPS proxy")
    # LDAP overlay: when Authentik is present locally, patch remote editor for header auth
    ak_installed = os.path.exists(os.path.expanduser('~/authentik/docker-compose.yml'))
    ldap_env_lines = ''
    if ak_installed:
        overlay_src = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'mediamtx_ldap_overlay.py')
        if os.path.exists(overlay_src):
            ok_ov, _ = _module_copy(deploy_cfg, overlay_src, '/tmp/mediamtx_ldap_overlay.py', log_fn=plog)
            if ok_ov:
                _module_run(deploy_cfg, 'mv /tmp/mediamtx_ldap_overlay.py /opt/mediamtx-webeditor/mediamtx_ldap_overlay.py', timeout=10)
                patcher = (
                    "import sys\n"
                    "EDITOR = '/opt/mediamtx-webeditor/mediamtx_config_editor.py'\n"
                    "MARKER = '# --- infra-TAK LDAP overlay ---'\n"
                    "with open(EDITOR) as f: src = f.read()\n"
                    "if MARKER in src: sys.exit(0)\n"
                    "inject = (\n"
                    "    '\\n' + MARKER + '\\n'\n"
                    "    'import os as _os\\n'\n"
                    "    \"if _os.environ.get(\\'LDAP_ENABLED\\'):\\n\"\n"
                    "    '    import sys as _sys; _sys.path.insert(0, _os.path.dirname(_os.path.abspath(__file__)))\\n'\n"
                    "    '    from mediamtx_ldap_overlay import apply_ldap_overlay\\n'\n"
                    "    '    apply_ldap_overlay(app)\\n'\n"
                    "    '# --- end LDAP overlay ---\\n'\n"
                    ")\n"
                    "lines = src.splitlines(keepends=True)\n"
                    "done = False\n"
                    "for i, line in enumerate(lines):\n"
                    "    if 'app = Flask(' in line:\n"
                    "        lines.insert(i + 1, '\\n' + inject)\n"
                    "        done = True; break\n"
                    "if not done:\n"
                    "    for i, line in enumerate(lines):\n"
                    "        if 'app.run(' in line:\n"
                    "            lines.insert(i, '\\n' + inject)\n"
                    "            done = True; break\n"
                    "if done:\n"
                    "    with open(EDITOR, 'w') as f: f.writelines(lines)\n"
                )
                with open('/tmp/mtx_ldap_patcher.py', 'w') as pf:
                    pf.write(patcher)
                _module_copy(deploy_cfg, '/tmp/mtx_ldap_patcher.py', '/tmp/mtx_ldap_patcher.py', log_fn=plog)
                _module_run(deploy_cfg, 'python3 /tmp/mtx_ldap_patcher.py && rm -f /tmp/mtx_ldap_patcher.py', timeout=15)
                try:
                    os.remove('/tmp/mtx_ldap_patcher.py')
                except Exception:
                    pass
                plog("✓ LDAP overlay applied (Authentik header auth)")
                # Endpoint patch so shared_stream_page / shared_hls_proxy don't duplicate (Flask AssertionError)
                with open('/tmp/mtx_endpoint_patch.py', 'w') as pf:
                    pf.write(MEDIAMTX_REMOTE_EP_PATCH_SCRIPT)
                _module_copy(deploy_cfg, '/tmp/mtx_endpoint_patch.py', '/tmp/mtx_endpoint_patch.py', log_fn=plog)
                _module_run(deploy_cfg, 'python3 /tmp/mtx_endpoint_patch.py && rm -f /tmp/mtx_endpoint_patch.py', timeout=15)
                try:
                    os.remove('/tmp/mtx_endpoint_patch.py')
                except Exception:
                    pass
                plog("✓ Endpoint patch applied (shared_stream_page, shared_hls_proxy)")
            else:
                plog("⚠ Failed to copy LDAP overlay to remote")
        else:
            plog("⚠ mediamtx_ldap_overlay.py not found — LDAP overlay skipped")
        ak_token_val = ''
        ak_env_path = os.path.expanduser('~/authentik/.env')
        if os.path.exists(ak_env_path):
            with open(ak_env_path) as _f:
                for _line in _f:
                    if _line.strip().startswith('AUTHENTIK_BOOTSTRAP_TOKEN='):
                        ak_token_val = _line.strip().split('=', 1)[1].strip()
        ak_public_url = f'https://{_get_authentik_host(settings)}' if settings.get('fqdn') else 'http://127.0.0.1:9090'
        ldap_env_lines = (
            f'Environment=LDAP_ENABLED=1\n'
            f'Environment=AUTHENTIK_API_URL={ak_public_url}\n'
            f'Environment=AUTHENTIK_TOKEN={ak_token_val}\n'
        )
    editor_svc = f"[Unit]\nDescription=MediaMTX Web Configuration Editor\nAfter=network.target mediamtx.service\n\n[Service]\nType=simple\nExecStart=/usr/bin/python3 /opt/mediamtx-webeditor/mediamtx_config_editor.py\nWorkingDirectory=/opt/mediamtx-webeditor\nEnvironment=PORT=5080\nEnvironment=MEDIAMTX_API_URL=http://127.0.0.1:9898\n{ldap_env_lines}Restart=always\nRestartSec=5\nUser=takwerx\n\n[Install]\nWantedBy=multi-user.target\n"
    with open('/tmp/mediamtx_webeditor_remote.service', 'w') as f:
        f.write(editor_svc)
    _module_copy(deploy_cfg, '/tmp/mediamtx_webeditor_remote.service', '/tmp/mediamtx-webeditor.service', log_fn=plog)
    _module_run(deploy_cfg, 'sudo mv /tmp/mediamtx-webeditor.service /etc/systemd/system/ 2>/dev/null || mv /tmp/mediamtx-webeditor.service /etc/systemd/system/', timeout=10)
    try:
        os.remove('/tmp/mediamtx_webeditor_remote.service')
    except Exception:
        pass
    plog("✓ Services created")
    _module_run(deploy_cfg, 'systemctl daemon-reload && systemctl enable mediamtx && systemctl enable mediamtx-webeditor 2>/dev/null; systemctl start mediamtx && systemctl start mediamtx-webeditor 2>/dev/null', timeout=90)
    plog("✓ Services started")

    # Step 5b: Test video
    test_video_url = 'https://raw.githubusercontent.com/takwerx/mediamtx-installer/main/config-editor/truck_60.ts'
    plog("  Downloading test video (truck_60.ts)...")
    ok_tv, _ = _module_run(deploy_cfg, f'mkdir -p /opt/mediamtx-webeditor/test_videos && wget -q -O /opt/mediamtx-webeditor/test_videos/truck_60.ts "{test_video_url}"', timeout=60)
    if ok_tv:
        plog("✓ Test video installed")
    else:
        plog("⚠ Test video download failed — you can upload it manually via the web console")

    # Step 6: Firewall
    plog("")
    plog("━━━ Step 6/8: Firewall (remote) ━━━")
    # v0.9.12 — Tier 1 (public streaming) only: rtsp 8554, rtsps 8322, srt 8890.
    # Webedit 5080 / API 9898 / HLS 8888 are Tier 3 (Caddy-loopback) — explicitly
    # DENIED here so a regressed bind can't leak the admin surface. Browsers
    # reach the webedit + HLS through Caddy on 443.
    _module_run(deploy_cfg,
        "ufw allow 8554/tcp 2>/dev/null; ufw allow 8322/tcp 2>/dev/null; ufw allow 8890/tcp 2>/dev/null; "
        "ufw deny 8888/tcp 2>/dev/null; ufw deny 5080/tcp 2>/dev/null; ufw deny 9898/tcp 2>/dev/null; true",
        timeout=15)
    plog("✓ Ports opened (RTSP/RTSPS/SRT public; webedit/API/HLS loopback only)")

    # Step 7: Caddy on infra-TAK (point stream.* to remote)
    plog("")
    plog("━━━ Step 7/8: Caddy Integration ━━━")
    cfg = _normalize_module_deployment_config(deploy_cfg)
    cfg['deployed'] = True
    settings['mediamtx_deployment'] = cfg
    save_settings(settings)
    generate_caddyfile(settings)
    subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True)
    domain = settings.get('fqdn', '')
    mtx_domain = _get_service_domain(settings, 'mediamtx') if domain else ''
    if mtx_domain:
        plog(f"✓ Caddyfile updated — {mtx_domain} → {host}:5080")
    else:
        plog("✓ Caddy updated (no FQDN — use IP:5080 for web console)")

    # Step 8: SSL cert sync for RTSPS / HLS encryption
    plog("")
    plog("━━━ Step 8/8: SSL Certificates (remote) ━━━")
    ssl_ok = False
    if mtx_domain:
        cert_base = '/var/lib/caddy/.local/share/caddy/certificates/acme-v02.api.letsencrypt.org-directory'
        cert_file = f'{cert_base}/{mtx_domain}/{mtx_domain}.crt'
        key_file  = f'{cert_base}/{mtx_domain}/{mtx_domain}.key'
        plog(f"  Waiting for Caddy to issue cert for {mtx_domain}...")
        for i in range(30):
            if os.path.exists(cert_file) and os.path.exists(key_file):
                break
            if i % 5 == 0:
                plog(f"  ⏳ {i * 2}s...")
            time.sleep(2)
        if os.path.exists(cert_file) and os.path.exists(key_file):
            _module_run(deploy_cfg, 'mkdir -p /etc/mediamtx/certs', timeout=10)
            ok_cert, _ = _module_copy(deploy_cfg, cert_file, '/tmp/mediamtx_stream.crt', log_fn=plog)
            ok_key, _  = _module_copy(deploy_cfg, key_file,  '/tmp/mediamtx_stream.key', log_fn=plog)
            if ok_cert and ok_key:
                _module_run(deploy_cfg, 'mv /tmp/mediamtx_stream.crt /etc/mediamtx/certs/stream.crt && mv /tmp/mediamtx_stream.key /etc/mediamtx/certs/stream.key && chmod 600 /etc/mediamtx/certs/stream.key', timeout=10)
                remote_cert = '/etc/mediamtx/certs/stream.crt'
                remote_key  = '/etc/mediamtx/certs/stream.key'
                yml_cmd = (
                    f"sed -i 's|^rtspServerKey:.*|rtspServerKey: {remote_key}|' /usr/local/etc/mediamtx.yml; "
                    f"sed -i 's|^rtspServerCert:.*|rtspServerCert: {remote_cert}|' /usr/local/etc/mediamtx.yml; "
                    f"sed -i 's|^hlsServerKey:.*|hlsServerKey: {remote_key}|' /usr/local/etc/mediamtx.yml; "
                    f"sed -i 's|^hlsServerCert:.*|hlsServerCert: {remote_cert}|' /usr/local/etc/mediamtx.yml; "
                    f"sed -i 's|^rtmpServerKey:.*|rtmpServerKey: {remote_key}|' /usr/local/etc/mediamtx.yml; "
                    f"sed -i 's|^rtmpServerCert:.*|rtmpServerCert: {remote_cert}|' /usr/local/etc/mediamtx.yml; "
                    f"sed -i 's|^rtspEncryption:.*|rtspEncryption: \"optional\"|' /usr/local/etc/mediamtx.yml; "
                    f"sed -i 's|^hlsEncryption:.*|hlsEncryption: yes|' /usr/local/etc/mediamtx.yml"
                )
                _module_run(deploy_cfg, yml_cmd, timeout=15)
                _module_run(deploy_cfg, 'systemctl restart mediamtx', timeout=15)
                plog(f"✓ SSL certificates synced — RTSPS and HTTPS HLS enabled")
                ssl_ok = True
                # The Caddyfile's /hls-proxy reverse_proxy only switches to https when
                # the stream cert exists at generate-time (see _get_mediamtx_hls_upstream).
                # We just enabled HLS-over-TLS on MediaMTX, so regenerate Caddy NOW —
                # otherwise it keeps proxying plain HTTP to MediaMTX's HTTPS HLS port and
                # the browser gets 400 "Client sent an HTTP request to an HTTPS server"
                # (the encrypt-enable-vs-Caddy-gen ordering race — Caddy was generated
                # before the LE stream cert had provisioned).
                _caddy_regenerate_if_fqdn()
                plog("✓ Caddy regenerated — /hls-proxy now matches the HTTPS HLS backend")
                # Create cert-sync script on infra-TAK host for renewals
                rcfg = deploy_cfg.get('remote', {})
                ssh_user = rcfg.get('ssh_user', 'root')
                ssh_port = int(rcfg.get('ssh_port', 22))
                ssh_key  = (rcfg.get('ssh_key_path') or '').strip()
                ssh_key_expanded = os.path.expanduser(ssh_key) if ssh_key else ''
                key_flag = f'-i {ssh_key_expanded}' if ssh_key_expanded and os.path.exists(ssh_key_expanded) else ''
                _sq = shlex.quote
                sync_script = (
                    f"#!/bin/bash\n"
                    f"# Auto-generated: sync Caddy certs to remote MediaMTX\n"
                    f"CERT={_sq(cert_file)}\n"
                    f"KEY={_sq(key_file)}\n"
                    f"REMOTE={_sq(f'{ssh_user}@{host}')}\n"
                    f"PORT={_sq(str(ssh_port))}\n"
                    f"KEY_FLAG={_sq(key_flag)}\n"
                    f"[ -f \"$CERT\" ] || exit 0\n"
                    f"scp -P $PORT $KEY_FLAG -o StrictHostKeyChecking=accept-new -o BatchMode=yes "
                    f"\"$CERT\" \"$REMOTE:/etc/mediamtx/certs/stream.crt\" 2>/dev/null\n"
                    f"scp -P $PORT $KEY_FLAG -o StrictHostKeyChecking=accept-new -o BatchMode=yes "
                    f"\"$KEY\" \"$REMOTE:/etc/mediamtx/certs/stream.key\" 2>/dev/null\n"
                    f"ssh -p $PORT $KEY_FLAG -o BatchMode=yes \"$REMOTE\" "
                    f"'chmod 600 /etc/mediamtx/certs/stream.key && systemctl restart mediamtx' 2>/dev/null\n"
                )
                sync_path = '/opt/tak-guarddog/mediamtx-cert-sync.sh'
                _makedirs_priv('/opt/tak-guarddog', exist_ok=True)
                _write_priv(sync_path, sync_script, perm=0o755)   # v10.0.5 non-root: /opt/tak-guarddog root-owned
                svc = "[Unit]\nDescription=Sync MediaMTX SSL certs to remote host\n\n[Service]\nType=oneshot\nExecStart=/opt/tak-guarddog/mediamtx-cert-sync.sh\n"
                timer = "[Unit]\nDescription=Sync MediaMTX certs daily\n\n[Timer]\nOnCalendar=daily\nPersistent=true\n\n[Install]\nWantedBy=timers.target\n"
                _write_priv('/etc/systemd/system/mediamtx-cert-sync.service', svc)
                _write_priv('/etc/systemd/system/mediamtx-cert-sync.timer', timer)
                _run_priv_chain([['systemctl', 'daemon-reload'], ['systemctl', 'enable', '--now', 'mediamtx-cert-sync.timer']], 'and')
                plog("✓ Cert renewal sync timer installed (daily)")
            else:
                plog("⚠ Failed to copy certs to remote — RTSPS not configured")
        else:
            plog("⚠ Cert not found after 60s — RTSPS not configured")
            plog("  Go to Caddy page, reload, then redeploy to retry")
    else:
        plog("  No domain configured — skipping SSL (RTSP unencrypted only)")

    # Register MediaMTX proxy provider + application in Authentik (if running)
    ak_dir = os.path.expanduser('~/authentik')
    ak_env_path = os.path.join(ak_dir, '.env')
    if os.path.exists(os.path.join(ak_dir, 'docker-compose.yml')) and os.path.exists(ak_env_path):
        _ak_token = ''
        with open(ak_env_path) as _f:
            for _line in _f:
                if _line.strip().startswith('AUTHENTIK_BOOTSTRAP_TOKEN='):
                    _ak_token = _line.strip().split('=', 1)[1].strip()
        if _ak_token and domain:
            plog("")
            plog("━━━ Registering MediaMTX in Authentik (proxy provider + application) ━━━")
            _ak_url = 'http://127.0.0.1:9090'
            _ak_headers = {'Authorization': f'Bearer {_ak_token}', 'Content-Type': 'application/json'}
            _ensure_authentik_console_app(domain, _ak_token, plog)
            _repair_embedded_outpost_all_apps(_ak_url, _ak_headers, settings, plog)

    # Harden MediaMTX ports: webedit (5080) and HLS (8888) only from console IP
    _mtx_console_ip = _fedhub_caddy_source_ip(settings)
    if _mtx_console_ip:
        _module_run(deploy_cfg,
            f'command -v ufw >/dev/null 2>&1 && ('
            f'sudo ufw allow from {_mtx_console_ip} to any port 5080 proto tcp 2>/dev/null; '
            f'sudo ufw allow from {_mtx_console_ip} to any port 8888 proto tcp 2>/dev/null; '
            f'sudo ufw deny 5080/tcp 2>/dev/null; sudo ufw deny 8888/tcp 2>/dev/null; '
            f'sudo ufw reload 2>/dev/null); true',
            timeout=15)
        plog(f"  UFW: ports 5080/8888 source-scoped to console IP {_mtx_console_ip}")
    else:
        _module_run(deploy_cfg,
            'command -v ufw >/dev/null 2>&1 && (sudo ufw deny 5080/tcp 2>/dev/null; sudo ufw deny 8888/tcp 2>/dev/null; sudo ufw reload 2>/dev/null); true',
            timeout=15)
        plog("  ⚠ No console IP set — ports 5080/8888 denied publicly. Set Settings → Server IP.")

    plog("")
    plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
    plog(f"🎉 MediaMTX v{version} deployed on remote host {host}!")
    if domain:
        plog(f"   Web Console: https://stream.{domain.split(':')[0]}")
    plog(f"   Remote: http://{host}:5080")
    plog(f"   HLS viewer password: {'*' * max(0, len(hls_pass) - 4) + hls_pass[-4:]}")
    if ssl_ok:
        plog(f"   RTSPS: rtsps://stream.{domain.split(':')[0]}:8322")
    plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
    mediamtx_deploy_status.update({'running': False, 'complete': True, 'error': False})
    return

def run_mediamtx_deploy():
    def plog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        mediamtx_deploy_log.append(entry)
        print(entry, flush=True)
    try:
        settings = load_settings()
        domain = settings.get('fqdn', '')
        deploy_cfg = _get_module_deployment_config(settings, 'mediamtx_deployment')
        if deploy_cfg.get('target_mode') == 'remote':
            _run_mediamtx_deploy_remote(settings, deploy_cfg, plog)
            return

        # Step 1: install deps (distro-branched). RHEL/Rocky has no apt. EPEL+CRB are
        # enabled for the general dep set; full ffmpeg comes from RPM Fusion (below).
        # EPEL/CRB may already be on from a prior TAK Server deploy — idempotent.
        # The .deb branch (else) is unchanged.
        plog("━━━ Step 1/7: Installing Dependencies ━━━")
        if _distro_family() == 'rhel':
            subprocess.run(_sudo_wrap(['dnf', 'install', '-y', 'epel-release', 'dnf-plugins-core']),
                           capture_output=True, text=True, timeout=300)
            _run_priv_chain([['dnf', 'config-manager', '--set-enabled', 'crb'], ['dnf', 'config-manager', '--set-enabled', 'powertools']], 'or', timeout=120)
            # Core deps (required). The MediaMTX binary is pure Go and doesn't need
            # ffmpeg, so install core deps strictly, then ffmpeg separately.
            ok, out = _pkg_install(['wget', 'tar', 'curl', 'openssl', 'python3', 'python3-pip'],
                                   log_fn=plog, timeout=900)
            if not ok:
                plog(f"✗ dnf install failed: {(out or '')[-200:]}")
                mediamtx_deploy_status.update({'running': False, 'error': True})
                return
            # ffmpeg: required for recording, the MP4-download conversion, and the
            # test stream. RHEL/EPEL only ship `ffmpeg-free` (NO libx264/libx265);
            # full ffmpeg matching the Ubuntu apt build lives in RPM Fusion. Add the
            # RPM Fusion free repo, then install ffmpeg; fall back to ffmpeg-free.
            # Warn-not-fail: core MediaMTX streaming works without ffmpeg — only the
            # recording / MP4 export / test-stream features need it.
            _rhel_ver = (subprocess.run('rpm -E %rhel', shell=True, capture_output=True, text=True).stdout.strip() or '9')
            subprocess.run(_sudo_wrap(['dnf', 'install', '-y',
                f'https://download1.rpmfusion.org/free/el/rpmfusion-free-release-{_rhel_ver}.noarch.rpm']),
                capture_output=True, text=True, timeout=300)
            ff_ok, _ = _pkg_install(['ffmpeg'], timeout=900)
            if not ff_ok:
                ff_ok, _ = _pkg_install(['ffmpeg-free'], timeout=600)
            plog("✓ ffmpeg installed (recording / MP4 export / test stream)" if ff_ok else
                 "⚠ ffmpeg unavailable — MediaMTX streaming OK, but recording / MP4 download / test stream need ffmpeg (RPM Fusion repo unreachable?)")
        else:
            wait_for_apt_lock(plog, mediamtx_deploy_log)
            r = _run_priv_chain([['apt-get', 'update', '-qq'], ['apt-get', 'install', '-y', 'wget', 'tar', 'curl', 'ffmpeg', 'openssl', 'python3', 'python3-pip']], 'and', timeout=300)
            if r.returncode != 0:
                plog(f"✗ apt install failed: {r.stdout[-200:]}")
                mediamtx_deploy_status.update({'running': False, 'error': True})
                return
        plog("✓ Dependencies installed (wget, ffmpeg, python3)")

        # Install Python packages (try with --break-system-packages for newer pip, else without)
        plog("  Installing Python packages...")
        r = subprocess.run('pip3 install Flask ruamel.yaml requests psutil --break-system-packages 2>&1',
            shell=True, capture_output=True, text=True, timeout=120)
        if r.returncode != 0 and 'no such option' in (r.stderr or r.stdout or ''):
            subprocess.run('pip3 install Flask ruamel.yaml requests psutil 2>&1',
                shell=True, capture_output=True, text=True, timeout=120)
        plog("✓ Python packages installed")

        # v0.9.31: ensure `takwerx` system user exists before any chown / unit
        # install happens. mediamtx.service + mediamtx-webeditor.service both
        # run as `User=takwerx` (v0.9.29 hardening); missing user → 217/USER
        # tight-loop on Restart=always. Idempotent.
        plog("  Ensuring takwerx system user...")
        created = _ensure_takwerx_system_user(plog=plog)
        if not created:
            plog("  ✓ takwerx system user already present")

        # Step 2: Detect architecture and latest version
        plog("")
        plog("━━━ Step 2/7: Detecting MediaMTX Version ━━━")
        arch_map = {'x86_64': 'amd64', 'aarch64': 'arm64', 'armv7l': 'armv7'}
        arch_raw = subprocess.run('uname -m', shell=True, capture_output=True, text=True).stdout.strip()
        mtx_arch = arch_map.get(arch_raw, 'amd64')
        plog(f"  Architecture: {arch_raw} → {mtx_arch}")

        r = subprocess.run('curl -s https://api.github.com/repos/bluenviron/mediamtx/releases/latest',
            shell=True, capture_output=True, text=True, timeout=30)
        import re as _re
        m = _re.search(r'"tag_name":\s*"v([^"]+)"', r.stdout)
        if not m:
            plog("✗ Could not detect latest MediaMTX version")
            mediamtx_deploy_status.update({'running': False, 'error': True})
            return
        version = m.group(1)
        plog(f"✓ Latest version: {version}")

        # Step 3: Download and install binary
        plog("")
        plog("━━━ Step 3/7: Downloading & Installing MediaMTX ━━━")
        url = f"https://github.com/bluenviron/mediamtx/releases/download/v{version}/mediamtx_v{version}_linux_{mtx_arch}.tar.gz"
        tmp = '/tmp/mediamtx_install'
        os.makedirs(tmp, exist_ok=True)
        r = subprocess.run(f'wget -q -O {tmp}/mediamtx.tar.gz "{url}"', shell=True, capture_output=True, text=True, timeout=120)
        if r.returncode != 0:
            plog(f"✗ Download failed")
            mediamtx_deploy_status.update({'running': False, 'error': True})
            return
        subprocess.run(f'tar -xzf {tmp}/mediamtx.tar.gz -C {tmp}', shell=True, capture_output=True)
        # install(1) reads the /tmp source (broker source-permissive), writes the
        # allowlisted dest, and sets the mode in one step (replaces mv + chmod).
        subprocess.run(_sudo_wrap(['install', '-m', '0755', f'{tmp}/mediamtx', '/usr/local/bin/mediamtx']), capture_output=True)
        # RHEL/SELinux: the binary was downloaded under /tmp (tmp_t) and `mv` preserves
        # that label, so systemd refuses to exec it → 203/EXEC "Permission denied" and
        # the service crash-loops. restorecon relabels /usr/local/bin/mediamtx to bin_t
        # (chcon fallback). No-op on Debian (restorecon/chcon absent → || true).
        if _distro_family() == 'rhel':
            _run_priv_chain([['restorecon', '-v', '/usr/local/bin/mediamtx'], ['chcon', '-t', 'bin_t', '/usr/local/bin/mediamtx']], 'or', timeout=30)
        subprocess.run(f'rm -rf {tmp}', shell=True, capture_output=True)
        plog(f"✓ MediaMTX v{version} installed to /usr/local/bin/mediamtx")

        # Step 4: Write config
        plog("")
        plog("━━━ Step 4/7: Writing Configuration ━━━")
        _makedirs_priv('/usr/local/etc', exist_ok=True)
        import secrets as _sec
        hls_pass = _sec.token_hex(8)

        mediamtx_yml = f"""# MediaMTX Configuration - Generated by TAKWERX Console
logLevel: info
logDestinations: [stdout]
logStructured: no
logFile: mediamtx.log
readTimeout: 10s
writeTimeout: 10s
writeQueueSize: 512
udpMaxPayloadSize: 1472

authMethod: internal
authInternalUsers:
- user: any
  ips: ['127.0.0.1', '::1']
  permissions:
  - action: read
  - action: publish
  - action: api
- user: hlsviewer
  pass: {hls_pass}
  ips: []
  permissions:
  - action: read
- user: any
  pass: ''
  ips: []
  permissions:
  - action: read
    path: teststream
authHTTPAddress:
authHTTPExclude:
- action: api
- action: metrics
- action: pprof

api: yes
# v0.9.12: bound to 127.0.0.1 — admin API never needs public-internet exposure.
# Webedit (also loopback) and Caddy (HLS proxy) are the only legitimate consumers.
# moved from 9997 — CloudTAK media container owns port 9997 (hardcoded in video-service.ts).
apiAddress: 127.0.0.1:9898
apiEncryption: no
apiAllowOrigins: ['*']
apiTrustedProxies: []

metrics: no
metricsAddress: :9998
pprof: no
pprofAddress: :9999
playback: no
playbackAddress: :9996

rtsp: yes
rtspTransports: [tcp]
rtspEncryption: "no"
rtspAddress: :8554
rtspsAddress: :8322
rtpAddress: :8000
rtcpAddress: :8001
rtspServerKey:
rtspServerCert:
rtspAuthMethods: [basic]

rtmp: no
rtmpAddress: :1935
rtmpEncryption: "no"
rtmpsAddress: :1936
rtmpServerKey:
rtmpServerCert:

hls: yes
# v0.9.12: HLS bound to 127.0.0.1 — browsers reach it through Caddy `/hls-proxy/`
# reverse proxy on 443 (mixed-content safe + only path that has Authentik auth).
hlsAddress: 127.0.0.1:8888
hlsEncryption: no
hlsServerKey:
hlsServerCert:
hlsAllowOrigins: ['*']
hlsTrustedProxies: ['127.0.0.1']
hlsAlwaysRemux: no
hlsVariant: mpegts
hlsSegmentCount: 3
hlsSegmentDuration: 500ms
hlsPartDuration: 200ms
hlsSegmentMaxSize: 50M
hlsDirectory: ''
hlsMuxerCloseAfter: 60s

webrtc: no
webrtcAddress: :8889
webrtcEncryption: no
webrtcAllowOrigins: ['*']

srt: yes
srtAddress: :8890

paths:
  teststream:
    record: no
  all_others:
  ~^live/(.+)$:
    runOnReady: ffmpeg -i rtsp://localhost:8554/live/$G1 -c copy -f rtsp rtsp://localhost:8554/$G1
    runOnReadyRestart: true
"""
        _write_priv('/usr/local/etc/mediamtx.yml', mediamtx_yml)
        plog("✓ Configuration written to /usr/local/etc/mediamtx.yml")
        plog(f"  HLS viewer password: {'*' * max(0, len(hls_pass) - 4) + hls_pass[-4:]}")

        # Step 5: Create mediamtx systemd service
        plog("")
        plog("━━━ Step 5/7: Creating systemd Services ━━━")
        # SupplementaryGroups=caddy lets takwerx read Caddy's LE cert/key files
        # (Caddy writes 0600 caddy:caddy in /var/lib/caddy/.local/share/caddy/...).
        # Without this, MediaMTX fails to start with "permission denied" on the cert.
        mediamtx_svc = """[Unit]
Description=MediaMTX RTSP/HLS/SRT Streaming Server
After=network.target

[Service]
Type=simple
ExecStart=/usr/local/bin/mediamtx /usr/local/etc/mediamtx.yml
Restart=always
RestartSec=5
User=takwerx
SupplementaryGroups=caddy

[Install]
WantedBy=multi-user.target
"""
        _write_priv('/etc/systemd/system/mediamtx.service', mediamtx_svc)
        plog("✓ mediamtx.service created")

        # Write web editor Python app — flexible: detect LDAP/Authentik and choose regular vs LDAP-enhanced source
        webeditor_dir = '/opt/mediamtx-webeditor'
        _makedirs_priv(webeditor_dir)
        _makedirs_priv(f'{webeditor_dir}/backups')
        _makedirs_priv(f'{webeditor_dir}/recordings')
        # Hand the dir to the console user NOW (broker creates it root-owned), so
        # the many open(editor_path,'w') writes below run directly non-root. (A
        # second chown later re-applies after file shuffling.)
        subprocess.run(_sudo_wrap(['chown', '-R', 'takwerx:takwerx', webeditor_dir]),
                       capture_output=True, timeout=10)

        modules = detect_modules()
        ak = modules.get('authentik', {})
        ldap_available = bool(ak.get('installed'))
        if ldap_available:
            plog("  LDAP/Authentik detected — will apply LDAP overlay after install")
        else:
            plog("  No LDAP — using regular MediaMTX editor from repo")

        webeditor_src = None
        clone_dir = '/tmp/mediamtx_editor_clone'
        try:
            subprocess.run(f'rm -rf {clone_dir}', shell=True, capture_output=True)
            os.makedirs(clone_dir, exist_ok=True)
            r = subprocess.run(f'git clone --depth 1 --branch "{MEDIAMTX_EDITOR_REF}" "{MEDIAMTX_EDITOR_REPO}" {clone_dir}',
                shell=True, capture_output=True, text=True, timeout=60)
            if r.returncode == 0:
                candidate = os.path.join(clone_dir, MEDIAMTX_EDITOR_PATH, 'mediamtx_config_editor.py')
                if os.path.exists(candidate):
                    webeditor_src = candidate
                    plog(f"  Cloned editor from {MEDIAMTX_EDITOR_REPO}")
        except Exception as e:
            plog(f"  Clone failed: {e}")
        if not webeditor_src:
            app_dir = os.path.dirname(os.path.abspath(__file__))
            for p in [os.path.join(app_dir, 'mediamtx_config_editor.py'),
                      os.path.join(app_dir, 'config-editor', 'mediamtx_config_editor.py'),
                      '/opt/takwerx/mediamtx_config_editor.py']:
                if os.path.exists(p):
                    webeditor_src = p
                    plog("  Using local web editor (clone skipped or failed)")
                    break
        if webeditor_src:
            import shutil as _shutil
            _shutil.copy2(webeditor_src, f'{webeditor_dir}/mediamtx_config_editor.py')
            # Patch port to read from PORT env var (systemd sets PORT=5080)
            editor_path = f'{webeditor_dir}/mediamtx_config_editor.py'
            try:
                with open(editor_path, 'r') as f:
                    lines = f.readlines()
                for i, line in enumerate(lines):
                    if 'app.run(' in line and 'port=5000' in line and 'os.environ.get("PORT"' not in line:
                        lines[i] = line.replace('port=5000', 'port=int(os.environ.get("PORT", 5080))', 1)
                        break
                with open(editor_path, 'w') as f:
                    f.writelines(lines)
            except Exception:
                pass
            # Console-deployed MediaMTX uses API port 9898 (CloudTAK uses 9997). Patch editor so "active streams" works.
            subprocess.run(f"sed -i 's/9997/9898/g' {webeditor_dir}/mediamtx_config_editor.py", shell=True)
            # When CloudTAK is installed, MediaMTX is at stream.* so "Stream URLs" in the editor should show stream. not video.
            # Only replace URL-like patterns (//video. or video.<domain>) — not JS vars like video.src / video.canPlayType
            if domain:
                base = domain.split(':')[0]
                if re.match(r'^[a-zA-Z0-9][a-zA-Z0-9.-]*$', base):
                    base_esc = base.replace('.', '\\.')
                    _editor_py = shlex.quote(f'{webeditor_dir}/mediamtx_config_editor.py')
                    subprocess.run(f"sed -i 's|video\\.{base_esc}|stream.{base_esc}|g' {_editor_py}", shell=True)
                    subprocess.run(f"sed -i 's|//video\\.|//stream.|g' {_editor_py}", shell=True)
                    plog("  Stream URL host set to stream.*")
            plog("✓ Web editor installed (port 5080, API 9898)")

            # Patch HLS URLs to go through Caddy /hls-proxy/ instead of direct port 8888 (avoids mixed content)
            import re as _hls_re
            try:
                with open(editor_path, 'r') as f:
                    esrc = f.read()
                esrc = _hls_re.sub(
                    r"stream_info\['hls_url'\] = f\"\{hls_protocol\}://\{hls_domain\}:8888/\{path_name\}/index\.m3u8\"",
                    "stream_info['hls_url'] = f\"/hls-proxy/{path_name}/index.m3u8\"", esrc)
                esrc = _hls_re.sub(
                    r'hls_base = f"\{streaming\[.protocol.\]\}://\{streaming\[.domain.\]\}:8888"',
                    'hls_base = "/hls-proxy"', esrc)
                esrc = _hls_re.sub(
                    r'hls_base = f"http://\{request\.host\.split.*?:8888"',
                    'hls_base = "/hls-proxy"', esrc)
                esrc = _hls_re.sub(
                    r"'hls': f'\{protocol\}://\{domain\}:8888/teststream/index\.m3u8'",
                    "'hls': '/hls-proxy/teststream/index.m3u8'", esrc)
                esrc = esrc.replace('const url = new URL(streamUrl);', 'const url = new URL(streamUrl, window.location.origin);')
                with open(editor_path, 'w') as f:
                    f.write(esrc)
                plog("✓ HLS URLs patched for HTTPS proxy")
            except Exception:
                plog("⚠ HLS URL patch failed — watch page may have mixed content warnings")

            # LDAP overlay: when Authentik is present, patch editor for header auth + Stream Access page
            if ldap_available:
                overlay_src = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'mediamtx_ldap_overlay.py')
                overlay_dst = f'{webeditor_dir}/mediamtx_ldap_overlay.py'
                if os.path.exists(overlay_src):
                    subprocess.run(f'cp "{overlay_src}" "{overlay_dst}"', shell=True)
                    # Inject import before app.run() — the overlay registers routes + before_request
                    editor_file = f'{webeditor_dir}/mediamtx_config_editor.py'
                    with open(editor_file, 'r') as ef:
                        editor_src = ef.read()
                    inject_block = (
                        "\n# --- infra-TAK LDAP overlay ---\n"
                        "import os as _os\n"
                        "if _os.environ.get('LDAP_ENABLED'):\n"
                        "    import sys as _sys; _sys.path.insert(0, _os.path.dirname(_os.path.abspath(__file__)))\n"
                        "    from mediamtx_ldap_overlay import apply_ldap_overlay\n"
                        "    apply_ldap_overlay(app)\n"
                        "# --- end LDAP overlay ---\n"
                    )
                    # Inject right after app = Flask(...) so overlay's before_request runs before vanilla login_required
                    if 'LDAP overlay' not in editor_src:
                        lines = editor_src.splitlines(keepends=True)
                        inserted = False
                        for i, line in enumerate(lines):
                            if 'app = Flask(' in line:
                                lines.insert(i + 1, '\n' + inject_block)
                                inserted = True
                                break
                        if not inserted:
                            for i, line in enumerate(lines):
                                if 'app.run(' in line:
                                    lines.insert(i, '\n' + inject_block)
                                    inserted = True
                                    break
                        if inserted:
                            with open(editor_file, 'w') as ef:
                                ef.writelines(lines)
                            plog("✓ LDAP overlay applied (Authentik header auth + Stream Access)")
                        else:
                            plog("  ⚠ app = Flask / app.run not found — LDAP overlay not injected")
                    else:
                        plog("✓ LDAP overlay already present")
                else:
                    plog("⚠ mediamtx_ldap_overlay.py not found next to app.py — LDAP overlay skipped")
                # Avoid duplicate Flask endpoints (shared_stream_page, shared_hls_proxy) so editor starts
                try:
                    _editor_path = f'{webeditor_dir}/mediamtx_config_editor.py'
                    if os.path.exists(_editor_path):
                        with open(_editor_path, 'r') as ef:
                            esrc = ef.read()
                        patched = _mediamtx_editor_endpoint_patch(esrc)
                        if patched != esrc:
                            with open(_editor_path, 'w') as ef:
                                ef.write(patched)
                            plog("✓ Endpoint patch applied (shared_stream_page, shared_hls_proxy)")
                except Exception:
                    pass
            # Deploy Ku-band simulator scripts so "Simulate link" in the editor works (Web Editor v1.1.8+)
            simulator_src = os.path.join(clone_dir, 'scripts', 'ku-band-simulator')
            simulator_dst = os.path.join(webeditor_dir, 'ku-band-simulator')
            if os.path.isdir(simulator_src):
                os.makedirs(simulator_dst, exist_ok=True)
                for name in os.listdir(simulator_src):
                    if name == 'ku_band_simulator.conf':
                        continue  # Don't overwrite existing config
                    src_path = os.path.join(simulator_src, name)
                    dst_path = os.path.join(simulator_dst, name)
                    if os.path.isfile(src_path):
                        _shutil.copy2(src_path, dst_path)
                        if name.endswith('.sh'):
                            os.chmod(dst_path, 0o755)
                plog("✓ Ku-band simulator scripts installed")
        else:
            plog("⚠ mediamtx_config_editor.py not found (clone failed and no local file)")
            plog("  Place it next to app.py or in config-editor/, or fix repo access, then redeploy")
            plog("  MediaMTX streaming will work — web editor unavailable until then")

        # Clean up clone dir now that copy is done
        try:
            subprocess.run(f'rm -rf {clone_dir}', shell=True, capture_output=True)
        except Exception:
            pass

        # Download test video
        test_video_dir = f'{webeditor_dir}/test_videos'
        os.makedirs(test_video_dir, exist_ok=True)
        test_video_url = 'https://raw.githubusercontent.com/takwerx/mediamtx-installer/main/config-editor/truck_60.ts'
        plog("  Downloading test video (truck_60.ts)...")
        r = subprocess.run(f'wget -q -O {test_video_dir}/truck_60.ts "{test_video_url}"',
            shell=True, capture_output=True, text=True, timeout=60)
        if r.returncode == 0:
            plog("✓ Test video installed")
        else:
            plog("⚠ Test video download failed — you can upload it manually via the web console")

        # Web editor systemd service — add LDAP env vars when Authentik is present
        ldap_env_lines = ''
        if ldap_available:
            ak_env_path = os.path.expanduser('~/authentik/.env')
            ak_token_val = ''
            if os.path.exists(ak_env_path):
                with open(ak_env_path) as _f:
                    for _line in _f:
                        if _line.strip().startswith('AUTHENTIK_BOOTSTRAP_TOKEN='):
                            ak_token_val = _line.strip().split('=', 1)[1].strip()
            ldap_env_lines = (
                f'Environment=LDAP_ENABLED=1\n'
                f'Environment=AUTHENTIK_API_URL=http://127.0.0.1:9090\n'
                f'Environment=AUTHENTIK_TOKEN={ak_token_val}\n'
            )

        # Write self-healing overlay script — runs before every service start
        # Re-injects LDAP overlay + patches (port, API) if the upstream editor self-updated
        if ldap_available:
            heal_path = f'{webeditor_dir}/ensure_overlay.py'
            with open(heal_path, 'w') as hf:
                hf.write(MEDIAMTX_ENSURE_OVERLAY_SCRIPT)
            os.chmod(heal_path, 0o755)
            plog("✓ Self-healing overlay script installed (runs on every service start)")

        exec_start_pre = ''
        if ldap_available:
            # Dash prefix: pre-step failure must not block the editor from starting
            exec_start_pre = f'ExecStartPre=-/usr/bin/python3 {webeditor_dir}/ensure_overlay.py\n'

        editor_file = f'{webeditor_dir}/mediamtx_config_editor.py'
        if os.path.exists(editor_file):
            webeditor_svc = f"""[Unit]
Description=MediaMTX Web Configuration Editor
After=network.target mediamtx.service

[Service]
Type=simple
{exec_start_pre}ExecStart=/usr/bin/python3 /opt/mediamtx-webeditor/mediamtx_config_editor.py
WorkingDirectory=/opt/mediamtx-webeditor
Environment=PORT=5080
Environment=MEDIAMTX_API_URL=http://127.0.0.1:9898
{ldap_env_lines}Restart=always
RestartSec=5
User=takwerx

[Install]
WantedBy=multi-user.target
"""
            _write_priv('/etc/systemd/system/mediamtx-webeditor.service', webeditor_svc)
            plog("✓ mediamtx-webeditor.service created")
        else:
            plog("  Skipping mediamtx-webeditor.service (editor file not installed)")

        # Ensure web editor Python deps (Flask, etc.) so systemd can start it even if Step 1 pip failed
        if os.path.exists(editor_file):
            r = subprocess.run(
                'pip3 install Flask ruamel.yaml requests psutil --break-system-packages 2>&1',
                shell=True, capture_output=True, text=True, timeout=120)
            if r.returncode != 0 and 'no such option' in (r.stderr or r.stdout or ''):
                r = subprocess.run('pip3 install Flask ruamel.yaml requests psutil 2>&1',
                    shell=True, capture_output=True, text=True, timeout=120)
            if r.returncode != 0:
                plog("  ⚠ pip install for web editor deps had issues (check logs); trying to start anyway")
            else:
                plog("  ✓ Web editor Python deps installed")

        subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'enable', 'mediamtx']), capture_output=True)
        if os.path.exists(editor_file):
            subprocess.run(_sudo_wrap(['systemctl', 'enable', 'mediamtx-webeditor']), capture_output=True)

        # v0.9.29 — Pre-create writable dirs + chown for the takwerx-run web editor.
        # The upstream mediamtx_config_editor.py (from mediamtx-installer) hardcodes:
        #   BACKUP_DIR  = '/usr/local/etc/mediamtx_backups'
        #   CONFIG_FILE = '/usr/local/etc/mediamtx.yml'
        # and at IMPORT time (line ~93) calls `os.makedirs(BACKUP_DIR, exist_ok=True)`.
        # If `/usr/local/etc/` is root-owned (default after `mkdir -p` for the .yml)
        # AND the BACKUP_DIR doesn't exist, the import fails with PermissionError
        # since the service runs as `User=takwerx`. Symptom seen on tak-test-4
        # 2026-05-18: mediamtx-webeditor.service in fail-loop (264 restarts) with
        #   `PermissionError: [Errno 13] Permission denied: '/usr/local/etc/mediamtx_backups'`
        # Downstream: Caddy's stream.* vhost reverse-proxies to :5080 → nothing
        # listening → Caddy returns 502 → browser sees authentik's "Not Found"
        # page (because the forward_auth flow falls back to authentik on error).
        # Same problem class as the LE-cert read-access fix earlier in this release.
        if os.path.exists(editor_file):
            try:
                subprocess.run(_sudo_wrap(['mkdir', '-p', '/usr/local/etc/mediamtx_backups']), capture_output=True, timeout=5)
                subprocess.run(_sudo_wrap(['chown', '-R', 'takwerx:takwerx', '/usr/local/etc/mediamtx_backups']), capture_output=True, timeout=5)
                # Editor writes theme_config.json, email_config.json, users_file,
                # share_links, group_metadata, srt_passphrase_backup, pending_reg,
                # reset_tokens, etc. into /opt/mediamtx-webeditor/. All as takwerx.
                subprocess.run(_sudo_wrap(['chown', '-R', 'takwerx:takwerx', '/opt/mediamtx-webeditor']), capture_output=True, timeout=10)
                # mediamtx.yml is read by `mediamtx` (User=takwerx) and written by
                # the editor's Save-Config UI. takwerx ownership lets both work.
                subprocess.run(_sudo_wrap(['chown', 'takwerx:takwerx', '/usr/local/etc/mediamtx.yml']), capture_output=True, timeout=5)
                plog("  ✓ Web editor writable paths chowned to takwerx (backups + /opt/mediamtx-webeditor + mediamtx.yml)")
            except Exception as _pe:
                plog(f"  ⚠ Could not chown web editor paths: {_pe}")

        subprocess.run(_sudo_wrap(['systemctl', 'start', 'mediamtx']), capture_output=True)
        if os.path.exists(editor_file):
            subprocess.run(_sudo_wrap(['systemctl', 'start', 'mediamtx-webeditor']), capture_output=True)
        plog("✓ Services enabled and started")

        # Step 6: Firewall
        # v0.9.12 — Tier 1 (public streaming) only: rtsp 8554, rtsps 8322, srt 8890,
        # rtp 8000, rtcp 8001. Webedit 5080 / API 9898 / HLS 8888 are Tier 3
        # (Caddy-loopback) — explicitly DENIED here so a regressed bind can't
        # leak the admin surface. Browsers reach the webedit + HLS through Caddy.
        plog("")
        plog("━━━ Step 6/7: Configuring Firewall ━━━")
        for port_proto in ['8554/tcp', '8322/tcp', '8890/udp', '8000/udp', '8001/udp']:
            subprocess.run(_sudo_wrap(['ufw', 'allow', port_proto]), capture_output=True)
        for port_proto in ['8888/tcp', '5080/tcp', '9898/tcp']:
            subprocess.run(_sudo_wrap(['ufw', 'deny', port_proto]), capture_output=True)
        plog("✓ Ports opened: 8554 (RTSP), 8322 (RTSPS), 8890 (SRT), 8000/8001 (RTP/RTCP); 8888/5080/9898 loopback-only (Caddy)")

        # Step 7: Caddy integration
        plog("")
        plog("━━━ Step 7/7: Caddy Integration ━━━")
        caddy_running = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'caddy']), capture_output=True, text=True).stdout.strip() == 'active'
        if caddy_running and domain:
            # Update Caddyfile first so Caddy issues the cert
            generate_caddyfile(settings)
            subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True)
            mtx_domain = _get_service_domain(settings, 'mediamtx')
            plog(f"✓ Caddyfile updated — {mtx_domain}")

            # Wait up to 60s for cert
            cert_base = '/var/lib/caddy/.local/share/caddy/certificates/acme-v02.api.letsencrypt.org-directory'
            cert_file = f'{cert_base}/{mtx_domain}/{mtx_domain}.crt'
            key_file  = f'{cert_base}/{mtx_domain}/{mtx_domain}.key'
            plog(f"  Waiting for Caddy to issue cert for {mtx_domain}...")
            for i in range(30):
                if os.path.exists(cert_file) and os.path.exists(key_file):
                    break
                if i % 5 == 0:
                    plog(f"  ⏳ {i * 2}s...")
                time.sleep(2)

            if os.path.exists(cert_file):
                yml = '/usr/local/etc/mediamtx.yml'
                # Wire cert paths — strip continuation lines first then replace
                for key in ['rtspServerKey', 'rtspServerCert', 'hlsServerKey', 'hlsServerCert', 'rtmpServerKey', 'rtmpServerCert']:
                    subprocess.run(f"sed -i '/^{key}:/{{ n; /^  /d }}' {yml}", shell=True)
                subprocess.run(f"sed -i 's|^rtspServerKey:.*|rtspServerKey: {key_file}|' {yml}", shell=True)
                subprocess.run(f"sed -i 's|^rtspServerCert:.*|rtspServerCert: {cert_file}|' {yml}", shell=True)
                subprocess.run(f"sed -i 's|^hlsServerKey:.*|hlsServerKey: {key_file}|' {yml}", shell=True)
                subprocess.run(f"sed -i 's|^hlsServerCert:.*|hlsServerCert: {cert_file}|' {yml}", shell=True)
                subprocess.run(f"sed -i 's|^rtmpServerKey:.*|rtmpServerKey: {key_file}|' {yml}", shell=True)
                subprocess.run(f"sed -i 's|^rtmpServerCert:.*|rtmpServerCert: {cert_file}|' {yml}", shell=True)
                # Enable encryption
                subprocess.run(f"sed -i 's|^rtspEncryption:.*|rtspEncryption: \"optional\"|' {yml}", shell=True)
                subprocess.run(f"sed -i 's|^hlsEncryption:.*|hlsEncryption: yes|' {yml}", shell=True)
                plog(f"✓ SSL certificates wired — RTSPS and HTTPS HLS enabled")
                plog(f"  Cert: {cert_file}")

                # Grant MediaMTX (running as takwerx) read access to Caddy's LE cert files.
                # Caddy stores certs as 0600 caddy:caddy under /var/lib/caddy/.local/share/caddy/...
                # We add takwerx to the caddy group (via SupplementaryGroups=caddy in the unit) and
                # make the directory chain group-traversable + the cert/key files group-readable.
                # Without this, mediamtx fails on startup with "permission denied" on the cert path.
                try:
                    subprocess.run('usermod -aG caddy takwerx 2>/dev/null', shell=True, capture_output=True)
                    for d in ('/var/lib/caddy',
                              '/var/lib/caddy/.local',
                              '/var/lib/caddy/.local/share',
                              '/var/lib/caddy/.local/share/caddy',
                              '/var/lib/caddy/.local/share/caddy/certificates',
                              cert_base,
                              f'{cert_base}/{mtx_domain}'):
                        subprocess.run(_sudo_wrap(['chmod', 'g+rx', d]), capture_output=True)
                    subprocess.run(_sudo_wrap(['chmod', 'g+r', cert_file, key_file]), capture_output=True)
                    # daemon-reload so the SupplementaryGroups=caddy in the unit (written in Step 5) takes effect
                    subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True)
                    plog("  ✓ Cert read-access granted to MediaMTX (takwerx in caddy group)")
                except Exception as _e:
                    plog(f"  ⚠ Could not grant cert read-access: {_e}")

                subprocess.run(_sudo_wrap(['systemctl', 'restart', 'mediamtx']), capture_output=True)
                time.sleep(2)
                # Caddy's /hls-proxy reverse_proxy only emits https:// when the stream
                # cert exists at generate-time (_get_mediamtx_hls_upstream). On a fresh
                # box the Step-7 Caddyfile was written before the LE cert had issued, so
                # it may still proxy plain HTTP to MediaMTX's now-HTTPS HLS port → browser
                # 400 ("Client sent an HTTP request to an HTTPS server"). We just confirmed
                # the cert AND flipped hlsEncryption: yes, so regenerate Caddy now to
                # switch /hls-proxy to the https backend (closes the encrypt-vs-gen race).
                _caddy_regenerate_if_fqdn()
                plog("✓ Caddy regenerated — /hls-proxy now matches the HTTPS HLS backend")
            else:
                plog(f"  ⚠ Cert not found after 60s — SSL not wired")
                plog(f"  Go to Caddy page, reload, then restart MediaMTX to retry")
        elif not domain:
            plog("  No domain configured — skipping Caddy (access via port 5080 directly)")
        else:
            plog("  Caddy not running — skipping SSL integration")

        # Verify MediaMTX is up — poll up to 30s so the deploy log shows green
        # only after the service is actually accepting connections. Without this,
        # hitting stream.fqdn immediately after deploy gets Authentik "Not Found"
        # because Caddy has the vhost but :5080 isn't listening yet.
        plog("")
        plog("━━━ Waiting for MediaMTX to become active ━━━")
        mtx_active = False
        for _i in range(15):
            r = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'mediamtx']), capture_output=True, text=True)
            if r.stdout.strip() == 'active':
                mtx_active = True
                plog("✓ MediaMTX is active")
                break
            time.sleep(2)
        if not mtx_active:
            plog("⚠ MediaMTX did not become active within 30s — check: systemctl status mediamtx")
        if mtx_active:
            # If Authentik is running, ensure stream visibility groups exist (video-public, video-private, video-admin)
            ak_dir = os.path.expanduser('~/authentik')
            env_path = os.path.join(ak_dir, '.env')
            if os.path.exists(os.path.join(ak_dir, 'docker-compose.yml')) and os.path.exists(env_path):
                ak_token = ''
                with open(env_path) as f:
                    for line in f:
                        if line.strip().startswith('AUTHENTIK_BOOTSTRAP_TOKEN='):
                            ak_token = line.strip().split('=', 1)[1].strip()
                            break
                if ak_token:
                    import urllib.request
                    import urllib.error
                    plog("")
                    plog("━━━ Creating Authentik groups for stream access ━━━")
                    ak_url = 'http://127.0.0.1:9090'
                    ak_headers = {'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'}
                    for group_name in ('vid_public', 'vid_private'):
                        try:
                            req = urllib.request.Request(f'{ak_url}/api/v3/core/groups/',
                                data=json.dumps({'name': group_name, 'is_superuser': False}).encode(),
                                headers=ak_headers, method='POST')
                            urllib.request.urlopen(req, timeout=10)
                            plog(f"  ✓ Created group: {group_name}")
                        except urllib.error.HTTPError as e:
                            if e.code == 400:
                                plog(f"  ✓ Group already exists: {group_name}")
                            else:
                                plog(f"  ⚠ Could not create {group_name}: {e.code}")
                        except Exception as ex:
                            plog(f"  ⚠ Could not create {group_name}: {str(ex)[:60]}")
                    plog("  Assign users to vid_* groups in MediaMTX stream-access page or Authentik (they do not show in TAK clients).")

                    plog("")
                    plog("━━━ Registering MediaMTX in Authentik (proxy provider + application) ━━━")
                    _ensure_authentik_console_app(domain, ak_token, plog)
                    _repair_embedded_outpost_all_apps(ak_url, ak_headers, settings, plog)

            plog("")
            plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
            plog(f"🎉 MediaMTX v{version} deployed successfully!")
            if domain:
                mtx_display_domain = f"stream.{domain}"
                plog(f"   Web Console: https://{mtx_display_domain}")
                plog(f"   HLS streams: https://{mtx_display_domain}/[stream]/index.m3u8")
            else:
                plog(f"   Web Editor: http://{settings.get('server_ip','server')}:5080")
            plog(f"   RTSP: rtsp://[server]:8554/[stream]")
            plog(f"   SRT:  srt://[server]:8890?streamid=[stream]")
            plog(f"   HLS viewer password: {'*' * max(0, len(hls_pass) - 4) + hls_pass[-4:]}")
            plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
            mediamtx_deploy_status.update({'running': False, 'complete': True, 'error': False})
        else:
            plog("✗ MediaMTX service not active after deploy — check logs")
            mediamtx_deploy_status.update({'running': False, 'error': True})

    except Exception as e:
        plog(f"✗ Unexpected error: {str(e)}")
        mediamtx_deploy_status.update({'running': False, 'error': True})

# ── CloudTAK ──────────────────────────────────────────────────────────────────
cloudtak_deploy_log = []
cloudtak_deploy_status = {'running': False, 'complete': False, 'error': False}
cloudtak_uninstall_status = {'running': False, 'done': False, 'error': None}
_cloudtak_deploy_lock = threading.Lock()

# Plugin catalog — each entry describes a community CloudTAK plugin.
# install_dir: subdirectory under ~/CloudTAK/api/web/plugins/ that Vite
#   auto-discovers via import.meta.glob at build time (no wiring needed).
#
# local_path (optional): absolute path to the plugin source directory on this
#   machine. When set, install creates a symlink instead of git-cloning so
#   edits in the source tree are reflected immediately on next API rebuild.
#   Vite follows symlinks, so the bundle picks it up without any extra config.
#   Set repo instead (or in addition) once the plugin has its own public repo.
_REPO_ROOT = os.path.dirname(os.path.abspath(__file__))

CLOUDTAK_PLUGINS = [
    {
        'key': 'ping',
        'name': 'Cell Ping / RTT',
        'description': (
            'Plot cellphone tower coverage as CoT features. '
            'Cell Ping produces a u-d-c-c uncertainty circle; '
            'RTT produces a u-rb-a arc (±70° wedge). '
            'Posts directly to an active DataSync mission.'
        ),
        'repo': 'https://github.com/clptak/cloudtak-plugin-cellphone',
        'install_dir': 'ping',
        'requires': 'CloudTAK 13.2+',
        'author': 'clptak',
        'license': 'MIT',
    },
    {
        'key': 'tak-dispatcher',
        'name': 'CloudTAK Dispatcher',
        'description': (
            'Standalone dispatcher plugin for CloudTAK — create incidents on the map, '
            'notify responders via mission thread and direct message. Works without the '
            'TAK-CAD server plugin; auto-upgrades to full TAK-CAD mode when detected.'
        ),
        # Deployed from its own public repo (like ping). The web plugin and the CloudTAK
        # API routes live in separate subdirs: the installer clones the repo to a cache dir,
        # copies plugin/ into web/plugins/ and server/*.ts into api/routes/. The server files
        # must NOT land under web/plugins or CloudTAK's web build (vue-tsc) would type-check
        # them (they import server-only api libs). plugin-takcad.ts is the optional TAK-CAD
        # proxy; plugin-dispatcher.ts is the standalone Events/Incidents store.
        'repo': 'https://github.com/takwerx/cloudtak-dispatcher-plugin',
        'plugin_subpath': 'plugin',
        'server_subpath': 'server',
        'install_dir': 'tak-dispatcher',
        'requires': 'CloudTAK 13.2+',
        'author': 'takwerx',
        'license': 'Proprietary',
    },
]

cloudtak_plugin_log = []
cloudtak_plugin_status = {'running': False, 'complete': False, 'error': False, 'action': '', 'plugin': ''}
_cloudtak_plugin_lock = threading.Lock()

