@app.route('/api/cloudtak/control', methods=['POST'])
@login_required
def cloudtak_control():
    action = (request.json or {}).get('action', '')
    settings = load_settings()
    cfg = _get_cloudtak_deployment_config(settings)
    if cfg.get('target_mode') == 'remote':
        rcfg = cfg.get('remote', {})
        if not (rcfg.get('host') or '').strip():
            return jsonify({'error': 'Remote host not configured'}), 400
        if action == 'start':
            cmd = "cd ~/CloudTAK && docker compose up -d"
        elif action == 'stop':
            cmd = "cd ~/CloudTAK && docker compose stop"
        elif action == 'restart':
            cmd = "cd ~/CloudTAK && docker compose restart"
        elif action == 'update':
            cmd = "cd ~/CloudTAK && [ -x ./cloudtak.sh ] && ./cloudtak.sh update || (docker compose pull && docker compose up -d)"
        else:
            return jsonify({'error': 'Invalid action'}), 400
        ok, out = _ssh_probe(rcfg, cmd, timeout=900 if action == 'update' else 120)
        if not ok:
            return jsonify({'error': (out or 'Remote action failed')[:220]}), 400
        time.sleep(2)
        ok, out = _ssh_probe(rcfg, "docker ps --filter name=cloudtak-api --format '{{.Status}}' 2>/dev/null", timeout=10)
        running = bool(ok and out and 'Up' in out)
    else:
        cloudtak_dir = os.path.expanduser('~/CloudTAK')
        if action == 'start':
            subprocess.run(_sudo_wrap(['docker', 'compose', 'up', '-d']), cwd=cloudtak_dir, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, timeout=60)
        elif action == 'stop':
            subprocess.run(_sudo_wrap(['docker', 'compose', 'stop']), cwd=cloudtak_dir, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, timeout=60)
        elif action == 'restart':
            subprocess.run(_sudo_wrap(['docker', 'compose', 'restart']), cwd=cloudtak_dir, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, timeout=60)
        elif action == 'update':
            # cloudtak.sh runs docker internally; the non-root console reaches it
            # through the broker via the shim PATH (env). No-op env as root.
            subprocess.run(f'cd {cloudtak_dir} && ./cloudtak.sh update 2>&1', shell=True,
                           capture_output=True, timeout=600, env=_broker_shim_env())
        else:
            return jsonify({'error': 'Invalid action'}), 400
        time.sleep(3)
        r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=cloudtak-api', '--format', '{{.Status}}']), capture_output=True, text=True)
        running = 'Up' in r.stdout
    return jsonify({'success': True, 'running': running})

@app.route('/api/cloudtak/logs')
@login_required
def cloudtak_container_logs():
    lines = request.args.get('lines', 80, type=int)
    lines = max(1, min(lines if lines is not None else 80, 500))
    container = request.args.get('container', '').strip()
    if container and not re.match(r'^[a-zA-Z0-9][a-zA-Z0-9_.-]*$', container):
        return jsonify({'entries': ['Invalid container name']}), 400
    settings = load_settings()
    cfg = _get_cloudtak_deployment_config(settings)
    if cfg.get('target_mode') == 'remote':
        rcfg = cfg.get('remote', {})
        if not (rcfg.get('host') or '').strip():
            return jsonify({'entries': ['Remote host not configured']})
        if container:
            cmd = f"docker logs {container} --tail {lines} 2>&1"
        else:
            cmd = "cd ~/CloudTAK && docker compose logs --tail " + str(lines) + " 2>&1"
        ok, out = _ssh_probe(rcfg, cmd, timeout=20)
        entries = [l for l in ((out or '').strip().split('\n') if (out or '').strip() else []) if l.strip()]
        if not ok and not entries:
            entries = ['Could not fetch remote logs']
        return jsonify({'entries': entries})
    cloudtak_dir = os.path.expanduser('~/CloudTAK')
    compose_yml = os.path.join(cloudtak_dir, 'docker-compose.yml')
    if not os.path.exists(compose_yml):
        compose_yml = os.path.join(cloudtak_dir, 'compose.yaml')
    if container:
        r = subprocess.run(_sudo_wrap(['docker', 'logs', container, '--tail', str(lines)]),
            capture_output=True, text=True, timeout=15)
    else:
        if os.path.exists(compose_yml):
            r = subprocess.run(_sudo_wrap(['docker', 'compose', '-f', compose_yml, 'logs', '--tail', str(lines)]), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=15, cwd=cloudtak_dir)
        else:
            r = subprocess.run(_sudo_wrap(['docker', 'logs', 'cloudtak-api-1', '--tail', str(lines)]), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=15)
    entries = [l for l in (r.stdout.strip().split('\n') if r.stdout.strip() else []) if l.strip()]
    return jsonify({'entries': entries})

@app.route('/api/cloudtak/uninstall', methods=['POST'])
@login_required
def cloudtak_uninstall():
    data = request.json or {}
    password = data.get('password', '')
    req_cfg = data.get('config') if isinstance(data.get('config'), dict) else None
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'error': 'Invalid admin password'}), 403
    if cloudtak_uninstall_status.get('running'):
        return jsonify({'error': 'Uninstall already in progress'}), 409
    # If UI sent an explicit target config, persist it first so uninstall uses
    # the same target the user currently selected.
    if req_cfg is not None:
        try:
            settings = load_settings()
            merged = _normalize_cloudtak_deployment_config(req_cfg)
            settings['cloudtak_deployment'] = merged
            save_settings(settings)
        except Exception as e:
            return jsonify({'error': f'Could not save deployment target: {e}'}), 400
    cloudtak_uninstall_status.update({'running': True, 'done': False, 'error': None})
    def do_uninstall():
        try:
            settings = load_settings()
            cfg = _get_cloudtak_deployment_config(settings)
            if cfg.get('target_mode') == 'remote':
                rcfg = cfg.get('remote', {})
                rhost = (rcfg.get('host') or '').strip()
                if not rhost:
                    cloudtak_uninstall_status.update({'running': False, 'done': True, 'error': 'Remote target selected but host is not configured'})
                    return
                ok, out = _ssh_probe(
                    rcfg,
                    "set -e; cd ~/CloudTAK 2>/dev/null || true; "
                    "if [ -f ~/CloudTAK/docker-compose.yml ] || [ -f ~/CloudTAK/compose.yaml ]; then "
                    "cd ~/CloudTAK; COMPOSE_FILE=docker-compose.yml; [ -f compose.yaml ] && COMPOSE_FILE=compose.yaml; "
                    "docker compose -f \"$COMPOSE_FILE\" down -v --rmi local 2>/dev/null || "
                    "docker-compose -f \"$COMPOSE_FILE\" down -v --rmi local 2>/dev/null || true; "
                    "fi; rm -rf ~/CloudTAK",
                    timeout=300
                )
                if not ok:
                    cloudtak_uninstall_status.update({'running': False, 'done': True, 'error': f'Remote uninstall failed on {rhost}: {(out or "unknown error")[:240]}'})
                    return
            else:
                # v10.0.5 non-root: CloudTAK may live at ~/CloudTAK OR (root-era) /root/CloudTAK,
                # which the takwerx console can't stat/cd/rm. The old ~/CloudTAK-only path silently
                # no-op'd on flipped boxes (os.path.exists('/home/takwerx/CloudTAK') False) → the
                # containers kept running and the tree stayed. Resolve the real dir (broker-check
                # /root) and tear down through the BROKER (root cd's /root, removes root-owned
                # containers / .docker-store / .git).
                cloudtak_dir = os.path.expanduser('~/CloudTAK')
                if not os.path.exists(cloudtak_dir):
                    _rchk = subprocess.run(_sudo_wrap(['test', '-d', '/root/CloudTAK']), capture_output=True, timeout=10)
                    cloudtak_dir = '/root/CloudTAK' if _rchk.returncode == 0 else None
                if cloudtak_dir:
                    # v10.0.8: no shell — --project-directory replaces the bash-cd (denied by
                    # the broker rulebook). `docker compose` only: the legacy docker-compose
                    # fallback was itself a bug (see cloudtak-update-docker-compose memory).
                    _broker_compose(cloudtak_dir, 'down -v --rmi local', timeout=300)
                # Belt-and-suspenders: force-remove any surviving cloudtak-* containers by name
                # (covers a dir-less / root-owned state where compose down didn't catch them) —
                # two broker calls replace the old bash+xargs pipeline (both denied).
                _ids = subprocess.run(_sudo_wrap(['docker', 'ps', '-aq', '--filter', 'name=cloudtak']),
                                      capture_output=True, text=True, timeout=30)
                _surv = (_ids.stdout or '').split()
                if _surv:
                    subprocess.run(_sudo_wrap(['docker', 'rm', '-f'] + _surv),
                                   capture_output=True, timeout=120)
                if cloudtak_dir:
                    subprocess.run(_sudo_wrap(['rm', '-rf', cloudtak_dir]), capture_output=True, timeout=120)
            cfg['deployed'] = False
            settings['cloudtak_deployment'] = _normalize_cloudtak_deployment_config(cfg)
            save_settings(settings)
            cloudtak_deploy_log.clear()
            cloudtak_deploy_status.update({'running': False, 'complete': False, 'error': False})
            generate_caddyfile()
            subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
            _update_boot_stagger_service()
            cloudtak_uninstall_status.update({'running': False, 'done': True, 'error': None})
        except subprocess.TimeoutExpired:
            cloudtak_uninstall_status.update({'running': False, 'done': True, 'error': 'Uninstall timed out'})
        except Exception as e:
            cloudtak_uninstall_status.update({'running': False, 'done': True, 'error': str(e)[:200]})
    threading.Thread(target=do_uninstall, daemon=True).start()
    return jsonify({'success': True, 'message': 'Uninstall started'})

@app.route('/api/cloudtak/uninstall/status')
@login_required
def cloudtak_uninstall_status_api():
    return jsonify({
        'running': cloudtak_uninstall_status.get('running', False),
        'done': cloudtak_uninstall_status.get('done', False),
        'error': cloudtak_uninstall_status.get('error')
    })

@app.route('/api/cloudtak/reset-server-config', methods=['POST'])
@login_required
def cloudtak_reset_server_config():
    """Clear CloudTAK's stored TAK Server auth so the bootstrap wizard runs again.

    Resets auth to empty jsonb ({}) in the server table via psql inside the
    postgis container, then restarts just the api container so it reloads
    config from the database. Works for local and remote targets.
    """
    settings = load_settings()
    cfg = _get_cloudtak_deployment_config(settings)
    target_mode = (cfg.get('target_mode') or 'local').strip().lower()

    # Two-step reset (confirmed from CloudTAK source api/routes/server.ts):
    #
    # 1. Clear the server connection fields so /api/server returns status:unconfigured
    #    and the configure wizard shows again.
    #
    # 2. TRUNCATE profile CASCADE. CloudTAK's PATCH /server handler calls
    #    profileControl.generate() which does a plain INSERT (not upsert). If the
    #    admin user's profile row still exists, the wizard fails with
    #    "Key (username)=(...) already exists". We use TRUNCATE CASCADE (not DELETE)
    #    because multiple tables (profile_overlays, profile_config, etc.) have FK
    #    references to profile.username — a plain DELETE hits FK violations.
    #    Truncating all profiles is correct for a reset: all profile rows are tied to
    #    the old TAK Server's user accounts which won't exist on the new server.
    sql_cmd = (
        "UPDATE server SET auth = '{}'::jsonb, url = '', api = '', webtak = '' WHERE id = 1;"
        " TRUNCATE profile CASCADE;"
    )
    psql_cmd = f"docker exec cloudtak-postgis-1 psql -U docker -d gis -c \"{sql_cmd}\" 2>&1"
    restart_cmd = "cd ~/CloudTAK && docker compose restart api 2>&1"

    if target_mode == 'remote':
        rcfg = cfg.get('remote', {})
        rhost = (rcfg.get('host') or '').strip()
        if not rhost:
            return jsonify({'success': False, 'error': 'Remote host not configured'}), 400
        ok1, out1 = _ssh_probe(rcfg, psql_cmd, timeout=30)
        if not ok1:
            return jsonify({'success': False, 'error': f'SQL reset failed on {rhost}: {(out1 or "unknown")[:400]}'}), 500
        ok2, out2 = _ssh_probe(rcfg, restart_cmd, timeout=60)
        if not ok2:
            return jsonify({'success': False, 'error': f'API restart failed on {rhost}: {(out2 or "unknown")[:200]}'}), 500
        return jsonify({'success': True, 'message': f'CloudTAK server config cleared on {rhost}. Visit map.{settings.get("fqdn","<domain>")} to re-run the bootstrap wizard.'})
    else:
        try:
            r1 = subprocess.run(psql_cmd, shell=True, capture_output=True, text=True, timeout=30)
            if r1.returncode != 0:
                return jsonify({'success': False, 'error': f'SQL reset failed: {(r1.stdout + r1.stderr)[:400]}'}), 500
        except subprocess.TimeoutExpired:
            return jsonify({'success': False, 'error': 'psql command timed out'}), 500
        try:
            cloudtak_dir = os.path.expanduser('~/CloudTAK')
            r2 = subprocess.run(_sudo_wrap(['docker', 'compose', 'restart', 'api']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=60, cwd=cloudtak_dir)
            if r2.returncode != 0:
                return jsonify({'success': False, 'error': f'API restart failed: {(r2.stdout + r2.stderr)[:200]}'}), 500
        except subprocess.TimeoutExpired:
            return jsonify({'success': False, 'error': 'docker compose restart timed out'}), 500
        fqdn = settings.get('fqdn', '')
        return jsonify({'success': True, 'message': f'CloudTAK server config cleared. Visit {"map." + fqdn if fqdn else "CloudTAK"} to re-run the bootstrap wizard.'})


def _plugin_built_marker_path(ct_dir, install_dir):
    # v0.9.44: SHA of the source last *successfully built* into the CloudTAK image.
    # Lives outside any git clone so `git pull` on the cache can't touch it.
    return os.path.join(ct_dir, '.plugin-src', f'.built-{install_dir}')


def _read_plugin_built_sha(ct_dir, install_dir):
    try:
        with open(_plugin_built_marker_path(ct_dir, install_dir)) as f:
            return f.read().strip() or None
    except Exception:
        return None


def _write_plugin_built_sha(ct_dir, install_dir, sha):
    try:
        p = _plugin_built_marker_path(ct_dir, install_dir)
        os.makedirs(os.path.dirname(p), exist_ok=True)
        with open(p, 'w') as f:
            f.write((sha or '').strip())
    except Exception:
        pass


def _snapshot_cloudtak_plugin_state(ct_dir, install_path):
    """v0.9.44: back up the CloudTAK files a plugin action mutates (api/routes + the web
    plugin dir) so a failed rebuild can be rolled back — a broken plugin must never leave
    CloudTAK in an unbuildable state."""
    import tempfile, shutil
    snap = tempfile.mkdtemp(prefix='ct-plugin-rollback-')
    routes = os.path.join(ct_dir, 'api', 'routes')
    if os.path.isdir(routes):
        shutil.copytree(routes, os.path.join(snap, 'routes'), symlinks=True)
    web_existed = os.path.isdir(install_path) or os.path.islink(install_path)
    if web_existed:
        shutil.copytree(install_path, os.path.join(snap, 'web'), symlinks=True)
    return {'snap': snap, 'web_existed': web_existed}


def _rollback_cloudtak_plugin_state(ct_dir, install_path, snap_info, plog=None):
    import shutil
    if not snap_info or not snap_info.get('snap'):
        return
    snap = snap_info['snap']
    routes = os.path.join(ct_dir, 'api', 'routes')
    snap_routes = os.path.join(snap, 'routes')
    if os.path.isdir(snap_routes):
        shutil.rmtree(routes, ignore_errors=True)
        shutil.move(snap_routes, routes)
    if os.path.islink(install_path):
        os.unlink(install_path)
    elif os.path.isdir(install_path):
        shutil.rmtree(install_path, ignore_errors=True)
    snap_web = os.path.join(snap, 'web')
    if snap_info.get('web_existed') and os.path.isdir(snap_web):
        shutil.move(snap_web, install_path)
    shutil.rmtree(snap, ignore_errors=True)
    if plog:
        plog('  ↩ Restored CloudTAK api/routes + plugin dir to the pre-update state.')


def _cleanup_snapshot(snap_info):
    import shutil
    if snap_info and snap_info.get('snap'):
        shutil.rmtree(snap_info['snap'], ignore_errors=True)


def _detect_cloudtak_plugins():
    """Return the CLOUDTAK_PLUGINS catalog annotated with installed/commit/update_available."""
    ct_dir = os.path.expanduser('~/CloudTAK')
    plugins_base = os.path.join(ct_dir, 'api', 'web', 'plugins')
    result = []
    for p in CLOUDTAK_PLUGINS:
        install_path = os.path.join(plugins_base, p['install_dir'])
        installed = os.path.isdir(install_path) or os.path.islink(install_path)
        is_local  = bool(p.get('local_path'))
        sha = None
        update_available = False
        # Resolve which directory actually holds the plugin's git clone. For repo plugins that
        # ship the web/server halves in subdirs, install_path (under api/web/plugins/) is a
        # *copy* with no .git — the real clone lives in ~/CloudTAK/.plugin-src/<install_dir>.
        # Running `git -C` in a dir that has no .git makes git walk UP the tree and report
        # CloudTAK's own repo commit/update state instead of the plugin's (the bogus-SHA bug).
        # Local-path plugins are copied from this repo and have no upstream of their own.
        git_dir = None
        if installed and not is_local:
            uses_subpaths = bool(p.get('repo') and (p.get('plugin_subpath') or p.get('server_subpath')))
            cand = os.path.join(ct_dir, '.plugin-src', p['install_dir']) if uses_subpaths else install_path
            if os.path.isdir(os.path.join(cand, '.git')):
                git_dir = cand
        if git_dir:
            # v0.9.44 honest badge: show the SHA actually BUILT into the running image,
            # not the source cache HEAD. A failed rebuild advances the cache but leaves the
            # old image live, so comparing the cache would falsely clear the "update" badge.
            built_sha = _read_plugin_built_sha(ct_dir, p['install_dir'])
            head_sha = None
            try:
                r = subprocess.run(
                    ['git', '-C', git_dir, 'rev-parse', '--short=7', 'HEAD'],
                    capture_output=True, text=True, timeout=5
                )
                if r.returncode == 0:
                    head_sha = r.stdout.strip()
            except Exception:
                pass
            # Built marker wins; fall back to cache HEAD for pre-0.9.44 installs (no marker).
            sha = built_sha or head_sha
            # Remote HEAD — an update exists if nothing is built yet or built != upstream.
            try:
                r2 = subprocess.run(
                    ['git', '-C', git_dir, 'ls-remote', 'origin', 'HEAD'],
                    capture_output=True, text=True, timeout=5
                )
                if r2.returncode == 0 and r2.stdout.strip():
                    remote_short = r2.stdout.split()[0][:7]
                    if remote_short and (not sha or sha != remote_short):
                        update_available = True
            except Exception:
                pass
        result.append({**p, 'installed': installed, 'sha': sha, 'update_available': update_available, 'local': is_local})
    return result


def _run_cloudtak_plugin_action(plugin_key, action):
    """Background thread: install / update / remove a CloudTAK plugin then rebuild the API image."""
    global cloudtak_plugin_log, cloudtak_plugin_status
    cloudtak_plugin_log = []
    cloudtak_plugin_status = {'running': True, 'complete': False, 'error': False, 'action': action, 'plugin': plugin_key}

    plugin = next((p for p in CLOUDTAK_PLUGINS if p['key'] == plugin_key), None)
    if not plugin:
        cloudtak_plugin_log.append(f'Unknown plugin key: {plugin_key}')
        cloudtak_plugin_status.update({'running': False, 'error': True})
        return

    ct_dir = os.path.expanduser('~/CloudTAK')
    plugins_base = os.path.join(ct_dir, 'api', 'web', 'plugins')
    install_path = os.path.join(plugins_base, plugin['install_dir'])

    def plog(msg):
        ts = datetime.now().strftime('%H:%M:%S')
        entry = f'[{ts}] {msg}'
        cloudtak_plugin_log.append(entry)
        print(entry, flush=True)

    def run_cmd(cmd, cwd=None, timeout=600, shell=False):
        cmd_str = cmd if isinstance(cmd, str) else ' '.join(cmd)
        plog(f'$ {cmd_str}')
        try:
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout, cwd=cwd, shell=shell)
            for line in (r.stdout or '').splitlines():
                if line.strip():
                    plog(line)
            for line in (r.stderr or '').splitlines():
                if line.strip():
                    plog(line)
            return r.returncode == 0
        except subprocess.TimeoutExpired:
            plog('Error: command timed out')
            return False
        except Exception as e:
            plog(f'Error: {e}')
            return False

    local_path = plugin.get('local_path')
    repo = plugin.get('repo')
    plugin_subpath = plugin.get('plugin_subpath')
    server_subpath = plugin.get('server_subpath')
    # Repo plugins that ship the web plugin and the server route in separate subdirs are
    # cloned to a cache dir, then plugin_subpath is copied into web/plugins and server_subpath
    # into api/routes (server *.ts must NOT live under web/plugins or the web build breaks).
    use_subpaths = bool(repo and (plugin_subpath or server_subpath))
    cache_path = os.path.join(ct_dir, '.plugin-src', plugin['install_dir'])

    def _web_src():
        return os.path.join(cache_path, plugin_subpath) if plugin_subpath else cache_path

    def _clone_or_pull_cache():
        import shutil
        if os.path.isdir(os.path.join(cache_path, '.git')):
            return run_cmd(['git', '-C', cache_path, 'pull'])
        shutil.rmtree(cache_path, ignore_errors=True)
        os.makedirs(os.path.dirname(cache_path), exist_ok=True)
        return run_cmd(['git', 'clone', repo, cache_path])

    built_ok = False
    snap = None
    try:
        # v0.9.44: snapshot the files we're about to mutate so a failed rebuild rolls back.
        snap = _snapshot_cloudtak_plugin_state(ct_dir, install_path)
        if action == 'install':
            plog(f'Installing plugin: {plugin["name"]}')
            if os.path.isdir(install_path) or os.path.islink(install_path):
                plog(f'Plugin already exists at {install_path} — already installed?')
                cloudtak_plugin_status.update({'running': False, 'error': True})
                return
            os.makedirs(plugins_base, exist_ok=True)
            if local_path:
                # Copy (not symlink) — Docker COPY follows the symlink as-is and
                # the host path won't exist inside the container, breaking Vite's glob.
                import shutil
                plog(f'Copying local plugin source: {local_path} → {install_path}')
                shutil.copytree(local_path, install_path)
            elif use_subpaths:
                import shutil
                plog(f'Cloning plugin repository: {repo}')
                if not _clone_or_pull_cache():
                    cloudtak_plugin_status.update({'running': False, 'error': True})
                    return
                plog(f'Copying web plugin: {plugin_subpath or "."} → {install_path}')
                shutil.copytree(_web_src(), install_path)
            else:
                plog('Cloning plugin repository...')
                if not run_cmd(['git', 'clone', plugin['repo'], install_path]):
                    cloudtak_plugin_status.update({'running': False, 'error': True})
                    return

        elif action == 'update':
            plog(f'Updating plugin: {plugin["name"]}')
            if not os.path.isdir(install_path) and not os.path.islink(install_path):
                plog(f'Plugin not installed at {install_path}')
                cloudtak_plugin_status.update({'running': False, 'error': True})
                return
            if local_path:
                # Re-copy from source so any code changes in the repo are picked up.
                import shutil
                plog(f'Re-copying local plugin source: {local_path} → {install_path}')
                shutil.rmtree(install_path, ignore_errors=True)
                if os.path.islink(install_path):
                    os.unlink(install_path)
                shutil.copytree(local_path, install_path)
            elif use_subpaths:
                import shutil
                plog(f'Pulling plugin repository: {repo}')
                if not _clone_or_pull_cache():
                    cloudtak_plugin_status.update({'running': False, 'error': True})
                    return
                plog(f'Re-copying web plugin: {plugin_subpath or "."} → {install_path}')
                shutil.rmtree(install_path, ignore_errors=True)
                if os.path.islink(install_path):
                    os.unlink(install_path)
                shutil.copytree(_web_src(), install_path)
            else:
                if not run_cmd(['git', '-C', install_path, 'pull']):
                    cloudtak_plugin_status.update({'running': False, 'error': True})
                    return

        elif action == 'remove':
            plog(f'Removing plugin: {plugin["name"]}')
            if not os.path.isdir(install_path) and not os.path.islink(install_path):
                plog('Plugin is not installed — nothing to remove')
                cloudtak_plugin_status.update({'running': False, 'error': True})
                return
            import shutil
            if os.path.islink(install_path):
                os.unlink(install_path)
            else:
                shutil.rmtree(install_path)
            plog(f'Removed {install_path}')

        # Server-side route files: copied into api/routes/ so the browser plugin
        # can reach TAK Server plugin APIs via CloudTAK's cert auth. CloudTAK
        # auto-loads every file in api/routes/ (schema.load('./routes/')). For repo
        # plugins the routes come from the cloned cache's server_subpath.
        server_path = plugin.get('server_path')
        if use_subpaths and server_subpath:
            server_path = os.path.join(cache_path, server_subpath)
        if server_path and os.path.isdir(server_path):
            import shutil
            routes_base = os.path.join(ct_dir, 'api', 'routes')
            os.makedirs(routes_base, exist_ok=True)
            for fname in sorted(os.listdir(server_path)):
                if not fname.endswith('.ts'):
                    continue
                dest = os.path.join(routes_base, fname)
                if action == 'remove':
                    if os.path.exists(dest):
                        os.remove(dest)
                        plog(f'Removed server route: api/routes/{fname}')
                else:
                    shutil.copy2(os.path.join(server_path, fname), dest)
                    plog(f'Installed server route: api/routes/{fname}')

        # On remove, drop the repo source cache too (kept until now so the server-route
        # removal above could list which files to delete).
        if use_subpaths and action == 'remove':
            import shutil
            shutil.rmtree(cache_path, ignore_errors=True)

        # Rebuild the API image to bake in (or remove) the plugin from the Vite bundle.
        # Service name is 'api' per upstream docker-compose.yml (cloudtak.sh uses the same).
        plog('')
        plog('Rebuilding CloudTAK API image — this takes 5–15 minutes...')
        if not run_cmd(['docker', 'compose', 'build', '--no-cache', 'api'], cwd=ct_dir, timeout=1200):
            plog('✗ Rebuild failed — rolling back so CloudTAK stays buildable...')
            _rollback_cloudtak_plugin_state(ct_dir, install_path, snap, plog)
            snap = None
            cloudtak_plugin_status.update({'running': False, 'error': True})
            return
        built_ok = True
        # v0.9.44: record the source SHA that actually built (honest update badge).
        if action == 'remove':
            try:
                os.remove(_plugin_built_marker_path(ct_dir, plugin['install_dir']))
            except Exception:
                pass
        elif not local_path:
            src = cache_path if use_subpaths else install_path
            try:
                rr = subprocess.run(['git', '-C', src, 'rev-parse', '--short=7', 'HEAD'],
                                    capture_output=True, text=True, timeout=5)
                if rr.returncode == 0:
                    _write_plugin_built_sha(ct_dir, plugin['install_dir'], rr.stdout.strip())
            except Exception:
                pass

        plog('Restarting CloudTAK API container...')
        if not run_cmd(['docker', 'compose', 'up', '-d', '--force-recreate', 'api'], cwd=ct_dir, timeout=120):
            cloudtak_plugin_status.update({'running': False, 'error': True})
            return

        action_label = {'install': 'installed', 'update': 'updated', 'remove': 'removed'}.get(action, action)
        plog(f'✓ Plugin {action_label} successfully.')
        if action in ('install', 'update'):
            plog('  → In CloudTAK: Settings → Refresh App to activate the new service worker.')
            plog('    If still on the old version: DevTools (F12) → Application → Clear site data, then reload.')
            plog('    (A refresh — even Cmd/Ctrl+Shift+R — will NOT help; the service worker serves a cached copy.)')
            plog('    Plugin appears at the bottom of the right-side menu.')
        cloudtak_plugin_status.update({'running': False, 'complete': True, 'error': False})

    except Exception as e:
        plog(f'Unexpected error: {e}')
        if not built_ok:
            plog('Rolling back partial changes...')
            _rollback_cloudtak_plugin_state(ct_dir, install_path, snap, plog)
            snap = None
        cloudtak_plugin_status.update({'running': False, 'error': True})
    finally:
        _cleanup_snapshot(snap)


@app.route('/api/cloudtak/plugins/list')
@login_required
def cloudtak_plugins_list():
    """Return plugin catalog with installed/commit state and current action status."""
    plugins = _detect_cloudtak_plugins()
    return jsonify({'plugins': plugins, 'status': cloudtak_plugin_status})


@app.route('/api/cloudtak/plugins/action', methods=['POST'])
@login_required
def cloudtak_plugin_action():
    """Trigger install / update / remove for a named plugin."""
    with _cloudtak_plugin_lock:
        if cloudtak_plugin_status.get('running'):
            return jsonify({'error': 'Another plugin action is already running'}), 409
    data = request.get_json() or {}
    plugin_key = (data.get('plugin') or '').strip()
    action = (data.get('action') or '').strip()
    if not plugin_key or action not in ('install', 'update', 'remove'):
        return jsonify({'error': 'Invalid request — provide plugin key and action (install/update/remove)'}), 400
    if not any(p['key'] == plugin_key for p in CLOUDTAK_PLUGINS):
        return jsonify({'error': f'Unknown plugin: {plugin_key}'}), 400
    t = threading.Thread(target=_run_cloudtak_plugin_action, args=(plugin_key, action), daemon=True)
    t.start()
    return jsonify({'ok': True})


@app.route('/api/cloudtak/plugins/log')
@login_required
def cloudtak_plugin_log_api():
    """Poll plugin action log (same ?index=N pattern as /api/cloudtak/deploy/log)."""
    idx = max(0, int(request.args.get('index', 0)))
    return jsonify({
        'entries': cloudtak_plugin_log[idx:],
        'total': len(cloudtak_plugin_log),
        'running': cloudtak_plugin_status.get('running', False),
        'complete': cloudtak_plugin_status.get('complete', False),
        'error': cloudtak_plugin_status.get('error', False),
        'action': cloudtak_plugin_status.get('action', ''),
        'plugin': cloudtak_plugin_status.get('plugin', ''),
    })


def _cloudtak_build_env_content(settings, domain, signing_secret, minio_pass, postgres_pass='docker', remote_host=''):
    """Build CloudTAK .env content for local or remote target.

    postgres_pass: strong random password for the postgis DB. Defaults to
    'docker' for backwards compatibility with pre-v0.9.11 call sites; new
    installs (v0.9.11+) should always pass a `secrets.token_hex(24)` value.
    The value is substituted into the override file's postgis service via
    Compose variable expansion (${POSTGRES_PASSWORD}) so postgis initdb
    bakes the strong password into pg_authid on first boot of a fresh
    data volume.
    """
    # Prefer explicit CloudTAK service domains when available (works even if fqdn is unset).
    ct_map_host = (_get_service_domain(settings, 'cloudtak_map') or '').strip()
    ct_tiles_host = (_get_service_domain(settings, 'cloudtak_tiles') or '').strip()
    ct_video_host = (_get_service_domain(settings, 'cloudtak_video') or '').strip()

    if ct_map_host and ct_tiles_host and ct_video_host:
        api_url = f"https://{ct_map_host}"
        pmtiles_url = f"https://{ct_tiles_host}"
        media_url = f"https://{ct_video_host}"
    elif domain:
        api_url = f"https://map.{domain}"
        pmtiles_url = f"https://tiles.map.{domain}"
        media_url = f"https://video.{domain}"
    else:
        if remote_host:
            api_url = f"http://{remote_host}:5000"
            pmtiles_url = f"http://{remote_host}:5002"
        else:
            api_url = f"http://172.20.0.1:5000"
            pmtiles_url = f"http://{settings.get('server_ip', '127.0.0.1')}:5002"
        media_url = "http://media:9997"
    return f"""CLOUDTAK_Mode=docker-compose
CLOUDTAK_Config_media_url={media_url}

SigningSecret={signing_secret}

ASSET_BUCKET=cloudtak
AWS_S3_Endpoint=http://store:9000
AWS_S3_AccessKeyId=cloudtakminioadmin
AWS_S3_SecretAccessKey={minio_pass}
MINIO_ROOT_USER=cloudtakminioadmin
MINIO_ROOT_PASSWORD={minio_pass}

# POSTGRES_PASSWORD: substituted into postgis service via docker-compose.override.yml.
# Postgres reads POSTGRES_PASSWORD env on initdb (first boot of empty volume) and bakes it
# into pg_authid. On subsequent boots the value is ignored — the password in the DB persists.
# v0.9.11+ generates a random 48-char hex value; pre-v0.9.11 installs used 'docker' (weak).
POSTGRES_PASSWORD={postgres_pass}
POSTGRES=postgres://docker:{postgres_pass}@postgis:5432/gis

# API_URL must be reachable by the browser (for tile URLs in TileJSON). We set it to the public
# map URL when domain is set so the map and basemaps render.
API_URL={api_url}
PMTILES_URL={pmtiles_url}

# Port remapping — avoids conflicts with standalone MediaMTX which owns the original ports.
# CloudTAK's docker-compose.yml supports these env vars natively (no override file needed).
# MEDIA_PORT_API=9997 because video-service.ts hardcodes port 9997 for all MediaMTX API calls.
# Standalone MediaMTX API moved to 9898 to free up 9997 for CloudTAK media container.
MEDIA_PORT_API=9997
MEDIA_PORT_RTSP=18554
MEDIA_PORT_RTMP=11935
MEDIA_PORT_HLS=18888
MEDIA_PORT_SRT=18890
"""


def _cloudtak_build_override_yml(settings):
    """Build docker-compose.override.yml for CloudTAK deployment.

    Adds extra_hosts so the api container can resolve TAK Server FQDN and
    host.docker.internal, and gives the events container an internal API_URL.
    """
    import socket as _sock
    extra_hosts = ['host.docker.internal:host-gateway']
    tak_fqdn = (_get_takserver_host(settings) or '').strip()
    if tak_fqdn:
        try:
            tak_ip = _sock.gethostbyname(tak_fqdn)
            extra_hosts.append(f'{tak_fqdn}:{tak_ip}')
        except Exception:
            server_ip = (settings.get('server_ip') or '').strip()
            if server_ip:
                extra_hosts.append(f'{tak_fqdn}:{server_ip}')
    hosts_block = '\n'.join(f'      - "{h}"' for h in extra_hosts)
    # NOTE: We deliberately do NOT add cap_drop / no-new-privileges here.
    # CloudTAK's api container runs both nginx and Node in the same image;
    # cap_drop:ALL silently breaks nginx workers (can't write /dev/stdout)
    # and breaks the nginx→Node loopback proxy in subtle ways that produce
    # nothing in the logs. Same lesson learned earlier on Authentik worker
    # (commit c908179) and TAK Portal (commit 7fe8191) — these containers
    # legitimately need a default capability set; capability hardening at
    # this level is not appropriate for them.
    # v0.9.11 / v0.9.12 security hardening — lock down every host port that
    # doesn't actually need public-internet exposure.
    #
    # Upstream dfpc-coe/CloudTAK ships postgis bound to 0.0.0.0:5433 with hardcoded
    # docker:docker creds, which was actively exploited in the wild by PG_MEM/PGMiner
    # cryptominer family (live compromise on infra-TAK May 8-10, 2026). The audit
    # that followed found the same class of issue across nearly every CloudTAK
    # container — host ports bound to 0.0.0.0 for app/admin endpoints that are
    # only meant to be reached by Caddy (loopback) or by sibling containers via
    # Docker DNS (no host port needed at all).
    #
    # Tier classification (see docs/PORT-EXPOSURE-POLICY.md):
    #   - api 5000        → Tier 3 (Caddy-loopback)  — browser → cloudtak.fqdn → Caddy → 127.0.0.1:5000
    #   - tiles 5002      → Tier 3 (Caddy-loopback)  — same path, used for tile URLs
    #   - events 5003     → Tier 4 (Docker-internal) — only api/store talk to it; no host port needed
    #   - media 9997      → Tier 3 (Caddy-loopback)  — admin API; api container talks via Docker DNS
    #   - media 18888 HLS → Tier 3 (Caddy-loopback)  — HTTP HLS playback through Caddy
    #   - media 18554 RTSP, 11935 RTMP, 18890 SRT    → Tier 1 (public) — direct streaming clients
    #   - postgis 5433    → Tier 4 (Docker-internal) — gone entirely (v0.9.11)
    #   - store 9000 S3   → Tier 4 (Docker-internal) — gone entirely (v0.9.11)
    #   - store 9002 web  → Tier 3 (Caddy-loopback)  — operator SSH-tunnels for MinIO console
    #
    # postgis POSTGRES_PASSWORD: "${{POSTGRES_PASSWORD}}": Compose substitutes the
    #   value from .env. On a fresh volume initdb bakes this into pg_authid; on an
    #   existing volume the env var is ignored and the previously-baked password
    #   stays in force (so update-only flows don't break running installs).
    #
    # Defense-in-depth: _auto_harden_cloudtak() also installs UFW deny rules for
    # every Tier 3/4 port so a regressed override or disabled UFW alone can't
    # reopen the attack surface.
    # Note: port hardening is applied directly to compose.yaml via
    # _patch_cloudtak_compose_ports() (compose-version-agnostic).
    # `ports: !reset` is NOT used here because Docker Compose v5.x (shipped
    # with Docker Engine 27+) does not support the !reset YAML tag — it
    # resolves to null, silently dropping ALL port bindings.
    return f"""# TAKWERX: CloudTAK container overrides — v0.9.11+v0.9.12 security hardening
# Port hardening applied directly to compose.yaml by _patch_cloudtak_compose_ports().
services:
  api:
    extra_hosts:
{hosts_block}
  events:
    extra_hosts:
{hosts_block}
    environment:
      API_URL: "http://api:5000"
  media:
    extra_hosts:
{hosts_block}
    environment:
      API_URL: "http://api:5000"
  postgis:
    environment:
      POSTGRES_PASSWORD: "${{POSTGRES_PASSWORD:-docker}}"
"""


# --- CloudTAK embedded-MediaMTX (cloudtak-media) self-heal scripts (v0.9.48) ----
# Run INSIDE the cloudtak-media container via `docker exec -i … sh` (stdin-piped, so
# no host/remote quoting concerns). THREE fixes, healed together with one restart:
#
#  (B) /mediamtx.yml — low-latency browser-HLS profile, identical to infra-TAK's own
#      MediaMTX module (app.py ~14616, field-proven on the restreamer):
#        hlsVariant: mpegts        (default lowLatency LL-HLS bails on drone variable
#                                   framerate → hls.js 404s a part and stops)
#        hlsAlwaysRemux: false     (we first shipped true to pre-warm, but with the
#                                   segment tuning below true caused startup buffering
#                                   AND extra lag on the on-demand pull; false matches
#                                   the restreamer and is smoother — field A/B 2026-06-07)
#        hlsSegmentCount: 3 / hlsSegmentDuration: 500ms / hlsPartDuration: 200ms
#                                   (the DEFAULT 7×1s playlist was the 20s lag; 3×500ms
#                                   dropped CloudTAK to ~3s behind a direct view —
#                                   the residual is the proxy hop + hls.js, not config)
#
#  (C) /lib/persist.ts — THE teardown fix. media-infra's reaper cron (every 10s) lists
#      CloudTAK leases with `ephemeral=false` and DELETES every MediaMTX path not in
#      that set. FloatingVideo's viewer lease is ephemeral=true → excluded → its path
#      reaped within ≤10s → browser buffers then 404s. The CloudTAK API
#      (api/routes/video-lease.ts) filters `(${ephemeral}::BOOLEAN IS NULL OR ephemeral
#      = ${ephemeral})` and AllBoolean.ALL='all' casts to NULL → returns ALL leases;
#      impersonate=true sets the username filter to NULL so it does NOT exclude them.
#      So flipping the reaper's query `'ephemeral','false'` → `'ephemeral','all'` keeps
#      ACTIVE viewer paths while still reaping genuinely-closed ones (FloatingVideo
#      deletes its lease on close) — fleet-safe, no orphaned-RTSP leak. (The PLAN's
#      earlier "just drop ephemeral=false" failed because the param is a REQUIRED enum;
#      'all' is the right token.) Field-validated 2026-06-07: viewer-open path held
#      across 4+ reap cycles, viewer-close path reaped within ~10s.
#
#  (D) /lib/payload.ts — SRT streamid fix. ATAK UAS Tool emits a CoT video URL like
#      `srt://host:8890?streamid=#!::m=request,r=uas1`. CloudTAK URL-DECODES it, so the
#      lease/source carries a bare `#`. MediaMTX (Go net/url) treats `#` as a fragment
#      and drops the streamid → caller dials with no streamid → REJECT. ffmpeg/libsrt
#      handle `#` (that's why a direct view works), but MediaMTX's gosrt does not. Fix:
#      in createPayload, percent-encode `#`→`%23` for srt:// sources only — MediaMTX
#      decodes it back for the handshake. MUST live here (downstream of CloudTAK's
#      decode, upstream of the gosrt parse); encoding it in the CoT gets undone.
#      Field-validated 2026-06-07 (A/B: raw `#` REJECT, `%23` came online → HLS).
#
# All three live in cloudtak-media; the container runs the .ts files directly so an edit
# + restart takes effect. persist.ts / payload.ts may be absent on other media-infra
# builds → treated as not-applicable, never an error. Drift only happens on a container
# RECREATE (every edit survives a plain `docker restart`). The converger is
# check-before-apply → a no-op (no restart, no video drop) on an already-correct box.
_CT_MEDIA_CHECK_SH = r'''
if [ "$(yq -r '.hlsVariant' /mediamtx.yml 2>/dev/null)" = mpegts ] \
 && [ "$(yq -r '.hlsAlwaysRemux' /mediamtx.yml 2>/dev/null)" = false ] \
 && [ "$(yq -r '.hlsSegmentCount' /mediamtx.yml 2>/dev/null)" = 3 ] \
 && [ "$(yq -r '.hlsSegmentDuration' /mediamtx.yml 2>/dev/null)" = 500ms ] \
 && [ "$(yq -r '.hlsPartDuration' /mediamtx.yml 2>/dev/null)" = 200ms ]; then H=ok; else H=drift; fi
if [ ! -f /lib/persist.ts ]; then R=na
elif grep -qF "'ephemeral', 'all'" /lib/persist.ts; then R=ok
else R=drift; fi
if [ ! -f /lib/payload.ts ]; then P=na
elif grep -qF "replace(/#/g, '%23')" /lib/payload.ts; then P=ok
else P=drift; fi
printf '%s %s %s\n' "$H" "$R" "$P"
'''
_CT_MEDIA_APPLY_SH = r'''
yq -i '.hlsVariant = "mpegts" | .hlsAlwaysRemux = false | .hlsSegmentCount = 3 | .hlsSegmentDuration = "500ms" | .hlsPartDuration = "200ms"' /mediamtx.yml
if [ -f /lib/persist.ts ]; then
  sed -i "s/'ephemeral', 'false'/'ephemeral', 'all'/g" /lib/persist.ts
fi
if [ -f /lib/payload.ts ]; then
  sed -i "s|source: path.proxy,|source: path.proxy.startsWith('srt://') ? path.proxy.replace(/#/g, '%23') : path.proxy,|" /lib/payload.ts
fi
'''


def _ct_media_converged(check_out):
    """True iff the container check shows the HLS profile set, the reaper ephemeral-aware,
    and the SRT streamid encode present (persist.ts / payload.ts absent = not-applicable)."""
    p = (check_out or '').split()
    return len(p) >= 3 and p[0] == 'ok' and p[1] in ('ok', 'na') and p[2] in ('ok', 'na')


def _cloudtak_media_hls_heal(plog=None, remote_cfg=None, wait=False):
    """v0.9.48: self-heal the CloudTAK embedded MediaMTX (cloudtak-media) — CONVERGENCE,
    not an event handler. Reads the live container state first and only patches
    /mediamtx.yml (HLS profile), /lib/persist.ts (ephemeral-aware reaper), and
    /lib/payload.ts (SRT streamid #→%23 encode), then restarts the container, when a
    value has actually drifted — so a correctly-configured box is a no-op (no needless
    restart, no video drop). Heals all three files in one restart. See _CT_MEDIA_*_SH
    above for the what/why.

    Drift source: a container RECREATE (CloudTAK update, operator `docker compose up`,
    daemon restart) reverts the files to the image default; they survive a plain
    `docker restart`. This converger is the source of truth — it runs at console
    startup (Guard-Dog-independent) and right after every infra-TAK recreate for
    immediate convergence instead of waiting for the next boot.

    `wait=True` retries container resolution for ~10s (use right after `up -d`).
    Returns True if converged (already-correct or healed), False on error/no container.
    """
    def _log(m):
        (plog or (lambda x: print(x, flush=True)))(m)
    tries = 10 if wait else 1
    try:
        if remote_cfg:
            import base64
            chk_b64 = base64.b64encode(_CT_MEDIA_CHECK_SH.encode()).decode()
            apply_b64 = base64.b64encode(_CT_MEDIA_APPLY_SH.encode()).decode()
            # base64 strings are quoting-safe; decode on the remote host and pipe into
            # the container's sh via stdin (`docker exec -i`).
            cmd = (
                "for i in $(seq 1 %d); do "
                "m=$(docker ps --filter name=cloudtak-media --format '{{.Names}}' | head -n1); "
                "[ -n \"$m\" ] && break; sleep 1; done; "
                "if [ -z \"$m\" ]; then echo NOCONTAINER; exit 0; fi; "
                "out=$(echo %s | base64 -d | docker exec -i \"$m\" sh 2>/dev/null); "
                "set -- $out; "
                "if [ \"$1\" = mpegts ] && [ \"$2\" = true ] && { [ \"$3\" = ok ] || [ \"$3\" = na ]; }; then echo OK; exit 0; fi; "
                "echo %s | base64 -d | docker exec -i \"$m\" sh && docker restart \"$m\" >/dev/null && echo HEALED || echo FAIL"
            ) % (tries, chk_b64, apply_b64)
            ok, out = _ssh_probe(remote_cfg, cmd, timeout=120)
            out = (out or '').strip()
            if ok and 'HEALED' in out:
                _log("  ✓ Remote cloudtak-media healed (HLS=mpegts/alwaysRemux + reaper ephemeral-aware)")
                return True
            if ok and 'OK' in out:
                return True  # already converged — silent
            _log(f"  ⚠ Remote cloudtak-media heal skipped: {(out or 'no cloudtak-media container')[:160]}")
            return False
        # Local: resolve the cloudtak-media container (compose suffixes it, e.g. -1).
        media = None
        for _ in range(tries):
            r = subprocess.run(
                _sudo_wrap(['docker', 'ps', '--filter', 'name=cloudtak-media', '--format', '{{.Names}}']), capture_output=True, text=True, timeout=15)
            names = [n for n in (r.stdout or '').split() if n.strip()]
            if names:
                media = names[0]
                break
            time.sleep(1)
        if not media:
            return False  # CloudTAK media not up — nothing to heal (silent on the no-wait path)
        cur = subprocess.run(
            _sudo_wrap(['docker', 'exec', '-i', media, 'sh']),
            input=_CT_MEDIA_CHECK_SH, capture_output=True, text=True, timeout=25)
        if _ct_media_converged(cur.stdout):
            return True  # already converged — no restart
        ap = subprocess.run(
            _sudo_wrap(['docker', 'exec', '-i', media, 'sh']),
            input=_CT_MEDIA_APPLY_SH, capture_output=True, text=True, timeout=40)
        if ap.returncode != 0:
            _log(f"  ⚠ cloudtak-media heal apply failed: {(ap.stderr or ap.stdout or '').strip()[:200]}")
            return False
        subprocess.run(_sudo_wrap(['docker', 'restart', media]), capture_output=True, text=True, timeout=60)
        _log("  ✓ cloudtak-media healed (HLS=mpegts/alwaysRemux + reaper ephemeral-aware)")
        return True
    except Exception as e:
        _log(f"  ⚠ cloudtak-media heal error (non-fatal): {e}")
        return False


def _compose_cmd(remote_cfg=None):
    """Return the working Docker Compose invocation ('docker compose' or
    'docker-compose'), preferring v2, or None if neither is present.

    Probe ONCE and run only the available binary. The old pattern — try
    `docker compose`, then on ANY non-zero fall back to `docker-compose` — masks the
    real failure of the v2 command with a bogus `docker-compose: not found` on
    Compose-v2-only boxes (the exact symptom that hid a real CloudTAK build error on
    test12). Detecting up front means the genuine error surfaces."""
    if remote_cfg:
        ok, _ = _ssh_probe(remote_cfg, 'docker compose version >/dev/null 2>&1 && echo OK', timeout=20)
        if ok:
            return 'docker compose'
        ok, _ = _ssh_probe(remote_cfg, 'docker-compose version >/dev/null 2>&1 && echo OK', timeout=20)
        return 'docker-compose' if ok else None
    if subprocess.run(_sudo_wrap(['docker', 'compose', 'version']), capture_output=True, timeout=20).returncode == 0:
        return 'docker compose'
    if subprocess.run('docker-compose version', shell=True, capture_output=True, timeout=20).returncode == 0:
        return 'docker-compose'
    return None


def _patch_cloudtak_compose_ports(cloudtak_dir=None):
    """Patch port bindings in CloudTAK compose.yaml / docker-compose.yml.

    Applies loopback-only restrictions to Tier-3 (Caddy-facing) services and
    removes host-port bindings for Tier-4 (Docker-internal-only) services.
    Must be called after every deployment or git pull that may reset upstream
    0.0.0.0 bindings.

    Idempotent — patterns already containing '127.0.0.1:' are not re-matched.
    Returns True if the file was modified.

    Corruption recovery: if the file contains the v0.9.12 bad-backref
    signature (`ports:J7.0.0.1`), restore from git first, then patch.

    IMPORTANT: backrefs use \\g<N> syntax (NOT \\N) because `r'\\1127.0.0.1...'`
    is parsed by Python's re engine as octal \\112 (= 'J') + '7.0.0.1...',
    corrupting every file it touched. `\\g<1>127.0.0.1` is unambiguous.

    Port policy (matches docs/PORT-EXPOSURE-POLICY.md):
      api 5000        Tier 3 → 127.0.0.1:5000:5000
      tiles 5002      Tier 3 → 127.0.0.1:5002:5002
      events 5003     Tier 4 → removed (Docker-internal only)
      media 9997      Tier 3 → 127.0.0.1:9997:9997 (HLS admin)
      media 8888 HLS  Tier 3 → 127.0.0.1:PORT:8888 (via MEDIA_PORT_HLS)
      media RTSP/RTMP/SRT  Tier 1 → untouched (public streaming)
      postgis 5433    Tier 4 → removed
      store 9000      Tier 4 → removed
      store 9002      Tier 3 → 127.0.0.1:9002:9002
    """
    import re as _re
    if cloudtak_dir is None:
        cloudtak_dir = os.path.expanduser('~/CloudTAK')
    changed = False
    for _fname in ('compose.yaml', 'docker-compose.yml'):
        _path = os.path.join(cloudtak_dir, _fname)
        if not os.path.exists(_path):
            continue
        try:
            # Corruption recovery from the v0.9.12 bad-backref bug
            with open(_path) as f:
                _pre = f.read()
            if 'ports:J' in _pre or 'J7.0.0.1' in _pre:
                try:
                    subprocess.run(
                        f'cd {shlex.quote(cloudtak_dir)} && '
                        f'git -c safe.directory={shlex.quote(cloudtak_dir)} checkout -- {shlex.quote(_fname)}',
                        shell=True, capture_output=True, timeout=10
                    )
                except Exception:
                    pass

            with open(_path) as f:
                _ct = f.read()
            _orig = _ct

            # Tier 3: api 5000 → loopback (idempotent: won't match 127.0.0.1:5000)
            _ct = _re.sub(r'(\s+- )"?5000:5000"?', r'\g<1>"127.0.0.1:5000:5000"', _ct)

            # Tier 3: tiles 5002 → loopback
            _ct = _re.sub(r'(\s+- )"?5002:5002"?', r'\g<1>"127.0.0.1:5002:5002"', _ct)

            # Tier 4: events 5003 — remove the ports block entirely
            _ct = _re.sub(
                r'\n([ \t]+)ports:[ \t]*\n\1[ \t]+- "?5003:5003"?',
                '', _ct
            )

            # Tier 3: media API port (${MEDIA_PORT_API:-9997}:9997) → loopback
            _ct = _re.sub(
                r'(\s+- ")(\$\{MEDIA_PORT_API:-\d+\}:9997")',
                r'\g<1>127.0.0.1:\g<2>',
                _ct
            )

            # Tier 3: media HLS port (*:8888) → loopback (update default to 18888)
            _ct = _re.sub(
                r'(\s+- ")(\$\{MEDIA_PORT_HLS:-)\d+(\}:8888")',
                r'\g<1>127.0.0.1:\g<2>18888\g<3>',
                _ct
            )

            # Tier 4: postgis 5433 — remove the ports block entirely
            _ct = _re.sub(
                r'\n([ \t]+)ports:[ \t]*\n\1[ \t]+- "?5433:5432"?',
                '', _ct
            )

            # Tier 4: store 9000 — remove the line only (9002 stays in the block)
            _ct = _re.sub(r'\n[ \t]+- "?9000:9000"?', '', _ct)

            # Tier 3: store 9002 → loopback
            _ct = _re.sub(r'(\s+- )"?9002:9002"?', r'\g<1>"127.0.0.1:9002:9002"', _ct)

            # v10.0.1 (arm64 only): upstream pins postgis/postgis:<tag>, which is
            # amd64-only (no arm64 manifest) → the container crash-loops with
            # "exec format error" on aarch64, taking the api/migrations down with it.
            # imresamu/postgis mirrors the SAME tag scheme with an arm64 build added,
            # so swap only the registry/namespace and keep CloudTAK's exact PG/PostGIS
            # tag. No-op on amd64 (the validated path is byte-identical). Lives here so
            # it is re-applied after every clone/git-checkout, like the port patches.
            if _host_arch() == 'arm64':
                _ct = _re.sub(r'(image:\s*)postgis/postgis:', r'\g<1>imresamu/postgis:', _ct)
                # tiles (pmtiles) won't run on arm64: its @mapbox/vtquery@0.6.0
                # native addon has no arm64 build and only compiles via the
                # deprecated mason toolchain (amd64-only C++ deps). Stop the
                # crash-loop — restart 'always' → 'no' so it exits once and stays
                # quiet. pmtiles generation is unavailable on arm64 (non-core; the
                # map + all other CloudTAK features work). Targets the tiles
                # service uniquely via its dockerfile path.
                _ct = _re.sub(
                    r"(dockerfile:\s*\./tasks/pmtiles/Dockerfile\.compose\s*\n\s*restart:\s*)'?always'?",
                    r"\g<1>'no'", _ct, count=1)

            if _ct != _orig:
                with open(_path, 'w') as f:
                    f.write(_ct)
                changed = True
        except Exception:
            pass
        break  # only patch the first matching file
    return changed


def _cloudtak_build_arm64_media(cloudtak_dir=None, plog=None):
    """arm64 only: build media-infra from source and tag it as the exact image
    CloudTAK's compose pins, so `docker compose up` uses the local arm64 build
    instead of pulling the amd64-only ghcr.io/dfpc-coe/media-infra:<tag> (which
    crash-loops with "exec format error" on aarch64).

    media-infra's bases (golang:*-alpine, bluenviron/mediamtx:*-ffmpeg) are
    multi-arch and it compiles its Go server from source, so it builds natively
    on arm64 — dfpc-coe just never publishes an arm64 image. Compose has no
    pull_policy (default 'missing'), so a locally-present tag shadows the pull.

    No-op on amd64 (returns False; the published image is used unchanged).
    Non-fatal: a failure WARNs and returns False — the deploy continues (media is
    a non-core video proxy; core CloudTAK runs without it). The compose media
    ports are untouched (9997/HLS already loopback-bound), so this is port-safe.
    """
    if _host_arch() != 'arm64':
        return False
    import re as _re
    _log = plog or (lambda _m: None)
    if cloudtak_dir is None:
        cloudtak_dir = os.path.expanduser('~/CloudTAK')
    image_ref = None
    for _fname in ('compose.yaml', 'docker-compose.yml'):
        _p = os.path.join(cloudtak_dir, _fname)
        if not os.path.exists(_p):
            continue
        try:
            with open(_p) as f:
                _m = _re.search(r'image:\s*(ghcr\.io/dfpc-coe/media-infra:\S+)', f.read())
            if _m:
                image_ref = _m.group(1).strip().strip('"\'')
        except Exception:
            pass
        break
    if not image_ref:
        _log("  ⚠ arm64: media-infra image pin not found in compose — media may crash-loop")
        return False
    tag = image_ref.rsplit(':', 1)[-1]
    src_dir = os.path.join(cloudtak_dir, 'media-infra-src')
    _log(f"  arm64: building media-infra {tag} from source (no arm64 image is published)…")
    try:
        subprocess.run(f'rm -rf {shlex.quote(src_dir)}', shell=True, timeout=30)
        r = subprocess.run(
            f'git clone --depth 1 --branch {shlex.quote(tag)} '
            f'https://github.com/dfpc-coe/media-infra.git {shlex.quote(src_dir)}',
            shell=True, capture_output=True, text=True, timeout=180)
        if r.returncode != 0:
            _log(f"  ✗ media-infra clone failed (media will be unavailable): {(r.stderr or '')[:200]}")
            return False
        r = subprocess.run(
            _sudo_wrap(['docker', 'build', '-t', image_ref, src_dir]), capture_output=True, text=True, timeout=1800)
        if r.returncode != 0:
            _tail = '\n'.join((r.stdout or r.stderr or '').splitlines()[-8:])
            _log(f"  ✗ media-infra arm64 build failed (media will be unavailable):\n{_tail}")
            return False
        _log(f"  ✓ media-infra {tag} built for arm64 → tagged {image_ref} (local image shadows the amd64 pull)")
        return True
    except Exception as e:
        _log(f"  ✗ media-infra arm64 build error (media will be unavailable): {str(e)[:200]}")
        return False


def _cloudtak_fix_nginx_user(container_name='cloudtak-api-1', total_timeout=180, ssh_cfg=None):
    """Patch nginx.conf user directive from 'nginx' to 'root' and reload workers.

    The CloudTAK container image generates 'user nginx;' in nginx.conf via nginx.conf.js,
    but workers crash immediately with exit code 2 because /dev/stdout and /dev/stderr
    are not writable after dropping root privileges. Patching to 'user root;' and
    reloading causes workers to spawn correctly.

    The container takes a variable amount of time to write nginx.conf via the
    entrypoint (nginx.conf.js generates it), so we poll until the file exists,
    apply the patch, reload, and verify a worker process has spawned. If
    `ssh_cfg` is provided, runs against a remote host via SSH; otherwise
    operates against local Docker.
    """
    def _exec(cmd):
        if ssh_cfg:
            return _ssh_probe(ssh_cfg, cmd, timeout=20)
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=20)
            return (r.returncode == 0), (r.stdout or '') + (r.stderr or '')
        except Exception as e:
            return False, str(e)

    deadline = time.time() + total_timeout
    sleep_s = 2
    patched = False
    while time.time() < deadline:
        ok, out = _exec(f'docker exec {container_name} test -f /etc/nginx/nginx.conf && echo READY')
        if ok and 'READY' in (out or ''):
            ok2, out2 = _exec(
                f'docker exec {container_name} sh -c "grep -q \\"^user root;\\" /etc/nginx/nginx.conf || sed -i \\"s/^user nginx;/user root;/\\" /etc/nginx/nginx.conf"'
            )
            _exec(f'docker exec {container_name} nginx -s reload 2>/dev/null || true')
            patched = True
            break
        time.sleep(sleep_s)
    if not patched:
        return False
    worker_deadline = time.time() + 30
    while time.time() < worker_deadline:
        ok, out = _exec(f'docker exec {container_name} sh -c "ps -o pid,user,args -A 2>/dev/null | grep \\"nginx: worker\\" | grep -v grep | wc -l"')
        try:
            n = int((out or '').strip().splitlines()[-1].strip()) if (out or '').strip() else 0
        except Exception:
            n = 0
        if n > 0:
            return True
        _exec(f'docker exec {container_name} nginx -s reload 2>/dev/null || true')
        time.sleep(2)
    return False


def _cloudtak_git_prep(cloudtak_dir, plog):
    """Make a CloudTAK checkout safe to git-reset under the non-root console.

    Two non-root hazards live in ~/CloudTAK and bite the deploy/update git ops:
      * A killed `git checkout` leaves a stale .git/index.lock that wedges every
        later git op ("Unable to create '.git/index.lock': File exists"). CloudTAK
        is ~18k tracked files, so on slower/SELinux boxes (RHEL) the index refresh
        can run long and get timeout-killed where a faster box (Ubuntu) finishes —
        a non-fleet-uniform failure. The .git tree is takwerx-owned, so we just
        unlink the stale lock.
      * `.docker-store/` is an UPSTREAM compose bind-mount (`- .docker-store:/data`,
        MinIO's live S3 data), which is ROOT-owned and NOT gitignored. Add it to
        .git/info/exclude so git status/checkout never tries to walk or touch a
        tree the non-root console can neither read into nor modify.
    Both writes land in the takwerx-owned .git, so plain file IO works non-root."""
    try:
        _lock = os.path.join(cloudtak_dir, '.git', 'index.lock')
        if os.path.exists(_lock):
            os.remove(_lock)
            plog("  cleared stale .git/index.lock")
    except Exception as e:
        plog(f"  ⚠ could not clear .git/index.lock: {e}")
    try:
        _excl = os.path.join(cloudtak_dir, '.git', 'info', 'exclude')
        _cur = ''
        if os.path.exists(_excl):
            with open(_excl) as _f:
                _cur = _f.read()
        if '.docker-store' not in _cur:
            os.makedirs(os.path.dirname(_excl), exist_ok=True)
            with open(_excl, 'a') as _f:
                _f.write('\n# TAKWERX: never track the root-owned MinIO bind-mount\n.docker-store/\n')
    except Exception:
        pass


def run_cloudtak_deploy(cfg=None):
    def plog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        cloudtak_deploy_log.append(entry)
        print(entry, flush=True)
    # Clear release tag cache so we fetch fresh "latest" from GitHub (avoid deploying an old tag)
    _cloudtak_release_cache['tag'] = None
    _cloudtak_release_cache['ts'] = 0
    try:
        settings = load_settings()
        cfg = cfg or _get_cloudtak_deployment_config(settings)
        cloudtak_dir = os.path.expanduser('~/CloudTAK')
        domain = settings.get('fqdn', '')
        target_mode = (cfg.get('target_mode') or 'local').strip().lower()

        if target_mode == 'remote':
            remote_cfg = cfg.get('remote', {})
            remote_host = (remote_cfg.get('host') or '').strip()
            if not remote_host:
                plog("✗ Remote host not set. Save CloudTAK target settings first.")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plog("━━━ Step 1/6: Checking remote SSH ━━━")
            ok, out = _ssh_probe(remote_cfg, 'echo REMOTE_OK', timeout=20)
            if not ok or 'REMOTE_OK' not in (out or ''):
                plog(f"✗ Cannot SSH to remote CloudTAK host: {(out or '')[:200]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plog(f"✓ SSH connected to {remote_host}")

            plog("")
            plog("━━━ Step 2/6: Ensuring Docker on remote ━━━")
            docker_cmd = (
                "if ! command -v docker >/dev/null 2>&1; then "
                "curl -fsSL https://get.docker.com | sh; "
                "fi; "
                "(sudo systemctl enable docker >/dev/null 2>&1 || systemctl enable docker >/dev/null 2>&1 || true); "
                "(sudo systemctl start docker >/dev/null 2>&1 || systemctl start docker >/dev/null 2>&1 || true); "
                "docker --version"
            )
            ok, out = _ssh_probe(remote_cfg, docker_cmd, timeout=420)
            if not ok:
                plog(f"✗ Docker setup failed on remote: {(out or '')[:220]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plog(f"✓ {((out or '').splitlines()[-1] if out else 'Docker ready')}")

            plog("")
            plog("━━━ Docker log limits (remote) ━━━")
            _ensure_docker_log_limits_remote(remote_cfg, log_fn=plog)

            plog("")
            plog("━━━ Step 3/6: Cloning/Updating CloudTAK on remote ━━━")
            remote_release_tag = _get_cloudtak_latest_release_tag(use_cache=False)
            if remote_release_tag:
                plog(f"  Target: stable release {remote_release_tag}")
                prep_cmd = (
                    f"rm -rf ~/CloudTAK && git clone --depth 1 --branch {remote_release_tag} https://github.com/dfpc-coe/CloudTAK.git ~/CloudTAK && "
                    "test -f ~/CloudTAK/docker-compose.yml -o -f ~/CloudTAK/compose.yaml"
                )
            else:
                plog("  ⚠ Could not fetch latest release tag — using main branch")
                prep_cmd = (
                    "if [ -d ~/CloudTAK/.git ]; then "
                    "cd ~/CloudTAK && git pull --rebase --autostash; "
                    "else "
                    "rm -rf ~/CloudTAK && git clone --depth 1 https://github.com/dfpc-coe/CloudTAK.git ~/CloudTAK; "
                    "fi; "
                    "test -f ~/CloudTAK/docker-compose.yml -o -f ~/CloudTAK/compose.yaml"
                )
            ok, out = _ssh_probe(remote_cfg, prep_cmd, timeout=600)
            if not ok:
                plog(f"✗ CloudTAK repo prep failed on remote: {(out or '')[:220]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plog("✓ Remote repository ready")

            plog("")
            plog("━━━ Step 4/6: Writing CloudTAK config on remote ━━━")
            import secrets as _secrets
            signing_secret = _secrets.token_hex(32)
            minio_pass = _secrets.token_hex(16)
            postgres_pass = _secrets.token_hex(24)
            env_content = _cloudtak_build_env_content(settings, domain, signing_secret, minio_pass, postgres_pass=postgres_pass, remote_host=remote_host)
            override_yml = _cloudtak_build_override_yml(settings)
            tmp_dir = tempfile.mkdtemp(prefix='cloudtak-remote-')
            try:
                env_tmp = os.path.join(tmp_dir, '.env')
                ov_tmp = os.path.join(tmp_dir, 'docker-compose.override.yml')
                with open(env_tmp, 'w') as f:
                    f.write(env_content)
                with open(ov_tmp, 'w') as f:
                    f.write(override_yml)
                ok1, o1 = _scp_to_host(remote_cfg, env_tmp, '/tmp/.env')
                ok2, o2 = _scp_to_host(remote_cfg, ov_tmp, '/tmp/docker-compose.override.yml')
                if not ok1 or not ok2:
                    plog(f"✗ Could not copy CloudTAK config to remote: {((o1 or o2) or '')[:220]}")
                    cloudtak_deploy_status.update({'running': False, 'error': True})
                    return
                mv_cmd = (
                    "mv /tmp/.env ~/CloudTAK/.env && "
                    "mv /tmp/docker-compose.override.yml ~/CloudTAK/docker-compose.override.yml"
                )
                ok, out = _ssh_probe(remote_cfg, mv_cmd, timeout=40)
                if not ok:
                    plog(f"✗ Could not place remote config files: {(out or '')[:220]}")
                    cloudtak_deploy_status.update({'running': False, 'error': True})
                    return
            finally:
                shutil.rmtree(tmp_dir, ignore_errors=True)
            plog("✓ Remote .env and override written")

            plog("")
            plog("━━━ Step 5/6: Building/Starting remote containers ━━━")
            run_cmd = (
                "cd ~/CloudTAK && "
                "docker compose build --no-cache && "
                "docker compose up -d"
            )
            ok, out = _ssh_probe(remote_cfg, run_cmd, timeout=3600)
            if not ok:
                plog(f"✗ Remote build/start failed: {(out or '')[:220]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plog("✓ Containers built and restarted.")
            fw_cmd = (
                "sudo ufw allow 5000/tcp >/dev/null 2>&1 || true; "
                "sudo ufw allow 5002/tcp >/dev/null 2>&1 || true; "
                "command -v firewall-cmd >/dev/null 2>&1 && "
                "(sudo firewall-cmd --permanent --add-port=5000/tcp >/dev/null 2>&1 || true); "
                "command -v firewall-cmd >/dev/null 2>&1 && "
                "(sudo firewall-cmd --permanent --add-port=5002/tcp >/dev/null 2>&1 || true); "
                "command -v firewall-cmd >/dev/null 2>&1 && (sudo firewall-cmd --reload >/dev/null 2>&1 || true)"
            )
            _ssh_probe(remote_cfg, fw_cmd, timeout=40)
            # Probe /api/server (returns 200 even on unconfigured installs — see Step 6 comment).
            # /api/connections is auth-gated and not a reliable readiness signal on a fresh install.
            ready_cmd = (
                "python3 - <<'PY'\n"
                "import urllib.request,sys,time\n"
                "ok=False\n"
                "for _ in range(120):\n"
                "  try:\n"
                "    r=urllib.request.urlopen('http://127.0.0.1:5000/api/server', timeout=15)\n"
                "    if r.getcode() < 500: ok=True; break\n"
                "  except urllib.error.HTTPError as e:\n"
                "    if e.code < 500: ok=True; break\n"
                "  except Exception:\n"
                "    pass\n"
                "  time.sleep(2)\n"
                "print('READY' if ok else 'NOT_READY')\n"
                "sys.exit(0 if ok else 1)\n"
                "PY"
            )
            ok, out = _ssh_probe(remote_cfg, ready_cmd, timeout=270)
            if ok and 'READY' in (out or ''):
                plog("✓ Remote CloudTAK API is responding")
            else:
                plog("⚠ Remote CloudTAK API did not confirm readiness in time; continuing — Caddy is wired so URL will work as soon as Node finishes warming up")

            plog("")
            plog("━━━ Step 6/6: Updating Caddy ━━━")
            if domain:
                generate_caddyfile(settings)
                r = subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=15)
                if r.returncode == 0:
                    plog(f"✓ Caddy updated — map.{domain} routed to remote CloudTAK")
                else:
                    plog(f"⚠ Caddy reload issue: {(r.stderr or r.stdout or '').strip()[:140]}")
            else:
                plog("⚠ No FQDN configured. Use remote direct URL on port 5000.")
            cfg['deployed'] = True
            settings['cloudtak_deployment'] = _normalize_cloudtak_deployment_config(cfg)
            save_settings(settings)
            # v0.9.48 (Part B+C/D): self-heal cloudtak-media (HLS config + ephemeral-aware reaper) on the remote.
            _cloudtak_media_hls_heal(plog=plog, remote_cfg=remote_cfg, wait=True)
            plog("✓ CloudTAK remote deployment complete")
            plog("Deploy finished — CloudTAK is running.")
            cloudtak_deploy_status.update({'running': False, 'complete': True, 'error': False})
            return

        # Step 1: Check Docker
        plog("━━━ Step 1/7: Checking Docker ━━━")
        r = subprocess.run(_sudo_wrap(['docker', '--version']), capture_output=True, text=True)
        if r.returncode != 0:
            plog("  Docker not found — installing...")
            subprocess.run(_docker_install_cmd(), shell=True, capture_output=True, text=True, timeout=300)
            r2 = subprocess.run(_sudo_wrap(['docker', '--version']), capture_output=True, text=True)
            if r2.returncode != 0:
                plog("✗ Failed to install Docker")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plog(f"  {r2.stdout.strip()}")
        else:
            plog(f"  {r.stdout.strip()}")
        plog("✓ Docker available")

        _ensure_docker_log_limits(plog)

        # Step 2: Clone or update repo
        plog("")
        plog("━━━ Step 2/7: Cloning CloudTAK ━━━")
        release_tag = _get_cloudtak_latest_release_tag(use_cache=False)
        if os.path.exists(cloudtak_dir):
            # A real checkout needs a VALID repo, not merely a .git directory — a deleted or
            # interrupted CloudTAK can leave a HOLLOW .git (objects/ + info/ but no HEAD/config),
            # which os.path.isdir('.git') wrongly accepts, sending us down the in-place-update
            # path that then dies "fatal: not a git repository". Ask git, not the filesystem.
            _isrepo = subprocess.run(
                f'git -C {cloudtak_dir} -c safe.directory={cloudtak_dir} rev-parse --is-inside-work-tree 2>/dev/null',
                shell=True, capture_output=True, text=True).stdout.strip() == 'true'
            if _isrepo:
                # In-place update — NEVER rm -rf a CloudTAK tree: it holds
                # .docker-store/ (the upstream `- .docker-store:/data` MinIO
                # bind-mount), which is LIVE data, root-owned, and undeletable by the
                # non-root console — that exact rm -rf failure ("destination path
                # already exists and is not an empty directory") is what broke arm
                # deploy. Reset to the target tag IN PLACE, preserving
                # .docker-store / .env / docker-compose.override.yml (all untracked).
                plog(f"  ~/CloudTAK exists — updating in place to {release_tag or 'latest'} (preserving data)...")
                _cloudtak_git_prep(cloudtak_dir, plog)
                if release_tag:
                    r = subprocess.run(
                        f'cd {cloudtak_dir} && '
                        f'git -c safe.directory={cloudtak_dir} fetch --depth 1 origin tag {release_tag} && '
                        f'git -c safe.directory={cloudtak_dir} checkout -f {release_tag}',
                        shell=True, capture_output=True, text=True, timeout=300)
                else:
                    r = subprocess.run(
                        f'cd {cloudtak_dir} && '
                        f'git -c safe.directory={cloudtak_dir} reset --hard && '
                        f'git -c safe.directory={cloudtak_dir} pull',
                        shell=True, capture_output=True, text=True, timeout=300)
                if r.returncode != 0:
                    plog(f"✗ In-place update failed: {(r.stderr or r.stdout or '').strip()[:200]}")
                    cloudtak_deploy_status.update({'running': False, 'error': True})
                    return
            else:
                # Dir exists but has NO valid git checkout (hollow/partial .git from an
                # interrupted clone or a delete that left a stub). Don't rm the whole tree — it
                # may hold .docker-store MinIO data. REPAIR the checkout IN PLACE: drop only the
                # broken .git, re-init, fetch the target tag, checkout -f. Tracked source is
                # restored; untracked .docker-store / .env / docker-compose.override.yml are left
                # untouched. If the tree is root-owned (can't rm .git) the git ops fail and we
                # surface an actionable message rather than the cryptic clone/update error.
                plog(f"  ~/CloudTAK has no valid git checkout — repairing in place to {release_tag or 'latest'} (preserving data)...")
                if release_tag:
                    _fetchco = (f'git -c safe.directory={cloudtak_dir} fetch --depth 1 origin tag {release_tag} && '
                                f'git -c safe.directory={cloudtak_dir} checkout -f {release_tag}')
                else:
                    _fetchco = (f'git -c safe.directory={cloudtak_dir} fetch --depth 1 origin HEAD && '
                                f'git -c safe.directory={cloudtak_dir} checkout -f FETCH_HEAD')
                # Drop the broken .git via the BROKER — a root-era hollow .git has root-owned
                # objects (e.g. .git/objects/42/…), which a plain (takwerx) `rm -rf .git` can't
                # remove ("Permission denied"). The broker rm runs as root. .docker-store and the
                # rest of the tree stay untouched (git init + checkout -f run as takwerx after).
                _grm = subprocess.run(_sudo_wrap(['rm', '-rf', os.path.join(cloudtak_dir, '.git')]),
                                      capture_output=True, text=True, timeout=120)
                if os.path.exists(os.path.join(cloudtak_dir, '.git')):
                    plog(f"✗ In-place repair failed: could not remove {cloudtak_dir}/.git "
                         f"({(_grm.stderr or _grm.stdout or 'broker rm failed').strip()[:160]})")
                    cloudtak_deploy_status.update({'running': False, 'error': True})
                    return
                r = subprocess.run(
                    f'cd {cloudtak_dir} && git init -q && '
                    f'git remote add origin https://github.com/dfpc-coe/CloudTAK.git && ' + _fetchco,
                    shell=True, capture_output=True, text=True, timeout=600)
                if r.returncode != 0:
                    plog(f"✗ In-place repair failed: {(r.stderr or r.stdout or '').strip()[:200]}")
                    plog(f"  If {cloudtak_dir} holds root-owned data, a root operator must clear it, then redeploy.")
                    cloudtak_deploy_status.update({'running': False, 'error': True})
                    return
                _cloudtak_git_prep(cloudtak_dir, plog)
        else:
            release_tag = _get_cloudtak_latest_release_tag(use_cache=False)
            tag_label = release_tag or 'main (latest release tag unavailable)'
            plog(f"  Cloning from GitHub (shallow, {tag_label})...")
            clone_timeout = 600  # 10 min — VPS→GitHub can be slow
            branch_flag = f' --branch {release_tag}' if release_tag else ''
            clone_cmd = f'git clone --depth 1{branch_flag} https://github.com/dfpc-coe/CloudTAK.git {cloudtak_dir}'
            for attempt in range(2):
                try:
                    r = subprocess.run(clone_cmd, shell=True, capture_output=True, text=True, timeout=clone_timeout)
                    if r.returncode == 0:
                        break
                    plog(f"✗ Clone failed: {r.stderr.strip()[:200]}")
                    if attempt == 0:
                        plog("  Retrying once...")
                        subprocess.run(f'rm -rf {cloudtak_dir}', shell=True, capture_output=True, timeout=30)
                except subprocess.TimeoutExpired:
                    plog(f"✗ Clone timed out after {clone_timeout}s")
                    if attempt == 0:
                        plog("  Retrying once (slow network to GitHub is common)...")
                        subprocess.run(f'rm -rf {cloudtak_dir}', shell=True, capture_output=True, timeout=30)
                    else:
                        cloudtak_deploy_status.update({'running': False, 'error': True})
                        return
            if not os.path.exists(os.path.join(cloudtak_dir, '.git')):
                plog("✗ Clone failed after retry")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
        plog("✓ Repository ready")
        # Log version on disk so we can confirm clone got the right tag (vs UI showing something else)
        for _pkg in ['api/package.json', 'web/package.json', 'package.json']:
            _p = os.path.join(cloudtak_dir, _pkg)
            if os.path.isfile(_p):
                try:
                    with open(_p) as _f:
                        _v = (json.load(_f).get('version') or '').strip()
                    if _v:
                        plog(f"  Version on disk ({_pkg}): {_v}")
                        break
                except Exception:
                    pass

        # Ensure compose file exists (fix partial/bad clone)
        compose_yml = os.path.join(cloudtak_dir, 'docker-compose.yml')
        compose_yaml = os.path.join(cloudtak_dir, 'compose.yaml')
        if not os.path.exists(compose_yml) and not os.path.exists(compose_yaml):
            plog("  docker-compose.yml missing — re-cloning...")
            subprocess.run(f'rm -rf {cloudtak_dir}', shell=True, capture_output=True, timeout=30)
            _rclone_tag = release_tag if 'release_tag' in dir() else _get_cloudtak_latest_release_tag()
            _rclone_branch = f' --branch {_rclone_tag}' if _rclone_tag else ''
            r = subprocess.run(f'git clone --depth 1{_rclone_branch} https://github.com/dfpc-coe/CloudTAK.git {cloudtak_dir}', shell=True, capture_output=True, text=True, timeout=600)
            if r.returncode != 0:
                plog(f"✗ Re-clone failed: {r.stderr.strip()[:200]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            compose_yml = os.path.join(cloudtak_dir, 'docker-compose.yml')
            compose_yaml = os.path.join(cloudtak_dir, 'compose.yaml')
        if not os.path.exists(compose_yml):
            compose_yml = compose_yaml if os.path.exists(compose_yaml) else os.path.join(cloudtak_dir, 'docker-compose.yml')
        if not os.path.exists(compose_yml):
            plog(f"✗ No compose file found in {cloudtak_dir}")
            cloudtak_deploy_status.update({'running': False, 'error': True})
            return

        # Step 3: Generate .env and docker-compose.override.yml
        plog("")
        plog("━━━ Step 3/7: Configuring .env ━━━")
        env_path = os.path.join(cloudtak_dir, '.env')
        import secrets as _secrets
        signing_secret = _secrets.token_hex(32)
        minio_pass = _secrets.token_hex(16)
        postgres_pass = _secrets.token_hex(24)

        env_content = _cloudtak_build_env_content(settings, domain, signing_secret, minio_pass, postgres_pass=postgres_pass)
        with open(env_path, 'w') as f:
            f.write(env_content)
        try:
            _pwfile = os.path.join(cloudtak_dir, '.postgres-password')
            with open(_pwfile, 'w') as _pf:
                _pf.write(postgres_pass + '\n')
            os.chmod(_pwfile, 0o600)
            plog(f"  postgis password saved to {_pwfile} (chmod 600)")
        except Exception as _pwe:
            plog(f"  WARNING: could not save .postgres-password: {_pwe}")

        # So the API container can reach the host (e.g. TAKWERX Console / Marti at :5001)
        override_path = os.path.join(cloudtak_dir, 'docker-compose.override.yml')
        override_yml = _cloudtak_build_override_yml(settings)
        with open(override_path, 'w') as f:
            f.write(override_yml)
        plog("  docker-compose.override.yml written (api → host.docker.internal for :5001)")

        # v0.9.56: harden base-compose port bindings BEFORE `up -d`. The Step-2 clone pulls
        # upstream CloudTAK, whose base compose republishes every port on 0.0.0.0 — incl. media
        # "${MEDIA_PORT_API:-9997}:9997". Since v0.9.48 Caddy binds <localIP>:9997 for the CloudTAK
        # video vhost, so a wildcard 0.0.0.0:9997 publish COLLIDES and the Caddy reload in Step 5/7
        # dies ("address already in use") → blank map.<fqdn>. Same patch the startup migration /
        # update auto-harden run; idempotent (skips 127.0.0.1:*-prefixed lines), so the later passes
        # are no-ops. Previously only ran on console startup/update, not deploy — a box deployed long
        # after the last console restart (CORAZ) stayed broken until hand-fixed.
        try:
            if _patch_cloudtak_compose_ports(cloudtak_dir):
                plog("  ✓ Compose port bindings hardened → loopback (media 9997, api 5000, tiles 5002, store 9002; events/postgis/store-9000 unpublished)")
        except Exception as _ppe:
            plog(f"  WARNING: compose port-harden failed (Caddy :9997 may collide): {_ppe}")

        # v10.0.1 (arm64 only): the media-infra image is amd64-only on ghcr; build it
        # from source on-box and tag it as the pinned image so `up` uses the arm64
        # build (no-op on amd64). Non-fatal — media is a non-core video proxy.
        try:
            _cloudtak_build_arm64_media(cloudtak_dir, plog=plog)
        except Exception as _me:
            plog(f"  WARNING: arm64 media-infra build step errored (media may be unavailable): {_me}")

        api_url = ''
        media_url = ''
        for _line in env_content.splitlines():
            if _line.startswith('API_URL='):
                api_url = _line.split('=', 1)[1].strip()
            elif _line.startswith('CLOUDTAK_Config_media_url='):
                media_url = _line.split('=', 1)[1].strip()
        plog(f"✓ .env written")
        if api_url:
            plog(f"  API URL: {api_url}")
        if media_url:
            plog(f"  Media URL: {media_url} (CloudTAK media container — port 9997 hardcoded in source)")

        # v10.0.1 arm64: CloudTAK's tiles task (tasks/pmtiles) builds FROM node:*-alpine
        # (musl libc), but its native dep @mapbox/vtquery has NO musl-arm64 prebuilt — the
        # glibc prebuilt it pulls fails to load at runtime ("__libc_single_threaded: symbol
        # not found"), crashing cloudtak-tiles on arm64. Swap the tiles base to a glibc
        # (Debian bookworm) Node image on arm64 so the prebuilt resolves. x86 stays on Alpine
        # (works there). Re-applied on every deploy so it survives a CloudTAK source refresh.
        try:
            if (os.uname().machine or '').lower() in ('aarch64', 'arm64'):
                _tiles_df = os.path.join(cloudtak_dir, 'tasks', 'pmtiles', 'Dockerfile.compose')
                if os.path.isfile(_tiles_df):
                    with open(_tiles_df) as _f:
                        _dfc = _f.read()
                    _newdf = re.sub(r'(?m)^FROM\s+node:([\w.\-]+)-alpine[\w.\-]*',
                                    r'FROM node:\1-bookworm-slim', _dfc, count=1)
                    if _newdf != _dfc:
                        with open(_tiles_df, 'w') as _f:
                            _f.write(_newdf)
                        plog("  arm64: patched tiles Dockerfile base alpine→bookworm-slim (glibc — fixes @mapbox/vtquery)")
        except Exception as _te:
            plog(f"  ⚠ tiles arm64 base patch skipped (non-fatal): {str(_te)[:100]}")

        # Step 4: Build Docker images (stream output, 45 min timeout)
        plog("")
        plog("━━━ Step 4/7: Building Docker Images ━━━")
        plog("  This may take 5-10 minutes on first run...")
        proc = subprocess.Popen(
            _sudo_wrap(['docker', 'compose', 'build', '--no-cache']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, cwd=cloudtak_dir, bufsize=1
        )
        def _read_build():
            for line in iter(proc.stdout.readline, ''):
                line = line.rstrip()
                if line:
                    plog(f"  {line}")
        reader = threading.Thread(target=_read_build, daemon=True)
        reader.start()
        try:
            proc.wait(timeout=2700)  # 45 min max
        except subprocess.TimeoutExpired:
            proc.kill()
            plog("✗ Docker build timed out after 45 minutes — try again or check server resources (RAM, disk)")
            cloudtak_deploy_status.update({'running': False, 'error': True})
            return
        reader.join(timeout=5)
        if proc.returncode != 0:
            plog(f"✗ Docker build failed")
            cloudtak_deploy_status.update({'running': False, 'error': True})
            return
        plog("✓ Images built")

        # Step 5: Start containers including media on remapped ports
        plog("")
        plog("━━━ Step 5/7: Starting Containers ━━━")
        plog("  Starting all containers including media (remapped ports)...")
        plog("  Standalone MediaMTX stays on original ports — no conflict")
        r = subprocess.run(
            _sudo_wrap(['docker', 'compose', 'up', '-d', '--force-recreate']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=600, cwd=cloudtak_dir
        )
        if r.returncode != 0:
            plog(f"✗ docker compose up failed")
            for line in r.stdout.strip().split('\n')[-10:]:
                if line.strip():
                    plog(f"  {line}")
            cloudtak_deploy_status.update({'running': False, 'error': True})
            return
        plog("✓ Containers started")
        plog("✓ Restart complete.")

        # Open port 5000 (and 5002 for tiles) so http://ip:5000 works when no domain or before Caddy is used.
        # 9997 (v0.9.48): Caddy fronts the CloudTAK video vhost on :9997 (CloudTAK hardcodes
        # that port for every media URL); allow it now so a fresh install works without
        # waiting for the next console-update _auto_harden_cloudtak() pass. The media
        # container still publishes 9997 on 127.0.0.1 only, so this exposes Caddy, not it.
        # Family-gated backend (see _fw_backend): the broker shims both ufw and
        # firewall-cmd onto the console PATH on every platform, so `which firewall-cmd`
        # mis-detects on Debian (and bare `ufw` errors on RHEL). Drive the firewall
        # through _fw_allow() instead of raw ufw + `which firewall-cmd`.
        for _p in (5000, 5002, 9997):
            _fw_allow(_p, 'tcp')
        plog("✓ Firewall: ports 5000 (Web UI), 5002 (tiles), 9997 (Caddy video) opened")

        # CloudTAK nginx proxies /api to 127.0.0.1:5001 (Node app in same container). Do NOT
        # replace that with host:5001 or /api would hit TAKWERX Console and the app would stay on "Loading CloudTAK".

        # Update Caddyfile NOW (before waiting for API) so the public URL is reachable
        # the moment CloudTAK comes up. Persist deployed=True first so detect_modules()
        # picks up cloudtak as installed even on retries.
        try:
            cfg['deployed'] = True
            settings['cloudtak_deployment'] = _normalize_cloudtak_deployment_config(cfg)
            save_settings(settings)
        except Exception as _e:
            plog(f"  ⚠ Could not persist deployment flag: {_e}")
        if domain:
            try:
                generate_caddyfile(settings)
                r_cd = subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=15)
                if r_cd.returncode == 0:
                    plog(f"✓ Caddy updated early — map.{domain} routed (will work as soon as API responds)")
                else:
                    plog(f"⚠ Caddy reload: {r_cd.stdout.strip()[:100]}")
            except Exception as _e:
                plog(f"⚠ Caddy update skipped: {_e}")

        # Step 6: Wait for API to be ready.
        #
        # On a fresh deploy the Node app inside cloudtak-api-1 has to:
        #   1. wait for postgis to accept connections,
        #   2. run Drizzle migrations against the gis db,
        #   3. seed iconsets/basemaps from /home/etl/api/dist/data,
        #   4. start serving on 127.0.0.1:5001 (which nginx proxies to :5000).
        #
        # On slow VPSes this takes 20–30 minutes the first time. We probe /api/server
        # because it returns 200 with no auth even when CloudTAK is in the
        # "unconfigured" state (verified empirically on 2026-05-10 — the response
        # is `{"status":"unconfigured", ...}`). /api/connections is auth-gated and
        # not a reliable readiness signal on a fresh install.
        #
        # Important: every loop iteration can take up to ~12s wall clock when
        # nginx returns 502 from a stuck upstream, so we MUST track real wall
        # clock — not `attempt * poll_interval` which lies by 5–6×.
        plog("")
        plog("━━━ Step 6/7: Waiting for CloudTAK API ━━━")
        plog("  Probing /api/server (returns 200 even on unconfigured installs)")
        import urllib.request as _urlreq
        import urllib.error as _urlerr
        api_ready = False
        max_wait_sec = 1800  # 30 minutes wall-clock — fresh-boot Postgres + Drizzle migrations on slow VPS can take 25 min
        poll_interval = 2
        start_ts = time.time()
        _last_diag_ts = [0.0]
        _last_status_ts = [0.0]
        diag_throttle = 60  # repeat a diagnostic line at most once per minute so we keep heartbeat
        def _check_url(url, name):
            # 15s per-request timeout: during Drizzle migrations Node can be
            # bound but slow to respond. 5s was too aggressive and produced
            # false TimeoutErrors against a healthy-but-warming backend.
            try:
                r = _urlreq.Request(url, method='GET')
                resp = _urlreq.urlopen(r, timeout=15)
                return resp.getcode(), None
            except _urlerr.HTTPError as e:
                return e.code, None
            except Exception as e:
                return None, f"{type(e).__name__}: {str(e)[:80]}"
        while True:
            elapsed = int(time.time() - start_ts)
            if elapsed >= max_wait_sec:
                break
            code, err = _check_url('http://127.0.0.1:5000/api/server', 'api/server')
            # Anything 2xx/3xx/4xx means Node is alive and responding (even 401/403/404 are fine —
            # nginx is up and Node returned a real HTTP response). Only 5xx and connection errors mean
            # not ready.
            if code is not None and code < 500:
                plog(f"✓ CloudTAK API is responding (GET /api/server → {code}) after {elapsed}s")
                api_ready = True
                break
            now_ts = time.time()
            if now_ts - _last_diag_ts[0] >= diag_throttle:
                _last_diag_ts[0] = now_ts
                if code is not None:
                    plog(f"  Backend returned {code} (Node app still starting at {elapsed}s) — we'll keep trying")
                elif err:
                    plog(f"  /api/server → {err} at {elapsed}s — Node not yet bound, waiting")
            elif elapsed > 0 and now_ts - _last_status_ts[0] >= 30:
                _last_status_ts[0] = now_ts
                plog(f"  ⏳ Waiting for backend... ({elapsed}s elapsed, max {max_wait_sec}s)")
            time.sleep(poll_interval)

        if not api_ready:
            # Caddy is already wired (Step 5 did it before this wait), so the public URL will
            # work the instant Node finishes its first-boot migration — even if that's after
            # we exit. Don't fail the deploy: the operator can hit the URL and it'll come up.
            plog("")
            plog(f"⚠ CloudTAK API did not respond within {max_wait_sec}s — but containers are running.")
            plog("  Postgres + Drizzle migrations on first boot can take 25+ min on slow VPS.")
            plog("  Caddy is already configured. The site will work as soon as Node finishes warming up.")
            plog("  Watch progress: docker logs -f cloudtak-api-1")
            if domain:
                plog(f"  Try: https://map.{domain}/ in a few minutes. If it shows the old version,")
                plog(f"  open DevTools (F12) → Application → Clear site data, then reload (a refresh won't help — SW cache).")
            # Fall through — do not return, do not mark error. Step 7 will reconfirm Caddy.
        else:
            plog("✓ CloudTAK API responded — proceeding to Caddy confirmation")

        # Step 7: Re-confirm Caddy (it was already updated earlier; this is a safety net).
        # Wrapped in its own try/except — a Caddyfile error must never flip error:True
        # on an otherwise successful deploy (CloudTAK containers are already running).
        plog("")
        plog("━━━ Step 7/7: Confirming Caddy ━━━")
        try:
            if domain:
                generate_caddyfile(settings)
                r = subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=30)
                if r.returncode == 0:
                    plog(f"✓ Caddy confirmed — map.{domain} and tiles.map.{domain} live")
                else:
                    plog(f"⚠ Caddy reload: {r.stdout.strip()[:100]}")
            else:
                plog("  No domain configured — skipping Caddy (access via port 5000)")
        except Exception as _caddy_e:
            plog(f"⚠ Caddy confirm skipped: {_caddy_e} (CloudTAK is still running)")

        # v0.9.48 (Part B+C/D): self-heal cloudtak-media (HLS config + ephemeral-aware
        # reaper) — a fresh install creates the container from the image default.
        _cloudtak_media_hls_heal(plog=plog, wait=True)

        plog("")
        plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
        if api_ready:
            ready_emoji = "🎉"
            ready_verb = "deployed"
        else:
            ready_emoji = "⏳"
            ready_verb = "deployed (still warming up — first-boot migrations in progress)"
        if domain:
            plog(f"{ready_emoji} CloudTAK {ready_verb}! Open https://map.{domain} in your browser")
            plog(f"   Tiles: https://tiles.map.{domain}")
            plog(f"   Video: https://video.{domain} (via standalone MediaMTX)")
        else:
            server_ip = settings.get('server_ip', 'your-server-ip')
            plog(f"{ready_emoji} CloudTAK {ready_verb}! Open http://{server_ip}:5000 in your browser")
        plog(f"   Log in and go to Admin → Connections to configure your TAK Server")
        plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
        if api_ready:
            plog("Deploy finished — CloudTAK is running and ready.")
        else:
            plog("Deploy finished — containers up. Node app may still be running first-boot migrations.")
            plog("  Watch progress: docker logs -f cloudtak-api-1")
            plog("  Once you see 'ok - http://localhost:5000' the URL above will work.")
        # cfg['deployed']=True already saved in early-Caddy step; keep settings consistent.
        _update_boot_stagger_service()
        cloudtak_deploy_status.update({'running': False, 'complete': True, 'error': False})

    except Exception as e:
        plog(f"✗ Unexpected error: {str(e)}")
        cloudtak_deploy_status.update({'running': False, 'error': True})

def run_cloudtak_redeploy(cfg=None):
    """Rewrite .env and override, restart stack, re-apply nginx patch. Reuses deploy log/status."""
    def plog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        cloudtak_deploy_log.append(entry)
        print(entry, flush=True)
    try:
        settings = load_settings()
        cfg = cfg or _get_cloudtak_deployment_config(settings)
        if cfg.get('target_mode') == 'remote':
            remote_cfg = cfg.get('remote', {})
            remote_host = (remote_cfg.get('host') or '').strip()
            if not remote_host:
                plog("✗ Remote host not configured")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plog(f"  Updating remote CloudTAK config on {remote_host}...")
            domain = (settings.get('fqdn') or '').strip() or None
            import secrets as _secrets
            signing_secret = _secrets.token_hex(32)
            minio_pass = _secrets.token_hex(16)
            # Preserve existing postgres password from remote .env so we don't break the
            # DB connection on an existing install. If the remote .env doesn't have one
            # (pre-v0.9.11), fall back to 'docker' (the upstream literal). New strong
            # passwords are only generated on first install or full Remove+Reinstall.
            postgres_pass = 'docker'
            try:
                _ok_pw, _pw_out = _ssh_probe(
                    remote_cfg,
                    "grep -E '^POSTGRES_PASSWORD=' ~/CloudTAK/.env 2>/dev/null | head -1 | cut -d= -f2-",
                    timeout=15
                )
                if _ok_pw and (_pw_out or '').strip():
                    postgres_pass = (_pw_out or '').strip()
                    plog("  Preserving existing postgis password from remote .env")
            except Exception:
                pass
            env_content = _cloudtak_build_env_content(settings, domain, signing_secret, minio_pass, postgres_pass=postgres_pass, remote_host=remote_host)
            override_yml = _cloudtak_build_override_yml(settings)
            tmp_dir = tempfile.mkdtemp(prefix='cloudtak-reremote-')
            try:
                env_tmp = os.path.join(tmp_dir, '.env')
                ov_tmp = os.path.join(tmp_dir, 'docker-compose.override.yml')
                with open(env_tmp, 'w') as f:
                    f.write(env_content)
                with open(ov_tmp, 'w') as f:
                    f.write(override_yml)
                ok1, o1 = _scp_to_host(remote_cfg, env_tmp, '/tmp/.env')
                ok2, o2 = _scp_to_host(remote_cfg, ov_tmp, '/tmp/docker-compose.override.yml')
                if not ok1 or not ok2:
                    plog(f"✗ Could not copy config to remote: {((o1 or o2) or '')[:200]}")
                    cloudtak_deploy_status.update({'running': False, 'error': True})
                    return
            finally:
                shutil.rmtree(tmp_dir, ignore_errors=True)
            cmd = (
                "mv /tmp/.env ~/CloudTAK/.env && "
                "mv /tmp/docker-compose.override.yml ~/CloudTAK/docker-compose.override.yml && "
                "cd ~/CloudTAK && docker compose up -d"
            )
            ok, out = _ssh_probe(remote_cfg, cmd, timeout=180)
            if not ok:
                plog(f"✗ Restart failed: {(out or '')[:200]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            if domain:
                generate_caddyfile(settings)
                try:
                    subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=45)
                    plog("✓ Caddy reloaded")
                except subprocess.TimeoutExpired:
                    plog("⚠ Caddy reload timed out — reload manually if needed")
            # v0.9.48 (Part B+C/D): re-apply cloudtak-media self-heal (HLS + reaper) on remote.
            _cloudtak_media_hls_heal(plog=plog, remote_cfg=remote_cfg, wait=True)
            plog("✓ Update config & restart done (remote)")
            cloudtak_deploy_status.update({'running': False, 'complete': True, 'error': False})
            return
        cloudtak_dir = os.path.expanduser('~/CloudTAK')
        compose_yml = os.path.join(cloudtak_dir, 'docker-compose.yml')
        if not os.path.exists(compose_yml):
            compose_yml = os.path.join(cloudtak_dir, 'compose.yaml')
        if not os.path.exists(compose_yml):
            plog("✗ CloudTAK not found (no compose file)")
            cloudtak_deploy_status.update({'running': False, 'error': True})
            return
        domain = (settings.get('fqdn') or '').strip() or None
        env_path = os.path.join(cloudtak_dir, '.env')
        signing_secret = None
        minio_pass = None
        postgres_pass = None
        if os.path.exists(env_path):
            with open(env_path) as f:
                for line in f:
                    line = line.strip()
                    if line.startswith('SigningSecret='):
                        signing_secret = line.split('=', 1)[1].strip()
                    elif line.startswith('MINIO_ROOT_PASSWORD='):
                        minio_pass = line.split('=', 1)[1].strip()
                    elif line.startswith('POSTGRES_PASSWORD='):
                        postgres_pass = line.split('=', 1)[1].strip()
        import secrets as _secrets
        if not signing_secret:
            signing_secret = _secrets.token_hex(32)
        if not minio_pass:
            minio_pass = _secrets.token_hex(16)
        # Preserve existing postgis password on reconfig so the DB connection keeps
        # working. Pre-v0.9.11 installs don't have POSTGRES_PASSWORD in .env — fall
        # back to 'docker' (the upstream literal that postgres already initialized
        # the volume with). Strong passwords only land on Remove + Reinstall.
        if not postgres_pass:
            postgres_pass = 'docker'
        env_content = _cloudtak_build_env_content(settings, domain, signing_secret, minio_pass, postgres_pass=postgres_pass)
        with open(env_path, 'w') as f:
            f.write(env_content)
        override_path = os.path.join(cloudtak_dir, 'docker-compose.override.yml')
        with open(override_path, 'w') as f:
            f.write(_cloudtak_build_override_yml(settings))
        plog("✓ .env and override written")
        plog("  Restarting containers...")
        dcc = _compose_cmd()
        if not dcc:
            plog("✗ Neither `docker compose` nor `docker-compose` is available")
            cloudtak_deploy_status.update({'running': False, 'error': True})
            return
        r = subprocess.run(
            f'{dcc} up -d --force-recreate 2>&1',
            shell=True, capture_output=True, text=True, timeout=180, cwd=cloudtak_dir
        )
        if r.returncode != 0:
            _tail = '\n'.join((r.stdout or r.stderr or 'unknown').strip().splitlines()[-20:])
            plog(f"✗ Restart failed (via `{dcc}`):\n{_tail}")
            cloudtak_deploy_status.update({'running': False, 'error': True})
            return
        plog("✓ Containers restarted")
        time.sleep(3)
        # Restore /api proxy to 127.0.0.1:5001 (Node in container) if a previous patch sent it to the host
        api_container = None
        for _ in range(15):
            r = subprocess.run(_sudo_wrap(['docker', 'compose', 'ps', '-q', 'api']), capture_output=True, text=True, timeout=5, cwd=cloudtak_dir)
            cid = (r.stdout or '').strip()
            if cid and len(cid) >= 8:
                api_container = cid
                break
            time.sleep(1)
        if api_container:
            for nf in ['/etc/nginx/nginx.conf', '/etc/nginx/conf.d/default.conf']:
                subprocess.run(_sudo_wrap(['docker', 'exec', api_container, 'sed', '-i', 's|proxy_pass http://[^;]*:5001|proxy_pass http://127.0.0.1:5001|g', nf]), capture_output=True, timeout=5)
                subprocess.run(_sudo_wrap(['docker', 'exec', api_container, 'sed', '-i', 's/^user nginx;/user root;/', nf]), capture_output=True, timeout=5)
            subprocess.run(_sudo_wrap(['docker', 'exec', api_container, 'nginx', '-s', 'reload']), capture_output=True, timeout=5)
            plog("  Nginx proxy and user directive patched, workers reloaded")
        plog("  Waiting for CloudTAK API to respond...")
        import urllib.request as _urlreq
        for attempt in range(45):
            try:
                _urlreq.urlopen('http://localhost:5000/', timeout=3)
                plog("✓ CloudTAK API is responding")
                break
            except Exception:
                if attempt % 5 == 0 and attempt > 0:
                    plog(f"  Still waiting... ({attempt * 2}s)")
                time.sleep(2)
        else:
            plog("⚠ API did not respond in time — if map.<domain> stays on 'Loading CloudTAK', check Container Logs and ensure the api container is running")
        if domain:
            generate_caddyfile(settings)
            try:
                subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=45)
                plog("✓ Caddy reloaded")
            except subprocess.TimeoutExpired:
                plog("⚠ Caddy reload timed out — reload it from the Caddy page if needed")
        # v0.9.48 (Part B+C/D): force-recreate above reverted cloudtak-media to the image
        # default — re-apply the self-heal (HLS config + ephemeral-aware reaper).
        _cloudtak_media_hls_heal(plog=plog, wait=True)
        plog("✓ Update config & restart done")
        cloudtak_deploy_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        plog(f"✗ Error: {str(e)}")
        cloudtak_deploy_status.update({'running': False, 'error': True})
    finally:
        cloudtak_deploy_status['running'] = False


def run_cloudtak_update():
    """Fetch latest stable release tag, checkout, rebuild images, restart. Preserves DB and config."""
    def plog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        cloudtak_deploy_log.append(entry)
        print(entry, flush=True)
    try:
        settings = load_settings()
        cfg = _get_cloudtak_deployment_config(settings)
        is_remote = cfg.get('target_mode') == 'remote'
        remote_cfg = cfg.get('remote', {}) if is_remote else {}
        remote_host = (remote_cfg.get('host') or '').strip() if is_remote else ''

        plog("━━━ Step 1/3: Fetching latest stable release ━━━")
        release_tag = _get_cloudtak_latest_release_tag(use_cache=False)
        if not release_tag:
            plog("  ⚠ Could not fetch release tag from GitHub (rate limit or network) — will pull latest HEAD instead")
        else:
            plog(f"  Target: {release_tag}")

        plog("")
        plog("━━━ Step 2/3: Checking out stable release ━━━")
        if is_remote:
            if not remote_host:
                plog("✗ Remote host not configured")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            checkout_cmd = (
                f"cd ~/CloudTAK && "
                f"git checkout -- . && "
                f"git fetch --depth 1 origin tag {release_tag} && "
                f"git checkout {release_tag}"
            )
            ok, out = _ssh_probe(remote_cfg, checkout_cmd, timeout=120)
            if not ok:
                plog(f"✗ Checkout failed on remote: {(out or '')[:220]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
        else:
            cloudtak_dir = os.path.expanduser('~/CloudTAK')
            if not os.path.isdir(os.path.join(cloudtak_dir, '.git')):
                plog("✗ ~/CloudTAK not found — use Deploy instead")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            plugins_base = os.path.join(cloudtak_dir, 'api', 'web', 'plugins')
            # Note which catalog plugins are installed before checkout.
            # git shallow-fetch checkouts can wipe untracked subdirectories.
            pre_installed = {
                p['install_dir']: p for p in CLOUDTAK_PLUGINS
                if os.path.isdir(os.path.join(plugins_base, p['install_dir']))
                   or os.path.islink(os.path.join(plugins_base, p['install_dir']))
            }
            # Clear any stale .git/index.lock (a prior checkout that ran long enough
            # to be timeout-killed on a slower/SELinux box leaves one and wedges the
            # repo) and exclude the root-owned .docker-store MinIO bind-mount from git.
            # Then do ONE force-checkout to the tag: -f discards the tracked
            # docker-compose.yml port patch (re-applied below) and the override/.env/
            # .docker-store are untracked, so they survive. Patches (nginx, port
            # bindings) live in docker-compose.override.yml which is untracked.
            # Generous timeout so no family crosses it (CloudTAK is ~18k tracked files).
            _cloudtak_git_prep(cloudtak_dir, plog)
            if release_tag:
                r = subprocess.run(
                    f'cd {cloudtak_dir} && '
                    f'git -c safe.directory={cloudtak_dir} fetch --depth 1 origin tag {release_tag} && '
                    f'git -c safe.directory={cloudtak_dir} checkout -f {release_tag}',
                    shell=True, capture_output=True, text=True, timeout=300)
            else:
                r = subprocess.run(
                    f'cd {cloudtak_dir} && '
                    f'git -c safe.directory={cloudtak_dir} reset --hard && '
                    f'git -c safe.directory={cloudtak_dir} pull',
                    shell=True, capture_output=True, text=True, timeout=300)
            if r.returncode != 0:
                plog(f"✗ Checkout failed: {r.stderr.strip()[:200]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            # Restore any catalog plugins that the checkout wiped.
            os.makedirs(plugins_base, exist_ok=True)
            routes_base = os.path.join(cloudtak_dir, 'api', 'routes')
            for install_dir, p in pre_installed.items():
                dest = os.path.join(plugins_base, install_dir)
                local_path = p.get('local_path')
                repo       = p.get('repo')
                plugin_subpath = p.get('plugin_subpath')
                server_subpath = p.get('server_subpath')
                use_subpaths = bool(repo and (plugin_subpath or server_subpath))
                cache_path = os.path.join(cloudtak_dir, '.plugin-src', install_dir)
                server_path = p.get('server_path')
                # Repo plugins with subdirs: clone (or reuse) the cache, source web + routes from it.
                if use_subpaths:
                    import shutil as _shutil
                    if not os.path.isdir(os.path.join(cache_path, '.git')):
                        _shutil.rmtree(cache_path, ignore_errors=True)
                        os.makedirs(os.path.dirname(cache_path), exist_ok=True)
                        subprocess.run(['git', 'clone', repo, cache_path], capture_output=True, timeout=120)
                    server_path = os.path.join(cache_path, server_subpath) if server_subpath else None
                if not os.path.exists(dest) and not os.path.islink(dest):
                    import shutil as _shutil
                    if use_subpaths:
                        web_src = os.path.join(cache_path, plugin_subpath) if plugin_subpath else cache_path
                        if os.path.isdir(web_src):
                            _shutil.copytree(web_src, dest)
                            plog(f"  Restored plugin (repo): {p['name']}")
                        else:
                            plog(f"  ⚠ Plugin '{p['name']}' repo missing '{plugin_subpath}' dir")
                    elif local_path and os.path.isdir(local_path):
                        _shutil.copytree(local_path, dest)
                        plog(f"  Restored plugin (copy): {p['name']}")
                    elif repo:
                        plog(f"  Restoring plugin (git clone): {p['name']}…")
                        subprocess.run(['git', 'clone', repo, dest], capture_output=True, timeout=120)
                        plog(f"  Restored plugin: {p['name']}")
                    else:
                        plog(f"  ⚠ Plugin '{p['name']}' was wiped — no repo or local_path to restore from")
                # Server-side route files live in api/routes/ which the checkout
                # also wipes — re-copy them whenever the plugin is installed.
                if server_path and os.path.isdir(server_path):
                    import shutil as _shutil
                    os.makedirs(routes_base, exist_ok=True)
                    for fname in sorted(os.listdir(server_path)):
                        if fname.endswith('.ts'):
                            _shutil.copy2(os.path.join(server_path, fname), os.path.join(routes_base, fname))
                            plog(f"  Restored server route: api/routes/{fname}")
        plog(f"✓ Checked out {release_tag or 'latest HEAD'}")

        # v0.9.49: the checkout above reset the (tracked) compose file to upstream
        # defaults, which republish every hardened port on 0.0.0.0 — including
        # media :9997 ("${MEDIA_PORT_API:-9997}:9997"). Since v0.9.48 Caddy binds the
        # CloudTAK video vhost on server_ip:9997, so a wildcard 0.0.0.0:9997 docker
        # publish now COLLIDES → `up -d` dies with "address already in use". (Pre-.48
        # it merely re-exposed the port silently until the next console restart ran
        # the startup migration.) Re-apply the loopback hardening here — the same
        # patch the startup migration / deploy path run — BEFORE the build/up.
        if is_remote:
            # _patch_cloudtak_compose_ports() edits local files; over SSH apply the
            # critical media:9997 → loopback rewrite via perl (consistent regex across
            # distros; sed's brace/backref handling diverges). The `unless /127.0.0.1/`
            # guard makes it idempotent. Fuller hardening runs on the box's next restart.
            _media_perl = (
                "cd ~/CloudTAK && for f in docker-compose.yml docker-compose.yaml; do "
                "[ -f \"$f\" ] && perl -i -pe "
                "'s/(- \")(\\$\\{MEDIA_PORT_API:-\\d+\\}:9997\")/${1}127.0.0.1:$2/ unless m{127\\.0\\.0\\.1}' "
                "\"$f\"; done; true"
            )
            ok_sed, _ = _ssh_probe(remote_cfg, _media_perl, timeout=30)
            plog("  Re-applied media:9997 loopback hardening after checkout"
                 if ok_sed else "  ⚠ Could not re-apply media:9997 loopback (non-fatal)")
        else:
            try:
                if _patch_cloudtak_compose_ports(cloudtak_dir):
                    plog("  Re-applied port hardening after checkout (loopback/removed)")
            except Exception as _pe:
                plog(f"  ⚠ Port-hardening patch failed (non-fatal): {_pe}")

        plog("")
        plog("━━━ Step 3/3: Rebuilding and restarting ━━━")
        if is_remote:
            dcc = _compose_cmd(remote_cfg=remote_cfg)
            if not dcc:
                plog("✗ Neither `docker compose` nor `docker-compose` is available on the remote host")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            build_cmd = f"cd ~/CloudTAK && {dcc} build --no-cache && {dcc} up -d"
            ok, out = _ssh_probe(remote_cfg, build_cmd, timeout=2700)
            if not ok:
                plog(f"✗ Build/restart failed on remote: {(out or '')[:600]}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
        else:
            cloudtak_dir = os.path.expanduser('~/CloudTAK')
            dcc = _compose_cmd()
            if not dcc:
                plog("✗ Neither `docker compose` nor `docker-compose` is available")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
            # Detected compose binary only — no fallback chain that would mask the real
            # build error with a bogus 'docker-compose: not found'. Surface the tail of
            # the combined output so an actual build failure is diagnosable.
            r = subprocess.run(
                f'{dcc} build --no-cache && {dcc} up -d 2>&1',
                shell=True, capture_output=True, text=True, timeout=2700, cwd=cloudtak_dir)
            if r.returncode != 0:
                _tail = '\n'.join((r.stdout or r.stderr or 'unknown').strip().splitlines()[-20:])
                plog(f"✗ Build/restart failed (via `{dcc}`):\n{_tail}")
                cloudtak_deploy_status.update({'running': False, 'error': True})
                return
        plog("✓ Containers rebuilt and restarted")
        # v0.9.48 (Part B+C/D): the rebuild recreated cloudtak-media from the image
        # default — re-apply the self-heal (HLS config + ephemeral-aware reaper).
        _cloudtak_media_hls_heal(plog=plog, remote_cfg=(remote_cfg if is_remote else None), wait=True)
        plog("")
        plog(f"✓ CloudTAK updated to {release_tag}")
        plog("Update finished — CloudTAK is running.")
        plog("")
        plog("⚠ Service worker note: a refresh (even Cmd/Ctrl+Shift+R) will NOT show the new")
        plog("  version — CloudTAK's service worker serves a cached copy. To force it:")
        plog("  DevTools (F12) → Application → Clear site data, then reload.")
        plog("  (In-app Settings → Refresh App sometimes works but is not reliable.)")
        _update_boot_stagger_service()
        cloudtak_deploy_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        plog(f"✗ Error: {str(e)}")
        cloudtak_deploy_status.update({'running': False, 'error': True})
    finally:
        cloudtak_deploy_status['running'] = False


# ── Email Relay ────────────────────────────────────────────────────────────────
email_deploy_log = []
email_deploy_status = {'running': False, 'complete': False, 'error': False}

PROVIDERS = {
    'brevo':   {'name': 'Brevo',   'host': 'smtp-relay.brevo.com', 'port': '587', 'url': 'https://app.brevo.com/settings/keys/smtp'},
    'smtp2go': {'name': 'SMTP2GO', 'host': 'mail.smtp2go.com',     'port': '587', 'url': 'https://app.smtp2go.com/settings/users/smtp'},
    'mailgun': {'name': 'Mailgun', 'host': 'smtp.mailgun.org',      'port': '587', 'url': 'https://app.mailgun.com/mg/sending/domains'},
    'custom':  {'name': 'Custom',  'host': '',                      'port': '587', 'url': ''},
}

def run_email_deploy(provider_key, smtp_user, smtp_pass, from_addr, from_name):
    log = email_deploy_log
    status = email_deploy_status

    def plog(msg):
        log.append(msg)

    try:
        settings = load_settings()
        pkg_mgr = settings.get('pkg_mgr', 'apt')
        provider = PROVIDERS.get(provider_key, PROVIDERS['brevo'])

        plog(f"📧 Step 1/5 — Installing Postfix...")
        if pkg_mgr == 'apt':
            wait_for_apt_lock(plog, log)
            # Resolve mailname: prefer saved FQDN, fall back to hostname -f, hard-fallback to hostname
            # hostname -f can return an unresolvable name on some VPS configs, causing
            # mydomain to be derived as "0" and postfix install to fail with
            # "meter mydomain: bad parameter value: 0"
            fqdn_result = subprocess.run('hostname -f 2>/dev/null || hostname', shell=True, capture_output=True, text=True)
            fqdn = (settings.get('fqdn') or fqdn_result.stdout.strip() or 'localhost').strip()
            if not fqdn or fqdn == '0':
                fqdn = settings.get('fqdn', 'localhost')
            subprocess.run(
                f'echo "postfix postfix/mailname string {fqdn}" | debconf-set-selections && '
                'echo "postfix postfix/main_mailer_type string Internet Site" | debconf-set-selections',
                shell=True, capture_output=True, timeout=30)
            r = subprocess.run(
                _sudo_wrap(['apt-get', 'install', '-y', 'postfix', 'libsasl2-modules']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=300)
            if r.returncode != 0:
                # Attempt recovery: set myhostname/mydomain explicitly then retry dpkg --configure
                plog(f"⚠ Postfix install hit error, attempting recovery (mydomain fix)...")
                subprocess.run(
                    f'postconf -e "myhostname={fqdn}" 2>/dev/null; '
                    f'postconf -e "mydomain={fqdn.split(".", 1)[-1] if "." in fqdn else fqdn}" 2>/dev/null; '
                    'dpkg --configure postfix 2>&1 || true',
                    shell=True, capture_output=True, timeout=60)
                r = subprocess.run('dpkg -l postfix 2>&1', shell=True, capture_output=True, text=True)
                if 'ii' not in r.stdout:
                    plog(f"✗ Postfix install failed: {r.stdout[-500:]}")
                    status.update({'running': False, 'error': True})
                    return
        else:
            r = subprocess.run(_sudo_wrap(['dnf', 'install', '-y', 'postfix', 'cyrus-sasl-plain']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=300)
            if r.returncode != 0:
                plog(f"✗ Postfix install failed: {r.stdout[-500:]}")
                status.update({'running': False, 'error': True})
                return
        plog("✓ Postfix installed")

        plog(f"📧 Step 2/5 — Configuring main.cf...")
        relay_host = provider['host']
        relay_port = provider['port']
        main_cf_additions = f"""
# TAKWERX Email Relay — managed by TAK-infra
inet_interfaces = all
mynetworks = 127.0.0.0/8 [::1]/128 172.16.0.0/12
# Send-only smarthost: never treat the base domain as a local destination
# (default mydestination includes $mydomain -> 550 "User unknown in local
# recipient table" for any address at the TAK base domain, GH #48)
mydestination = $myhostname, localhost.localdomain, localhost
relayhost = [{relay_host}]:{relay_port}
smtp_sasl_auth_enable = yes
smtp_sasl_password_maps = hash:/etc/postfix/sasl_passwd
smtp_sasl_security_options = noanonymous
smtp_tls_security_level = may
smtp_use_tls = yes
header_size_limit = 4096000
smtp_generic_maps = hash:/etc/postfix/generic
"""
        # Read existing main.cf and strip any previous TAKWERX block. v10.0.5
        # non-root: /etc/postfix is root-owned — read+write via the broker (raw
        # open(...,'w') EPERM'd as the takwerx console: [Errno 13] /etc/postfix/main.cf).
        main_cf_path = '/etc/postfix/main.cf'
        try:
            existing = _read_priv(main_cf_path)
        except Exception:
            existing = ''
        if existing:
            # Remove previous TAKWERX block if present
            import re
            existing = re.sub(r'\n# TAKWERX Email Relay.*', '', existing, flags=re.DOTALL)
            # Remove any existing relayhost line (Ubuntu default has a blank one)
            existing = re.sub(r'^\s*relayhost\s*=.*$', '', existing, flags=re.MULTILINE)
            # Remove any existing mynetworks (we set it in our block for Docker relay)
            existing = re.sub(r'^\s*mynetworks\s*=.*$', '', existing, flags=re.MULTILINE)
            # Remove any existing mydestination (package default includes $mydomain,
            # which makes same-domain mail bounce locally — GH #48; ours wins)
            existing = re.sub(r'^\s*mydestination\s*=.*$', '', existing, flags=re.MULTILINE)
            existing = existing.rstrip()
        _write_priv(main_cf_path, existing + '\n' + main_cf_additions)
        plog("✓ main.cf configured")

        plog(f"📧 Step 3/5 — Writing credentials...")
        sasl_line = f"[{relay_host}]:{relay_port}    {smtp_user}:{smtp_pass}"
        _write_priv('/etc/postfix/sasl_passwd', sasl_line + '\n')
        subprocess.run('postmap /etc/postfix/sasl_passwd', shell=True, capture_output=True)
        subprocess.run(_sudo_wrap(['chmod', '600', '/etc/postfix/sasl_passwd', '/etc/postfix/sasl_passwd.db']), capture_output=True)

        # Generic map for from address rewriting
        hostname = subprocess.run('hostname -f', shell=True, capture_output=True, text=True).stdout.strip()
        generic_line = f"root@{hostname}    {from_addr}"
        _write_priv('/etc/postfix/generic', generic_line + '\n')
        subprocess.run('postmap /etc/postfix/generic', shell=True, capture_output=True)
        plog("✓ Credentials written and hashed")

        plog(f"📧 Step 4/5 — Enabling and starting Postfix...")
        subprocess.run(_sudo_wrap(['systemctl', 'enable', 'postfix']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
        r = subprocess.run(_sudo_wrap(['systemctl', 'restart', 'postfix']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)
        if r.returncode != 0:
            plog(f"✗ Postfix restart failed: {r.stdout}")
            status.update({'running': False, 'error': True})
            return
        plog("✓ Postfix running")

        plog(f"📧 Step 5/5 — Saving configuration...")
        settings['email_relay'] = {
            'provider': provider_key,
            'relay_host': relay_host,
            'relay_port': relay_port,
            'smtp_user': smtp_user,
            'from_addr': from_addr,
            'from_name': from_name,
        }
        # Store password separately (still in settings.json, local only)
        settings['email_relay']['smtp_pass'] = smtp_pass
        save_settings(settings)
        plog("✓ Configuration saved")
        plog("")
        plog("✅ Email Relay deployed successfully!")
        plog(f"   Provider: {provider['name']}")
        plog(f"   Relay:    {relay_host}:{relay_port}")
        plog(f"   From:     {from_name} <{from_addr}>")

        # Auto-configure Authentik if installed (SMTP + recovery flow)
        ak_dir = os.path.expanduser('~/authentik')
        if os.path.exists(os.path.join(ak_dir, 'docker-compose.yml')):
            plog("")
            plog("🔑 Step 6/6 — Configuring Authentik (SMTP + password recovery)...")
            try:
                ak_msg = _configure_authentik_smtp_and_recovery(from_addr, plog)
                plog(f"✓ {ak_msg}")
            except Exception as e:
                plog(f"⚠ Authentik auto-config failed: {e}")
                plog("  You can configure it manually via the 'Configure Authentik' button.")
        else:
            plog("")
            plog("📋 Configure apps to use SMTP:")
            plog("   Host: localhost   Port: 25   No auth required")

        status.update({'running': False, 'complete': True, 'error': False})

    except Exception as e:
        plog(f"✗ Deploy failed: {str(e)}")
        status.update({'running': False, 'error': True})


def _authentik_smtp_configured():
    """True if Authentik .env has email settings (SMTP was pushed by Configure Authentik or deploy)."""
    settings = load_settings()
    ak_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    if ak_cfg.get('target_mode') == 'remote':
        return bool(settings.get('authentik_smtp_configured_remote'))
    env_path = os.path.expanduser('~/authentik/.env')
    if not os.path.exists(env_path):
        return False
    with open(env_path) as f:
        for line in f:
            if line.strip().startswith('AUTHENTIK_EMAIL__HOST=') and '=' in line and line.strip().split('=', 1)[1].strip():
                return True
    return False

