@app.route('/api/cesium-tiles/upload', methods=['POST'])
@login_required
def cesium_tiles_upload():
    import zipfile
    import tempfile
    import shutil
    ct_dir = _cesium_dir()
    _cesium_ensure_dir()  # create + (RHEL) caddy-readable perms + httpd_sys_content_t (new files inherit it)
    dataset_name = (request.form.get('name') or '').strip()
    if not dataset_name:
        return jsonify({'success': False, 'error': 'Dataset name is required'})
    # Sanitize: letters, digits, hyphens, underscores only
    import re as _re_ct
    dataset_name = _re_ct.sub(r'[^A-Za-z0-9_\-]', '-', dataset_name).strip('-') or 'dataset'
    if 'file' not in request.files:
        return jsonify({'success': False, 'error': 'No file provided'})
    f = request.files['file']
    if not f.filename.lower().endswith('.zip'):
        return jsonify({'success': False, 'error': 'Upload must be a .zip file'})
    dest_dir = os.path.join(ct_dir, dataset_name)
    if os.path.exists(dest_dir):
        return jsonify({'success': False, 'error': f'Dataset "{dataset_name}" already exists — delete it first or choose a different name'})
    # Stream to a temp file to avoid loading GB into memory
    tmp_fd, tmp_path = tempfile.mkstemp(suffix='.zip', dir=ct_dir)
    try:
        with os.fdopen(tmp_fd, 'wb') as tmp_f:
            chunk_size = 64 * 1024
            while True:
                chunk = f.stream.read(chunk_size)
                if not chunk:
                    break
                tmp_f.write(chunk)
        # Validate zip contains tileset.json (at root or one level deep)
        with zipfile.ZipFile(tmp_path, 'r') as zf:
            names = zf.namelist()
            has_tileset = any(
                n == 'tileset.json' or n.endswith('/tileset.json')
                for n in names
            )
            if not has_tileset:
                return jsonify({'success': False, 'error': 'Zip does not contain a tileset.json — make sure you zipped the dataset folder itself, not just its contents'})
            # Detect if there is a single top-level directory wrapping everything
            top_dirs = {n.split('/')[0] for n in names if n}
            single_wrap = (len(top_dirs) == 1 and not any(
                n == 'tileset.json' for n in names
            ))
            os.makedirs(dest_dir, exist_ok=True)
            if single_wrap:
                # Strip the wrapping directory when extracting
                wrap = list(top_dirs)[0]
                for member in zf.infolist():
                    rel = member.filename[len(wrap):].lstrip('/')
                    if not rel:
                        continue
                    target = os.path.join(dest_dir, rel)
                    if member.filename.endswith('/'):
                        os.makedirs(target, exist_ok=True)
                    else:
                        os.makedirs(os.path.dirname(target), exist_ok=True)
                        with zf.open(member) as src, open(target, 'wb') as dst:
                            shutil.copyfileobj(src, dst)
            else:
                zf.extractall(dest_dir)
    except zipfile.BadZipFile:
        return jsonify({'success': False, 'error': 'File is not a valid zip archive'})
    except Exception as e:
        shutil.rmtree(dest_dir, ignore_errors=True)
        return jsonify({'success': False, 'error': str(e)})
    finally:
        try:
            os.unlink(tmp_path)
        except Exception:
            pass
    # Verify tileset.json ended up in the right place
    if not os.path.exists(os.path.join(dest_dir, 'tileset.json')):
        shutil.rmtree(dest_dir, ignore_errors=True)
        return jsonify({'success': False, 'error': 'Could not find tileset.json at the root of the extracted dataset — check your zip structure'})
    settings = load_settings()
    return jsonify({'success': True, 'dataset': dataset_name, 'datasets': _cesium_list_datasets(settings)})


@app.route('/api/cesium-tiles/upload-folder', methods=['POST'])
@login_required
def cesium_tiles_upload_folder():
    import re as _re_ctf
    import shutil
    ct_dir = _cesium_dir()
    _cesium_ensure_dir()  # create + (RHEL) caddy-readable perms + httpd_sys_content_t (new files inherit it)
    raw_name = (request.form.get('name') or '').strip()
    if not raw_name:
        return jsonify({'success': False, 'error': 'Dataset name is required'})
    dataset_name = _re_ctf.sub(r'[^A-Za-z0-9_\-]', '-', raw_name).strip('-') or 'dataset'
    dest_dir = os.path.join(ct_dir, dataset_name)
    if os.path.exists(dest_dir):
        return jsonify({'success': False, 'error': f'Dataset "{dataset_name}" already exists — delete it first or choose a different name'})
    files = request.files.getlist('files[]')
    if not files:
        return jsonify({'success': False, 'error': 'No files received'})
    # Validate tileset.json is present (filename is the relative path, already top-folder-stripped by JS)
    has_tileset = any(
        (f.filename or '').lstrip('/') == 'tileset.json'
        for f in files
    )
    if not has_tileset:
        return jsonify({'success': False, 'error': 'No tileset.json found — make sure the folder contains tileset.json at its root'})
    try:
        os.makedirs(dest_dir, exist_ok=True)
        for f in files:
            rel = (f.filename or '').lstrip('/')
            if not rel or '..' in rel.split('/'):
                continue
            target = os.path.join(dest_dir, rel)
            # Prevent path traversal
            if not os.path.abspath(target).startswith(os.path.abspath(dest_dir) + os.sep):
                continue
            os.makedirs(os.path.dirname(target), exist_ok=True)
            f.save(target)
    except Exception as exc:
        shutil.rmtree(dest_dir, ignore_errors=True)
        return jsonify({'success': False, 'error': str(exc)})
    settings = load_settings()
    return jsonify({'success': True, 'dataset': dataset_name, 'datasets': _cesium_list_datasets(settings)})


@app.route('/api/cesium-tiles/datasets/<name>', methods=['DELETE'])
@login_required
def cesium_tiles_delete(name):
    import shutil
    import re as _re_ctd
    if not _re_ctd.match(r'^[A-Za-z0-9_\-]+$', name):
        return jsonify({'success': False, 'error': 'Invalid dataset name'})
    ct_dir = _cesium_dir()
    target = os.path.join(ct_dir, name)
    # Prevent path traversal
    if not os.path.abspath(target).startswith(os.path.abspath(ct_dir)):
        return jsonify({'success': False, 'error': 'Invalid path'})
    if not os.path.isdir(target):
        return jsonify({'success': False, 'error': 'Dataset not found'})
    shutil.rmtree(target)
    settings = load_settings()
    return jsonify({'success': True, 'datasets': _cesium_list_datasets(settings)})


# ── WebODM ───────────────────────────────────────────────────────────────────

# WebODM ODM (NodeODX) resource ceiling — fleet-uniform safety cap. A co-located ODM
# job must never starve/OOM the rest of the TAK stack. Enforced three ways on wo_nodeodm:
#   cpus           — CPU-time ceiling (host protection)
#   mem_limit      — OOM backstop: Docker kills the ODM container, never the host
#   --max_concurrency — NodeODX self-limits its thread pool so a job COMPLETES within the
#                       cap instead of spawning host-core-count threads and OOM-killing.
#                       (NodeODX reads os.cpus()=host count and ignores the cpu cgroup, so
#                        the cpus cap alone won't stop it — this is the lever that does.)
# Field guidance: Tom Endress, 2026-06 — validated "set to 4 cores/threads" holding under
# co-located MediaMTX load; he wanted it safe for the fleet ("hate to see it OOM a TAKStack").
ODM_MAX_CORES      = 4   # fleet ceiling — the single knob to retune fleet-wide (Tom-validated)
ODM_CORE_RESERVE   = 2   # cores always left for OS + co-located services
ODM_MEM_PER_CORE_G = 1   # NodeODX peak ~1GB/thread @ 2MP (per NodeODX max-concurrency help)
ODM_MEM_HEADROOM_G = 2   # GB above the per-core estimate


def _webodm_odm_limits(detected_cores, cfg):
    """(cpus, mem_g) for the wo_nodeodm container. Operator override (hard-clamped to the
    fleet ceiling) or auto-tune from detected cores. Always recomputes the target —
    never max(cur, target), so the fleet converges (CLAUDE.md fleet-uniform rule)."""
    cfg = cfg or {}
    auto = max(1, min(int(detected_cores or 1) - ODM_CORE_RESERVE, ODM_MAX_CORES))
    try:
        cpus = int(cfg.get('odm_cpus')) if str(cfg.get('odm_cpus') or '').strip() else auto
    except (TypeError, ValueError):
        cpus = auto
    cpus = max(1, min(cpus, ODM_MAX_CORES))          # hard fleet clamp
    try:
        mem = int(cfg.get('odm_mem_g')) if str(cfg.get('odm_mem_g') or '').strip() else \
              cpus * ODM_MEM_PER_CORE_G + ODM_MEM_HEADROOM_G
    except (TypeError, ValueError):
        mem = cpus * ODM_MEM_PER_CORE_G + ODM_MEM_HEADROOM_G
    return cpus, max(2, mem)


WEBODM_DOCKER_COMPOSE = '''version: '2.4'
volumes:
  wo_dbdata:
  wo_appmedia:
services:
  wo_db:
    image: webodm/webodm_db
    container_name: wo_db
    volumes:
      - {wo_dir}/db:/var/lib/postgresql/data:Z
    restart: unless-stopped
    oom_score_adj: -100
  wo_broker:
    image: redis:7.0.10
    container_name: wo_broker
    restart: unless-stopped
    oom_score_adj: -500
  wo_webapp:
    image: webodm/webodm_webapp
    container_name: webapp
    entrypoint: /bin/bash -c "service cron start && chmod +x /webodm/*.sh && /bin/bash -c \\"/webodm/wait-for-postgres.sh wo_db /webodm/wait-for-it.sh -t 0 wo_broker:6379 -- /webodm/start.sh\\""
    volumes:
      - {wo_dir}/media:/webodm/app/media:z
      - {wo_dir}/plugins/webodm-tak-overlay:/webodm/coreplugins/tak_incident_overlay:z
      - {wo_dir}/local_settings.py:/webodm/webodm/local_settings.py:ro,z
    ports:
      - "127.0.0.1:{wo_port}:8000"
    depends_on:
      - wo_db
      - wo_broker
      - wo_worker
    environment:
      - WO_PORT={wo_port}
      - WO_HOST=0.0.0.0
      - WO_DEBUG=NO
      - WO_DATABASE_HOST=wo_db
      - WO_BROKER=redis://wo_broker
      - WO_SECRET_KEY={wo_secret}
      - WEB_CONCURRENCY=2
    restart: unless-stopped
  wo_worker:
    image: webodm/webodm_webapp
    container_name: wo_worker
    entrypoint: /bin/bash -c "/webodm/wait-for-postgres.sh wo_db /webodm/wait-for-it.sh -t 0 wo_broker:6379 -- /webodm/worker.sh start"
    volumes:
      - {wo_dir}/media:/webodm/app/media:z
      - {wo_dir}/plugins/webodm-tak-overlay:/webodm/coreplugins/tak_incident_overlay:z
      - {wo_dir}/local_settings.py:/webodm/webodm/local_settings.py:ro,z
    depends_on:
      - wo_db
      - wo_broker
    environment:
      - WO_DATABASE_HOST=wo_db
      - WO_BROKER=redis://wo_broker
      - WO_DEBUG=NO
      - WO_SECRET_KEY={wo_secret}
      - WEB_CONCURRENCY=2
    restart: unless-stopped
  wo_nodeodm:
    image: webodm/nodeodx
    container_name: wo_nodeodm
    command: ["--max_concurrency", "{wo_odm_cpus}"]
    cpus: {wo_odm_cpus}
    mem_limit: {wo_odm_mem}g
    restart: unless-stopped
    oom_score_adj: 250
'''

_webodm_deploy_status = {'running': False, 'complete': False, 'error': False, 'log': []}


def _webodm_deploy_log(msg, status=None):
    _webodm_deploy_status['log'].append(msg)
    if status:
        _webodm_deploy_status.update(status)


WEBODM_LOCAL_SETTINGS_STUB = (
    '# Managed by infra-TAK. OIDC login config is written here after the\n'
    '# Authentik step of a WebODM deploy (GH #50). Do not edit by hand.\n'
)


def _webodm_local_settings_content(settings, client_id, client_secret):
    """Render WebODM's local_settings.py enabling native OIDC login against
    Authentik. WebODM >= 3.2.2 (app/oidc_providers.py) requires exactly these
    keys: name, client_id, client_secret, auth_endpoint, token_endpoint,
    userinfo_endpoint — a missing/empty key silently disables the provider."""
    ak_base = _get_authentik_base_url(settings)
    return (
        '# Managed by infra-TAK — WebODM native OIDC login via Authentik (GH #50).\n'
        '# Rewritten on WebODM deploy and Authentik repair. Do not edit by hand.\n'
        'OIDC_AUTH_PROVIDERS = [{\n'
        "    'name': 'Authentik',\n"
        f"    'client_id': {json.dumps(client_id)},\n"
        f"    'client_secret': {json.dumps(client_secret)},\n"
        f"    'auth_endpoint': {json.dumps(ak_base + '/application/o/authorize/')},\n"
        f"    'token_endpoint': {json.dumps(ak_base + '/application/o/token/')},\n"
        f"    'userinfo_endpoint': {json.dumps(ak_base + '/application/o/userinfo/')},\n"
        '}]\n'
    )


def _webodm_apply_oidc_local_settings(settings, client_id, client_secret, plog=None):
    """Write {wo_dir}/local_settings.py with the OIDC provider block and restart
    the WebODM containers when it changed. Handles local installs (incl. a
    flipped box keeping /root/webodm — broker-routed reads/writes) and remote
    deployments. The webapp/worker only pick the file up through the compose
    mount, so on pre-mount installs we write the file and tell the operator a
    redeploy is needed instead of restarting for nothing."""
    def log(msg):
        if plog:
            plog(msg)
    if not client_id or not client_secret:
        return False
    content = _webodm_local_settings_content(settings, client_id, client_secret)
    deploy_cfg = _get_module_deployment_config(settings, 'webodm_deployment')
    try:
        if deploy_cfg.get('target_mode') == 'remote':
            if not deploy_cfg.get('deployed'):
                return False
            wo_dir = (deploy_cfg.get('remote', {}).get('_resolved_wo_dir') or '~/webodm').strip()
            ok, existing = _module_run(deploy_cfg,
                f'cat {wo_dir}/local_settings.py 2>/dev/null; true', timeout=15)
            ok_m, _ = _module_run(deploy_cfg,
                f'grep -q local_settings.py {wo_dir}/docker-compose.yml', timeout=15)
            mount_present = bool(ok_m)
            if ok and (existing or '').strip() == content.strip():
                if mount_present:
                    log('  ✓ WebODM OIDC login already configured')
                else:
                    log('  ⚠ OIDC creds written, but the running compose predates the local_settings mount — redeploy WebODM to activate one-click login')
                return True
            import tempfile as _tf
            with _tf.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as tf:
                tf.write(content)
                tmp_ls = tf.name
            try:
                ok_cp, _ = _module_copy(deploy_cfg, tmp_ls, f'{wo_dir}/local_settings.py', log_fn=plog)
            finally:
                try:
                    os.unlink(tmp_ls)
                except Exception:
                    pass
            if not ok_cp:
                log('  ⚠ Could not write local_settings.py on remote — WebODM keeps manual login')
                return False
            _module_run(deploy_cfg, f'chmod 600 {wo_dir}/local_settings.py', timeout=15)
            if not mount_present:
                log('  ⚠ OIDC creds written, but the running compose predates the local_settings mount — redeploy WebODM to activate one-click login')
                return True
            _module_run(deploy_cfg, 'docker restart webapp wo_worker 2>&1', timeout=120)
            log('  ✓ WebODM native OIDC login configured (webapp restarted)')
            return True

        wo_dir = _webodm_dir()   # ~/webodm OR (flipped box) /root/webodm
        compose_path = os.path.join(wo_dir, 'docker-compose.yml')
        try:
            compose_txt = _read_priv(compose_path)
        except Exception:
            return False   # WebODM not installed locally
        ls_path = os.path.join(wo_dir, 'local_settings.py')
        try:
            existing = _read_priv(ls_path)
        except Exception:
            existing = ''
        mount_present = 'local_settings.py' in compose_txt
        if existing.strip() == content.strip() and mount_present:
            log('  ✓ WebODM OIDC login already configured')
            return True
        _write_priv(ls_path, content, perm=0o600)
        if not mount_present:
            log('  ⚠ OIDC creds written, but the running compose predates the local_settings mount — redeploy WebODM to activate one-click login')
            return True
        subprocess.run(_sudo_wrap(['docker', 'restart', 'webapp', 'wo_worker']),
                       capture_output=True, timeout=120)
        log('  ✓ WebODM native OIDC login configured (webapp restarted)')
        return True
    except Exception as e:
        log(f'  ⚠ WebODM OIDC local_settings error: {str(e)[:120]}')
        return False


def _run_webodm_deploy_remote(settings, deploy_cfg, plog):
    """Deploy WebODM on a remote host via SSH (mirrors Node-RED remote pattern)."""
    import secrets as _sec
    remote = deploy_cfg.get('remote', {})
    host = (remote.get('host') or '').strip()
    if not host:
        plog('✗ Remote host not configured')
        _webodm_deploy_status.update({'running': False, 'error': True})
        return
    plog(f'━━━ WebODM remote deploy → {host} ━━━')

    # Resolve home dir on remote — Docker doesn't expand ~ in volume paths
    ok, home_out = _module_run(deploy_cfg, 'echo $HOME', timeout=10)
    wo_dir_remote = (home_out or '').strip() + '/webodm' if ok and (home_out or '').strip() else '~/webodm'
    wo_port = settings.get('webodm_port', 8765)
    compose_path_remote = f'{wo_dir_remote}/docker-compose.yml'
    plog(f'  WebODM dir on remote: {wo_dir_remote}')

    # Ensure Docker on remote
    plog('━━━ Checking Docker (remote) ━━━')
    ok, out = _module_run(deploy_cfg, 'docker --version 2>&1', timeout=15)
    if not ok or 'Docker version' not in (out or ''):
        plog('  Docker not found — installing...')
        ok, out = _module_run(deploy_cfg, 'curl -fsSL https://get.docker.com | sh 2>&1', timeout=300, log_fn=plog)
        if not ok:
            plog(f'✗ Docker install failed: {(out or "")[-300:]}')
            _webodm_deploy_status.update({'running': False, 'error': True})
            return
    ok, dv = _module_run(deploy_cfg, 'docker --version 2>&1', timeout=10)
    plog(f'  {(dv or "").strip()}')

    # Create directory structure on remote
    plog('━━━ Creating directories (remote) ━━━')
    # local_settings.py must exist before `compose up` — Docker would otherwise
    # create a DIRECTORY at the mount source. touch keeps existing OIDC creds.
    ok, out = _module_run(deploy_cfg,
        f'mkdir -p {wo_dir_remote}/plugins {wo_dir_remote}/media {wo_dir_remote}/db && '
        f'touch {wo_dir_remote}/local_settings.py && chmod 600 {wo_dir_remote}/local_settings.py',
        timeout=15, log_fn=plog)
    if not ok:
        plog(f'✗ mkdir failed: {out}')
        _webodm_deploy_status.update({'running': False, 'error': True})
        return
    plog('✓ Directories created')

    # Clone TAK overlay plugin on remote
    plog('━━━ Installing TAK overlay plugin (remote) ━━━')
    ok, out = _module_run(deploy_cfg,
        f'rm -rf {wo_dir_remote}/plugins/webodm-tak-overlay && '
        f'git clone --depth=1 https://github.com/Humble-Helper-96/webodm-tak-overlay.git '
        f'{wo_dir_remote}/plugins/webodm-tak-overlay 2>&1 && '
        # Upstream ships an empty __init__.py; WebODM needs Plugin re-exported
        # at package level or the plugin never loads (GH #50).
        f'{{ grep -q Plugin {wo_dir_remote}/plugins/webodm-tak-overlay/__init__.py 2>/dev/null || '
        f'echo from .plugin import Plugin > {wo_dir_remote}/plugins/webodm-tak-overlay/__init__.py; }}',
        timeout=90, log_fn=plog)
    if not ok:
        plog(f'✗ Plugin clone failed: {(out or "")[-300:]}')
        _webodm_deploy_status.update({'running': False, 'error': True})
        return
    plog('✓ TAK overlay plugin cloned')

    # Write compose file locally, scp to remote
    plog('━━━ Writing docker-compose.yml ━━━')
    wo_secret = _sec.token_hex(32)
    # ODM resource cap (GH #32) — detect remote core count, then apply the fleet ceiling.
    _okc, _np = _module_run(deploy_cfg, 'nproc 2>/dev/null || echo 4', timeout=10)
    try:
        _cores = int((_np or '4').strip() or 4) if _okc else 4
    except (TypeError, ValueError):
        _cores = 4
    _odm_cpus, _odm_mem = _webodm_odm_limits(_cores, deploy_cfg)
    plog(f'  ODM cap: {_odm_cpus} cores / {_odm_mem}g / max_concurrency {_odm_cpus} (host {_cores} cores, ceiling {ODM_MAX_CORES})')
    wo_compose = WEBODM_DOCKER_COMPOSE.format(
        wo_dir=wo_dir_remote, wo_port=wo_port, wo_secret=wo_secret,
        wo_odm_cpus=_odm_cpus, wo_odm_mem=_odm_mem)
    # Remote: bind WebODM port on 0.0.0.0 so Caddy on the console can reach it
    wo_compose = wo_compose.replace(
        f'      - "127.0.0.1:{wo_port}:8000"',
        f'      - "0.0.0.0:{wo_port}:8000"',
    )
    compose_content = wo_compose
    import tempfile as _tf
    with _tf.NamedTemporaryFile(mode='w', suffix='.yml', delete=False) as tf:
        tf.write(compose_content)
        tmp_compose = tf.name
    ok1, _ = _module_copy(deploy_cfg, tmp_compose, compose_path_remote, log_fn=plog)
    try:
        os.unlink(tmp_compose)
    except Exception:
        pass
    if not ok1:
        plog('✗ Failed to copy docker-compose.yml to remote')
        _webodm_deploy_status.update({'running': False, 'error': True})
        return
    plog('✓ docker-compose.yml written')

    # Pull images on remote
    plog('━━━ Pulling WebODM images (remote — may take several minutes) ━━━')
    ok, out = _module_run(deploy_cfg, f'docker compose -f {compose_path_remote} pull 2>&1', timeout=600, log_fn=plog)
    if not ok:
        plog(f'  Pull warning (non-fatal): {(out or "")[-200:]}')

    # Start containers on remote
    plog('━━━ Starting WebODM containers (remote) ━━━')
    ok, out = _module_run(deploy_cfg, f'docker compose -f {compose_path_remote} up -d 2>&1', timeout=120, log_fn=plog)
    if not ok:
        plog(f'✗ docker compose up failed: {(out or "")[-300:]}')
        _webodm_deploy_status.update({'running': False, 'error': True})
        return
    plog('✓ WebODM containers started')

    # Harden WebODM port: allow only from console IP, deny public access
    _wo_console_ip = _fedhub_caddy_source_ip(settings)
    if _wo_console_ip:
        _module_run(deploy_cfg,
            f'command -v ufw >/dev/null 2>&1 && ('
            f'sudo ufw allow from {_wo_console_ip} to any port {wo_port} proto tcp 2>/dev/null; '
            f'sudo ufw deny {wo_port}/tcp 2>/dev/null; '
            f'sudo ufw reload 2>/dev/null); true',
            timeout=15)
        plog(f"  UFW: WebODM port {wo_port} source-scoped to console IP {_wo_console_ip}")
    else:
        _module_run(deploy_cfg,
            f'command -v ufw >/dev/null 2>&1 && (sudo ufw deny {wo_port}/tcp 2>/dev/null; sudo ufw reload 2>/dev/null); true',
            timeout=15)
        plog(f"  ⚠ No console IP set — WebODM port {wo_port} denied publicly. Set Settings → Server IP to enable source-scoping.")

    # Readiness check — probe via curl on the remote host
    plog('━━━ Waiting for WebODM readiness (remote, up to 90s) ━━━')
    import time as _time
    for _ in range(18):
        _time.sleep(5)
        ok_curl, curl_out = _module_run(deploy_cfg,
            f'curl -s -o /dev/null -w "%{{http_code}}" http://127.0.0.1:{wo_port}/ 2>/dev/null || echo 000',
            timeout=10)
        code = (curl_out or '').strip()
        if code and code not in ('000', '502', '503'):
            plog(f'  WebODM responded (HTTP {code})')
            break
    else:
        plog('  WebODM did not respond in time — check: docker logs webapp (on remote)')

    # Register NodeODM processing node on remote
    plog('━━━ Registering NodeODM node (remote) ━━━')
    # Wait for Django migrations to complete before registering NodeODM (fresh host pulls ~1.5GB)
    plog("  Waiting for WebODM Django migrations to complete...")
    _node_registered = False
    _pending = 99
    for _nr_attempt in range(24):  # 24 × 15s = 6 minutes
        _ok_mig, _mig_out = _module_run(deploy_cfg,
            'docker exec webapp python manage.py showmigrations 2>/dev/null | grep -c "\\[ \\]" || echo 99',
            timeout=20)
        try:
            _pending = int((_mig_out or '99').strip())
        except Exception:
            pass
        if _ok_mig and _pending == 0:
            plog(f"  ✓ Migrations complete ({_nr_attempt * 15}s)")
            ok_node, out_node = _module_run(deploy_cfg,
                'docker exec webapp python manage.py addnode wo_nodeodm 3000 --label NodeODX 2>&1',
                timeout=30)
            if ok_node:
                plog("  ✓ NodeODM processing node registered")
                _node_registered = True
            else:
                plog(f"  ⚠ Node registration skipped (add manually: wo_nodeodm:3000): {(out_node or '')[:120]}")
            break
        if _nr_attempt % 2 == 1:
            plog(f"  ⏳ Waiting for migrations... ({(_nr_attempt + 1) * 15}s, {_pending} pending)")
        _time.sleep(15)
    if not _node_registered and _pending != 0:
        plog("  ⚠ Migrations did not complete in 6 min — NodeODM not registered. Add manually: wo_nodeodm:3000")

    # Save settings, reload Caddy (local), configure Authentik (local)
    s = load_settings()
    s['webodm_enabled'] = True
    deploy_cfg['deployed'] = True
    deploy_cfg['remote']['_resolved_wo_dir'] = wo_dir_remote
    s['webodm_deployment'] = _normalize_module_deployment_config(deploy_cfg)
    save_settings(s)
    generate_caddyfile(s)
    try:
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), timeout=15, check=True)
        plog('✓ Caddy reloaded — TLS cert provisioning started')
    except Exception as ce:
        plog(f'  Caddy reload warning: {ce}')
    fqdn = s.get('fqdn', '').strip()
    ak_token = _get_authentik_env_value(s, 'AUTHENTIK_TOKEN') or _get_authentik_env_value(s, 'AUTHENTIK_BOOTSTRAP_TOKEN')
    if fqdn and ak_token:
        plog('━━━ Configuring Authentik for WebODM ━━━')
        _ensure_authentik_webodm_app(fqdn, ak_token, plog=plog, settings=s)
    else:
        plog('  Authentik not configured — skipping proxy provider setup')
    plog('✓ WebODM deployed on remote.')
    _webodm_deploy_status.update({'running': False, 'complete': True, 'error': False})


def _run_webodm_deploy(settings):
    import subprocess as _sp
    import secrets as _sec
    plog = _webodm_deploy_log
    deploy_cfg = _get_module_deployment_config(settings, 'webodm_deployment')
    if deploy_cfg.get('target_mode') == 'remote':
        _run_webodm_deploy_remote(settings, deploy_cfg, plog)
        return
    wo_dir = os.path.expanduser('~/webodm')
    wo_port = settings.get('webodm_port', 8765)
    plugin_dir = os.path.join(wo_dir, 'plugins', 'webodm-tak-overlay')
    compose_path = os.path.join(wo_dir, 'docker-compose.yml')
    # Reapply guard: on a box flipped from root, a root-era install lives at
    # /root/webodm (deliberately not re-homed). Deploying to ~/webodm there
    # would create a SECOND install and orphan the existing projects/DB.
    _existing_dir = _webodm_dir()
    if _existing_dir != wo_dir:
        plog(f'ERROR: existing WebODM install found at {_existing_dir} (root-era install on a non-root box). '
             f'An in-place reapply would create a second install at {wo_dir} and orphan the existing data. '
             f'Uninstall WebODM from the console first, then deploy fresh.')
        _webodm_deploy_status.update({'running': False, 'error': True})
        return
    try:
        plog('Creating directories…')
        for sub in ['', 'plugins', 'media', 'db']:
            os.makedirs(os.path.join(wo_dir, sub) if sub else wo_dir, exist_ok=True)

        plog('Installing TAK overlay plugin…')
        if os.path.isdir(plugin_dir):
            # Broker-routed: the running container (root) drops __pycache__/*.pyc
            # into the bind-mounted plugin dir, which plain rmtree can't remove
            # under the non-root console (reapply path; fresh deploys never hit it).
            subprocess.run(_sudo_wrap(['rm', '-rf', plugin_dir]),
                           capture_output=True, timeout=60, check=True)
        r = _sp.run(['git', 'clone', '--depth=1',
                     'https://github.com/Humble-Helper-96/webodm-tak-overlay.git',
                     plugin_dir], capture_output=True, text=True, timeout=60)
        if r.returncode != 0:
            raise RuntimeError(f'Plugin clone failed: {r.stderr[:300]}')
        plog(f'Plugin cloned: {plugin_dir}')
        # The plugin repo ships an EMPTY __init__.py, but WebODM's loader does
        # getattr(<package>, "Plugin") — without a package-level re-export the
        # plugin never instantiates and silently never appears (GH #50).
        init_py = os.path.join(plugin_dir, '__init__.py')
        try:
            with open(init_py) as f:
                _init_ok = 'Plugin' in f.read()
        except OSError:
            _init_ok = False
        if not _init_ok:
            with open(init_py, 'w') as f:
                f.write('from .plugin import Plugin\n')
            plog('Patched plugin __init__.py (re-export Plugin for the WebODM loader)')

        # local_settings.py must exist before `compose up` — Docker would otherwise
        # create a DIRECTORY at the mount source. A reapply keeps existing OIDC creds;
        # the file can be ROOT-owned (the Authentik sweep writes it via the broker on
        # non-root boxes), so chmod must be broker-routed too.
        ls_path = os.path.join(wo_dir, 'local_settings.py')
        if not os.path.exists(ls_path):
            with open(ls_path, 'w') as f:
                f.write(WEBODM_LOCAL_SETTINGS_STUB)
        _chmod_priv(ls_path, 0o600)

        plog('Writing docker-compose.yml…')
        wo_secret = _sec.token_hex(32)
        # ODM resource cap (GH #32) — local core count, then the fleet ceiling.
        _odm_cores = os.cpu_count() or 4
        _odm_cpus, _odm_mem = _webodm_odm_limits(_odm_cores, deploy_cfg)
        plog(f'ODM cap: {_odm_cpus} cores / {_odm_mem}g / max_concurrency {_odm_cpus} (host {_odm_cores} cores, ceiling {ODM_MAX_CORES})')
        compose_content = WEBODM_DOCKER_COMPOSE.format(
            wo_dir=wo_dir,
            wo_port=wo_port,
            wo_secret=wo_secret,
            wo_odm_cpus=_odm_cpus,
            wo_odm_mem=_odm_mem,
        )
        with open(compose_path, 'w') as f:
            f.write(compose_content)

        plog('Pulling images (this may take several minutes)…')
        r = _sp.run(_sudo_wrap(['docker', 'compose', '-f', compose_path, 'pull']),
                    capture_output=True, text=True, timeout=300,
                    cwd=wo_dir)
        if r.returncode != 0:
            plog(f'Pull warning (non-fatal): {r.stderr[:200]}')

        plog('Hardening firewall — blocking direct access to WebODM ports…')
        if _distro_family() == 'rhel':
            # No ufw on RHEL — and the bare `ufw` argv call raises FileNotFoundError
            # (no shell/fallback) which aborts the deploy. firewalld default-denies
            # un-opened ports and the cloud security group covers external access, so
            # the WebODM ports are already not externally reachable. (Firewalld-native
            # deny is part of the firewall-parity track.)
            plog('  (RHEL: ufw absent — WebODM ports covered by firewalld default-deny / cloud SG)')
        else:
            for _wo_ufw_port in [wo_port, 3001]:
                _sp.run(_sudo_wrap(['ufw', 'deny', f'{_wo_ufw_port}/tcp']), capture_output=True)

        plog('Starting WebODM containers…')
        r = _sp.run(_sudo_wrap(['docker', 'compose', '-f', compose_path, 'up', '-d']),
                    capture_output=True, text=True, timeout=120, cwd=wo_dir)
        if r.returncode != 0:
            raise RuntimeError(f'docker compose up failed: {r.stderr[:300]}')

        plog('Waiting for WebODM to become ready (up to 90 s)…')
        import time as _time
        import urllib.request as _ur
        for _ in range(18):
            _time.sleep(5)
            try:
                resp = _ur.urlopen(f'http://127.0.0.1:{wo_port}/', timeout=4)
                if resp.status < 500:
                    break
            except Exception:
                pass
        else:
            plog('WebODM did not respond in time — check logs with: docker logs webapp')

        plog('Registering NodeODM processing node…')
        import time as _t2
        _t2.sleep(5)
        try:
            # Use manage.py addnode — same approach as WebODM's own start.sh,
            # no auth credentials required, idempotent on duplicate hostname
            _r_node = _sp.run(
                _sudo_wrap(['docker', 'exec', 'webapp', 'python', 'manage.py',
                 'addnode', 'wo_nodeodm', '3000', '--label', 'NodeODX']),
                capture_output=True, text=True, timeout=30, cwd=wo_dir)
            if _r_node.returncode == 0:
                plog('NodeODM processing node registered.')
            else:
                plog(f'Node registration skipped (add manually: wo_nodeodm:3000): {_r_node.stderr[:200]}')
        except Exception as e:
            plog(f'Auto node registration skipped: {e}')

        s = load_settings()
        s['webodm_enabled'] = True
        save_settings(s)
        generate_caddyfile(s)
        import subprocess as _sp2
        try:
            _sp2.run(['systemctl', 'reload', 'caddy'], timeout=15, check=True)
            plog('Caddy reloaded — TLS cert provisioning started.')
        except Exception as ce:
            plog(f'Caddy reload warning: {ce}')
        fqdn = s.get('fqdn', '').strip()
        ak_token = _get_authentik_env_value(s, 'AUTHENTIK_TOKEN') or _get_authentik_env_value(s, 'AUTHENTIK_BOOTSTRAP_TOKEN')
        if fqdn and ak_token:
            plog('Configuring Authentik for WebODM…')
            _ensure_authentik_webodm_app(fqdn, ak_token, plog=plog, settings=s)
        else:
            plog('Authentik not configured — skipping proxy provider setup.')
        plog('WebODM deployed successfully.')
        _webodm_deploy_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as exc:
        plog(f'ERROR: {exc}')
        _webodm_deploy_status.update({'running': False, 'complete': False, 'error': str(exc)})


