@app.route('/api/webodm/ready')
@login_required
def webodm_ready():
    """
    Returns {ready, status, url}.
    Checks that the webapp container is running and responding to HTTP requests,
    then confirms the Authentik proxy can reach it (caddy forward_auth is live).
    Used by the post-deploy warmup phase so the operator doesn't try to open
    WebODM before it has finished starting up.
    """
    import subprocess as _sp
    import urllib.request as _ur
    settings = load_settings()
    wo_host = _get_service_domain(settings, 'webodm')
    wo_url = f'https://{wo_host}' if wo_host else ''

    # 1. Container health — 'healthy' state means Django is answering its own healthcheck
    try:
        r = _sp.run(_sudo_wrap(['docker', 'inspect', '--format={{.State.Health.Status}}', 'webapp']),
                    capture_output=True, text=True, timeout=6)
        health = r.stdout.strip()
    except Exception:
        health = ''

    if health == 'healthy':
        return jsonify({'ready': True, 'status': 'healthy', 'url': wo_url})

    # 2. Fallback: probe WebODM's internal API endpoint directly from the container
    try:
        r2 = _sp.run(_sudo_wrap(['docker', 'exec', 'webapp', 'curl', '-sf', '--max-time', '4',
                      'http://localhost:8000/api/']),
                     capture_output=True, text=True, timeout=8)
        if r2.returncode == 0:
            return jsonify({'ready': True, 'status': 'responding', 'url': wo_url})
    except Exception:
        pass

    # 3. Not ready yet — figure out a useful status message
    try:
        r3 = _sp.run(_sudo_wrap(['docker', 'inspect', '--format={{.State.Status}}', 'webapp']),
                     capture_output=True, text=True, timeout=6)
        state = r3.stdout.strip()
    except Exception:
        state = 'unknown'

    status_msg = {
        'starting': 'Container is starting up…',
        'running': 'Container running — Django is still initialising…',
        'exited': 'Container exited unexpectedly — check logs',
    }.get(state, f'Container state: {state}')

    return jsonify({'ready': False, 'status': status_msg, 'url': wo_url})


@app.route('/api/webodm/uninstall', methods=['POST'])
@login_required
def webodm_uninstall():
    import subprocess as _sp
    data = request.json or {}
    password = data.get('password', '')
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'error': 'Invalid admin password'}), 403
    s = load_settings()
    deploy_cfg = _get_module_deployment_config(s, 'webodm_deployment')
    if deploy_cfg.get('target_mode') == 'remote':
        wo_dir_remote = (deploy_cfg.get('remote', {}).get('_resolved_wo_dir') or '~/webodm').strip()
        compose_path_remote = f'{wo_dir_remote}/docker-compose.yml'
        _module_run(deploy_cfg,
            f'docker compose -f {compose_path_remote} down --volumes 2>/dev/null; true',
            timeout=90)
        _module_run(deploy_cfg, f'rm -rf {wo_dir_remote}/db 2>/dev/null; true', timeout=15)
    else:
        import shutil as _sh
        wo_dir = _webodm_dir()   # ~/webodm OR (flipped box) /root/webodm
        if subprocess.run(_sudo_wrap(['test', '-f', os.path.join(wo_dir, 'docker-compose.yml')]),
                          capture_output=True, timeout=10).returncode == 0:
            _webodm_compose(wo_dir, 'down --volumes', timeout=90)
        # Remove the Postgres data dir via the broker (root-owned on a flipped box); media/ is kept.
        subprocess.run(_sudo_wrap(['rm', '-rf', os.path.join(wo_dir, 'db')]), capture_output=True, timeout=60)
    s['webodm_enabled'] = False
    deploy_cfg['deployed'] = False
    s['webodm_deployment'] = _normalize_module_deployment_config(deploy_cfg)
    save_settings(s)
    generate_caddyfile(s)
    _sp.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), timeout=15, capture_output=True)
    return jsonify({'success': True})


