# Authentik module
authentik_deploy_log = []
authentik_deploy_status = {'running': False, 'complete': False, 'error': False}

# ─────────────────────────────────────────────────────────────────────────────
# v10.0.1: serialize Authentik `docker compose` operations against the deploy.
#
# The Authentik/TAK deploy and the background spiral monitor (_authentik_spiral_
# monitor) BOTH issue `docker compose` operations against the ~/authentik project,
# in the SAME gunicorn process. On a fresh deploy the monitor's first 10-min tick
# can land mid-deploy and — false-positiving on a freshly-booted outpost's normal
# transient "stage recursion / failed to execute flow" markers — fire a routing
# repair whose `docker compose up` races the deploy's own compose calls. Concurrent
# `docker compose up` on one project corrupts container state: observed live on
# aws-arm (2026-06-21) leaving authentik-postgresql-1 force-recreated but never
# started ("Created", Running=false), so authentik-server-1 could no longer resolve
# host `postgresql` ("Temporary failure in name resolution") → 502 on its own
# `ak healthcheck` → server UNHEALTHY → its API 500s → the LDAP service-account sync
# + webadmin sync (and the manual Resync button) all fail → 8446 lands on WebTAK
# instead of the Admin GUI.
#
# Fix: a process-wide "deploy active" guard. Deploy entry points set it (via the
# @_with_authentik_deploy_guard decorator); the spiral monitor stands down while it
# is set, plus a short cooldown so the post-deploy settle isn't disturbed. Both run
# in the same process, so a plain counter under a lock is sufficient (and reentrant-
# safe across the Authentik-then-TAK deploy sequence).
# ─────────────────────────────────────────────────────────────────────────────
_authentik_deploy_guard_lock = _threading.Lock()
_authentik_deploy_active_count = [0]
_authentik_deploy_settled_until = [0.0]

def _authentik_deploy_guard_enter():
    with _authentik_deploy_guard_lock:
        _authentik_deploy_active_count[0] += 1

def _authentik_deploy_guard_exit(cooldown_secs=300):
    with _authentik_deploy_guard_lock:
        if _authentik_deploy_active_count[0] > 0:
            _authentik_deploy_active_count[0] -= 1
        if _authentik_deploy_active_count[0] == 0:
            _authentik_deploy_settled_until[0] = time.time() + cooldown_secs

def _authentik_deploy_in_progress():
    with _authentik_deploy_guard_lock:
        return _authentik_deploy_active_count[0] > 0 or time.time() < _authentik_deploy_settled_until[0]

def _with_authentik_deploy_guard(fn):
    """Decorator: mark an Authentik/TAK deploy as in-progress for its whole duration
    so the spiral monitor won't run concurrent `docker compose` on the authentik
    project. See the block comment above."""
    import functools
    @functools.wraps(fn)
    def _wrapped(*a, **kw):
        _authentik_deploy_guard_enter()
        try:
            return fn(*a, **kw)
        finally:
            _authentik_deploy_guard_exit()
    return _wrapped


def _wait_for_authentik_stack_healthy(plog, timeout=240):
    """v10.0.1: Wait for the LOCAL Authentik stack to report healthy before the deploy
    runs the LDAP service-account / webadmin sync (both hit the Authentik API and fail
    with a 500 while authentik-server is unhealthy). Also SELF-HEALS the fresh-deploy
    failure mode: if a core container (postgresql/server/worker) was left stopped by a
    recreate race, a one-shot full `docker compose up -d` (no --no-deps) starts it back
    up. Returns True if the server reports healthy (or is up with no healthcheck), else
    False (caller proceeds non-fatally). No-ops cleanly for REMOTE Authentik."""
    try:
        settings = load_settings()
        ak_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
        if ak_cfg.get('target_mode') == 'remote' and (ak_cfg.get('remote', {}).get('host') or '').strip():
            return True  # remote Authentik — not locally healable from here
    except Exception:
        pass
    ak_dir = os.path.expanduser('~/authentik')
    if not os.path.exists(os.path.join(ak_dir, 'docker-compose.yml')):
        return True
    core = ['authentik-postgresql-1', 'authentik-server-1', 'authentik-worker-1']
    healed = False
    deadline = time.time() + timeout
    last_log = 0.0
    while time.time() < deadline:
        # Any core container not running? (created/exited == the recreate-race signature)
        stopped = []
        for c in core:
            r = subprocess.run(_sudo_wrap(['docker', 'inspect', '--format', '{{.State.Running}}', c]), capture_output=True, text=True, timeout=10)
            if (r.stdout or '').strip() != 'true':
                stopped.append(c)
        if stopped and not healed:
            plog(f"  ⚠ Authentik stack: {', '.join(stopped)} not running — starting the stack (docker compose up -d)…")
            subprocess.run(_sudo_wrap(['docker', 'compose', 'up', '-d']), cwd=ak_dir, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=180)
            healed = True
            time.sleep(10)
            continue
        # Server reporting healthy? (or up with no healthcheck defined)
        hr = subprocess.run(_sudo_wrap(['docker', 'inspect', '--format', '{{.State.Health.Status}}', 'authentik-server-1']), capture_output=True, text=True, timeout=10)
        status = (hr.stdout or '').strip()
        if status == 'healthy':
            return True
        if status in ('', '<no value>') and not stopped:
            return True  # running, no healthcheck — best signal we have
        if time.time() - last_log > 25:
            plog(f"  … waiting for Authentik server to become healthy (status: {status or 'unknown'})")
            last_log = time.time()
        time.sleep(8)
    plog(f"  ⚠ Authentik server did not report healthy within {timeout}s — proceeding (sync may need a retry/Resync)")
    return False


def _sync_authentik_ldap_sa_with_retry(plog, attempts=3):
    """v10.0.1: Wait for Authentik to be healthy, then run the LDAP service-account
    sync, retrying on a TRANSIENT Authentik API failure (500/502/503/timeout/DNS) —
    the fresh-deploy window where authentik-server is briefly unhealthy. a25cd5d added
    the SA-sync call but not this robustness, so a single API 500 left 8446 on WebTAK.
    Returns (ok, msg)."""
    last = (False, '')
    for i in range(attempts):
        _wait_for_authentik_stack_healthy(plog, timeout=240 if i == 0 else 90)
        try:
            ok, msg = _ensure_authentik_ldap_service_account()
        except Exception as e:
            ok, msg = False, f'exception: {str(e)[:120]}'
        last = (ok, msg)
        if ok:
            return ok, msg
        transient = any(s in (msg or '') for s in
            ('500', '502', '503', 'timed out', 'timeout', "Can't contact",
             'Temporary failure', 'Connection refused', 'not ready'))
        if not transient or i == attempts - 1:
            return ok, msg
        plog(f"  ℹ LDAP SA-sync attempt {i + 1} hit a transient Authentik error "
             f"({(msg or '')[:70]}) — waiting for Authentik to settle and retrying…")
        time.sleep(20)
    return last


@app.route('/authentik')
@login_required
def authentik_page():
    modules = detect_modules()
    ak = modules.get('authentik', {})
    settings = load_settings()
    # Reset deploy_done once Authentik is running so the running view shows
    if ak.get('installed') and ak.get('running') and not authentik_deploy_status.get('running', False):
        authentik_deploy_status.update({'complete': False, 'error': False})
    container_info = {}
    ak_port = '9090'
    if ak.get('installed'):
        env_path = os.path.expanduser('~/authentik/.env')
        if os.path.exists(env_path):
            with open(env_path) as f:
                for line in f:
                    if line.strip().startswith('COMPOSE_PORT_HTTP='):
                        val = line.strip().split('=', 1)[1].strip()
                        if ':' in val: ak_port = val.split(':')[-1]
                        else: ak_port = val or '9090'
    if ak.get('running'):
        ak_deploy = _get_module_deployment_config(settings, 'authentik_deployment')
        docker_cmd = 'docker ps --filter "name=authentik" --format "{{.Names}}|||{{.Status}}" 2>/dev/null'
        if ak_deploy.get('target_mode') == 'remote' and (ak_deploy.get('remote', {}).get('host') or '').strip():
            ok, out = _ssh_probe(ak_deploy['remote'], docker_cmd, timeout=15)
            raw = out or ''
        else:
            r = subprocess.run(docker_cmd, shell=True, capture_output=True, text=True)
            raw = r.stdout or ''
        containers = []
        for line in raw.strip().split('\n'):
            if line.strip():
                parts = line.split('|||')
                containers.append({'name': parts[0], 'status': parts[1] if len(parts) > 1 else ''})
        # Fetch per-container CPU/RAM for the service cards (non-blocking; ignore errors)
        _stats_cmd = 'docker stats --no-stream --format "{{.Name}}|||{{.CPUPerc}}|||{{.MemUsage}}" 2>/dev/null'
        _stats_by_name = {}
        try:
            if ak_deploy.get('target_mode') == 'remote' and (ak_deploy.get('remote', {}).get('host') or '').strip():
                _ok_s, _stats_raw = _ssh_probe(ak_deploy['remote'], _stats_cmd, timeout=20)
                _stats_raw = (_stats_raw or '') if _ok_s else ''
            else:
                _sr = subprocess.run(_stats_cmd, shell=True, capture_output=True, text=True, timeout=15)
                _stats_raw = _sr.stdout or ''
            for _sl in _stats_raw.strip().split('\n'):
                if not _sl.strip():
                    continue
                _sp = _sl.split('|||')
                if len(_sp) >= 3:
                    _cn = _sp[0].strip().lstrip('/')
                    _cpu_s = _sp[1].strip().rstrip('%')
                    _mem_s = _sp[2].strip().split('/')[0].strip()
                    try:
                        _stats_by_name[_cn] = {'cpu_raw': round(float(_cpu_s), 1), 'mem': _mem_s}
                    except ValueError:
                        pass
        except Exception:
            pass
        _vcpu = None
        try:
            if ak_deploy.get('target_mode') == 'remote' and (ak_deploy.get('remote', {}).get('host') or '').strip():
                _vcpu = _get_vcpu_count_remote(ak_deploy.get('remote', {}))
            else:
                _vcpu = _get_vcpu_count_local()
        except Exception:
            pass
        for _c in containers:
            _s = _stats_by_name.get(_c['name'], {})
            if _s:
                _raw = _s['cpu_raw']
                _sys = round(_raw / _vcpu, 1) if (_vcpu and _vcpu > 1) else _raw
                _c['cpu_raw'] = _raw
                _c['cpu_sys'] = _sys
                _c['mem'] = _s['mem']
        container_info['containers'] = containers
        container_info['vcpu_count'] = _vcpu
    modules = detect_modules()
    portal_installed = modules.get('takportal', {}).get('installed', False)
    portal_running = modules.get('takportal', {}).get('running', False)
    all_healthy = ak.get('installed') and ak.get('running') and all(
        'unhealthy' not in c.get('status', '') for c in container_info.get('containers', [])
    ) and len(container_info.get('containers', [])) > 0
    authentik_deploy_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    remote_host = None
    if authentik_deploy_cfg.get('target_mode') == 'remote':
        remote_host = (authentik_deploy_cfg.get('remote', {}).get('host') or '').strip() or None
    return render_template_string(AUTHENTIK_TEMPLATE,
        settings=settings, ak=ak, container_info=container_info,
        ak_port=ak_port, authentik_base_url=_get_authentik_base_url(settings),
        takserver_base_url=_get_takserver_base_url(settings), version=VERSION,
        ak_version_info=_get_authentik_version_info(),
        deploying=authentik_deploy_status.get('running', False),
        deploy_done=authentik_deploy_status.get('complete', False),
        deploy_error=authentik_deploy_status.get('error', False),
        error_log_exists=os.path.exists(os.path.join(CONFIG_DIR, 'authentik_error.log')),
        all_healthy=all_healthy,
        portal_installed=portal_installed,
        portal_running=portal_running,
        authentik_deploy_cfg=authentik_deploy_cfg,
        remote_host=remote_host,
        vcpu_count=container_info.get('vcpu_count'))

@app.route('/api/authentik/control', methods=['POST'])
@login_required
def authentik_control():
    action = request.json.get('action')
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    if deploy_cfg.get('target_mode') == 'remote':
        remote = deploy_cfg.get('remote', {})
        if not (remote.get('host') or '').strip():
            return jsonify({'error': 'Remote host not configured'}), 400
        ak_dir = '~/authentik'
        _ssh_probe(remote, f'docker network inspect {INFRATAK_DOCKER_NETWORK} >/dev/null 2>&1 || docker network create {INFRATAK_DOCKER_NETWORK}', timeout=10)
        if action == 'start':
            _ssh_probe(remote, f'cd {ak_dir} && docker compose up -d 2>&1', timeout=120)
        elif action == 'stop':
            _ssh_probe(remote, f'cd {ak_dir} && docker compose stop 2>&1', timeout=60)
        elif action == 'restart':
            _ssh_probe(remote, f'cd {ak_dir} && docker compose down --timeout 30 2>&1 && docker compose up -d 2>&1', timeout=180)
        elif action == 'update':
            latest = _get_authentik_target_release(settings)
            _ssh_probe(remote, f"cd {ak_dir} && sed -i 's/AUTHENTIK_TAG:-[^}}]*/AUTHENTIK_TAG:-{latest}/g' docker-compose.yml 2>/dev/null", timeout=10)
            _ssh_probe(remote, f'cd {ak_dir} && docker compose pull 2>&1 && docker compose down --timeout 30 2>&1 && docker compose up -d 2>&1', timeout=360)
        else:
            return jsonify({'error': 'Invalid action'}), 400
        time.sleep(3)
        ok, out = _ssh_probe(remote, 'docker ps --filter name=authentik-server --format "{{.Status}}"', timeout=10)
        running = bool(ok and out and 'Up' in out)
        return jsonify({'success': True, 'running': running, 'action': action})
    ak_dir = os.path.expanduser('~/authentik')
    _patch_authentik_compose_network()
    if action == 'start':
        subprocess.run(_sudo_wrap(['docker', 'compose', 'up', '-d']), cwd=ak_dir, capture_output=True, text=True, timeout=120)
    elif action == 'stop':
        subprocess.run(_sudo_wrap(['docker', 'compose', 'down']), cwd=ak_dir, capture_output=True, text=True, timeout=60)
    elif action == 'restart':
        _run_priv_chain([['docker', 'compose', 'down'], ['docker', 'compose', 'up', '-d']], 'and', timeout=120, cwd=ak_dir)
    elif action == 'update':
        import re as _re
        latest = _get_authentik_target_release(settings)
        cp = os.path.join(ak_dir, 'docker-compose.yml')
        if os.path.isfile(cp):
            with open(cp) as _f:
                _cc = _f.read()
            _new = _re.sub(r'AUTHENTIK_TAG:-[^}]+', f'AUTHENTIK_TAG:-{latest}', _cc)
            if _new != _cc:
                with open(cp, 'w') as _f:
                    _f.write(_new)
        _ensure_authentik_compose_patches(cp)
        _run_priv_chain([['docker', 'compose', 'pull'], ['docker', 'compose', 'down', '--timeout', '30'], ['docker', 'compose', 'up', '-d'], ['docker', 'image', 'prune', '-f']], 'and', timeout=360, cwd=ak_dir)
    else:
        return jsonify({'error': 'Invalid action'}), 400
    time.sleep(5)
    r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=authentik-server', '--format', '{{.Status}}']), capture_output=True, text=True)
    running = 'Up' in r.stdout
    _authentik_release_cache['tag'] = None
    return jsonify({'success': True, 'running': running, 'action': action})

@app.route('/api/authentik/deploy', methods=['POST'])
@login_required
def authentik_deploy():
    if authentik_deploy_status.get('running'):
        return jsonify({'error': 'Deployment already in progress'}), 409
    data = request.get_json() or {}
    if data.get('config'):
        settings = load_settings()
        cfg = _normalize_module_deployment_config(data['config'])
        settings['authentik_deployment'] = cfg
        save_settings(settings)
    authentik_deploy_log.clear()
    authentik_deploy_status.update({'running': True, 'complete': False, 'error': False})
    threading.Thread(target=run_authentik_deploy, args=(False,), daemon=True).start()
    return jsonify({'success': True})

def _authentik_installed_for_reconfigure():
    """True if Authentik is present so Update config is allowed. Checks: remote deployed, compose file, docker container, or HTTP reachable."""
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    if deploy_cfg.get('target_mode') == 'remote' and deploy_cfg.get('deployed') and (deploy_cfg.get('remote', {}).get('host') or '').strip():
        return True
    if os.path.exists(os.path.expanduser('~/authentik/docker-compose.yml')):
        return True
    try:
        r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=authentik-server', '--format', '{{.Names}}']), capture_output=True, text=True, timeout=5)
        if r.returncode == 0 and r.stdout and 'authentik' in (r.stdout or '').strip().lower():
            return True
    except Exception:
        pass
    try:
        import urllib.request
        url = _get_authentik_api_url(settings).rstrip('/') + '/'
        req = urllib.request.Request(url, method='GET')
        urllib.request.urlopen(req, timeout=5)
        return True
    except Exception:
        pass
    return False


@app.route('/api/authentik/container-stats')
@login_required
def authentik_container_stats():
    """Return per-container CPU (system-normalized %) + RAM for the Authentik service cards."""
    settings = load_settings()
    deploy_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    _stats_cmd = 'docker stats --no-stream --format "{{.Name}}|||{{.CPUPerc}}|||{{.MemUsage}}" 2>/dev/null'
    _stats_raw = ''
    _is_remote = deploy_cfg.get('target_mode') == 'remote' and (deploy_cfg.get('remote', {}).get('host') or '').strip()
    try:
        if _is_remote:
            _ok, _stats_raw = _ssh_probe(deploy_cfg['remote'], _stats_cmd, timeout=20)
            if not _ok:
                _stats_raw = ''
        else:
            _r = subprocess.run(_stats_cmd, shell=True, capture_output=True, text=True, timeout=15)
            _stats_raw = _r.stdout or ''
    except Exception:
        pass
    _vcpu = None
    try:
        _vcpu = _get_vcpu_count_remote(deploy_cfg['remote']) if _is_remote else _get_vcpu_count_local()
    except Exception:
        pass
    result = {}
    for _sl in (_stats_raw or '').strip().split('\n'):
        if not _sl.strip():
            continue
        _sp = _sl.split('|||')
        if len(_sp) >= 3:
            _cn = _sp[0].strip().lstrip('/')
            _cpu_s = _sp[1].strip().rstrip('%')
            _mem_s = _sp[2].strip().split('/')[0].strip()
            if not _cn.startswith('authentik'):
                continue
            try:
                _raw = round(float(_cpu_s), 1)
                _sys = round(_raw / _vcpu, 1) if (_vcpu and _vcpu > 1) else _raw
                result[_cn] = {'cpu_raw': _raw, 'cpu_sys': _sys, 'mem': _mem_s, 'vcpu_count': _vcpu}
            except ValueError:
                pass
    return jsonify(result)


@app.route('/api/authentik/reconfigure', methods=['POST'])
@login_required
def authentik_reconfigure():
    """Re-run LDAP/CoreConfig/forward-auth setup without removing anything. Use when TAK Server was deployed after Authentik."""
    if authentik_deploy_status.get('running'):
        return jsonify({'error': 'Deployment already in progress'}), 409
    if not _authentik_installed_for_reconfigure():
        return jsonify({'error': 'Authentik not installed. Deploy Authentik first.'}), 400
    authentik_deploy_log.clear()
    authentik_deploy_status.update({'running': True, 'complete': False, 'error': False})
    threading.Thread(target=run_authentik_deploy, args=(True,), daemon=True).start()
    return jsonify({'success': True})

