@app.route('/api/takserver/connect-ldap', methods=['POST'])
@login_required
def takserver_connect_ldap():
    """One-shot: fix LDAP blueprint (remove recursion-causing password_stage), fix flow auth, ensure LDAP app open to all users (QR registration), ensure service account, ensure webadmin, patch CoreConfig, restart TAK Server."""
    diag = []
    settings = load_settings()
    ak_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
    is_remote_ak = ak_cfg.get('target_mode') == 'remote' and (ak_cfg.get('remote', {}).get('host') or '').strip()
    # For remote Authentik, verify API reachability first (console must reach Authentik host:9090)
    if is_remote_ak:
        ok_api, err_api = _check_authentik_api_reachable(settings)
        if not ok_api:
            return jsonify({'success': False, 'message': err_api or 'Authentik API unreachable'}), 400
    # Fix LDAP blueprint if it has the broken password_stage (causes "invalid credentials" / recursion on user bind). Same fix for local or remote.
    if is_remote_ak:
        ok_bp, out = _module_run(ak_cfg, "grep -q 'password_stage: !KeyOf ldap-authentication-password' ~/authentik/blueprints/tak-ldap-setup.yaml 2>/dev/null && sed -i '/password_stage: !KeyOf ldap-authentication-password/d' ~/authentik/blueprints/tak-ldap-setup.yaml && cd ~/authentik && docker compose restart worker 2>&1; echo BP_DONE", timeout=120)
        if ok_bp and 'BP_DONE' in (out or ''):
            diag.append('LDAP blueprint checked on remote (flow fix via API runs next)')
            if 'restart' in (out or '').lower():
                time.sleep(10)  # allow worker to reconcile if we restarted it
        elif not ok_bp:
            diag.append('Blueprint fix on remote: skip or failed (flow fix via API will still run)')
    else:
        bp_path = os.path.expanduser('~/authentik/blueprints/tak-ldap-setup.yaml')
        if os.path.exists(bp_path):
            try:
                with open(bp_path, 'r') as f:
                    content = f.read()
                if 'password_stage: !KeyOf ldap-authentication-password' in content:
                    content = content.replace('      password_stage: !KeyOf ldap-authentication-password\n', '')
                    with open(bp_path, 'w') as f:
                        f.write(content)
                    subprocess.run(_sudo_wrap(['docker', 'compose', 'restart', 'worker']), cwd=os.path.expanduser('~/authentik'), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, timeout=90)
                    time.sleep(50)  # let blueprint reconcile and update identification stage
                    diag.append('LDAP blueprint fixed (removed password_stage); worker restarted')
            except Exception as e:
                diag.append(f'Blueprint fix: {str(e)[:80]}')
    # Fix flow (clear identification password_stage, ensure 3 ldap-* bindings) so user bind / QR works
    ok_flow, err_flow = _ensure_ldap_flow_authentication_none()
    if not ok_flow:
        diag.append(f'Flow fix: {err_flow}')
        msg = ' | '.join(diag)
        if is_remote_ak:
            msg += '. For remote Authentik ensure this host can reach the Authentik server on port 9090 (firewall).'
        return jsonify({'success': False, 'message': msg}), 400
    diag.append('Flow: OK')
    # Ensure LDAP app has no restrictive policy (blocks QR registration for non-admin users)
    try:
        settings = load_settings()
        ak_token = _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN') or _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN')
        if ak_token:
            ak_url = _get_authentik_api_url(settings)
            _ensure_app_access_policies(ak_url, {'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'}, lambda m: diag.append(m.strip()))
            diag.append('App policies: LDAP open to all authenticated users')
    except Exception as e:
        diag.append(f'App policies: {str(e)[:60]}')
    # Resync LDAP credential BEFORE bind test so drifted password can't block the fix
    changed, resync_msg = _resync_ldap_credential_to_coreconfig()
    if changed:
        diag.append(f'Credential resync: {resync_msg}')
    # v10.0.1: wait for Authentik healthy (self-heal a stopped container) + retry on
    # a transient API 500 — on an unhealthy fresh-deploy Authentik this button used to
    # fail with "Authentik API 500: <!DOCTYPE html>…" and leave 8446 on WebTAK.
    ok, msg = _sync_authentik_ldap_sa_with_retry(lambda m: diag.append(m.strip()))
    if not ok:
        if '-w' in (msg or ''):
            msg = 'ldapsearch timed out or failed (check Authentik LDAP outpost logs)'
        diag.append(f'Service account: LDAP bind failed ({msg}) — continuing with CoreConfig patch')
    else:
        diag.append(f'Service account: {msg}')
    ok_wa, err_wa = _ensure_authentik_webadmin()
    if not ok_wa:
        diag.append(f'WebAdmin: {err_wa}')
    else:
        diag.append('WebAdmin: OK')
    _remove_webadmin_from_userauth()
    diag.append('Removed flat-file webadmin shadow if present (8446 → LDAP)')
    ok, msg = _apply_ldap_to_coreconfig()
    diag.append(f'CoreConfig: {msg}')
    # Run the proactive FQDN routing migration directly from the manual repair button, BEFORE the
    # bind verification below. Previously this only fired from a full deploy or the webadmin-sync
    # 'inconclusive' branch — so on a box stranded on internal routing (hard 'fail' verdict) the
    # operator's "Resync LDAP" click never actually moved the outpost off the spiral-prone path.
    # The migration is self-contained (recreates only the ldap container, validates the websocket
    # connection, auto-rolls-back if FQDN isn't viable), so it's safe to invoke here. Visible output.
    try:
        _ensure_authentik_ldap_outpost_on_fqdn(lambda m: diag.append(m.strip()))
    except Exception as _e:
        diag.append(f'Proactive routing: skipped ({str(_e)[:80]})')
    # Diagnostic: compare passwords and check outpost health
    try:
        settings = load_settings()
        ldap_pass = _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_LDAPSERVICE_PASSWORD')
        import re as _re
        cc_pass = ''
        if os.path.exists('/opt/tak/CoreConfig.xml'):
            with open('/opt/tak/CoreConfig.xml') as f:
                m = _re.search(r'serviceAccountCredential="([^"]*)"', f.read())
                cc_pass = m.group(1) if m else ''
        if ldap_pass and cc_pass:
            diag.append(f'Password match: {"YES" if ldap_pass == cc_pass else "NO (MISMATCH!)"}')
        elif not cc_pass:
            diag.append('Password: not in CoreConfig')
        ak_cfg = _get_module_deployment_config(settings, 'authentik_deployment')
        if ak_cfg.get('target_mode') == 'remote' and (ak_cfg.get('remote', {}).get('host') or '').strip():
            ok_ssh, out = _ssh_probe(ak_cfg['remote'], 'docker ps --filter name=authentik-ldap --format "{{.Status}}" 2>/dev/null', timeout=10)
            ldap_status = (out or '').strip()
            diag.append(f'LDAP outpost: {ldap_status or "not running"}')
            ok_ssh2, out2 = _ssh_probe(ak_cfg['remote'], 'docker logs authentik-ldap-1 --since 60s 2>&1 | tail -25', timeout=15)
            outpost_tail = (out2 or '').strip()
        else:
            r = subprocess.run(_sudo_wrap(['docker', 'ps', '--filter', 'name=authentik-ldap', '--format', '{{.Status}}']), capture_output=True, text=True, timeout=10)
            ldap_status = (r.stdout or '').strip()
            diag.append(f'LDAP outpost: {ldap_status or "not running"}')
            r = _priv_pipe(['docker', 'logs', 'authentik-ldap-1', '--since', '60s'], ['tail', '-25'], timeout=10)
            outpost_tail = (r.stdout or '').strip()
        if outpost_tail:
            # Classify the bind OUTCOME up front — the result line was previously cut off by the
            # 200-char truncation, which hid whether the failure was a flow spiral (slow-disk /
            # recursion), a real password mismatch, or actually a success that verification missed.
            _low = outpost_tail.lower()
            if 'exceeded stage recursion depth' in _low or 'nil pointer dereference' in _low:
                diag.append('Outpost verdict: FLOW SPIRAL (stage recursion) — bind-flow recursion, NOT a bad password')
            elif 'invalid credentials' in _low or 'access denied' in _low or 'insufficient access' in _low:
                diag.append('Outpost verdict: INVALID CREDENTIALS — password mismatch (re-set webadmin pw + Sync webadmin)')
            elif 'authenticated' in _low:
                diag.append('Outpost verdict: AUTHENTICATED — bind succeeded (verification may be falsely red)')
            elif 'failed to execute flow' in _low or 'ak-stage-flow-error' in _low or 'flow error' in _low:
                diag.append('Outpost verdict: FLOW ERROR — bind flow could not complete (check ldap-* flow bindings)')
            # Surface the outcome-bearing lines (not just the last 5), and raise the cap so the
            # decisive line is never cut. Fall back to the raw tail if no marker matched.
            _markers = ('authenticated', 'invalid credentials', 'access denied', 'recursion',
                        'flow error', 'failed to execute flow', 'ak-stage-flow-error', 'bind request')
            _hot = [ln for ln in outpost_tail.splitlines() if any(m in ln.lower() for m in _markers)]
            _show = '\n'.join(_hot[-8:]) if _hot else outpost_tail
            diag.append(f'Outpost log: {_show[:800]}')
    except Exception as e:
        diag.append(f'Diagnostic error: {str(e)[:100]}')
    # Post-fix verification signals (best-effort)
    try:
        verify = {}
        verify['coreconfig_has_ldap'] = bool(_coreconfig_has_ldap())
        ws = _get_authentik_webadmin_status()
        verify['webadmin_exists_in_authentik'] = bool(ws.get('exists'))
        verify['webadmin_superuser'] = bool(ws.get('is_superuser'))
        ldap_pass = _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_LDAPSERVICE_PASSWORD') or ''
        verify['service_bind_seen'] = bool(_test_ldap_bind(ldap_pass)) if ldap_pass else False
        wap = (settings.get('webadmin_password') or '').strip()
        # Tri-state verdict ('ok' | 'fail' | 'inconclusive'). The boolean wrapper used to
        # conflate 'fail' and 'inconclusive' as False, so a box where ldapsearch couldn't be
        # installed (apt lock / no network during deploy) ALWAYS reported webadmin-bind=FAIL and
        # a scary "NOT READY (verification failed)" — even when the bind actually worked. We now
        # distinguish a CONFIRMED failure (real problem) from "could not verify" (probably fine).
        wa_verdict = _test_ldap_bind_dn_verdict('cn=webadmin,ou=users,dc=takldap', wap) if wap else 'fail'
        verify['webadmin_bind'] = wa_verdict
        verify['webadmin_bind_seen'] = (wa_verdict == 'ok')
        core_ok = all([
            verify['coreconfig_has_ldap'],
            verify['webadmin_exists_in_authentik'],
            verify['webadmin_superuser'],
        ])
        verify['ready'] = bool(core_ok and wa_verdict == 'ok')
        verify['unverified'] = bool(core_ok and wa_verdict == 'inconclusive')
        diag.append(
            "Verification: coreconfig={} webadmin={} superuser={} webadmin-bind={} ready={}".format(
                'OK' if verify['coreconfig_has_ldap'] else 'FAIL',
                'OK' if verify['webadmin_exists_in_authentik'] else 'FAIL',
                'OK' if verify['webadmin_superuser'] else 'FAIL',
                {'ok': 'OK', 'fail': 'FAIL', 'inconclusive': 'UNVERIFIED'}.get(wa_verdict, 'FAIL'),
                'YES' if verify['ready'] else ('UNVERIFIED' if verify['unverified'] else 'NO'),
            )
        )
    except Exception as e:
        verify = {'ready': False, 'error': str(e)[:120]}
        diag.append(f'Verification: ERROR ({str(e)[:80]})')
    # An 'inconclusive' webadmin bind (core config all good but ldapsearch unavailable) is NOT a
    # failure — report success with a clear UNVERIFIED caveat and the manual 8446 test as the next
    # step, instead of a false-red dead end. Only a CONFIRMED 'fail' blocks success.
    if verify.get('unverified'):
        overall_ok = bool(ok)
        diag.append('Final: READY (webadmin bind UNVERIFIED — ldapsearch unavailable; confirm by logging in at '
                    ':8446. If 8446 rejects the password, run: docker logs authentik-ldap-1 --since 2m — a '
                    '"stage recursion" line means the bind-flow spiral, "invalid credentials" means a password mismatch)')
    else:
        overall_ok = bool(ok and verify.get('ready', True))
        diag.append('Final: READY' if overall_ok else 'Final: NOT READY (verification failed)')
    return jsonify({'success': overall_ok, 'message': ' | '.join(diag), 'verification': verify})


@app.route('/api/takserver/ldap-drift-check')
@login_required
def takserver_ldap_drift_check():
    """Compare LDAP service-account password in Authentik .env vs CoreConfig.xml.

    Returns {match: bool, detail: str} so the frontend can warn on drift.
    """
    settings = load_settings()
    coreconfig = '/opt/tak/CoreConfig.xml'
    env_pass = _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_LDAPSERVICE_PASSWORD')
    env_src = 'authentik'
    if env_pass is None:
        portal_env = os.path.expanduser('~/tak-portal/.env')
        if os.path.isfile(portal_env):
            try:
                with open(portal_env) as f:
                    for line in f:
                        if line.strip().startswith('AUTHENTIK_BOOTSTRAP_LDAPSERVICE_PASSWORD='):
                            env_pass = line.strip().split('=', 1)[1].strip()
                            env_src = portal_env
                            break
            except Exception:
                pass
    if not os.path.exists(coreconfig):
        return jsonify({'match': True, 'detail': 'no_coreconfig'})
    try:
        with open(coreconfig, 'r') as f:
            cc = f.read()
    except Exception:
        return jsonify({'match': True, 'detail': 'coreconfig_unreadable'})
    if 'adm_ldapservice' not in cc:
        return jsonify({'match': True, 'detail': 'no_ldap_in_coreconfig'})
    import re as _re
    m = _re.search(r'serviceAccountCredential="([^"]*)"', cc)
    if not m:
        return jsonify({'match': True, 'detail': 'no_credential_attr'})
    cc_pass = m.group(1)

    if env_pass is None:
        return jsonify({'match': True, 'detail': 'no_env_password_found'})

    if cc_pass == env_pass:
        return jsonify({'match': True, 'detail': 'ok', 'source': env_src})
    return jsonify({
        'match': False,
        'detail': 'LDAP credential drift detected — CoreConfig.xml password does not match Authentik .env. Click Resync LDAP to fix.',
        'source': env_src
    })


_vacuum_status = {'running': False, 'full': False, 'started': None, 'result': None, 'error': None}

def _run_vacuum_background(use_full, tak_cfg):
    vacuum_sql = "VACUUM FULL;" if use_full else "VACUUM ANALYZE;"
    timeout_sec = 3600 if use_full else 600
    _vacuum_status.update({'running': True, 'full': use_full, 'started': datetime.now().isoformat(), 'result': None, 'error': None})
    try:
        if tak_cfg.get('mode') == 'two_server':
            s1 = tak_cfg.get('server_one', {})
            # cd / first: SSH lands in /root, and `sudo -u postgres` can't cd there, which
            # prints a benign "could not change directory to /root: Permission denied" warning
            # into the output and reads as a failure even though VACUUM ran. (Local path uses cwd='/'.)
            vacuum_cmd = f"cd / && sudo -u postgres psql -d cot -c '{vacuum_sql}' 2>&1"
            ok, out = _ssh_probe(s1, vacuum_cmd, timeout=timeout_sec)
            if not ok:
                _vacuum_status.update({'running': False, 'error': (out or 'SSH command failed')[:500]})
                return
            _vacuum_status.update({'running': False, 'result': (out or '').strip()})
        else:
            r = _pg_exec(['psql', '-d', 'cot', '-c', vacuum_sql], timeout=timeout_sec)
            out = (r.stdout or '') + (r.stderr or '')
            if r.returncode != 0:
                _vacuum_status.update({'running': False, 'error': out.strip() or f'Exit code {r.returncode}'})
                return
            _vacuum_status.update({'running': False, 'result': out.strip()})
    except subprocess.TimeoutExpired:
        _vacuum_status.update({'running': False, 'error': 'VACUUM timed out (database may be very large)'})
    except Exception as e:
        _vacuum_status.update({'running': False, 'error': str(e)[:200]})

@app.route('/api/takserver/vacuum', methods=['POST'])
@login_required
def takserver_vacuum():
    """Run VACUUM on the CoT database in background. Returns immediately, poll /api/takserver/vacuum/status."""
    if not os.path.exists('/opt/tak'):
        return jsonify({'success': False, 'error': 'TAK Server not installed'}), 400
    if _vacuum_status['running']:
        return jsonify({'success': False, 'error': 'VACUUM already running', 'status': 'running', 'full': _vacuum_status['full'], 'started': _vacuum_status['started']}), 409
    data = request.get_json() or {}
    use_full = data.get('full') is True
    settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    if tak_cfg.get('mode') == 'two_server':
        s1 = tak_cfg.get('server_one', {})
        if not s1.get('host'):
            return jsonify({'success': False, 'error': 'Server One host not configured'}), 400
    threading.Thread(target=_run_vacuum_background, args=(use_full, tak_cfg), daemon=True).start()
    return jsonify({'success': True, 'status': 'started', 'full': use_full})

@app.route('/api/takserver/vacuum/status')
@login_required
def takserver_vacuum_status():
    """Poll VACUUM progress. Also checks PostgreSQL directly for running VACUUM."""
    running = _vacuum_status['running']
    full = _vacuum_status['full']
    elapsed_secs = 0
    if not running:
        try:
            check_sql = "SELECT query, extract(epoch from now() - query_start)::int AS secs FROM pg_stat_activity WHERE query ILIKE '%VACUUM%' AND state = 'active' AND pid != pg_backend_pid() LIMIT 1;"
            settings = load_settings()
            tak_cfg = _get_tak_deployment_config(settings)
            if tak_cfg.get('mode') == 'two_server':
                s1 = tak_cfg.get('server_one', {})
                if s1.get('host'):
                    ok, out = _ssh_probe(s1, f'sudo -u postgres psql -t -A -d cot -c "{check_sql}" 2>/dev/null', timeout=10)
                    raw = (out or '').strip()
            else:
                r = _pg_exec(['psql', '-t', '-A', '-d', 'cot', '-c', check_sql], timeout=10)
                raw = (r.stdout or '').strip()
            if raw and 'VACUUM' in raw.upper():
                running = True
                full = 'FULL' in raw.upper()
                parts = raw.split('|')
                elapsed_secs = int(parts[-1]) if len(parts) > 1 and parts[-1].strip().isdigit() else 0
        except Exception:
            pass
    if running and not elapsed_secs and _vacuum_status.get('started'):
        try:
            st = datetime.fromisoformat(_vacuum_status['started'])
            elapsed_secs = int((datetime.now() - st).total_seconds())
        except Exception:
            pass
    return jsonify({
        'running': running,
        'full': full,
        'elapsed_secs': elapsed_secs,
        'result': _vacuum_status['result'],
        'error': _vacuum_status['error'],
    })


@app.route('/api/takserver/reindex', methods=['POST'])
@login_required
def takserver_reindex():
    """Run REINDEX on the CoT database to rebuild indexes and improve query performance."""
    if not os.path.exists('/opt/tak'):
        return jsonify({'success': False, 'error': 'TAK Server not installed'}), 400
    reindex_sql = "REINDEX DATABASE cot;"
    timeout_sec = 3600

    settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    if tak_cfg.get('mode') == 'two_server':
        s1 = tak_cfg.get('server_one', {})
        if not s1.get('host'):
            return jsonify({'success': False, 'error': 'Server One host not configured'}), 400
        # cd / first (see VACUUM note): avoids the benign "/root: Permission denied" warning leaking into output.
        reindex_cmd = f"cd / && sudo -u postgres psql -d cot -c '{reindex_sql}' 2>&1"
        ok, out = _ssh_probe(s1, reindex_cmd, timeout=timeout_sec)
        if not ok:
            return jsonify({'success': False, 'error': (out or 'SSH command failed')[:500]}), 400
        return jsonify({'success': True, 'output': (out or '').strip(), 'remote': True})

    try:
        r = _pg_exec(['psql', '-d', 'cot', '-c', reindex_sql], timeout=timeout_sec)
        out = (r.stdout or '') + (r.stderr or '')
        if r.returncode != 0:
            return jsonify({'success': False, 'error': out.strip() or f'Exit code {r.returncode}'}), 400
        return jsonify({'success': True, 'output': out.strip()})
    except subprocess.TimeoutExpired:
        return jsonify({'success': False, 'error': 'REINDEX timed out (database may be very large)'}), 400
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:200]}), 500


@app.route('/api/takserver/cot-db-size')
@login_required
def takserver_cot_db_size():
    """Return CoT database size in bytes and human-readable (for UI)."""
    if not os.path.exists('/opt/tak'):
        return jsonify({'size_bytes': 0, 'size_human': 'N/A', 'error': 'TAK Server not installed'})
    size_cmd = "sudo -u postgres psql -t -A -c \"SELECT COALESCE(pg_database_size('cot'), 0);\" 2>/dev/null"
    try:
        settings = load_settings()
        tak_cfg = _get_tak_deployment_config(settings)
        if tak_cfg.get('mode') == 'two_server':
            s1 = tak_cfg.get('server_one', {})
            if not s1.get('host'):
                return jsonify({'size_bytes': 0, 'size_human': 'N/A', 'error': 'Server One host not configured'})
            ok, out = _ssh_probe(s1, size_cmd, timeout=15)
            raw = (out or '0').strip()
        else:
            r = _pg_exec(['psql', '-t', '-A', '-c', "SELECT COALESCE(pg_database_size('cot'), 0);"], timeout=10)
            raw = (r.stdout or '0').strip()
        size = int(raw or 0)
        if size >= 1024 ** 3:
            human = f'{size // (1024**3)} GB'
        elif size >= 1024 ** 2:
            human = f'{size // (1024**2)} MB'
        elif size >= 1024:
            human = f'{size // 1024} KB'
        else:
            human = f'{size} B'
        # Additional stats
        msg_count = 0
        dead_tuples = 0
        try:
            stats_sql = "SELECT COALESCE((SELECT SUM(n_live_tup) FROM pg_stat_user_tables), 0), COALESCE((SELECT SUM(n_dead_tup) FROM pg_stat_user_tables), 0);"
            if tak_cfg.get('mode') == 'two_server':
                ok2, out2 = _ssh_probe(s1, f'sudo -u postgres psql -t -A -d cot -c "{stats_sql}" 2>/dev/null', timeout=15)
                parts = (out2 or '0|0').strip().split('|')
            else:
                r2 = _pg_exec(['psql', '-t', '-A', '-d', 'cot', '-c', stats_sql], timeout=10)
                parts = (r2.stdout or '0|0').strip().split('|')
            msg_count = int(parts[0]) if len(parts) > 0 and parts[0].strip().isdigit() else 0
            dead_tuples = int(parts[1]) if len(parts) > 1 and parts[1].strip().isdigit() else 0
        except Exception:
            pass
        return jsonify({'size_bytes': size, 'size_human': human, 'message_count': msg_count, 'dead_tuples': dead_tuples})
    except Exception as e:
        return jsonify({'size_bytes': 0, 'size_human': 'N/A', 'error': str(e)[:200]})


@app.route('/api/takserver/cert-expiry')
@login_required
def takserver_cert_expiry():
    """Return Root CA and Intermediate CA expiry dates and days remaining."""
    cert_dir = '/opt/tak/certs/files'
    results = {}
    for label, filename in [('root_ca', 'root-ca.pem'), ('intermediate_ca', 'ca.pem')]:
        path = os.path.join(cert_dir, filename)
        if not os.path.exists(path):
            results[label] = {'error': 'Not found', 'file': filename}
            continue
        try:
            r = subprocess.run(
                ['openssl', 'x509', '-enddate', '-noout', '-in', path],
                capture_output=True, text=True, timeout=5
            )
            if r.returncode != 0:
                results[label] = {'error': 'Failed to read cert'}
                continue
            raw = r.stdout.strip().split('=', 1)[-1]
            from datetime import datetime
            expiry = datetime.strptime(raw, '%b %d %H:%M:%S %Y %Z')
            now = datetime.utcnow()
            days_left = (expiry - now).days
            results[label] = {
                'file': filename,
                'expires': expiry.strftime('%Y-%m-%d'),
                'days_left': days_left
            }
        except Exception as e:
            results[label] = {'error': str(e)[:200]}
    return jsonify(results)


@app.route('/api/fedhub/cert-expiry')
@login_required
def fedhub_cert_expiry():
    """Return Federation Hub Root CA and Intermediate CA expiry (local or remote). Same shape as /api/takserver/cert-expiry."""
    settings = load_settings()
    cfg = _get_fedhub_deployment_config(settings)
    if not cfg.get('deployed'):
        return jsonify({'root_ca': {'error': 'Not deployed'}, 'intermediate_ca': {'error': 'Not deployed'}})
    is_remote = cfg.get('target_mode') == 'remote'
    remote = cfg.get('remote', {})
    if is_remote and not (remote.get('host') or '').strip():
        return jsonify({'root_ca': {'error': 'No host'}, 'intermediate_ca': {'error': 'No host'}})
    fh_dir = '/opt/tak/federation-hub/certs/files'
    results = {}
    for label, filename in [('root_ca', 'root-ca.pem'), ('intermediate_ca', 'ca.pem')]:
        path = f'{fh_dir}/{filename}'
        cmd = f'openssl x509 -enddate -noout -in {shlex.quote(path)} 2>/dev/null'
        ok, out = _module_run(cfg, cmd, timeout=15)
        if not ok or not (out or '').strip() or 'notAfter' not in out:
            results[label] = {'error': 'Not found', 'file': filename}
            continue
        try:
            raw = out.strip().split('=', 1)[-1].strip()
            from datetime import datetime
            expiry = datetime.strptime(raw, '%b %d %H:%M:%S %Y %Z')
            now = datetime.utcnow()
            days_left = (expiry - now).days
            results[label] = {
                'file': filename,
                'expires': expiry.strftime('%Y-%m-%d'),
                'days_left': days_left,
            }
        except Exception as e:
            results[label] = {'error': str(e)[:200], 'file': filename}
    return jsonify(results)


def _canonical_tak_group_name(value):
    """Normalize TAK group names to a canonical channel name.

    We intentionally collapse TAK Portal directional suffix groups
    (e.g. *_READ, *_WRITE, *_BOTH) to the base name so cert assignment
    targets the same channel identity.
    """
    name = str(value or '').strip()
    if not name:
        return ''
    m = re.match(r'^(.*?)(?:[_-](?:read|write|both))$', name, re.IGNORECASE)
    if m:
        base = (m.group(1) or '').strip()
        if base:
            return base
    return name


def _exclude_from_cert_group_picker(name):
    """Return True for system/admin groups we do not want in cert picker."""
    n = str(name or '').strip()
    if not n:
        return True
    lowered = n.lower()
    if lowered == '__anon__':
        return True
    if lowered == 'role_admin':
        return True
    if lowered.startswith('authentik'):
        return True
    if lowered.startswith('cn=tak_'):
        return True
    if lowered in ('vid_public', 'vid_private'):
        return True
    return False


@app.route('/api/takserver/groups')
@login_required
def takserver_groups():
    """List groups from TAK Server APIs using admin cert.

    We merge:
    - /Marti/api/groups/all
    - /user-management/api/list-groupnames
    so TAK Portal-created groups can still appear in certificate workflows.
    """
    settings = load_settings()
    cert_dir = '/opt/tak/certs/files'
    cert_pass = _get_tak_cert_password(settings)
    admin_p12 = os.path.join(cert_dir, 'admin.p12')
    if not os.path.exists(admin_p12):
        return jsonify({'error': 'admin.p12 not found in /opt/tak/certs/files/', 'groups': []})
    try:
        # TAK Server generates legacy PKCS12 (RC2-40-CBC) that modern curl/OpenSSL 3.x
        # rejects (exit 58). Extract PEM cert+key with -legacy flag for curl.
        admin_pem = '/tmp/tak-admin-curl.pem'
        admin_key = '/tmp/tak-admin-curl.key'
        # v10.0.5 non-root: admin.p12 is 0600 tak:tak — cat it via the broker into a temp so
        # openssl can read it (raw openssl as takwerx -> empty PEM -> "Failed to extract").
        import tempfile as _tf
        _src_p12, _tmp_src = admin_p12, None
        try:
            _cat = subprocess.run(_sudo_wrap(['cat', admin_p12]), capture_output=True, timeout=10)
            if _cat.returncode == 0 and _cat.stdout:
                _fd, _tmp_src = _tf.mkstemp(suffix='.p12')
                with os.fdopen(_fd, 'wb') as _f:
                    _f.write(_cat.stdout)
                _src_p12 = _tmp_src
        except Exception:
            pass
        subprocess.run(
            f'openssl pkcs12 -in {_src_p12} -passin pass:{shlex.quote(cert_pass)} -clcerts -nokeys -legacy 2>/dev/null > {admin_pem}',
            shell=True, capture_output=True, text=True, timeout=10)
        subprocess.run(
            f'openssl pkcs12 -in {_src_p12} -passin pass:{shlex.quote(cert_pass)} -nocerts -nodes -legacy 2>/dev/null > {admin_key}',
            shell=True, capture_output=True, text=True, timeout=10)
        if _tmp_src:
            try:
                os.remove(_tmp_src)
            except Exception:
                pass
        if not os.path.exists(admin_pem) or os.path.getsize(admin_pem) == 0:
            return jsonify({'error': 'Failed to extract PEM from admin.p12 (legacy conversion)', 'groups': []})
        import json as _json
        def _curl_json(url):
            cmd = ['curl', '-sk', '--max-time', '8',
                   '--cert', admin_pem, '--key', admin_key, url]
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=12)
            body = (r.stdout or '').strip()
            if r.returncode != 0 or not body:
                return None, f'curl_exit_{r.returncode}'
            try:
                return _json.loads(body), None
            except _json.JSONDecodeError:
                return None, 'invalid_json'

        merged = {}
        warnings = []

        marti_data, marti_err = _curl_json('https://127.0.0.1:8443/Marti/api/groups/all')
        if marti_data is not None:
            items = marti_data.get('data', marti_data) if isinstance(marti_data, dict) else marti_data
            if isinstance(items, list):
                for g in items:
                    if not isinstance(g, dict):
                        continue
                    name = _canonical_tak_group_name(g.get('name'))
                    if _exclude_from_cert_group_picker(name):
                        continue
                    merged[name] = {
                        'name': name,
                        'direction': g.get('direction', ''),
                        'active': g.get('active', True)
                    }
        elif marti_err:
            warnings.append(f'marti_groups:{marti_err}')

        um_data, um_err = _curl_json('https://127.0.0.1:8443/user-management/api/list-groupnames')
        if um_data is not None:
            items = um_data.get('data', um_data) if isinstance(um_data, dict) else um_data
            if isinstance(items, list):
                for g in items:
                    if isinstance(g, str):
                        name = _canonical_tak_group_name(g)
                    elif isinstance(g, dict):
                        name = _canonical_tak_group_name(
                            g.get('name')
                            or g.get('groupName')
                            or g.get('groupname')
                            or g.get('group')
                            or ''
                        )
                    else:
                        name = ''
                    if _exclude_from_cert_group_picker(name):
                        continue
                    if name not in merged:
                        merged[name] = {
                            'name': name,
                            'direction': '',
                            'active': True
                        }
        elif um_err:
            warnings.append(f'user_mgmt_groups:{um_err}')

        # Also pull tak_* groups directly from Authentik so newly-created groups
        # appear in the picker before first user login hits TAK.
        ak_token = _get_authentik_env_value(settings, 'AUTHENTIK_BOOTSTRAP_TOKEN') or _get_authentik_env_value(settings, 'AUTHENTIK_TOKEN')
        if ak_token:
            try:
                import urllib.request as _req
                import urllib.parse as _parse
                ak_url = _get_authentik_api_url(settings)
                next_url = f'{ak_url}/api/v3/core/groups/?page_size=200&name__istartswith=tak_'
                seen = 0
                while next_url and seen < 2000:
                    req = _req.Request(next_url, headers={'Authorization': f'Bearer {ak_token}', 'Content-Type': 'application/json'})
                    with _req.urlopen(req, timeout=12) as resp:
                        page = _json.loads((resp.read() or b'').decode('utf-8', 'replace'))
                    results = page.get('results', []) if isinstance(page, dict) else []
                    for g in results:
                        raw = (g.get('name') or '').strip() if isinstance(g, dict) else ''
                        if not raw:
                            continue
                        name = raw[4:] if raw.lower().startswith('tak_') else raw
                        name = _canonical_tak_group_name(name)
                        if _exclude_from_cert_group_picker(name):
                            continue
                        if name not in merged:
                            merged[name] = {
                                'name': name,
                                'direction': '',
                                'active': True
                            }
                    seen += len(results)
                    nxt = page.get('next') if isinstance(page, dict) else None
                    if not nxt:
                        next_url = None
                    elif str(nxt).startswith('http'):
                        next_url = str(nxt)
                    else:
                        next_url = _parse.urljoin(ak_url, str(nxt))
            except Exception as e:
                warnings.append(f'authentik_groups:{str(e)[:80]}')

        groups = sorted(merged.values(), key=lambda x: x['name'].lower())
        if not groups and warnings:
            return jsonify({'error': '; '.join(warnings), 'groups': []})
        if warnings:
            return jsonify({'groups': groups, 'warnings': warnings})
        return jsonify({'groups': groups})
    except Exception as e:
        return jsonify({'error': str(e)[:200], 'groups': []})
    finally:
        for f in ['/tmp/tak-admin-curl.pem', '/tmp/tak-admin-curl.key']:
            try:
                os.remove(f)
            except OSError:
                pass


@app.route('/api/takserver/ca-info')
@login_required
def takserver_ca_info():
    """Return current Root CA and Intermediate CA names, expiry, and truststore contents."""
    cert_dir = '/opt/tak/certs/files'
    cert_pass = _get_tak_cert_password(load_settings())
    info = {'root_ca': None, 'intermediate_ca': None, 'old_cas_in_truststore': [], 'suggested_new_name': ''}
    for label, filename in [('root_ca', 'root-ca.pem'), ('intermediate_ca', 'ca.pem')]:
        path = os.path.join(cert_dir, filename)
        if not os.path.exists(path):
            continue
        try:
            r = subprocess.run(['openssl', 'x509', '-subject', '-enddate', '-noout', '-in', path],
                               capture_output=True, text=True, timeout=5)
            cn = ''
            expiry_raw = ''
            for line in r.stdout.strip().split('\n'):
                line = line.strip()
                if line.startswith('subject=') or line.startswith('subject ='):
                    subj = line.split('=', 1)[-1].strip()
                    for part in subj.split(','):
                        part = part.strip()
                        if part.startswith('CN') or part.startswith('CN '):
                            cn = part.split('=', 1)[-1].strip()
                elif 'notAfter' in line:
                    expiry_raw = line.split('=', 1)[-1].strip()
            days_left = None
            expires = ''
            if expiry_raw:
                from datetime import datetime
                exp_dt = datetime.strptime(expiry_raw, '%b %d %H:%M:%S %Y %Z')
                days_left = (exp_dt - datetime.utcnow()).days
                expires = exp_dt.strftime('%Y-%m-%d')
            info[label] = {'name': cn, 'file': filename, 'expires': expires, 'days_left': days_left}
        except Exception:
            pass
    import re
    def _increment_name(name):
        m = re.search(r'(\d+)$', name)
        if m:
            return name[:m.start()] + f'{int(m.group(1)) + 1:02d}'
        return name + '-02'
    if info['intermediate_ca'] and info['intermediate_ca']['name']:
        info['suggested_new_name'] = _increment_name(info['intermediate_ca']['name'])
    if info['root_ca'] and info['root_ca']['name']:
        info['suggested_new_root_name'] = _increment_name(info['root_ca']['name'])
        info['suggested_new_root_int_name'] = _increment_name(info.get('suggested_new_name', 'INT-CA-01'))
    # List CAs in current truststore (to show old CAs that can be revoked)
    import glob as _glob
    ts_files = sorted(_glob.glob(os.path.join(cert_dir, 'truststore-*.jks')))
    ts_files = [f for f in ts_files if 'root' not in os.path.basename(f)]
    if ts_files:
        ts_path = ts_files[-1]
        info['truststore_file'] = os.path.basename(ts_path)
        try:
            if _tak_is_container():
                # v10.0.1: no host keytool on a container box (JDK is inside the container) —
                # list the truststore inside the running TAK container so old CAs are detected
                # and the 'Revoke Old CA' box actually appears on arm64.
                _kt = f'keytool -list -keystore {shlex.quote(ts_path)} -storepass {shlex.quote(cert_pass)}'
                r = subprocess.run(f'docker exec {TAK_CONTAINER} bash -c {shlex.quote(_kt)}',
                                   shell=True, capture_output=True, text=True, timeout=15)
            else:
                r = subprocess.run(
                    ['keytool', '-list', '-keystore', ts_path, '-storepass', cert_pass],
                    capture_output=True, text=True, timeout=10)
            aliases = []
            trusted_aliases = []
            for line in r.stdout.split('\n'):
                if ',' not in line:
                    continue
                alias = line.split(',')[0].strip()
                if 'trustedCertEntry' in line:
                    aliases.append(alias)
                    trusted_aliases.append(alias)
                elif 'PrivateKeyEntry' in line:
                    aliases.append(alias)
            info['truststore_aliases'] = aliases
            current_cn = (info['intermediate_ca'] or {}).get('name', '').lower()
            root_cn = (info['root_ca'] or {}).get('name', '').lower()
            old_cas = []
            skip_aliases = {'mykey'}  # legacy default alias, not a CA to revoke
            for a in trusted_aliases:
                if a.lower() in skip_aliases:
                    continue
                if a.lower() != current_cn.lower() and a.lower() != 'root-ca' and a.lower() != root_cn.lower():
                    old_cas.append(a)
            info['old_cas_in_truststore'] = old_cas
        except Exception:
            pass
    return jsonify(info)


rotate_intca_log = []
rotate_intca_status = {'running': False, 'complete': False, 'error': False}

@app.route('/api/takserver/rotate-intca', methods=['POST'])
@login_required
def takserver_rotate_intca():
    """Rotate the intermediate CA: create new CA, server cert, admin cert, import old CA into truststore."""
    if rotate_intca_status.get('running'):
        return jsonify({'error': 'Rotation already in progress'}), 409
    data = request.json or {}
    new_ca_name = (data.get('new_ca_name') or '').strip()
    if not new_ca_name:
        return jsonify({'error': 'New CA name is required'}), 400
    import re
    if not re.match(r'^[a-zA-Z0-9._-]+$', new_ca_name):
        return jsonify({'error': 'CA name can only contain letters, numbers, dots, hyphens, underscores'}), 400

    cert_dir = '/opt/tak/certs/files'
    if not os.path.exists(os.path.join(cert_dir, 'root-ca.pem')):
        return jsonify({'error': 'root-ca.pem not found — cannot rotate without a Root CA'}), 400
    if not os.path.exists(os.path.join(cert_dir, 'ca.pem')):
        return jsonify({'error': 'ca.pem not found — no current intermediate CA detected'}), 400

    # Detect current intermediate CA name
    try:
        r = subprocess.run(['openssl', 'x509', '-subject', '-noout', '-in', os.path.join(cert_dir, 'ca.pem')],
                           capture_output=True, text=True, timeout=5)
        old_ca_name = ''
        for part in r.stdout.replace('subject=', '').split(','):
            part = part.strip()
            if part.startswith('CN') or part.startswith('CN '):
                old_ca_name = part.split('=', 1)[-1].strip()
    except Exception:
        old_ca_name = ''
    if not old_ca_name:
        return jsonify({'error': 'Could not detect current intermediate CA name from ca.pem'}), 500
    if new_ca_name == old_ca_name:
        return jsonify({'error': f'New CA name must be different from current ({old_ca_name})'}), 400

    # Optional new cert password (save so thread uses it for new keystores)
    new_cert_password = (data.get('new_cert_password') or '').strip()
    if new_cert_password:
        settings = load_settings()
        settings['tak_cert_password'] = new_cert_password
        save_settings(settings)
    cert_pass = _get_tak_cert_password(load_settings())

    # Root CA days left — cap new intermediate validity to this
    root_days_left = None
    try:
        r = subprocess.run(['openssl', 'x509', '-enddate', '-noout', '-in', os.path.join(cert_dir, 'root-ca.pem')],
                           capture_output=True, text=True, timeout=5)
        if r.returncode == 0 and r.stdout:
            from datetime import datetime
            expiry_raw = r.stdout.strip().split('=', 1)[-1].strip()
            exp_dt = datetime.strptime(expiry_raw, '%b %d %H:%M:%S %Y %Z')
            root_days_left = (exp_dt - datetime.utcnow()).days
    except Exception:
        pass

    try:
        requested_validity = int(data.get('intermediate_validity_days') or 730)
        requested_validity = max(1, min(3652, requested_validity))
    except (TypeError, ValueError):
        requested_validity = 730
    int_validity_days = min(requested_validity, root_days_left) if root_days_left is not None and root_days_left > 0 else requested_validity
    if root_days_left is not None and requested_validity > root_days_left:
        pass  # already capped to root_days_left in int_validity_days

    rotate_intca_log.clear()
    rotate_intca_status.update({'running': True, 'complete': False, 'error': False})

    def do_rotate():
        def log(msg):
            rotate_intca_log.append(msg)

        def run(cmd, desc=None, check=True):
            if desc:
                log(desc)
            cmd = _rotate_tak_cert_cmd(cmd)  # v10.0.1: container-aware (runuser/chown/systemctl → docker)
            try:
                r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=120)
                if check and r.returncode != 0:
                    err = (r.stderr or r.stdout or '').strip()[:200]
                    log(f"  ✗ Failed (exit {r.returncode}): {err}")
                    return False
                return True
            except Exception as e:
                log(f"  ✗ Exception: {e}")
                return False

        try:
            log(f"━━━ Rotating Intermediate CA ━━━")
            log(f"  Old CA: {old_ca_name}")
            log(f"  New CA: {new_ca_name}")
            log("")

            # Save current (old) intermediate to a named file before we overwrite ca.pem — needed for transition bundle and truststore
            old_pem = os.path.join(cert_dir, f'{old_ca_name}.pem')
            if not os.path.exists(old_pem):
                run(f'cp {cert_dir}/ca.pem {old_pem}')
                log(f"  Saved current CA to {old_ca_name}.pem for transition bundle")

            log("Step 1/7: Restoring Root CA as working CA...")
            run(f'cp {cert_dir}/root-ca.pem {cert_dir}/ca.pem')
            run(f'cp {cert_dir}/root-ca-do-not-share.key {cert_dir}/ca-do-not-share.key')
            run(f'cp {cert_dir}/root-ca-trusted.pem {cert_dir}/ca-trusted.pem')
            log("✓ Root CA files restored")

            _patch_openssl_string_mask()

            log("")
            log(f"Step 2/7: Creating new Intermediate CA: {new_ca_name}...")
            run('chown tak:tak /opt/tak/certs/cert-metadata.sh && chmod 500 /opt/tak/certs/cert-metadata.sh')
            run(f'grep -qE "^CA_VALIDITY=" /opt/tak/certs/cert-metadata.sh 2>/dev/null && sed -i "s/^CA_VALIDITY=.*/CA_VALIDITY={int_validity_days}/" /opt/tak/certs/cert-metadata.sh || true', check=False)
            run(f'grep -qE "^INTERMEDIATE_VALIDITY" /opt/tak/certs/cert-metadata.sh 2>/dev/null && sed -i "s/^INTERMEDIATE_VALIDITY.*/INTERMEDIATE_VALIDITY={int_validity_days}/" /opt/tak/certs/cert-metadata.sh || true', check=False)
            log(f"  New intermediate validity: {int_validity_days} days (capped by root if needed)")
            _patch_cert_metadata_password(cert_pass)
            if not run(f'cd /opt/tak/certs && echo "y" | runuser -u tak -- /opt/tak/certs/makeCert.sh ca "{new_ca_name}" 2>&1'):
                raise Exception('Failed to create new intermediate CA')
            log(f"✓ Intermediate CA {new_ca_name} created")

            log("")
            log("Step 3/7: Creating new server certificate (signed by new CA)...")
            if not run(f'cd /opt/tak/certs && echo "y" | runuser -u tak -- /opt/tak/certs/makeCert.sh server takserver 2>&1'):
                raise Exception('Failed to create new server certificate')
            log("✓ Server certificate regenerated (signed by new CA)")

            log("")
            log("Step 4/7: Regenerating all client certificates...")
            run('chown tak:tak /opt/tak/certs/cert-metadata.sh && chmod 500 /opt/tak/certs/cert-metadata.sh')
            skip = {'takserver', 'root-ca', 'ca', old_ca_name.lower(), new_ca_name.lower()}
            regen_count = 0
            for f in sorted(os.listdir(cert_dir)):
                if not f.endswith('.p12'):
                    continue
                name = f[:-4]
                if name.lower() in skip or name.startswith('truststore-'):
                    continue
                log(f"  Regenerating: {name}")
                run(f'cd /opt/tak/certs && echo "y" | runuser -u tak -- /opt/tak/certs/makeCert.sh client {name} 2>&1')
                regen_count += 1
            log(f"✓ {regen_count} client certificate(s) regenerated (signed by new CA)")

            log("")
            log("Step 5/7: Updating truststore...")
            ts_jks = os.path.join(cert_dir, f'truststore-{new_ca_name}.jks')
            # v10.0.5 non-root: bare keytool writes JKS into tak-owned /opt/tak/certs/files
            # and fails as takwerx — route via the broker-allowed `runuser -u tak -- keytool`.
            run(f'runuser -u tak -- keytool -import -alias root-ca -file {cert_dir}/root-ca.pem '
                f'-keystore {ts_jks} -storepass {shlex.quote(cert_pass)} -noprompt 2>&1', check=False)
            log("  Root CA imported into new truststore")
            old_pem = os.path.join(cert_dir, f'{old_ca_name}.pem')
            if os.path.exists(old_pem):
                run(f'runuser -u tak -- keytool -import -trustcacerts -file {old_pem} '
                    f'-keystore {ts_jks} -alias "{old_ca_name}" -deststorepass {shlex.quote(cert_pass)} -noprompt 2>&1',
                    check=False)
                log(f"  Old CA ({old_ca_name}) imported into new truststore (transition period)")
            else:
                log(f"  ⚠ {old_ca_name}.pem not found — old CA NOT added to truststore")
            log("✓ Truststore updated")

            log("")
            log("Step 6/7: Updating CoreConfig.xml...")
            # v10.0.5 non-root: sed isn't broker-routed + /opt/tak is tak:tak — rewrite
            # CoreConfig via broker read-modify-write.
            for _cc in ('/opt/tak/CoreConfig.xml', '/opt/tak/CoreConfig.example.xml'):
                try:
                    _t = _read_priv(_cc)
                    if old_ca_name in _t:
                        _write_priv(_cc, _t.replace(old_ca_name, new_ca_name))
                except Exception:
                    pass
            _patch_coreconfig_passwords(cert_pass, log_fn=log)
            log("✓ CoreConfig.xml updated")

            log("")
            log("Step 7/7: Updating TAK Portal certificates...")
            # v10.0.1: delegate to _takportal_sync_certs — refreshes client cert +
            # CA via a temp-file re-encode (the old stdin pipe failed on OpenSSL 3
            # and shipped an unreadable legacy cert). restart=True so the portal
            # picks up the new CA-signed cert.
            _tp_ok, _tp_msg = _takportal_sync_certs(plog=log, restart=True)
            log(f"  {'✓' if _tp_ok else '⚠'} TAK Portal cert sync: {_tp_msg}")

            log("")
            log("Restarting TAK Server...")
            ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
            if ne_changed:
                log(f"  NameEntry fix: {ne_msg}")
            changed, resync_msg = _resync_ldap_credential_to_coreconfig()
            if changed:
                log(f"  LDAP resync: {resync_msg}")
            run('systemctl restart takserver 2>&1')
            log("  Waiting for TAK Server to come back up...")
            time.sleep(45)
            log("✓ TAK Server restarted")

            log("")
            log("━━━ ROTATION COMPLETE ━━━")
            log(f"  New CA: {new_ca_name}")
            log(f"  Server cert + all client certs signed by new CA")
            log(f"  Old CA ({old_ca_name}) in truststore — server still accepts old client certs during transition")
            log(f"  Existing ATAK clients must re-enroll (new QR) to get the new CA")
            log(f"  When everyone has re-enrolled, use 'Revoke Old CA' to remove {old_ca_name}")
            rotate_intca_status.update({'running': False, 'complete': True, 'error': False})
        except Exception as e:
            log(f"")
            log(f"✗ ROTATION FAILED: {e}")
            rotate_intca_status.update({'running': False, 'complete': True, 'error': True})

    import threading
    threading.Thread(target=do_rotate, daemon=True).start()
    return jsonify({'started': True, 'old_ca': old_ca_name, 'new_ca': new_ca_name})


@app.route('/api/takserver/rotate-intca/status')
@login_required
def takserver_rotate_intca_status():
    return jsonify({'log': rotate_intca_log, **rotate_intca_status})


@app.route('/api/takserver/revoke-old-ca', methods=['POST'])
@login_required
def takserver_revoke_old_ca():
    """Create new server cert (signed by current/new CA), remove old CA from truststore, restart. Cuts off clients with old certs."""
    data = request.json or {}
    old_ca_alias = (data.get('old_ca_alias') or '').strip()
    if not old_ca_alias:
        return jsonify({'error': 'Old CA alias is required'}), 400

    cert_dir = '/opt/tak/certs/files'
    cert_pass = _get_tak_cert_password(load_settings())
    import glob as _glob
    ts_files = sorted(_glob.glob(os.path.join(cert_dir, 'truststore-*.jks')))
    ts_files = [f for f in ts_files if 'root' not in os.path.basename(f)]
    if not ts_files:
        return jsonify({'error': 'No truststore found'}), 500
    ts_path = ts_files[-1]

    try:
        # 1) Create new server cert (signed by current = new CA) so server presents new chain. Skip if using Let's Encrypt.
        le_jks = os.path.join(cert_dir, 'takserver-le.jks')
        if not os.path.isfile(le_jks):
            r = subprocess.run(
                _rotate_tak_cert_cmd('cd /opt/tak/certs && echo "y" | runuser -u tak -- /opt/tak/certs/makeCert.sh server takserver 2>&1'),
                shell=True, capture_output=True, text=True, timeout=120)
            if r.returncode != 0:
                return jsonify({'error': f'Creating new server cert failed: {(r.stderr or r.stdout or "")[:200]}'}), 500
            # Build JKS from new takserver.p12 so server can use it (CoreConfig may reference takserver.jks or we update connector)
            p12 = os.path.join(cert_dir, 'takserver.p12')
            jks = os.path.join(cert_dir, 'takserver.jks')
            if os.path.isfile(p12):
                subprocess.run(
                    _rotate_tak_cert_cmd(
                        f'runuser -u tak -- keytool -importkeystore -srcstoretype PKCS12 -srckeystore {p12} -srcstorepass {shlex.quote(cert_pass)} '
                        f'-deststoretype JKS -destkeystore {jks} -deststorepass {shlex.quote(cert_pass)} -noprompt 2>&1'),
                    shell=True, capture_output=True, text=True, timeout=30)

        # 2) Remove old CA from truststore
        r = subprocess.run(
            _rotate_tak_cert_cmd(
                f'runuser -u tak -- keytool -delete -alias {shlex.quote(old_ca_alias)} '
                f'-keystore {shlex.quote(ts_path)} -storepass {shlex.quote(cert_pass)} 2>&1'),
            shell=True, capture_output=True, text=True, timeout=15)
        if r.returncode != 0:
            return jsonify({'error': f'keytool failed: {r.stderr or r.stdout}'}), 500

        # 3) Regenerate .p12 truststore
        ts_p12 = ts_path.replace('.jks', '.p12')
        subprocess.run(
            _rotate_tak_cert_cmd(
                f'runuser -u tak -- keytool -importkeystore -srckeystore {ts_path} -destkeystore {ts_p12} '
                f'-srcstoretype JKS -deststoretype PKCS12 -srcstorepass {shlex.quote(cert_pass)} -deststorepass {shlex.quote(cert_pass)} -noprompt 2>&1'),
            shell=True, capture_output=True, text=True, timeout=15)

        if _tak_is_container():
            subprocess.run(_sudo_wrap(['docker', 'restart', 'takserver']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=120)
        else:
            subprocess.run(_sudo_wrap(['systemctl', 'restart', 'takserver']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=90)

        # 4) Update TAK Portal certs so it can talk to TAK Server (new server cert / chain)
        # v10.0.1: delegate to _takportal_sync_certs (temp-file re-encode of the
        # client cert + CA; restart so the portal picks up the new chain).
        _takportal_sync_certs(restart=True)

        msg = (f'Removed {old_ca_alias} from truststore and restarted TAK Server. '
               f'Server cert is now signed by the new CA (clients who re-enrolled via CloudTAK/QR can connect). '
               f'TAK Portal certs updated. Clients still using certs signed by {old_ca_alias} must re-enroll.')
        if os.path.isfile(le_jks):
            msg = (f'Removed {old_ca_alias} from truststore and restarted TAK Server. '
                   f'(Server TLS is Let\'s Encrypt; unchanged.) Clients with certs signed by {old_ca_alias} must re-enroll.')
        return jsonify({'success': True, 'message': msg})
    except Exception as e:
        return jsonify({'error': str(e)[:200]}), 500


rotate_rootca_log = []
rotate_rootca_status = {'running': False, 'complete': False, 'error': False}

@app.route('/api/takserver/rotate-rootca', methods=['POST'])
@login_required
def takserver_rotate_rootca():
    """Full Root CA rotation: new root, new intermediate, new server cert, all client certs, update TAK Portal, restart."""
    if rotate_rootca_status.get('running'):
        return jsonify({'error': 'Root CA rotation already in progress'}), 409
    data = request.json or {}
    new_root_name = (data.get('new_root_name') or '').strip()
    new_int_name = (data.get('new_int_name') or '').strip()
    if not new_root_name or not new_int_name:
        return jsonify({'error': 'Both new Root CA and Intermediate CA names are required'}), 400
    import re
    for name in [new_root_name, new_int_name]:
        if not re.match(r'^[a-zA-Z0-9._-]+$', name):
            return jsonify({'error': f'CA name "{name}" can only contain letters, numbers, dots, hyphens, underscores'}), 400

    # Optional new cert password (save so thread uses it for new keystores)
    new_cert_password = (data.get('new_cert_password') or '').strip()
    if new_cert_password:
        settings = load_settings()
        settings['tak_cert_password'] = new_cert_password
        save_settings(settings)
    cert_pass = _get_tak_cert_password(load_settings())

    cert_dir = '/opt/tak/certs/files'
    if not os.path.exists(os.path.join(cert_dir, 'root-ca.pem')):
        return jsonify({'error': 'root-ca.pem not found — no current Root CA detected'}), 400

    # Detect current names
    old_root_name = ''
    old_int_name = ''
    for label, filename in [('root', 'root-ca.pem'), ('int', 'ca.pem')]:
        path = os.path.join(cert_dir, filename)
        if not os.path.exists(path):
            continue
        try:
            r = subprocess.run(['openssl', 'x509', '-subject', '-noout', '-in', path],
                               capture_output=True, text=True, timeout=5)
            for line in r.stdout.strip().split('\n'):
                if line.startswith('subject=') or line.startswith('subject ='):
                    subj = line.split('=', 1)[-1].strip()
                    for part in subj.split(','):
                        part = part.strip()
                        if part.startswith('CN') or part.startswith('CN '):
                            cn = part.split('=', 1)[-1].strip()
                            if label == 'root':
                                old_root_name = cn
                            else:
                                old_int_name = cn
        except Exception:
            pass
    if not old_root_name:
        return jsonify({'error': 'Could not detect current Root CA name'}), 500

    rotate_rootca_log.clear()
    rotate_rootca_status.update({'running': True, 'complete': False, 'error': False})

    def do_rotate_root():
        def log(msg):
            rotate_rootca_log.append(msg)

        def run(cmd, desc=None, check=True):
            if desc:
                log(desc)
            cmd = _rotate_tak_cert_cmd(cmd)  # v10.0.1: container-aware (runuser/chown/systemctl → docker)
            try:
                r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=120)
                if check and r.returncode != 0:
                    err = (r.stderr or r.stdout or '').strip()[:200]
                    log(f"  ✗ Failed (exit {r.returncode}): {err}")
                    return False
                return True
            except Exception as e:
                log(f"  ✗ Exception: {e}")
                return False

        try:
            log("━━━ Rotating Root CA ━━━")
            log(f"  Old Root CA: {old_root_name}")
            log(f"  Old Intermediate CA: {old_int_name}")
            log(f"  New Root CA: {new_root_name}")
            log(f"  New Intermediate CA: {new_int_name}")
            log("")

            log("Step 1/8: Removing old certificate files...")
            if _tak_is_container():
                # v10.0.1: the cert files are owned by the container uid, so a HOST `rm -rf`
                # as takwerx SILENTLY fails and the old truststore-*.jks survives — then Step 6's
                # `keytool -import -alias root-ca` hits the existing `root-ca` alias and is dropped
                # (check=False), so the new ROOT CA never lands in the truststore and EUDs get
                # "cert not trusted". Clear the dir INSIDE the container (root there) so the
                # rotation starts from a clean slate, exactly like the native rm does. The native
                # branch below is byte-identical to before — Ubuntu/Rocky are untouched.
                _tak_real = os.path.realpath('/opt/tak')
                run(f"docker run --rm -v {shlex.quote(_tak_real)}:/opt/tak:z --entrypoint bash "
                    f"{TAK_CONTAINER} -c 'rm -rf /opt/tak/certs/files && mkdir -p /opt/tak/certs/files' 2>&1")
            else:
                run('rm -rf /opt/tak/certs/files')
                run('mkdir -p /opt/tak/certs/files')
                run('chown -R tak:tak /opt/tak/certs/')
            log("✓ Old cert files cleared")

            _patch_openssl_string_mask()

            log("")
            log(f"Step 2/8: Creating new Root CA: {new_root_name}...")
            run('chown tak:tak /opt/tak/certs/cert-metadata.sh && chmod 500 /opt/tak/certs/cert-metadata.sh')
            _patch_cert_metadata_password(cert_pass)
            if not run(f'cd /opt/tak/certs && echo "{new_root_name}" | runuser -u tak -- /opt/tak/certs/makeRootCa.sh 2>&1'):
                raise Exception('Failed to create new Root CA')
            log(f"✓ Root CA {new_root_name} created")

            log("")
            log(f"Step 3/8: Creating new Intermediate CA: {new_int_name}...")
            if not run(f'cd /opt/tak/certs && echo "y" | runuser -u tak -- /opt/tak/certs/makeCert.sh ca "{new_int_name}" 2>&1'):
                raise Exception('Failed to create new Intermediate CA')
            log(f"✓ Intermediate CA {new_int_name} created")

            log("")
            log("Step 4/8: Creating new server certificate...")
            if not run('cd /opt/tak/certs && echo "y" | runuser -u tak -- /opt/tak/certs/makeCert.sh server takserver 2>&1'):
                raise Exception('Failed to create server certificate')
            log("✓ Server certificate created")

            log("")
            log("Step 5/8: Regenerating all client certificates...")
            skip = {'takserver', 'root-ca', 'ca', new_root_name.lower(), new_int_name.lower(),
                    old_root_name.lower(), old_int_name.lower()}
            # We need to create admin and user first since old files were cleared
            run('cd /opt/tak/certs && runuser -u tak -- /opt/tak/certs/makeCert.sh client admin 2>&1')
            log("  Regenerated: admin")
            run('cd /opt/tak/certs && runuser -u tak -- /opt/tak/certs/makeCert.sh client user 2>&1')
            log("  Regenerated: user")
            # Check settings or old backup for any other client cert names to recreate
            regen_count = 2
            log(f"✓ {regen_count} client certificate(s) created")
            log("  Note: Additional client certs (Node-RED, etc.) must be recreated manually")

            log("")
            log("Step 6/8: Updating truststore...")
            ts_jks = os.path.join(cert_dir, f'truststore-{new_int_name}.jks')
            # v10.0.5 non-root: route keytool via broker-allowed `runuser -u tak -- keytool`.
            run(f'runuser -u tak -- keytool -import -alias root-ca -file {cert_dir}/root-ca.pem '
                f'-keystore {ts_jks} -storepass {shlex.quote(cert_pass)} -noprompt 2>&1', check=False)
            log("  Root CA imported into truststore")
            log("✓ Truststore updated")

            log("")
            log("Step 7/8: Updating CoreConfig.xml...")
            # v10.0.5 non-root: sed isn't broker-routed + /opt/tak is tak:tak — rewrite
            # CoreConfig via broker read-modify-write.
            _repl = []
            if old_int_name:
                _repl.append((old_int_name, new_int_name))
            if old_root_name and old_root_name != new_root_name:
                _repl.append((old_root_name, new_root_name))
            for _cc in ('/opt/tak/CoreConfig.xml', '/opt/tak/CoreConfig.example.xml'):
                try:
                    _t = _read_priv(_cc); _orig = _t
                    for _o, _n in _repl:
                        _t = _t.replace(_o, _n)
                    if _t != _orig:
                        _write_priv(_cc, _t)
                except Exception:
                    pass
            _patch_coreconfig_passwords(cert_pass, log_fn=log)
            log("✓ CoreConfig.xml updated")

            log("")
            log("Step 8/8: Restarting TAK Server and updating TAK Portal...")
            ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
            if ne_changed:
                log(f"  NameEntry fix: {ne_msg}")
            changed, resync_msg = _resync_ldap_credential_to_coreconfig()
            if changed:
                log(f"  LDAP resync: {resync_msg}")
            run('systemctl restart takserver 2>&1')
            log("  TAK Server restarting...")

            # Copy new certs to TAK Portal if it's running
            portal_running = _priv_pipe(['docker', 'ps', '--format', '{{.Names}}'], ['grep', '-q', 'tak-portal']).returncode == 0
            if portal_running:
                log("  Updating TAK Portal certificates...")
                # v10.0.1: delegate to _takportal_sync_certs — temp-file re-encode
                # of the client cert + CA (the old stdin pipe failed on OpenSSL 3
                # and shipped an unreadable legacy cert). restart=True.
                _tp_ok, _tp_msg = _takportal_sync_certs(plog=log, restart=True)
                log(f"  {'✓' if _tp_ok else '⚠'} TAK Portal cert sync: {_tp_msg}")
            else:
                log("  TAK Portal not running — skip cert copy (will update on next TAK Portal deploy)")

            log("  Waiting for TAK Server to come back up...")
            time.sleep(45)
            log("✓ TAK Server restarted")

            log("")
            log("━━━ ROOT CA ROTATION COMPLETE ━━━")
            log(f"  New Root CA: {new_root_name}")
            log(f"  New Intermediate CA: {new_int_name}")
            log(f"  All certificates have been regenerated")
            if portal_running:
                log(f"  TAK Portal updated — users can scan new QR codes to re-enroll")
            log(f"  All existing client connections are disconnected")
            log(f"  Clients must re-enroll via TAK Portal QR code")
            rotate_rootca_status.update({'running': False, 'complete': True, 'error': False})
        except Exception as e:
            log(f"")
            log(f"✗ ROOT CA ROTATION FAILED: {e}")
            rotate_rootca_status.update({'running': False, 'complete': True, 'error': True})

    import threading
    threading.Thread(target=do_rotate_root, daemon=True).start()
    return jsonify({'started': True, 'old_root': old_root_name, 'new_root': new_root_name})


