@app.route('/api/takserver/create-client-cert', methods=['POST'])
@login_required
def takserver_create_client_cert():
    """Create a client certificate with optional group assignment."""
    data = request.json or {}
    cert_name = (data.get('name') or '').strip()
    if not cert_name:
        return jsonify({'error': 'Certificate name is required'}), 400
    import re
    if not re.match(r'^[a-zA-Z0-9._-]+$', cert_name):
        return jsonify({'error': 'Name can only contain letters, numbers, dots, hyphens, underscores'}), 400
    if len(cert_name) > 64:
        return jsonify({'error': 'Name too long (max 64 chars)'}), 400

    cert_dir = '/opt/tak/certs/files'
    if os.path.exists(os.path.join(cert_dir, f'{cert_name}.p12')):
        return jsonify({'error': f'Certificate "{cert_name}" already exists'}), 400

    def _normalize_groups(values):
        out = []
        seen = set()
        for v in (values or []):
            g = _canonical_tak_group_name(v)
            if not g:
                continue
            key = g.lower()
            if key in seen:
                continue
            seen.add(key)
            out.append(g)
        return out

    groups_in = _normalize_groups(data.get('groups_in', []))
    groups_out = _normalize_groups(data.get('groups_out', []))
    groups_both = _normalize_groups(data.get('groups_both', []))
    groups_in = [g for g in groups_in if g not in groups_both]
    groups_out = [g for g in groups_out if g not in groups_both]

    try:
        _patch_openssl_string_mask()
        if _tak_is_container():
            # container: no host `tak` user — chown tak:tak is invalid; just fix the mode (broker root)
            _run_priv_chain([['chmod', '500', '/opt/tak/certs/cert-metadata.sh']], 'and')
        else:
            _run_priv_chain([['chown', 'tak:tak', '/opt/tak/certs/cert-metadata.sh'], ['chmod', '500', '/opt/tak/certs/cert-metadata.sh']], 'and')
        r = subprocess.run(
            _rotate_tak_cert_cmd(f'cd /opt/tak/certs && runuser -u tak -- /opt/tak/certs/makeCert.sh client {cert_name} 2>&1'),
            shell=True, capture_output=True, text=True, timeout=30
        )
        if r.returncode != 0:
            return jsonify({'error': f'makeCert.sh failed: {r.stdout or r.stderr}'}), 500

        p12_path = os.path.join(cert_dir, f'{cert_name}.p12')
        if not os.path.exists(p12_path):
            return jsonify({'error': 'Certificate file was not created'}), 500

        if groups_in or groups_out or groups_both:
            pem_path = os.path.join(cert_dir, f'{cert_name}.pem')
            cmd = f'java -jar /opt/tak/utils/UserManager.jar certmod'
            for g in groups_both:
                cmd += f' -g {shlex.quote(g)}'
            for g in groups_in:
                cmd += f' -ig {shlex.quote(g)}'
            for g in groups_out:
                cmd += f' -og {shlex.quote(g)}'
            cmd += f' {shlex.quote(pem_path)}'
            # v10.0.1 container: java + UserManager.jar live ONLY inside the takserver container
            # (no host JDK), so run the group-assignment in-container; native path unchanged.
            full = _tak_exec(cmd) if _tak_is_container() else (cmd + ' 2>&1')
            gr = subprocess.run(full, shell=True, capture_output=True, text=True, timeout=15)
            if gr.returncode != 0:
                pass  # cert still created, group assignment is best-effort

        return jsonify({
            'success': True,
            'name': cert_name,
            'p12': f'{cert_name}.p12',
            'download_url': f'/api/certs/download/{cert_name}.p12',
            'groups_both': groups_both,
            'groups_in': groups_in,
            'groups_out': groups_out
        })
    except Exception as e:
        return jsonify({'error': str(e)[:200]}), 500


def _sync_webadmin_after_authentik_reconfigure(plog):
    """After Authentik reconfigure, regenerate Caddyfile and reload Caddy. Does NOT touch TAK Server or 8446 cert."""
    modules = detect_modules()
    if not modules.get('takserver', {}).get('installed'):
        return
    try:
        plog("  Syncing WebAdmin (Caddy reload only, no TAK restart)...")
        settings = load_settings()
        generate_caddyfile(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
        plog("  ✓ Caddy reloaded.")
    except Exception as e:
        plog(f"  ⚠ WebAdmin sync failed: {str(e)[:80]} — run Update config on TAK Server page if needed.")


def _run_takserver_update_config():
    """Regenerate Caddyfile, reload Caddy, re-install 8446 LE cert for current TAK Server hostname, restart TAK Server."""
    settings = load_settings()
    fqdn = settings.get('fqdn', '').strip()
    generate_caddyfile(settings)
    subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
    takserver_host = _get_service_domain(settings, 'takserver')
    if fqdn and takserver_host:
        caddy_active = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'caddy']), capture_output=True, text=True)
        if caddy_active.stdout.strip() == 'active':
            def _log(msg):
                print(msg, flush=True)
            install_le_cert_on_8446(takserver_host, _log, wait_for_cert=False)
    subprocess.run(_tak_systemctl('restart'), shell=True, capture_output=True, text=True, timeout=60)  # v10.0.1: container-aware
    takserver_update_config_status.update({'running': False, 'complete': True, 'error': False})

takserver_update_config_status = {'running': False, 'complete': False, 'error': False}

@app.route('/api/takserver/update-config', methods=['POST'])
@login_required
def takserver_update_config():
    """Sync Caddy + 8446 cert to current TAK Server domain and restart TAK Server. Use after changing TAK Server domain in Caddy/Domains."""
    if takserver_update_config_status.get('running'):
        return jsonify({'error': 'Update already in progress'}), 409
    modules = detect_modules()
    tak = modules.get('takserver', {})
    if not tak.get('installed'):
        return jsonify({'error': 'TAK Server not installed'}), 400
    takserver_update_config_status.update({'running': True, 'complete': False, 'error': False})
    def _run():
        try:
            _run_takserver_update_config()
        except Exception as e:
            takserver_update_config_status.update({'running': False, 'complete': True, 'error': True, 'message': str(e)[:200]})
    threading.Thread(target=_run, daemon=True).start()
    return jsonify({'success': True, 'message': 'Update config started. Caddy and 8446 cert (if applicable) will be updated; TAK Server will restart.'})

@app.route('/api/takserver/update-config/status')
@login_required
def takserver_update_config_status_api():
    return jsonify(takserver_update_config_status)

@app.route('/api/takserver/control', methods=['POST'])
@login_required
def takserver_control():
    action = request.json.get('action')
    target = request.json.get('target', 'core')  # core | database | both
    if action not in ['start', 'stop', 'restart']:
        return jsonify({'error': 'Invalid action'}), 400
    results = {}
    settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    is_two_server = tak_cfg.get('mode') == 'two_server'
    # Handle remote database (Server One)
    if is_two_server and target in ('database', 'both'):
        s1 = tak_cfg.get('server_one', {})
        if s1.get('host'):
            pg_action = 'restart' if action == 'restart' else action
            db_cmd = f'sudo pg_ctlcluster 15 main {pg_action} 2>&1 || sudo systemctl {pg_action} postgresql 2>&1'
            ok, out = _ssh_probe(s1, db_cmd, timeout=30)
            verify_ok, verify_out = _ssh_probe(s1, 'pg_isready -q && echo DB_OK', timeout=10)
            db_running = verify_ok and 'DB_OK' in (verify_out or '')
            results['database'] = {'success': ok or db_running, 'running': db_running, 'host': s1['host']}
        else:
            results['database'] = {'success': False, 'error': 'Server One host not configured'}
    # Handle local TAK Server (Core)
    if target in ('core', 'both'):
        if action in ('start', 'restart'):
            ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
            if ne_changed:
                results['nameentry_fix'] = ne_msg
            changed, msg = _resync_ldap_credential_to_coreconfig()
            if changed:
                results['ldap_resync'] = msg
        # v10.0.1: container-aware lifecycle — _tak_systemctl maps start/stop/
        # restart to `docker ...` in container mode (native systemctl on .deb).
        subprocess.run(_tak_systemctl(action), shell=True, capture_output=True, text=True, timeout=120)
        time.sleep(3)
        results['core'] = {'success': True, 'running': _takserver_running_local()}
    return jsonify({'success': True, 'results': results, 'action': action, 'target': target,
                    'running': results.get('core', {}).get('running', None)})

@app.route('/api/takserver/log')
@login_required
def takserver_log():
    """Tail the takserver-messaging.log file"""
    log_path = '/opt/tak/logs/takserver-messaging.log'
    offset = request.args.get('offset', 0, type=int)
    lines = request.args.get('lines', 100, type=int)
    if not os.path.exists(log_path):
        return jsonify({'entries': [], 'offset': 0, 'size': 0})
    try:
        size = os.path.getsize(log_path)
        if offset == 0:
            r = subprocess.run(f'tail -n {lines} "{log_path}"', shell=True, capture_output=True, text=True, timeout=10)
            entries = r.stdout.strip().split('\n') if r.stdout.strip() else []
            return jsonify({'entries': entries, 'offset': size, 'size': size})
        elif size > offset:
            with open(log_path, 'r') as f:
                f.seek(offset)
                new_data = f.read()
            entries = new_data.strip().split('\n') if new_data.strip() else []
            return jsonify({'entries': entries, 'offset': size, 'size': size})
        else:
            return jsonify({'entries': [], 'offset': offset, 'size': size})
    except Exception as e:
        return jsonify({'entries': [f'Error reading log: {str(e)[:200]}'], 'offset': offset, 'size': 0})

@app.route('/api/takserver/services')
@login_required
def takserver_services():
    """Get TAK Server Java process status"""
    services = []
    try:
        r = subprocess.run("ps aux | grep java | grep -v grep", shell=True, capture_output=True, text=True, timeout=10)
        seen = {}
        for line in r.stdout.strip().split('\n'):
            if not line.strip(): continue
            parts = line.split()
            if len(parts) < 11: continue
            pid = parts[1]
            cpu = parts[2]
            mem_pct = parts[3]
            rss_kb = int(parts[5])
            mem_mb = round(rss_kb / 1024)
            cmd = ' '.join(parts[10:])
            # Identify the service
            if 'profiles.active=messaging' in cmd:
                name = 'Messaging'; icon = '📡'
            elif 'profiles.active=api' in cmd:
                name = 'API'; icon = '🧩'
            elif 'profiles.active=config' in cmd:
                name = 'Config'; icon = '⚙️'
            elif 'takserver-pm.jar' in cmd:
                name = 'Plugin Manager'; icon = '🔌'
            elif 'takserver-retention.jar' in cmd:
                name = 'Retention'; icon = '📦'
            else:
                continue  # skip unknown java processes
            # Keep only one entry per service name (highest mem)
            if name not in seen or mem_mb > seen[name]['mem_mb_raw']:
                seen[name] = {
                    'name': name, 'icon': icon, 'pid': pid,
                    'cpu': f"{cpu}%", 'mem_mb': f"{mem_mb} MB",
                    'mem_pct': f"{mem_pct}%", 'status': 'running',
                    'mem_mb_raw': mem_mb
                }
        for svc in seen.values():
            del svc['mem_mb_raw']
            services.append(svc)
        # Check PostgreSQL — remote for two-server, local otherwise
        settings = load_settings()
        tak_cfg = _get_tak_deployment_config(settings)
        if tak_cfg.get('mode') == 'two_server':
            s1 = tak_cfg.get('server_one', {})
            s1_host = (s1.get('host') or '').strip()
            if s1_host:
                import socket
                db_port = int(tak_cfg.get('database', {}).get('port') or 5432)
                try:
                    s = socket.create_connection((s1_host, db_port), timeout=5)
                    s.close()
                    pg_status = 'running'
                except Exception:
                    pg_status = 'stopped'
                services.append({
                    'name': f'PostgreSQL ({s1_host})', 'icon': '🐘', 'pid': '',
                    'cpu': '', 'mem_mb': '', 'mem_pct': '',
                    'status': pg_status
                })
            else:
                services.append({
                    'name': 'PostgreSQL (remote)', 'icon': '🐘', 'pid': '',
                    'cpu': '', 'mem_mb': '', 'mem_pct': '',
                    'status': 'stopped'
                })
        elif _tak_is_container():
            # v10.0.1: single-server container deploy — PostgreSQL runs in the
            # takserver-db container, not as a host systemd service.
            pg_running = _tak_container_running(TAK_DB_CONTAINER)
            services.append({
                'name': 'PostgreSQL', 'icon': '🐘', 'pid': '',
                'cpu': '', 'mem_mb': '', 'mem_pct': '',
                'status': 'running' if pg_running else 'stopped'
            })
        else:
            # Native host PostgreSQL: Debian/Ubuntu use the unsuffixed `postgresql`
            # meta-service; RHEL/EL (PGDG) use `postgresql-15`. EITHER being active
            # means PG is up. Probing only `postgresql` false-reds every Rocky/RHEL
            # native box ("PostgreSQL stopped") even though postgresql-15 is serving
            # cot fine — same EL/Debian split already handled at the deploy probe.
            pg = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'postgresql', 'postgresql-15']), capture_output=True, text=True, timeout=5)
            pg_active = 'active' in (pg.stdout or '').split()
            services.append({
                'name': 'PostgreSQL', 'icon': '🐘', 'pid': '',
                'cpu': '', 'mem_mb': '', 'mem_pct': '',
                'status': 'running' if pg_active else 'stopped'
            })
    except Exception as e:
        services.append({'name': 'Error', 'icon': '❌', 'status': str(e)[:200]})
    return jsonify({'services': services, 'count': len([s for s in services if s['status'] == 'running'])})


@app.route('/api/takserver/remote-metrics')
@login_required
def takserver_remote_metrics():
    """Return CPU/memory/disk/uptime for Server One when in two-server (remote DB) mode."""
    settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    if tak_cfg.get('mode') != 'two_server':
        return jsonify({'error': 'Not two-server'}), 404
    s1 = tak_cfg.get('server_one', {})
    if not (s1.get('host') or '').strip():
        return jsonify({'error': 'No Server One host'}), 404
    metrics = _get_remote_host_metrics(s1)
    if metrics is None:
        return jsonify({'error': 'Could not fetch remote metrics'}), 503
    return jsonify(metrics)


@app.route('/api/takserver/uninstall', methods=['POST'])
@login_required
def takserver_uninstall():
    """Remove TAK Server, clean up, ready for fresh deploy"""
    data = request.json or {}
    password = data.get('password', '')
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'error': 'Invalid admin password'}), 403
    steps = []
    # v10.0.1: container TAK teardown FIRST. The native systemctl/apt steps below
    # are no-ops on a Docker TAK (no unit, no package) and --restart=always would
    # just respawn the containers, so do the real teardown here. Confirmed by the
    # uninstall test: native Remove left containers/volume/network/bundle behind.
    if _tak_is_container():
        for c in (TAK_CONTAINER, TAK_DB_CONTAINER):
            subprocess.run(_sudo_wrap(['docker', 'rm', '-f', c]), capture_output=True, timeout=60)
        subprocess.run(_sudo_wrap(['docker', 'volume', 'rm', TAK_DB_VOLUME]), capture_output=True, timeout=30)
        subprocess.run(_sudo_wrap(['docker', 'network', 'rm', TAK_DOCKER_NET]), capture_output=True, timeout=30)
        subprocess.run(_sudo_wrap(['rm', '-rf', TAK_DOCKER_ROOT]), capture_output=True, timeout=60)  # v10.0.1: broker rm — the host console user can't delete the root-owned in-container cert files
        # Remove the /opt/tak symlink explicitly. After ~/tak-docker is gone it is a
        # DANGLING symlink, which the native `if os.path.exists('/opt/tak')` cleanup
        # below skips (exists() follows the link → False), leaving it behind.
        subprocess.run(_sudo_wrap(['rm', '-f', '/opt/tak']), capture_output=True, timeout=10)
        # Reset the persisted method/credentials so detection falls back to the
        # platform default (arm64 still defaults to container; a redeploy re-sets it).
        try:
            _us = load_settings()
            _us.pop('tak_install_method', None)
            _us.pop('tak_db_password', None)
            save_settings(_us)
        except Exception:
            pass
        steps.append('Container TAK removed (containers, volume, network, ~/tak-docker)')
    # Stop service
    subprocess.run(_sudo_wrap(['systemctl', 'stop', 'takserver']), capture_output=True, timeout=90)
    subprocess.run(_sudo_wrap(['systemctl', 'disable', 'takserver']), capture_output=True, timeout=90)
    steps.append('Stopped TAK Server')
    # Kill any remaining processes
    subprocess.run('pkill -9 -f takserver 2>/dev/null; true', shell=True, capture_output=True)
    steps.append('Killed remaining processes')
    # Purge package — must complete BEFORE removing /opt/tak, otherwise the
    # package can remain in 'ii' state with files gone, and the next
    # `apt-get install` becomes a no-op ("already newest version") that leaves
    # a half-installed system. See deploy Step 4 self-heal for the matching
    # recovery path.
    if _distro_family() == 'rhel':
        # EL9 native: dnf remove the rpm, then drop the SELinux policy module that
        # the rpm's apply-selinux.sh loaded (else a reinstall warns it's already there).
        # IMPORTANT: clean_requirements_on_remove=False — by default `dnf remove
        # takserver` CASCADES out postgresql15 (and psql) as now-orphaned deps, which
        # runs BEFORE the cot/martiuser drop below → the drop fails (no psql) and a
        # redeploy inherits a stale martiuser with a mismatched password. Keeping
        # postgres (matches the .deb uninstall, which doesn't cascade it) lets the
        # later DROP DATABASE cot / DROP USER martiuser actually run.
        _rpm_installed = subprocess.run('rpm -q takserver 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
        if _rpm_installed.startswith('takserver'):
            subprocess.run(_sudo_wrap(['dnf', 'remove', '-y', '--setopt=clean_requirements_on_remove=False', 'takserver']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=180)
            _after = subprocess.run('rpm -q takserver 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
            if not _after.startswith('takserver') or 'not installed' in _after.lower():
                steps.append('Removed TAK Server rpm (dnf)')
            else:
                subprocess.run('rpm -e --noscripts --nodeps takserver 2>&1', shell=True, capture_output=True, text=True, timeout=120)
                steps.append('Force-removed TAK Server rpm')
        # remove the takserver SELinux module (named takserver-policy on EL9)
        _run_priv_chain([['semodule', '-r', 'takserver-policy'], ['semodule', '-r', 'takserver']], 'seq', timeout=60)
    else:
        pkg_status = subprocess.run(
            "dpkg-query -W -f='${Status}' takserver 2>/dev/null",
            shell=True, capture_output=True, text=True
        ).stdout.strip()
        if pkg_status:
            # Try purge (apt first, then dpkg, then dpkg --force-all). Capture
            # stderr so silent failures don't pretend success.
            purge_ok = False
            for cmd in (
                'DEBIAN_FRONTEND=noninteractive apt-get purge -y takserver',
                'DEBIAN_FRONTEND=noninteractive dpkg --purge takserver',
                'DEBIAN_FRONTEND=noninteractive dpkg --purge --force-all takserver',
            ):
                r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=180)
                after = subprocess.run(
                    "dpkg-query -W -f='${Status}' takserver 2>/dev/null",
                    shell=True, capture_output=True, text=True
                ).stdout.strip()
                if not after or 'not-installed' in after:
                    purge_ok = True
                    break
            if purge_ok:
                steps.append('Purged TAK Server package')
            else:
                steps.append('⚠ Could not purge takserver package (still registered with dpkg) — manual cleanup required')
    # Clean up /opt/tak
    if os.path.exists('/opt/tak'):
        subprocess.run(_sudo_wrap(['rm', '-rf', '/opt/tak']), capture_output=True)
        steps.append('Removed /opt/tak')
    # Clean up PostgreSQL — local or external depending on deployment mode
    settings = load_settings()
    tak_cfg = _get_tak_deployment_config(settings)
    if tak_cfg.get('mode') == 'external_db':
        # External / managed DB: use stored martiuser credentials to drop the cot database.
        # martiuser was granted azure_pg_admin (Azure) or rds_superuser (AWS) during provisioning
        # so it has permission to drop databases it doesn't own.
        edb = tak_cfg.get('external_db', {})
        edb_host = (edb.get('host') or '').strip()
        edb_port = int(edb.get('port') or 5432)
        edb_name = (edb.get('name') or 'cot').strip()
        edb_user = (edb.get('user') or 'martiuser').strip()
        edb_pass = (edb.get('password') or '').strip()
        if edb_host and edb_pass:
            env = dict(os.environ, PGPASSWORD=edb_pass)
            # Terminate active connections then drop the database
            terminate_sql = f"SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE datname='{edb_name}' AND pid <> pg_backend_pid();"
            drop_sql = f"DROP DATABASE IF EXISTS {edb_name};"
            for sql, label in [(terminate_sql, 'terminate connections'), (drop_sql, f'drop database {edb_name}')]:
                r = subprocess.run(
                    ['psql', '-h', edb_host, '-p', str(edb_port), '-U', edb_user,
                     '-d', 'postgres', '--no-password', '-c', sql],
                    capture_output=True, text=True, timeout=30, env=env
                )
                if r.returncode == 0:
                    steps.append(f'External DB: {label} — OK')
                else:
                    steps.append(f'External DB: {label} — {(r.stderr or r.stdout or "failed")[:120]}')
        else:
            steps.append('External DB cleanup skipped — no credentials stored (run Provision Database on next deploy)')
        # The .deb installer always creates a local martiuser + cot DB regardless of deployment
        # mode. Clean them up so re-deploys don't hit stale-password noise in the postinstall.
        subprocess.run("runuser -u postgres -- psql -c \"DROP DATABASE IF EXISTS cot WITH (FORCE);\" 2>/dev/null || runuser -u postgres -- psql -c \"DROP DATABASE IF EXISTS cot;\" 2>/dev/null; true", shell=True, capture_output=True, timeout=30)
        subprocess.run("runuser -u postgres -- psql -c \"DROP USER IF EXISTS martiuser;\" 2>/dev/null; true", shell=True, capture_output=True, timeout=30)
        steps.append('Cleaned up local PostgreSQL side-effect (cot database, martiuser)')
    else:
        # Local PostgreSQL (single-server or two-server mode)
        subprocess.run("runuser -u postgres -- psql -c \"DROP DATABASE IF EXISTS cot WITH (FORCE);\" 2>/dev/null || runuser -u postgres -- psql -c \"DROP DATABASE IF EXISTS cot;\" 2>/dev/null; true", shell=True, capture_output=True, timeout=30)
        subprocess.run("runuser -u postgres -- psql -c \"DROP USER IF EXISTS martiuser;\" 2>/dev/null; true", shell=True, capture_output=True, timeout=30)
        steps.append('Cleaned up local PostgreSQL (cot database, martiuser)')
    # Clean up GPG verification artifacts
    subprocess.run('rm -rf /usr/share/debsig/keyrings/* /etc/debsig/policies/* 2>/dev/null; true', shell=True, capture_output=True, timeout=10)
    steps.append('Cleaned up GPG verification artifacts')
    # Clean up uploads so user can upload fresh
    for f in os.listdir(UPLOAD_DIR):
        os.remove(os.path.join(UPLOAD_DIR, f))
    steps.append('Cleared uploads')
    # Reset deploy status
    deploy_log.clear()
    deploy_status.update({'running': False, 'complete': False, 'error': False})
    # Clear saved deployment config so the form is blank on next visit
    try:
        _settings = load_settings()
        td = _settings.get('tak_deployment', {})
        td['mode'] = 'single_server'
        edb = td.get('external_db', {})
        edb['host'] = ''
        edb['password'] = ''
        td['external_db'] = edb
        _settings['tak_deployment'] = td
        save_settings(_settings)
        steps.append('Cleared saved deployment config')
    except Exception as _ce:
        steps.append(f'Could not clear deployment config (non-fatal): {_ce}')
    # v0.9.31: regenerate Caddyfile so the webtak.<fqdn> vhost is removed.
    # Same gap as takportal/authentik uninstall — without this the vhost
    # remained and Caddy fell through to Authentik's "Not Found" page.
    try:
        settings = load_settings()
        generate_caddyfile(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
        steps.append('Regenerated Caddyfile + reloaded Caddy')
    except Exception as caddy_err:
        steps.append(f'Caddy regen warning (non-fatal): {caddy_err}')
    return jsonify({'success': True, 'steps': steps})

@app.route('/api/upload/takserver', methods=['POST'])
@login_required
def upload_takserver_package():
    if 'files' not in request.files:
        return jsonify({'error': 'No files uploaded'}), 400
    files = request.files.getlist('files')
    if not files or all(f.filename == '' for f in files):
        return jsonify({'error': 'No files selected'}), 400
    os_type = load_settings().get('os_type', '')
    results = {'packages': [], 'gpg_key': None, 'policy': None}
    for f in files:
        raw_name = f.filename or ''
        fn = secure_filename(raw_name)
        if not fn:
            return jsonify({'error': f'Invalid filename: {raw_name[:64]}'}), 400
        fp = os.path.join(UPLOAD_DIR, fn)
        f.save(fp)
        sz = round(os.path.getsize(fp) / (1024*1024), 1)
        # v10.0.1 platform gate: the accepted package type is fixed by arch+distro,
        # mirroring the existing .deb/.rpm cross-rejection. arm64 → docker .zip only
        # (no native arm TAK package exists); amd64 RHEL → .rpm only; amd64 Debian/
        # Ubuntu → .deb only. Reject anything else up-front so a box can't be deployed
        # with the wrong package by accident.
        _arch = _host_arch()
        _native_ext = '.rpm' if _distro_family() == 'rhel' else '.deb'
        if fn.endswith('.deb'):
            if _arch == 'arm64':
                os.remove(fp)
                return jsonify({'error': f'.deb uploaded but this arm64 box deploys TAK Server via the container path — upload the takserver-docker .zip.'}), 400
            if _distro_family() == 'rhel':
                os.remove(fp)
                return jsonify({'error': f'.deb uploaded but system is {os_type} (RHEL family). Need a takserver .rpm.'}), 400
            results['packages'].append({'filename': fn, 'filepath': fp, 'pkg_type': 'deb', 'size_mb': sz})
        elif fn.endswith('.rpm'):
            if _arch == 'arm64':
                os.remove(fp)
                return jsonify({'error': f'.rpm uploaded but this arm64 box deploys TAK Server via the container path — upload the takserver-docker .zip.'}), 400
            if _distro_family() != 'rhel':
                os.remove(fp)
                return jsonify({'error': f'.rpm uploaded but system is {os_type}. Need a takserver .deb.'}), 400
            results['packages'].append({'filename': fn, 'filepath': fp, 'pkg_type': 'rpm', 'size_mb': sz})
        elif fn.endswith('.zip') and 'docker' in fn.lower():
            # official takserver-docker-*.zip — the CONTAINER path. amd64 must use its
            # native package (.deb/.rpm); arm64 is container-only here, so it takes the
            # zip. (The TAK deb/rpm are arch-neutral — _all/.noarch — but arm64 deploys
            # via the container path: it's the supported, field-validated arm path.)
            if _arch != 'arm64':
                os.remove(fp)
                return jsonify({'error': f'Docker .zip uploaded but this is an amd64 {os_type} system — upload the native takserver {_native_ext}. (The docker .zip is the arm64 path.)'}), 400
            results['packages'].append({'filename': fn, 'filepath': fp, 'pkg_type': 'docker', 'size_mb': sz})
        elif fn.endswith('.key') or 'gpg' in fn.lower():
            results['gpg_key'] = {'filename': fn, 'filepath': fp, 'size_mb': sz}
        elif fn.endswith('.pol') or 'policy' in fn.lower():
            results['policy'] = {'filename': fn, 'filepath': fp, 'size_mb': sz}
    return jsonify({'success': True, **results,
        'has_verification': results['gpg_key'] is not None and results['policy'] is not None})

@app.route('/api/upload/takserver/delete', methods=['POST'])
@login_required
def delete_uploaded_file():
    fn = request.json.get('filename', '')
    import re
    if not fn or not re.match(r'^[a-zA-Z0-9._-]+$', fn):
        return jsonify({'error': 'Invalid filename'}), 400
    fp = os.path.join(UPLOAD_DIR, fn)
