@app.route('/api/takserver/security-config')
@login_required
def takserver_security_config_get():
    """Read issued cert validity (validityDays) from CoreConfig TAKServerCAConfig. Lets you change it anytime (e.g. 90 days = re-enroll by scanning QR)."""
    coreconfig_path = '/opt/tak/CoreConfig.xml'
    if not os.path.exists(coreconfig_path):
        return jsonify({'error': 'TAK Server not installed'}), 400
    try:
        r = subprocess.run(_sudo_wrap(['cat', coreconfig_path]), capture_output=True, text=True, timeout=5)
        if r.returncode != 0:
            return jsonify({'error': 'Could not read CoreConfig.xml'}), 500
        content = r.stdout or ''
    except Exception as e:
        return jsonify({'error': str(e)[:200]}), 500
    import re
    m = re.search(r'<TAKServerCAConfig[^>]*validityDays="(\d+)"', content)
    validity_days = int(m.group(1)) if m else 3650
    return jsonify({'validity_days': validity_days})


@app.route('/api/takserver/security-config', methods=['POST'])
@login_required
def takserver_security_config_post():
    """Update issued cert validity (validityDays) in CoreConfig and restart TAK Server. E.g. set to 90 to force re-enrollment (scan QR again); or rotate CA / revoke client cert from TAK Server."""
    data = request.get_json() or {}
    try:
        validity_days = int(data.get('validity_days', 0))
        if validity_days < 1 or validity_days > 3652:
            return jsonify({'error': 'validity_days must be between 1 and 3652'}), 400
    except (TypeError, ValueError):
        return jsonify({'error': 'validity_days must be a number'}), 400
    coreconfig_path = '/opt/tak/CoreConfig.xml'
    if not os.path.exists(coreconfig_path):
        return jsonify({'error': 'TAK Server not installed'}), 400
    try:
        r = subprocess.run(_sudo_wrap(['cat', coreconfig_path]), capture_output=True, text=True, timeout=5)
        if r.returncode != 0:
            return jsonify({'error': 'Could not read CoreConfig.xml'}), 500
        content = r.stdout or ''
    except Exception as e:
        return jsonify({'error': str(e)[:200]}), 500
    import re
    if not re.search(r'<TAKServerCAConfig[^>]*validityDays="\d+"', content):
        return jsonify({'error': 'TAKServerCAConfig / validityDays not found in CoreConfig (certificate enrollment may not be enabled)'}), 400
    new_content = re.sub(r'(<TAKServerCAConfig[^>]*validityDays=")\d+(")', rf'\g<1>{validity_days}\g<2>', content, count=1)
    if new_content == content:
        return jsonify({'error': 'No change applied'}), 400
    try:
        _write_priv(coreconfig_path, new_content)  # v10.0.5 non-root: broker write (literal `sudo tee` bypassed the broker)
    except Exception as e:
        return jsonify({'error': str(e)[:200]}), 500
    subprocess.run(_tak_systemctl('restart'), shell=True, capture_output=True, timeout=90)  # v10.0.1: container-aware
    return jsonify({'success': True, 'validity_days': validity_days, 'message': f'Issued cert validity set to {validity_days} days. TAK Server restarted.'})


@app.route('/api/takserver/update', methods=['POST'])
@login_required
def takserver_update():
    """Run TAK Server upgrade. Two-server: core first (local), then database (SSH to Server One)."""
    if not os.path.exists('/opt/tak'):
        return jsonify({'error': 'TAK Server not installed. Deploy TAK Server first.'}), 400
    settings = load_settings()
    # v10.0.1: a container box must NEVER take the .deb/dpkg/apt upgrade path — it does not
    # upgrade the image and litters the host. Run the data-preserving container upgrade instead:
    # rebuild the image from the new takserver-docker-*.zip while KEEPING the DB volume + certs.
    if _tak_is_container():
        if upgrade_status['running']:
            return jsonify({'error': 'Update already in progress'}), 409
        _zips = [f for f in os.listdir(UPLOAD_DIR) if f.lower().endswith('.zip') and 'docker' in f.lower()]
        if not _zips:
            return jsonify({'error': 'Container upgrade: upload the new takserver-docker-*.zip bundle (not a .deb).'}), 400
        _zip = os.path.join(UPLOAD_DIR, sorted(_zips, key=lambda f: os.path.getmtime(os.path.join(UPLOAD_DIR, f)))[-1])
        upgrade_log.clear()
        upgrade_status.update({'running': True, 'complete': False, 'error': False})
        threading.Thread(target=run_takserver_upgrade_container, args=(_zip,), daemon=True).start()
        return jsonify({'success': True})
    # RHEL/Rocky native: upgrade from the new takserver-*.noarch.rpm via dnf.
    if _distro_family() == 'rhel' or settings.get('pkg_mgr') == 'dnf':
        if upgrade_status['running']:
            return jsonify({'error': 'Update already in progress'}), 409
        _tak_cfg = _get_tak_deployment_config(settings)
        _all_rpms = sorted([f for f in os.listdir(UPLOAD_DIR) if f.endswith('.rpm')],
                           key=lambda f: os.path.getmtime(os.path.join(UPLOAD_DIR, f)), reverse=True)
        # v10.0.5: RHEL two-server (split) update — core (local dnf) + database rpm on Server One
        # (SSH dnf) + SchemaManager on Server One. Previously ALL RHEL boxes fell through to the
        # single-server path below, so a split update never touched the DB box.
        if _tak_cfg.get('mode') == 'two_server':
            _core_rpm = next((f for f in _all_rpms if 'core' in f.lower()), '')
            _db_rpm = next((f for f in _all_rpms if 'database' in f.lower()), '')
            if not _core_rpm or not _db_rpm:
                return jsonify({'error': 'Two-server update requires both takserver-core and takserver-database .noarch.rpm packages. Upload both.'}), 400
            _s1 = _tak_cfg.get('server_one', {})
            if not _s1.get('host'):
                return jsonify({'error': 'Server One host not configured in deployment settings.'}), 400
            upgrade_log.clear()
            upgrade_status.update({'running': True, 'complete': False, 'error': False})
            threading.Thread(target=run_takserver_upgrade_two_server_rhel, args=(
                os.path.join(UPLOAD_DIR, _core_rpm), os.path.join(UPLOAD_DIR, _db_rpm), _s1, _tak_cfg,
            ), daemon=True).start()
            return jsonify({'success': True})
        _rpms = sorted([f for f in os.listdir(UPLOAD_DIR)
                        if f.endswith('.rpm') and '-database' not in f.lower() and '-core' not in f.lower()],
                       key=lambda f: os.path.getmtime(os.path.join(UPLOAD_DIR, f)), reverse=True)
        if not _rpms:
            return jsonify({'error': 'No takserver .rpm found. Upload the new takserver-*.noarch.rpm from tak.gov first (the single-server package, not core/database).'}), 400
        # external_db: pass the RDS block so the upgrade runs SchemaManager against the managed DB.
        _edb = _tak_cfg.get('external_db') if _tak_cfg.get('mode') == 'external_db' else None
        upgrade_log.clear()
        upgrade_status.update({'running': True, 'complete': False, 'error': False})
        threading.Thread(target=run_takserver_upgrade_rhel, args=(os.path.join(UPLOAD_DIR, _rpms[0]),),
                         kwargs={'external_db': _edb}, daemon=True).start()
        return jsonify({'success': True})
    if upgrade_status['running']:
        return jsonify({'error': 'Update already in progress'}), 409
    tak_cfg = _get_tak_deployment_config(settings)
    is_two_server = tak_cfg.get('mode') == 'two_server'
    pkg_files = sorted([f for f in os.listdir(UPLOAD_DIR) if f.endswith('.deb')],
        key=lambda f: os.path.getmtime(os.path.join(UPLOAD_DIR, f)), reverse=True)
    if not pkg_files:
        return jsonify({'error': 'No .deb package found. Upload the new TAK Server .deb from tak.gov first.'}), 400
    if is_two_server:
        core_pkg = next((f for f in pkg_files if 'core' in f.lower()), '')
        db_pkg = next((f for f in pkg_files if 'database' in f.lower()), '')
        if not core_pkg or not db_pkg:
            return jsonify({'error': 'Two-server update requires both takserver-core and takserver-database .deb packages. Upload both.'}), 400
        s1 = tak_cfg.get('server_one', {})
        if not s1.get('host'):
            return jsonify({'error': 'Server One host not configured in deployment settings.'}), 400
        upgrade_log.clear()
        upgrade_status.update({'running': True, 'complete': False, 'error': False})
        threading.Thread(target=run_takserver_upgrade_two_server, args=(
            os.path.join(UPLOAD_DIR, core_pkg),
            os.path.join(UPLOAD_DIR, db_pkg),
            s1, tak_cfg
        ), daemon=True).start()
    else:
        single_pkgs = [f for f in pkg_files if '-database' not in f.lower() and '-core' not in f.lower()]
        if not single_pkgs:
            return jsonify({'error': 'Only split packages (core/database) found. For one-server update, upload the single takserver .deb. Remove the wrong files and upload the correct package.'}), 400
        upgrade_log.clear()
        upgrade_status.update({'running': True, 'complete': False, 'error': False})
        threading.Thread(target=run_takserver_upgrade, args=(os.path.join(UPLOAD_DIR, single_pkgs[0]),), daemon=True).start()
    return jsonify({'success': True})

@app.route('/api/takserver/update/log')
@login_required
def takserver_update_log():
    idx = int(request.args.get('index', 0))
    return jsonify({'entries': upgrade_log[idx:], 'total': len(upgrade_log),
        'running': upgrade_status['running'], 'complete': upgrade_status['complete'], 'error': upgrade_status['error']})

def _tak_upgrade_apt_install(cwd, pkg_name, upgrade_log, timeout_sec=600):
    """Run apt-get install for a local .deb with streamed output.

    subprocess.run(capture_output=True) buffers all stdout/stderr until exit, so a slow
    configure/postinst looks like a silent hang. stdbuf -oL line-buffers; a reader thread
    appends lines to upgrade_log so operators see where apt stalled if a timeout fires.
    """
    qn = shlex.quote(pkg_name)
    # v10.0.5 non-root: pass env via Popen instead of a literal `env` wrapper, so
    # `apt-get` is the direct command and resolves to the broker shim on PATH (root).
    _aenv = dict(os.environ, DEBIAN_FRONTEND='noninteractive', NEEDRESTART_MODE='l')
    cmd = f'stdbuf -oL -eL apt-get install -y ./{qn} 2>&1'
    proc = subprocess.Popen(
        cmd, shell=True, cwd=cwd, env=_aenv,
        stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, bufsize=1)
    if proc.stdout is None:
        return 1

    def _drain():
        for line in iter(proc.stdout.readline, ''):
            if line and 'NEEDRESTART' not in line:
                upgrade_log.append('  ' + line.rstrip('\n'))

    t = threading.Thread(target=_drain, daemon=True)
    t.start()
    try:
        proc.wait(timeout=timeout_sec)
    except subprocess.TimeoutExpired:
        proc.kill()
        try:
            proc.wait(timeout=15)
        except Exception:
            pass
        t.join(timeout=5)
        raise
    t.join(timeout=5)
    return proc.returncode if proc.returncode is not None else 1


# takserver .postinst chmod/chown targets; fallbacks if postinst is unreadable.
_TAK_POSTINST_EXPLICIT_SH_FALLBACK = (
    '/opt/tak/config/takserver-config.sh',
    '/opt/tak/messaging/takserver-messaging.sh',
)
# Paths that look like files (do not mkdir — postinst cp/install references these).
_TAK_POSTINST_SKIP_DIR_MK_SUFFIX = (
    '.xml', '.sql', '.conf', '.jks', '.pem', '.properties', '.jar', '.war', '.deb', '.rpm',
    '.pol', '.p12', '.crt', '.key', '.idx', '.policy',
)
_TAK_POSTINST_SH_GLOB_DIRS = (
    '/opt/tak/config',
    '/opt/tak/messaging',
    '/opt/tak/utils',
    '/opt/tak/api',
    '/opt/tak/cluster',
    '/opt/tak/retention',
)


def _tak_postinst_path_should_skip_mkdir(p):
    """True if p is almost certainly a file (postinst cp/install lines mention these — do not mkdir)."""
    pl = p.lower()
    if pl.endswith(_TAK_POSTINST_SKIP_DIR_MK_SUFFIX):
        return True
    if pl.endswith('.dist') or '.dist.' in os.path.basename(p):
        return True
    return False


def _tak_postinst_resolved_mitigation_paths():
    """Return (sh_paths, dir_paths) from takserver.postinst chmod/chown lines only (+ .sh fallbacks).

    Do not parse cp/install/mv — those reference many files; mkdir on them breaks dpkg.
    Do not mkdir /opt/tak/config/takserver-config here — an empty dir breaks postinst cp; see rmdir helper.
    """
    sh_paths = set(_TAK_POSTINST_EXPLICIT_SH_FALLBACK)
    dir_paths = set()
    pi = '/var/lib/dpkg/info/takserver.postinst'
    try:
        if os.path.isfile(pi):
            with open(pi, 'r', encoding='utf-8', errors='ignore') as f:
                lines = f.read().splitlines()
            for line in lines:
                if '#' in line:
                    line = line.split('#', 1)[0]
                if not any(k in line for k in ('chmod', 'chown')):
                    continue
                for m in re.finditer(r'/opt/tak/[A-Za-z0-9_./-]+', line):
                    p = m.group(0)
                    if p.endswith('.sh'):
                        sh_paths.add(p)
                    elif p.endswith(('.deb', '.rpm', '.jar', '.war')):
                        continue
                    elif _tak_postinst_path_should_skip_mkdir(p):
                        continue
                    elif p == '/opt/tak/config/takserver-config':
                        # Postinst populates via cp; empty pre-created dir breaks cp (see _tak_upgrade_remove_blocking_empty_takserver_config).
                        continue
                    else:
                        dir_paths.add(p)
    except OSError:
        pass
    return sorted(sh_paths), sorted(dir_paths)


def _sudo_test(path, flag):
    """True if a test on `path` succeeds (flag '-d','-f','-e'). v10.0.5 non-root:
    /opt/tak is world-traversable and its files are world-readable, so a plain
    os.path check works — the old `sudo test` failed (takwerx isn't in sudoers)
    and returned False for everything."""
    if flag == '-d':
        return os.path.isdir(path)
    if flag == '-f':
        return os.path.isfile(path)
    return os.path.exists(path)


def _tak_upgrade_remove_blocking_empty_takserver_config(ulog):
    """Remove empty /opt/tak/config/takserver-config if present.

    A prior workaround mkdir created an empty directory; postinst then fails with:
    cp: -r not specified; omitting directory '.../takserver-config'
    Real install unpacks/copies into that path — it must not exist as an empty infra-TAK placeholder.
    """
    p = '/opt/tak/config/takserver-config'
    try:
        # v10.0.5 non-root: check emptiness in Python (world-readable) + remove via the
        # broker-routed `rmdir` shim (the old literal `sudo bash -c` failed as takwerx).
        if os.path.isdir(p) and not os.listdir(p):
            r = subprocess.run(_sudo_wrap(['rmdir', p]), capture_output=True, text=True, timeout=15)
            if r.returncode == 0:
                ulog(f"  ✓ removed empty {p} (so postinst can populate — not a mkdir placeholder)")
    except Exception as e:
        ulog(f"  ⚠ could not clear empty {p}: {e}")


def _tak_upgrade_mitigate_takserver_postinst_config_sh(ulog):
    """Ensure dirs, named scripts, and *.sh globs exist so takserver postinst chmod/chown succeeds.

    Implemented in Python (not a single bash -c blob) so every step is logged and failures are visible.
    After a killed upgrade, dpkg --configure needs paths the .deb would normally unpack.

    Also invoked from _tak_upgrade_dpkg_configure_a so this always runs immediately before dpkg --configure -a.
    """
    ulog("Preparing /opt/tak paths expected by takserver postinst (partial-upgrade workaround)...")
    _tak_upgrade_remove_blocking_empty_takserver_config(ulog)
    sh_paths, dir_paths = _tak_postinst_resolved_mitigation_paths()
    placeholder = (
        '#!/bin/sh\n'
        '# infra-TAK: placeholder until package files are restored — run: apt reinstall takserver .deb\n'
        'exit 0\n'
    )
    # v10.0.5 non-root: literal `sudo mkdir/tee/chmod/bash` all fail (takwerx not in
    # sudoers). Route mkdir via the shim (_sudo_wrap), writes via _write_priv (perm sets
    # the +x), and do emptiness/glob checks in Python (world-readable).
    import glob as _glob
    try:
        for d in sorted(dir_paths):
            r = subprocess.run(_sudo_wrap(['mkdir', '-p', d]), capture_output=True, text=True, timeout=30)
            if r.returncode != 0:
                ulog(f"✗ mkdir -p {d} failed: {(r.stderr or r.stdout or '').strip()[:400]}")
            else:
                ulog(f"  ✓ mkdir -p {d}")
        for fpath in sorted(sh_paths):
            parent = os.path.dirname(fpath)
            subprocess.run(_sudo_wrap(['mkdir', '-p', parent]), capture_output=True, text=True, timeout=30)
            if _sudo_test(fpath, '-f'):
                continue
            try:
                _write_priv(fpath, placeholder, perm=0o755)
            except Exception as _we:
                ulog(f"✗ could not write {fpath}: {str(_we)[:200]}")
                continue
            ulog(f"  ✓ placeholder {os.path.basename(fpath)}")
        for d in _TAK_POSTINST_SH_GLOB_DIRS:
            subprocess.run(_sudo_wrap(['mkdir', '-p', d]), capture_output=True, text=True, timeout=30)
            if _glob.glob(os.path.join(d, '*.sh')):
                continue
            stub = os.path.join(d, '_infra_tak_placeholder_for_postinst.sh')
            try:
                _write_priv(stub, placeholder, perm=0o755)
                ulog(f"  ✓ {d}/*.sh glob placeholder")
            except Exception:
                pass
    except Exception as e:
        ulog(f"✗ Tak path preparation error: {e}")


def _run_dpkg_configure_a(ulog, upgrade_log, timeout_sec=3600):
    """Run dpkg --configure -a, streaming output. Returns exit code (0 = success)."""
    ulog("Running dpkg --configure -a...")
    # v10.0.5 non-root: drop literal `sudo` — `dpkg` is an ALWAYS-shim binary, so the
    # bare invocation routes through the broker (running as root). `sudo dpkg` failed.
    cmd = 'DEBIAN_FRONTEND=noninteractive NEEDRESTART_MODE=l dpkg --configure -a 2>&1'
    proc = subprocess.Popen(
        cmd, shell=True, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, bufsize=1)
    if proc.stdout is None:
        ulog("✗ Could not start dpkg --configure -a")
        return 1

    def _drain():
        for line in iter(proc.stdout.readline, ''):
            if line and 'NEEDRESTART' not in line:
                upgrade_log.append('  ' + line.rstrip('\n'))

    t = threading.Thread(target=_drain, daemon=True)
    t.start()
    try:
        proc.wait(timeout=timeout_sec)
    except subprocess.TimeoutExpired:
        proc.kill()
        try:
            proc.wait(timeout=15)
        except Exception:
            pass
        t.join(timeout=5)
        ulog("✗ dpkg --configure -a timed out.")
        return 1
    t.join(timeout=5)
    return proc.returncode if proc.returncode is not None else 1


def _tak_upgrade_dpkg_configure_a(ulog, upgrade_log, pkg_path=None):
    """Ensure dpkg is in a clean state before apt-get install.

    First attempt: dpkg --configure -a.
    If that fails and pkg_path is set (the .deb we're about to install), re-unpack it
    with dpkg --unpack (restores all missing files without running postinst), then retry
    dpkg --configure -a. This handles the common case where a timed-out upgrade left
    files missing while dpkg still needs to configure the half-installed package.
    """
    ulog("Ensuring dpkg state is consistent...")
    rc = _run_dpkg_configure_a(ulog, upgrade_log)
    if rc == 0:
        ulog("✓ dpkg state OK")
        return True

    if not pkg_path or not os.path.isfile(pkg_path):
        ulog("✗ dpkg --configure -a failed and no .deb available for re-unpack.")
        return False

    ulog("dpkg --configure -a failed — re-unpacking .deb to restore missing files...")
    ulog(f"  dpkg --unpack {os.path.basename(pkg_path)}")
    try:
        rc2 = _tak_upgrade_apt_install_streamed(
            'dpkg --unpack ' + shlex.quote(pkg_path) + ' 2>&1',
            os.path.dirname(pkg_path), upgrade_log, timeout_sec=300)
    except subprocess.TimeoutExpired:
        ulog("✗ dpkg --unpack timed out.")
        return False
    if rc2 != 0:
        ulog(f"✗ dpkg --unpack failed (exit {rc2}).")
        return False
    ulog("✓ Files restored from .deb")

    ulog("Retrying dpkg --configure -a after re-unpack...")
    rc3 = _run_dpkg_configure_a(ulog, upgrade_log)
    if rc3 != 0:
        ulog("✗ dpkg --configure -a still failed after re-unpack. Manual intervention needed.")
        return False
    ulog("✓ dpkg state OK (after re-unpack)")
    return 'ALREADY_INSTALLED'


def _tak_upgrade_apt_install_streamed(cmd, cwd, upgrade_log, timeout_sec=600):
    """Run a shell command with line-buffered output streamed to upgrade_log. Returns exit code."""
    proc = subprocess.Popen(
        cmd, shell=True, cwd=cwd,
        stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, bufsize=1)
    if proc.stdout is None:
        return 1

    def _drain():
        for line in iter(proc.stdout.readline, ''):
            if line and 'NEEDRESTART' not in line:
                upgrade_log.append('  ' + line.rstrip('\n'))

    t = threading.Thread(target=_drain, daemon=True)
    t.start()
    try:
        proc.wait(timeout=timeout_sec)
    except subprocess.TimeoutExpired:
        proc.kill()
        try:
            proc.wait(timeout=15)
        except Exception:
            pass
        t.join(timeout=5)
        raise
    t.join(timeout=5)
    return proc.returncode if proc.returncode is not None else 1


SNAPSHOT_DIR = '/opt/tak/snapshots'

_SNAPSHOT_LABEL_RE = re.compile(r'^[A-Za-z0-9._-]+$')


def _validate_snapshot_label(label):
    """v0.9.12: defence against path traversal in snapshot routes.

    Reject anything that could escape SNAPSHOT_DIR. Returns (ok, safe_label_or_error).

    Defence in depth:
      1. Reject empty / non-str inputs.
      2. Reject reserved names ('.', '..').
      3. Whitelist regex — only [A-Za-z0-9._-]+. Forbids '/', '\\', whitespace,
         null bytes, and every shell metacharacter.
      4. realpath check — after joining, the resolved path must live strictly
         inside the resolved SNAPSHOT_DIR. Catches edge cases where a clever
         attacker bypasses the regex (e.g. symlink games on disk).
    """
    if not label or not isinstance(label, str):
        return False, 'label is required'
    if label in ('.', '..'):
        return False, 'invalid label'
    if not _SNAPSHOT_LABEL_RE.fullmatch(label):
        return False, 'label must match [A-Za-z0-9._-]+'
    try:
        snap_real = os.path.realpath(os.path.join(SNAPSHOT_DIR, label))
        base_real = os.path.realpath(SNAPSHOT_DIR)
    except Exception:
        return False, 'label resolves to invalid path'
    if not snap_real.startswith(base_real + os.sep) and snap_real != base_real:
        return False, 'label resolves outside SNAPSHOT_DIR'
    if snap_real == base_real:
        return False, 'invalid label'
    return True, label


def _tak_snapshot(label, plog=None):
    """Create a TAK Server snapshot at /opt/tak/snapshots/<label>/.

    Captures: installed TAK version, CoreConfig.xml, UserAuthenticationFile.xml,
    /etc/default/takserver, PostgreSQL cot dump, and /opt/tak/certs/files/.

    Returns (True, metadata_dict) on success, (False, error_str) on failure.
    Idempotent — if the label already exists it is overwritten.
    """
    import shutil as _shutil
    if plog is None:
        plog = lambda m: print(m, flush=True)

    snap_path = os.path.join(SNAPSHOT_DIR, label)
    plog(f"  snapshot [{label}]: creating at {snap_path}")

    try:
        _makedirs_priv(snap_path)  # /opt/tak/snapshots root-owned — broker mkdir
    except Exception as e:
        return False, f"Could not create snapshot dir: {e}"

    meta = {
        'label':      label,
        'taken_at':   datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
        'source':     'manual',
        'tak_version': None,
        'size_mb':    0,
    }

    # 1. TAK version — try dpkg (multiple package names) then rpm
    try:
        for _pkg in ('takserver', 'takserver-core', 'takserver-database'):
            _r = subprocess.run(
                f"dpkg -s {_pkg} 2>/dev/null | grep ^Version:",
                shell=True, capture_output=True, text=True, timeout=5)
            if _r.returncode == 0 and _r.stdout.strip():
                meta['tak_version'] = _r.stdout.strip().replace('Version:', '').strip()
                break
        if meta['tak_version'] is None:
            _r = subprocess.run("rpm -q takserver 2>/dev/null", shell=True, capture_output=True, text=True, timeout=5)
            if _r.returncode == 0 and _r.stdout.strip():
                _ver = _r.stdout.strip()
                if _ver.startswith('takserver-'):
                    _ver = _ver.split('-', 1)[1]
                _ver = _ver.replace('.noarch', '')
                if _ver:
                    meta['tak_version'] = _ver
    except Exception as e:
        plog(f"  snapshot: version probe failed: {e}")

    # 2. CoreConfig.xml
    cc_src = '/opt/tak/CoreConfig.xml'
    if os.path.exists(cc_src):
        try:
            subprocess.run(_sudo_wrap(['cp','-p',cc_src, os.path.join(snap_path,'CoreConfig.xml')]), capture_output=True, check=True)
            plog("  snapshot: CoreConfig.xml copied")
        except Exception as e:
            plog(f"  snapshot: CoreConfig copy failed: {e}")
    else:
        plog("  snapshot: CoreConfig.xml not found — skipping")

    # 2b. UserAuthenticationFile.xml — flat-file users (admin, webadmin, optional Phase 1A nodered).
    # Without this, restoring a snapshot loses any flat-file users added since the snapshot,
    # which breaks Phase 1A's nodered cert auth even though the cert files survive in certs/.
    uaf_src = '/opt/tak/UserAuthenticationFile.xml'
    if os.path.exists(uaf_src):
        try:
            subprocess.run(_sudo_wrap(['cp','-p',uaf_src, os.path.join(snap_path,'UserAuthenticationFile.xml')]), capture_output=True, check=True)
            plog("  snapshot: UserAuthenticationFile.xml copied")
        except Exception as e:
            plog(f"  snapshot: UserAuthenticationFile.xml copy failed: {e}")
    else:
        plog("  snapshot: UserAuthenticationFile.xml not found — skipping (flat-file auth not configured)")

    # 3. /etc/default/takserver (JVM heap)
    heap_src = '/etc/default/takserver'
    if os.path.exists(heap_src):
        try:
            subprocess.run(_sudo_wrap(['cp','-p',heap_src, os.path.join(snap_path,'takserver.default')]), capture_output=True, check=True)
            plog("  snapshot: takserver.default copied")
        except Exception as e:
            plog(f"  snapshot: takserver.default copy failed: {e}")

    # 4. PostgreSQL cot dump
    # In a two-server deployment the database lives on Server One — stream via SSH.
    # In a single-server deployment it runs locally as the postgres OS user.
    pg_dump_path = os.path.join(snap_path, 'cot.pgdump')
    plog("  snapshot: pg_dump starting — cot database (may take 30–90s for large databases)…")
    meta['db_dump'] = False   # set True only when a non-empty cot dump actually lands
    try:
        _snap_settings = load_settings()
        _snap_tak_cfg = _get_tak_deployment_config(_snap_settings)
        _snap_two_server = _snap_tak_cfg.get('mode') == 'two_server'
        _snap_s1 = _snap_tak_cfg.get('server_one', {})
        _snap_edb = _snap_tak_cfg.get('external_db', {}) if _snap_tak_cfg.get('mode') == 'external_db' else {}
        if _snap_edb.get('host'):
            # external_db / RDS: the DB is managed (no SSH, no local postgres) — dump over
            # TCP with the client pg_dump. Stream to a console-writable temp, then broker-cp
            # into the root-owned snapshot dir (same pattern as the two-server branch).
            # Previously this mode fell through to the local branch: non-root skipped
            # "deferred", root hard-failed (no local postgres OS user). PLAN-v10.0.6 §3.
            import shutil as _shu
            _eh = _snap_edb['host']
            _ep = int(_snap_edb.get('port') or 5432)
            _en = _snap_edb.get('name') or 'cot'
            _eu = _snap_edb.get('user') or 'martiuser'
            if not _shu.which('pg_dump'):
                plog("  snapshot: external-DB mode but no pg_dump client on this box — DB dump skipped "
                     "(managed-DB automated backups still apply; install postgresql client tools to capture dumps in snapshots)")
            else:
                plog(f"  snapshot: external-DB mode — pg_dump over TCP from {_eh}:{_ep}")
                import tempfile
                _fd, _tmp_dump = tempfile.mkstemp(prefix='cot-snap-', suffix='.pgdump')
                os.close(_fd)
                try:
                    _pg_env = dict(os.environ)
                    _pg_env['PGPASSWORD'] = _snap_edb.get('password') or ''
                    with open(_tmp_dump, 'wb') as _f:
                        r2 = subprocess.run(
                            ['pg_dump', '-Fc', '-h', _eh, '-p', str(_ep), '-U', _eu, '-d', _en],
                            stdout=_f, stderr=subprocess.PIPE, timeout=600, env=_pg_env)
                    if r2.returncode == 0 and os.path.getsize(_tmp_dump) > 0:
                        _cp = subprocess.run(_sudo_wrap(['cp', _tmp_dump, pg_dump_path]), capture_output=True, timeout=120)
                        if _cp.returncode == 0:
                            meta['db_dump'] = True
                            plog(f"  snapshot: cot pg_dump (external DB {_eh}) written ({os.path.getsize(_tmp_dump) // 1024} KB)")
                        else:
                            plog(f"  snapshot: pg_dump copy into snapshot FAILED: {(_cp.stderr or b'').decode()[:160]}")
                    else:
                        plog(f"  snapshot: external-DB pg_dump FAILED (check network path + client-vs-server version): {(r2.stderr or b'').decode()[:200]}")
                finally:
                    try: os.remove(_tmp_dump)
                    except Exception: pass
        elif _snap_two_server and _snap_s1.get('host'):
            plog("  snapshot: two-server mode — streaming pg_dump from Server One via SSH")
            _ssh_dump_cmd = 'sudo -u postgres pg_dump -Fc cot'
            _host = (_snap_s1.get('host') or '').strip()
            _user = (_snap_s1.get('ssh_user') or 'root').strip() or 'root'
            _port = int(_snap_s1.get('ssh_port') or 22)
            _key  = (_snap_s1.get('ssh_key_path') or '').strip() or None
            _ssh_parts = [
                'ssh', '-o', 'StrictHostKeyChecking=accept-new', '-o', 'BatchMode=yes',
                '-p', str(_port),
            ]
            if _key:
                _ssh_parts += ['-i', _key]
            _ssh_parts += [f'{_user}@{_host}', _ssh_dump_cmd]
            # v10.0.5 non-root: the snapshot dir is root-owned (broker mkdir), so the non-root
            # console can't open() a file inside it — a direct write here was the silent
            # [Errno 13] that left two-server snapshots with NO database. Stream the SSH dump to
            # a console-writable temp, then broker-cp it into the snapshot dir (cp is already
            # broker-routed above for CoreConfig). Identical behaviour as root. NB: don't stat
            # the dest — the root-owned dir isn't traversable by takwerx; trust the temp size + cp rc.
            import tempfile
            _fd, _tmp_dump = tempfile.mkstemp(prefix='cot-snap-', suffix='.pgdump')
            os.close(_fd)
            try:
                with open(_tmp_dump, 'wb') as _f:
                    r2 = subprocess.run(_ssh_parts, stdout=_f, stderr=subprocess.PIPE, timeout=300)
                if r2.returncode == 0 and os.path.getsize(_tmp_dump) > 0:
                    _cp = subprocess.run(_sudo_wrap(['cp', _tmp_dump, pg_dump_path]), capture_output=True, timeout=120)
                    if _cp.returncode == 0:
                        meta['db_dump'] = True
                        plog(f"  snapshot: cot pg_dump (remote) written ({os.path.getsize(_tmp_dump) // 1024} KB)")
                    else:
                        plog(f"  snapshot: pg_dump copy into snapshot FAILED: {(_cp.stderr or b'').decode()[:160]}")
                else:
                    plog(f"  snapshot: remote pg_dump FAILED: {(r2.stderr or b'').decode()[:200]}")
            finally:
                try: os.remove(_tmp_dump)
                except Exception: pass
        elif _broker_should_route() and _broker_available():
            # v10.0.8 (PLAN §B): non-root SINGLE-server — the broker writes the dump to disk
            # itself (broker pg_dump op), so the 32MB socket cap that forced the v10.0.5
            # "DB dump deferred" skip no longer applies. Honest warning path on failure.
            try:
                _sz = _pg_dump_priv(pg_dump_path, db='cot', timeout=600,
                                    container=(TAK_DB_CONTAINER if _tak_is_container() else None))
                if _sz > 0:
                    meta['db_dump'] = True
                    plog(f"  snapshot: cot pg_dump written via broker ({_sz // 1024} KB)")
                else:
                    plog("  snapshot: broker pg_dump produced an EMPTY dump — db_dump=False (config+certs captured)")
            except Exception as _pg_e:
                plog(f"  snapshot: broker pg_dump FAILED: {str(_pg_e)[:200]} — db_dump=False (config+certs captured)")
        else:
            with open(pg_dump_path, 'wb') as _f:
                r2 = subprocess.run(
                    'sudo -u postgres pg_dump -Fc cot',
                    shell=True, stdout=_f, stderr=subprocess.PIPE, timeout=300
                )
            if r2.returncode == 0 and os.path.getsize(pg_dump_path) > 0:
                meta['db_dump'] = True
                plog(f"  snapshot: cot pg_dump written ({os.path.getsize(pg_dump_path) // 1024} KB)")
            else:
                plog(f"  snapshot: pg_dump FAILED: {(r2.stderr or b'').decode()[:200]}")
                try: os.remove(pg_dump_path)
                except Exception: pass
    except Exception as e:
        plog(f"  snapshot: pg_dump exception: {e}")

    # 5. Certificates
    certs_src = '/opt/tak/certs/files'
    certs_dst = os.path.join(snap_path, 'certs')
    if os.path.isdir(certs_src):
        try:
            subprocess.run(_sudo_wrap(['rm','-rf',certs_dst]), capture_output=True)
            subprocess.run(_sudo_wrap(['cp','-rp',certs_src,certs_dst]), capture_output=True, check=True)
            plog("  snapshot: certs/ copied")
        except Exception as e:
            plog(f"  snapshot: certs copy failed: {e}")
    else:
        plog("  snapshot: /opt/tak/certs/files not found — skipping")

    # Compute total size
    try:
        total = 0
        for dirpath, _, filenames in os.walk(snap_path):
            for fn in filenames:
                try: total += os.path.getsize(os.path.join(dirpath, fn))
                except Exception: pass
        meta['size_mb'] = round(total / (1024 * 1024), 1)
    except Exception:
        pass

    # Persist to settings
    try:
        s = load_settings()
        snaps = s.get('tak_snapshots') or []
        # Remove any existing entry with same label
        snaps = [sn for sn in snaps if sn.get('label') != label]
        snaps.append(meta)
        # Keep most recent 50
        snaps.sort(key=lambda x: x.get('taken_at', ''), reverse=True)
        s['tak_snapshots'] = snaps[:50]
        save_settings(s)
    except Exception as e:
        plog(f"  snapshot: settings save failed: {e}")

    if not meta.get('db_dump'):
        plog(f"  ⚠ snapshot [{label}]: NO cot database dump captured — this snapshot restores "
             f"CoreConfig / UserAuth / certs ONLY, not the database. DB-level rollback is NOT available.")
    plog(f"  ✓ snapshot [{label}]: done ({meta['size_mb']} MB, version={meta['tak_version']}, "
         f"db_dump={'yes' if meta.get('db_dump') else 'NO'})")
    return True, meta


def _tak_rollback(label, plog=None):
    """Restore TAK Server from snapshot at /opt/tak/snapshots/<label>/.

    Steps:
      1. Validate snapshot exists and has a pg_dump
      2. systemctl stop takserver
      3. Restore CoreConfig.xml, UserAuthenticationFile.xml, takserver.default, certs/
      4. pg_restore --clean -d cot from snapshot
      5. systemctl start takserver

    Returns (True, None) on success, (False, error_str) on failure.
    """
    import shutil as _shutil
    if plog is None:
        plog = lambda m: print(m, flush=True)

    ok, label_or_err = _validate_snapshot_label(label)
    if not ok:
        return False, f"Invalid snapshot label: {label_or_err}"
    label = label_or_err
    snap_path = os.path.join(SNAPSHOT_DIR, label)
    if not os.path.isdir(snap_path):
        return False, f"Snapshot '{label}' not found at {snap_path}"

    plog(f"  rollback [{label}]: starting")

    # 1. Validate. os.path.exists is authoritative as root; on the non-root
    # console the root-owned snapshot dir may not be stat-able — confirm via a
    # broker `test -f` before declaring the dump missing (v10.0.8).
    pg_dump_path = os.path.join(snap_path, 'cot.pgdump')
    if not os.path.exists(pg_dump_path):
        _via_broker = (_broker_should_route() and _broker_available()
                       and subprocess.run(_sudo_wrap(['test', '-f', pg_dump_path]),
                                          capture_output=True, timeout=10).returncode == 0)
        if not _via_broker:
            return False, f"Snapshot '{label}' has no cot.pgdump — cannot restore database"

    # 2. Stop TAK Server
    plog("  rollback: stopping takserver…")
    subprocess.run(_tak_systemctl('stop'), shell=True, capture_output=True, timeout=60)  # v10.0.1: container-aware

    # 3. Restore CoreConfig.xml
    cc_src = os.path.join(snap_path, 'CoreConfig.xml')
    if os.path.exists(cc_src):
        try:
            subprocess.run(_sudo_wrap(['cp','-p',cc_src,'/opt/tak/CoreConfig.xml']), capture_output=True, check=True)
            plog("  rollback: CoreConfig.xml restored")
        except Exception as e:
            plog(f"  rollback: CoreConfig restore failed: {e}")

    # 3b. Restore UserAuthenticationFile.xml (flat-file users incl. optional Phase 1A nodered).
    uaf_src = os.path.join(snap_path, 'UserAuthenticationFile.xml')
    uaf_dst = '/opt/tak/UserAuthenticationFile.xml'
    if os.path.exists(uaf_src):
        try:
            subprocess.run(_sudo_wrap(['cp','-p',uaf_src,uaf_dst]), capture_output=True, check=True)
            # Match the ownership convention used elsewhere for /opt/tak files.
            subprocess.run(
                _sudo_wrap(['chown', ('1000:1000' if _tak_is_container() else 'tak:tak'), '/opt/tak/UserAuthenticationFile.xml']), capture_output=True, timeout=10
            )
            plog("  rollback: UserAuthenticationFile.xml restored")
        except Exception as e:
            plog(f"  rollback: UserAuthenticationFile.xml restore failed: {e}")
    else:
        plog("  rollback: snapshot has no UserAuthenticationFile.xml — leaving current file in place")

    # 4. Restore JVM heap settings
    heap_src = os.path.join(snap_path, 'takserver.default')
    if os.path.exists(heap_src):
        try:
            subprocess.run(_sudo_wrap(['cp','-p',heap_src,'/etc/default/takserver']), capture_output=True, check=True)
            plog("  rollback: takserver.default restored")
        except Exception as e:
            plog(f"  rollback: takserver.default restore failed: {e}")

    # 5. Restore certs
    certs_src = os.path.join(snap_path, 'certs')
    certs_dst = '/opt/tak/certs/files'
    if os.path.isdir(certs_src):
        try:
            subprocess.run(_sudo_wrap(['rm','-rf',certs_dst]), capture_output=True)
            subprocess.run(_sudo_wrap(['cp','-rp',certs_src,certs_dst]), capture_output=True, check=True)
            # Restore ownership (tak:tak) on certs
            subprocess.run(
                _sudo_wrap(['chown', '-R', ('1000:1000' if _tak_is_container() else 'tak:tak'), '/opt/tak/certs/files']), capture_output=True, timeout=15
            )
            plog("  rollback: certs/ restored")
        except Exception as e:
            plog(f"  rollback: certs restore failed: {e}")

    # 6. pg_restore
    # In two-server mode stream the dump to Server One and restore there.
    # In single-server mode restore into the local takserver-db container.
    #
    # v10.0.5 non-root: cot.pgdump lives in the root-owned snapshot dir (0600 from
    # pg_dump), so the non-root console can't open() it to feed pg_restore's stdin.
    # Stage a console-readable copy via the broker (cp + chown to the console uid,
    # inside /opt/tak/snapshots/), open THAT, and remove it afterwards. On root the
    # broker doesn't route, so _staged_dump stays the original path (opened directly).
    # v10.0.8: staging is now ONLY for the two-server SSH stream — the local restore
    # goes through the broker pg_restore op (the broker opens the dump as root and
    # feeds pg_restore itself; a staged copy pushed through the exec proxy would hit
    # the 32MB socket cap on any real database).
    _rb_settings = load_settings()
    _rb_tak_cfg  = _get_tak_deployment_config(_rb_settings)
    _rb_two_server = _rb_tak_cfg.get('mode') == 'two_server' and (_rb_tak_cfg.get('server_one', {}) or {}).get('host')
    _staged_dump = pg_dump_path
    if _rb_two_server and _broker_should_route() and _broker_available():
        _staged_dump = os.path.join(snap_path, '.cot.pgdump.staged')
        try:
            subprocess.run(_sudo_wrap(['cp', pg_dump_path, _staged_dump]), capture_output=True, check=True, timeout=120)
            subprocess.run(_sudo_wrap(['chown', f'{os.getuid()}:{os.getgid()}', _staged_dump]), capture_output=True, check=True, timeout=30)
        except Exception as _e_stage:
            plog(f"  rollback: could not stage cot.pgdump for restore: {_e_stage}")
            _staged_dump = pg_dump_path  # fall back; open() may still work as root
    plog("  rollback: restoring PostgreSQL cot database…")
    try:
        _rb_s1 = _rb_tak_cfg.get('server_one', {})
        if _rb_two_server:
            plog("  rollback: two-server mode — streaming pg_restore to Server One via SSH")
            _rb_host = (_rb_s1.get('host') or '').strip()
            _rb_user = (_rb_s1.get('ssh_user') or 'root').strip() or 'root'
            _rb_port = int(_rb_s1.get('ssh_port') or 22)
            _rb_key  = (_rb_s1.get('ssh_key_path') or '').strip() or None
            _rb_ssh  = ['ssh', '-o', 'StrictHostKeyChecking=accept-new', '-o', 'BatchMode=yes',
                        '-p', str(_rb_port)]
            if _rb_key:
                _rb_ssh += ['-i', _rb_key]
            _rb_remote_cmd = 'sudo -u postgres pg_restore --clean -d cot'
            _rb_ssh += [f'{_rb_user}@{_rb_host}', _rb_remote_cmd]
            with open(_staged_dump, 'rb') as _f:
                r2 = subprocess.run(_rb_ssh, stdin=_f, capture_output=True, timeout=300)
            if r2.returncode in (0, 1):
                stderr = (r2.stderr or b'').decode()[:200]
                if stderr:
                    plog(f"  rollback: pg_restore (remote) warnings (non-fatal): {stderr}")
                else:
                    plog("  rollback: pg_restore (remote) successful")
            else:
                plog(f"  rollback: remote pg_restore failed (exit {r2.returncode}): {(r2.stderr or b'').decode()[:200]}")
        elif _broker_should_route() and _broker_available():
            # v10.0.8 non-root single-server: broker pg_restore op — the broker
            # opens the dump as root and feeds pg_restore/docker-exec itself, so
            # nothing crosses the socket. Covers native (runuser postgres) AND
            # container TAK (docker exec takserver-db) via the container key.
            resp = _broker_request({'op': 'pg_restore', 'path': pg_dump_path, 'db': 'cot',
                                    'container': (TAK_DB_CONTAINER if _tak_is_container() else None),
                                    'timeout': 600}, timeout=630)
            if resp.get('ok') and resp.get('returncode') in (0, 1):
                stderr = (resp.get('stderr') or '')[:200]
                if stderr:
                    plog(f"  rollback: pg_restore warnings (non-fatal): {stderr}")
                else:
                    plog("  rollback: pg_restore successful")
            else:
                plog(f"  rollback: pg_restore failed (exit {resp.get('returncode')}): "
                     f"{(resp.get('error') or resp.get('stderr') or '')[:200]}")
        elif _tak_is_container():
            pg_container = TAK_DB_CONTAINER
            r = subprocess.run(
                _sudo_wrap(['docker', 'ps', '-q', '--filter', f'name={pg_container}']), capture_output=True, text=True, timeout=10
            )
            if (r.stdout or '').strip():
                r2 = subprocess.run(
                    _sudo_wrap(['docker', 'exec', '-i', pg_container, 'pg_restore', '-U', 'postgres', '--clean', '-d', 'cot']),
                    stdin=open(_staged_dump, 'rb'),
                    capture_output=True,
                    timeout=300
                )
                if r2.returncode in (0, 1):
                    stderr = (r2.stderr or b'').decode()[:400]
                    if stderr:
                        plog(f"  rollback: pg_restore warnings (non-fatal): {stderr[:200]}")
                    else:
                        plog("  rollback: pg_restore successful")
                else:
                    plog(f"  rollback: pg_restore failed (exit {r2.returncode}): {(r2.stderr or b'').decode()[:200]}")
            else:
                plog(f"  rollback: {pg_container} not running — skipping pg_restore")
        else:
            # v10.0.8: ROOT native single-server — restore directly via the local
            # postgres OS user. The old code only knew the takserver-db container
            # and silently SKIPPED the DB restore on native installs (the dump was
            # captured but never came back — the same class of gap as the non-root
            # "DB dump deferred" this release closes).
            with open(_staged_dump, 'rb') as _f:
                r2 = subprocess.run(['runuser', '-u', 'postgres', '--',
                                     'pg_restore', '--clean', '-d', 'cot'],
                                    stdin=_f, capture_output=True, timeout=600)
            if r2.returncode in (0, 1):
                stderr = (r2.stderr or b'').decode()[:400]
                if stderr:
                    plog(f"  rollback: pg_restore warnings (non-fatal): {stderr[:200]}")
                else:
                    plog("  rollback: pg_restore successful")
            else:
                plog(f"  rollback: pg_restore failed (exit {r2.returncode}): {(r2.stderr or b'').decode()[:200]}")
    except Exception as e:
        plog(f"  rollback: pg_restore exception: {e}")
    finally:
        # Remove the staged dump copy (broker-owned by the console uid now).
        if _staged_dump != pg_dump_path:
            try: subprocess.run(_sudo_wrap(['rm', '-f', _staged_dump]), capture_output=True, timeout=30)
            except Exception: pass

    # 7. Start TAK Server
    plog("  rollback: starting takserver…")
    subprocess.run(_tak_systemctl('start'), shell=True, capture_output=True, timeout=90)  # v10.0.1: container-aware

    # 8. Restart Node-RED so it resyncs mission state from the restored DB.
    # Without this, Node-RED keeps trying to manage missions that were wiped by
    # the rollback, causing NPEs in TAK Server's mission API on the next poll.
    try:
        r_nr = subprocess.run(
            _sudo_wrap(['docker', 'restart', 'nodered']), capture_output=True, text=True, timeout=30
        )
        if r_nr.returncode == 0:
            plog("  rollback: Node-RED restarted (mission state resynced)")
        else:
            plog("  rollback: Node-RED not running or restart skipped (non-fatal)")
    except Exception as _e_nr:
        plog(f"  rollback: Node-RED restart error (non-fatal): {_e_nr}")

    plog(f"  ✓ rollback [{label}]: complete")
    return True, None


# Snapshot/rollback log stream
_snapshot_log   = []
_snapshot_status = {'running': False, 'complete': False, 'error': False}

def _tak_setup_snapshot_schedule(plog=None):
    """v10.0.6: scheduled snapshots now run IN-PROCESS (see _tak_snapshot_scheduler) —
    the v0.9.3 systemd timer NEVER worked (4 broken layers: parsed a `-p` port the
    console unit doesn't have → bogus 2121; curled http on an https-only console; used
    a session cookie nothing ever created; and the endpoint is @login_required with no
    loopback bypass — it 401'd even when reachable). All it produced was a red
    takserver-snapshot.service in `systemctl --failed` (seen on test12).

    This function now just REMOVES the legacy units (idempotent, clears the failed
    state) — the in-process scheduler reads tak_snapshot_schedule live, so enable/
    disable/schedule changes need no setup step at all."""
    if plog is None:
        plog = lambda m: print(m, flush=True)
    try:
        _legacy = ['/etc/systemd/system/takserver-snapshot.service',
                   '/etc/systemd/system/takserver-snapshot.timer']
        if any(os.path.exists(p) for p in _legacy):
            subprocess.run(_sudo_wrap(['systemctl', 'disable', '--now', 'takserver-snapshot.timer']),
                           capture_output=True, timeout=10)
            subprocess.run(_sudo_wrap(['rm', '-f'] + _legacy), capture_output=True, timeout=10)
            subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=10)
            subprocess.run(_sudo_wrap(['systemctl', 'reset-failed', 'takserver-snapshot.service']),
                           capture_output=True, timeout=10)
            plog("  snapshot schedule: legacy systemd timer removed — scheduling is in-process now")
        cfg = (load_settings().get('tak_snapshot_schedule') or {})
        if cfg.get('enabled'):
            plog(f"  snapshot schedule: enabled ({cfg.get('frequency', 'daily')} at "
                 f"{int(cfg.get('hour', 2)):02d}:{int(cfg.get('minute', 0)):02d}, "
                 f"retention={int(cfg.get('retention', 7))}) — runs in-process")
        else:
            plog("  snapshot schedule: disabled")
        return True
    except Exception as e:
        plog(f"  snapshot schedule: error — {e}")
        return False


def _tak_snapshot_scheduler():
    """v10.0.6: in-process scheduled TAK snapshots (replaces the never-functional
    systemd timer — see _tak_setup_snapshot_schedule docstring). Daemon thread,
    one-minute tick; reads tak_snapshot_schedule live so UI changes apply without
    any restart. Catch-up semantics match the old timer's Persistent=true: if the
    console was down at HH:MM, the snapshot fires on the next tick that day. The
    occurrence is stamped BEFORE the run so a failing snapshot doesn't retry every
    minute. Prunes only `scheduled-*` snapshots beyond the retention count —
    manual and pre-update snapshots are never touched."""
    global _snapshot_status, _snapshot_log
    import time as _st
    _st.sleep(180)  # let _startup_migrations finish before the first tick
    while True:
        try:
            s = load_settings()
            cfg = s.get('tak_snapshot_schedule') or {}
            if not cfg.get('enabled') or not os.path.exists('/opt/tak'):
                _st.sleep(60)
                continue
            now = datetime.now()
            hour = max(0, min(23, int(cfg.get('hour', 2))))
            minute = max(0, min(59, int(cfg.get('minute', 0))))
            weekly = (cfg.get('frequency', 'daily') == 'weekly')
            occurrence = now.strftime('%Y-%m-%d')
            due = ((not weekly or now.weekday() == 5)                      # Sat for weekly
                   and (now.hour, now.minute) >= (hour, minute)
                   and cfg.get('last_scheduled_run') != occurrence
                   and not _snapshot_status.get('running'))
            if not due:
                _st.sleep(60)
                continue
            # Stamp first — a failing snapshot must not re-fire every minute all day.
            cfg['last_scheduled_run'] = occurrence
            s['tak_snapshot_schedule'] = cfg
            save_settings(s)
            label = f"scheduled-{now.strftime('%Y%m%d-%H%M%S')}"
            def plog(m):
                entry = f"[{datetime.now().strftime('%H:%M:%S')}] {m}"
                _snapshot_log.append(entry)
                print(f"[snapshot-scheduler] {m}", flush=True)
            _snapshot_log = []
            _snapshot_status = {'running': True, 'complete': False, 'error': False}
            plog(f"scheduled snapshot starting — {label}")
            ok, result = _tak_snapshot(label, plog)
            if ok:
                _snapshot_status = {'running': False, 'complete': True, 'error': False}
                try:
                    s2 = load_settings()
                    sn = s2.get('tak_snapshots') or []
                    for snap in sn:
                        if snap.get('label') == label:
                            snap['source'] = 'scheduled'
                    # Retention: newest N scheduled snapshots survive.
                    retention = max(1, min(90, int(cfg.get('retention', 7))))
                    scheduled = sorted(
                        [x for x in sn if x.get('source') == 'scheduled'
                         or str(x.get('label', '')).startswith('scheduled-')],
                        key=lambda x: x.get('taken_at', ''), reverse=True)
                    for victim in scheduled[retention:]:
                        v_ok, v_label = _validate_snapshot_label(victim.get('label', ''))
                        if not v_ok:
                            continue
                        subprocess.run(_sudo_wrap(['rm', '-rf', os.path.join(SNAPSHOT_DIR, v_label)]),
                                       capture_output=True, timeout=60)
                        sn = [x for x in sn if x.get('label') != v_label]
                        plog(f"retention: pruned old scheduled snapshot {v_label}")
                    s2['tak_snapshots'] = sn
                    save_settings(s2)
                except Exception as _pe:
                    plog(f"retention prune error (non-fatal): {str(_pe)[:120]}")
                plog("scheduled snapshot complete")
            else:
                _snapshot_status = {'running': False, 'complete': False, 'error': True}
                plog(f"scheduled snapshot FAILED: {result}")
        except Exception as _sched_e:
            print(f"[snapshot-scheduler] tick error (non-fatal): {str(_sched_e)[:200]}", flush=True)
        _st.sleep(60)


@app.route('/api/takserver/snapshot/schedule', methods=['GET'])
@login_required
def takserver_snapshot_schedule_get_api():
    """Return current scheduled snapshot configuration."""
    s   = load_settings()
    cfg = s.get('tak_snapshot_schedule') or {
        'enabled': False, 'frequency': 'daily', 'hour': 2, 'minute': 0, 'retention': 7
    }
    # v10.0.6: scheduling is in-process (daemon thread reads settings live), so
    # "active" simply mirrors enabled — no systemd timer exists anymore.
    cfg['timer_active'] = bool(cfg.get('enabled'))
    return jsonify(cfg)


@app.route('/api/takserver/snapshot/schedule', methods=['POST'])
@login_required
def takserver_snapshot_schedule_post_api():
    """Update scheduled snapshot configuration and rewrite the systemd timer."""
    data = request.get_json(force=True) or {}
    s    = load_settings()
    cfg  = s.get('tak_snapshot_schedule') or {}
    cfg['enabled']   = bool(data.get('enabled', False))
    cfg['frequency'] = str(data.get('frequency', 'daily'))
    cfg['hour']      = max(0, min(23, int(data.get('hour', 2))))
    cfg['minute']    = max(0, min(59, int(data.get('minute', 0))))
    cfg['retention'] = max(1, min(90, int(data.get('retention', 7))))
    s['tak_snapshot_schedule'] = cfg
    save_settings(s)
    ok = _tak_setup_snapshot_schedule(lambda m: print(m, flush=True))
    return jsonify({'ok': ok, 'config': cfg})


