@app.route('/api/takserver/snapshot/<label>/download')
@login_required
def takserver_snapshot_download_api(label):
    """Stream a .tar.gz of the snapshot directory directly to the client."""
    import subprocess
    ok, safe_label = _validate_snapshot_label(label)
    if not ok:
        return jsonify({'error': safe_label}), 400
    snap_path = os.path.join(SNAPSHOT_DIR, safe_label)
    if not os.path.isdir(snap_path):
        return jsonify({'error': 'Snapshot not found'}), 404

    # v10.0.5 non-root: the snapshot tree under /opt/tak/snapshots is root-owned
    # (config/keystores often 0600). tar run as takwerx would SILENTLY skip the
    # unreadable files and hand back a partial archive. Stage a console-readable
    # copy via the broker (cp -rp + chown to the console uid, all under /opt/tak/),
    # tar from there, and clean it up when the stream finishes. On root the broker
    # doesn't route, so we tar SNAPSHOT_DIR directly — unchanged behaviour.
    staging = None
    src_dir = SNAPSHOT_DIR
    if _broker_should_route() and _broker_available():
        staging = os.path.join(SNAPSHOT_DIR, '.dl-' + safe_label)
        try:
            subprocess.run(_sudo_wrap(['rm', '-rf', staging]), capture_output=True, timeout=60)
            subprocess.run(_sudo_wrap(['mkdir', '-p', staging]), capture_output=True, check=True, timeout=30)
            subprocess.run(_sudo_wrap(['cp', '-rp', snap_path, os.path.join(staging, safe_label)]),
                           capture_output=True, check=True, timeout=300)
            subprocess.run(_sudo_wrap(['chown', '-R', f'{os.getuid()}:{os.getgid()}', staging]),
                           capture_output=True, check=True, timeout=120)
            src_dir = staging
        except Exception as e:
            try: subprocess.run(_sudo_wrap(['rm', '-rf', staging]), capture_output=True, timeout=60)
            except Exception: pass
            return jsonify({'error': f'Could not stage snapshot for download: {str(e)[:200]}'}), 500

    def _stream():
        # Stream tar directly from disk — no in-memory buffering
        proc = subprocess.Popen(
            ['tar', '-czf', '-', '-C', src_dir, safe_label],
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
        )
        try:
            while True:
                chunk = proc.stdout.read(65536)
                if not chunk:
                    break
                yield chunk
        finally:
            proc.stdout.close()
            proc.wait()
            if staging:
                try: subprocess.run(_sudo_wrap(['rm', '-rf', staging]), capture_output=True, timeout=60)
                except Exception: pass

    from flask import Response
    return Response(
        _stream(),
        headers={
            'Content-Disposition': f'attachment; filename="{safe_label}.tar.gz"',
            'Content-Type': 'application/gzip',
        }
    )


@app.route('/api/takserver/snapshot/upload', methods=['POST'])
@login_required
def takserver_snapshot_upload_api():
    """Accept a snapshot .tar.gz, validate its structure, extract to SNAPSHOT_DIR, and register it."""
    import shutil as _shutil
    import tarfile as _tarfile

    uploaded = request.files.get('file')
    if not uploaded or not uploaded.filename:
        return jsonify({'ok': False, 'error': 'No file provided'}), 400

    filename = uploaded.filename
    if not filename.endswith('.tar.gz'):
        return jsonify({'ok': False, 'error': 'File must be a .tar.gz archive'}), 400

    # v10.0.5 non-root: snapshot UPLOAD is PARKED (non-blocking). Doing it safely
    # under the non-root console means extracting an operator-supplied archive on
    # the console side, which needs a traversal-hardened extractor (new attack
    # surface). Until that lands, refuse cleanly instead of throwing an EPERM 500
    # when writing into the root-owned /opt/tak/snapshots. On-box snapshots (the
    # rollback safety net) and download are unaffected; restore an uploaded archive
    # on a root console, or use download→rollback on the same box.
    if _broker_should_route() and _broker_available():
        return jsonify({'ok': False, 'error':
            'Snapshot upload is not yet supported on the non-root (least-privilege) '
            'console. On-box snapshots and download still work — use those, or import '
            'the archive on a root console.'}), 501

    # Derive label from filename (strip .tar.gz)
    raw_label = filename[:-7]
    # Sanitise — only allow chars valid in a directory name
    import re as _re_ul
    safe_label = _re_ul.sub(r'[^A-Za-z0-9._-]', '_', raw_label)
    if not safe_label:
        safe_label = 'uploaded'

    # Ensure the label doesn't collide; append a suffix if needed
    dest_path = os.path.join(SNAPSHOT_DIR, safe_label)
    if os.path.exists(dest_path):
        import time as _t_ul
        safe_label = safe_label + '_' + str(int(_t_ul.time()))[-6:]
        dest_path = os.path.join(SNAPSHOT_DIR, safe_label)

    tmp_path = dest_path + '.tmp.tar.gz'
    try:
        os.makedirs(SNAPSHOT_DIR, exist_ok=True)
        uploaded.save(tmp_path)

        # Validate: must be a valid tar.gz and contain at least CoreConfig.xml or cot.pgdump
        try:
            with _tarfile.open(tmp_path, 'r:gz') as tf:
                names = tf.getnames()
        except Exception as e:
            return jsonify({'ok': False, 'error': f'Invalid tar.gz archive: {e}'}), 400

        has_core   = any('CoreConfig.xml'  in n for n in names)
        has_pgdump = any('cot.pgdump'      in n for n in names)
        if not has_core and not has_pgdump:
            return jsonify({'ok': False, 'error': 'Archive does not appear to be a TAK Server snapshot (missing CoreConfig.xml and cot.pgdump)'}), 400

        # Extract — honour the top-level directory inside the archive (tar -C SNAPSHOT_DIR)
        result = subprocess.run(
            ['tar', '-xzf', tmp_path, '-C', SNAPSHOT_DIR],
            capture_output=True, timeout=120
        )
        if result.returncode != 0:
            return jsonify({'ok': False, 'error': f'Extraction failed: {(result.stderr or b"").decode()[:200]}'}), 500

        # The archive may have a different top-level name than safe_label; find it
        # (tar extracts the directory that was originally tarred)
        extracted_label = safe_label
        for n in names:
            parts = n.split('/')
            if parts[0]:
                extracted_label = parts[0]
                break
        extracted_path = os.path.join(SNAPSHOT_DIR, extracted_label)

        # Compute size and build metadata
        total = 0
        for dirpath, _, filenames in os.walk(extracted_path):
            for fn in filenames:
                try: total += os.path.getsize(os.path.join(dirpath, fn))
                except Exception: pass
        size_mb = round(total / (1024 * 1024), 1)

        # Probe installed TAK version (dpkg then rpm) for the upload metadata
        _upload_ver = None
        try:
            for _pkg in ('takserver', 'takserver-core', 'takserver-database'):
                _r = subprocess.run(
                    f"dpkg -s {_pkg} 2>/dev/null | grep ^Version:",
                    shell=True, capture_output=True, text=True, timeout=5)
                if _r.returncode == 0 and _r.stdout.strip():
                    _upload_ver = _r.stdout.strip().replace('Version:', '').strip()
                    break
            if _upload_ver is None:
                _r = subprocess.run("rpm -q takserver 2>/dev/null", shell=True, capture_output=True, text=True, timeout=5)
                if _r.returncode == 0 and _r.stdout.strip():
                    _ver = _r.stdout.strip()
                    if _ver.startswith('takserver-'):
                        _ver = _ver.split('-', 1)[1]
                    _ver = _ver.replace('.noarch', '')
                    if _ver:
                        _upload_ver = _ver
        except Exception:
            pass

        meta = {
            'label':      extracted_label,
            'taken_at':   datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
            'source':     'uploaded',
            'tak_version': _upload_ver,
            'size_mb':    size_mb,
        }

        s = load_settings()
        snaps = [sn for sn in (s.get('tak_snapshots') or []) if sn.get('label') != extracted_label]
        snaps.append(meta)
        snaps.sort(key=lambda x: x.get('taken_at', ''), reverse=True)
        s['tak_snapshots'] = snaps[:50]
        save_settings(s)

        return jsonify({'ok': True, 'label': extracted_label, 'size_mb': size_mb})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)[:300]}), 500
    finally:
        try: os.remove(tmp_path)
        except Exception: pass


@app.route('/api/takserver/snapshot/<label>', methods=['DELETE'])
@login_required
def takserver_snapshot_delete_api(label):
    """Delete a snapshot directory and its settings entry."""
    ok, safe_label = _validate_snapshot_label(label)
    if not ok:
        return jsonify({'ok': False, 'error': safe_label}), 400
    snap_path = os.path.join(SNAPSHOT_DIR, safe_label)
    if os.path.isdir(snap_path):
        # /opt/tak/snapshots is root-owned — the non-root console can't rmtree it.
        # Route through the broker (rm is path-checked to /opt/tak/); on root this
        # runs `rm -rf` directly. label is already traversal-validated above.
        try:
            r = subprocess.run(_sudo_wrap(['rm', '-rf', snap_path]),
                               capture_output=True, text=True, timeout=60)
            if r.returncode != 0:
                return jsonify({'ok': False, 'error': (r.stderr or 'delete failed').strip()[:200]}), 500
        except Exception as e:
            return jsonify({'ok': False, 'error': str(e)[:200]}), 500
    try:
        s     = load_settings()
        snaps = [sn for sn in (s.get('tak_snapshots') or []) if sn.get('label') != safe_label]
        s['tak_snapshots'] = snaps
        save_settings(s)
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)[:200]}), 500
    return jsonify({'ok': True})


