def _verify_takserver_dpkg_ok(ulog):
    """v0.9.44: return True iff `takserver` is fully configured (`install ok installed`).

    A .deb postinstall can fail and leave the package `half-configured` while the rest of
    the upgrade looked fine — field: test6 sat half-configured for 3 weeks while the update
    reported done. Callers must NOT report success when this returns False. The console
    also auto-repairs a half-configured state on its next restart via
    _selfheal_takserver_half_configured, but we surface the failure immediately so it
    isn't silently missed."""
    try:
        r = subprocess.run(['dpkg-query', '-W', '-f=${Status}', 'takserver'],
                           capture_output=True, text=True, timeout=10)
        state = (r.stdout or '').strip()
    except Exception as e:
        ulog(f"  ⚠ Could not verify takserver dpkg state ({e}) — assuming OK")
        return True
    if r.returncode != 0 or not state:
        ulog("  ⚠ takserver not found in dpkg — skipping state verification")
        return True
    if state == 'install ok installed':
        ulog("✓ takserver dpkg state verified: install ok installed")
        return True
    ulog(f"✗ Upgrade left takserver dpkg state '{state}' — NOT fully configured.")
    ulog("  Reporting failure so it isn't missed. The console auto-repairs a half-configured")
    ulog("  state on its next restart; otherwise re-run the update once the postinstall")
    ulog("  cause is resolved.")
    return False


def run_takserver_upgrade(pkg_path):
    def ulog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        upgrade_log.append(entry)
        print(entry, flush=True)
    try:
        pkg_name = os.path.basename(pkg_path)
        ulog("=" * 50)
        ulog("TAK Server update (upgrade)")
        ulog("=" * 50)
        heap_backup = None
        heap_file = '/etc/default/takserver'
        if os.path.isfile(heap_file):
            try:
                heap_backup = _read_priv(heap_file)
                if heap_backup.strip():
                    ulog("✓ JVM heap settings backed up")
            except Exception:
                heap_backup = None

        # v0.9.3: Pre-upgrade snapshot — abort upgrade if snapshot fails
        snap_label = f"pre-upgrade-{datetime.utcnow().strftime('%Y%m%d-%H%M%S')}"
        ulog(f"Taking pre-upgrade snapshot [{snap_label}]…")
        snap_ok, snap_result = _tak_snapshot(snap_label, ulog)
        if snap_ok:
            ulog("✓ Pre-upgrade snapshot saved — rollback available via Snapshots & Recovery"
                 if snap_result.get('db_dump')
                 else "⚠ Pre-upgrade snapshot saved (config + certs) — but NO cot database dump captured; DB-level rollback is NOT available")
            # Tag source in settings
            try:
                _s = load_settings()
                for sn in (_s.get('tak_snapshots') or []):
                    if sn.get('label') == snap_label:
                        sn['source'] = 'pre-upgrade'
                save_settings(_s)
            except Exception:
                pass
        else:
            ulog(f"✗ Pre-upgrade snapshot failed — aborting upgrade to protect current data")
            ulog(f"  Detail: {snap_result}")
            upgrade_status.update({'running': False, 'complete': False, 'error': True})
            return

        wait_for_unattended_upgrade_worker(ulog, upgrade_log)
        wait_for_apt_lock(ulog, upgrade_log)
        dpkg_result = _tak_upgrade_dpkg_configure_a(ulog, upgrade_log, pkg_path=pkg_path)
        if not dpkg_result:
            upgrade_status.update({'running': False, 'complete': False, 'error': True})
            return
        if dpkg_result == 'ALREADY_INSTALLED':
            ulog("Package already installed via re-unpack + configure — skipping redundant apt-get install.")
        else:
            wait_for_apt_lock(ulog, upgrade_log)
            ulog("")
            ulog("Installing upgrade package: " + pkg_name)
            try:
                rc = _tak_upgrade_apt_install(os.path.dirname(pkg_path), pkg_name, upgrade_log, timeout_sec=3600)
            except subprocess.TimeoutExpired as te:
                ulog("Error: " + str(te))
                upgrade_status.update({'running': False, 'complete': False, 'error': True})
                return
            if rc != 0:
                ulog("Update failed (exit " + str(rc) + ")")
                upgrade_status.update({'running': False, 'complete': False, 'error': True})
                return
        ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
        if ne_changed:
            ulog(f"NameEntry fix: {ne_msg}")
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed:
            ulog(f"LDAP resync: {resync_msg}")
        settings = load_settings()
        takserver_host = _get_service_domain(settings, 'takserver')
        if takserver_host:
            ulog("Re-installing LE cert on 8446 (postinst may have reset connector)...")
            if install_le_cert_on_8446(takserver_host, ulog, wait_for_cert=False):
                ulog("\u2713 8446 LE cert restored")
            else:
                ulog("\u26a0 8446 LE cert not available \u2014 self-signed cert will be used until next Update config")
        if heap_backup and heap_backup.strip():
            try:
                _write_priv(heap_file, heap_backup)
                ulog("✓ JVM heap settings restored")
            except Exception as e:
                ulog(f"⚠ Could not restore heap settings: {e}")
        ulog("Restarting TAK Server...")
        subprocess.run(_tak_systemctl('restart'), shell=True, capture_output=True, text=True, timeout=90)  # v10.0.1: container-aware
        if _get_authentik_env_content(settings):
            ulog("Syncing webadmin to Authentik (LDAP cache refresh)...")
            ok_wa, err_wa = _ensure_authentik_webadmin(skip_bind_verify=False)
            if ok_wa:
                ulog("\u2713 webadmin synced to Authentik")
            else:
                ulog(f"\u26a0 webadmin sync: {err_wa or 'failed'} \u2014 use Sync webadmin button if 8446 login fails")
        generate_caddyfile(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
        if not _verify_takserver_dpkg_ok(ulog):
            upgrade_status.update({'running': False, 'complete': False, 'error': True})
            return
        ulog("TAK Server update complete.")
        upgrade_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        ulog("Error: " + str(e))
        upgrade_status.update({'running': False, 'complete': False, 'error': True})

def run_takserver_upgrade_rhel(rpm_path, external_db=None):
    """v10.0.1 — RHEL/Rocky native .rpm TAK Server upgrade via dnf. `dnf install` of the new .rpm
    upgrades in place and PRESERVES the existing cot database (TAK config guide §5.2.1 — dnf keeps
    the postgres data dir + a delete_old_cluster.sh). Mirrors the .deb path (run_takserver_upgrade):
    pre-upgrade snapshot (abort on fail) → dnf install → SELinux re-apply → CoreConfig sanitize +
    LDAP resync → 8446 LE cert → restart → webadmin sync. Logs to upgrade_log/upgrade_status.

    v10.0.5: external_db (dict from tak_deployment['external_db']) — when set (mode==external_db),
    run SchemaManager against the managed RDS after the dnf upgrade and BEFORE the restart, so a
    breaking schema jump is applied (the RHEL single path never did this — see HANDOFF 2026-07-01
    caveat). Default None = byte-identical to the single_server path."""
    def ulog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        upgrade_log.append(entry); print(entry, flush=True)
    def rc(cmd, label=None, timeout=3600):
        if label: ulog(label)
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=timeout)
            for ln in ((r.stdout or '') + (r.stderr or '')).strip().split('\n')[-12:]:
                if ln.strip(): upgrade_log.append("  " + ln)
            return r.returncode == 0
        except Exception as e:
            ulog(f"  ! {str(e)[:160]}"); return False
    try:
        pkg_name = os.path.basename(rpm_path)
        ulog("=" * 50); ulog("TAK Server update (upgrade) — RHEL/Rocky .rpm"); ulog("=" * 50)
        if subprocess.run(f'rpm -qp {shlex.quote(rpm_path)} > /dev/null 2>&1', shell=True, capture_output=True, timeout=30).returncode != 0:
            ulog("✗ FATAL: the uploaded .rpm is corrupted or incomplete (rpm -qp failed). Re-upload a fresh takserver-*.noarch.rpm.")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return

        # Pre-upgrade snapshot — abort if it fails (protect current data), same as the .deb path.
        snap_label = f"pre-upgrade-{datetime.utcnow().strftime('%Y%m%d-%H%M%S')}"
        ulog(f"Taking pre-upgrade snapshot [{snap_label}]…")
        snap_ok, snap_result = _tak_snapshot(snap_label, ulog)
        if not snap_ok:
            ulog(f"✗ Pre-upgrade snapshot failed — aborting upgrade to protect current data ({snap_result})")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return
        ulog("✓ Pre-upgrade snapshot saved — rollback available via Snapshots & Recovery"
             if snap_result.get('db_dump')
             else "⚠ Pre-upgrade snapshot saved (config + certs) — but NO cot database dump captured; DB-level rollback is NOT available")
        try:
            _s = load_settings()
            for sn in (_s.get('tak_snapshots') or []):
                if sn.get('label') == snap_label: sn['source'] = 'pre-upgrade'
            save_settings(_s)
        except Exception: pass

        # Ensure the build repo + postgres module state the guide requires (idempotent on an
        # already-installed box; powertools/CRB on Rocky, codeready-builder on RHEL).
        rc('dnf config-manager --set-enabled powertools 2>/dev/null; dnf config-manager --set-enabled crb 2>/dev/null; '
           'subscription-manager repos --enable codeready-builder-for-rhel-8-x86_64-rpms 2>/dev/null; '
           'dnf -qy module disable postgresql 2>/dev/null; true')
        # dnf install the new rpm — the guide's EXACT upgrade command (§5.2.1/5.2.2). The flag
        # --setopt=clean_requirements_on_remove=false is what PRESERVES the existing postgres DB +
        # deps when swapping the takserver rpm. NEVER use --allowerasing here (it would let dnf
        # erase the DB to resolve a conflict).
        ulog(""); ulog("Installing upgrade package: " + pkg_name)
        rc(f'dnf install -y {shlex.quote(rpm_path)} --setopt=clean_requirements_on_remove=false 2>&1', "Upgrading via dnf (guide §5.2.1)...")
        if not os.path.exists('/opt/tak'):
            ulog("  /opt/tak missing after dnf install — forcing reinstall...")
            rc(f'dnf reinstall -y {shlex.quote(rpm_path)} 2>&1 || dnf install -y {shlex.quote(rpm_path)} --setopt=clean_requirements_on_remove=false 2>&1')
        if not os.path.exists('/opt/tak'):
            ulog("✗ FATAL: /opt/tak not found after rpm upgrade — check `rpm -q takserver` / `dnf history`.")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return

        # SELinux: the rpm ships apply-selinux.sh — re-apply under enforcing (postinst may reset it).
        _enf = subprocess.run('getenforce 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
        if _enf == 'Enforcing' and os.path.exists('/opt/tak/apply-selinux.sh'):
            ulog("Re-applying TAK Server SELinux policy...")
            subprocess.run(_sudo_wrap(['bash', '/opt/tak/apply-selinux.sh']), cwd='/opt/tak', capture_output=True, text=True, timeout=120)

        ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
        if ne_changed: ulog(f"NameEntry fix: {ne_msg}")
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed: ulog(f"LDAP resync: {resync_msg}")
        settings = load_settings()
        takserver_host = _get_service_domain(settings, 'takserver')
        if takserver_host:
            ulog("Re-installing LE cert on 8446 (postinst may have reset connector)...")
            install_le_cert_on_8446(takserver_host, ulog, wait_for_cert=False)
        # v10.0.5 external-DB: apply the new version's schema deltas to the managed RDS BEFORE
        # the restart (the RHEL single path never did — validated 5.6→5.7 only because that jump
        # was schema-compatible). SchemaManager reads the JDBC-preserved CoreConfig.xml from
        # /opt/tak (no CLI flags — same proven block as the external-DB deploy). Idempotent
        # 'upgrade': "already up to date" on a no-op jump.
        if external_db and (external_db.get('host') or '').strip() and os.path.exists('/opt/tak/db-utils/SchemaManager.jar'):
            ulog("External DB: running SchemaManager against RDS (applying schema deltas)...")
            _sm = subprocess.run('cd /opt/tak && java -jar /opt/tak/db-utils/SchemaManager.jar upgrade 2>&1',
                                 shell=True, capture_output=True, text=True, timeout=300)
            _smo = (_sm.stdout or '') + (_sm.stderr or '')
            for _ln in _smo.strip().split('\n')[-12:]:
                if _ln.strip(): upgrade_log.append("  " + _ln)
            if _sm.returncode == 0 or 'SchemaManager complete' in _smo or 'up to date' in _smo.lower():
                ulog("✓ SchemaManager upgrade complete (RDS schema current)")
            else:
                ulog(f"⚠ SchemaManager exited {_sm.returncode} — check output above; TAK may still start if schema was partially applied.")
        ulog("Restarting TAK Server...")
        subprocess.run(_tak_systemctl('restart'), shell=True, capture_output=True, text=True, timeout=90)
        if _get_authentik_env_content(settings):
            ok_wa, err_wa = _ensure_authentik_webadmin(skip_bind_verify=False)
            ulog("✓ webadmin synced to Authentik" if ok_wa else f"⚠ webadmin sync: {err_wa or 'failed'} — use Sync webadmin if 8446 login fails")
        generate_caddyfile(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
        _rq = subprocess.run('rpm -q takserver 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
        ulog(f"✓ Installed: {_rq}" if _rq.startswith('takserver') else "⚠ rpm -q takserver did not report installed — verify manually")
        ulog("TAK Server update complete.")
        upgrade_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        ulog("Error: " + str(e))
        upgrade_status.update({'running': False, 'complete': False, 'error': True})


def run_takserver_upgrade_container(zip_path):
    """v10.0.1 — DATA-PRESERVING container upgrade. Rebuilds the TAK Server image from the new
    takserver-docker-*.zip and recreates the containers while KEEPING the database (the
    TAK_DB_VOLUME named volume) and the existing CA/certs + CoreConfig + UserAuthenticationFile.
    Mirrors _deploy_takserver_container's unpack/build/run, but: extracts the new bundle ALONGSIDE
    the old one (both inside the allowlisted bundle root) and carries certs/CoreConfig over in
    place, NEVER `docker volume rm`s the DB, and does NO cert-gen / DB re-provision. Logs to
    upgrade_log/upgrade_status (the Update panel). SACRED: the DB volume must never be removed
    on this path — that is the whole point of an upgrade vs a redeploy."""
    def ulog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        upgrade_log.append(entry); print(entry, flush=True)
    def rc(cmd, timeout=2400):
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=timeout)
            if r.returncode != 0 and (r.stderr or r.stdout):
                ulog(f"    ! {((r.stderr or r.stdout) or '').strip()[:200]}")
            return r.returncode == 0
        except Exception as e:
            ulog(f"    ! {str(e)[:160]}"); return False
    def _fail(msg):
        ulog(f"✗ {msg}")
        upgrade_status.update({'running': False, 'complete': False, 'error': True})
    try:
        ulog("=" * 50)
        ulog(f"TAK Server CONTAINER upgrade — {os.path.basename(zip_path)}")
        ulog("  Database volume + certificates are PRESERVED (no volume wipe, no cert-gen)")
        ulog("=" * 50)
        old_tak = os.path.realpath('/opt/tak')        # current bundle's tak/ dir
        old_ctx = os.path.dirname(old_tak)            # current bundle dir (inside TAK_DOCKER_ROOT)

        # 1) Stop+remove the OLD containers — NOT the volume (the DB stays in TAK_DB_VOLUME).
        ulog("Step 1/6: Stopping current containers (database volume kept)...")
        subprocess.run(_sudo_wrap(['docker', 'rm', '-f', TAK_CONTAINER, TAK_DB_CONTAINER]), capture_output=True, timeout=90)

        # 2) Extract the new bundle ALONGSIDE the old (no wipe — keeps the old certs reachable for
        #    an in-place broker copy; both dirs are inside the allowlisted ~/tak-docker root).
        ulog("Step 2/6: Unpacking new bundle...")
        try:
            import zipfile
            with zipfile.ZipFile(zip_path) as zf:
                for info in zf.infolist():
                    out_path = zf.extract(info, TAK_DOCKER_ROOT)
                    mode = (info.external_attr >> 16) & 0xFFFF
                    if mode and not info.is_dir():
                        try: os.chmod(out_path, mode)
                        except OSError: pass
        except Exception as e:
            return _fail(f"Failed to extract the new bundle: {str(e)[:160]}")
        entries = [d for d in os.listdir(TAK_DOCKER_ROOT)
                   if os.path.isdir(os.path.join(TAK_DOCKER_ROOT, d)) and 'docker' in d.lower()
                   and os.path.isfile(os.path.join(TAK_DOCKER_ROOT, d, 'docker', 'Dockerfile.takserver'))
                   and os.path.join(TAK_DOCKER_ROOT, d) != old_ctx]
        entries.sort(key=lambda d: os.path.getmtime(os.path.join(TAK_DOCKER_ROOT, d)), reverse=True)
        if not entries:
            return _fail("No NEW takserver-docker bundle found (same version as installed, or not an official zip). "
                         "Upload a different takserver-docker-*.zip. The old install is untouched.")
        new_ctx = os.path.join(TAK_DOCKER_ROOT, entries[0])
        new_tak = os.path.join(new_ctx, 'tak')
        ulog(f"✓ New bundle: {entries[0]}")

        # 3) Carry the PRESERVED certs / CoreConfig / UserAuth over old -> new (in place, broker),
        #    re-point /opt/tak, then drop the old bundle dir.
        ulog("Step 3/6: Carrying over certs + CoreConfig (preserved)...")
        subprocess.run(_sudo_wrap(['rm', '-rf', os.path.join(new_tak, 'certs', 'files')]), capture_output=True, timeout=30)
        subprocess.run(_sudo_wrap(['mkdir', '-p', os.path.join(new_tak, 'certs')]), capture_output=True, timeout=10)
        subprocess.run(_sudo_wrap(['cp', '-rp', os.path.join(old_tak, 'certs', 'files'), os.path.join(new_tak, 'certs', 'files')]), capture_output=True, timeout=120)
        for f in ('CoreConfig.xml', 'UserAuthenticationFile.xml'):
            subprocess.run(_sudo_wrap(['cp', '-p', os.path.join(old_tak, f), os.path.join(new_tak, f)]), capture_output=True, timeout=30)
        if not os.path.exists(os.path.join(new_tak, 'certs', 'files', 'takserver.jks')):
            return _fail("Certs did not carry over (takserver.jks missing in new bundle) — aborting before swap. Old install untouched.")
        subprocess.run(_sudo_wrap(['rm', '-f', '/opt/tak']), capture_output=True, timeout=10)
        rc(f'ln -sfn {shlex.quote(new_tak)} /opt/tak', timeout=15)
        if old_ctx and old_ctx != new_ctx:
            subprocess.run(_sudo_wrap(['rm', '-rf', old_ctx]), capture_output=True, timeout=60)
        ulog("✓ certs + CoreConfig carried over; /opt/tak re-pointed")

        # 4) Build the new-version images.
        ulog("Step 4/6: Building new TAK Server images (minutes on arm64)...")
        if not rc(f'cd {shlex.quote(new_ctx)} && docker build -t takserver_db -f docker/Dockerfile.takserver-db . 2>&1'):
            return _fail("DB image build failed.")
        if not rc(f'cd {shlex.quote(new_ctx)} && docker build -t {TAK_CONTAINER} -f docker/Dockerfile.takserver . 2>&1'):
            return _fail("TAK Server image build failed.")
        ulog("✓ Images built")

        # 5) Recreate the containers on the SAME volume + network. NO `docker volume rm`.
        ulog("Step 5/6: Recreating containers (DB volume reused)...")
        rc(f'docker network inspect {TAK_DOCKER_NET} >/dev/null 2>&1 || docker network create {TAK_DOCKER_NET}', timeout=30)
        rc(f'docker run --mount source={TAK_DB_VOLUME},destination=/var/lib/postgresql '
           f'-v {shlex.quote(new_tak)}:/opt/tak:z --restart=always --network {TAK_DOCKER_NET} '
           f'--network-alias tak-database --name {TAK_DB_CONTAINER} -d takserver_db', timeout=120)
        time.sleep(8)
        # CREATE (not run -d) so the Authentik LDAP network is attached BEFORE the JVM starts.
        # If TAK boots without the LDAP net reachable, it loads its group cache EMPTY -> every user
        # resolves to "not a member of any group" -> "no channels", needing a manual restart+resync.
        # create -> connect the LDAP net -> start guarantees LDAP (ldap://authentik-ldap-1:3389) is
        # resolvable from the first boot, so groups load and webadmin/EUD channels work hands-off.
        rc(f'docker create -v {shlex.quote(new_tak)}:/opt/tak:z --restart=always '
           f'-p 8089:8089 -p 8443:8443 -p 8446:8446 --network {TAK_DOCKER_NET} '
           f'--name {TAK_CONTAINER} {TAK_CONTAINER}', timeout=60)
        _aknet, _aklname = _ensure_tak_on_authentik_network()  # connect LDAP net to the created (not-yet-started) container
        if _aknet:
            ulog(f"✓ Joined Authentik network ({_aknet}) before start — LDAP/groups reachable from boot")
        rc(f'docker start {TAK_CONTAINER}', timeout=90)

        # 6) Wait for messaging (TAK runs its schema migrations here against the preserved DB).
        ulog("Step 6/6: Waiting for messaging microservice (schema migration; up to 10 min)...")
        _up = False
        for waited in range(0, 600, 10):
            time.sleep(10)
            r = subprocess.run(_sudo_wrap(['docker', 'exec', TAK_CONTAINER, 'grep', '-q', 'Started TAK Server messaging Microservice', '/opt/tak/logs/takserver-messaging.log']), capture_output=True)
            if r.returncode == 0:
                _up = True; ulog("✓ TAK Server messaging microservice started"); break
            if waited and waited % 60 == 0:
                upgrade_log.append(f"  ⏳ {waited//60} min …")
        if not _up:
            ulog("⚠ Did not see messaging start within 10 min — check `docker logs takserver`. DB + certs were preserved (no data loss).")
        # Re-sync the TAK Portal to the recreated TAK JVM — the rotation does this (Step 7) and
        # it's exactly what 'patches the Portal back to working' on native. The upgrade recreated
        # the containers, so the Portal must refresh its client cert + CA and reconnect, or
        # webadmin/enrollment via the Portal breaks. Same helper, same as the native rotation.
        try:
            _pr = subprocess.run(_sudo_wrap(['docker', 'ps', '--format', '{{.Names}}']), capture_output=True, text=True, timeout=10)
            if 'tak-portal' in (_pr.stdout or ''):
                ulog("Re-syncing TAK Portal certs + reconnecting to the upgraded TAK Server...")
                _tp_ok, _tp_msg = _takportal_sync_certs(plog=ulog, restart=True)
                ulog(f"  {'✓' if _tp_ok else '⚠'} TAK Portal cert sync: {_tp_msg}")
        except Exception as _tpe:
            ulog(f"  ⚠ TAK Portal cert sync skipped: {str(_tpe)[:120]}")
        ulog("")
        ulog("✓ Container upgrade complete — database and certificates preserved.")
        upgrade_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        ulog(f"✗ Container upgrade failed: {str(e)[:200]}")
        upgrade_status.update({'running': False, 'complete': False, 'error': True})


def run_takserver_upgrade_two_server(core_pkg_path, db_pkg_path, s1_cfg, tak_cfg):
    """Two-server upgrade: core first (local), then database (SSH to Server One)."""
    def ulog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        upgrade_log.append(entry)
        print(entry, flush=True)
    try:
        core_name = os.path.basename(core_pkg_path)
        db_name = os.path.basename(db_pkg_path)
        s1_host = s1_cfg.get('host', '')
        ulog("=" * 50)
        ulog("TAK Server Two-Server Update")
        ulog(f"  Core package: {core_name}")
        ulog(f"  Database package: {db_name}")
        ulog(f"  Server One (DB): {s1_host}")
        ulog("=" * 50)

        heap_backup = None
        heap_file = '/etc/default/takserver'
        if os.path.isfile(heap_file):
            try:
                heap_backup = _read_priv(heap_file)
                if heap_backup.strip():
                    ulog("✓ JVM heap settings backed up")
            except Exception:
                heap_backup = None
        wait_for_unattended_upgrade_worker(ulog, upgrade_log)

        # Step 1: Update Core (local) — per TAK guide, core first
        ulog("")
        ulog("━━━ Step 1/4: Stopping TAK Server ━━━")
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'takserver']), capture_output=True, text=True, timeout=90)
        ulog("✓ TAK Server stopped")

        ulog("")
        ulog("━━━ Step 2/4: Upgrading Core (this host) ━━━")
        wait_for_apt_lock(ulog, upgrade_log)
        dpkg_result = _tak_upgrade_dpkg_configure_a(ulog, upgrade_log, pkg_path=core_pkg_path)
        if not dpkg_result:
            upgrade_status.update({'running': False, 'complete': False, 'error': True})
            return
        if dpkg_result == 'ALREADY_INSTALLED':
            ulog("Core already installed via re-unpack + configure — skipping redundant apt-get install.")
        else:
            wait_for_apt_lock(ulog, upgrade_log)
            ulog(f"Installing {core_name}...")
            try:
                rc = _tak_upgrade_apt_install(os.path.dirname(core_pkg_path), core_name, upgrade_log, timeout_sec=3600)
            except subprocess.TimeoutExpired as te:
                ulog(f"✗ Error: {te}")
                upgrade_status.update({'running': False, 'complete': False, 'error': True})
                return
            if rc != 0:
                ulog(f"✗ Core upgrade failed (exit {rc})")
                upgrade_status.update({'running': False, 'complete': False, 'error': True})
                return
        ulog("✓ Core package upgraded")

        # Restore JDBC URL to Server One (the upgrade may have reset CoreConfig)
        db_host = s1_host
        db_port = int(tak_cfg.get('database', {}).get('port') or 5432)
        db_password = (tak_cfg.get('database', {}).get('password') or '').strip()
        if db_host:
            import re as _re
            try:
                with open('/opt/tak/CoreConfig.xml', 'r') as f:
                    cc = f.read()
                jdbc_url = f'jdbc:postgresql://{db_host}:{db_port}/cot'
                if '127.0.0.1' in cc and db_host not in cc:
                    cc = _re.sub(r'jdbc:postgresql://[^"]*', jdbc_url, cc)
                    if db_password:
                        cc = _re.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + db_password + m.group(2), cc)
                    _write_priv('/opt/tak/CoreConfig.xml', cc)
                    ulog(f"✓ CoreConfig.xml JDBC restored to {db_host}:{db_port}")
                else:
                    ulog(f"✓ CoreConfig.xml JDBC already points to {db_host}")
            except Exception as e:
                ulog(f"⚠ Could not verify CoreConfig JDBC: {e}")

        # Step 3: Update Database (Server One via SSH)
        ulog("")
        ulog(f"━━━ Step 3/4: Upgrading Database on Server One ({s1_host}) ━━━")
        ulog(f"Copying {db_name} to Server One...")
        ok, scp_out = _scp_to_host(s1_cfg, db_pkg_path, '/tmp/', timeout=300)
        if not ok:
            ulog(f"✗ SCP failed: {(scp_out or '')[:300]}")
            ulog("Core was upgraded but database was NOT. You can manually install the database .deb on Server One.")
            upgrade_status.update({'running': False, 'complete': False, 'error': True})
            return
        ulog("✓ Package copied to Server One")

        install_cmd = (
            f'cd /tmp && sudo DEBIAN_FRONTEND=noninteractive apt-get install -y ./{db_name} 2>&1'
        )
        ulog(f"Installing {db_name} on Server One...")
        ok, install_out = _ssh_probe(s1_cfg, install_cmd, timeout=600)
        if install_out:
            for line in (install_out or '').strip().split('\n'):
                if line.strip() and 'NEEDRESTART' not in line:
                    upgrade_log.append("  " + line)
        if not ok:
            # Verify PG is still running (SchemaManager may exit non-zero with warnings)
            _ssh_probe(s1_cfg, 'sudo pg_ctlcluster 15 main start 2>/dev/null; true', timeout=20)
            verify_cmd = 'sudo -u postgres psql -lqt 2>/dev/null | grep -q cot && pg_isready -q && echo PG_OK'
            vok, vout = _ssh_probe(s1_cfg, verify_cmd, timeout=10)
            if vok and 'PG_OK' in (vout or ''):
                ulog("⚠ Install had warnings but PostgreSQL is running and cot database exists")
            else:
                ulog(f"✗ Database upgrade failed on Server One")
                ulog("Core was upgraded but database upgrade had issues. Check Server One manually.")
                upgrade_status.update({'running': False, 'complete': False, 'error': True})
                return
        ulog("✓ Database package upgraded on Server One")

        # Re-fetch password from Server One — the DB package upgrade may have regenerated it
        fresh_pw, _pw_err = _fetch_db_password_from_server_one(s1_cfg)
        if fresh_pw and fresh_pw != db_password:
            pw_ok, pw_msg = _verify_server_one_db_password(s1_cfg, fresh_pw, db_port=db_port)
            if pw_ok:
                ulog("⚠ DB password changed during upgrade — re-patching CoreConfig.xml")
                try:
                    with open('/opt/tak/CoreConfig.xml', 'r') as f:
                        cc = f.read()
                    cc = _re.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + fresh_pw + m.group(2), cc)
                    _write_priv('/opt/tak/CoreConfig.xml', cc)
                    db_password = fresh_pw
                    tak_cfg.setdefault('database', {})['password'] = fresh_pw
                    settings = load_settings()
                    settings['tak_deployment'] = tak_cfg
                    save_settings(settings)
                    ulog("✓ CoreConfig.xml and saved settings updated with new DB password")
                except Exception as e:
                    ulog(f"⚠ Could not update CoreConfig with new password: {e}")
            else:
                ulog(f"⚠ Fresh password from Server One also failed validation ({pw_msg})")
        elif fresh_pw:
            pw_ok, pw_msg = _verify_server_one_db_password(s1_cfg, fresh_pw, db_port=db_port)
            if pw_ok:
                ulog("✓ DB credential verified after upgrade")
            else:
                ulog(f"⚠ DB credential check failed after upgrade: {pw_msg}")

        # Step 4: Start TAK Server
        ulog("")
        ulog("━━━ Step 4/4: Starting TAK Server ━━━")
        if heap_backup and heap_backup.strip():
            try:
                _write_priv(heap_file, heap_backup)
                ulog("✓ JVM heap settings restored")
            except Exception as e:
                ulog(f"⚠ Could not restore heap settings: {e}")
        ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
        if ne_changed:
            ulog(f"NameEntry fix: {ne_msg}")
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed:
            ulog(f"LDAP resync: {resync_msg}")
        settings = load_settings()
        takserver_host = _get_service_domain(settings, 'takserver')
        if takserver_host:
            ulog("Re-installing LE cert on 8446 (postinst may have reset connector)...")
            if install_le_cert_on_8446(takserver_host, ulog, wait_for_cert=False):
                ulog("\u2713 8446 LE cert restored")
            else:
                ulog("\u26a0 8446 LE cert not available \u2014 self-signed cert will be used until next Update config")
        subprocess.run(_sudo_wrap(['systemctl', 'start', 'takserver']), capture_output=True, text=True, timeout=90)
        ulog("Waiting 30 seconds for startup...")
        for remaining in range(20, -1, -10):
            time.sleep(10)
            upgrade_log.append(f"  \u23f3 {remaining//60:02d}:{remaining%60:02d} remaining")
        ulog("\u2713 TAK Server started")
        if _get_authentik_env_content(settings):
            ulog("Syncing webadmin to Authentik (LDAP cache refresh)...")
            ok_wa, err_wa = _ensure_authentik_webadmin(skip_bind_verify=False)
            if ok_wa:
                ulog("\u2713 webadmin synced to Authentik")
            else:
                ulog(f"\u26a0 webadmin sync: {err_wa or 'failed'} \u2014 use Sync webadmin button if 8446 login fails")
        generate_caddyfile(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)

        if not _verify_takserver_dpkg_ok(ulog):
            upgrade_status.update({'running': False, 'complete': False, 'error': True})
            return
        ulog("")
        ulog("=" * 50)
        ulog("\u2713 Two-server update complete")
        ulog(f"  Core: upgraded on this host")
        ulog(f"  Database: upgraded on {s1_host}")
        ulog("=" * 50)
        upgrade_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        ulog(f"✗ Error: {str(e)}")
        upgrade_status.update({'running': False, 'complete': False, 'error': True})


def run_takserver_upgrade_two_server_rhel(core_rpm_path, db_rpm_path, s1_cfg, tak_cfg):
    """v10.0.5 — RHEL/Rocky TWO-SERVER (split) TAK Server upgrade. dnf mirror of
    run_takserver_upgrade_two_server: core first (local dnf), then the takserver-database
    .noarch.rpm on Server One (SSH dnf), then SchemaManager on Server One, restore JDBC→Server
    One in CoreConfig, restart. The dispatcher used to funnel ALL RHEL updates to the single-
    server run_takserver_upgrade_rhel, so a RHEL split update never upgraded the DB box at all.

    CRUX (rhel-split-schema-build): the takserver-database .noarch.rpm deliberately does NOT run
    SchemaManager, so a split DB upgrade leaves the schema at the OLD version → the upgraded core
    500s on /oauth/token ('group_bitpos_sequence does not exist') and 8446 login fails. We run
    SchemaManager explicitly on Server One (same as _setup_server_one_rhel Step 7) after the db
    rpm upgrade. Logs to upgrade_log/upgrade_status."""
    def ulog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        upgrade_log.append(entry); print(entry, flush=True)
    def rc(cmd, label=None, timeout=3600):
        if label: ulog(label)
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=timeout)
            for ln in ((r.stdout or '') + (r.stderr or '')).strip().split('\n')[-12:]:
                if ln.strip(): upgrade_log.append("  " + ln)
            return r.returncode == 0
        except Exception as e:
            ulog(f"  ! {str(e)[:160]}"); return False
    try:
        import re as _re
        core_name = os.path.basename(core_rpm_path)
        db_name = os.path.basename(db_rpm_path)
        s1_host = s1_cfg.get('host', '')
        db_port = int(tak_cfg.get('database', {}).get('port') or 5432)
        db_password = (tak_cfg.get('database', {}).get('password') or '').strip()
        ulog("=" * 50)
        ulog("TAK Server Two-Server Update — RHEL/Rocky .rpm")
        ulog(f"  Core package: {core_name}")
        ulog(f"  Database package: {db_name}")
        ulog(f"  Server One (DB): {s1_host}")
        ulog("=" * 50)
        if subprocess.run(f'rpm -qp {shlex.quote(core_rpm_path)} > /dev/null 2>&1', shell=True, capture_output=True, timeout=30).returncode != 0:
            ulog("✗ FATAL: the uploaded takserver-core .rpm is corrupted or incomplete (rpm -qp failed). Re-upload a fresh takserver-core-*.noarch.rpm.")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return

        # Pre-upgrade snapshot — abort if it fails (protect current data), same as the single path.
        snap_label = f"pre-upgrade-{datetime.utcnow().strftime('%Y%m%d-%H%M%S')}"
        ulog(f"Taking pre-upgrade snapshot [{snap_label}]…")
        snap_ok, snap_result = _tak_snapshot(snap_label, ulog)
        if not snap_ok:
            ulog(f"✗ Pre-upgrade snapshot failed — aborting upgrade to protect current data ({snap_result})")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return
        ulog("✓ Pre-upgrade snapshot saved — rollback available via Snapshots & Recovery"
             if snap_result.get('db_dump')
             else "⚠ Pre-upgrade snapshot saved (config + certs) — but NO cot database dump captured; DB-level rollback is NOT available")
        try:
            _s = load_settings()
            for sn in (_s.get('tak_snapshots') or []):
                if sn.get('label') == snap_label: sn['source'] = 'pre-upgrade'
            save_settings(_s)
        except Exception: pass

        # heap backup (native RHEL keeps JVM heap in /etc/default/takserver, same as .deb)
        heap_backup = None
        heap_file = '/etc/default/takserver'
        if os.path.isfile(heap_file):
            try:
                heap_backup = _read_priv(heap_file)
                if heap_backup and heap_backup.strip(): ulog("✓ JVM heap settings backed up")
            except Exception:
                heap_backup = None

        # Repo prereqs (idempotent on an already-installed box; powertools/CRB + module disable).
        rc('dnf config-manager --set-enabled powertools 2>/dev/null; dnf config-manager --set-enabled crb 2>/dev/null; '
           'subscription-manager repos --enable codeready-builder-for-rhel-8-x86_64-rpms 2>/dev/null; '
           'dnf -qy module disable postgresql 2>/dev/null; true')

        # ━━━ Step 1/5: Stop TAK Server ━━━
        ulog(""); ulog("━━━ Step 1/5: Stopping TAK Server ━━━")
        subprocess.run(_tak_systemctl('stop'), shell=True, capture_output=True, text=True, timeout=90)
        ulog("✓ TAK Server stopped")

        # ━━━ Step 2/5: Upgrade Core (this host, dnf) ━━━
        ulog(""); ulog("━━━ Step 2/5: Upgrading Core (this host) ━━━")
        _core_ok = rc(f'dnf install -y {shlex.quote(core_rpm_path)} --setopt=clean_requirements_on_remove=false 2>&1',
                      "Upgrading takserver-core via dnf (guide §5.2.1)...")
        if not _core_ok:
            # Idempotency: dnf can exit non-zero on a re-install / scriptlet hiccup though the
            # package installed fine (mirrors the deploy pre-stage fix). rpm -q = truth.
            _chk = subprocess.run('rpm -q takserver-core', shell=True, capture_output=True, text=True, timeout=30, env=_broker_shim_env())
            if _chk.returncode == 0:
                _core_ok = True
                ulog("takserver-core dnf exit non-zero but rpm -q confirms it is installed — continuing (idempotent).")
        if not _core_ok:
            ulog("✗ Core upgrade failed — check the dnf error above."); upgrade_status.update({'running': False, 'complete': False, 'error': True}); return
        if not os.path.exists('/opt/tak'):
            ulog("✗ FATAL: /opt/tak not found after core rpm upgrade — check `rpm -q takserver-core` / `dnf history`.")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return
        ulog("✓ Core package upgraded")

        # SELinux: re-apply under enforcing (postinst may reset it).
        _enf = subprocess.run('getenforce 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
        if _enf == 'Enforcing' and os.path.exists('/opt/tak/apply-selinux.sh'):
            ulog("Re-applying TAK Server SELinux policy...")
            subprocess.run(_sudo_wrap(['bash', '/opt/tak/apply-selinux.sh']), cwd='/opt/tak', capture_output=True, text=True, timeout=120)

        # Restore JDBC → Server One in CoreConfig (upgrade may reset it). Idempotent guard.
        if s1_host:
            try:
                cc = _read_priv('/opt/tak/CoreConfig.xml')
                jdbc_url = f'jdbc:postgresql://{s1_host}:{db_port}/cot'
                if cc and '127.0.0.1' in cc and s1_host not in cc:
                    cc = _re.sub(r'jdbc:postgresql://[^"]*', jdbc_url, cc)
                    if db_password:
                        cc = _re.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + db_password + m.group(2), cc)
                    _write_priv('/opt/tak/CoreConfig.xml', cc)
                    ulog(f"✓ CoreConfig.xml JDBC restored to {s1_host}:{db_port}")
                else:
                    ulog(f"✓ CoreConfig.xml JDBC already points to {s1_host}")
            except Exception as e:
                ulog(f"⚠ Could not verify CoreConfig JDBC: {e}")

        # ━━━ Step 3/5: Upgrade Database on Server One (SSH dnf) ━━━
        ulog(""); ulog(f"━━━ Step 3/5: Upgrading Database on Server One ({s1_host}) ━━━")
        ok, scp_out = _scp_to_host(s1_cfg, db_rpm_path, '/tmp/', timeout=300)
        if not ok:
            ulog(f"✗ SCP failed: {(scp_out or '')[:300]}")
            ulog("Core was upgraded but database was NOT. You can manually `dnf install` the database .rpm on Server One.")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return
        ulog("✓ Package copied to Server One")
        install_cmd = f'cd /tmp && sudo dnf -y install ./{db_name} --setopt=clean_requirements_on_remove=false 2>&1; echo RC=$?'
        ulog(f"Installing {db_name} on Server One (dnf)...")
        ok, install_out = _ssh_probe(s1_cfg, install_cmd, timeout=600)
        for line in (install_out or '').strip().split('\n')[-12:]:
            if line.strip(): upgrade_log.append("  " + line)
        # dnf can exit non-zero on a re-install though the pkg is fine — verify PG + cot on Server One.
        verify_cmd = ('PGSVC=postgresql-15; systemctl list-unit-files 2>/dev/null | grep -q "^postgresql-15" || PGSVC=postgresql; '
                      'sudo -u postgres psql -lqt 2>/dev/null | grep -qw cot && systemctl is-active "$PGSVC" >/dev/null 2>&1 && echo PG_OK')
        vok, vout = _ssh_probe(s1_cfg, verify_cmd, timeout=15)
        if 'PG_OK' in (vout or ''):
            ulog("✓ Database package upgraded on Server One (PostgreSQL running, cot present)")
        else:
            ulog("✗ Database upgrade failed on Server One (PostgreSQL/cot check did not pass). Check Server One manually.")
            upgrade_status.update({'running': False, 'complete': False, 'error': True}); return

        # Re-fetch password from Server One — the DB rpm upgrade may have regenerated it.
        fresh_pw, _pw_err = _fetch_db_password_from_server_one(s1_cfg)
        if fresh_pw and fresh_pw != db_password:
            pw_ok, pw_msg = _verify_server_one_db_password(s1_cfg, fresh_pw, db_port=db_port)
            if pw_ok:
                ulog("⚠ DB password changed during upgrade — re-patching CoreConfig.xml")
                try:
                    cc = _read_priv('/opt/tak/CoreConfig.xml')
                    cc = _re.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + fresh_pw + m.group(2), cc)
                    _write_priv('/opt/tak/CoreConfig.xml', cc)
                    db_password = fresh_pw
                    tak_cfg.setdefault('database', {})['password'] = fresh_pw
                    _s2 = load_settings(); _s2['tak_deployment'] = tak_cfg; save_settings(_s2)
                    ulog("✓ CoreConfig.xml and saved settings updated with new DB password")
                except Exception as e:
                    ulog(f"⚠ Could not update CoreConfig with new password: {e}")
            else:
                ulog(f"⚠ Fresh password from Server One also failed validation ({pw_msg})")
        elif fresh_pw:
            pw_ok, pw_msg = _verify_server_one_db_password(s1_cfg, fresh_pw, db_port=db_port)
            ulog("✓ DB credential verified after upgrade" if pw_ok else f"⚠ DB credential check failed after upgrade: {pw_msg}")

        # ━━━ Step 4/5: Build schema on Server One (SchemaManager) ━━━
        # The .noarch.rpm does NOT build/upgrade the schema (rhel-split-schema-build). Run it
        # explicitly against the split DB so the new version's deltas land, else the upgraded
        # core 500s on /oauth/token. Idempotent 'upgrade' (mirrors _setup_server_one_rhel Step 7).
        ulog(""); ulog("━━━ Step 4/5: Applying TAK schema on Server One (SchemaManager) ━━━")
        if db_password:
            schema_cmd = (
                'if [ -f /opt/tak/db-utils/SchemaManager.jar ]; then '
                'cd /opt/tak/db-utils && sudo java -jar SchemaManager.jar '
                f'-url jdbc:postgresql://127.0.0.1:{db_port}/cot -user martiuser '
                f'-password {shlex.quote(db_password)} upgrade 2>&1 | tail -12; '
                'else echo NO_SCHEMA_MANAGER; fi'
            )
            _, scout = _ssh_probe(s1_cfg, schema_cmd, timeout=300)
            for line in (scout or '').strip().split('\n')[-12:]:
                if line.strip(): upgrade_log.append("  " + line)
            if 'up to date' in (scout or '') or 'Successfully applied' in (scout or ''):
                ulog("✓ TAK schema applied on Server One (SchemaManager upgrade)")
            elif 'NO_SCHEMA_MANAGER' in (scout or ''):
                ulog("⚠ SchemaManager.jar not found on Server One — schema NOT upgraded; 8446 login may 500 on a breaking jump.")
            else:
                ulog("⚠ SchemaManager did not confirm — verify Server One cot tables; 8446 login may 500 on a breaking jump.")
        else:
            ulog("⚠ No DB password available — cannot run SchemaManager on Server One. Schema NOT upgraded.")

        # ━━━ Step 5/5: Start TAK Server ━━━
        ulog(""); ulog("━━━ Step 5/5: Starting TAK Server ━━━")
        if heap_backup and heap_backup.strip():
            try:
                _write_priv(heap_file, heap_backup); ulog("✓ JVM heap settings restored")
            except Exception as e:
                ulog(f"⚠ Could not restore heap settings: {e}")
        ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
        if ne_changed: ulog(f"NameEntry fix: {ne_msg}")
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed: ulog(f"LDAP resync: {resync_msg}")
        settings = load_settings()
        takserver_host = _get_service_domain(settings, 'takserver')
        if takserver_host:
            ulog("Re-installing LE cert on 8446 (postinst may have reset connector)...")
            install_le_cert_on_8446(takserver_host, ulog, wait_for_cert=False)
        subprocess.run(_tak_systemctl('restart'), shell=True, capture_output=True, text=True, timeout=90)
        ulog("Waiting 30 seconds for startup...")
        for remaining in range(20, -1, -10):
            time.sleep(10)
            upgrade_log.append(f"  ⏳ {remaining//60:02d}:{remaining%60:02d} remaining")
        ulog("✓ TAK Server started")
        if _get_authentik_env_content(settings):
            ok_wa, err_wa = _ensure_authentik_webadmin(skip_bind_verify=False)
            ulog("✓ webadmin synced to Authentik" if ok_wa else f"⚠ webadmin sync: {err_wa or 'failed'} — use Sync webadmin if 8446 login fails")
        generate_caddyfile(settings)
        subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True, timeout=15)
        _rq = subprocess.run('rpm -q takserver-core 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
        ulog(f"✓ Installed: {_rq}" if _rq.startswith('takserver-core') else "⚠ rpm -q takserver-core did not report installed — verify manually")
        ulog(""); ulog("=" * 50)
        ulog("✓ Two-server RHEL update complete")
        ulog(f"  Core: upgraded on this host")
        ulog(f"  Database + schema: upgraded on {s1_host}")
        ulog("=" * 50)
        upgrade_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        ulog(f"✗ Error: {str(e)}")
        upgrade_status.update({'running': False, 'complete': False, 'error': True})


def run_takserver_two_server_db_migrate(
    old_s1_cfg, new_s1_cfg, tak_cfg_snapshot, core_ip, db_port, db_user, db_name,
    local_db_deb_path=None, local_db_deb_filename=None,
):
    """Background job: pg_dump on old Server One, restore on new, re-point Core + settings, start takserver.
    Prerequisite: new host already has PostgreSQL + takserver-database (Deploy Server One) with empty/scratch cot.
    local_db_deb_path: optional path to uploaded takserver-database .deb for version check vs current Server One."""
    def mlog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        tak_migrate_log.append(entry)
        print(entry, flush=True)

    remote_dump = '/tmp/cot_migrate_infra_tak.dump'
    stopped_tak = False
    new_host = (new_s1_cfg.get('host') or '').strip()
    old_host = (old_s1_cfg.get('host') or '').strip()

    try:
        mlog('=' * 50)
        mlog('Two-server database migration (Server One → new host)')
        mlog(f'  From: {old_host}')
        mlog(f'  To:   {new_host}')
        mlog('=' * 50)

        ok, out = _ssh_probe(old_s1_cfg, 'echo OLD_SSH_OK', timeout=20)
        if not ok:
            mlog(f'✗ SSH to current Server One failed: {(out or "")[:300]}')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return
        mlog('✓ SSH to current Server One OK')

        ok, out = _ssh_probe(new_s1_cfg, 'echo NEW_SSH_OK', timeout=20)
        if not ok:
            mlog(f'✗ SSH to new Server One failed. Install the same SSH key on the new host: {(out or "")[:300]}')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return
        mlog('✓ SSH to new Server One OK')

        if local_db_deb_path and local_db_deb_filename:
            if not os.path.isfile(local_db_deb_path):
                mlog(f'✗ Database .deb no longer on console: {local_db_deb_filename}. Upload again and retry.')
                tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
                return
            ok_ver, ver_err = _assert_uploaded_db_deb_matches_server_one(
                old_s1_cfg, local_db_deb_path, local_db_deb_filename,
            )
            if not ok_ver:
                mlog(f'✗ {ver_err}')
                tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
                return
            mlog('✓ takserver-database .deb version matches current Server One')

        db_pass = (tak_cfg_snapshot.get('database', {}).get('password') or '').strip()
        if not db_pass and os.path.exists('/opt/tak/CoreConfig.xml'):
            try:
                r = subprocess.run(_sudo_wrap(['cat', '/opt/tak/CoreConfig.xml']), capture_output=True, text=True, timeout=8)
                cc = r.stdout or ''
                for pattern in (
                    r'<connection[^>]*url\s*=\s*["\']jdbc:postgresql://[^"\']+/cot["\'][^>]*password\s*=\s*["\']([^"\']*)["\']',
                    r'<connection[^>]*username\s*=\s*["\']martiuser["\'][^>]*password\s*=\s*["\']([^"\']*)["\']',
                ):
                    m = re.search(pattern, cc)
                    if m and (m.group(1) or '').strip():
                        db_pass = m.group(1).strip()
                        break
            except Exception:
                pass
        if not db_pass:
            mlog('✗ Could not determine DB password (saved settings or CoreConfig). Set DB password in TAK deployment settings or use Sync DB password, then retry.')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return

        mlog('')
        mlog('━━━ Stopping TAK Server (this host) ━━━')
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'takserver']), capture_output=True, text=True, timeout=45)
        stopped_tak = True
        mlog('✓ TAK Server stopped')

        mlog('')
        mlog('━━━ Dumping database on old Server One ━━━')
        dump_cmd = f'sudo rm -f {remote_dump} && sudo -u postgres pg_dump -Fc cot -f {remote_dump} && test -s {remote_dump} && echo DUMP_OK'
        ok, out = _ssh_probe(old_s1_cfg, dump_cmd, timeout=3600)
        if not ok or 'DUMP_OK' not in (out or ''):
            mlog(f'✗ pg_dump failed: {(out or "")[:800]}')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return
        mlog('✓ pg_dump complete on old Server One')

        os.makedirs(UPLOAD_DIR, exist_ok=True)
        local_dump = os.path.join(UPLOAD_DIR, 'cot_migrate_infra_tak.dump')
        try:
            if os.path.isfile(local_dump):
                os.remove(local_dump)
        except OSError:
            pass

        mlog('')
        mlog('━━━ Copying dump to console ━━━')
        ok, scp_out = _scp_from_host(old_s1_cfg, remote_dump, local_dump, timeout=3600)
        if not ok or not os.path.isfile(local_dump) or os.path.getsize(local_dump) < 100:
            mlog(f'✗ SCP from old Server One failed: {(scp_out or "")[:400]}')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return
        mlog(f'✓ Dump copied to console ({os.path.getsize(local_dump) // (1024 * 1024)} MB)')

        mlog('')
        mlog('━━━ Copying dump to new Server One ━━━')
        ok, scp_out = _scp_to_host(new_s1_cfg, local_dump, '/tmp/', timeout=3600)
        if not ok:
            mlog(f'✗ SCP to new Server One failed: {(scp_out or "")[:400]}')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return
        mlog('✓ Dump on new Server One /tmp/')

        mlog('')
        mlog('━━━ Replacing cot database on new Server One ━━━')
        pw_q = shlex.quote(db_pass)
        usr_q = shlex.quote(db_user)
        dbn_q = shlex.quote(db_name)
        owner_sql = db_user if re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', db_user or '') else usr_q
        restore_script = (
            'sudo -u postgres psql -tAc "SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE datname = \'cot\' AND pid <> pg_backend_pid();" >/dev/null 2>&1 || true; '
            'sudo -u postgres psql -c "DROP DATABASE IF EXISTS cot WITH (FORCE);" 2>/dev/null || '
            'sudo -u postgres psql -c "DROP DATABASE IF EXISTS cot;" 2>/dev/null || true; '
            f'sudo -u postgres psql -c "CREATE DATABASE cot OWNER {owner_sql};" && '
            f'sudo -u postgres pg_restore --no-privileges -d cot --no-owner --role={usr_q} {remote_dump} 2>&1 | tail -40; '
            f'if PGPASSWORD={pw_q} psql -h 127.0.0.1 -p {int(db_port)} -U {usr_q} -d {dbn_q} -tAc "select 1" 2>/dev/null | tr -d "[:space:]" | grep -qx 1; '
            'then echo RESTORE_OK; else echo RESTORE_FAIL; fi'
        )
        ok, rout = _ssh_probe(new_s1_cfg, restore_script, timeout=7200)
        if rout:
            for line in (rout or '').strip().split('\n')[-45:]:
                if line.strip():
                    tak_migrate_log.append('  ' + line[:500])
        if 'RESTORE_OK' not in (rout or ''):
            mlog('✗ Restore or post-restore DB check failed (see lines above). Old Server One unchanged.')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return
        mlog('✓ Database restored and verified on new Server One')

        mlog('')
        mlog('━━━ PostgreSQL remote access on new Server One ━━━')
        ok_pg, log_lines, _pw_unused = _setup_server_one(new_s1_cfg, core_ip, db_port, None, None)
        for line in log_lines:
            mlog(line)
        if not ok_pg:
            mlog('✗ Could not configure PostgreSQL on new Server One')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return

        mlog('')
        mlog('━━━ Verifying DB auth on new Server One ━━━')
        pw_verify = db_pass
        ok_v, msg_v = _verify_server_one_db_password(new_s1_cfg, pw_verify, db_port=db_port, db_user=db_user, db_name=db_name)
        if not ok_v:
            mlog(f'✗ DB auth check on new host failed: {msg_v}')
            mlog('  (Restored DB keeps the martiuser password from the old server — ensure saved/CoreConfig password matches.)')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return
        mlog('✓ martiuser can connect to cot on new Server One')

        jdbc_url = f'jdbc:postgresql://{new_host}:{db_port}/{db_name}'
        mlog('')
        mlog('━━━ Updating CoreConfig.xml (this host) ━━━')
        try:
            r = subprocess.run(_sudo_wrap(['cat', '/opt/tak/CoreConfig.xml']), capture_output=True, text=True, timeout=8)
            cc = r.stdout or ''
            if not cc.strip():
                raise RuntimeError('empty CoreConfig')
            cc = re.sub(r'jdbc:postgresql://[^"\']+', jdbc_url, cc, count=1)
            cc = re.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + pw_verify + m.group(2), cc, count=1)
            _write_priv('/opt/tak/CoreConfig.xml', cc)   # v10.0.5 non-root: broker (was literal `sudo tee`)
            mlog(f'✓ JDBC → {new_host}:{db_port}')
        except Exception as e:
            mlog(f'✗ CoreConfig update failed: {e}')
            tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
            return

        mlog('')
        mlog('━━━ Saving deployment settings ━━━')
        settings = load_settings()
        cfg = _get_tak_deployment_config(settings)
        cfg['server_one'] = dict(new_s1_cfg)
        cfg.setdefault('database', {})['password'] = pw_verify
        settings['tak_deployment'] = cfg
        save_settings(settings)
        mlog('✓ Server One host updated in settings')
        sg_ok, sg_msg = _sync_guarddog_remote_db_from_settings(settings)
        mlog(f'{"✓" if sg_ok else "⚠"} Guard Dog remote DB config: {sg_msg}')

        mlog('')
        mlog('━━━ Starting TAK Server ━━━')
        subprocess.run(_sudo_wrap(['systemctl', 'start', 'takserver']), capture_output=True, text=True, timeout=45)
        stopped_tak = False
        mlog('✓ TAK Server start issued')

        mlog('')
        mlog('━━━ Health agent on new Server One ━━━')
        ha_ok, ha_msg = _deploy_health_agent_to_server_one(new_s1_cfg)
        mlog(ha_msg if ha_ok else f'⚠ {ha_msg}')

        mlog('')
        mlog('Cleaning temp files...')
        _ssh_probe(old_s1_cfg, f'sudo rm -f {remote_dump}', timeout=15)
        _ssh_probe(new_s1_cfg, f'sudo rm -f {remote_dump}', timeout=15)
        try:
            if os.path.isfile(local_dump):
                os.remove(local_dump)
        except OSError:
            pass

        mlog('')
        mlog('=' * 50)
        mlog('✓ Migration complete — TAK Server now uses new database host')
        mlog(f'  You may decommission the old Server One ({old_host}) when ready.')
        mlog('=' * 50)
        tak_migrate_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        mlog(f'✗ Error: {str(e)}')
        tak_migrate_status.update({'running': False, 'complete': False, 'error': True})
    finally:
        if stopped_tak:
            mlog('⚠ Restarting TAK Server (migration did not finish cleanly)')
            subprocess.run(_sudo_wrap(['systemctl', 'start', 'takserver']), capture_output=True, text=True, timeout=45)


@app.route('/api/deploy/cancel', methods=['POST'])
@login_required
def cancel_deploy():
    if not deploy_status['running']:
        return jsonify({'error': 'No deployment in progress'}), 400
    deploy_status['cancelled'] = True
    log_step("⚠ Deployment cancelled by user")
    deploy_status.update({'running': False, 'error': True})
    # Kill any running subprocess children
    subprocess.run('pkill -P $$ 2>/dev/null; true', shell=True, capture_output=True)
    return jsonify({'success': True})

@app.route('/api/deploy/takserver', methods=['POST'])
@login_required
def deploy_takserver():
    if deploy_status['running']:
        return jsonify({'error': 'Deployment already in progress'}), 400
    data = request.json
    if not data: return jsonify({'error': 'No configuration provided'}), 400
    settings = load_settings()
    tak_deploy_cfg = _get_tak_deployment_config(settings)
    requested_mode = (data.get('deployment_mode') or tak_deploy_cfg.get('mode') or 'single_server').strip().lower()
    is_two_server = requested_mode == 'two_server'
    is_external_db = requested_mode == 'external_db'
    if is_external_db:
        _edb_cfg = tak_deploy_cfg.get('external_db', {})
        if not (_edb_cfg.get('host') or '').strip():
            return jsonify({'error': 'External DB: no database host configured. Fill in the host, save config, and run Provision Database (step 2) + Test Connection (step 3) before deploying.'}), 400
        if not (_edb_cfg.get('password') or '').strip():
            return jsonify({'error': 'External DB: Provision Database (step 2) has not been completed — no martiuser password stored. Run Provision Database with all 5 Azure extensions whitelisted, then Test Connection (step 3), before deploying.'}), 400
    try:
        for field, key in [('Country', 'cert_country'), ('State', 'cert_state'),
                           ('City', 'cert_city'), ('Organization', 'cert_org'),
                           ('Organizational Unit', 'cert_ou')]:
            _sanitize_cert_field(data.get(key, ''), field)
    except ValueError as e:
        return jsonify({'error': str(e)[:200]}), 400
    # v10.0.5: TAK's makeRootCa.sh REFUSES to run (cert-gen exit 255) unless these are set,
    # and they're NOT persisted — so they reset to blank on a redeploy after Remove. Refuse
    # up front with a clear message instead of failing mid-cert-gen.
    _cert_required_missing = [f for f, k in [('Country', 'cert_country'), ('State', 'cert_state'),
                                             ('City', 'cert_city'), ('Organization', 'cert_org'),
                                             ('Organizational Unit', 'cert_ou')]
                              if not (data.get(k, '') or '').strip()]
    if _cert_required_missing:
        return jsonify({'error': 'Certificate Information is required: ' + ', '.join(_cert_required_missing) +
                        '. Fill these in (they reset after a Remove) and deploy again.'}), 400

    # ── v10.0.1: container path (arm64 forced, or operator-selected on amd64) ──
    # Uses the official takserver-docker-*.zip instead of a .deb/.rpm. Branches
    # here and returns BEFORE the byte-identical .deb selection logic below.
    _explicit_method = data.get('install_method') if data.get('install_method') in ('native', 'container') else None
    _method = _explicit_method or _tak_install_method()
    # Auto-correct an un-pinned method to match the uploaded artifact: if we'd take
    # the native path but only a takserver-docker .zip is uploaded (no .deb/.rpm),
    # use the container path. Avoids a confusing "No package file found." when the
    # operator uploaded the container bundle (common on arm64).
    if _method == 'native' and not _explicit_method:
        _ups = os.listdir(UPLOAD_DIR)
        _has_native = any(f.endswith('.deb') or f.endswith('.rpm') for f in _ups)
        _has_zip = any(f.lower().endswith('.zip') and 'docker' in f.lower() for f in _ups)
        if not _has_native and _has_zip:
            _method = 'container'
    if _method == 'container':
        zips = [f for f in os.listdir(UPLOAD_DIR) if f.lower().endswith('.zip') and 'docker' in f.lower()]
        if not zips:
            return jsonify({'error': 'No takserver-docker .zip found. Upload the official takserver-docker-*.zip bundle (container deploy — required on arm64).'}), 400
        selected_zip = sorted(zips)[-1]
        try:
            _int_days = max(1, min(3652, int(data.get('intermediate_ca_validity_days') or 730)))
        except (TypeError, ValueError):
            _int_days = 730
        try:
            _iss_days = max(1, min(3652, int(data.get('issued_cert_validity_days') or _int_days)))
        except (TypeError, ValueError):
            _iss_days = _int_days
        if _iss_days > _int_days:
            return jsonify({'error': f'Issued cert validity ({_iss_days} days) cannot exceed intermediate CA validity ({_int_days} days)'}), 400
        c_config = {
            'install_method': 'container',
            'package_path': os.path.join(UPLOAD_DIR, selected_zip),
            # v10.0.5: default cert-metadata to NON-EMPTY — TAK's makeRootCa.sh refuses to run
            # (exit 255) if STATE/CITY/ORGANIZATIONAL_UNIT are blank, and the TAK deploy form
            # doesn't collect them, so an empty value here aborted cert-gen. Use the operator's
            # value when present, else a sensible default.
            'cert_country': (data.get('cert_country') or '').strip() or 'US',
            'cert_state': (data.get('cert_state') or '').strip() or 'State',
            'cert_city': (data.get('cert_city') or '').strip() or 'City',
            'cert_org': (data.get('cert_org') or '').strip() or 'TAK',
            'cert_ou': (data.get('cert_ou') or '').strip() or 'TAK', 'root_ca_name': data.get('root_ca_name', 'ROOT-CA-01'),
            'intermediate_ca_name': data.get('intermediate_ca_name', 'INTERMEDIATE-CA-01'),
            'intermediate_ca_validity_days': _int_days, 'issued_cert_validity_days': _iss_days,
            'enable_admin_ui': data.get('enable_admin_ui', False),
            'enable_webtak': data.get('enable_webtak', False),
            'webadmin_password': data.get('webadmin_password', ''),
        }
        cert_password = (data.get('cert_password') or data.get('tak_cert_password') or '').strip()
        if cert_password:
            _s = load_settings(); _s['tak_cert_password'] = cert_password; save_settings(_s)
        deploy_log.clear()
        deploy_status.update({'running': True, 'complete': False, 'error': False})
        threading.Thread(target=run_takserver_deploy, args=(c_config,), daemon=True).start()
        return jsonify({'success': True})

    pkg_files = [f for f in os.listdir(UPLOAD_DIR) if f.endswith('.deb') or f.endswith('.rpm')]
    if not pkg_files: return jsonify({'error': 'No package file found.'}), 400
    if is_two_server:
        core_pkg = next((f for f in pkg_files if 'core' in f.lower()), '')
        if not core_pkg:
            return jsonify({'error': 'No takserver-core package found in uploads. For two-server deploy, upload both takserver-core and takserver-database .deb files.'}), 400
        selected_pkg = core_pkg
    else:
        # single_server and external_db both use the full combined takserver .deb
        single_pkgs = [f for f in pkg_files if '-database' not in f.lower() and '-core' not in f.lower()]
        if not single_pkgs:
            split_names = ', '.join(pkg_files)
            mode_label = 'External / Managed Database' if is_external_db else 'one-server'
            return jsonify({'error': f'Only split packages found ({split_names}). For {mode_label} deploy, upload the single takserver .deb (not takserver-database or takserver-core). Remove the wrong files and upload the correct package.'}), 400
        selected_pkg = single_pkgs[0]
    try:
        intermediate_days = int(data.get('intermediate_ca_validity_days') or 730)
        intermediate_days = max(1, min(3652, intermediate_days))
    except (TypeError, ValueError):
        intermediate_days = 730
    issued_days_raw = data.get('issued_cert_validity_days')
    if issued_days_raw not in (None, ''):
        try:
            issued_days = max(1, min(3652, int(issued_days_raw)))
        except (TypeError, ValueError):
            issued_days = intermediate_days
    else:
        issued_days = intermediate_days
    if issued_days > intermediate_days:
        return jsonify({'error': f'Issued cert validity ({issued_days} days) cannot exceed intermediate CA validity ({intermediate_days} days)'}), 400
    config = {
        'package_path': os.path.join(UPLOAD_DIR, selected_pkg),
        'two_server': is_two_server,
        'external_db': is_external_db,
        'tak_deploy_cfg': tak_deploy_cfg if (is_two_server or is_external_db) else None,
        # v10.0.5: default cert-metadata to NON-EMPTY (makeRootCa.sh exits 255 on blank
        # STATE/CITY/ORGANIZATIONAL_UNIT). Operator value when present, else a default.
        'cert_country': (data.get('cert_country') or '').strip() or 'US',
        'cert_state': (data.get('cert_state') or '').strip() or 'State',
        'cert_city': (data.get('cert_city') or '').strip() or 'City',
        'cert_org': (data.get('cert_org') or '').strip() or 'TAK',
        'cert_ou': (data.get('cert_ou') or '').strip() or 'TAK', 'root_ca_name': data.get('root_ca_name', 'ROOT-CA-01'),
        'intermediate_ca_name': data.get('intermediate_ca_name', 'INTERMEDIATE-CA-01'),
        'intermediate_ca_validity_days': intermediate_days,
        'issued_cert_validity_days': issued_days,
        'enable_admin_ui': data.get('enable_admin_ui', False),
        'enable_webtak': data.get('enable_webtak', False),
        'webadmin_password': data.get('webadmin_password', ''),
    }
    for ext, key in [('.key', 'gpg_key_path'), ('.pol', 'policy_path')]:
        matches = [f for f in os.listdir(UPLOAD_DIR) if f.endswith(ext)]
        if matches: config[key] = os.path.join(UPLOAD_DIR, matches[0])
    # Optional certificate password at deploy (default atakatak); persist so deploy uses it for keystores/CoreConfig
    cert_password = (data.get('cert_password') or data.get('tak_cert_password') or '').strip()
    if cert_password:
        settings = load_settings()
        settings['tak_cert_password'] = cert_password
        save_settings(settings)
    deploy_log.clear()
    deploy_status.update({'running': True, 'complete': False, 'error': False})
    threading.Thread(target=run_takserver_deploy, args=(config,), daemon=True).start()
    return jsonify({'success': True})

def log_step(msg):
    entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
    deploy_log.append(entry)
    print(entry, flush=True)

def run_cmd(cmd, desc=None, check=True, quiet=False):
    if desc: log_step(desc)
    try:
        # v10.0.5 non-root: this helper drives the ENTIRE TAK Server deploy (native
        # + container) as bare shell strings. As the non-root console it must route
        # its privileged binaries (dnf/rpm/docker/systemctl/firewall + coreutils on
        # /opt/tak) through the broker shims, else every step fails "must be run with
        # superuser privileges". No-op as root / when shims absent.
        r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=600,
                           env=_broker_shim_env())
        if not quiet and r.stdout.strip():
            for line in r.stdout.strip().split('\n'):
                if 'NEEDRESTART' not in line:
                    deploy_log.append(f"  {line}")
        if not quiet and r.returncode == 0 and r.stderr.strip():
            for line in r.stderr.strip().split('\n'):
                if 'NEEDRESTART' not in line and 'error' in line.lower():
                    deploy_log.append(f"  ✗ {line}")
        if check and r.returncode != 0:
            log_step(f"✗ Command failed (exit {r.returncode})")
            # v10.0.5 non-root: surface the FULL stderr on failure. The broker
            # PATH-shim writes its reason to stderr as `takwerx_broker: DENIED: …`
            # / `ERROR: …` and returns 126; the 'error'-substring filter above
            # silently drops "DENIED" (no 'error' in it), which is exactly why the
            # container-deploy 126s looked causeless. Failure-path only, ignores
            # `quiet` so cert-gen failures are visible too.
            err = (r.stderr or '').strip()
            for line in err.split('\n')[-15:]:
                if line.strip() and 'NEEDRESTART' not in line:
                    deploy_log.append(f"  ✗ {line}")
            return False
        return True
    except Exception as e:
        log_step(f"✗ {str(e)}")
        return False

def wait_for_package_lock():
    """Wait for unattended-upgrades to finish (common on fresh VPS).
    NO TIMEOUT - waits as long as needed. Ticks every 10 seconds."""
    return wait_for_unattended_upgrade_worker(
        log_step, deploy_log, lambda: deploy_status.get('cancelled'))

def _tak_container_running(name):
    """True if the named docker container exists and is in the running state."""
    try:
        r = subprocess.run(
            _sudo_wrap(['docker', 'inspect', '-f', '{{.State.Running}}', name]),
            capture_output=True, text=True, timeout=10)
        return r.returncode == 0 and r.stdout.strip() == 'true'
    except Exception:
        return False


@_with_authentik_deploy_guard
def _deploy_takserver_container(config):
    """v10.0.1 — Deploy TAK Server as Docker containers from the official
    takserver-docker-*.zip. Used on arm64 (forced — no native arm TAK package)
    and selectable on amd64. Mirrors the proven installTAK docker sequence and
    reuses the host-side cert/CoreConfig helpers via the /opt/tak symlink.

    Single-server (bundled PostGIS container) only in v1. Two-server / external
    DB and Authentik/LDAP auto-wiring are NOT done here — TAK comes up with
    certs + admin + CoreConfig + firewall; LDAP is the post-deploy one-click
    'Connect TAK Server to LDAP' (same fallback the .deb path degrades to).

    FIRST CUT — validate on a real arm64 box; the container init timing and
    configureInDocker behavior are the likely tuning points. Verbose logging is
    intentional so the first deploy gives a clean debug trace."""
    try:
        deploy_status['cancelled'] = False
        s0 = load_settings()
        cert_pass = _get_tak_cert_password(s0)
        zip_path = config['package_path']
        root_ca = config['root_ca_name']; int_ca = config['intermediate_ca_name']
        log_step("=" * 50); log_step("TAK Server Deployment Starting (CONTAINER / arm64-capable)"); log_step("=" * 50)
        log_step(f"  Bundle: {os.path.basename(zip_path)}")
        log_step(f"  Arch: {_host_arch()} | method: container")

        # ── Step 1/9: Docker prerequisite ───────────────────────────────────
        log_step(""); log_step("━━━ Step 1/9: Docker Prerequisite ━━━")
        if not run_cmd('docker --version', "Checking Docker..."):
            log_step("✗ Docker is not installed/usable — install Docker first (Marketplace deploys it).")
            deploy_status.update({'error': True, 'running': False}); return
        run_cmd('systemctl start docker > /dev/null 2>&1', check=False)

        # ── Step 2/9: Unpack bundle + symlink /opt/tak ──────────────────────
        log_step(""); log_step("━━━ Step 2/9: Unpacking TAK docker bundle ━━━")
        # v10.0.1: broker rm — a prior deploy's in-container cert-gen leaves root-owned files
        # under ~/tak-docker that the host console user (takwerx) cannot delete; a host `rm -rf`
        # silently fails and the STALE bundle dir survives, so the next deploy picks the wrong
        # build context ("Dockerfile.takserver not found under .../<old-version>/docker").
        subprocess.run(_sudo_wrap(['rm', '-rf', TAK_DOCKER_ROOT]), capture_output=True, timeout=60)
        run_cmd(f'mkdir -p {shlex.quote(TAK_DOCKER_ROOT)}')
        # Extract with Python's zipfile rather than shelling to `unzip` — minimal
        # cloud images (incl. this arm64 AMI) ship without unzip (exit 127), and
        # this is cross-distro with no package install. zipfile does NOT restore
        # unix permission bits, so re-apply them from external_attr — the bundle's
        # makeCert.sh/makeRootCa.sh/configureInDocker.sh MUST stay executable.
        log_step("Extracting bundle (Python zipfile — no unzip dependency)...")
        try:
            import zipfile
            with zipfile.ZipFile(zip_path) as zf:
                for info in zf.infolist():
                    out_path = zf.extract(info, TAK_DOCKER_ROOT)
                    mode = (info.external_attr >> 16) & 0xFFFF
                    if mode and not info.is_dir():
                        try:
                            os.chmod(out_path, mode)
                        except OSError:
                            pass
        except Exception as _ze:
            log_step(f"✗ Failed to extract the takserver-docker bundle: {str(_ze)[:200]}")
            deploy_status.update({'error': True, 'running': False}); return
        # The bundle extracts to <root>/takserver-docker-<ver>/ which holds docker/ + tak/
        try:
            # Only consider dirs that are an actual bundle (have docker/Dockerfile.takserver),
            # and pick the NEWEST (the one just extracted) so a leftover dir from a prior
            # version can never shadow the upload even if cleanup somehow left one behind.
            entries = [d for d in os.listdir(TAK_DOCKER_ROOT)
                       if os.path.isdir(os.path.join(TAK_DOCKER_ROOT, d)) and 'docker' in d.lower()
                       and os.path.isfile(os.path.join(TAK_DOCKER_ROOT, d, 'docker', 'Dockerfile.takserver'))]
            entries.sort(key=lambda d: os.path.getmtime(os.path.join(TAK_DOCKER_ROOT, d)), reverse=True)
            build_ctx = os.path.join(TAK_DOCKER_ROOT, entries[0]) if entries else TAK_DOCKER_ROOT
        except Exception:
            build_ctx = TAK_DOCKER_ROOT
        tak_dir = os.path.join(build_ctx, 'tak')
        if not os.path.isfile(os.path.join(build_ctx, 'docker', 'Dockerfile.takserver')):
            log_step(f"✗ Dockerfile.takserver not found under {build_ctx}/docker — is this an official takserver-docker zip?")
            deploy_status.update({'error': True, 'running': False}); return
        log_step(f"  Build context: {build_ctx}")
        # Symlink host /opt/tak → the bundle's tak/ so all host-side /opt/tak
        # logic (CoreConfig sed, cert files, _patch_* helpers) works unchanged.
        run_cmd('[ -L /opt/tak ] && rm -f /opt/tak; [ -d /opt/tak ] && rm -rf /opt/tak; true', check=False)
        run_cmd(f'ln -sfn {shlex.quote(tak_dir)} /opt/tak', "Symlinking /opt/tak → bundle tak/...")
        log_step("✓ Bundle unpacked and /opt/tak symlinked")

        # ── Step 3/9: Build images (multi-arch base → native arm64 build) ───
        log_step(""); log_step("━━━ Step 3/9: Building TAK Server images ━━━")
        log_step("  (first build pulls postgres:15.1 + eclipse-temurin:17-jammy — minutes on arm64)")
        if not run_cmd(f'cd {shlex.quote(build_ctx)} && docker build -t takserver_db -f docker/Dockerfile.takserver-db . 2>&1', "Building takserver_db image..."):
            log_step("✗ takserver_db image build failed."); deploy_status.update({'error': True, 'running': False}); return
        if not run_cmd(f'cd {shlex.quote(build_ctx)} && docker build -t {TAK_CONTAINER} -f docker/Dockerfile.takserver . 2>&1', "Building takserver image..."):
            log_step("✗ takserver image build failed."); deploy_status.update({'error': True, 'running': False}); return
        log_step("✓ Images built")

        # ── Step 4/9: Network, volume, run DB + first takserver (cert-gen) ──
        # ── Step 3.5: martiuser DB password INTO CoreConfig BEFORE the DB inits ─
        # The DB container's configureInDocker → takserver-setup-db.sh reads the
        # martiuser password straight out of /opt/tak/CoreConfig.xml at init and
        # provisions the role with it. pg_hba.conf is `md5`, so an empty password
        # → "Skipping schema changes, no DB password" → TAK can never auth. So we
        # MUST seed CoreConfig.xml and set the connection password BEFORE starting
        # the DB container (this is what installTAK does at its line 1302, before
        # its docker run). At this point cert_block isn't added yet, so the only
        # password="" in the file is the <connection> one — a global sed is safe.
        log_step(""); log_step("━━━ Step 3.5/9: Database credentials ━━━")
        import secrets as _secrets
        _alpha = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
        db_pass = ''.join(_secrets.choice(_alpha) for _ in range(20))
        try:
            _sdb = load_settings(); _sdb['tak_db_password'] = db_pass; save_settings(_sdb)
        except Exception:
            pass
        run_cmd('[ -f /opt/tak/CoreConfig.xml ] || cp /opt/tak/CoreConfig.example.xml /opt/tak/CoreConfig.xml', "Seeding CoreConfig.xml from example...", check=False)
        run_cmd(f"sed -i 's/password=\"\"/password=\"{db_pass}\"/g' /opt/tak/CoreConfig.xml /opt/tak/CoreConfig.example.xml",
                "Setting martiuser DB password in CoreConfig (before DB init)...", check=False)
        log_step("✓ DB password set in CoreConfig (martiuser will be provisioned with it)")

        log_step(""); log_step("━━━ Step 4/9: Starting containers ━━━")
        run_cmd(f'docker rm -f {TAK_CONTAINER} {TAK_DB_CONTAINER} 2>/dev/null; true', check=False)
        run_cmd(f'docker network inspect {TAK_DOCKER_NET} >/dev/null 2>&1 || docker network create {TAK_DOCKER_NET}', "Ensuring docker network...")
        # Wipe any stale DB volume so postgres re-inits and takserver-setup-db.sh
        # re-provisions martiuser with the CURRENT password — an existing volume
        # keeps the old/empty-password role and auth fails.
        run_cmd(f'docker volume rm {TAK_DB_VOLUME} >/dev/null 2>&1; docker volume create {TAK_DB_VOLUME} >/dev/null 2>&1; true', check=False)
        run_cmd(
            f'docker run --mount source={TAK_DB_VOLUME},destination=/var/lib/postgresql '
            f'-v {shlex.quote(tak_dir)}:/opt/tak:z --restart=always --network {TAK_DOCKER_NET} '
            f'--network-alias tak-database --name {TAK_DB_CONTAINER} -d takserver_db',
            "Starting database container...")
        # First takserver run WITHOUT host ports — just to init the bundle
        # (configureInDocker copies CoreConfig.example → CoreConfig.xml, lays out
        # certs/) and give us a container to `docker exec` cert generation into.
        run_cmd(
            f'docker run -v {shlex.quote(tak_dir)}:/opt/tak:z --restart=always '
            f'--network {TAK_DOCKER_NET} --name {TAK_CONTAINER} -d {TAK_CONTAINER}',
            "Starting TAK Server container (init pass)...")
        log_step("  Waiting up to 2 min for container init (configureInDocker)...")
        _ready = False
        for _ in range(24):
            time.sleep(5)
            if deploy_status.get('cancelled'): return
            if _tak_container_running(TAK_CONTAINER) and os.path.exists('/opt/tak/certs/makeCert.sh'):
                _ready = True; break
        if not _ready:
            log_step("⚠ Container did not report ready in 2 min — continuing; check `docker logs takserver`.")
        else:
            log_step("✓ Containers up; bundle initialized")

        # ── Step 5/9: Firewall ──────────────────────────────────────────────
        log_step(""); log_step("━━━ Step 5/9: Configuring Firewall ━━━")
        if _distro_family() == 'rhel':
            be = _fw_backend()
            for _fp in (22, 8089, 8443, 8446, 5001):
                _fw_allow(_fp, 'tcp')
            if be == 'firewalld':
                log_step("✓ Firewall configured — firewalld active (22, 8089, 8443, 8446, 5001)")
            else:
                log_step("ⓘ No host firewall active (firewalld not installed) — relying on the "
                         "provider security group; TAK ports left reachable")
        else:
            for p in ['22/tcp', '8089/tcp', '8443/tcp', '8446/tcp', '5001/tcp']:
                run_cmd(f'ufw allow {p} > /dev/null 2>&1', check=False)
            run_cmd('ufw --force enable > /dev/null 2>&1', check=False)
            log_step("✓ Firewall configured (22, 8089, 8443, 8446, 5001)")

        # ── Step 6/9: Certificates (docker exec; files land in symlinked /opt/tak) ─
        log_step(""); log_step("━━━ Step 6/9: Generating Certificates ━━━")
        log_step(f"  Root CA: {root_ca} | Intermediate CA: {int_ca}")
        run_cmd('rm -rf /opt/tak/certs/files', check=False)
        int_validity_days = config.get('intermediate_ca_validity_days', 730)
        # v10.0.5 non-root: patch cert-metadata.sh via broker READ/MODIFY/WRITE — `sed` is
        # broker-denied, so the old `cp`/`sed -i` here silently no-op'd, leaving STATE/CITY/OU
        # unset -> makeRootCa "Please set STATE, CITY, ORGANIZATIONAL_UNIT" -> exit 255 -> 0
        # certs. The native path (run_takserver_deploy) was already converted to this; the
        # container path was missed. (The cert fields DO reach config; the WRITE was failing.)
        try:
            cm_path = '/opt/tak/certs/cert-metadata.sh'
            orig_path = cm_path + '.original'
            try:
                base = _read_priv(orig_path)
            except Exception:
                base = _read_priv(cm_path)
                _write_priv(orig_path, base)
            repl = [('COUNTRY', config['cert_country']), ('STATE', config['cert_state']),
                    ('CITY', config['cert_city']), ('ORGANIZATION', config['cert_org']),
                    ('ORGANIZATIONAL_UNIT', config['cert_ou']),
                    ('CA_VALIDITY', str(int_validity_days)),
                    ('INTERMEDIATE_VALIDITY', str(int_validity_days))]
            if cert_pass and cert_pass != 'atakatak':
                repl += [('CAPASS', cert_pass), ('PASS', cert_pass)]
            lines = base.splitlines(keepends=True)
            for var, val in repl:
                if not val:
                    continue
                for i, line in enumerate(lines):
                    stripped = line.lstrip()
                    if stripped.startswith(var + '='):
                        indent = line[:len(line) - len(stripped)]
                        safe = str(val).replace('"', '\\"')
                        lines[i] = f'{indent}{var}="{safe}"\n'
                        break
            _write_priv(cm_path, ''.join(lines))
        except Exception as _e:
            log_step(f"  ✗ cert-metadata.sh patch failed: {_e}")
        _patch_openssl_string_mask(log_step)
        _patch_cert_metadata_password(cert_pass)
        # Container TAK user is uid 1000 — chown so makeCert (run as that user
        # inside the container) can write the cert files on the shared mount.
        run_cmd('chown -R 1000:1000 /opt/tak/certs 2>/dev/null; true', check=False)
        # v10.0.1/v10.0.5 (ARM container): generate certs in a ONE-SHOT `docker run` container
        # that mounts the shared bundle — NOT `docker exec` into the init-pass service container.
        # The init container crash-loops until certs exist (TAK's entrypoint exits with no
        # keystore -> --restart=always backoff), so `docker exec` hit a STOPPED container and
        # returned exit 255 -> ZERO certs while the deploy falsely logged "✓ created". A fresh
        # `docker run --entrypoint bash <image>` uses the image's default user (uid 1000/tak,
        # same as docker exec) + ENV (Java on PATH), sees the configured certs/ dir on the
        # mount, and does NOT depend on the service container being up. FATAL on failure.
        def _certrun(inner, label):
            cmd = (f"docker run --rm -v {shlex.quote(tak_dir)}:/opt/tak:z "
                   f"--entrypoint bash {TAK_CONTAINER} -c {shlex.quote(inner)} 2>&1")
            if not run_cmd(cmd, label, quiet=True):
                log_step(f"✗ Certificate generation FAILED at: {label} — aborting (TAK is unusable without certs)")
                deploy_status.update({'running': False, 'error': True})
                return False
            return True
        log_step(f"Creating Root CA: {root_ca}...")
        if not _certrun(f'cd /opt/tak/certs && echo "{root_ca}" | ./makeRootCa.sh', f"Root CA {root_ca}"):
            return
        log_step(f"Creating Intermediate CA: {int_ca}...")
        if not _certrun(f'cd /opt/tak/certs && echo "y" | ./makeCert.sh ca "{int_ca}"', f"Intermediate CA {int_ca}"):
            return
        log_step("Creating server certificate...")
        if not _certrun('cd /opt/tak/certs && ./makeCert.sh server takserver', "server cert"):
            return
        log_step("Creating admin certificate...")
        if not _certrun('cd /opt/tak/certs && ./makeCert.sh client admin', "admin cert"):
            return
        log_step("Creating user certificate...")
        if not _certrun('cd /opt/tak/certs && ./makeCert.sh client user', "user cert"):
            return
        _certrun(f'keytool -import -alias root-ca -file /opt/tak/certs/files/root-ca.pem -keystore /opt/tak/certs/files/truststore-{int_ca}.jks -storepass {shlex.quote(cert_pass)} -noprompt', "truststore")
        log_step("✓ Certificates created and truststore built")

        # ── Step 7/9: CoreConfig.xml (host-side sed on symlinked /opt/tak) ──
        log_step(""); log_step("━━━ Step 7/9: Configuring CoreConfig.xml ━━━")
        # CoreConfig.xml was already seeded + DB-password-set in Step 3.5 (before
        # the DB init). Here we layer the cert/enrollment patches on top.
        # The cert/enrollment patches — truststore → INT-CA (fixes 8089 "peer not
        # verified" / red dot), <certificateSigning> (fixes 8446 "registration
        # failed"), and 8089 x509 — go through the version-tolerant ElementTree
        # patcher. The takserver-docker bundle's CoreConfig format (absolute paths,
        # `<vbm/>`) silently breaks the string-seds the .deb path uses, so we patch
        # as XML here. The .deb path keeps its field-validated seds (untouched).
        _ok_ce, _msg_ce = _patch_coreconfig_cert_enrollment(
            '/opt/tak/CoreConfig.xml', int_ca, cert_pass, config, log_fn=log_step)
        if not _ok_ce:
            log_step(f"  ⚠ cert-enrollment patch failed ({_msg_ce}) — enrollment may need a manual fix")
        _patch_coreconfig_passwords(cert_pass, log_fn=log_step)
        run_cmd('sed -i \'s|<auth>|<auth x509useGroupCache="true">|g\' /opt/tak/CoreConfig.xml', check=False)
        admin_ui = str(config.get('enable_admin_ui', False)).lower()
        webtak = str(config.get('enable_webtak', False)).lower()
        if config.get('enable_admin_ui') or config.get('enable_webtak'):
            log_step(f"WebTAK: AdminUI={admin_ui}, WebTAK={webtak}")
            run_cmd(f'sed -i \'s|"cert_https"/|"cert_https" enableAdminUI="{admin_ui}" enableWebtak="{webtak}" enableNonAdminUI="false"/|g\' /opt/tak/CoreConfig.xml', check=False)
        _sanitize_coreconfig_name_entries()
        log_step("✓ CoreConfig.xml configured")

        # ── Step 8/9: Re-run takserver WITH host ports (two-phase) ──────────
        log_step(""); log_step("━━━ Step 8/9: Final TAK Server run (publishing ports) ━━━")
        run_cmd(f'docker rm -f {TAK_CONTAINER} 2>/dev/null; true', check=False)
        run_cmd('rm -f /opt/tak/CoreConfig.xml.backup 2>/dev/null; true', check=False)
        run_cmd(
            f'docker run -v {shlex.quote(tak_dir)}:/opt/tak:z --restart=always '
            f'-p 8089:8089 -p 8443:8443 -p 8446:8446 '
            f'--network {TAK_DOCKER_NET} --name {TAK_CONTAINER} -d {TAK_CONTAINER}',
            "Starting TAK Server (ports 8089/8443/8446)...")
        log_step("  Waiting for messaging microservice to come up (up to 10 min)...")
        _up = False
        for waited in range(0, 600, 10):
            time.sleep(10)
            if deploy_status.get('cancelled'): return
            r = subprocess.run(_sudo_wrap(['docker', 'exec', TAK_CONTAINER, 'grep', '-q', 'Started TAK Server messaging Microservice', '/opt/tak/logs/takserver-messaging.log']), capture_output=True)
            if r.returncode == 0:
                _up = True; log_step("✓ TAK Server messaging microservice started"); break
            if waited and waited % 60 == 0:
                deploy_log.append(f"  ⏳ {waited//60} min …")
        if not _up:
            log_step("⚠ Did not see 'messaging Microservice started' within 10 min — admin promote may need a retry. Check `docker logs takserver`.")

        # ── Step 9/9: Promote admin ─────────────────────────────────────────
        log_step(""); log_step("━━━ Step 9/9: Promoting Admin ━━━")
        run_cmd(_tak_exec('java -jar /opt/tak/utils/UserManager.jar certmod -A /opt/tak/certs/files/admin.pem') + ' 2>&1', "Promoting admin certificate...", check=False)
        # v10.0.1: webadmin handling mirrors the .deb path. When Authentik is
        # present, webadmin lives in Authentik/LDAP ONLY — creating a flat-file
        # webadmin shadows LDAP and makes 8446 land on WebTAK instead of the Admin
        # GUI (the flat-file user has no ROLE_ADMIN group). So remove the shadow;
        # the Authentik sync (finish section) puts webadmin in tak_ROLE_ADMIN.
        webadmin_pass = config.get('webadmin_password', '')
        _s_wa = load_settings()
        authentik_for_webadmin = bool(webadmin_pass and _get_authentik_env_content(_s_wa))
        if webadmin_pass:
            if authentik_for_webadmin:
                log_step("Authentik detected — webadmin will live in Authentik/LDAP only (skipping flat-file; avoids 8446 WebTAK shadow).")
                _remove_webadmin_from_userauth()
            else:
                log_step("Creating webadmin user (flat-file)...")
                run_cmd(_tak_exec(f'java -jar /opt/tak/utils/UserManager.jar usermod -A -p {shlex.quote(webadmin_pass)} webadmin') + ' 2>&1', check=False)
                log_step("✓ webadmin user created")
        run_cmd(_tak_systemctl('restart'), "Restarting TAK Server...", check=False)
        time.sleep(15)

        # ── Persist method + regen Caddy + finish ───────────────────────────
        settings = load_settings()
        settings['tak_install_method'] = 'container'
        if webadmin_pass:
            settings['webadmin_password'] = webadmin_pass
        save_settings(settings)
        if settings.get('fqdn'):
            try:
                generate_caddyfile(settings)
                subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True)
                log_step("  ✓ Caddy config updated for TAK Server")
            except Exception as _ce:
                log_step(f"  ⚠ Caddy regen failed (non-fatal): {str(_ce)[:120]}")

        # v10.0.1: make the container deploy self-sufficient like the .deb path —
        # auto-connect LDAP when Authentik is present, then wire the LE cert onto
        # 8446. Without these, enrollment fails: 'invalid credentials' (TAK can't
        # see Authentik/Portal users) and 'identity could not be verified' (8446
        # serves the self-signed PKI cert). Order mirrors the .deb deploy.
        # Auto-connect to LDAP if Authentik is already deployed
        try:
            ak_installed = bool(detect_modules().get('authentik', {}).get('installed'))
            if ak_installed and not _coreconfig_has_ldap():
                log_step(""); log_step("━━━ Connecting TAK Server to LDAP (Authentik detected) ━━━")
                ldap_ok, ldap_msg = _apply_ldap_to_coreconfig()
                if ldap_ok:
                    log_step(f"✓ {ldap_msg}")
                else:
                    log_step(f"⚠ LDAP auto-connect: {ldap_msg} — use 'Connect TAK Server to LDAP' after deploy")
        except Exception as e:
            log_step(f"⚠ LDAP auto-connect failed: {str(e)[:120]} — use 'Connect TAK Server to LDAP' after deploy")
        # Wire the Let's Encrypt cert onto the 8446 enrollment connector (trusted
        # cert so ATAK/iTAK don't reject the server identity).
        if settings.get('fqdn'):
            log_step(""); log_step("━━━ Installing trusted cert on 8446 (enrollment) ━━━")
            try:
                install_le_cert_on_8446(_get_service_domain(settings, 'takserver'), log_step, wait_for_cert=True)
            except Exception as _le:
                log_step(f"  ⚠ LE cert on 8446 failed (non-fatal): {str(_le)[:120]}")

        # v10.0.1: sync webadmin to Authentik (with the LDAP flow repair) so the
        # FIRST 8446 login lands on the Admin GUI, not WebTAK — same as the .deb
        # deploy. Without this the container box needs a manual 'Resync LDAP to TAK
        # Server' (the flow-repair retry below is exactly what that button does).
        if _get_authentik_env_content(settings):
            # First ensure the SERVICE ACCOUNT bind works: on a fresh Authentik
            # deploy adm_ldapservice's DB password can diverge from the .env (the
            # deploy's "bind verified via docker log" is a false positive), so the
            # SA bind fails 'Invalid credentials 49' → TAK can't query ANY groups →
            # every user lands on WebTAK. This sets the pw to the .env value + verifies
            # the bind (the other half of what 'Resync LDAP to TAK Server' does).
            # See memory authentik-ldapservice-password-mismatch-fresh-deploy.
            try:
                # v10.0.1: wait for Authentik to be healthy (self-heal a stopped
                # container) + retry on a transient API 500, instead of firing once.
                _sa_ok, _sa_msg = _sync_authentik_ldap_sa_with_retry(log_step)
                log_step(f"  {'✓' if _sa_ok else '⚠'} LDAP service-account bind: {_sa_msg}")
            except Exception as _sae:
                log_step(f"  ⚠ LDAP service-account sync error (non-fatal): {str(_sae)[:120]}")
        if webadmin_pass and _get_authentik_env_content(settings):
            sync_ok = False
            sync_err = None
            for attempt in range(2):
                ok, err = _ensure_authentik_webadmin(skip_bind_verify=False)
                if ok:
                    sync_ok = True
                    log_step("  ✓ webadmin synced to Authentik (tak_ROLE_ADMIN)")
                    break
                sync_err = (err or 'Unknown sync error')[:120]
                if attempt == 0:
                    log_step(f"  ℹ webadmin sync attempt 1 failed: {sync_err} — repairing LDAP flow and retrying...")
                    try:
                        ok_flow, err_flow = _ensure_ldap_flow_authentication_none()
                        log_step("  ✓ LDAP flow repaired (cleared recursion spiral)" if ok_flow
                                 else f"  ⚠ LDAP flow repair: {err_flow} — retrying anyway")
                    except Exception as _fe:
                        log_step(f"  ⚠ LDAP flow repair error (non-fatal): {str(_fe)[:120]}")
                    time.sleep(15)
            if not sync_ok:
                log_step(f"  ⚠ webadmin Authentik sync not verified: {sync_err}")
                log_step("     Fix: TAK Server page → 'Resync LDAP to TAK Server', then log in to 8446 (user: webadmin).")
            else:
                _remove_webadmin_from_userauth()
                log_step("  ✓ Removed flat-file webadmin shadow (8446 → LDAP/Admin GUI)")
            # Proactively migrate the LDAP outpost to FQDN routing (matches .deb;
            # prevents the heavy-load internal-routing flow spiral).
            try:
                _ensure_authentik_ldap_outpost_on_fqdn(log_step)
            except Exception as _oe:
                log_step(f"  ⚠ LDAP outpost routing migration skipped (non-fatal): {str(_oe)[:120]}")

        # v10.0.1: a (re)deploy regenerates the TAK CA + admin.p12, so refresh the
        # TAK Portal client cert + CA if the portal is present — otherwise the
        # portal keeps the OLD-CA, legacy-algo tak-client.p12 (which its Node 22 /
        # OpenSSL 3 can't read) and the dashboard shows no connected users / uptime
        # (Marti stats 503), even though enrollment via 8446 still works. No-ops
        # cleanly if TAK Portal isn't installed. See memory
        # takportal-stale-client-cert-on-redeploy.
        try:
            if _priv_pipe(['docker', 'ps', '--format', '{{.Names}}'], ['grep', '-q', 'tak-portal']).returncode == 0:
                log_step(""); log_step("━━━ Refreshing TAK Portal certs (CA changed on redeploy) ━━━")
                _tp_ok, _tp_msg = _takportal_sync_certs(plog=log_step, restart=True)
                log_step(f"  {'✓' if _tp_ok else '⚠'} TAK Portal cert sync: {_tp_msg}")
        except Exception as _tpe:
            log_step(f"  ⚠ TAK Portal cert sync skipped (non-fatal): {str(_tpe)[:120]}")

        # v10.0.1: auto-deploy Guard Dog so it runs from the start — mirrors the
        # .deb tail (run_takserver_deploy). run_guarddog_deploy() writes the
        # container fields into guarddog.conf (via _tak_is_container()) so the
        # monitors target the takserver / takserver-db containers, not host
        # postgresql/systemd. run_guarddog_deploy has its own try/except, so a
        # Guard Dog hiccup never fails the TAK deploy.
        if not os.path.exists('/opt/tak-guarddog'):
            log_step("")
            log_step("━━━ Guard Dog (monitoring) — installing automatically ━━━")
            alert_email = (load_settings().get('guarddog_alert_email') or '').strip()
            run_guarddog_deploy(alert_email)
            if guarddog_deploy_status.get('complete') and not guarddog_deploy_status.get('error'):
                log_step("✓ Guard Dog installed. Configure notifications on the Guard Dog page.")
            elif os.path.exists('/opt/tak-guarddog') and not _guarddog_is_enabled():
                # Partial install (e.g. enable failed): ensure timers are enabled so Guard Dog runs
                log_step("Enabling Guard Dog timers…")
                subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=10)
                for t in _guarddog_timer_list():
                    subprocess.run(_sudo_wrap(['systemctl', 'enable', t]), capture_output=True, timeout=5)
                    subprocess.run(_sudo_wrap(['systemctl', 'start', t]), capture_output=True, timeout=5)
                subprocess.run(_sudo_wrap(['systemctl', 'enable', 'tak-health.service']), capture_output=True, timeout=5)
                subprocess.run(_sudo_wrap(['systemctl', 'start', 'tak-health.service']), capture_output=True, timeout=5)
                if _guarddog_is_enabled():
                    log_step("✓ Guard Dog enabled. Configure notifications on the Guard Dog page.")

        ip = settings.get('server_ip', 'YOUR-IP')
        log_step(""); log_step("=" * 50)
        log_step("✓ TAK Server (container) deployment complete")
        log_step(f"  Admin UI:  https://{settings.get('fqdn') or ip}:8446")
        log_step(f"  Clients:   {settings.get('fqdn') or ip}:8089 (TLS/x509)")
        log_step("=" * 50)
        deploy_status.update({'running': False, 'complete': True, 'error': False})
    except Exception as e:
        log_step(f"✗ Container deploy error: {str(e)[:300]}")
        deploy_status.update({'running': False, 'complete': False, 'error': True})


@_with_authentik_deploy_guard
def run_takserver_deploy(config):
    # v10.0.1 dispatch: arm64 (or operator-selected) container deploys route to
    # the Docker path. Everything else runs the body below, which branches Steps
    # 2/3/4/6 on _distro_family(): RHEL family → native .rpm (PGDG/dnf + SELinux +
    # firewalld); Debian/Ubuntu → the byte-identical .deb path (every `else` here
    # is the original apt code verbatim). Steps 1/5/7/8/9 are shared.
    if config.get('install_method') == 'container':
        return _deploy_takserver_container(config)
    try:
        deploy_status['cancelled'] = False
        cert_pass = _get_tak_cert_password(load_settings())
        log_step("=" * 50); log_step("TAK Server Deployment Starting"); log_step("=" * 50)
        pkg = config['package_path']; pkg_name = os.path.basename(pkg)

        wait_for_package_lock()
        if deploy_status.get('cancelled'): return

        log_step(""); log_step("━━━ Step 1/9: System Limits ━━━")
        log_step("Increasing JVM thread limits...")
        # v10.0.5 non-root: shell `>> /etc/security/limits.conf` is a shell redirect
        # (not a routed binary) — fails as takwerx. Append via the broker instead.
        try:
            _lc = _read_priv('/etc/security/limits.conf')
        except Exception:
            _lc = ''
        if 'soft nofile 32768' not in _lc:
            _write_priv('/etc/security/limits.conf', '* soft nofile 32768\n* hard nofile 32768\n', mode='a')
        log_step("✓ System limits configured")

        log_step(""); log_step("━━━ Step 2/9: PostgreSQL Repository ━━━")
        if _distro_family() == 'rhel':
            # EL9 native: EPEL + PostgreSQL Global Dev Group (PGDG) repo + Java 17 + CRB.
            # Ports reference/rocky-scripts/rock9_tak/Rocky_9_TAK_Server_install.sh (steps 2–6).
            # NOTE: deliberately NO blanket `dnf update -y` (the standalone script does it on a
            # fresh box; here other modules are already installed and a full update mid-deploy is
            # an unnecessary fleet risk) — the rpm install resolves its deps from these repos.
            _pg_arch = 'aarch64' if _host_arch() == 'arm64' else 'x86_64'
            run_cmd('dnf install -y epel-release 2>&1', "Installing EPEL...", check=False)
            run_cmd(f'dnf install -y https://download.postgresql.org/pub/repos/yum/reporpms/EL-9-{_pg_arch}/pgdg-redhat-repo-latest.noarch.rpm 2>&1', "Adding PostgreSQL (PGDG) repository...", check=False)
            run_cmd('dnf -qy module disable postgresql 2>&1', check=False, quiet=True)
            run_cmd('dnf install -y java-17-openjdk-devel 2>&1', "Installing Java 17 (OpenJDK)...", check=False)
            run_cmd('dnf config-manager --set-enabled crb 2>&1', check=False, quiet=True)
            run_cmd('dnf makecache 2>&1', "Refreshing package metadata...", check=False, quiet=True)
            log_step("✓ EPEL + PostgreSQL (PGDG) repo + Java 17 + CRB configured")
        else:
            run_cmd('DEBIAN_FRONTEND=noninteractive NEEDRESTART_MODE=l apt-get install -y lsb-release > /dev/null 2>&1', "Installing prerequisites...", check=False)
            # v10.0.5 non-root: the PGDG key (curl -o /usr/share/...) and the repo
            # list (echo > /etc/apt/...) wrote to root paths as the non-root console
            # and failed. Fetch the key as takwerx, then write key + list through the
            # broker into already-allowlisted dirs (/usr/share/keyrings, /etc/apt).
            log_step("Adding PostgreSQL GPG key...")
            try:
                _cn = subprocess.run(['lsb_release', '-cs'], capture_output=True, text=True, timeout=10).stdout.strip() or 'jammy'
                _pgkey = subprocess.run(['curl', '-fsSL', 'https://www.postgresql.org/media/keys/ACCC4CF8.asc'],
                                        capture_output=True, timeout=30).stdout
                _write_priv('/usr/share/keyrings/pgdg.asc', _pgkey, perm=0o644)
                _write_priv('/etc/apt/sources.list.d/pgdg.list',
                            f'deb [signed-by=/usr/share/keyrings/pgdg.asc] https://apt.postgresql.org/pub/repos/apt {_cn}-pgdg main\n')
                run_cmd('apt-get update -qq > /dev/null 2>&1', "Updating package lists...")
                log_step("✓ PostgreSQL repository configured")
            except Exception as _e:
                log_step(f"✗ PostgreSQL repo setup failed: {_e}")

        log_step(""); log_step("━━━ Step 3/9: Package Verification ━━━")
        if _distro_family() == 'rhel':
            log_step("RPM install (dnf verifies repo/package GPG signatures) — skipping debsig")
        elif config.get('gpg_key_path') and config.get('policy_path'):
            log_step("GPG key and policy found — verifying...")
            run_cmd('DEBIAN_FRONTEND=noninteractive apt-get install -y debsig-verify', check=False)
            r = subprocess.run(f"grep 'id=' {config['policy_path']} | head -1 | sed 's/.*id=\"\\([^\"]*\\)\".*/\\1/'", shell=True, capture_output=True, text=True)
            pid = r.stdout.strip()
            log_step(f"  Policy ID: {pid}")
            if pid:
                run_cmd(f'mkdir -p /usr/share/debsig/keyrings/{pid}')
                run_cmd(f'mkdir -p /etc/debsig/policies/{pid}')
                run_cmd(f'rm -f /usr/share/debsig/keyrings/{pid}/debsig.gpg')
                run_cmd(f'touch /usr/share/debsig/keyrings/{pid}/debsig.gpg')
                run_cmd(f'gpg --no-default-keyring --keyring /usr/share/debsig/keyrings/{pid}/debsig.gpg --import {config["gpg_key_path"]}')
                run_cmd(f'cp {config["policy_path"]} /etc/debsig/policies/{pid}/debsig.pol')
                v = subprocess.run(f'debsig-verify -v {pkg}', shell=True, capture_output=True, text=True)
                if v.returncode == 0: log_step("✓ Package signature VERIFIED")
                else:
                    log_step(f"⚠ Verification exit code {v.returncode} — installing anyway")
                    if v.stdout.strip():
                        for line in v.stdout.strip().split('\n'):
                            if line.strip(): log_step(f"  {line.strip()}")
                    if v.stderr.strip():
                        for line in v.stderr.strip().split('\n'):
                            if line.strip(): log_step(f"  {line.strip()}")
        else:
            log_step("No GPG key/policy — skipping verification")

        log_step(""); log_step("━━━ Step 4/9: Installing TAK Server ━━━")
        if config.get('two_server') and os.path.exists('/opt/tak'):
            log_step("✓ TAK Server core already installed (two-server step 6) — skipping")
        elif _distro_family() == 'rhel':
            # EL9 native .rpm install (ports reference/rocky-scripts steps 7–10:
            # dnf install rpm → SELinux apply-selinux.sh → alternatives --set java).
            log_step(f"Installing {pkg_name} (dnf)...")
            _rpm_ok = subprocess.run(f'rpm -qp {pkg} > /dev/null 2>&1', shell=True, capture_output=True, timeout=30)
            if _rpm_ok.returncode != 0:
                log_step("✗ FATAL: the uploaded .rpm is corrupted or incomplete (rpm -qp failed).")
                log_step("  Delete the upload, download a fresh takserver-*.noarch.rpm from tak.gov, re-upload, and retry.")
                deploy_status.update({'error': True, 'running': False}); return
            # half-removed self-heal: rpm DB says installed but /opt/tak is gone
            _pre = subprocess.run('rpm -q takserver 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
            if _pre.startswith('takserver') and not os.path.exists('/opt/tak'):
                log_step("  Detected half-removed takserver (rpm installed, /opt/tak missing) — removing before reinstall...")
                subprocess.run(_sudo_wrap(['dnf', 'remove', '-y', 'takserver']), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=180)
            run_cmd(f'dnf install -y {pkg} 2>&1', "Installing TAK Server rpm (resolving deps from PGDG/EPEL/CRB)...", check=False)
            if not os.path.exists('/opt/tak'):
                log_step("  /opt/tak missing after install — forcing reinstall...")
                run_cmd(f'dnf reinstall -y {pkg} 2>&1 || dnf install -y {pkg} 2>&1', check=False)
            if not os.path.exists('/opt/tak'):
                log_step("✗ FATAL: /opt/tak not found after rpm install — run `dnf remove -y takserver && rm -rf /opt/tak` on the host and retry")
                deploy_status.update({'error': True, 'running': False}); return
            # SELinux: TAK runs under enforcing; the rpm ships apply-selinux.sh — apply + verify.
            run_cmd('dnf install -y checkpolicy 2>&1', check=False, quiet=True)
            _enf = subprocess.run('getenforce 2>/dev/null', shell=True, capture_output=True, text=True).stdout.strip()
            if _enf == 'Enforcing':
                if os.path.exists('/opt/tak/apply-selinux.sh'):
                    # v10.0.5 non-root: the script compiles + `semodule -i`s TAK's own
                    # SELinux policy and uses sudo internally -> must run as root. The
                    # non-root console routes it through the broker (gated to this exact
                    # TAK script). cwd=/opt/tak so it finds takserver-policy.te.
                    log_step("Applying TAK Server SELinux policy...")
                    subprocess.run(_sudo_wrap(['bash', '/opt/tak/apply-selinux.sh']),
                                   cwd='/opt/tak', capture_output=True, text=True, timeout=120)
                    _mod = _priv_pipe(['semodule', '-l'], ['grep', '-i', 'takserver']).stdout.strip()
                    if _mod:
                        log_step(f"  ✓ SELinux policy applied ({_mod.splitlines()[0]})")
                    else:
                        log_step("  ⚠ SELinux: takserver module not listed after apply-selinux.sh — TAK may hit AVC denials under enforcing")
                else:
                    log_step("  ⚠ /opt/tak/apply-selinux.sh missing — TAK SELinux policy not applied")
            else:
                log_step(f"  SELinux {_enf or 'unavailable'} — skipping TAK SELinux policy")
            # Java default → 17 (arch-aware)
            _jarch = 'aarch64' if _host_arch() == 'arm64' else 'x86_64'
            run_cmd(f'alternatives --set java java-17-openjdk.{_jarch} 2>/dev/null; true', check=False, quiet=True)
            # The rpm ships only CoreConfig.example.xml (the .deb postinst creates
            # CoreConfig.xml; the rpm does not). Seed it so the SHARED Step 8 CoreConfig
            # seds have a file to edit — without this Step 8 fails "CoreConfig.xml not
            # found" on every rpm box. Mirrors the container deploy's seed (line ~53493).
            run_cmd('[ -f /opt/tak/CoreConfig.xml ] || cp /opt/tak/CoreConfig.example.xml /opt/tak/CoreConfig.xml', "Seeding CoreConfig.xml from example...", check=False)
            run_cmd('chown tak:tak /opt/tak/CoreConfig.xml 2>/dev/null; true', check=False, quiet=True)
            log_step("✓ TAK Server installed")
        else:
            settings = load_settings()
            if settings.get('pkg_mgr', 'apt') == 'apt':
                wait_for_apt_lock(log_step, deploy_log)
            log_step(f"Installing {pkg_name}...")
            # Pre-flight: if a prior Remove button run left the package marked
            # installed (dpkg `ii`) but /opt/tak gone, `apt-get install` becomes
            # a no-op ("already newest version") and we'd FATAL below. Detect
            # that state and purge first so the install actually extracts.
            _pre_status = subprocess.run(
                "dpkg-query -W -f='${Status}' takserver 2>/dev/null",
                shell=True, capture_output=True, text=True
            ).stdout.strip()
            if _pre_status and 'installed' in _pre_status and not os.path.exists('/opt/tak'):
                log_step("  Detected half-removed takserver (package marked installed, /opt/tak missing) — purging before reinstall...")
                for _cmd in (
                    'DEBIAN_FRONTEND=noninteractive apt-get purge -y takserver',
                    'DEBIAN_FRONTEND=noninteractive dpkg --purge takserver',
                    'DEBIAN_FRONTEND=noninteractive dpkg --purge --force-all takserver',
                ):
                    subprocess.run(_cmd, shell=True, capture_output=True, text=True, timeout=180)
                    _after = subprocess.run(
                        "dpkg-query -W -f='${Status}' takserver 2>/dev/null",
                        shell=True, capture_output=True, text=True
                    ).stdout.strip()
                    if not _after or 'not-installed' in _after:
                        break
                log_step("  ✓ Purge complete — proceeding with fresh install")
            # Validate the .deb before attempting install — fail fast on corrupted uploads
            # rather than burning through three install attempts and leaving a broken dpkg state.
            _deb_ok = subprocess.run(
                f'dpkg-deb --info {pkg} > /dev/null 2>&1',
                shell=True, capture_output=True, timeout=30
            )
            if _deb_ok.returncode != 0:
                log_step("✗ FATAL: The uploaded package is corrupted or incomplete (dpkg-deb --info failed).")
                log_step("  On this page: delete the current upload, download a fresh copy from tak.gov, re-upload, then click")
                log_step("  'Clean up & retry' to purge the broken state before trying again.")
                deploy_status.update({'error': True, 'running': False})
                return
            # --allow-downgrades: installing an OLDER TAK (e.g. 5.6 onto a box that had 5.7, to test
            # an upgrade) is a downgrade; apt refuses with "Packages were downgraded and -y was used
            # without --allow-downgrades" otherwise. Harmless on a fresh install (no prior version).
            r1 = run_cmd(f'DEBIAN_FRONTEND=noninteractive NEEDRESTART_MODE=l apt-get install -y --allow-downgrades {pkg} 2>&1', check=False)
            if not r1:
                log_step("  apt-get failed, trying dpkg + dependency fix...")
                run_cmd(f'DEBIAN_FRONTEND=noninteractive NEEDRESTART_MODE=l dpkg -i {pkg} 2>&1', check=False)
                run_cmd('DEBIAN_FRONTEND=noninteractive NEEDRESTART_MODE=l apt-get install -f -y 2>&1', "  Resolving dependencies...", check=False)
            pg_check = subprocess.run('pg_lsclusters 2>/dev/null | grep -q "15"', shell=True, capture_output=True)
            if pg_check.returncode != 0:
                log_step("  Creating PostgreSQL 15 cluster...")
                # v10.0.5 non-root: pg_createcluster/dpkg aren't shimmed coreutils —
                # route the argv through the broker so they run as root.
                subprocess.run(_sudo_wrap(['pg_createcluster', '15', 'main', '--start']),
                               capture_output=True, text=True, timeout=180)
            subprocess.run(_sudo_wrap(['dpkg', '--configure', '-a']),
                           capture_output=True, text=True, timeout=180)
            # Last-resort self-heal: if /opt/tak is still missing (e.g. apt
            # decided the package was already installed and skipped extraction
            # despite our pre-flight purge), force a reinstall from the .deb.
            if not os.path.exists('/opt/tak'):
                log_step("  /opt/tak missing after install — forcing reinstall from .deb...")
                run_cmd(f'DEBIAN_FRONTEND=noninteractive NEEDRESTART_MODE=l apt-get install --reinstall -y --allow-downgrades {pkg} 2>&1', check=False)
                run_cmd('dpkg --configure -a 2>&1', check=False, quiet=True)
            if not os.path.exists('/opt/tak'):
                log_step("✗ FATAL: /opt/tak not found after install (even after forced reinstall) — run `dpkg --purge --force-all takserver && rm -rf /opt/tak` on the host and retry")
                deploy_status.update({'error': True, 'running': False}); return
            log_step("✓ TAK Server installed")

        # For external_db: patch CoreConfig JDBC URL NOW, before first start,
        # so TAKServer's own SchemaManager (triggered by systemd) targets the right DB.
        if config.get('external_db') and config.get('tak_deploy_cfg'):
            _edb_early = config['tak_deploy_cfg'].get('external_db', {})
            _edb_host_early = (_edb_early.get('host') or '').strip()
            _edb_port_early = int(_edb_early.get('port') or 5432)
            _edb_pass_early = (_edb_early.get('password') or '').strip()
            _edb_user_early = (_edb_early.get('username') or 'martiuser').strip()
            if _edb_host_early and os.path.exists('/opt/tak/CoreConfig.xml'):
                log_step(f"External DB: pre-patching CoreConfig JDBC → {_edb_host_early}:{_edb_port_early} (before first start)...")
                try:
                    import re as _re_early
                    with open('/opt/tak/CoreConfig.xml', 'r') as _f:
                        _cc = _f.read()
                    _jdbc_early = f'jdbc:postgresql://{_edb_host_early}:{_edb_port_early}/cot'
                    _cc = _re_early.sub(r'jdbc:postgresql://[^"]*', _jdbc_early, _cc)
                    _cc = _re_early.sub(r'(<connection[^>]*username=")[^"]*(")', lambda m: m.group(1) + _edb_user_early + m.group(2), _cc)
                    if _edb_pass_early:
                        _edb_pass_xml = html.escape(_edb_pass_early, quote=True)
                        _cc = _re_early.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + _edb_pass_xml + m.group(2), _cc)
                    _write_priv('/opt/tak/CoreConfig.xml', _cc)
                    log_step(f"✓ CoreConfig JDBC pre-patched to {_edb_host_early}:{_edb_port_early}")
                except Exception as _e:
                    log_step(f"⚠ Could not pre-patch CoreConfig JDBC: {_e}")

        log_step(""); log_step("━━━ Step 5/9: Starting TAK Server ━━━")
        run_cmd('systemctl daemon-reload')
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed:
            log_step(f"LDAP resync: {resync_msg}")
        run_cmd('systemctl start takserver', "Starting TAK Server...")
        run_cmd('systemctl enable takserver > /dev/null 2>&1')
        log_step("Waiting 30 seconds...")
        for remaining in range(20, -1, -10):
            time.sleep(10)
            deploy_log.append(f"  \u23f3 {remaining//60:02d}:{remaining%60:02d} remaining")
        log_step("✓ TAK Server started")

        log_step(""); log_step("━━━ Step 6/9: Configuring Firewall ━━━")
        if _distro_family() == 'rhel':
            # firewalld via _fw_allow (no-op if firewalld absent). Report HONESTLY: only
            # claim "configured" when a backend is actually active — otherwise say the box
            # has no host firewall (relying on the provider security group). Always-on
            # firewalld on RHEL is gated on the module-port sweep (see PLAN-firewall-
            # cybercontrols-multiplatform.md) so default-deny can't strand a module's port.
            be = _fw_backend()
            for _fp in (22, 8089, 8443, 8446, 5001):
                _fw_allow(_fp, 'tcp')
            if be == 'firewalld':
                log_step("✓ Firewall configured — firewalld active (22, 8089, 8443, 8446, 5001)")
            else:
                log_step("ⓘ No host firewall active (firewalld not installed) — relying on the "
                         "provider security group; TAK ports left reachable")
        else:
            for p in ['22/tcp', '8089/tcp', '8443/tcp', '8446/tcp', '5001/tcp']:
                run_cmd(f'ufw allow {p} > /dev/null 2>&1')
            run_cmd('ufw --force enable > /dev/null 2>&1')
            log_step("✓ Firewall configured (22, 8089, 8443, 8446, 5001)")

        log_step(""); log_step("━━━ Step 7/9: Generating Certificates ━━━")
        root_ca, int_ca = config['root_ca_name'], config['intermediate_ca_name']
        log_step(f"  Root CA: {root_ca} | Intermediate CA: {int_ca}")
        run_cmd('rm -rf /opt/tak/certs/files')
        # v10.0.5 non-root: cert-metadata.sh is tak-owned (0600) and `sed` is broker-
        # denied, so the old `cp`/`sed -i` patching silently failed -> STATE/CITY/OU
        # never set -> makeRootCa.sh aborted "Please set ... STATE, CITY,
        # ORGANIZATIONAL_UNIT" -> 0 keystores. Patch it via broker read/modify/write
        # instead (sources from a .original baseline so re-runs start clean).
        int_validity_days = config.get('intermediate_ca_validity_days', 730)
        try:
            cm_path = '/opt/tak/certs/cert-metadata.sh'
            orig_path = cm_path + '.original'
            try:
                base = _read_priv(orig_path)
            except Exception:
                base = _read_priv(cm_path)
                _write_priv(orig_path, base, perm=0o600)
            repl = [('COUNTRY', config['cert_country']), ('STATE', config['cert_state']),
                    ('CITY', config['cert_city']), ('ORGANIZATION', config['cert_org']),
                    ('ORGANIZATIONAL_UNIT', config['cert_ou']),
                    ('CA_VALIDITY', str(int_validity_days)),
                    ('INTERMEDIATE_VALIDITY', str(int_validity_days))]
            if cert_pass and cert_pass != 'atakatak':
                repl += [('CAPASS', cert_pass), ('PASS', cert_pass)]
            lines = base.splitlines(keepends=True)
            for var, val in repl:
                if not val:
                    continue
                for i, line in enumerate(lines):
                    stripped = line.lstrip()
                    if stripped.startswith(var + '='):
                        indent = line[:len(line) - len(stripped)]
                        safe = str(val).replace('"', '\\"')
                        lines[i] = f'{indent}{var}="{safe}"\n'
                        break
            _write_priv(cm_path, ''.join(lines), perm=0o600)
            run_cmd('chown tak:tak /opt/tak/certs/cert-metadata.sh /opt/tak/certs/cert-metadata.sh.original', check=False)
            log_step(f"  Intermediate CA validity: {int_validity_days} days (issued cert defaults to same)")
        except Exception as _e:
            log_step(f"  ✗ cert-metadata.sh patch failed: {_e}")

        _patch_openssl_string_mask(log_step)

        run_cmd('chown -R tak:tak /opt/tak/certs/')
        # v10.0.5 non-root: cert gen runs AS the `tak` service user. Pre-non-root
        # this was `sudo -u tak ./makeCert.sh` (a shell pipe). The non-root console
        # has no sudo, so route `runuser -u tak -- <script>` through the broker
        # (which is tightly gated to TAK's cert scripts + keytool). As root this
        # runuser runs directly. stdin (CA name / "y") + cwd are forwarded by the
        # broker. The scripts are tak-owned (0500) so they run/read correctly.
        def _tak_cert(args, inp=None, desc=None):
            if desc: log_step(desc)
            try:
                r = subprocess.run(
                    _sudo_wrap(['runuser', '-u', 'tak', '--'] + args),
                    input=(inp.encode() if inp else None),
                    capture_output=True, cwd='/opt/tak/certs', timeout=300)
                out = (r.stdout or b'').decode(errors='replace') + (r.stderr or b'').decode(errors='replace')
                for line in out.splitlines():
                    if line.strip() and 'error' in line.lower():
                        deploy_log.append(f"  {line[:200]}")
                if r.returncode != 0:
                    log_step(f"  ✗ cert step exit {r.returncode}")
                return r.returncode == 0
            except Exception as e:
                log_step(f"  ✗ {e}")
                return False
        _tak_cert(['/opt/tak/certs/makeRootCa.sh'], inp=f'{root_ca}\n', desc=f"Creating Root CA: {root_ca}...")
        _tak_cert(['/opt/tak/certs/makeCert.sh', 'ca', int_ca], inp='y\n', desc=f"Creating Intermediate CA: {int_ca}...")
        _tak_cert(['/opt/tak/certs/makeCert.sh', 'server', 'takserver'], desc="Creating server certificate...")
        _tak_cert(['/opt/tak/certs/makeCert.sh', 'client', 'admin'], desc="Creating admin certificate...")
        _tak_cert(['/opt/tak/certs/makeCert.sh', 'client', 'user'], desc="Creating user certificate...")
        log_step("✓ All certificates created")
        log_step("Importing root CA into TAK clients truststore...")
        _tak_cert(['keytool', '-import', '-alias', 'root-ca', '-file', '/opt/tak/certs/files/root-ca.pem',
                   '-keystore', f'/opt/tak/certs/files/truststore-{int_ca}.jks',
                   '-storepass', cert_pass, '-noprompt'])
        log_step("✓ Root CA imported into truststore (TAK clients trust chain complete)")
        log_step("Restarting TAK Server...")
        ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
        if ne_changed:
            log_step(f"  NameEntry fix: {ne_msg}")
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed:
            log_step(f"LDAP resync: {resync_msg}")
        run_cmd('systemctl stop takserver'); time.sleep(10)
        run_cmd('pkill -9 -f takserver 2>/dev/null; true', check=False); time.sleep(5)
        run_cmd('systemctl start takserver')
        log_step("Waiting 1.5 minutes...")
        for remaining in range(80, -1, -10):
            time.sleep(10)
            deploy_log.append(f"  \u23f3 {remaining//60:02d}:{remaining%60:02d} remaining")

        log_step(""); log_step("━━━ Step 8/9: Configuring CoreConfig.xml ━━━")
        # v10.0.5 non-root: these were `sed -i /opt/tak/CoreConfig.xml` — but sed is
        # broker-denied AND CoreConfig is tak-owned (0640), so every edit failed
        # exit 4 and X.509 auth / truststore / cert-enrollment / WebTAK were never
        # applied (TAK installs but is misconfigured). Do ONE broker read-modify-write.
        issued_days = config.get('issued_cert_validity_days') or config.get('intermediate_ca_validity_days', 730)
        cert_block = ('<certificateSigning CA="TAKServer"><certificateConfig>\n'
            f'<nameEntries>\n<nameEntry name="O" value="{config["cert_org"]}"/>\n'
            f'<nameEntry name="OU" value="{config["cert_ou"]}"/>\n</nameEntries>\n'
            '</certificateConfig>\n<TAKServerCAConfig keystore="JKS" '
            f'keystoreFile="certs/files/{int_ca}-signing.jks" keystorePass="{cert_pass}" '
            f'validityDays="{issued_days}" signatureAlg="SHA256WithRSA" />\n'
            '</certificateSigning>\n<vbm enabled="false"/>')
        try:
            _cc = _read_priv('/opt/tak/CoreConfig.xml')
            log_step("Enabling X.509 auth on 8089...")
            _cc = _cc.replace('<input auth="anonymous" _name="stdtcp" protocol="tcp" port="8087"/>',
                              '<input auth="x509" _name="stdssl" protocol="tls" port="8089"/>')
            log_step("Setting intermediate CA truststore...")
            _cc = _cc.replace('truststoreFile="certs/files/truststore-root.jks',
                              f'truststoreFile="certs/files/truststore-{int_ca}.jks')
            log_step("Enabling certificate enrollment...")
            _cc = _cc.replace('<vbm enabled="false"/>', cert_block)
            _cc = _cc.replace('<auth>', '<auth x509useGroupCache="true">')
            if config.get('enable_admin_ui') or config.get('enable_webtak'):
                admin_ui = str(config.get('enable_admin_ui', False)).lower()
                webtak = str(config.get('enable_webtak', False)).lower()
                log_step(f"WebTAK: AdminUI={admin_ui}, WebTAK={webtak}")
                _cc = _cc.replace('"cert_https"/',
                                  f'"cert_https" enableAdminUI="{admin_ui}" enableWebtak="{webtak}" enableNonAdminUI="false"/')
            _write_priv('/opt/tak/CoreConfig.xml', _cc)
        except Exception as _cce:
            log_step(f"  ✗ CoreConfig patch failed: {_cce}")
        _patch_coreconfig_passwords(cert_pass, log_fn=log_step)
        # For two-server and external_db: ensure JDBC URL and password point to the remote DB host
        import re
        _needs_jdbc_patch = (config.get('two_server') or config.get('external_db')) and config.get('tak_deploy_cfg')
        if _needs_jdbc_patch:
            tc = config['tak_deploy_cfg']
            if config.get('external_db'):
                # External/managed DB — credentials come from the external_db config block
                edb = tc.get('external_db', {})
                db_host = (edb.get('host') or '').strip()
                db_port = int(edb.get('port') or 5432)
                db_pass = (edb.get('password') or '').strip()
                mode_label = 'External DB'
            else:
                # Two-server — credentials come from server_one / database config
                db_host = (tc.get('server_one', {}).get('host') or '').strip()
                db_port = int(tc.get('database', {}).get('port') or 5432)
                db_pass = (tc.get('database', {}).get('password') or '').strip()
                s1_cfg = tc.get('server_one', {})
                mode_label = 'Two-server'
                # If password is missing, fetch it live from Server One
                if not db_pass and db_host and s1_cfg:
                    log_step("Two-server: DB password not cached — fetching from Server One...")
                    try:
                        db_pass, _ = _fetch_db_password_from_server_one(s1_cfg)
                        if db_pass:
                            log_step("✓ Fetched DB password from Server One")
                            settings = load_settings()
                            _tcfg = _get_tak_deployment_config(settings)
                            _tcfg.setdefault('database', {})['password'] = db_pass
                            settings['tak_deployment'] = _tcfg
                            save_settings(settings)
                    except Exception:
                        pass
                    if not db_pass:
                        log_step("⚠ Could not fetch DB password from Server One — TAK Server may not authenticate to PostgreSQL")
            if db_host:
                jdbc_url = f'jdbc:postgresql://{db_host}:{db_port}/cot'
                log_step(f"{mode_label}: ensuring JDBC points to {db_host}:{db_port}...")
                try:
                    r = subprocess.run(['cat', '/opt/tak/CoreConfig.xml'], capture_output=True, text=True, timeout=5)
                    cc = r.stdout or ''
                    needs_patch = 'jdbc:postgresql://127.0.0.1' in cc or db_host not in cc
                    # Also patch if password in file is empty
                    if not needs_patch and db_pass:
                        pw_match = re.search(r'password="([^"]*)"', cc)
                        if pw_match and not pw_match.group(1):
                            needs_patch = True
                    if needs_patch:
                        cc = re.sub(r'jdbc:postgresql://[^"]*', jdbc_url, cc)
                        if db_pass:
                            db_pass_xml = html.escape(db_pass, quote=True)
                            cc = re.sub(r'(<connection[^>]*password=")[^"]*(")', lambda m: m.group(1) + db_pass_xml + m.group(2), cc)
                        subprocess.run(_sudo_wrap(['tee', '/opt/tak/CoreConfig.xml']), input=cc, capture_output=True, text=True, timeout=5)
                        log_step(f"✓ JDBC URL and password set for {db_host}:{db_port}")
                    else:
                        log_step(f"✓ JDBC URL already points to {db_host}")
                except Exception as e:
                    log_step(f"⚠ Could not verify JDBC URL: {e}")
        log_step("✓ CoreConfig.xml configured")

        # Auto-connect to LDAP if Authentik is already deployed
        try:
            ak_installed = bool(detect_modules().get('authentik', {}).get('installed'))
            if ak_installed and not _coreconfig_has_ldap():
                log_step("Authentik detected — connecting TAK Server to LDAP...")
                ldap_ok, ldap_msg = _apply_ldap_to_coreconfig()
                if ldap_ok:
                    log_step(f"✓ {ldap_msg}")
                else:
                    log_step(f"⚠ LDAP auto-connect: {ldap_msg} — use 'Connect TAK Server to LDAP' after deploy")
        except Exception as e:
            log_step(f"⚠ LDAP auto-connect failed: {str(e)[:120]} — use 'Connect TAK Server to LDAP' after deploy")

        log_step("Final restart...")
        ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
        if ne_changed:
            log_step(f"  NameEntry fix: {ne_msg}")
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed:
            log_step(f"LDAP resync: {resync_msg}")
        run_cmd('systemctl stop takserver'); time.sleep(10)
        run_cmd('pkill -9 -f takserver 2>/dev/null; true', check=False); time.sleep(5)

        # For external_db: run SchemaManager explicitly against RDS now that CoreConfig
        # points at the correct host. SchemaManager has no CLI JDBC flags — it reads
        # CoreConfig.xml from the working directory. Run from /opt/tak so it finds the
        # already-patched CoreConfig.xml there rather than falling back to example.xml.
        if config.get('external_db') and os.path.exists('/opt/tak/db-utils/SchemaManager.jar'):
            log_step("External DB: running SchemaManager against RDS (ensuring schema is current)...")
            sm_r = subprocess.run(
                'cd /opt/tak && java -jar /opt/tak/db-utils/SchemaManager.jar upgrade 2>&1',
                shell=True, capture_output=True, text=True, timeout=300
            )
            sm_out = (sm_r.stdout or '') + (sm_r.stderr or '')
            for line in sm_out.strip().split('\n')[:30]:
                if line.strip():
                    deploy_log.append(f"  {line.rstrip()}")
            if sm_r.returncode == 0 or 'SchemaManager complete' in sm_out or 'already up to date' in sm_out.lower():
                log_step("✓ SchemaManager upgrade complete (RDS schema ready)")
            else:
                log_step(f"⚠ SchemaManager exited {sm_r.returncode} — check logs above. TAK Server may still start if schema was partially applied.")

        run_cmd('systemctl start takserver')
        log_step("Waiting 10 minutes for full initialization before promoting admin...")
        total_wait = 600
        waited = 0
        while waited < total_wait:
            time.sleep(10)
            waited += 10
            if deploy_status.get('cancelled'):
                log_step("\u26a0 Cancelled during initialization wait")
                return
            left = total_wait - waited
            m, s = divmod(left, 60)
            deploy_log.append(f"  \u23f3 {m:02d}:{s:02d} remaining")
        log_step("\u2713 Initialization wait complete")

        log_step(""); log_step("━━━ Step 9/9: Promoting Admin ━━━")
        run_cmd('java -jar /opt/tak/utils/UserManager.jar certmod -A /opt/tak/certs/files/admin.pem 2>&1', "Promoting admin certificate...", check=False)
        webadmin_pass = config.get('webadmin_password', '')
        settings_for_ak = load_settings()
        authentik_for_webadmin = bool(webadmin_pass and _get_authentik_env_content(settings_for_ak))
        if webadmin_pass:
            if authentik_for_webadmin:
                log_step("Authentik detected — webadmin will live in Authentik/LDAP only (skipping flat-file UserManager; avoids 8446 shadowing).")
                _remove_webadmin_from_userauth()
            else:
                # v0.9.12: shlex.quote the password so any future operator-supplied
                # value with shell metacharacters is safely literalized instead of
                # being interpreted by bash. webadmin_pass should already pass
                # _validate_cert_password upstream, but defense-in-depth.
                log_step("Creating webadmin user (flat-file)...")
                run_cmd(f"java -jar /opt/tak/utils/UserManager.jar usermod -A -p {shlex.quote(webadmin_pass)} webadmin 2>&1", check=False)
                log_step("✓ webadmin user created")
        # v10.0.1: sync the LDAP service-account (adm_ldapservice) password into
        # Authentik on this NATIVE (.deb/.rpm) deploy. Without it the SA password
        # stays mismatched (Authentik DB ≠ CoreConfig) → TAK's SA bind fails err 49
        # → group resolution dies → webadmin (even when correctly in tak_ROLE_ADMIN)
        # can't be confirmed admin → 8446 drops to WebTAK. The container path already
        # does this (c7b18ad); mirror it here so amd64/RHEL self-heal too — the same
        # canonical call the "Connect TAK Server to LDAP" route uses. The resync +
        # restart that follow then align CoreConfig and reload TAK with the now-
        # matching credential. Non-fatal: a miss just means the operator runs the
        # Resync button once (the pre-fix behaviour).
        if _get_authentik_env_content(load_settings()):
            try:
                # v10.0.1: wait for Authentik to be healthy (self-heal a stopped
                # container) + retry on a transient API 500, instead of firing once.
                ok_sa, msg_sa = _sync_authentik_ldap_sa_with_retry(log_step)
                if ok_sa:
                    log_step("  ✓ LDAP service-account password synced to Authentik (8446 admin bind)")
                else:
                    log_step(f"  ⚠ LDAP service-account sync: {msg_sa} — run 'Connect TAK Server to LDAP' if 8446 shows WebTAK")
            except Exception as _sae:
                log_step(f"  ⚠ LDAP service-account sync error (non-fatal): {str(_sae)[:120]}")
        ne_changed, ne_msg = _sanitize_coreconfig_name_entries()
        if ne_changed:
            log_step(f"  NameEntry fix: {ne_msg}")
        changed, resync_msg = _resync_ldap_credential_to_coreconfig()
        if changed:
            log_step(f"LDAP resync: {resync_msg}")
        run_cmd('systemctl restart takserver')
        log_step("Waiting 30 seconds...")
        for remaining in range(20, -1, -10):
            time.sleep(10)
            deploy_log.append(f"  \u23f3 {remaining//60:02d}:{remaining%60:02d} remaining")
        ip = load_settings().get('server_ip', 'YOUR-IP')
        settings = load_settings()
        # Save webadmin_password to settings so Authentik deploy can read it
        if webadmin_pass:
            settings['webadmin_password'] = webadmin_pass
            save_settings(settings)
        # Regenerate Caddyfile if Caddy is configured
        if settings.get('fqdn'):
            generate_caddyfile(settings)
            subprocess.run(_sudo_wrap(['systemctl', 'reload', 'caddy']), capture_output=True)
            log_step(f"  ✓ Caddy config updated for TAK Server")

        # Sync webadmin to Authentik with verification so first 8446 login works without manual fixes.
        if webadmin_pass and _get_authentik_env_content(settings):
            sync_ok = False
            sync_err = None
            for attempt in range(2):
                ok, err = _ensure_authentik_webadmin(skip_bind_verify=False)
                if ok:
                    sync_ok = True
                    log_step("  ✓ webadmin synced to Authentik")
                    break
                sync_err = (err or 'Unknown sync error')[:120]
                if attempt == 0:
                    # The first webadmin bind on a fresh deploy frequently fails with
                    # "exceeded stage recursion depth" — a flow-execution spiral, NOT a
                    # bad password. Cause: webadmin is verified while the LDAP outpost is
                    # still on internal direct routing, and the ldap-authentication-flow
                    # may carry a password_stage on its identification stage (recursion).
                    # adm_ldapservice masks this (cached session); webadmin is a fresh bind
                    # so it hits the spiral cold. Repair the flow before retrying — this is
                    # what "Connect TAK Server to LDAP" does (clears password_stage, fixes
                    # the 3 ldap-* stage bindings, force-recreates the outpost). Without it
                    # a clean install dead-ends here. Idempotent on already-healthy boxes.
                    log_step(f"  ℹ webadmin sync attempt 1 failed: {sync_err} — repairing LDAP flow and retrying...")
                    try:
                        ok_flow, err_flow = _ensure_ldap_flow_authentication_none()
                        if ok_flow:
                            log_step("  ✓ LDAP flow repaired (cleared recursion spiral)")
                        else:
                            log_step(f"  ⚠ LDAP flow repair: {err_flow} — retrying webadmin sync anyway")
                    except Exception as _fe:
                        log_step(f"  ⚠ LDAP flow repair error (non-fatal): {str(_fe)[:120]}")
                    time.sleep(15)
            if not sync_ok:
                # Do NOT abort the deploy. TAK Server is installed and running; a webadmin
                # bind-verify miss is usually a recoverable flow spiral (common on slow-disk
                # boxes and on installs with no public IP / no LE cert, where the outpost is
                # stuck on internal routing). Aborting here would also skip Guard Dog, the
                # LE cert step, and the completion banner over a problem that's fixable in
                # one click post-deploy. Finish the deploy and tell the operator how to fix.
                log_step(f"  ⚠ webadmin Authentik sync not verified: {sync_err}")
                log_step("     TAK Server is installed — this is usually a recoverable LDAP flow spiral, not a TAK Server problem.")
                log_step("     Fix: TAK Server page → 'Connect TAK Server to LDAP'. Then test https://<host>:8446 (user: webadmin).")
                log_step("     (webadmin may already work — the cold first bind can false-negative; try the 8446 login first.)")
            else:
                _remove_webadmin_from_userauth()
                log_step("  ✓ Removed any flat-file webadmin shadow (8446 → LDAP only)")

        # v0.8.5: Now that TAK Server is installed (heavy LDAP load profile activated),
        # proactively migrate the LDAP outpost to FQDN routing if it's still on internal direct.
        # This prevents the responder-class bug where heavy load on internal routing causes
        # flow-execution recursion that's masked by cached service-account sessions.
        if _get_authentik_env_content(settings):
            try:
                _ensure_authentik_ldap_outpost_on_fqdn(log_step)
            except Exception as _e:
                log_step(f"  ⚠ Proactive routing migration skipped: {_e}")
            try:
                _ensure_authentik_gunicorn_timeout(log_step)
            except Exception as _e:
                log_step(f"  ⚠ Gunicorn timeout migration skipped: {_e}")
            try:
                _ensure_authentik_pg_persistent_connections(log_step)
            except Exception as _e:
                log_step(f"  ⚠ PG persistent connections migration skipped: {_e}")

        # If Caddy is already running with a domain, install LE cert on 8446 now.
        # This handles the case where Caddy was deployed before TAK Server.
        fqdn = settings.get('fqdn', '')
        if fqdn:
            caddy_active = subprocess.run(_sudo_wrap(['systemctl', 'is-active', 'caddy']), capture_output=True, text=True)
            if caddy_active.stdout.strip() == 'active':
                log_step("")
                log_step("━━━ Installing LE Cert on Port 8446 ━━━")
                install_le_cert_on_8446(_get_service_domain(settings, 'takserver'), log_step, wait_for_cert=True)

        log_step(""); log_step("=" * 50); log_step("✓ DEPLOYMENT COMPLETE!"); log_step("=" * 50); log_step("")
        log_step(f"  WebGUI (cert):     https://{ip}:8443")
        if webadmin_pass:
            log_step(f"  WebGUI (password): https://{ip}:8446")
            log_step(f"  Username: webadmin")
        log_step(f"  Certificate Password: {cert_pass}")
        log_step(f"  Admin cert: /opt/tak/certs/files/admin.p12")
        deploy_status.update({'complete': True, 'running': False})

        # Auto-deploy Guard Dog so it runs from the start (user can disable or configure notifications later)
        if not os.path.exists('/opt/tak-guarddog'):
            log_step("")
            log_step("━━━ Guard Dog (monitoring) — installing automatically ━━━")
            alert_email = (load_settings().get('guarddog_alert_email') or '').strip()
            run_guarddog_deploy(alert_email)
            if guarddog_deploy_status.get('complete') and not guarddog_deploy_status.get('error'):
                log_step("✓ Guard Dog installed. Configure notifications on the Guard Dog page.")
            elif os.path.exists('/opt/tak-guarddog') and not _guarddog_is_enabled():
                # Partial install (e.g. enable failed): ensure timers are enabled so Guard Dog runs
                log_step("Enabling Guard Dog timers…")
                subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True, timeout=10)
                for t in _guarddog_timer_list():
                    subprocess.run(_sudo_wrap(['systemctl', 'enable', t]), capture_output=True, timeout=5)
                    subprocess.run(_sudo_wrap(['systemctl', 'start', t]), capture_output=True, timeout=5)
                subprocess.run(_sudo_wrap(['systemctl', 'enable', 'tak-health.service']), capture_output=True, timeout=5)
                subprocess.run(_sudo_wrap(['systemctl', 'start', 'tak-health.service']), capture_output=True, timeout=5)
                if _guarddog_is_enabled():
                    log_step("✓ Guard Dog enabled. Configure notifications on the Guard Dog page.")
    except Exception as e:
        log_step(f"✗ FATAL ERROR: {str(e)}")
        deploy_status.update({'error': True, 'running': False})

def _send_cert_file_priv(cert_dir, filename):
    """Stream a cert file to the browser, reading 0600 tak:tak files via the
    broker (GH #52). TAK Server writes private-key material (.p12/.key) 0600
    tak:tak; the non-root takwerx console can't open() them, so raw
    send_from_directory hit PermissionError → HTTP 500. Plain open() stays the
    fast path for world-readable files and root-era consoles. Do NOT loosen the
    key perms instead — the privileged read is the fix.
    """
    from flask import send_file
    import io
    fp = os.path.join(cert_dir, filename)
    if not os.path.isfile(fp):
        return jsonify({'error': f'{filename} not found'}), 404
    try:
        with open(fp, 'rb') as f:
            data = f.read()
    except PermissionError:
        try:
            r = subprocess.run(_sudo_wrap(['cat', fp]), capture_output=True, timeout=15)
            data = r.stdout if r.returncode == 0 else b''
        except Exception:
            data = b''
        if not data:
            return jsonify({'error': f'Could not read {filename}: permission denied for the console user and the privileged read failed'}), 500
    return send_file(io.BytesIO(data), as_attachment=True, download_name=filename)

@app.route('/api/download/admin-cert')
@login_required
def download_admin_cert():
    return _send_cert_file_priv('/opt/tak/certs/files', 'admin.p12')

@app.route('/api/download/user-cert')
@login_required
def download_user_cert():
    return _send_cert_file_priv('/opt/tak/certs/files', 'user.p12')

@app.route('/api/download/truststore')
@login_required
def download_truststore():
    p = '/opt/tak/certs/files'
    if os.path.exists(p):
        for f in os.listdir(p):
            if f.startswith('truststore-') and f.endswith('.p12') and 'root' not in f:
                # truststore-*.p12 is 0600 tak:tak too (GH #52) — same privileged read.
                return _send_cert_file_priv(p, f)
    return jsonify({'error': 'truststore not found'}), 404


@app.route('/api/download/ca-pem')
@login_required
def download_ca_pem():
    p = '/opt/tak/certs/files'
    if os.path.exists(os.path.join(p, 'ca.pem')):
        return send_from_directory(p, 'ca.pem', as_attachment=True)
    return jsonify({'error': 'ca.pem not found'}), 404


@app.route('/api/takserver/federation-info')
@login_required
def takserver_federation_info():
    """Return V2 federation status: enabled, port, and whether UFW allows that port inbound."""
    info = {'v2_enabled': False, 'v2_port': None, 'firewall_open': False, 'ca_exists': False}
    info['ca_exists'] = os.path.exists('/opt/tak/certs/files/ca.pem')
    cc_path = '/opt/tak/CoreConfig.xml'
    if not os.path.exists(cc_path):
        return jsonify(info)
    try:
        r = subprocess.run(_sudo_wrap(['cat', cc_path]), capture_output=True, text=True, timeout=5)
        cc = r.stdout or ''
    except Exception:
        return jsonify(info)
    import re as _re
    m = _re.search(r'<federation-server.*?v2enabled\s*=\s*"true".*?v2port\s*=\s*"(\d+)"', cc, _re.DOTALL | _re.IGNORECASE)
    if not m:
        m = _re.search(r'<federation-server.*?v2port\s*=\s*"(\d+)".*?v2enabled\s*=\s*"true"', cc, _re.DOTALL | _re.IGNORECASE)
    if m:
        info['v2_enabled'] = True
        info['v2_port'] = int(m.group(1))
    else:
        pm = _re.search(r'v2port\s*=\s*"(\d+)"', cc, _re.IGNORECASE)
        if pm:
            info['v2_port'] = int(pm.group(1))
        info['v2_enabled'] = bool(_re.search(r'v2enabled\s*=\s*"true"', cc, _re.IGNORECASE))
    if info['v2_port']:
        try:
            r = _priv_pipe(['ufw', 'status'], ['grep', '-w', info["v2_port"]], timeout=10)
            info['firewall_open'] = 'ALLOW' in (r.stdout or '')
        except Exception:
            pass
    return jsonify(info)


@app.route('/api/takserver/federation-firewall', methods=['POST'])
@login_required
def takserver_federation_firewall():
    """Open or close the V2 federation port in UFW."""
    data = request.json or {}
    port = data.get('port')
    action = data.get('action', 'open')
    if not port or not isinstance(port, int) or port < 1 or port > 65535:
        return jsonify({'success': False, 'error': 'Invalid port'}), 400
    try:
        be = _fw_backend()  # 'firewalld' on RHEL, 'ufw' on Debian — bare ufw broke on RHEL
        if action == 'open':
            _fw_allow(port, 'tcp')
        elif be == 'firewalld':
            subprocess.run(_sudo_wrap(['firewall-cmd', '--permanent', f'--remove-port={port}/tcp']), capture_output=True, text=True, timeout=10)
            subprocess.run(_sudo_wrap(['firewall-cmd', '--reload']), capture_output=True, text=True, timeout=10)
        else:
            subprocess.run(_sudo_wrap(['ufw', 'delete', 'allow', f'{port}/tcp']), capture_output=True, text=True, timeout=10)
        if be == 'firewalld':
            r = _priv_pipe(['firewall-cmd', '--list-ports'], ['grep', '-w', f'{port}/tcp'], timeout=10)
            is_open = bool((r.stdout or '').strip())
        else:
            r = _priv_pipe(['ufw', 'status'], ['grep', '-w', str(port)], timeout=10)  # str(port): grep argv must be a string
            is_open = 'ALLOW' in (r.stdout or '')
        return jsonify({'success': True, 'firewall_open': is_open})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:200]}), 500


def _takportal_sync_certs(plog=None, restart=False):
    """Refresh BOTH TAK Portal cert artifacts from the CURRENT TAK Server certs:
      - data/certs/tak-client.p12  (admin.p12 re-encoded to a modern PKCS12 — TAK
        emits legacy RC2-40-CBC which the portal's Node 22 / OpenSSL 3 cannot read)
      - data/certs/tak-ca.pem      (server CA chain for the portal truststore)

    Mirrors run_takportal_deploy Step 5; idempotent; safe to call on every TAK
    (re)deploy / CA change / resync. Returns (success, message).

    v10.0.1 — why this exists: a container TAK redeploy and the old
    'sync portal CA' action refreshed ONLY the CA, leaving tak-client.p12 as the
    OLD-CA + legacy-algo cert. The portal then couldn't read its client cert →
    Marti stats 503 (no connected users / uptime), while enrollment still worked
    (that path goes through Authentik/8446, not this cert). Both halves must
    refresh together. See memory takportal-stale-client-cert-on-redeploy.
    Works the same on native and container boxes (the portal is always a
    container and admin.p12 is always at /opt/tak/certs/files)."""
    def _log(m):
        if plog:
            plog(m)
    r = _priv_pipe(['docker', 'ps', '--format', '{{.Names}}'], ['grep', '-q', 'tak-portal'])
    if r.returncode != 0:
        return (False, 'TAK Portal container is not running')
    cert_dir = '/opt/tak/certs/files'
    subprocess.run(_sudo_wrap(['docker', 'exec', 'tak-portal', 'mkdir', '-p', '/usr/src/app/data/certs']), capture_output=True, text=True)
    cert_pass = _get_tak_cert_password(load_settings())
    # --- client cert: admin.p12 -> modern PKCS12 -> tak-client.p12 ---
    ok_client = False
    admin_p12 = os.path.join(cert_dir, 'admin.p12')
    if not os.path.exists(admin_p12):
        for name in ['webadmin.p12', 'admin.p12']:
            p = os.path.join(cert_dir, name)
            if os.path.exists(p):
                admin_p12 = p
                break
    if os.path.exists(admin_p12):
        # v10.0.5 non-root: admin.p12 is 0600 tak:tak — cat it via the broker (root) into a
        # console-readable temp so the openssl -legacy READ stage below works. Raw openssl as
        # takwerx produced an empty PEM → the code fell back to copying the unreadable LEGACY
        # p12 → portal can't read its client cert → Marti stats 503.
        _fd_a, _local_admin_p12 = tempfile.mkstemp(suffix='.p12', prefix='tak-portal-src-')
        try:
            _cat_a = subprocess.run(_sudo_wrap(['cat', admin_p12]), capture_output=True, timeout=15)
            with os.fdopen(_fd_a, 'wb') as _f:
                _f.write(_cat_a.stdout or b'')
        except Exception:
            try:
                os.close(_fd_a)
            except Exception:
                pass
            _local_admin_p12 = admin_p12
        fd_p12, modern_p12 = tempfile.mkstemp(suffix='.p12', prefix='tak-portal-admin-')
        os.close(fd_p12)
        fd_pem, tmp_pem = tempfile.mkstemp(suffix='.pem', prefix='tak-portal-pem-')
        os.close(fd_pem)
        # Re-encode in TWO stages via a temp PEM file — NOT a stdin pipe.
        # v10.0.1: `openssl pkcs12 -export` does NOT reliably read PEM from stdin
        # on OpenSSL 3.0.x (Ubuntu 22.04), so the old
        # `openssl pkcs12 -in ... | openssl pkcs12 -export -out ...` pipe silently
        # produced an empty file and fell back to copying the unreadable LEGACY
        # p12 — the real reason the portal could never read its client cert.
        # -legacy is required to READ TAK's RC2-40-CBC admin.p12; the export stage
        # defaults to modern AES, which the portal's Node 22 / OpenSSL 3 can read.
        subprocess.run(
            f'openssl pkcs12 -in {shlex.quote(_local_admin_p12)} -passin pass:{shlex.quote(cert_pass)} -nodes -legacy -out {shlex.quote(tmp_pem)} 2>/dev/null',
            shell=True, capture_output=True, text=True, timeout=30)
        if os.path.exists(tmp_pem) and os.path.getsize(tmp_pem) > 0:
            subprocess.run(
                f'openssl pkcs12 -export -in {shlex.quote(tmp_pem)} -passout pass:{shlex.quote(cert_pass)} -out {shlex.quote(modern_p12)} 2>/dev/null',
                shell=True, capture_output=True, text=True, timeout=30)
        try:
            os.remove(tmp_pem)
        except OSError:
            pass
        if os.path.exists(modern_p12) and os.path.getsize(modern_p12) > 0:
            subprocess.run(_sudo_wrap(['docker', 'cp', modern_p12, 'tak-portal:/usr/src/app/data/certs/tak-client.p12']), capture_output=True, text=True)
            _log("  ✓ tak-client.p12 refreshed (admin.p12 re-encoded to modern PKCS12)")
            ok_client = True
        else:
            subprocess.run(_sudo_wrap(['docker', 'cp', admin_p12, 'tak-portal:/usr/src/app/data/certs/tak-client.p12']), capture_output=True, text=True)
            _log("  ⚠ tak-client.p12 copied in LEGACY format (re-encode failed — portal may not read it)")
            ok_client = True
        try:
            os.remove(modern_p12)
        except OSError:
            pass
        if _local_admin_p12 != admin_p12:
            try:
                os.remove(_local_admin_p12)
            except OSError:
                pass
    else:
        _log("  ⚠ admin.p12 not found in /opt/tak/certs/files/ — client cert not refreshed")
    # --- CA chain: takserver.pem (full chain) or ca.pem+root-ca.pem -> tak-ca.pem ---
    ok_ca = False
    tak_ca_src = None
    ca_bundle_path = None
    takserver_pem = os.path.join(cert_dir, 'takserver.pem')
    if os.path.isfile(takserver_pem):
        tak_ca_src = takserver_pem
    else:
        bundle_parts = []
        for ca_file in [os.path.join(cert_dir, 'ca.pem'), os.path.join(cert_dir, 'root-ca.pem')]:
            if os.path.isfile(ca_file):
                try:
                    content = _read_priv(ca_file).strip()   # v10.0.5 non-root: read via broker
                except Exception:
                    content = ''
                if 'BEGIN CERTIFICATE' in content and 'TRUSTED' not in content:
                    bundle_parts.append(content)
        if bundle_parts:
            fd_ca, ca_bundle_path = tempfile.mkstemp(suffix='.pem', prefix='tak-ca-bundle-')
            with os.fdopen(fd_ca, 'w') as f:
                f.write('\n'.join(bundle_parts) + '\n')
            tak_ca_src = ca_bundle_path
    if tak_ca_src:
        subprocess.run(_sudo_wrap(['docker', 'cp', tak_ca_src, 'tak-portal:/usr/src/app/data/certs/tak-ca.pem']), capture_output=True, text=True, timeout=10)
        _log("  ✓ tak-ca.pem refreshed (server CA chain)")
        ok_ca = True
        if ca_bundle_path is not None and tak_ca_src == ca_bundle_path:
            try:
                os.remove(tak_ca_src)
            except OSError:
                pass
    else:
        _log("  ⚠ no CA cert files found in /opt/tak/certs/files/ — CA not refreshed")
    if restart and (ok_client or ok_ca):
        subprocess.run(_sudo_wrap(['docker', 'restart', 'tak-portal']), capture_output=True, text=True, timeout=30)
    if ok_client and ok_ca:
        return (True, 'TAK Portal client cert + CA refreshed and portal restarted')
    if ok_ca and not ok_client:
        return (False, 'CA refreshed but client cert (admin.p12) not found')
    if ok_client and not ok_ca:
        return (False, 'Client cert refreshed but CA not found')
    return (False, 'No certs refreshed (admin.p12 / CA not found in certs/files)')


@app.route('/api/takserver/sync-portal-ca', methods=['POST'])
@login_required
def takserver_sync_portal_ca():
    """Resync TAK Portal to TAK Server: refresh BOTH the client cert
    (data/certs/tak-client.p12) and the CA (data/certs/tak-ca.pem), then restart.
    v10.0.1: previously copied ONLY the CA, which left a stale/legacy client cert
    after a CA change → Marti stats 503. Now delegates to _takportal_sync_certs."""
    r = _priv_pipe(['docker', 'ps', '--format', '{{.Names}}'], ['grep', '-q', 'tak-portal'])
    if r.returncode != 0:
        return jsonify({'success': False, 'error': 'TAK Portal container is not running. Start it first.'}), 400
    ok, msg = _takportal_sync_certs(restart=True)
    if not ok:
        return jsonify({'success': False, 'error': msg}), 500
    return jsonify({'success': True, 'message': msg})


@app.route('/api/certs/list')
@login_required
def list_cert_files():
    cert_path = '/opt/tak/certs/files'
    if not os.path.exists(cert_path):
        return jsonify({'files': []})
    files = []
    for f in sorted(os.listdir(cert_path)):
        fp = os.path.join(cert_path, f)
        if os.path.isfile(fp):
            files.append({'name': f, 'size': os.path.getsize(fp),
                'size_display': f"{os.path.getsize(fp)/1024:.1f} KB" if os.path.getsize(fp) < 1024*1024 else f"{os.path.getsize(fp)/(1024*1024):.1f} MB"})
    return jsonify({'files': files})

@app.route('/api/certs/download/<filename>')
@login_required
def download_cert_file(filename):
    import re
    if not re.match(r'^[a-zA-Z0-9._-]+$', filename):
        return jsonify({'error': 'Invalid filename'}), 400
    return _send_cert_file_priv('/opt/tak/certs/files', filename)

@app.route('/api/deploy/log')
@login_required
def deploy_log_stream():
    last = int(request.args.get('after', 0))
    return jsonify({'entries': deploy_log[last:], 'total': len(deploy_log),
        'running': deploy_status['running'], 'complete': deploy_status['complete'], 'error': deploy_status['error']})


@app.route('/api/takserver/purge-failed-install', methods=['POST'])
@login_required
def takserver_purge_failed_install():
    """Purge a broken takserver dpkg state after a FATAL install failure so the operator can re-upload and retry."""
    if deploy_status.get('running'):
        return jsonify({'error': 'Deployment is running — wait for it to complete first.'}), 400
    log = []
    # v10.0.5 non-root + multiplatform: package removal is family-specific and must
    # route through the broker. The old handler ran `dpkg --purge` (Debian-only — it's
    # "command not found" on RHEL) and a raw `rm -rf /opt/tak` (fails as the non-root
    # console — /opt/tak is root/tak-owned).
    if _distro_family() == 'rhel':
        purge_cmds = [['dnf', 'remove', '-y', 'takserver']]
    else:
        purge_cmds = [['dpkg', '--purge', '--force-all', 'takserver'],
                      ['apt-get', 'autoremove', '-y']]
    purge_cmds.append(['rm', '-rf', '/opt/tak'])
    for argv in purge_cmds:
        try:
            r = subprocess.run(_sudo_wrap(argv), capture_output=True, text=True, timeout=180)
            log.append((r.stdout.strip() or r.stderr.strip() or '(ok)')[:300])
        except Exception as e:
            log.append(f'{argv[0]}: {e}')
    # Delete any corrupted takserver package uploads (.deb via dpkg-deb, .rpm via rpm -qp).
    cleaned_debs = []
    for fn in os.listdir(UPLOAD_DIR):
        low = fn.lower()
        if 'takserver' not in low or not (low.endswith('.deb') or low.endswith('.rpm')):
            continue
        fp = os.path.join(UPLOAD_DIR, fn)
        verify = ['dpkg-deb', '--info', fp] if low.endswith('.deb') else ['rpm', '-qp', fp]
        try:
            ok = subprocess.run(verify, capture_output=True, timeout=15).returncode == 0
        except Exception:
            ok = True  # verifier missing for this family — don't delete a good upload
        if not ok:
            try:
                os.remove(fp)
                cleaned_debs.append(fn)
            except OSError:
                pass
    deploy_status.update({'running': False, 'complete': False, 'error': False, 'cancelled': False})
    deploy_log.clear()
    return jsonify({'success': True, 'cleaned_debs': cleaned_debs, 'log': log})


