@app.route('/api/host-resource-usage')
@login_required
def api_host_resource_usage():
    """Top processes by CPU and RAM for this host or a remote (target=tak_db|fedhub). Same hosts as UU cards."""
    target = request.args.get('target', 'this_host')
    if target == 'tak_db':
        settings = load_settings()
        cfg = _get_tak_deployment_config(settings)
        if cfg.get('mode') != 'two_server':
            return jsonify({'cpu_top': [], 'mem_top': [], 'error': 'Not two-server'})
        s1 = cfg.get('server_one', {})
        if not (s1.get('host') or '').strip():
            return jsonify({'cpu_top': [], 'mem_top': [], 'error': 'No DB host'})
        return jsonify(_top_processes_remote(s1))
    if target == 'fedhub':
        settings = load_settings()
        fh_cfg = _get_fedhub_deployment_config(settings)
        if not fh_cfg.get('deployed') or fh_cfg.get('target_mode') != 'remote':
            return jsonify({'cpu_top': [], 'mem_top': [], 'error': 'Fed Hub not deployed'})
        fh_remote = fh_cfg.get('remote', {})
        if not (fh_remote.get('host') or '').strip():
            return jsonify({'cpu_top': [], 'mem_top': [], 'error': 'No Fed Hub host'})
        return jsonify(_top_processes_remote(fh_remote))
    return jsonify(_top_processes_local())


_kernel_patch_cache = {'ts': 0, 'data': None}

@app.route('/api/system/kernel-patch-status')
@login_required
def kernel_patch_status_api():
    """Return running kernel version and whether a linux-image update is available via apt.
    Result is cached for 60 seconds to avoid hitting apt on every page load."""
    import time as _kpt
    now = _kpt.time()
    if _kernel_patch_cache['data'] and now - _kernel_patch_cache['ts'] < 60:
        return jsonify(_kernel_patch_cache['data'])
    try:
        running_kernel = subprocess.run(['uname', '-r'], capture_output=True, text=True, timeout=5).stdout.strip()
    except Exception:
        running_kernel = 'unknown'
    # v10.0.1: the "is a kernel update pending?" probe is package-manager
    # specific. The apt path is byte-identical to pre-v10 (the #1 regression
    # surface). The dnf path (EL9: RHEL/Rocky/Alma/CentOS) uses `dnf
    # check-update`, whose exit code 100 means "updates available" — scoped to
    # the kernel packages so the banner means the same thing on every distro.
    if (load_settings().get('pkg_mgr', 'apt') or 'apt').lower() == 'dnf':
        try:
            r = subprocess.run(
                _sudo_wrap(['dnf', '-q', 'check-update', 'kernel', 'kernel-core']), capture_output=True, text=True, timeout=30
            )
            # dnf check-update: 100 = updates available, 0 = up to date, 1 = error.
            # Treat error/timeout as "no banner" (same fail-safe as the apt branch).
            upgradable_count = 1 if r.returncode == 100 else 0
        except Exception:
            upgradable_count = 0
    else:
        try:
            upgradable_out = subprocess.run(
                'apt list --upgradable 2>/dev/null | grep linux-image | wc -l',
                shell=True, capture_output=True, text=True, timeout=20
            ).stdout.strip()
            upgradable_count = int(upgradable_out) if upgradable_out.isdigit() else 0
        except Exception:
            upgradable_count = 0
    data = {
        'running_kernel': running_kernel,
        'upgradable': upgradable_count > 0,
        'patched': upgradable_count == 0,
    }
    _kernel_patch_cache.update({'ts': now, 'data': data})
    return jsonify(data)


# v0.9.31 — one-click "Patch now" background-detached kernel/apt upgrade.
#
# WHY THIS EXISTS
# ---------------
# The kernel-update banner used to instruct operators to run
# `apt update && apt full-upgrade && reboot`. Locally this is fine. Over SSH
# it's a foot-gun: `apt full-upgrade` replaces systemd, networking, and
# (often) openssh-server, which can drop the SSH session mid-transaction.
# The chained command never reaches `reboot`; apt leaves an interrupted
# transaction (Start-Date but no End-Date in /var/log/apt/history.log);
# the box reboots later on the OLD kernel because the new one's initramfs
# never finalized. Field-hit on the SSDNodes box 2026-05-18 — operator
# followed the banner's instructions to the letter, ended up with the box
# still on 5.15.0-177 and the banner still firing.
#
# WHAT IT DOES
# ------------
# The "Patch now" button POSTs to /api/system/kernel-patch/start. The server
# fires `apt-get update && apt-get full-upgrade` as a TRANSIENT SYSTEMD UNIT
# via `systemd-run --no-block`. This is critical because:
#
#   apt full-upgrade with NEEDRESTART_MODE=a auto-restarts services whose
#   libraries got upgraded. takwerx-console.service is a Python gunicorn
#   process linked against libpython3.x / libssl / libc — almost any apt
#   full-upgrade will cause needrestart to `systemctl restart
#   takwerx-console.service`. If our apt subprocess shared takwerx-console's
#   cgroup, that restart would kill the apt job mid-flight — same disaster
#   as the original SSH-drop scenario, just from a different cause.
#
# `systemd-run --no-block --unit=infratak-kernel-patch` creates a transient
# .service unit in its OWN cgroup, completely decoupled from
# takwerx-console.service. When needrestart restarts the console, our apt
# job sails on. Bonus: full journalctl integration + clean systemctl
# status query for done/error/running state.
#
# Reboot is a SEPARATE explicit operator click — we never auto-reboot.
# Banner clears naturally within 60s of post-reboot once
# `apt list --upgradable | grep linux-image` returns 0.
#
# FLEET-UNIFORM COMPLIANCE
# ------------------------
# Same code path on every box. No per-customer state. systemd-run is part
# of systemd itself — always present on every box we deploy on (Ubuntu
# 22.04+). dpkg force-conf flags + DEBIAN_FRONTEND=noninteractive +
# NEEDRESTART_MODE=a are CONSTANTS baked into the unit definition — no
# operator override knob. If a box hits a class of upgrade that needs
# different flags, that's a code change pushed to the fleet.
_KERNEL_PATCH_UNIT = 'infratak-kernel-patch.service'
_KERNEL_PATCH_LOGFILE = '/var/log/takguard/kernel-patch.log'


def _kernel_patch_unit_state():
    """Return (load_state, active_state, sub_state, result, main_pid).
      load_state:   'loaded' | 'not-found' | 'masked' | 'error' | ''
                    NB: 'not-found' is the post-reboot state for transient
                    units (they do not survive reboot). 'masked' / 'error'
                    are rare but possible on hand-broken systemd setups.
      active_state: 'active' | 'inactive' | 'activating' | 'deactivating' | 'failed' | ''
      sub_state:    'running' | 'exited' | 'dead' | 'failed' | ...
      result:       'success' | 'exit-code' | 'signal' | ''
                    NB: when LoadState != 'loaded', `systemctl show -p Result`
                    returns the DEFAULT property value `success` — NOT a real
                    outcome. Callers MUST gate on load_state before treating
                    `result == 'success'` as meaningful. This is the v0.9.32
                    "reboot-loop banner" bug: post-reboot the transient unit
                    is gone, but `systemctl show` still returns Result=success
                    as a default, which `_kernel_patch_job_state` was reading
                    as "the patch job completed successfully" → banner stuck
                    in done/Reboot-now state forever.
      main_pid:     int or 0 (0 = no main PID)
    Empty strings on any error.
    """
    try:
        r = subprocess.run(
            ['systemctl', 'show', '-p', 'LoadState,ActiveState,SubState,Result,MainPID',
             _KERNEL_PATCH_UNIT],
            capture_output=True, text=True, timeout=5
        )
        out = r.stdout or ''
        load = active = sub = result = ''
        pid = 0
        for line in out.splitlines():
            if line.startswith('LoadState='):
                load = line.split('=', 1)[1].strip()
            elif line.startswith('ActiveState='):
                active = line.split('=', 1)[1].strip()
            elif line.startswith('SubState='):
                sub = line.split('=', 1)[1].strip()
            elif line.startswith('Result='):
                result = line.split('=', 1)[1].strip()
            elif line.startswith('MainPID='):
                try:
                    pid = int(line.split('=', 1)[1].strip())
                except ValueError:
                    pid = 0
        return (load, active, sub, result, pid)
    except Exception:
        return ('', '', '', '', 0)


def _kernel_patch_start_job():
    """Fire `apt-get update && apt-get full-upgrade` as a transient systemd
    unit. Returns (ok, message, pid_or_None).

    Why systemd-run vs subprocess.Popen: needrestart inside the apt run will
    almost certainly restart takwerx-console.service (any libpython/libssl/
    libc upgrade triggers it with NEEDRESTART_MODE=a). A plain Popen child
    shares the parent's cgroup and would get killed. systemd-run creates a
    transient unit in a separate cgroup that survives takwerx-console's
    restart, daemon-reexec, etc.

    Idempotent: if the transient unit is already active, refuses to spawn
    another and returns the existing pid. If the unit is failed or
    inactive, accepts the new request (and resets failed-state first so
    systemd allows the re-start).
    """
    if not (os.path.exists('/usr/bin/systemd-run') or os.path.exists('/bin/systemd-run')):
        return (False, "systemd-run not found — cannot detach safely", None)
    load, active, sub, result, pid = _kernel_patch_unit_state()
    if active in ('active', 'activating') and pid:
        return (False, f"kernel patch already running (pid {pid})", pid)
    # If unit is in a failed state from a previous run, reset so systemd
    # accepts a fresh start request with the same unit name. Only meaningful
    # if LoadState=loaded — a transient unit that doesn't exist post-reboot
    # has LoadState=not-found and reset-failed would be a no-op anyway.
    if load == 'loaded' and active == 'failed':
        try:
            subprocess.run(_sudo_wrap(['systemctl', 'reset-failed', _KERNEL_PATCH_UNIT]),
                           capture_output=True, timeout=5)
        except Exception:
            pass
    try:
        _makedirs_priv(os.path.dirname(_KERNEL_PATCH_LOGFILE))
    except Exception:
        pass
    # v10.0.1: which OS-upgrade command this job runs is package-manager
    # specific. The apt script below is byte-identical to pre-v10 (critical
    # regression surface); the dnf override for EL9 is applied right after.
    pkg_mgr = (load_settings().get('pkg_mgr', 'apt') or 'apt').lower()
    # Bash script body. Written to a tmp file rather than inlined into the
    # systemd-run argv to keep the unit definition compact.
    script = (
        '#!/bin/bash\n'
        'set -o pipefail\n'
        'export DEBIAN_FRONTEND=noninteractive NEEDRESTART_MODE=a\n'
        'TS() { date -u +"%Y-%m-%dT%H:%M:%SZ"; }\n'
        'echo "[$(TS)] === infra-TAK kernel patch job starting (pid $$) ==="\n'
        # v0.9.44: OS patching must NEVER sweep in a TAK Server MAJOR upgrade — that is
        # operator-driven and backup-gated (the console TAK update flow). Field: a kernel
        # patch pulled takserver 5.6->5.7, whose postinstall failed and wedged dpkg. Hold
        # the installed TAK packages for the duration of this run, release on exit. Only
        # holds WE add are released, so any pre-existing operator hold is preserved.
        'TAK_PKGS="takserver takserver-fed-hub"\n'
        'HELD=""\n'
        'PREHELD="$(apt-mark showhold 2>/dev/null)"\n'
        'for p in $TAK_PKGS; do\n'
        '  if dpkg -s "$p" >/dev/null 2>&1; then\n'
        '    case " $PREHELD " in *" $p "*) : ;; *) apt-mark hold "$p" >/dev/null 2>&1 && HELD="$HELD $p" ;; esac\n'
        '  fi\n'
        'done\n'
        '[ -n "$HELD" ] && echo "[$(TS)] TAK packages held for this patch (operator-driven upgrade only):$HELD"\n'
        'release_holds() { for p in $HELD; do apt-mark unhold "$p" >/dev/null 2>&1; done; [ -n "$HELD" ] && echo "[$(TS)] released TAK holds:$HELD"; }\n'
        'trap release_holds EXIT\n'
        'echo "[$(TS)] apt-get update"\n'
        'apt-get update 2>&1 || { rc=$?; echo "[$(TS)] FATAL: apt-get update failed (exit $rc)"; exit $rc; }\n'
        'echo "[$(TS)] apt-get full-upgrade -y (TAK Server packages held)"\n'
        'apt-get -y -o Dpkg::Options::="--force-confdef" -o Dpkg::Options::="--force-confold" full-upgrade 2>&1 \\\n'
        '  || { rc=$?; echo "[$(TS)] FATAL: apt-get full-upgrade failed (exit $rc)"; exit $rc; }\n'
        'echo "[$(TS)] === DONE — safe to reboot ==="\n'
    )
    if pkg_mgr == 'dnf':
        # EL9 (RHEL/Rocky/Alma/CentOS) path. Full `dnf -y upgrade`, the OS-wide
        # equivalent of apt full-upgrade, with the TAK Server packages EXCLUDED —
        # the SAME invariant the apt path enforces via apt-mark hold: OS patching
        # must never sweep in an operator-driven, backup-gated TAK major upgrade
        # (v0.9.44 field incident — a kernel patch pulled takserver 5.6->5.7 and
        # wedged the package DB). `--exclude='takserver*'` covers takserver and
        # takserver-fed-hub and needs no versionlock plugin. systemd-run, the
        # detached-cgroup rationale, and the reboot-pending signal are all
        # distro-agnostic, so only this script body changes. dnf runs as root
        # inside the transient unit (no new direct sudo call from the console);
        # logged for the v10.0.5 sudoers allowlist (NON-ROOT-COMMANDS: dnf).
        script = (
            '#!/bin/bash\n'
            'set -o pipefail\n'
            'TS() { date -u +"%Y-%m-%dT%H:%M:%SZ"; }\n'
            'echo "[$(TS)] === infra-TAK kernel patch job starting (pid $$) [dnf/EL9] ==="\n'
            'echo "[$(TS)] dnf -y upgrade (TAK Server packages excluded)"\n'
            "dnf -y upgrade --exclude='takserver*' 2>&1 \\\n"
            '  || { rc=$?; echo "[$(TS)] FATAL: dnf upgrade failed (exit $rc)"; exit $rc; }\n'
            'echo "[$(TS)] === DONE — safe to reboot ==="\n'
        )
    _script_path = '/var/lib/infratak-kernel-patch.sh'
    try:
        # v10.0.5 non-root: /var/lib is root-owned — write via the broker. A raw
        # open() here EPERM'd as the takwerx console, silently failing the whole
        # job so the transient unit never started and the UI hung on "pid ?".
        _write_priv(_script_path, script, perm=0o755)
    except Exception as _we:
        return (False, f"could not write script to {_script_path}: {_we}", None)
    cmd = [
        'systemd-run',
        '--unit=' + _KERNEL_PATCH_UNIT.replace('.service', ''),
        '--description=infra-TAK Kernel Patch Job (detached)',
        '--property=StandardOutput=append:' + _KERNEL_PATCH_LOGFILE,
        '--property=StandardError=append:' + _KERNEL_PATCH_LOGFILE,
        '--setenv=DEBIAN_FRONTEND=noninteractive',
        '--setenv=NEEDRESTART_MODE=a',
        '--setenv=PATH=/usr/sbin:/usr/bin:/sbin:/bin',
        '--no-block',
        '/bin/bash', _script_path,
    ]
    try:
        # v10.0.5 non-root: systemd-run creates a SYSTEM transient unit (needs
        # root) — route through the broker, which gates it to exactly this unit +
        # the fixed script (see _check_systemd_run). A bare subprocess failed as
        # the non-root console (system bus auth), which is the "pid ?" regression.
        r = subprocess.run(_sudo_wrap(cmd), capture_output=True, text=True, timeout=15)
    except Exception as _se:
        return (False, f"systemd-run spawn failed: {_se}", None)
    if r.returncode != 0:
        err = (r.stderr or r.stdout or '').strip()[:300]
        return (False, f"systemd-run returned {r.returncode}: {err}", None)
    # Poll briefly for the unit to enter active state and have a MainPID
    import time as _ktime
    new_pid = 0
    for _ in range(20):  # up to ~2 sec
        _ld, a, s, _res, p = _kernel_patch_unit_state()
        if a in ('active', 'activating') and p:
            new_pid = p
            break
        _ktime.sleep(0.1)
    # Bust the kernel-patch status cache so the banner reflects fresh state
    _kernel_patch_cache.update({'ts': 0, 'data': None})
    return (True, f"started (unit {_KERNEL_PATCH_UNIT}, pid {new_pid or 'pending'})", new_pid or None)


def _kernel_reboot_pending():
    """v0.9.44: True when the running kernel isn't the newest installed one — a more
    reliable "reboot needed" signal than /var/run/reboot-required, which can be cleared
    (e.g. a reboot that didn't land the new kernel, or a notify hook that never fired)
    while a reboot is still required to activate a freshly-installed kernel."""
    try:
        running = subprocess.run(['uname', '-r'], capture_output=True, text=True, timeout=5).stdout.strip()
        newest = subprocess.run(
            "ls -1 /boot/vmlinuz-* 2>/dev/null | sed 's|.*/vmlinuz-||' | sort -V | tail -1",
            shell=True, capture_output=True, text=True, timeout=5).stdout.strip()
        return bool(running and newest and running != newest)
    except Exception:
        return False


def _kernel_patch_job_state():
    """Return current state of the background kernel-patch transient unit.
    Returns a dict suitable for jsonify:
      {
        'running': bool,
        'pid': int|None,
        'done': bool,
        'error': bool,
        'log_tail': str (last ~4 KB),
        'log_present': bool,
        'unit_state': str (e.g. 'active/running', 'inactive/dead', 'failed/failed')
      }

    v0.9.44: `done`/`error` are now derived from the job's log markers and the
    `/var/run/reboot-required` flag rather than the systemd-default Result value,
    because a *successful* transient unit is garbage-collected within seconds of
    completing — even while the box is still up — which used to leave the UI stuck
    on "in progress". `reboot_required` is also returned. The reboot flag auto-clears
    after the reboot, so it subsumes the v0.9.32 post-reboot guard below.

    v0.9.32 fix: post-reboot the transient unit `infratak-kernel-patch.service`
    is gone from systemd's memory (transient units do not survive reboot).
    But `systemctl show -p Result` on a non-existent unit returns
    `Result=success` as the DEFAULT property value — not as a real outcome.
    The prior code treated that default as "patch completed successfully" and
    left the dashboard banner stuck on "Kernel patch complete — reboot
    required" forever. Operator clicks Reboot, box reboots, banner is back,
    infinite loop. Two-layer fix here:

      1. Hard gate on `load_state == 'loaded'`. If the unit was never loaded
         this boot (i.e. doesn't exist), Result is meaningless — return
         done=False, error=False, running=False. checkKernelPatch() then
         falls through to the apt-list status check, which correctly says
         "patched" once the new kernel is running.

      2. Defense in depth: even if LoadState=loaded but the apt-list probe
         says no kernel update is pending, downgrade done→False. The "done"
         state's only purpose is to surface "you should reboot to boot the
         new kernel" — if there's no new kernel to boot, the banner has
         nothing to assert.
    """
    load, active, sub, result, pid = _kernel_patch_unit_state()
    running = (active in ('active', 'activating'))
    log_tail = ''
    log_present = False
    # v10.0.5 non-root: the log is written by the root transient unit; read it via
    # the broker so the takwerx console can stream it regardless of dir perms.
    # (As root, _read_priv reads directly.) Raises if absent → log not present yet.
    try:
        _full = _read_priv(_KERNEL_PATCH_LOGFILE)
        log_present = True
        log_tail = _full[-4000:]
    except Exception:
        log_present = False
        log_tail = ''

    # v0.9.44: a pending reboot (new kernel staged) is the authoritative "you
    # should reboot" signal — and the kernel auto-clears /var/run/reboot-required
    # after the reboot, so it also ends the post-reboot banner loop the old
    # LoadState gate was guarding against (more directly than the apt-list probe).
    reboot_required = os.path.exists('/var/run/reboot-required') or _kernel_reboot_pending()

    # Transient unit gone. systemd garbage-collects a *successful* transient unit
    # within seconds of completion — even while the box is still up — so the old
    # "load != loaded => done=False" gate left the UI stuck on "in progress" with
    # the DONE log showing. Read the job's own log markers + the reboot flag instead.
    if load != 'loaded':
        last_done = log_tail.rfind('=== DONE')
        last_fatal = log_tail.rfind('FATAL:')
        completed_ok = last_done != -1 and last_done > last_fatal
        return {
            'running': False,
            'pid': None,
            'done': bool(completed_ok and reboot_required),
            'error': bool(last_fatal != -1 and last_fatal > last_done),
            'reboot_required': reboot_required,
            'log_tail': log_tail,
            'log_present': log_present,
            'unit_state': f"not-loaded/{load or 'unknown'}",
        }

    # Use systemd's own Result= field as the authoritative success/fail
    # signal — don't depend on log_tail content (log may be rotated, wiped,
    # or empty if the unit died before writing anything). The log-tail
    # banner string is just operator-visible confirmation.
    # Done only if it finished successfully AND a reboot is actually pending —
    # the "done" banner's whole job is to say "reboot to boot the new kernel",
    # so if reboot-required is gone (already rebooted) there's nothing to assert.
    done = (not running) and (result == 'success') and reboot_required
    err = (not running) and (active == 'failed' or (result not in ('', 'success')))

    # If the job clearly completed (success or failure), bust the kernel
    # patch status cache so the post-reboot banner check picks up reality.
    if (done or err) and _kernel_patch_cache.get('ts'):
        _kernel_patch_cache.update({'ts': 0, 'data': None})
    return {
        'running': running,
        'pid': (pid or None) if running else None,
        'done': done,
        'error': err,
        'reboot_required': reboot_required,
        'log_tail': log_tail,
        'log_present': log_present,
        'unit_state': f"{active or 'unknown'}/{sub or 'unknown'}" + (f" ({result})" if result else ''),
    }


@app.route('/api/system/kernel-patch/start', methods=['POST'])
@login_required
def kernel_patch_start_api():
    """Start the detached kernel-patch background job. Idempotent — if a
    job is already running, returns the existing pid + a 200."""
    try:
        ok, msg, pid = _kernel_patch_start_job()
    except Exception as e:
        return jsonify({'ok': False, 'error': f'start error: {e}'}), 500
    return jsonify({'ok': ok, 'message': msg, 'pid': pid})


@app.route('/api/system/kernel-patch/job-status')
@login_required
def kernel_patch_job_status_api():
    """Return live state of the kernel-patch background job (running/done/
    error/log_tail). Distinct from /api/system/kernel-patch-status which
    reports whether ANY apt linux-image upgrade is available — this one
    reports the job spawned by THIS console session."""
    try:
        return jsonify(_kernel_patch_job_state())
    except Exception as e:
        return jsonify({'running': False, 'error': True, 'log_tail': f'job-status error: {e}', 'pid': None, 'done': False, 'log_present': False}), 500


@app.route('/api/system/kernel-patch/reboot', methods=['POST'])
@login_required
def kernel_patch_reboot_api():
    """Schedule a system reboot. Detached so the response can still complete
    before the box goes down. Operator MUST have explicitly clicked the
    'Reboot now' button — this endpoint is intentionally unguarded beyond
    login_required; the UI confirm dialog is the only gate."""
    try:
        subprocess.Popen(
            _sudo_wrap(['systemctl', 'reboot']),
            stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
            start_new_session=True, close_fds=True
        )
    except Exception as e:
        return jsonify({'ok': False, 'error': f'reboot spawn failed: {e}'}), 500
    return jsonify({'ok': True, 'message': 'reboot scheduled'})


@app.route('/api/metrics')
@login_required
def api_metrics():
    metrics = get_system_metrics()
    try:
        settings = load_settings()
        metrics['unattended_upgrades_hosts'] = _build_uu_hosts(metrics, settings)
    except Exception:
        metrics['unattended_upgrades_hosts'] = [{
            'id': 'this_host', 'label': 'This host',
            'enabled': metrics.get('unattended_upgrades', {}).get('enabled', False),
            'running': metrics.get('unattended_upgrades', {}).get('running', False),
        }]
    return jsonify(metrics)



def _run_unattended_upgrades_remote(remote_cfg, action):
    """Run enable/disable unattended-upgrades on remote host via SSH. Returns (success, result_dict)."""
    if action == 'disable':
        # Can't use pkill -f over SSH: the SSH session's own cmdline contains the
        # script text, so pkill matches and kills the SSH connection (exit 255).
        # systemctl stop handles SIGTERM→SIGKILL on its own; just let it work.
        script = (
            'sudo systemctl stop apt-daily-upgrade.timer 2>/dev/null; '
            'sudo systemctl disable apt-daily-upgrade.timer 2>/dev/null; '
            'sudo systemctl stop apt-daily.timer 2>/dev/null; '
            'sudo systemctl disable apt-daily.timer 2>/dev/null; '
            'sudo systemctl stop unattended-upgrades 2>/dev/null; '
            'sudo systemctl disable unattended-upgrades 2>/dev/null; true; '
            'e=$(sudo systemctl is-enabled unattended-upgrades 2>/dev/null); echo "ENABLED=$e"'
        )
        ssh_timeout = 90
    else:
        script = (
            'sudo systemctl enable unattended-upgrades 2>/dev/null; sudo systemctl start unattended-upgrades 2>/dev/null; '
            'sudo systemctl enable apt-daily-upgrade.timer 2>/dev/null; sudo systemctl start apt-daily-upgrade.timer 2>/dev/null; true; '
            'e=$(sudo systemctl is-enabled unattended-upgrades 2>/dev/null); echo "ENABLED=$e"'
        )
        ssh_timeout = 30
    host = (remote_cfg.get('host') or '').strip()
    user = (remote_cfg.get('ssh_user') or 'root').strip()
    key = (remote_cfg.get('ssh_key_path') or '').strip()
    try:
        ok, out = _ssh_probe(remote_cfg, script, timeout=ssh_timeout)
        if not ok:
            return False, {'error': (out or 'ssh failed')[:300]}
        uu = _get_unattended_upgrades_status_remote(remote_cfg)
        if 'error' in uu:
            return False, uu
        return True, uu
    except Exception as e:
        return False, {'error': str(e)[:300]}


@app.route('/api/unattended-upgrades', methods=['POST'])
@login_required
def api_toggle_unattended_upgrades():
    """Enable or disable unattended-upgrades service on this host or a remote (target)."""
    data = request.json if request.is_json else {}
    action = data.get('action')
    target = data.get('target', 'this_host')
    if action not in ('enable', 'disable'):
        return jsonify({'success': False, 'error': 'action must be enable or disable'}), 400
    if target == 'tak_db':
        settings = load_settings()
        cfg = _get_tak_deployment_config(settings)
        if cfg.get('mode') != 'two_server':
            return jsonify({'success': False, 'error': 'Not two-server'}), 400
        s1 = cfg.get('server_one', {})
        if not (s1.get('host') or '').strip():
            return jsonify({'success': False, 'error': 'No DB host'}), 400
        ok, result = _run_unattended_upgrades_remote(s1, action)
        if ok:
            return jsonify({'success': True, 'target': 'tak_db', 'enabled': result['enabled'], 'running': result['running']})
        return jsonify({'success': False, 'error': result.get('error', 'unknown')}), 500
    if target == 'fedhub':
        settings = load_settings()
        fh_cfg = _get_fedhub_deployment_config(settings)
        if not fh_cfg.get('deployed') or fh_cfg.get('target_mode') != 'remote':
            return jsonify({'success': False, 'error': 'Fed Hub not deployed'}), 400
        fh_remote = fh_cfg.get('remote', {})
        if not (fh_remote.get('host') or '').strip():
            return jsonify({'success': False, 'error': 'No Fed Hub host'}), 400
        ok, result = _run_unattended_upgrades_remote(fh_remote, action)
        if ok:
            return jsonify({'success': True, 'target': 'fedhub', 'enabled': result['enabled'], 'running': result['running']})
        return jsonify({'success': False, 'error': result.get('error', 'unknown')}), 500
    # this_host
    try:
        if action == 'disable':
            subprocess.run('pkill -TERM -f "/usr/bin/unattended-upgrade" 2>/dev/null; true', shell=True, timeout=5)
            for _ in range(15):
                time.sleep(1)
                r = subprocess.run('pgrep -f "/usr/bin/unattended-upgrade" 2>/dev/null', shell=True, capture_output=True, text=True, timeout=3)
                if not (r.stdout or '').strip():
                    break
            else:
                subprocess.run('pkill -9 -f "/usr/bin/unattended-upgrade" 2>/dev/null; true', shell=True, timeout=5)
                time.sleep(3)
            _run_priv_chain([['systemctl', 'stop', 'unattended-upgrades'], ['systemctl', 'disable', 'unattended-upgrades']], 'and', timeout=25)
            _run_priv_chain([['systemctl', 'stop', 'apt-daily-upgrade.timer'], ['systemctl', 'disable', 'apt-daily-upgrade.timer']], 'seq', timeout=10)
        else:
            _run_priv_chain([['systemctl', 'enable', 'unattended-upgrades'], ['systemctl', 'start', 'unattended-upgrades']], 'and', timeout=30)
            _run_priv_chain([['systemctl', 'enable', 'apt-daily-upgrade.timer'], ['systemctl', 'start', 'apt-daily-upgrade.timer']], 'seq', timeout=10)
        uu = _get_unattended_upgrades_status()
        return jsonify({'success': True, 'target': 'this_host', 'enabled': uu['enabled'], 'running': uu['running']})
    except subprocess.CalledProcessError as e:
        return jsonify({'success': False, 'error': (e.stderr or str(e))[:200]}), 500
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)[:200]}), 500

@app.route('/api/modules')
@login_required
def api_modules():
    """Live module states for dashboard cards (so CLI uninstall/start/stop is reflected)."""
    modules = detect_modules()
    result = {}
    for k, m in modules.items():
        d = {'installed': m.get('installed', False), 'running': m.get('running', False)}
        if k in _auto_deploy_active:
            d['updating_config'] = True
        result[k] = d
    return jsonify(result)

# Full uninstall (all deployed services) — for testing: reset VPS without destroying it
full_uninstall_log = []
full_uninstall_status = {'running': False, 'done': False, 'error': None}

def run_full_uninstall():
    """Remove all deployed services in reverse dependency order. Console and config remain."""
    def plog(msg):
        entry = f"[{datetime.now().strftime('%H:%M:%S')}] {msg}"
        full_uninstall_log.append(entry)
        print(entry, flush=True)
    try:
        settings = load_settings()
        pkg_mgr = settings.get('pkg_mgr', 'apt')

        # 1. MediaMTX
        plog("━━━ MediaMTX ━━━")
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'mediamtx', 'mediamtx-webeditor']), capture_output=True, timeout=90)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', 'mediamtx', 'mediamtx-webeditor']), capture_output=True)
        for f in ['/etc/systemd/system/mediamtx.service', '/etc/systemd/system/mediamtx-webeditor.service',
                  '/usr/local/bin/mediamtx', '/usr/local/etc/mediamtx.yml']:
            if os.path.exists(f):
                try:
                    os.remove(f)
                except Exception:
                    pass
        if os.path.exists('/opt/mediamtx-webeditor'):
            subprocess.run(_sudo_wrap(['rm', '-rf', '/opt/mediamtx-webeditor']), capture_output=True)
        subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True)
        mediamtx_deploy_log.clear()
        mediamtx_deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ MediaMTX removed")

        # 2. TAK Portal
        plog("━━━ TAK Portal ━━━")
        portal_dir = os.path.expanduser('~/TAK-Portal')
        if os.path.exists(portal_dir):
            subprocess.run(_sudo_wrap(['docker', 'compose', 'down', '-v', '--rmi', 'local']), cwd=portal_dir, capture_output=True, timeout=120)
            subprocess.run(f'rm -rf {portal_dir}', shell=True, capture_output=True)
        takportal_deploy_log.clear()
        takportal_deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ TAK Portal removed")

        # 3. CloudTAK
        plog("━━━ CloudTAK ━━━")
        cloudtak_dir = os.path.expanduser('~/CloudTAK')
        for yml in [os.path.join(cloudtak_dir, 'docker-compose.yml'), os.path.join(cloudtak_dir, 'compose.yaml')]:
            if os.path.exists(yml):
                subprocess.run(_sudo_wrap(['docker', 'compose', '-f', yml, 'down', '-v', '--rmi', 'local']), capture_output=True, timeout=180, cwd=cloudtak_dir)
                break
        if os.path.exists(cloudtak_dir):
            subprocess.run(f'rm -rf "{cloudtak_dir}"', shell=True, capture_output=True, timeout=60)
        cloudtak_deploy_log.clear()
        cloudtak_deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ CloudTAK removed")

        # 4. Node-RED
        plog("━━━ Node-RED ━━━")
        nr_dir = os.path.expanduser('~/node-red')
        compose = os.path.join(nr_dir, 'docker-compose.yml')
        if os.path.exists(compose):
            subprocess.run(_sudo_wrap(['docker', 'compose', '-f', compose, 'down', '-v']), capture_output=True, timeout=60, cwd=nr_dir)
        if os.path.exists(nr_dir):
            subprocess.run(f'rm -rf "{nr_dir}"', shell=True, capture_output=True, timeout=10)
        nodered_deploy_log.clear()
        nodered_deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ Node-RED removed")

        # 5. TAK Server
        plog("━━━ TAK Server ━━━")
        # v10.0.1: container TAK teardown FIRST — systemctl/pkill don't touch Docker and
        # --restart=always respawns the containers; mirror takserver_uninstall()'s teardown
        # so a factory-reset on an arm64/container box doesn't orphan the containers/volume.
        if _tak_is_container():
            for c in (TAK_CONTAINER, TAK_DB_CONTAINER):
                subprocess.run(_sudo_wrap(['docker', 'rm', '-f', c]), capture_output=True, timeout=60)
            subprocess.run(_sudo_wrap(['docker', 'volume', 'rm', TAK_DB_VOLUME]), capture_output=True, timeout=30)
            subprocess.run(_sudo_wrap(['docker', 'network', 'rm', TAK_DOCKER_NET]), capture_output=True, timeout=30)
            subprocess.run(_sudo_wrap(['rm', '-rf', TAK_DOCKER_ROOT]), capture_output=True, timeout=60)  # v10.0.1: broker rm — the host console user can't delete the root-owned in-container cert files
            subprocess.run(_sudo_wrap(['rm', '-f', '/opt/tak']), capture_output=True, timeout=10)
            plog("  container TAK removed (containers, volume, network, ~/tak-docker)")
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'takserver']), capture_output=True, timeout=90)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', 'takserver']), capture_output=True, timeout=90)
        subprocess.run('pkill -9 -f takserver 2>/dev/null; true', shell=True, capture_output=True)
        # Purge BEFORE removing /opt/tak — see takserver_uninstall() for why
        # `apt-get remove` (no purge) + `rm -rf /opt/tak` is a footgun.
        pkg_status = subprocess.run(
            "dpkg-query -W -f='${Status}' takserver 2>/dev/null",
            shell=True, capture_output=True, text=True
        ).stdout.strip()
        if pkg_status:
            for _cmd in (
                'DEBIAN_FRONTEND=noninteractive apt-get purge -y takserver',
                'DEBIAN_FRONTEND=noninteractive dpkg --purge takserver',
                'DEBIAN_FRONTEND=noninteractive dpkg --purge --force-all takserver',
            ):
                subprocess.run(_cmd, shell=True, capture_output=True, text=True, timeout=180)
                _after = subprocess.run(
                    "dpkg-query -W -f='${Status}' takserver 2>/dev/null",
                    shell=True, capture_output=True, text=True
                ).stdout.strip()
                if not _after or 'not-installed' in _after:
                    break
        if os.path.exists('/opt/tak'):
            subprocess.run(_sudo_wrap(['rm', '-rf', '/opt/tak']), capture_output=True)
        subprocess.run("runuser -u postgres -- psql -c \"DROP DATABASE IF EXISTS cot WITH (FORCE);\" 2>/dev/null || runuser -u postgres -- psql -c \"DROP DATABASE IF EXISTS cot;\" 2>/dev/null; true", shell=True, capture_output=True, timeout=30)
        subprocess.run("runuser -u postgres -- psql -c \"DROP USER IF EXISTS martiuser;\" 2>/dev/null; true", shell=True, capture_output=True, timeout=30)
        subprocess.run('rm -rf /usr/share/debsig/keyrings/* /etc/debsig/policies/* 2>/dev/null; true', shell=True, capture_output=True, timeout=10)
        for f in os.listdir(UPLOAD_DIR):
            try:
                os.remove(os.path.join(UPLOAD_DIR, f))
            except Exception:
                pass
        deploy_log.clear()
        deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ TAK Server removed")

        # 6. Email Relay
        plog("━━━ Email Relay ━━━")
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'postfix']), capture_output=True, timeout=90)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', 'postfix']), capture_output=True, timeout=90)
        if pkg_mgr == 'apt':
            subprocess.run(_sudo_wrap(['apt-get', 'remove', '-y', 'postfix']), capture_output=True, timeout=120)
        else:
            subprocess.run(_sudo_wrap(['dnf', 'remove', '-y', 'postfix']), capture_output=True, timeout=120)
        settings = load_settings()
        settings.pop('email_relay', None)
        save_settings(settings)
        email_deploy_log.clear()
        email_deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ Email Relay removed")

        # 7. Authentik
        plog("━━━ Authentik ━━━")
        ak_dir = os.path.expanduser('~/authentik')
        if os.path.exists(ak_dir):
            subprocess.run(_sudo_wrap(['docker', 'compose', 'down', '-v', '--rmi', 'all', '--remove-orphans']), cwd=ak_dir, capture_output=True, text=True, timeout=180)
            subprocess.run(f'rm -rf {ak_dir}', shell=True, capture_output=True)
        authentik_deploy_log.clear()
        authentik_deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ Authentik removed")

        # 8. Caddy
        plog("━━━ Caddy ━━━")
        subprocess.run(_sudo_wrap(['systemctl', 'stop', 'caddy']), capture_output=True, timeout=90)
        subprocess.run(_sudo_wrap(['systemctl', 'disable', 'caddy']), capture_output=True, timeout=90)
        if pkg_mgr == 'apt':
            subprocess.run(_sudo_wrap(['apt-get', 'remove', '--purge', '-y', 'caddy']), capture_output=True, timeout=120)
        else:
            subprocess.run(_sudo_wrap(['dnf', 'remove', '-y', 'caddy']), capture_output=True, timeout=120)
        # Ensure binary and config are gone so console no longer shows Caddy as installed (which uses "which caddy")
        for path in ['/usr/bin/caddy', '/usr/local/bin/caddy']:
            if os.path.exists(path):
                try:
                    os.remove(path)
                except Exception:
                    subprocess.run(f'rm -f {path}', shell=True, capture_output=True)
        if os.path.exists('/etc/caddy'):
            subprocess.run(_sudo_wrap(['rm', '-rf', '/etc/caddy']), capture_output=True, timeout=10)
        subprocess.run(_sudo_wrap(['systemctl', 'daemon-reload']), capture_output=True)
        settings = load_settings()
        settings['fqdn'] = ''
        save_settings(settings)
        caddy_deploy_log.clear()
        caddy_deploy_status.update({'running': False, 'complete': False, 'error': False})
        plog("✓ Caddy removed")

        plog("")
        plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
        plog("All deployed services removed. Console remains. Use Marketplace to deploy again.")
        plog("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
        _update_boot_stagger_service()
        full_uninstall_status.update({'running': False, 'done': True, 'error': None})
    except subprocess.TimeoutExpired:
        full_uninstall_status.update({'running': False, 'done': True, 'error': 'Uninstall timed out'})
        full_uninstall_log.append(f"[{datetime.now().strftime('%H:%M:%S')}] ✗ Timeout")
    except Exception as e:
        full_uninstall_status.update({'running': False, 'done': True, 'error': str(e)[:200]})
        full_uninstall_log.append(f"[{datetime.now().strftime('%H:%M:%S')}] ✗ {str(e)[:200]}")

@app.route('/api/console/uninstall-all/validate', methods=['POST'])
@login_required
def console_uninstall_all_validate():
    """Check admin password only (for green check in UI)."""
    data = request.json or {}
    password = data.get('password', '')
    auth = load_auth()
    valid = bool(auth.get('password_hash') and check_password_hash(auth['password_hash'], password))
    return jsonify({'valid': valid})

@app.route('/api/console/uninstall-all', methods=['POST'])
@login_required
def console_uninstall_all():
    """Start full uninstall of all deployed services (for testing: reset without burning VPS)."""
    data = request.json or {}
    password = data.get('password', '')
    confirm = (data.get('confirm') or '').strip().upper()
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], password):
        return jsonify({'error': 'Invalid admin password'}), 403
    if confirm != 'UNINSTALL':
        return jsonify({'error': 'Type UNINSTALL in the confirmation box to proceed'}), 400
    if full_uninstall_status.get('running'):
        return jsonify({'error': 'Uninstall already in progress'}), 409
    full_uninstall_log.clear()
    full_uninstall_status.update({'running': True, 'done': False, 'error': None})
    threading.Thread(target=run_full_uninstall, daemon=True).start()
    return jsonify({'success': True, 'message': 'Full uninstall started'})

@app.route('/api/console/uninstall-all/status')
@login_required
def console_uninstall_all_status():
    return jsonify({
        'running': full_uninstall_status.get('running', False),
        'done': full_uninstall_status.get('done', False),
        'error': full_uninstall_status.get('error'),
        'log': full_uninstall_log[-200:],
    })

@app.route('/api/console/password/reset', methods=['POST'])
@login_required
def console_password_reset():
    """Reset console admin password (for 5001 and Uninstall all). Requires current password."""
    data = request.json or {}
    current = data.get('current_password', '')
    new_pw = data.get('new_password', '')
    confirm = data.get('new_password_confirm', '')
    auth = load_auth()
    if not auth.get('password_hash') or not check_password_hash(auth['password_hash'], current):
        return jsonify({'success': False, 'error': 'Current password is wrong'}), 403
    if not new_pw or len(new_pw) < 8:
        return jsonify({'success': False, 'error': 'New password must be at least 8 characters'}), 400
    if new_pw != confirm:
        return jsonify({'success': False, 'error': 'New password and confirmation do not match'}), 400
    auth['password_hash'] = generate_password_hash(new_pw)
    auth['created'] = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    save_auth(auth)
    _detached_console_restart()
    return jsonify({'success': True, 'message': 'Password updated. Console will restart in a few seconds.'})


def _get_current_ssh_port():
    """Read SSH port from /etc/ssh/sshd_config. Default 22 if not set or unreadable."""
    try:
        for line in _read_priv('/etc/ssh/sshd_config').splitlines():
            line = line.strip()
            if line and not line.startswith('#'):
                parts = line.split(None, 1)
                if len(parts) >= 2 and parts[0].lower() == 'port':
                    p = int(parts[1].strip())
                    if 1 <= p <= 65535:
                        return p
    except Exception:
        pass
    return 22


@app.route('/api/hardening/ssh-port', methods=['GET'])
@login_required
def api_hardening_ssh_port_get():
    """Return current SSH port from sshd_config."""
    return jsonify({'port': _get_current_ssh_port()})


@app.route('/api/hardening/ssh-port', methods=['POST'])
@login_required
def api_hardening_ssh_port_post():
    """Change SSH port: update sshd_config, open firewall, restart sshd. Requires root."""
    data = request.get_json() or {}
    try:
        port = int(data.get('port', 0))
    except (TypeError, ValueError):
        return jsonify({'success': False, 'error': 'Invalid port'}), 400
    if port < 1 or port > 65535:
        return jsonify({'success': False, 'error': 'Port must be between 1 and 65535'}), 400
    current = _get_current_ssh_port()
    if port == current:
        return jsonify({'success': True, 'message': f'SSH is already on port {port}. No change made.'})

    config_path = '/etc/ssh/sshd_config'
    try:
        lines = _read_priv(config_path).splitlines(keepends=True)   # v10.0.5 non-root: sshd_config may be 0600
    except Exception as e:
        return jsonify({'success': False, 'error': f'Cannot read sshd_config: {e}'}), 500

    # Replace or add Port line; drop any existing Port / #Port
    new_lines = []
    port_line_added = False
    for line in lines:
        stripped = line.strip()
        if stripped and not stripped.startswith('#'):
            parts = stripped.split(None, 1)
            if len(parts) >= 1 and parts[0].lower() == 'port':
                if not port_line_added:
                    new_lines.append(f'Port {port}\n')
                    port_line_added = True
                continue
        elif stripped.startswith('#Port') or (stripped.startswith('#') and stripped[1:].strip().lower().startswith('port')):
            if not port_line_added:
                new_lines.append(f'Port {port}\n')
                port_line_added = True
            continue
        new_lines.append(line)
    if not port_line_added:
        new_lines.append(f'\n# infra-TAK hardening\nPort {port}\n')

    try:
        _write_priv(config_path, ''.join(new_lines))   # v10.0.5 non-root: /etc/ssh/sshd_config root-owned
    except Exception as e:
        return jsonify({'success': False, 'error': f'Cannot write sshd_config: {e}'}), 500

    # Allow the new SSH port in the host firewall. v10.0.5: _fw_allow picks the
    # family-gated backend — bare `which ufw` is shim-poisoned and would skip firewalld
    # on RHEL, never opening the port → lockout after sshd restart.
    _fw_allow(int(port), 'tcp')

    # Restart SSH (ssh.service on Debian/Ubuntu, sshd on some others)
    for svc in ('ssh', 'sshd'):
        r = subprocess.run(_sudo_wrap(['systemctl', 'restart', svc]), capture_output=True, text=True, timeout=15)
        if r.returncode == 0:
            break

    settings = load_settings()
    settings['ssh_port'] = port
    save_settings(settings)
    return jsonify({'success': True, 'message': f'SSH port set to {port}. Connect using port {port} from now on.'})


